window.__QUIZ_SUBJECT__=[{"id": "objective>Physics>1995>1", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "Which of the following is a fundamental quantity?", "images": [], "options": {"A": "Heat capacity", "B": "Electric current", "C": "Torque", "D": "Reactance"}, "answer": "B", "explanation": "Fundamental quantities are independent quantities examples are mass, length, time, temperature, current, amount of substance, luminous intensity", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>2", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "A boy cycles continuously through a distance of 1.0 km in 5 minutes. Calculate his average speed.", "images": [], "options": {"A": "0.3 ms-1", "B": "3.3 ms-1", "C": "16.6 ms-1", "D": "20.0 ms-1"}, "answer": "B", "explanation": "Averagespeed=Total distanceTotal time=1 x 1000 m5 x 60 s=3.33 ms-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>3", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "TIME : MEASUREMENT OF TIME", "question": "A student found out from a simple pendulum experiment that 20 oscillations were completed in 38 seconds. What is the period of oscillation of the pendulum.", "images": [], "options": {"A": "8.0 s", "B": "3.8 s", "C": "2.0 s", "D": "1.9 s"}, "answer": "D", "explanation": "The period of oscillation is the time taken for one complete cycle of oscillation. In this case, 20 oscillations were completed in 38 seconds. Therefore, the period of oscillation is 38 s / 20 = 1.9 s.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>4", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A body of mass 7.5 kg is to be pulled up along a plane which is inclined at 30o to the horizontal. If the efficiency of the plane is 75%, what is the minimum force required to pull the body up the plane?", "images": [], "options": {"A": "5.0 N", "B": "20.0 N", "C": "50.0 N", "D": "75.0 N"}, "answer": "C", "explanation": "m=7.5kg;θ=30o;ε=75%  L=mg=7.5x10=75N  V.R=1sin θ=10.5=2  ε=LEx1V.Rx100%==>75%=75Ex12x100%  =75=752Ex100  =75100=752E  =150=1E  ∴E=50.0N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>5", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "The angular speed of an object describing a circle of radius 4m with linear constant speed of 10 ms-1 is", "images": [], "options": {"A": "40.00 rads-1", "B": "14.00 rads-1", "C": "2.50 rads-1", "D": "1.58 rads-1"}, "answer": "C", "explanation": "r=4m;v=10ms-1;ω=?;v=ωr;ω=vr=104=2.50rads-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>6", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "At what angle to the horizontal must the nozzle of a machine gun be kept when firing to obtain a maximum horizontal range for the bullets?", "images": [], "options": {"A": "0.0o", "B": "22.5o", "C": "30.0o", "D": "45.0o"}, "answer": "D", "explanation": "R=u2sin 2θg  Rmax=u2sin 2(45)g=u2sin 90g=u2g(sincesin90o=1)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>7", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "Which of the following will reduce the frequency of oscillation of a simple pendulum?", "images": [], "options": {"A": "Increasing the mass of the bob", "B": "Decreasing the mass of the bob", "C": "Increasing the length of the string", "D": "Decreasing the length of the string"}, "answer": "C", "explanation": "The frequency of oscillation of a simple pendulum is given by the formula f = 1/2π √(g/l), where g is the acceleration due to gravity and l is the length of the pendulum. From this formula, it can be seen that the frequency is inversely proportional to the square root of the length of the pendulum. Therefore, increasing the length of the pendulum will reduce the frequency of oscillation. The mass of the bob does not affect the frequency.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>8", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "A car travelling at a uniform speed of 120 kmhr-1 passes two stations in 4 minutes. Calculate the distance between the two stations.", "images": [], "options": {"A": "8 km", "B": "15 km", "C": "22 km", "D": "30 km"}, "answer": "A", "explanation": "The distance covered by a moving object is given by the formula d = vt, where v is the speed and t is the time. In this case, the speed of the car is 120 km/hr and the time is 4 minutes, which is equivalent to 4/60 = 0.067 hours. Substituting these values into the formula gives d = 120 * 0.067 = 8 km.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>9", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "MACHINES :", "question": "A machine has an efficiency of 60%. If the machine is required to overcome a load of 30 N with a force of 20 N. Calculate its mechanical advantage?", "images": [], "options": {"A": "0.7", "B": "0.9", "C": "1.5", "D": "2.5"}, "answer": "C", "explanation": "ε=60%;L=30N;E=20N;M.A=?  M.A=LE=3020=1.5", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>10", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A body weighing 10 N in air is partially immersed in water. It displaces water of mass 0.3 kg. What is the upthrust on the body? (g = 10 ms-2)", "images": [], "options": {"A": "13.0 N", "B": "7.0 N", "C": "3.3 N", "D": "3.0 N"}, "answer": "D", "explanation": "Upthrust = Weight of fluid displaced = 0.3 x 10 = 3.0 N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>11", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A mercury-in-glass thermometer reads -20o at the ice point and 100o at the steam point. Calculate the Celsius temperature corresponding to 70o on the thermometer.", "images": [], "options": {"A": "41.0oC", "B": "50.0oC", "C": "62.5oC", "D": "75.0oC"}, "answer": "D", "explanation": "∴70 - (-20)100 - (-20)=x - 0100 - 0  90120=x100  x=90 x 100120=75.0oC", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>12", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A brass rod is 2 m long at a certain temperature. Calculate the linear expansion of the rod for a temperature change of 100 K. (Take linear expansivity of brass as 1.8 x 10-5 K-1)", "images": [], "options": {"A": "0.3600 m", "B": "0.1800 m", "C": "0.360 m", "D": "0.0036 m"}, "answer": "D", "explanation": "L=2m;α=1.8x10-5 K-1;∆θ=100K  α=∆LL∆θ  ∆L=αL∆θ  ∆L=1.8x10-5x2x100=3.6x10-3  ∴∆L=0.0036m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>13", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONSERVATION OF MECHANICAL ENERGY", "question": "A body of specific heat capacity 450 Jkg-1K-1 falls to the ground from rest through a vertical height of 20 m. Assuming conservation of energy, calculate the change in temperature of the body striking the ground level. (g = 10 ms-2)", "images": [], "options": {"A": "0oC", "B": "29oC", "C": "49oC", "D": "94oC"}, "answer": "C", "explanation": "c=450Jkg-1K-1;h=20m;θ=?;g=10ms-2  Heatenergy=Potentialenergy  mc∆θ=mgh  c∆θ=gh  ∴∆θ=ghc=10x20450=2045=49oC", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>14", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Hot water at temperature of t is added to twice that amount of water at a temperature of 30oC. If the resulting temperature of the mixture is 50oC, calculate t", "images": [], "options": {"A": "90oC", "B": "80oC", "C": "50oC", "D": "40oC"}, "answer": "A", "explanation": "Heat loss by hot water = Heat gained by water  mc(t - 50) = 2mc(50 - 30)  t - 50 = 2(20)  t - 50 = 40  t = 40 + 50  t = 90oC", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>15", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "An air bubble of volume 2 cm3 is formed 20 m under water. What will be its volume when it rises to just below the surface of the water if the atmospheric pressure is equivalent to a height of 10 m of water?", "images": [], "options": {"A": "6 cm3", "B": "4 cm3", "C": "3 cm3", "D": "2 cm3"}, "answer": "A", "explanation": "P1 = 20 m + 10 m = 30 m = 3000 cm  V1 = 2 cm3  P2 = 10 m = 1000 cm  V2 = ?  P1V1 = P2V2  3000 x 2 = 1000 x  V2  ∴ V2 = 6 cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>16", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure of a given mass of gas changes from 200 Nm-2 to 100 Nm-2, while its temperature drops from 127oC to  -73oC. Calculate the ratio of the final volume of the gas to its initial volume.", "images": [], "options": {"A": "2.4 : 1", "B": "2.0 : 1", "C": "1.2 : 1", "D": "1.0 : 1"}, "answer": "D", "explanation": "P1=200Nm-2;P2=100Nm-2;T1=127+273=400K;T2=-73+273=200K;V2V1=?  P1V1T1=P2V2T2  P1V1T2=P2V2T1  V2V1=P1T2P2T1=200 x 200100 x 400=11  ∴ V2 : V1 = 1.0 : 1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>17", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The temperature of glass vessel containing 100 cm3 of mercury is raised from 10oC to 100oC. Calculate the apparent cubic expansion of the mercury. (Real cubic expansivity of mercury = 1.8 x 10-4 K-1, Cubic expansivity of glass = 2.4 x 10-5 K-1)", "images": [], "options": {"A": "0.52 cm3", "B": "1.42 cm3", "C": "1.87 cm3", "D": "14.22 cm3"}, "answer": "B", "explanation": "γ=V2 - V1V1(θ2 - θ1) ==> V2 = V1(1 + γ(θ2 - θ1))  (i) For mercury  V1 = 100 cm3  θ1 = 10oC  θ2 = 100oC  γr = 1.8 x 10-4 K-1  V2 = ?  V2 = 100(1 + 1.8 x 10-4 x (100 - 10)) = 100(1 + 1.8 x 10-4 x 90)  = 100(1 + 0.0162) = 100(1.0162)  V2 = 101.62 cm3    (ii) For glass  V1 = 100 cm3  θ1 = 10oC  θ2 = 100oC  γ = 2.4 x 10-5 K-1  V2 = ?  V2 = 100(1 + 2.4 x 10-5 x (100 - 10)) = 100(1 + 2.4 x 10-5 x 90)  = 100(1 + 0.00216) = 100(1.00216)  V2 = 100.216 cm3    Finally,  Volume of mercury expelled = 101.62 - 100.216 = 1.404 cm3  Volume of mercury remaining = 100.216 cm3  Temperature rise = 100oC - 10oC = 90oC  Apparent cubic expansion of the mercury γa   =Volume of mercury expelledVolume of mercury remaining x temp. rise=1.404100.216 x 90=1.4049019.44  ∴  γa  = 1.56 x 10-4 K-1    Since the options are in volume (cm3), the answer is B which is the volume of mercury expelled", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>18", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "An iron rod of mass 2 kg and at a temperature of 280oC is dropped into some quantity of water initially at a temperature of 30oC. If the temperature of the mixture is 70oC, calculate the mass of the water. (Neglect heat losses to the sorroundings)  [Specific heat capacity of iron = 460 Jkg-1K-1]  [Specific heat capacity of water = 4200 Jkg-1K-1]", "images": [], "options": {"A": "0.58 kg", "B": "0.77 kg", "C": "1.15 kg", "D": "1.50 kg"}, "answer": "C", "explanation": "ms = 2 kg; cs = 460 Jkg-1K-1; mw = ?; cw = 4200 Jkg-1K-1; θ1 = 280oC; θ2 = 30oC; θ3 = 70oC  Heat loss = Heat gained  mscs(θ1 - θ3) = mwcw(θ3 - θ2)  2 x 460 x (280 - 70) = mw x 4200 x (70 - 30)  2 x 460 x 210 = mw x 4200 x 40  193,200 = 168,000mw  ∴mw=193200168000=1.15kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>19", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "How much heat is required to covert 20 g of ice at 0oC to water at the same temperature?  [Specific latent heat of ice = 336 Jg-1]", "images": [], "options": {"A": "1.35 x 103 J", "B": "5.38 x 103 J", "C": "6.72 x 103 J", "D": "7.06 x 103 J"}, "answer": "C", "explanation": "The heat required to convert ice at 0oC to water at the same temperature is given by the formula: Q = m * L, where m is the mass of the ice and L is the specific latent heat of ice. Substituting the given values, we get Q = 20 g * 336 Jg-1 = 6.72 x 103 J. Therefore, the correct option is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>20", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "When two objects P and Q are supplied with the same quantity of heat, the temperature change in P is observed to be twice that in Q.  If the masses of P and Q are the same, calculate the ratio of the specific heat capacities of Q to P.", "images": [], "options": {"A": "4 : 1", "B": "2 : 1", "C": "1 : 1", "D": "1 : 2"}, "answer": "B", "explanation": "∆θP = 2 x ∆θQ  mP = mQ  cQ : cP = ?  HP = HQ (given)  i.e mP x cP x ∆θP = mQ x cQ x ∆θQ  Since ∆θP = 2 x ∆θQ and mP = mQ  ∴ mQ x cP x 2 x ∆θQ = mQ x cQ x ∆θQ  cP x 2 = cQ  cQcP=21∴cQ:cP=2:1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>21", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A ray of light is incident on mirror m1 and after reflection is incident on mirror m2 as shown in the diagram below. Calculate the angle of reflection of the ray at mirror m2.", "images": ["Physics/imgs/1995/phy_95_two_one.png"], "options": {"A": "120o", "B": "90o", "C": "60o", "D": "30o"}, "answer": "D", "explanation": "i at m1 = 60o ⇒ r = 60o  at m1 (law of reflection io = ro)  i at m2 = 30o  i = r, ∴ r = 30o", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>22", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light is incident on a body x as shown in the diagram below. What is the refractive index of the body?", "images": ["Physics/imgs/1995/phy_95_two_two.png"], "options": {"A": "1.63", "B": "1.50", "C": "1.49", "D": "1.33"}, "answer": "A", "explanation": "λ=sin isin r=sin 60osin 32o=1.63", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>23", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT", "question": "Light travels in straight lines. In which of the following is this principle manifested?  I. Pinhole camera  II. Formation of shadows  III. Diffraction of light  IV. Occurrence of eclipse", "images": [], "options": {"A": "I and III only", "B": "II and III only", "C": "I, II and III only", "D": "I, II and IV only"}, "answer": "D", "explanation": "Pinhole camera, shadow formation and the occurence of eclipse are as a result of the rectilinear propagation of light", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>24", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "The image of any real object formed by a diverging lens is always", "images": [], "options": {"A": "inverted", "B": "magnified", "C": "erect", "D": "real"}, "answer": "C", "explanation": "For all positions of the object formed by a concave (diverging) lens, the image is virtual, erect and diminished.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>25", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Which of the following is not self-luminous?", "images": [], "options": {"A": "Incadescent electric bulb", "B": "Incadescent flourescent tube", "C": "Lighted candle", "D": "The moon"}, "answer": "D", "explanation": "The moon is not self-luminous. Self-luminous objects are those that can emit light on their own. The moon does not emit light; it only reflects light from the sun.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>26", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "An object is placed on the principal axis and at the centre of curvature of a concave mirror. The image of the object formed by the mirror is", "images": [], "options": {"A": "real, inverted and magnified", "B": "at the principal focus", "C": "real and diminished", "D": "at the centre of curvature"}, "answer": "D", "explanation": "The image formed when an object is placed at centre of curvature of a concave (converging) mirror is real, inverted, same size as the object and at the centre of curvature of the mirror", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>27", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A wire is stretched between two points, 1 m apart, if the speed of the wave generated on plucking the wire is 200 ms-1, what is the minimum frequency which will resonate with the wire.", "images": [], "options": {"A": "50 Hz", "B": "75 Hz", "C": "100 Hz", "D": "200 Hz"}, "answer": "D", "explanation": "λ=1m;v=200 ms-1;f=?;f=vλ=2001=200Hz", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>28", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "Sixty complete waves pass a particular point in 4s. If the distance between three successive troughs of the waves is 15 m, calculate the speed of the waves.", "images": [], "options": {"A": "300.0 ms-1", "B": "225.0 ms-1", "C": "112.5 ms-1", "D": "75.0 ms-1"}, "answer": "B", "explanation": "f=no of oscillation madet(s)=604=15Hz  λ=15m;v=15x15=225.0ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>29", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "Which of the following media allow(s) the transmission of sound wave through them?  I. Air  II. Liquid  III. Solid", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I, II and III only"}, "answer": "D", "explanation": "Sound waves are mechanical waves, which means they require a medium to travel through. They can travel through all three states of matter: gases (like air), liquids, and solids. Therefore, all three options I, II, and III are correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>30", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "Which of the following wave characteristic can be used to distinguish a transverse wave from a longitudinal wave?", "images": [], "options": {"A": "Reflection", "B": "Refraction", "C": "Diffraction", "D": "Polarisation"}, "answer": "D", "explanation": "Polarisation only occurs with a wave whose direction is perpendicular to its vibration (i.e transverse waves)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>31", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "A sound note of frequency 250 Hz and a wavelength 1.3 m is produced at a point near a hill. If the echo of the sound is recieved 1 second later at that point, how far away is the hill from the point?", "images": [], "options": {"A": "131.3 m", "B": "162.5 m", "C": "248.7 m", "D": "261.3 m"}, "answer": "B", "explanation": "f = 250 Hz; λ = 1.3 m; t = 1 s; d = ?  v = fλ = 250 x 1.3 = 325 ms-1  v=2dt ∴d=vt2=325 x 12=162.5m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>32", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The period of a wave is 0.02 second. Calculate its wavelength if its speed is 330 ms-1", "images": [], "options": {"A": "6.6 m", "B": "5.0 m", "C": "4.0 m", "D": "3.3 m"}, "answer": "A", "explanation": "T=0.02s;λ=?;v=330ms-1;f=1T=10.02=50Hz  λ=vf=33050=6.6m", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>33", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES", "question": "An alternating voltage with a frequency of 50 Hz has a period of", "images": [], "options": {"A": "0.02 s", "B": "0.05 s", "C": "0.20 s", "D": "0.50 s"}, "answer": "A", "explanation": "The period of a wave is the reciprocal of its frequency. Therefore, period = 1 / frequency. Substituting the given frequency, we get period = 1 / 50 Hz = 0.02 s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>34", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SOUND WAVES : HARMONIES AND OVERTONES", "question": "A listener can detect the instrument from which a note is being sounded because different instruments produce the same note with different", "images": [], "options": {"A": "Frequencies", "B": "Pitches", "C": "Loudness", "D": "Overtones"}, "answer": "D", "explanation": "Quality (overtones) is a characteristics note of a musical instrument which distinguishes it from another note of the same pitch and loudness produced by another instrument", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>35", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY", "question": "What is the escape velocity of a body on the surface of the earth of radius R if the gravitational constant is G and the mass of the earth is M? (Neglect energy losses to the sorroundings)", "images": [], "options": {"A": "√2GR", "B": "√2GR", "C": "√2GR2", "D": "√2GM"}, "answer": "D", "explanation": "ve = √2gR  Since gR = GM  Therefore, ve = √2GM", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>36", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "A charge of 1.6 x 10-10 C is placed in a uniform electric field of intensity 2.0 x 105 NC-1. What is the magnitude of the electric force exerted on the charge?", "images": [], "options": {"A": "3.2 x 105 N", "B": "1.8 x 105 N", "C": "3.2 x 10-5 N", "D": "1.8 x 10-5 N"}, "answer": "C", "explanation": "The force exerted on a charge in an electric field is given by the formula F = qE, where F is the force, q is the charge, and E is the electric field intensity. In this case, the charge q is 1.6 x 10-10 C and the electric field intensity E is 2.0 x 105 NC-1. Substituting these values into the formula gives F = (1.6 x 10-10 C) * (2.0 x 105 NC-1) = 3.2 x 10-5 N. Therefore, the magnitude of the electric force exerted on the charge is 3.2 x 10-5 N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>37", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A balloon containing 546 cm3 of air is heated from 0oC to 10oC. If the pressure is kept constant, what will be its volume at 10oC.", "images": [], "options": {"A": "526 cm3", "B": "546 cm3", "C": "556 cm3", "D": "566 cm3"}, "answer": "D", "explanation": "V1T1=V2T2==>  5460 + 273=V210 + 273  V2=546 x 283273=566cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>38", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : INDUCTANCE", "question": "Calculate the inductance L of the coil in the circuit shown beside.", "images": ["Physics/imgs/1995/phy_95_three_eight.png"], "options": {"A": "14.4 H", "B": "3.8 H", "C": "0.6 H", "D": "0.4 H"}, "answer": "C", "explanation": "V=IXL  XL=VI=2402=120Ω  XL=2πfL  120=2πx100πxL  120=200L  L=120200=0.6H", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>39", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS", "question": "A series R-L-C circuit is shown in the diagram above. Which of the following vector diagrams correctly represents the phase relationship among I, V, VR, VC and VL if VC is greater than VL and the symbols have their usual meaning?", "images": ["Physics/imgs/1995/phy_95_three_nine.png", "Physics/imgs/1995/phy_95_three_nine_opt_a.png", "Physics/imgs/1995/phy_95_three_nine_opt_b.png", "Physics/imgs/1995/phy_95_three_nine_opt_c.png", "Physics/imgs/1995/phy_95_three_nine_opt_e.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "i.e VL - VC = -ve value (VC - VL = +ve)    Fromtan∅=VL - VCR  it shows that VL - VC will be inverted on the y-axis since VC > VL    So, the correct option is D not A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>40", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "Calculate the electric potential at a distance of 20.0 cm from a point charge of 0.015 C placed in air of permittivity  (Take14πεoas9.0x109Nm2C-2)", "images": [], "options": {"A": "3.40 x 109 V", "B": "6.75 x 108 V", "C": "6.75 x 106 V", "D": "3.40 x 105 V"}, "answer": "C", "explanation": "The electric potential (V) at a distance (r) from a point charge (q) is given by the formula V = kq/r, where k is Coulomb's constant. Substituting the given values, we get V = (9.0 x 10^9 Nm^2/C^2 * 0.015 C) / 0.20 m = 6.75 x 10^6 V. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>41", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "Calculate the inductive reactance of the circuit shown below", "images": ["Physics/imgs/1995/phy_95_four_one.png"], "options": {"A": "50.00 Ω", "B": "5.00 Ω", "C": "0.50 Ω", "D": "0.05 Ω"}, "answer": "A", "explanation": "RL=2πfL=2πx100πx0.25=50.00Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>42", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "If the current in the resistor R in Question 41 is 0.05 A, calculate the p.d across the inductor.", "images": [], "options": {"A": "2.5 V", "B": "25.0 V", "C": "49.0 V", "D": "50.0 V"}, "answer": "A", "explanation": "I = 0.05 A, p.d across RL = VL = IRL = 0.05 x 50  VL = 2.5 V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>43", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Acapacitorofcapacitance25μFisconnectedtoana.cpowersourceoffrequency200πHz.  Calculatethereactanceofthecapacitor.", "images": [], "options": {"A": "0.01 Ω", "B": "0.02 Ω", "C": "50.00 Ω", "D": "100.00 Ω"}, "answer": "D", "explanation": "XC=12πfC=12π x 200/π x 25 x 10-6=12 x 200 x 25 x 10-6 = 110-2 = 102  ∴XC=100.00Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>44", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The energy stored in a capacitor of capacitance 5μF is 40 J. Calculate the voltage applied across its terminal?", "images": [], "options": {"A": "4000 V", "B": "200 V", "C": "16 V", "D": "6 V"}, "answer": "A", "explanation": "E = 1/2QV; Q = CV  ∴ E = 1/2CV2; 40 = 1/2 x 5 x 10-6 x V2    V2=2 x 40 x 1065  V2 = 16 x 106    ∴ V = √(16 x 106) = 4000 V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>45", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The effective capacitance between points X and Y in the diagram below is 1.0μF. What is the value of the capacitance C, measured in micro-farad.", "images": ["Physics/imgs/1995/phy_95_four_five.png"], "options": {"A": "5.0 μ", "B": "4.0 μ", "C": "3.0 μ", "D": "1.0 μ"}, "answer": "D", "explanation": "Effective capacitance across the parallel = C + C = 2C  Effectivecapacitanceacrossthecircuit=12C+12=1 + C2C  ∴Effectivecapacitanceacrossthecircuit=1 + C2C=11 or 2C1 + C = 11  1 + C = 2C; 2C - C = 1 ∴ C = 1.0 μ", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>46", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Calculate the quantity of charge flowing through a conductor if a current of 10 A passes through the conductor for 10 s.", "images": [], "options": {"A": "100 C", "B": "20 C", "C": "15 C", "D": "10 C"}, "answer": "A", "explanation": "The quantity of charge flowing through a conductor is given by the formula Q = It. Substituting the given values, we get Q = 10*10 = 100 C.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>47", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : GRAPHICAL REPRESENTATION OF E.M.F AND CURRENT IN AN A.C. CIRCULT", "question": "An alternating current, having a waveform shown in the diagram below, is represented by the equation X = Xosinwt. Which of the following represents Xo?", "images": ["Physics/imgs/1995/phy_95_four_seven.png"], "options": {"A": "OS", "B": "OR", "C": "PQ", "D": "RT"}, "answer": "C", "explanation": "Xo equals PQ because it is the amplitude or maximum current.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>48", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT", "question": "What is the potential difference between X and Y in the diagram below if the battery is of negligible internal resistance?", "images": ["Physics/imgs/1995/phy_95_four_eight.png"], "options": {"A": "12.5 V", "B": "5.8 V", "C": "5.0 V", "D": "3.0 V"}, "answer": "D", "explanation": "V=IR;1RXY=13+12=56∴ RXY=65Ω  ∴RT=65+0.8=65+45=105=2Ω  V=IRT;5=2I;I=52A  ∴VacrossXY= IRXY = 52x65=3.0V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>49", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Calculate the current in the 3 Ω resistor in Question 48.", "images": [], "options": {"A": "0.3 A", "B": "0.4 A", "C": "1.0 A", "D": "1.5 A"}, "answer": "C", "explanation": "V = IR  Voltage across XY = 3 V = 3I  I=33=1.0A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>50", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A given wire of resistance 10 Ω has a length of 5 m and a cross-sectional area of 4.0 x 10-3 m2. Calculate the conductivity of the wire.", "images": [], "options": {"A": "0.80 x 102 Ω-1m-1", "B": "1.25 x 102 Ω-1m-1", "C": "2.02 x 102 Ω-1m-1", "D": "2.50 x 102 Ω-1m-1"}, "answer": "B", "explanation": "R=10Ω;L=5m;A=4.0x10-3m2  R=ρLA  ∴ρ=RAL=10 x 4.0 x 10-35=8.0x10-3Ωm  ∴σ=1ρ=18.0 x 10-3=1.25x102Ω-1m-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>51", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "Which of the following is a wind instrument", "images": [], "options": {"A": "Guitar", "B": "Organ", "C": "Violin", "D": "Piano"}, "answer": "B", "explanation": "Organ is a keyboard instrument operated by the player's hands and feet, in which pressurized air produces notes through a series of pipes organized in a scalelike rows.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1995>52", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A cell of e.m.f 1.5 V and internal resistance 2.5 Ω is connected in series with an ammeter of resistance 0.5 Ω and a load of resistance 7.0 Ω. Calculate the current in the circuit.", "images": [], "options": {"A": "0.15 A", "B": "0.20 A", "C": "2.10 A", "D": "3.00 A"}, "answer": "A", "explanation": "E = 1.5 V; R = 7 + 0.5 = 7.5 Ω; r = 0.5 Ω  E = I(R + r)  I=E(R + r)=15(7.5 + 2.5)=1.510=0.15A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>53", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "Which of the following statements are not true of a moving-coil milliammeter?  I. It can be used to measure alternating current  II. It has a linear scale  III. It can be adapted to read higher values of currents  IV. A resistor connected in parallel with the milliameter would convert it to a voltmeter", "images": [], "options": {"A": "I and IV only", "B": "II and III only", "C": "III and IV only", "D": "I, II and III only"}, "answer": "A", "explanation": "It cannot measure alternating current (A.C) because of the rapidly changing direction of the current and it is a resistor (multiplier) connected in 'series' with it that can be used to convert it to a voltmeter.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>54", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive nuclide of mass 6.0 g has a half-life of 8 days. Calculate the time during which 5.25 g of the nuclide would have decayed", "images": [], "options": {"A": "1 day", "B": "2 days", "C": "8 days", "D": "24 days"}, "answer": "D", "explanation": "t1/2 = 8 days    Amount that decayed = 5.25 g    Amount that remains after time t = 6 - 5.25 = 0.75 g    i.e after 8 days, 6 g would decay to 3 g (remains half of its original amount)    After another 8 days it would remain 1.5 g    Finally, in another 8 days it would now remain 0.75 g    ∴ After 3 half lives = 8 + 8 + 8 = 3 x 8 = 24 days      [OR]    t1/2 = 8 days    t1/2=0.693λ  i.e8=0.693λ==>λ=0.6938=0.086625day-1  Initial amount (No) = 6.0 g    Amount that decayed = 5.25 g    Amount that remains after time t (N) = 6 - 5.25 = 0.75 g    N = No e -λt    0.75 = 6 e -0.086625t  =0.756= e -0.086625t  Take the natural log (ln) of both sides    =ln(0.756)=-0.086625t  = -2.079 = -0.086625t    ∴t=-2.079-0.86625=24days", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>55", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "A moving-coil meter with an internal resistance of 100 Ω has a full-scale deflection when a current of 10 mA flows through it. What value of resistance would convert it to read 10 V at full-scale deflection?", "images": [], "options": {"A": "20 Ω", "B": "100 Ω", "C": "600 Ω", "D": "900 Ω"}, "answer": "D", "explanation": "V=IR;V=10V;R=100Ω;I=101000=0.01A  Total voltage = Voltage across moving-coil meter + Voltage across resistor (Rm)    i.e 10 = 0.01 x 100 + 0.01Rm    = 10 = 1 + 0.01Rm    = 0.01Rm = 10 - 1 = 9    ∴Rm=90.01=900Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>56", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following are emitted from a radioactive substance without altering either the nucleon number or the proton number of the substance?", "images": [], "options": {"A": "Protons", "B": "Neutrons", "C": "Gamma rays", "D": "Beta particles"}, "answer": "C", "explanation": "Gamma rays are emitted from a radioactive substance without altering either the nucleon number or the proton number of the substance. Gamma rays are a form of electromagnetic radiation, similar to X-rays and light, but with much higher energy. They are emitted during nuclear reactions, such as radioactive decay, but do not themselves carry any charge or mass, and therefore do not alter the nucleon or proton number of the emitting substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>57", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following is not a result of nuclear fission?", "images": [], "options": {"A": "Alpha particle", "B": "Beta particle", "C": "Gamma ray", "D": "X-ray"}, "answer": "D", "explanation": "X-rays are not a result of nuclear fission although they can used to cause nuclear fission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>58", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Calculate the energy carried by an X-ray of wavelength 6.0 x 10-10 m.   [Planck's constant = 6.6 x 10-34 Js, Velocity of light = 3 x 108 ms-1]", "images": [], "options": {"A": "3.3 x 10-12 J", "B": "3.3 x 10-16 J", "C": "1.1 x 10-16 J", "D": "3.3 x 10-24 J"}, "answer": "B", "explanation": "h = 6.6 x 10-34; c = 3 x 108 λ = 6.0 x 10-10 m    E=hf=hcλ=6.6 x 10-34 x 3 x 1086.0 x 10-10=3.3x10(-34 + 8 + 10)  ∴ E = 3.3 x 10-16 J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1995>59", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following cannot be explained by the molecular theory of matter?", "images": [], "options": {"A": "Conduction", "B": "Radiation", "C": "Convection", "D": "Expansion"}, "answer": "B", "explanation": "The molecular theory of matter, also known as the kinetic theory of matter, explains the behavior of matter based on the idea that matter is made up of tiny particles that are always in motion. This theory can explain conduction, convection, and expansion, which are all processes that involve the movement of particles. However, it cannot explain radiation, which involves the emission of energy as electromagnetic waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1995>60", "subject": "Physics", "year": "1995", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following is used for shielding radioactive fall-outs?", "images": [], "options": {"A": "Plastic", "B": "Wood", "C": "Textile", "D": "Lead"}, "answer": "D", "explanation": "Lead is used because of its high density and large number of electrons, it is well suited to scattering x-rays and gamma-rays. When the radiation attempts to pass through lead, its electrons absorb and scatter the energy. Eventually though, the lead will degrade from the energy to which it is exposed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>1", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "The diagram below represents a portion of a micrometer screw gauge in which the horizontal scale is in millimetre. What is the reading on the instrument?", "images": ["Physics/imgs/1996/phy_96_one.png"], "options": {"A": "3.72 mm", "B": "3.50 mm", "C": "3.30 mm", "D": "3.22 mm"}, "answer": "D", "explanation": "3+22100=3+0.22=3.22mm  ∴ the reading on the instrument is 3.22 mm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>2", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A loaded test-tube which floats upright in water is carefully and slightly depressed and then released. Which of the following best describes the subsequent motion of the test-tube?", "images": [], "options": {"A": "Circular", "B": "Rotational", "C": "Random", "D": "Oscillatory"}, "answer": "D", "explanation": "A loaded test-tube slightly depressed and released undergoes a simple harmonic motion which is an oscillatory motion", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>3", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "The dagram above illustrates the velocity-time graph of the motion of a body. Calculate the total distance travelled by the body.", "images": ["Physics/imgs/1996/phy_96_three.png"], "options": {"A": "50 m", "B": "65 m", "C": "175 m", "D": "225 m"}, "answer": "D", "explanation": "Distance covered by the body = Trapezium A + Rectangle B + Triangle C    ==> Trapezium A = 1/2(a + b)h = 1/2(10 + 20)5 = 1/2(30)5 = 15 x 5 = 75 m    Rectangle B = L x B = 20 x 5 = 100 m    Triangle C = 1/2bh = 1/2 x 5 x 20 = 5 x 10 = 50 m    ∴ Total distance = 75 + 100 + 50 = 225 m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>4", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A ball of mass 5.0 kg hits a smooth vertical wall normally with a speed of 2 ms-1 and rebounds with the same speed. Determine the impulse experienced by the ball.", "images": [], "options": {"A": "20.0 kgms-1", "B": "10.0 kgms-1", "C": "5.0 kgms-1", "D": "0.0 kgms-1"}, "answer": "A", "explanation": "Impulse is the change in momentum of an object when the object is acted upon by a force for an interval of time. In this case, the ball hits the wall and rebounds with the same speed but in the opposite direction. So, the change in momentum is 2*5 (initial momentum) + 2*5 (final momentum) = 20 kgms-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>5", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY", "question": "A rocket is launched from the surface of the earth. If the radius of the earth is 4.6 x 106 m and the acceleration of free fall due to gravity is 10 ms-2, calculate the escape velocity of the rocket.", "images": [], "options": {"A": "2.53 x 104 ms-1", "B": "9.6 x 103 ms-1", "C": "8.00 x 103 ms-1", "D": "4.23 x 103 ms-1"}, "answer": "B", "explanation": "r = 4.6 x 106 m; g = 10 ms-2; v = ?  escape velocity = √2gr = √(2 x 10 x 4.6 x 106)  = √(92 x 106) = 9.6 x 103 ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>6", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MACHINES :", "question": "The velocity ratio and efficiency of a system of pulleys are 6 and 80% respectively. How much effort is required to lift a load of mass 120 kg with this system.  [g = 10 ms-2]", "images": [], "options": {"A": "25 N", "B": "90 N", "C": "96 N", "D": "250 N"}, "answer": "D", "explanation": "V.R = 6; ε = 80%; E = ?; L = 120 kg = 120 x 10 = 1200 N; g = 10 ms-2; ε = L/E x 1/V.R x 100%   80%=1200Ex16x100%  =80=1200Ex16x100  =80100=12006E  =80x6E=1200x100  =480E=120000  =E=120000480  ∴E=250N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>7", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MACHINES :", "question": "Two spanners X and Y of lengths 15 cm and 20 cm respectively are used in turn to give a screw of pitch 2 mm one complete rotation. If RX and RY are the respective velocity ratios of the spanners, the the ratio RX : RY is", "images": [], "options": {"A": "1 : 50", "B": "3 : 20", "C": "3 : 4", "D": "4 : 3"}, "answer": "C", "explanation": "[Let your units be in cm]  IfRX=2πap=2π x 150.2andRY=2πap=2π x 200.2  RX:RY=2π x 150.2:2π x 200.2=2πx75:2πx100=3:4", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>8", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "The magnitude of the force required to make an object of mass M move with a speed V in a circular path of radius R is given by the expression", "images": [], "options": {"A": "mrv", "B": "(mr)2v", "C": "mv2r", "D": "mvr2"}, "answer": "C", "explanation": "The force required to make an object of mass M move with a speed V in a circular path of radius R is given by the centripetal force formula F = mv^2/r. Therefore, the correct answer is mv^2/r.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>9", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 4.2 kg moving with velocity 10 ms-1 due east, hits a stationary body of mass 2.8 kg. If they stick together after collision and move with velocity V due east, calculate the value of V.", "images": [], "options": {"A": "3 ms-1", "B": "6 ms-1", "C": "7 ms-1", "D": "15 ms-1"}, "answer": "B", "explanation": "m1 = 4.2 kg; u1 = 10 ms-1; u2 = 0; m2 = 2.8 kg; v = ?  momentum before collision = momentum after collision  m1u1 + m2u2 = (m1 + m2)v [v1 = v2 = v since the bodies stick together after collision]  = 4.2 x 10 = (4.2 + 2.8)v  = 42 = 7v  ∴v=427=6ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>10", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 2 kg is suspended from the ceiling of a lift with light inextensible string. If the lift moves upwards with acceleration of 2ms-2, calculate the magnitude of the tension in the string.  [g = 10 ms-2]", "images": [], "options": {"A": "24 N", "B": "20 N", "C": "16 N", "D": "4 N"}, "answer": "A", "explanation": "The tension in the string is the force that balances the weight of the body and the force due to the acceleration of the lift. The weight of the body is its mass times the acceleration due to gravity, which is 2 kg * 10 m/s^2 = 20 N. The force due to the acceleration of the lift is the mass of the body times the acceleration of the lift, which is 2 kg * 2 m/s^2 = 4 N. Therefore, the tension in the string is 20 N + 4 N = 24 N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>11", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A stationary object of mass 4 kg is set in motion by a net force of 50 N. If the object attains a speed of 5 ms-1 in time t. Calculate the value of t.", "images": [], "options": {"A": "0.20 s", "B": "0.40 s", "C": "0.63 s", "D": "0.80 s"}, "answer": "B", "explanation": "F = 50 N; m = 4 kg; u = 0; v = 5 ms-1; t = ?  F=ma;a=Fm=504=12.5ms-2  v = u + at  = 5 = 0 + 12.5t  = 5 = 12.5t  ∴t=512.5=0.40s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>12", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "Two simple pendula X and Y make 400 and 500 oscillations respectively in equal time. If the period of oscillations of X is 1.5 seconds, what is the period of oscillations of Y?", "images": [], "options": {"A": "0.53 s", "B": "0.83 s", "C": "1.20 s", "D": "1.50 s"}, "answer": "C", "explanation": "T=tn;t=Tn  since tX = tY  ∴1.5x400=500xt;t=1.5 x 400500=65=1.20s", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>13", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "A platinum-resistance thermometer has a resistance of 5 Ω at 0oC and 9 Ω at 100oC. Assuming that resistance changes uniformly with temperature, calculate the resistance of the thermometer when the temperature is 45oC.", "images": [], "options": {"A": "13.9 Ω", "B": "8.9 Ω", "C": "6.8 Ω", "D": "3.2 Ω"}, "answer": "C", "explanation": "R1 = 5 Ω at 0oC; R2 = 9 Ω at 100oC; R = ? at 45oC  45 - 0100 - 0=R - 59 - 5  45100=R - 54  180100=R-5  1.8 = R - 5  ∴ R = 1.8 + 5 = 6.8 Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>14", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The linear expansivity of a metal P is twice that of another metal Q. When these materials are heated through the same temperature change, their increase in length is the same. Calculate the ratio of the original length of P to that of Q.", "images": [], "options": {"A": "1 : 4", "B": "1 : 2", "C": "2 : 1", "D": "4 : 1"}, "answer": "B", "explanation": "αP = 2αQ  ΔθP = ΔθQ  ΔLP = ΔLQ  LP : LQ = ?  α=ΔLLΔθ  L=ΔLαΔθ  LP : LQ=ΔLPαPΔθP:ΔLQαQΔθQ  =ΔLQ2αQΔθQ : ΔLQαQΔθQ  =ΔLQ2αQΔθQ x αQΔθQΔLQ = 12  ∴ LP : LQ = 1 : 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>15", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure of a fixed mass of a gas is 2.0 x 105 Nm-2 at a known temperature. Assuming that the temperature remains constant, what will be the pressure of the gas if its volume is halved?", "images": [], "options": {"A": "1.0 x 105 Nm-2", "B": "2.0 x 105 Nm-2", "C": "3.0 x 105 Nm-2", "D": "4.0 x 105 Nm-2"}, "answer": "D", "explanation": "P1 = 2.0 x 105 Nm-2; V1 = V cm3; V2 = 1/2V1; P1 = ?    P1V1 = P2V2    2.0 x 105 x V = P2 x 1/2V    2.0 x 105 = P2 x 1/2    ∴ P2 = 2.0 x 105 x 2 = 4.0 x 105 Nm-2", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>16", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statements is not correct?", "images": [], "options": {"A": "Heat energy can be transformed into mechanical energy", "B": "The total heat content of a body is the sum of the kinetic energies of its molecules", "C": "If a body is heated, its molecules move faster", "D": "If a body is cooled, molecular movement remains constant"}, "answer": "D", "explanation": "The statement 'If a body is cooled, molecular movement remains constant' is incorrect. When a body is cooled, the kinetic energy of its molecules decreases, which results in a decrease in the speed of molecular movement. Therefore, molecular movement does not remain constant when a body is cooled.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>17", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "A 400 W immersion heater is used to heat a liquid of mass 0.5 kg. If the temperature of the liquid increses by 2.5oC in one second, calculate the specific heat capacity of the liquid. (Neglect heat losses to the sorroundings)", "images": [], "options": {"A": "80 Jkg-1K-1", "B": "320 Jkg-1K-1", "C": "500 Jkg-1K-1", "D": "1200 Jkg-1K-1"}, "answer": "B", "explanation": "P = 400 W; m = 0.5 kg; Δθ = 2.5oC; c = ?; t = 1 s  Pt = mcΔθ  = 400 x 1 = 0.5 x c x 2.5  = 400 = 1.25c  ∴c=4001.25=320Jkg-1K-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>18", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "What is the difference in the amount of heat given out by 4 kg of steam and 4 kg of water when both are cooled from 100oC to 80oC.  [Specific latent heat of steam = 2,260,000 Jkg-1]  [Specific heat capacity of water = 4,200 Jkg-1K-1]", "images": [], "options": {"A": "336,000 J", "B": "672,000 J", "C": "8,704,000 J", "D": "9,040,000 J"}, "answer": "D", "explanation": "Q of steam = ml + mcΔθ  Q of water = mcΔθ  [since steam and water have the same mass and temperature difference]  ∴ Q of steam - Q of water = ml + mcΔθ - (mcΔθ) = ml = 4 x 2,260,000 = 9,040,000 J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>19", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The heating element in an kettle circuit is usually located near the bottom of the kettle because", "images": [], "options": {"A": "Water is a good conductor of heat", "B": "Heat can be more quickly radiated to all parts of the water", "C": "No heat can be lost to the sorroundings", "D": "The convectional currents which are set up can carry heat to all parts of the water"}, "answer": "D", "explanation": "The heating element is at the bottom of an electric kettle so that the water at the bottom, when heated, expands and thus becomes lighter. And as it becomes lighter, it moves up and the heavier ones at the top comes down and the cycle continues thereby setting up convectional flow of currents", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>20", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The inside of a vacuum flask is usually coated with silver to reduce heat loss by", "images": [], "options": {"A": "convection", "B": "conduction", "C": "radiation", "D": "absorption"}, "answer": "C", "explanation": "It is found that, for a given temperature, a dull black surface radiates most and a highly polished surface radiates least. So, silver being a highly polished surface, prevents heat loss by radiation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>21", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : VAPOUR AND VAPOUR PRESSURE", "question": "The saturated vapour pressure of a liquid increases as the", "images": [], "options": {"A": "volume of the liquid increases", "B": "volume of the liquid decreases", "C": "temperature of the liquid increases", "D": "temperature of the liquid decreases"}, "answer": "C", "explanation": "The saturated vapour pressure of a liquid is the pressure exerted by a vapour in thermodynamic equilibrium with its condensed phases at a given temperature. It increases as the temperature of the liquid increases because the molecules have more kinetic energy to escape from the liquid surface and become a gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>22", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY AND THE WEATHER", "question": "Cloud formation is the direct result of", "images": [], "options": {"A": "precipitation", "B": "vaporisation", "C": "fusion", "D": "sublimation"}, "answer": "B", "explanation": "Cloud formation is the direct result of vaporisation. When water on the earth's surface is heated by the sun, it evaporates to form water vapour. This water vapour rises, cools, and condenses to form clouds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>23", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "Water boils at a lower temperature when heated at the top of a mountain that at sea-level because at the top of the mountain the", "images": [], "options": {"A": "saturation vapour pressure of water is higher than at sea-level", "B": "sun adds more heat to the water", "C": "temperature is lower than at sea level", "D": "pressure of the atmosphere is lower"}, "answer": "D", "explanation": "Liquid boils at a lower temperature at the top of a mountain than at sea level.  This is because the pressure at the top of a mountain is low. As the pressure is lowered, the boiling point is lowered", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>24", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "The main reason why rice cooks faster in pressure cooker than in cooking pot is that", "images": [], "options": {"A": "less heat escapes from the cooker", "B": "the vapour pressure of the cooker is constant", "C": "the rice is not affected by the draught over the cooker", "D": "The boiling point of water in the cooker is raised"}, "answer": "D", "explanation": "​Food cooks faster in a pressure cooker. Its because the pressure increases inside the cooker, which also increases the boiling point of water. ​So, more heat is required to reach the boiling point and is sufficient to cook food in a reduced time", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>25", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "In which of the following media would sound waves travel fastest?", "images": [], "options": {"A": "Kerosene", "B": "Air", "C": "Water", "D": "Iron"}, "answer": "D", "explanation": "Sound travels faster in solids as compared to liquids and gases as the particles are more tightly packed. The closer the molecules, the tighter their bonds, the less time it take to reach to other molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>26", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A ray of light strikes a plane mirror at a glancing angle of 50o. Calculate the angle between the incident and reflected ray", "images": [], "options": {"A": "20o", "B": "40o", "C": "60o", "D": "80o"}, "answer": "D", "explanation": "i = 90o - 50o = 40o  i = r  ∴ total angle between i and r = 40o + 40o = 80o", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>27", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "A boy walks away from a plane mirror at a speed of 3 ms-1 in a direction normal to the plane of the mirror. At what speed is his image approaching him?", "images": [], "options": {"A": "9.0 ms-1", "B": "6.0 ms-1", "C": "4.5 ms-1", "D": "0.0 ms-1"}, "answer": "B", "explanation": "Velocity of image w.r.t boy = velocity of object - velocity of image    velocity w.r.t to boy = v - (-v)    = 3.0 - (-3.0)    The image velocity is 6.0 ms-1 towards the boy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>28", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The graph above shows the relationship between sin i and sin r for a ray of light in air incident on a liqiud surface. If i and r are respectively angles of incidence and refraction, deduce the refractive index of the liquid from the graph.", "images": ["Physics/imgs/1996/phy_96_two_eight.png"], "options": {"A": "1.63", "B": "1.50", "C": "1.33", "D": "1.25"}, "answer": "D", "explanation": "The refractive index is the slope of the graph  =1.0 - 0.20.8 - 0.18=0.80.62=1.25", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>29", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "When a ray of light is incident normally on an air-glass interface, its angle of refraction is", "images": [], "options": {"A": "0o", "B": "42o", "C": "45o", "D": "60o"}, "answer": "A", "explanation": "No refraction as it goes through at right angle to the surface of the glass prism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>30", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light is incident on a glass block as shown in the diagram above. If the reflected and refracted rays are perpendicular to each other, what is the refractive index of the glass relative to air?", "images": ["Physics/imgs/1996/phy_96_three_zero.png"], "options": {"A": "1.65", "B": "1.58", "C": "1.52", "D": "1.48"}, "answer": "D", "explanation": "angle of incidence = 56o (given)  angle of incidence = angle of reflection = 56o  angle of reflection + angle of refraction + 90o = 180o (sum of angles on a straight line)  ∴ angle of reflection + angle of refraction = 90o  = 56o + angle of refraction = 90o  = angle of refraction = 90o - 56o = 34o  nair = 1  sin isin r=nglass1  sin 56osin 34o=nglass1  0.8290.559=nglass  ∴ nglass relative to air = 1.48", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>31", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The refractive index of a medium relative to air is 1.8. Calculate the critical angle for the medium correct to the nearest degree", "images": [], "options": {"A": "18o", "B": "34o", "C": "45o", "D": "68o"}, "answer": "B", "explanation": "The critical angle (c) can be calculated using the formula c = arcsin(1/n), where n is the refractive index. In this case, n = 1.8. Therefore, c = arcsin(1/1.8) = 34 degrees. The critical angle is the angle of incidence beyond which rays of light passing through a denser medium to the surface of a less dense medium are no longer refracted but totally internally reflected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>32", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens of focal length 5 cm forms a virtual image which is 10 cm from the lens. How far from the lens is the object?", "images": [], "options": {"A": "2.0 cm", "B": "3.3 cm", "C": "5.0 cm", "D": "10.0 cm"}, "answer": "D", "explanation": "f=5cm;v=10cm;u=?  1f=1v+1u  15=110+1u  1u=15-110  1u=2 - 110=110  ∴u=10.0cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>33", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "Which of the following instrument produces sound by the vibration of air column?", "images": [], "options": {"A": "Piano", "B": "Guitar", "C": "Flute", "D": "Handbell"}, "answer": "C", "explanation": "Flute players can change the pitch by changing the length of the tube (air column) with the fingers or by increasing the air speed in order to force the sound waves to the next note in the harmonic overtone series.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>34", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "The walls and ceilings of many standard auditoria are covered with perforated pads to", "images": [], "options": {"A": "increase the intensity of sound waves", "B": "increase the loudness of sound waves", "C": "reduce the effect of reverbrations of sound waves", "D": "increase the interference effect of sound waves"}, "answer": "C", "explanation": "Reverberation (also known as reverb), in acoustics, is a persistence of sound after it is produced. Reverberation is created when a sound or signal is reflected. This causes numerous reflections to build up and then decay as the sound is absorbed by the surfaces of objects in the space – which could include furniture, people, and air", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>35", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The string of length 1.0 m vibrates in 10 loops. If the total mass of the string is 1.0 x 10-3 kg and the tension in it is 10 N, calculate the frequency of the vibration.", "images": [], "options": {"A": "50 Hz", "B": "100 Hz", "C": "250 Hz", "D": "500 Hz"}, "answer": "C", "explanation": "fo =12l√Tμ  T=10N;m=1.0x10-3kg;l=1.0m;μ=ml=1.0 x 10-31.0=1.0x10-3kgm-1  fo =12 x 1√101.0 x 10-3  fo =12√10000  fo =12x 100  fo =50 Hz  Recall:10loops  10loops(10crestand10troughs)=102=5wavelengths  ∴f=5fo=5x50=250Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>36", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "A siren has a disc of 64 holes and makes 20 revolutions per second. Calculate the frequency of the sound from the siren.", "images": [], "options": {"A": "3.2 Hz", "B": "16.0 Hz", "C": "20.0 Hz", "D": "1280.0 Hz"}, "answer": "D", "explanation": "The frequency of the sound from the siren can be calculated by multiplying the number of holes in the disc by the number of revolutions per second. This is because each revolution of the disc will produce a sound wave for each hole in the disc. Therefore, the frequency of the sound is 64 holes * 20 revolutions per second = 1280 Hz.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>37", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "The distance between two successive crest of a water is 1 m. If a particle on the surface of the water makes two complete vertical oscillations in 1 second. Calculate the speed of the wave.", "images": [], "options": {"A": "0.5 ms-1", "B": "1.0 ms-1", "C": "2.0 ms-1", "D": "3.0 ms-1"}, "answer": "C", "explanation": "The speed of a wave is given by the product of its wavelength and frequency. In this case, the wavelength is the distance between two successive crests, which is 1 m, and the frequency is the number of complete oscillations per second, which is 2 Hz. Therefore, the speed of the wave is 1 m * 2 Hz = 2 ms-1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>38", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A sound wave of velocity 350 ms-1 is directed towards the surface of water. If the ratio of the wavelength of sound in water to that in air is 425 : 100, calculate the velocity of the wave in water.", "images": [], "options": {"A": "82.4 ms-1", "B": "148.8 ms-1", "C": "350.0 ms-1", "D": "1487.5 ms-1"}, "answer": "D", "explanation": "va = 350 ms-1  λw : λa = 425 : 100 ==> λa : λw = 100 : 425  vw = ?  vavw=fλafλw==>vavw=λaλw  350vw=100425==>350 x 425=100vw  ∴vw=350 x 425100 = 148750100 = 1487.5 ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>39", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The speed of sound in air is 330 ms-1. How far from the centre of a storm is an observer who hears a thunder clap 2 s after the lightning flash?  (Neglect the time taken by light to travel to the observer)", "images": [], "options": {"A": "1320 m", "B": "660 m", "C": "600 m", "D": "330 m"}, "answer": "B", "explanation": "v = 330 ms-1; t = 2 s; d = vt = 330 x 2 = 660 m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>40", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "The diagram below illustrates a variation of the displacement y of a wave particle with time t. If the velocity of the wave is 250 ms-1, calculate the distance between two successive particles which are in phase.", "images": ["Physics/imgs/1996/PLHJ8H.png"], "options": {"A": "2.0 m", "B": "2.5 m", "C": "3.0 m", "D": "5.0 m"}, "answer": "D", "explanation": "distance between two successive particles which are in phase = wavelength (λ)  v = fλ  ∴λ=vf=vT=250x0.02=5.0m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>41", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "The diagram above represents a stationary wave set up in a string which is fixed at both ends. If the frequency of the wave is 256 Hz and the distance between N1 and N2 equals 1.5 m, calculate the speed of the wave.", "images": ["Physics/imgs/1996/PLHJ8H.png"], "options": {"A": "128 ms-1", "B": "192 ms-1", "C": "384 ms-1", "D": "768 ms-1"}, "answer": "D", "explanation": "L = 1/2λ = 1.5 m; λ = 2 x 1.5 = 3 m; f = 256 Hz; v = ?    v = fλ = 256 x 3 = 768 ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>42", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "Calculate the power delivered by a 3-phase line of its voltage and current are 132 KV and 60 A respectively.", "images": [], "options": {"A": "2.38 x 107 W", "B": "7.92 x 106 W", "C": "3.96 x 106 W", "D": "2.64 x 106 W"}, "answer": "B", "explanation": "V = 132 KV; I = 60 A; P = IV = 60 x 132000 = 7920000 = 7.92 x 106 W", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>43", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "The main portion of the mouth piece of a telephone is to convert sound energy into", "images": [], "options": {"A": "Heat energy", "B": "light energy", "C": "chemical energy", "D": "electrical energy"}, "answer": "D", "explanation": "The main function of the mouthpiece of a telephone is to convert sound energy into electrical energy. This is done through a process called transduction, where the sound waves cause a diaphragm to vibrate, which in turn moves a coil of wire in a magnetic field, generating an electrical signal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>44", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "Which of the following is not a component of a d.c electric motor?", "images": [], "options": {"A": "commutator", "B": "field magnet", "C": "slip rings", "D": "armature"}, "answer": "C", "explanation": "Functionally, slip rings provide a continuous transfer of power, signals, or data. Specifically, in AC motors, they transfer resistance to the rotor windings. Commutators, on the other hand, are used in DC motors to reverse the polarity of current in the armature windings.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>45", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The diagram below illustrates the conversions of a galvanometer of resistance 2 Ω to an ammeter. The galvanometer gives a full-scale deflection for a current of 10 mA. Calculate the value of R.", "images": ["Physics/imgs/1996/phy_96_four_five.png"], "options": {"A": "2.0 x 103 Ω", "B": "2.0 x 102 Ω", "C": "2.0 x 10-1 Ω", "D": "2.0 x 10-3 Ω"}, "answer": "D", "explanation": "Ig = 10 mA = 0.01 A  Is = 10 - 0.01 = 9.99 A  Rg = 2 Ω  Rs = ?  V = IR  Voltage in galvanometer = Voltage in shunt  Ig x Rg = Is x Rs  0.01 x 2 = 9.99Rs  0.02 = 9.99Rs  Rs=0.029.99=2.0x10-3Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>46", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire of length 100 cm and cross-sectional area 2.0 x 103 cm2 has a resistance of 0.10 Ω. Calculate its electrical conductivity", "images": [], "options": {"A": "5.0 x 107 Ω-1cm-1", "B": "5.0 x 106 Ω-1cm-1", "C": "2.0 x 106 Ω-1cm-1", "D": "5.0 x 105 Ω-1cm-1"}, "answer": "D", "explanation": "L = 100 cm; A = 2.0 x 10-3 cm2; R = 0.10 Ω; σ = ?  RαLA ==> R=ρLA==> ρ=RALand σ=1ρ  ∴σ=LRA=1000.10 x 2.0 x 10-3=5.0x105Ω-1cm-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>47", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "Lenz's law of electromagnetic induction states that", "images": [], "options": {"A": "e.m.f is induced in the circuit whenever there is a change in the magnitude of flux linked with the circuit", "B": "the induced current in a conductor is in such a direction as to oppose the change producing it", "C": "the magnitude of the induced e.m.f in a circuit is proportional to the rate of change of the number of lines of force linking the circuit", "D": "a force exerted on a current carrying conductor in a magnetic field"}, "answer": "B", "explanation": "Lenz's law, in electromagnetism, states that an induced electric current flows in a direction such that the current opposes the change that induced it. This law was deduced in 1834 by the Russian physicist Heinrich Friedrich Emil Lenz (1804–65).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>48", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A cell of e.m.f 1.5 V is connected in series with a resistor of resistance 3 Ω. A high-resistance voltmeter connected across the cell registers only 0.9 V. Calculate the internal resistance of the cell.", "images": [], "options": {"A": "1.8 Ω", "B": "2.0 Ω", "C": "2.4 Ω", "D": "4.5 Ω"}, "answer": "B", "explanation": "E = 1.5 V; R = 3 Ω; V = 0.9 V; r = ?; V = IR  ∴I=VR=0.93=0.3A;FromI=ER + r=0.3  0.3=1.53 + r==>0.3(3+r)=1.5  = 0.9 + 0.3r = 1.5  = 0.3r = 1.5 - 0.9 = 0.6  ∴r=0.60.3=2.0Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>49", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "Soft iron is used in making the armature of an electric bell because it", "images": [], "options": {"A": "retains it magnetism for a long time", "B": "loses it magnetism", "C": "produces permanet magnets", "D": "is not easily magnetised"}, "answer": "B", "explanation": "The soft iron bar acquires the magnetic properties only when an electric current flows through the solenoid and loses the magnetic properties as soon as the current is switched off. Soft iron can be easily magnetized and demagnetized. That's why soft iron is used as the core of the electromagnet in an electric bell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>50", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The diagram beside illustrates an isolated metal sphere carrying charge W in a medium whose permitivity is εo. The magnitude of the electric field intensity P can be expressed as", "images": ["Physics/imgs/1996/phy_96_five_zero.png"], "options": {"A": "Q24πεor2", "B": "Q4πεor2", "C": "Q4πεor", "D": "Q24πεor"}, "answer": "B", "explanation": "P = Q4πεor2 it is measured in NC-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>51", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The diagram beside illustrates an isolated metal sphere carrying charge W in a medium whose permitivity is εo. The magnitude of the electric field intensity P can be expressed as The electric potential of a point P in the diagram on Question above can be expressed as", "images": ["Physics/imgs/1996/phy_96_five_zero.png"], "options": {"A": "Q24πεor", "B": "Q4πεor2", "C": "Q24πεor2", "D": "Q4πεor"}, "answer": "D", "explanation": "It can be expressed as:       V = Q4πεor", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>52", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Calculate the amount of heat generated in an external load of resistance 8 Ω, if an alternating current of peak value 5 A is passed through it for 100 s.", "images": [], "options": {"A": "20,000 J", "B": "10,000 J", "C": "5,000 J", "D": "4,000 J"}, "answer": "B", "explanation": "Io=5A;R=8Ω;t=100s  Ir.m.s=Io√2=5√2A  I2r.m.s=252A  H=I2r.m.sRt  ∴H=252x8x100=25x4x100=10,000J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>53", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "In the diagram below the resistor has a resistance of 8 Ω while the reactance of the inductor and the capacitor are 10 Ω and 16 Ω respectively. Calculate the current in the circuit.", "images": ["Physics/imgs/1996/phy_96_five_three.png"], "options": {"A": "3.6 A", "B": "3.8 A", "C": "9.2 A", "D": "13.0 A"}, "answer": "D", "explanation": "Z = √(XL - XC)2 + R2 = √(16 - 10)2 + 82  Z = √62 + 82  Z = √36 + 64 = √100  Z = 10 Ω  V=IZ;I=VZ=13010=13.0A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>54", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "The resistance in an R-C is 5 Ω. If the impedance of the circuit is 13 Ω. Calculate the reactance of the capacitor.", "images": [], "options": {"A": "65 Ω", "B": "18 Ω", "C": "16 Ω", "D": "12 Ω"}, "answer": "D", "explanation": "Z = 13 Ω ==> Z = √XC2 + R2    13 = √XC2 + 52    132 = XC2 + 52    169 = XC2 + 25    XC2 = 169 - 25 = 144    XC = 12 Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1996>55", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "What is the decay constant of a radioactive element whose half life is 3 seconds", "images": [], "options": {"A": "0.132 s-1", "B": "0.23 s-1", "C": "0.347 s-1", "D": "0.693 s-1"}, "answer": "B", "explanation": "t1/2=3s  t12=0.693λ  λ=0.693t1/2=0.6933=0.23s-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>56", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "Which of the following substance is most viscous at room temperature", "images": [], "options": {"A": "Water", "B": "Alcohol", "C": "Petrol", "D": "Palm Oil"}, "answer": "D", "explanation": "Viscosity is the property of a given liquid that describes its resistance to flow. A highly viscous fluid tends to be thick, like honey or cold maple syrup. Compared to a relatively non viscous fluid, such as water, highly viscous liquids flow much more slowly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>57", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following is not part of the electromagnetic spectrum?", "images": [], "options": {"A": "Radio wave", "B": "Gamma ray", "C": "Infra-red ray", "D": "Alpha particle"}, "answer": "D", "explanation": "Electromagnetic energy travels in waves and spans a broad spectrum from very long radio waves to very short gamma rays.   In order from highest to lowest energy, the sections of the EM spectrum are named: gamma rays, X-rays, ultraviolet radiation, visible light, infrared radiation, and radio waves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1996>58", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following is used in nuclear reactor to slow down fast-moving neutrons?", "images": [], "options": {"A": "carbondioxide gas", "B": "liquid sodium metal", "C": "concrete shield", "D": "graphite rods"}, "answer": "D", "explanation": "Graphite rods are used as moderators in a nuclear reactor. The primary reason that moderators are used in a nuclear reactor is to slow down the neutrons produced by fission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>59", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Which of the following particles/rays do not originate from the nucleus of an atom?", "images": [], "options": {"A": "Alpha particles", "B": "Beta particles", "C": "Gamma rays", "D": "X-rays"}, "answer": "D", "explanation": "X-rays do not originate from the nucleus of an atom. They are produced when electrons in the outer shells of atoms fall into a lower energy level. The energy difference between the two levels is emitted as an X-ray. On the other hand, alpha particles, beta particles, and gamma rays are all products of nuclear reactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1996>60", "subject": "Physics", "year": "1996", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The count rate of an alpha-particle source is 400 per minute. If the half-life of the source is 5 days, what would be the count rate per minute after 15 days.", "images": [], "options": {"A": "20", "B": "25", "C": "50", "D": "200"}, "answer": "C", "explanation": "Initial count rate = 400 per minute  t1/2 = 5 days  t = 15 days  Countrate=Initial count rate2NwhereNisthenumberofhalflives  N= tt1/2 = 155=3  Countrate=40023=4008=50perminute", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>1", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "An object of mass 0.40 kg attached to the end of a string is whirled round in a horizontal circle of radius 2.0 m with a constant speed of 8 ms-1. Calculate the angular velocity of the object", "images": [], "options": {"A": "0.8 rads-1", "B": "2.0 rads-1", "C": "4.0 rads-1", "D": "8.0 rads-1"}, "answer": "C", "explanation": "v = ωr; v = 8 ms-1; r = 2.0 m; ω = ?  ω=vr=82=4.0rads-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>2", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY", "question": "An object falls freely from a height of 25 m unto the roof a building of 5 m high. Calculate the velocity with which the object strikes the roof.  [g = 10 ms-2]", "images": [], "options": {"A": "17.3 ms-1", "B": "20.0 ms-1", "C": "24.5 ms-1", "D": "125.0 ms-1"}, "answer": "B", "explanation": "h = 25 m; height of building = 5 m; H = 25 - 5 = 20 m; u = 0; g = 10 ms-2; v = ?  v2 = u2 + 2gh  v2 = 2 x 10 x 20  v2 = 400  v = √400  ∴ v = 20.0 ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>3", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 20 kg is set in motion by two forces 3 N and 4 N, acting at right angles to each other. Determine its magnitude of acceleration", "images": [], "options": {"A": "400 ms-2", "B": "2.89 ms-2", "C": "0.35 ms-2", "D": "0.25 ms-2"}, "answer": "D", "explanation": "m = 20 kg  |FR|2 = 32 + 42 = 9 + 16  |FR|2 = 25  |FR| = 5 N  F = ma; 5 = 20a  a=520=0.25ms-2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>4", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A ball of mass 0.1 kg approaching a tennis player with a velocity of 10 ms-1, is hit back in the opposite direction with a velocity of 15 ms-1. If the time of impact between the racket and the ball is 0.01 s, calculate the magnitude of force with which the ball is hit.", "images": [], "options": {"A": "5000 N", "B": "500 N", "C": "250 N", "D": "50 N"}, "answer": "C", "explanation": "m = 0.1 kg; u = -10 ms-1; v = 15 ms-1; t = 0.01s; F = ?  impulse = Ft = m(v - u)  F x 0.01 = 0.1(15 - (-10))  F x 0.01 = 0.1(15 + 10)  0.01F = 0.1 x 25 = 2.5  F=2.50.01=250N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>5", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "Two blocks of the same dimensions, one steel and the other wooden are dropped simultaneously from the same height. If they fall freely, neglecting air resistance, the", "images": [], "options": {"A": "two blocks hit the ground simultaneously because they have the same acceleration.", "B": "two blocks reach the ground at the same time because their dimensions are the same.", "C": "wooden block, being lighter than the steel block, reaches the ground first.", "D": "steel block reaches the ground first because it is denser than the wooden block."}, "answer": "A", "explanation": "Because Earth gives everything the exact same acceleration, objects with different masses will still hit the ground at the same time if they are dropped from the same height.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>6", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS", "question": "Two forces 3 N and 4 N act on a body in directions due north and due east respectively. Calculate their equilibrant.", "images": [], "options": {"A": "5 N, 53o east of north", "B": "5 N, 53o west of south", "C": "5 N, 37o north of east", "D": "7 N, 37o west of north"}, "answer": "C", "explanation": "Y2 = 42 + 32; Y2 = 16 + 9 = 25;    Y = √25 = 5    tan θ = 3/4    θ = tan-1 3/4 = 37o    5 N, 37o north of east    since 4 N is the greater force ==> it will push towards east.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>7", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "A missile weighing 400 N on the earth's surface is shot into the atmosphere to an altitude of 6.40 x 106 m. Taking the earth as a sphere of radius 6 x 106 m and assuming the inverse-square law of universal gravitation, what would be the weight of the missile at the altitude?", "images": [], "options": {"A": "100 N", "B": "200 N", "C": "400 N", "D": "800 N"}, "answer": "A", "explanation": "Fe=400N;M=massofearth;h=6.40x106m;m=massofmissile;r=6.40x106m  G=universalgravitationconstant  Fe=GMmr2==>G=Fer2Mm  atanaltitudeofh=6.40x106m  R=r+h=6.40x106+6.40x106=12.80x106m  F=GMmR2=Fer2MmxMmR2  F=Fer2R2=400 x (6.40 x 106)2(12.80 x 106)2  =400 x 6.402 x 101212.802 x 1012=400 x 6.40212.802  =16384163.38=100N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>8", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "MACHINES :", "question": "In the diagram below, XY represents a plank used to lift a load from a point X on the ground onto a horizontal platform YP. What is the velocity ratio of the plank?", "images": ["Physics/imgs/1997/phy_97_eight.png"], "options": {"A": "XYZY", "B": "XYXZ", "C": "ZYXZ", "D": "XZXY"}, "answer": "A", "explanation": "V.R=Distance moved by effortDistance moved by effort=XYZY", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>9", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS", "question": "A uniform bar 15 m long, is balanced on a pivot placed at its mid-point. A boy of mass 55 kg sits on one arm of the bar at a point 5 m away from the pivot. What mass can be placed at 2 m away from the end of the bar to keep the bar horizontal?", "images": [], "options": {"A": "5.0 kg", "B": "6.9 kg", "C": "50.0 kg", "D": "55.0 kg"}, "answer": "C", "explanation": "x  x 5.5 = 55 x 5   x =55 x 55.5=55 x 5055=50.0kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>10", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A solid plastic cube of side 0.2 m is submerged in a liquid of density 0.8 kgm-3. Calculate the upthrust of the liquid on the cube.  [g = 10 ms-2]", "images": [], "options": {"A": "0.064 N", "B": "0.025 N", "C": "0.016 N", "D": "0.008 N"}, "answer": "A", "explanation": "Density = 0.8 kgm-3; g = 10 ms-2  Volume of cube = l3 = 0.2 x 0.2 x 0.2 = 8.0 x 10-3 m3  Upthrust = weight of liquid displaced = 8.0 x 10-3 x 0.8 x 10 = 0.064 N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>11", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "A piece of copper of mass 30 g loses 60 J of heat energy. If the specific heat capacity of iron is 400 Jkg-1K-1. Calculate the change in temperature of the copper.", "images": [], "options": {"A": "0.2 K", "B": "0.8 K", "C": "2.0 K", "D": "5.0 K"}, "answer": "D", "explanation": "m = 30 g = 0.03 kg; Q = 60 J; c = 400 Jkg-1K-1; θ = ?  Q = mcΔθ; 60 = 0.03 x 400 x Δθ  Δθ=60400 x 0.03=604 x 3=6012=5.0K", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>12", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "Steel bars, each of length 3 m at 28oC, are to be used for constructing a rail line. If the linear expansivity of steel is 1.0 x 10-3 K-1, what is the safety gap that must be left between successive bars if the highest temperature expected at 40oC?", "images": [], "options": {"A": "1.2 x 10-1 cm", "B": "7.2 x 10-2 cm", "C": "6.0 x 10-2 cm", "D": "3.6 x 10-2 cm"}, "answer": "D", "explanation": "α = 1.0 x 10-5 K; L = 3 m = 300 cm; θ1 = 28oC; θ2 = 40oC; ΔL = ?  α=ΔLLΔθ  ΔL = αLΔθ  ΔL = 1.0 x 10-5 x 3 x (40 - 28) = 1.0 x 10-5 x 300 x 12 = 3.6 x 10-2 cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>13", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "Which of the following diagrams correctly represents the variation of the volume V of a fixed mass of water with temperature T?", "images": ["Physics/imgs/1997/phy_97_one_three_opt_a.png", "Physics/imgs/1997/phy_97_one_three_opt_b.png", "Physics/imgs/1997/phy_97_one_three_opt_c.png", "Physics/imgs/1997/phy_97_one_three_opt_d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "ThegraphobtainedfromvolumeVofafixedmassofwaterwithtemperatureTis  astraightlinewhoseslopeisapproximately1273", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>14", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "In which of the following digram is the pressure of the entrapped air equal to the atmospheric pressure?", "images": ["Physics/imgs/1997/phy_97_one_four_opt_a.png", "Physics/imgs/1997/phy_97_one_four_opt_b.png", "Physics/imgs/1997/phy_97_one_four_opt_c.png", "Physics/imgs/1997/phy_97_one_four_opt_d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "The pressure of the entrapped air equal to the atmospheric pressure when its rested horizontally.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>15", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A solid material of volume 100 cm3 is heated through a temperature difference of 40oC. Calculate the increase in the volume of the material if its linear expansivity is 2.0 x 10-6 K-1.", "images": [], "options": {"A": "2.4 x 10-2 cm3", "B": "1.6 x 10-2 cm3", "C": "8.0 x 10-3 cm3", "D": "5.0 x 10-6 cm3"}, "answer": "A", "explanation": "V=100cm3;θ=40oC;α=2.0x10-6K-1;α=ΔVVΔθ  =3x2.0x10-6=ΔV100 x 40  ΔV=6.0x10-6x100x40=2.4x10-2cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>16", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following explains why a thick glass cup cracks when boiling water is poured into it?", "images": [], "options": {"A": "Large increase in the heat capacity of the cup", "B": "High density of water", "C": "Unequal expansion of the interior and exterior walls of the cup", "D": "Anomalous expansion of water"}, "answer": "C", "explanation": "When hot water is poured into thick glass cup, the inner surface of the cup becomes hot and expands. The outer surface of the cup does not expand quickly. Due to this uneven expansion, the glass cup cracks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>17", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "Calculate the quantity of heat released when 100 g of steam at 100oC condenses to water  [Take the specific latent heat of vaporization of water as 2.3 x 106 Jkg-1]", "images": [], "options": {"A": "2.3 x 101 J", "B": "2.3 x 102 J", "C": "2.3 x 104 J", "D": "2.3 x 105 J"}, "answer": "D", "explanation": "m = 100 g = 0.1 kg; θ = 100oC; L = 2.3 x 106 Jkg-1K-1; H = mL  ∴ H = 0.1 x 2.3 x 106 = 2.3 x 105 J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>18", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "A fixed mass of gas occupies a volume of 20 cm3 at a pressure of 700 mmHg. Assuming that the temperature remains constant, what will be the volume of the gas at 750 mmHg?", "images": [], "options": {"A": "2.5 cm3", "B": "15.5 cm3", "C": "18.7 cm3", "D": "21.4 cm3"}, "answer": "C", "explanation": "V1 = 20 cm3; P1 = 700 mmHg; V2 = ?; P2 = 750 mmHg  P1V1 = P2V2  V2=P1V1P2=700 x 20750=18.7cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>19", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "A cup containing 100 g of pure water at 20oC is placed in a refrigerator. If the refrigerator extracts heat at the rate of 840 J per minute, calculate the time taken for the water to freeze.  [Neglect the heat capacity of the materials of the cup]  [Specific heat capacity of water = 4.2 Jg-1K-1]  [Specific latent heat of fusion of ice = 336 Jg-1]", "images": [], "options": {"A": "15 minutes", "B": "20 minutes", "C": "42 minutes", "D": "50 minutes"}, "answer": "D", "explanation": "m = 100 g; θ = 20oC; Q = 840 J; t = ?; Q = ml + mcΔθ  Q = 100 x 336 + 100 x 4.2 x 20 = 33600 + 8400 = 42,000  Refrigerator absorbs 840 J per minutes  ∴42,000Jofheatwillbeabsorbedin42,000840minutes=50minutes", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>20", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "When white light is incident on a glass prism the spectrum produced on a screen placed beyond the prism is due to", "images": [], "options": {"A": "diffraction", "B": "reflection", "C": "refraction", "D": "polarization"}, "answer": "C", "explanation": "Dipersion is due to the fact that different colours of white light travel at different speeds through the glass. Each colour is therefore refracted in a slightly different direction or angle through the glass.  [N.B: In a vacuum and in air, all the colours of white light travel at the same speed.]", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1997>21", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "Two rays from a very distant object in the diagram below. P, F and C represents respectively the pole, focus and centre of curvature of a concave mirror. If two rays from a very distant object strike the mirror as shown, where will the image of the object be located?", "images": ["Physics/imgs/1997/phy_97_two_one.png"], "options": {"A": "Between P and F", "B": "Between F and C", "C": "Beyond C", "D": "At F"}, "answer": "D", "explanation": "The image of the object be located at F.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>22", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens of focal length 15 cm is used to obtain a real image magnified 11/2 times. Calculate the distance of the image from the lens.", "images": [], "options": {"A": "37.5 cm", "B": "22.5 cm", "C": "15.0 cm", "D": "7.5 cm"}, "answer": "A", "explanation": "f=15cm;u=x;v=3x2;ifu=2x;v=3x  ∴1f=1v+1u  =115=13x+12x  =115=2 + 36x  =115=56x  =6x=15x5=75  ∴x=756=12.5cm  v=3x=3x12.5=37.5cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>23", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "At what distance from a simple microscope must an object be placed so that an image 5 times the size of the object is produced 20 cm from the lens?", "images": [], "options": {"A": "2.0 cm", "B": "3.3 cm", "C": "4.0 cm", "D": "5.0 cm"}, "answer": "C", "explanation": "M=5i.evu=5∴v=5u=20cm(given);  ∴u=205=4.0cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>24", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "What is the frequency of a radio wave of wavelength 150 m if the velocity of radio waves in free space is 3 x 108 ms-1?", "images": [], "options": {"A": "4.5 x 1010 Hz", "B": "5.0 x 109 Hz", "C": "4.5 x 108 Hz", "D": "2.0 x 106 Hz"}, "answer": "D", "explanation": "f = ?; v = 3 x 108 ms-1; λ = 150 m; v = fλ  f=vλ=3 x 108150=2.0x106Hz", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>25", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "Whenever light waves are restricted to a specific plane, they are said to be", "images": [], "options": {"A": "diffracted", "B": "refracted", "C": "diffused", "D": "plane-polarized"}, "answer": "D", "explanation": "Plane polarized light consists of waves in which the direction of vibration is the same for all waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>26", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The magnification produced with a converging lens is 5. If the object is a square wire gauze of side 2 cm, calculate the area of the image", "images": [], "options": {"A": "100 cm2", "B": "40 cm2", "C": "20 cm2", "D": "10 cm2"}, "answer": "C", "explanation": "M = 5; L = 2 cm; Area of the object = L2 = 2 x 2 = 4 cm2  M=vu=Area of imageArea of object=5  ∴ Area of image = Area of object x 5 = 4 x 5 = 20 cm2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>27", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Which of the following is  not  true of the similarities between a camera and the human eye?", "images": [], "options": {"A": "Both the camera and the eye have light-proof interiors", "B": "Both camera and the eye, have light sensitive screens", "C": "Inverted images are formed on the screen in both", "D": "The distance between the lens and the screen is fixed in both"}, "answer": "D", "explanation": "The distance between the lens and the retina is fixed in the human eye. In camera the distance between the lens and the film can be varied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>28", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PROPERTIES OF WAVES : DIFFRACTION", "question": "The diagram below shows waves passing through a slit S. Which wave phenomenon is illustrated by the diagram?", "images": ["Physics/imgs/1997/phy_97_two_eight.png"], "options": {"A": "Reflection", "B": "Refraction", "C": "Polarization", "D": "Diffraction"}, "answer": "D", "explanation": "Diffraction is the bending of waves around obstacles, or the spreading of waves by passing them through an aperture, or opening.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1997>29", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "A sound note is produced by a ringing bell and the echo of the note from a nearby wall is received 0.5 s later. If the frequency of the note is 400 Hz and its wavelength 1 m, calculate the distance between the bell and the wall.", "images": [], "options": {"A": "400 m", "B": "200 m", "C": "125 m", "D": "100 m"}, "answer": "D", "explanation": "f = 400 Hz; λ = 1 m; t = 0.5 s; d = ?  v=fλ=400x1=400ms-1;v=2dt  ∴d=vt2=400 x 0.52=2002=100m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>30", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "The diagram below represents the profile of transverse wave. Which of the following points are in phase?", "images": ["Physics/imgs/1997/phy_97_three_zero.png"], "options": {"A": "O and P", "B": "O and Q", "C": "O and R", "D": "O and S"}, "answer": "D", "explanation": "If the crests of two waves pass the same point or line at the same time, then they are in phase for that position. Therefore (O and S) and also (P and T) are in phase", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>31", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The diagram below illustrates the profile of a progressive wave in which energy is transferred from P to Q in 3.0 x 10-3 s. Calculate the frequency of the wave.", "images": ["Physics/imgs/1997/phy_97_three_one.png"], "options": {"A": "2.0 x 103 Hz", "B": "1.3 x 103 Hz", "C": "1.0 x 103 Hz", "D": "6.7 x 102 Hz"}, "answer": "C", "explanation": "Time for completing cycles in PQ = 3 x 10-3 s; t = ?  since we have three complete cycles in PQ ∴ time to complete 3 cycles = 3 x 10-3 s  ∴Timetocomplete1cycle(T)=3 x 10-33=1x10-3s  ∴f=1T=11 x 10-3=1.0x103Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>32", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PROPERTIES OF WAVES : INTERFERENCE", "question": "Two identical waves travelling in the same direction are superimposed, what should be the phase difference between the waves for maximum destructive interference to occur?", "images": [], "options": {"A": "20o", "B": "45o", "C": "180o", "D": "225o"}, "answer": "C", "explanation": "Destructive interference occurs from the superposition of two identical waves that are 180°(π radians) out of phase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>33", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "A pipe, open at both ends, produces a fundamental note. If the velocity of sound in air is V and L the length of the pipe, which of the following expresses the frequency of the note?  [Neglect end correction]", "images": [], "options": {"A": "2VL", "B": "V2L", "C": "V3L", "D": "V4L"}, "answer": "B", "explanation": "L=λ2∴λ=2L;V=fλ;f=Vλ=V2L", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>34", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "Which of the following statements is  not  correct?", "images": [], "options": {"A": "The pitch of a note depends on the frequency of the vibrating source", "B": "The loudness of a note depends on its intensity", "C": "The velocity of sound in air does not depend on the intensity of the note producing it", "D": "Wind speed has no effect on the speed of sound in air"}, "answer": "D", "explanation": "The wind can slow down or accelerate the speed of sound, depending on whether it is blowing in the same direction or in the opposite direction to the sound signal. For short distances, the wind has no other significant effects on the level of its receipt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>35", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "A progressive wave has a wavelength of 50 cm. Calculate the phase difference between two points at a distance of 20 cm apart", "images": [], "options": {"A": "103π", "B": "52π", "C": "45π", "D": "23π"}, "answer": "C", "explanation": "λ=50cm;Δx=20cmapart;  Phasedifference=2πλxpathdifference  Δϕ=2πλxΔx  Δϕ=2π50x20=45π", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>36", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "An alternating current with a peak value of 5 A passes through a resistor of resistance 10.0 Ω. Calculate the rate at which energy is dissipated in the resistor.", "images": [], "options": {"A": "250.0 W", "B": "125.0 W", "C": "50.0 W", "D": "35.4 W"}, "answer": "B", "explanation": "Irms=Io&radic;2&nbsp;=5&radic;2&nbsp;  P=Irms2R=(5&radic;2&nbsp;)2x10=252x10=125.0W", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>37", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "The invisible part of the spectrum of white light consists of the following colours:", "images": [], "options": {"A": "red, orange and yellow only", "B": "infra-red, ultra-violet and blue only", "C": "indigo and green only", "D": "ultra-violent and infra-red only"}, "answer": "D", "explanation": "Light, by definition, is the band of radiation to which our eye is sensitive. Ultraviolet radiation ( UV ) and infrared radiation (IR) are not visible. They are the bands of radiation on either side of the visible band (ultra means beyond, infra means below).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>38", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "A charge of 1.0 x 10-5 C experiences a force of 40 N at a certain point in space. What is the magnitude of the electric field intensity at the point in newton per coulomb?", "images": [], "options": {"A": "8.0 x 106", "B": "4.0 x 106", "C": "3.0 x 10-4", "D": "2.0 x 10-4"}, "answer": "B", "explanation": "E=Fq=401.0 x 10-5=4.0x106", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>39", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An atom radiates 1.5 x 10-19 J of energy when an electron jumps from one energy level to another. What is the wavelength of the emitted radiation?  [Planck's constant = 6.6 x 10-34 Js, Speed of light in air = 3 x 108]", "images": [], "options": {"A": "1.32 x 106 m", "B": "2.98 x 10-6 m", "C": "3.32 x 106 m", "D": "6.82 x 10-6 m"}, "answer": "A", "explanation": "E=hf=hcλ  λ=hcE=6.6 x 10-34 x 3 x 1081.5 x 10-19=19.8 x 10-261.5 x 10-19=13.2x10-7m=1.32x10-6m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>40", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A capacitor of capacitance 25μf is connected to an a.c. power source of frequency 200/π Hz.  Calculate the reactance of the capacitor.", "images": [], "options": {"A": "0.01 Ω", "B": "0.02 Ω", "C": "50.00 Ω", "D": "100.00 Ω"}, "answer": "D", "explanation": "XC=12πfC=12 x π x 200/π x 25 x 10-6=106104=100.00Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>41", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "The current in a series R-L-C circuit attain its maximum value when the", "images": [], "options": {"A": "impedance is greater than the capacitive reactance", "B": "inductive reactance is equal to the capacitive reactance", "C": "inductive reactance is greater than the resistance", "D": "capacitive reactance is less than the resistance"}, "answer": "B", "explanation": "WhenXL=XCi.e2πfL=12πfC  ∴AtanRLCcircuit'sresonantfrequency,fo=12π√LC,thecurrentamplitudeisatits  maximumvalue.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>42", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "In a photocell, light energy is converted to", "images": [], "options": {"A": "electrical energy", "B": "chemical energy", "C": "heat energy", "D": "mechanical energy"}, "answer": "A", "explanation": "In a photocell, light energy is converted into electrical energy. This is based on the photoelectric effect, where photons (light energy) strike the surface of a metal and cause electrons to be emitted. These emitted electrons create a current, which is electrical energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>43", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "When a resistor of resistance R is connected across a cell. The terminal p.d. of the cell is reduced to three-quarters of its e.m.f. The internal resistance of the cell is expressed as", "images": [], "options": {"A": "R4", "B": "R3", "C": "R2", "D": "3R4"}, "answer": "B", "explanation": "V = 3/4E (given); E = V + v = IR + Ir    SinceV=IR;I=VR=3/4ER  ∴E=3/4E+3/4ERxr  E = 3/4E(1 + r/R)    1 = 3/4(1 + r/R)    Divide both sides by 3/4    4/3 = 1 + r/R    4/3 - 1 = r/R    1/3 = r/R    R = 3r  ∴r=R3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>44", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "A magnet is placed successively near rings made of the materials indicated in the diagrams below. The polarity of the magnet in each case is also indicated. Inside which of the rings will a magnetic field be observed?", "images": ["Physics/imgs/1997/phy_97_four_four.png"], "options": {"A": "I only", "B": "III only", "C": "I and III only", "D": "II and III only"}, "answer": "A", "explanation": "The materials which are strongly attracted by a magnetic field or magnet is known as ferromagnetic material for eg:  iron ,  steel , nickel, cobalt etc. The  permeability  off these materials is very very high ( ranging up to several hundred or thousand).    [Magnetic  permeability  is a diagnostic physical property which characterizes the degree of induced magnetism a material experiences under the influence of an external magnetic field]", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>45", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Calculate the terminal potential difference across a 20 Ω resistor connected to a battery of e.m.f. 15 V and internal resistance 5 Ω.", "images": [], "options": {"A": "60.0 V", "B": "15.0 V", "C": "12.0 V", "D": "6.3 V"}, "answer": "C", "explanation": "P.d = ?; R = 20 Ω; r = 5 Ω; E = 15 V  E=I(R+r)==>I=ER + r=1520 + 5=1525=0.6A  P.d (V) = IR = 0.6 x 20 = 12.0 V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>46", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "A magnet is being inserted into a coil of wire. On which of the following factors does the induced e.m.f. in the coil depend on?  I. Numbers of turn in the circuit  II. Strength of the magnet  III. Speed with which the magnet is inserted into the coil.", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I, II and III"}, "answer": "D", "explanation": "Induced e.m.f for a coil of wire depends on four things:    Magnetic strength of the core in the coil of wire. (stronger --> bigger emf)  Number of turns of wire in the coil (more turns --> bigger emf)  The cross-sectional area of the coil (larger area --> bigger emf)  How fast you move the magnet into/out of the coil.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>47", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "During the electrolysis of copper(II) tetraoxosulphate(VI) solution, an ammeter shows a steady current reading of 1.0 A for 30 minutes while   6.6 x 10-4 kg of copper is liberated. Calculate the error in the ammeter reading.  [The electrochemical equivalent of copper is 3.30 x 10 kgC-1]", "images": [], "options": {"A": "0.001 A", "B": "0.011 A", "C": "0.111 A", "D": "1.000 A"}, "answer": "C", "explanation": "m = Zit; Z = 3.30 x 10-7 kgC-1; m = 6.6 x 10-4 kg; t = 30 minutes = 30 x 60 = 1800 s  ∴I=mZt=6.6 x 10-43.30 x 10-7 x 1800=1.111  ∴ Error in ammeter reading = 1.111 - 1 = 0.111 A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>48", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "The relationship between the directions of the magnetic field, the current and the motion of a current-carrying wire in the field is easily remembered using", "images": [], "options": {"A": "octet rule", "B": "right-hand grip rule", "C": "Maxwell screw rule", "D": "Fleming left-hand rule"}, "answer": "D", "explanation": "John Ambrose Fleming introduced two rules to determine the direction of motion (in motors) or the direction of induced current (in generators). The rules are called as Fleming's left hand rule (for motors) and Fleming's right hand rule (for generators).     Fleming's Left-Hand Rule   \"If the forefinger points in the direction of magnetic field, the middle finger point in the direction of current, then the thumb will point in the direction of the force (motion)\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1997>49", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The current in the primary coil of a transformer is 2.5 A. If the coil has 50 turns and the secondary 250 turns, calculate the current in the secondary coil.  [Neglect energy loses in the transformer]", "images": [], "options": {"A": "0.2 A", "B": "0.5 A", "C": "2.5 A", "D": "5.0 A"}, "answer": "B", "explanation": "IP=2.5A;nS=250turns;nP=50turns;IS=?  ISIP=nPnS  ∴IS=IP nPnS=2.5 x 50250=2.550=0.5A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>50", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "Lenz's law of electromagnetic induction is essentially a statement of the", "images": [], "options": {"A": "inverse-square law of gravitation", "B": "inverse-square law of magnetism", "C": "inverse-square law of electrostatics", "D": "law of conservation of energy"}, "answer": "D", "explanation": "Lenz's law is based upon the law of conservation of energy. This law states that the induced current always tends to oppose the cause which produces it. So in order to do work against opposing forces, we have to put extra effort. This extra work leads to periodic changes in magnetic flux hence more current is induced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>51", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "The odour of a leaking gas is perceived at a distance from the source. This is made possible by the process of", "images": [], "options": {"A": "sublimation", "B": "diffusion", "C": "osmosis", "D": "evaporation"}, "answer": "B", "explanation": "Diffusion is the process resulting from random motion of molecules by which there is a net flow of matter from a region of high concentration to a region of low concentration. A familiar example is the perfume of a flower that quickly permeates the still air of a room.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1997>52", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The half-life of a radioactive material is 6 hours. What quantity of 1 kg of the material would decay in 24 hours?", "images": [], "options": {"A": "1516kg", "B": "12kg", "C": "14kg", "D": "18kg"}, "answer": "A", "explanation": "half life = 6 hours; 24 hours = 4 half lives = 4 x 6 hours    Amountremainingafter4halflives=124of1kg=116of1kg=116kg  ∴Quantitythatwoulddecayin24hours=1-116=1516kg  [OR]    ∴ 1 kg would decay to 1/2 kg after first half life (1/2 x 1.0 kg = 1/2 kg)    ==>  1/2 kg would decay to 1/4 kg after second half life (1/2 x 1/2 kg = 1/4 kg)    ==> 1/4 kg would decay to 1/8 kg after third half life (1/2 x 1/4 kg = 1/8 kg)    Finally 1/8 kg would decay to 1/16 kg after fourth half life (1/2 x 1/8 kg = 1/16 kg)    116kgwouldbeleft (or remains)after4halflives  ∴Quantitythatwoulddecayin24hours=1-116=1516kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>53", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "When a paint brush is removed from clean water, the bristles of the brush are pulled together because of", "images": [], "options": {"A": "the viscosity of the sorrounding air", "B": "the low density of water", "C": "surface tension forces", "D": "the weight of the brush bristles"}, "answer": "C", "explanation": "When the brush is taken out of water, the bristles cling together due to surface tension. This happens because the free surface of water tries to acquire a minimum surface area (in order to reduce residual force) thus creating tension and that this tension is known as surface tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>54", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "Which of the following is a pair of isotopes?", "images": [], "options": {"A": "35 18 Ar and 35 16 S", "B": "35 17 Cl and 37 17 Cl", "C": "15 7 N and 16 8 O", "D": "30 14 Si and 30 15 P"}, "answer": "B", "explanation": "Isotopes are members of a family of an element that all have the same number of protons but different numbers of neutrons. The number of protons in a nucleus determines the element's atomic number on the Periodic Table. For example, chlorine has 17 protons and is atomic number 17.    Chlorine has two stable isotopes, 35Cl (75.77%) and 37Cl (24.23%), giving chlorine a standard atomic weight of 35.45.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>55", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following statements is not true of nuclear fission?", "images": [], "options": {"A": "A mother nucleus is broken into two daughter nuclei roughly of equal parts", "B": "Neutron is normally used in bombarding heavy nucleus", "C": "Two light nuclei are made to combine to form a heavy nucleus", "D": "Very enormous energy is released"}, "answer": "C", "explanation": "Nuclear fission is a reaction in which the nucleus of an atom splits into two or more smaller nuclei. The fission process often produces gamma photons, and releases a very large amount of energy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>56", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A nucleus has a proton number of 84. it emits an α - particle and then a β - particle to achieve stability. What is the proton number of the product?", "images": [], "options": {"A": "81", "B": "82", "C": "83", "D": "86"}, "answer": "C", "explanation": "84A --> 82A1 + 42α     82A1 --> 83A2 + 0-1β;", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>57", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "In a nuclear reaction, the mass defect is 2.0 x 10-6 g. Calculate the energy released, given that the velocity of light is 3.0 x 108 ms-1.", "images": [], "options": {"A": "9.0 x 107 J", "B": "1.8 x 108 J", "C": "1.8 x 109 J", "D": "9.0 x 1010 J"}, "answer": "B", "explanation": "E = ? Δm = 2.0 x 10-6 g = 2.0 x 10-9 kg; c = 3 x 108 ms-1  E = Δmc2 =  2.0 x 10-9 x (3 x 108)2 = 2.0 x 10-9 x 9 x 1016 = 18 x 107 J = 1.8 x 108 J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1997>58", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "The ratio of tensile stress to tensile strain is known as", "images": [], "options": {"A": "modulus of rigidity", "B": "modulus of elasticity", "C": "shear modulus", "D": "Young modulus"}, "answer": "D", "explanation": "The Young's modulus (E) is a property of the material that tells us how easily it can stretch and deform and is defined as the ratio of tensile stress (σ) to tensile strain (ε). Where stress is the amount of force applied per unit area (σ = F/A) and strain is extension per unit length (ε = dl/l).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>59", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Which of the following is  not  correct about Rutherford's model of the atom?", "images": [], "options": {"A": "The mass of an atom is concentrated in the nucleus", "B": "The nucleus of an atom is positively charged", "C": "The nucleus is sorrounded by electron cloud", "D": "The model is applicable to atoms with only one electron in the outer shell"}, "answer": "D", "explanation": "The model described the atom as a tiny, dense, positively charged core called a nucleus, in which nearly all the mass is concentrated, around which the light, negative constituents, called electrons, circulate at some distance, much like planets revolving around the Sun.    [Rutherford's experiments suggested that the size of the nucleus is about 10-14 m to 10-15 m]", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1997>60", "subject": "Physics", "year": "1997", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statements about kinetic theory of matter is  not  correct?", "images": [], "options": {"A": "The molecules of matter are always in motion", "B": "When a body is heated, the average kinetic energy of its molecules decreases", "C": "Molecules of a liquid move more freely than those of a solid", "D": "Matter is made up of many tiny particles called molecules"}, "answer": "B", "explanation": "The kinetic theory of matter states that all matter is made of small particles that are in random motion and that have space between them.    Therefore when a body is heated, the average kinetic energy of its molecules increases", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>1", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Which of the following pairs of physical quantities comprises vectors?", "images": [], "options": {"A": "Capacitance and inductance", "B": "Force ratio and velocity ratio", "C": "Friction and momentum", "D": "Energy and power"}, "answer": "C", "explanation": "The momentum of a body is a vector quantity, for it is the product of mass, a scalar, by velocity, a vector.    Friction is an opposing force and Force, is a vector quantity, as it has both direction and magnitude.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>2", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF VELOCITY", "question": "During the same time interval, it is observed that a train travels the same distance as does a lorry. The two vehicles therefore have the same", "images": [], "options": {"A": "uniform acceleration", "B": "instantaneous velocity", "C": "average velocity", "D": "average speed"}, "answer": "D", "explanation": "The average speed is the total distance traveled by the object in a particular time interval.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>3", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A piece of stone attached to one end of a string is whirled round in a horizontal circle. When the string is suddenly cut, the stone will", "images": [], "options": {"A": "move towards the centre of the circle.", "B": "stop moving immediately.", "C": "move along a circular path of smaller radius.", "D": "fly off in a direction tangential to the circular path"}, "answer": "D", "explanation": "When a stone is going around a circular path, the instantaneous velocity of stone is acting as tangent to the circle. When the string breaks, the centripetal force stops to act. Due to inertia, the stone continues to move along the tangent to circular path. So, the stone flies off tangentially to the circular path.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>4", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The term torque means", "images": [], "options": {"A": "the moment of a couple about an axis.", "B": "the resultant of several forces acting on a body in equilibrium.", "C": "two equal and opposite forces whose lines of action do not coincide.", "D": "two coplanar forces at right angles to each other."}, "answer": "A", "explanation": "Torque is the measure of the force that can cause an object to rotate about an axis. Force is what causes an object to accelerate in linear kinematics. Similarly, torque is what causes an angular acceleration. Hence, torque can be defined as the rotational equivalent of linear force.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>5", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A rectangular block of wood floats in water with two-thirds of its volume immersed. When placed in another liquid, it floats with half of its volume immersed. Calculate the relative density of the liquid.", "images": [], "options": {"A": "1.43", "B": "1.33", "C": "1.00", "D": "0.75"}, "answer": "D", "explanation": "Relativedensity=Volume of liquid displacedVolume of water displaced=1/22/3=12x32=34=0.75", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>6", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle θ with the floor.   Use this information to answer Questions below     As the end Q of the plank is raised, the component of W, normal to the plank will", "images": ["Physics/imgs/1998/phy_98_six.png"], "options": {"A": "increase", "B": "decrease", "C": "remain the same", "D": "be slightly greater than W"}, "answer": "B", "explanation": "As the end Q of the plank is raised, the value of θ increases, and as θ increases, cos θ decreases. Therefore, the component of W, normal to the plank will decrease", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>7", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle θ with the floor.   Use this information to answer Questions below   If θ is equal to α at the time the box is just about to slide down the plank, the coefficient of static friction between the plank and the box is", "images": ["Physics/imgs/1998/phy_98_six.png"], "options": {"A": "sin α", "B": "cos α", "C": "tan α", "D": "sec α"}, "answer": "C", "explanation": "F=μR;μ=FrR;Fr=mgsinα;R=mgcosα;∴μ=mgsin αmgcos α=tanα", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>8", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MACHINES :", "question": "The diagram beside shows a box X of weight W resting on a plank PQ that has its lower end P hinged to a horizontal floor PR. The plank makes an angle θ with the floor.   Use this information to answer Questions below   If the box is pulled up from P to Q, which of the following expresses the velocity ratio of the inclined plane?", "images": ["Physics/imgs/1998/phy_98_six.png"], "options": {"A": "PRPQ", "B": "QRPQ", "C": "QRPR", "D": "PQQR"}, "answer": "D", "explanation": "V.R=Distance moved by effortDistance moved by load=PQQR", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>9", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A pilot records the atmospheric pressure outside his plane as 63 cm of Hg while a ground observer records a reading of 75 cm of Hg with his barometer. Assuming that the density of air is constant, calculate the height of the plane above the ground.  [Take the relative densities of air and mercury as 0.00136 and 13.6 respectively.]", "images": [], "options": {"A": "120 m", "B": "138 m", "C": "274 m", "D": "1,200 m"}, "answer": "D", "explanation": "Let h be the height above the ground;   Pressure change in air = Pressure change in mercury   ==> ρgh = ρgH  ρ = density of mercury; g = gravitational force; H = change in height  ==> ρgh = 0.00136 x g x h = (75 - 63) x 13.6 x g  ∴h=12 x 13.60.00136=120,000cm=1,200 m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>10", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "An object is projected with a velocity of 100 ms-1 at an angle of 60o to the vertical. Calculate the time taken by the object to reach the highest point.  [Take g as 10 ms-2]", "images": [], "options": {"A": "5.0 s", "B": "8.7 s", "C": "10.0 s", "D": "17.3 s"}, "answer": "B", "explanation": "vo = 100 ms-1; θ = 60o; At greatest height v = 0;  vosin θ - gt = 0; vosin θ = gt  t=vosin θg=100sin 60o10=10x√32=5√3=5x1.732=8.7s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>11", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "The earth is not a perfect sphere because its equatorial axis is longer than the polar axis. Where on the earth's surface would an object have its greatest weight?", "images": [], "options": {"A": "Halfway between the equator and the north pole", "B": "Near the equator", "C": "Halfway between the equator and the south pole", "D": "At either pole"}, "answer": "D", "explanation": "The Earth's equatorial bulge (itself also caused by centrifugal force from rotation) causes objects at the Equator to be further from the planet's center than objects at the poles. Because the force due to gravitational attraction between two bodies (the Earth and the object being weighed) varies inversely with the square of the distance between them,  an object at the Equator experiences a weaker gravitational pull than an object on one of the poles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>12", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A ball of mass 5.0 kg hits a smooth vertical wall normally with a speed of 2 ms-1 and rebounds with the same speed. The determine the impulse experienced by the ball.", "images": [], "options": {"A": "20.0 kgms-1", "B": "10.0 kgms-1", "C": "5.0 kgms-1", "D": "0.0 kgms-1"}, "answer": "A", "explanation": "impulse of force = Ft = change in momentum = m(v -u) = mv - mu  since u = v and v moves in opposite direction to u ∴ u = -v  impulse = mv - m(-v) = mv + mv = 2mv = 2 x 5 x 2 = 20.0 kgms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>13", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "An object is heated from 30oC to 57oC. The increase in its temperature on Kelvin scale is", "images": [], "options": {"A": "17 K", "B": "27 K", "C": "81 K", "D": "300 K"}, "answer": "D", "explanation": "Increase in temperature = θ2 - θ1; θ1 = initial temperature = 30oC; θ2 = final temperature = 57oC  Δθ = 57oC - 30oC = 27oC  ∴ Δθ = 27 + 273 = 300 K", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>14", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The lower and upper fixed points of a mercury-in-glass thermometer are marked Y and 180 mm respectively. On a particular day the mercury meniscus in the thermometer rises to 45 mm. If the corresponding reading on a Celsius scale is 10oC. Calculate the value of Y.", "images": [], "options": {"A": "4 mm", "B": "18 mm", "C": "30 mm", "D": "135 mm"}, "answer": "C", "explanation": "45 - y180 - y=10 - 0100 - 0  45 - y180 - y=10100=110  ==>10(45-y)=180-y  450-10y=180-y  450-180=10y-y  270=9y  ∴y=2709=30mm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>15", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A piece of brass of mass 170 kg has its temperature raised from 0oC to 30oC. Calculate its increase in volume, given the density of brass at 0oC as 8.5 x 103 kgm-3 and its cubic expansivity as 5.7 x 10-5 K-1.", "images": [], "options": {"A": "3.4 x 10-5 m3", "B": "4.3 x 10-5 m3", "C": "3.4 x 10-4 m3", "D": "3.4 x 10-3 m3"}, "answer": "A", "explanation": "γ=ΔVVΔθ  γ=cubicexpansivity;ΔV=increaseinvolume;V=originalvolume;Δθ=temperaturerise  =>5.7x10-5=ΔVV x (30 - 0);butV=mρ;m=mass;ρ=density=>V=1708.5x103=0.02m3  ∴5.7x10-5=ΔV0.02 x 30;ΔV=5.7x10-5x0.6=3.4x10-5m3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>16", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "The average kinetic energy of the molecules of a perfect gas is directly proportional to the", "images": [], "options": {"A": "pressure exerted by the gas.", "B": "volume of the gas molecules.", "C": "Kelvin temperature of the gas.", "D": "Celsius temperature of the gas."}, "answer": "C", "explanation": "The average kinetic energy of the molecules of a perfect gas is directly proportional to the Kelvin temperature of the gas. This is a consequence of the kinetic theory of gases, which states that the average kinetic energy of the gas molecules is proportional to the absolute temperature (measured in Kelvin). This is not related to the pressure exerted by the gas, the volume of the gas molecules, or the Celsius temperature of the gas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>17", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "How much heat is emitted when a body of mass 200 g cools from 37oC to 31oC?  [Specific heat capacity of the body = 0.4 Jg-1K-1]", "images": [], "options": {"A": "4800 J", "B": "1200 J", "C": "480 J", "D": "202 J"}, "answer": "C", "explanation": "Heat emitted = mcΔθ; m = mass; c = specific heat capacity of the body; Δθ = temperature change  H = 200 x 0.4 x (37 - 31) = 200 x 0.4 x 6 = 480 J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>18", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "If the cubic expansivity of brass between 27oC and 100oC is 5.7 x 10-5 K-1, what is its linear expansivity?", "images": [], "options": {"A": "2.85 x 10-5 K-1", "B": "1.90 x 10-5 K-1", "C": "1.86 x 10-5 K-1", "D": "1.70 x 10-5 K-1"}, "answer": "B", "explanation": "α=γ3=5.7 x 10-53=1.90x10-5K-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>19", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "Air at temperature 527oC and pressure 30 atmospheres is admitted into the cylinder of an engine. Calculate the pressure of the gas when it has expanded to 5 times its volume and cooled to 127oC as it leaves the engine.", "images": [], "options": {"A": "1.5 atmospheres", "B": "2.5 atmospheres", "C": "3.0 atmospheres", "D": "12.8 atmospheres"}, "answer": "C", "explanation": "P1V1T1=P2V2T2;P2=P1V1T2T1V2  P1=30atm;V1=Vcm3;T1=527+273=800K;T2=127+273=400K;  V2=5V1=5Vcm3  ∴P2=30 x V x 400800 x 5V=15V5V=3.0atmospheres", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>20", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The inside of a vacuum flask is usually coated with silver to reduce heat loss by", "images": [], "options": {"A": "evaporation", "B": "condensation", "C": "radiation", "D": "conduction"}, "answer": "C", "explanation": "It is found that, for a given temperature, a dull black surface radiates most and a highly polished surface radiates least. So, silver being a highly polished surface, prevents heat loss by radiation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>21", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Dry oxygen is trapped by a pellet of mercury in a uniform capillary tube which is sealed at one end. The length of the column of oxygen at 27oC is 50 cm. If the pressure of the oxygen is constant, at what temperature will it length be 60 cm?", "images": [], "options": {"A": "360.0oC", "B": "240.6oC", "C": "237.0oC", "D": "87.0oC"}, "answer": "D", "explanation": "V1T1=V2T2;T1V2=V1T2;T1=V1T2V2  T1=60 x (273 + 27)50=60 x 30050=360K  ∴T1=360-273=87.0oC", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>22", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "A waterfall is 1,260 m high. Calculate the change in temperature of a quantity of water that falls from the top to the bottom of the waterfall.  [Neglect heat loses to the sorroundings, take g as 10 ms-2 and specific heat capacity of water as 4200 Jkg-K-1]", "images": [], "options": {"A": "0.3oC", "B": "3.0oC", "C": "33.3oC", "D": "42.0oC"}, "answer": "B", "explanation": "Heat energy = Potential energy  i.e mcΔθ = mgh ==> cΔθ = gh  ∴Δθ=ghc=10 x 12604200=3.0oC", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>23", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "When a piece of metal is heated until it becomes red-hot. It is then quickly transferred into a beaker containing boiling water. What effect would this have on the boiling water?", "images": [], "options": {"A": "The boiling point rises slightly.", "B": "The boiling point rises sharply.", "C": "The rate of vaporisation of the boiling water increases.", "D": "The boiling point first rises and then falls"}, "answer": "C", "explanation": "Iron is \"red hot\" at 700°C; boiling water is 100°C. The heat from the iron will be absorbed by the water which will undergo a phase change to steam. The temperature of the iron will drop until it is in equilibrium with the water-100oC. The water will not get hotter, but it will produce more steam.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>24", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "A 90-W immersion heater is used to supply energy for 5 minutes. The energy supplied is used to completely melt 180 g of a solid at its melting point. Neglecting energy loses to the surroundings, calculate the specific latent heat of fusion of the solid.", "images": [], "options": {"A": "0.5 Jg-1", "B": "2.5 Jg-1", "C": "15.0 Jg-1", "D": "150.0 Jg-1"}, "answer": "D", "explanation": "Powerxtime=mL;m=mass=180g;t=time=5x60=300s;L=latentheat  L=Ptm=90 x 300180=3002=150.0Jg-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>25", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "If an ebonite rod is rubbed with fur", "images": [], "options": {"A": "both the ebonite rod and fur will be negatively charged.", "B": "the ebonite rod will be positively charged while the fur will have no charge.", "C": "there will be electron transfer only if the ebonite rod is earthed.", "D": "the ebonite rod will be negatively charged while the fur will be positively charged."}, "answer": "D", "explanation": "When an ebonite rod is rubbed with fur the rod gets negatively charged because the friction between the fur and the rod makes the ebonite rod to gain an electron from the fur. This is because electrons in fur are less tightly bound than the electrons in the ebonite rod. Therefore, the ebonite rod becomes negatively charged and the fur becomes positively charge due to loss of electron.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>26", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "An eclipse of the sun by the moon occurs when the sun, the moon and the earth are all in a straight line and the", "images": [], "options": {"A": "earth casts a shadow on the moon.", "B": "moon casts a shadow on the sun.", "C": "moon is between the sun and the earth.", "D": "sun is between the moon and the earth."}, "answer": "C", "explanation": "An eclipse of the Sun happens when the Moon moves between the Sun and Earth, blocking out the Sun's rays and casting a shadow on parts of Earth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>27", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The phenomenon which occurs when light changes direction as it passes from one medium to another is called", "images": [], "options": {"A": "reflection", "B": "polarisation", "C": "interference", "D": "refraction"}, "answer": "D", "explanation": "Refraction of light is the phenomenon of bending of light or change in the direction of light, when it passes obliquely from one transparent medium to another.  During refraction the frequency of the refracted ray remains constant; though speed of light changes on refraction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>28", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "What is the image distance of an object placed at a distance of 2f from a converging lens of focal length f?", "images": [], "options": {"A": "f4", "B": "f2", "C": "f", "D": "2f"}, "answer": "D", "explanation": "The image distance of an object placed at a distance of 2f from a converging lens of focal length f is 2f.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>29", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens of focal length 5 cm is used as a magnifying glass by a man whose near-point is 35 cm. Calculate the magnification given by the lens.", "images": [], "options": {"A": "8", "B": "7", "C": "6", "D": "5"}, "answer": "C", "explanation": "M=vu;v=35cm;f=5cm;u=?;but1f=1u+1v==>1u=1f-1v  1u=15-135=7 - 135  1u=635  ∴u=356=55/6cm  ∴M=3535/6=35x635=6", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>30", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The images formed by diverging lenses are always", "images": [], "options": {"A": "diminished, virtual and inverted.", "B": "diminished, virtual and erect.", "C": "diminished, inverted and real.", "D": "magnified, virtual and erect."}, "answer": "B", "explanation": "The image is always virtual, diminished, erect and is located between the object and the lens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>31", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An astronomical telescope, having an objective of focal length 100 cm and an eyepiece of focal length 10 cm, is used in normal adjustment. Calculate the separation of the lenses.", "images": [], "options": {"A": "0.10 m", "B": "0.90 m", "C": "1.10 m", "D": "1.80 m"}, "answer": "C", "explanation": "In normal adjustments, the seperation of lenses = fo + fe; where fo = 100 cm = 1 m; fe = 10 cm = 0.1 m  ∴ seperation = 1 + 0.1 = 1.10 m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>32", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A lantern gives an image 3 m square of a slide 7.62 cm square on a screen. If the screen is 10 m from the projection lens of the lantern, calculate the focal length of the lens.", "images": [], "options": {"A": "40.3 cm", "B": "26.1 cm", "C": "24.8 cm", "D": "0.7 cm"}, "answer": "C", "explanation": "Heightofimage=3m=300cm;Heightofobject=7.63cm;  Imagedistance=10m=1000cm  M=Height of imageHeight of object=3007.62=39.37  alsoM=Image distance (v)Object distance (u)i.eM=vu==>u=vM=100039.37=25.4cm  but1f=1u+1v  1f=125.4+11000=1000 + 25.425400  1f=1025.425400  ∴f=254001025.4=24.8cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>33", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "The intensity of light falling on the film in a camera depends on the  I. brightness of the object.  II. diameter of the aperture stop.  III. speed of the shutter.  Which of the statements above is/are correct?", "images": [], "options": {"A": "I, II and III", "B": "I and II only", "C": "I and III only", "D": "III only"}, "answer": "A", "explanation": "The intensity of light falling on the film in a camera does depend on the brightness of the object, the diameter of the aperture stop, and the speed of the shutter. Therefore, all three statements are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>34", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The shortest length of the air column in a resonance tube at resonance is 0.12 m and the next resonant length is 0.37 m. Calculate the frequency of vibration given that the speed of sound in air is 340 ms-1.", "images": [], "options": {"A": "1360 Hz", "B": "694 Hz", "C": "680 Hz", "D": "347 Hz"}, "answer": "C", "explanation": "v=fλ=2f(L2-L1)∴f=v2f(L2 - L1)=3402(0.37 - 0.12)=3400.5=680Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>35", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "A sonometer wire under a tension of 10 N, produces a frequency of 250 Hz when plucked. Keeping the length of the wire constant, the tension is adjusted to produce a new frequency of 350 Hz. Calculate the new tension.", "images": [], "options": {"A": "39.2 N", "B": "19.6 N", "C": "14.2 N", "D": "7.4 N"}, "answer": "B", "explanation": "fα√Tf=k√Twherekisconstant==>k=f√T  f1√T1=f2√T2==>f1f2=√T1√T2  ==>250350=√10√T2  =57=√10√T2  =5√T2=7√10  =√T2=7√105  squarebothsides  ∴T2=49 x 1025=49025=19.6N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>36", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "Which of the following instruments produces sound by the vibration of air column?", "images": [], "options": {"A": "Drum", "B": "Violin", "C": "Guitar", "D": "Flute"}, "answer": "D", "explanation": "Flute players can change the pitch by changing the length of the tube (air column) with the fingers or by increasing the air speed in order to force the sound waves to the next note in the harmonic overtone series.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>37", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "Calculate the wavelength of a note which is one octave lower than a note of 256 Hz in a medium in which the speed of sound is 352 ms1", "images": [], "options": {"A": "0.69 m", "B": "1.38 m", "C": "2.75 m", "D": "5.50 m"}, "answer": "C", "explanation": "fc = 256 Hz; an octave lower f = 2562 = 128 Hz; v=fλ;λ=vf=352128=2.75m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>38", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "Which of the following are both mechanical and transverse?", "images": [], "options": {"A": "Infra-red rays", "B": "Gamma rays", "C": "Sound waves", "D": "Water waves"}, "answer": "D", "explanation": "Water waves are both mechanical and transverse because it requires a material medium (water) and its vibrations move perpendicular to the direction of the wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>39", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "An electromagnetic wave of frequency 5.0 x 1014 Hz, is incident on the surface of water of refractive index. Taking the speed of the wave in air as 3 x 108 ms-1, calculate the wavelength of the wave in water.", "images": [], "options": {"A": "2.2 x 10-6 m", "B": "1.7 x 10-6 m", "C": "8.0 x 10-7 m", "D": "4.5 x 10-7 m"}, "answer": "D", "explanation": "anw=λaλw=43==>λw=3λa4  Fromv=fλa;λa=vf=3.0 x 1085.0 x 1014=35x108 - 14=0.6x10-6=6.0x10-7m  ∴λw=3 x 6.0 x 10-74=18.0 x 10-74=4.5x10-7m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>40", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "The gravitational force of the moon is one-sixth that of the earth. If the body weighs 6.0 N on the moon, calculate its weight on the earth.", "images": [], "options": {"A": "36.0 N", "B": "12.0 N", "C": "6.0 N", "D": "2.0 N"}, "answer": "A", "explanation": "The weight of an object is the force of gravity on it. Since the gravitational force of the moon is one-sixth that of the earth, the weight of the body on earth would be six times its weight on the moon. Therefore, if the body weighs 6.0 N on the moon, it would weigh 6.0 N * 6 = 36.0 N on the earth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>41", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "In the electrical method of magnetisation, the polarity of the magnet depends on the", "images": [], "options": {"A": "amount of current passed.", "B": "direction of current.", "C": "magnetic material used.", "D": "size of the magnetic material."}, "answer": "B", "explanation": "In the electrical method of magnetisation, the polarity of the magnet depends on the direction of the current. This is because the direction of the magnetic field produced by a current-carrying wire is determined by the right-hand rule, which states that if you point the thumb of your right hand in the direction of the current, your fingers will curl in the direction of the magnetic field.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>42", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A cell of e.m.f. 1.5 V is connected in series with a resistor of resistance 3 Ω. A high resistance voltmeter connected across the cell registers only 0.9 V. Calculate the internal resistance of the cell.", "images": [], "options": {"A": "5.0 Ω", "B": "4.5 Ω", "C": "2.4 Ω", "D": "2.0 Ω"}, "answer": "D", "explanation": "V=IR==>I=VR=0.93=0.3A  E=I(R+r)=IR+Ir  E-IR=Ir  E - IRI=r  sinceV=IR  ∴r=E - VI=1.5 - 0.90.3=0.60.3=2.0Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>43", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "Calculate the resistance of the filament of a lamp rated at 240 V, 60 W.", "images": [], "options": {"A": "240 Ω", "B": "360 Ω", "C": "960 Ω", "D": "1440 Ω"}, "answer": "C", "explanation": "P=V2R==>R=V2P=240260=57,60060=960Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>44", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MAGNETIC FIELD : THE EARTH’S MAGNETIC FIELD", "question": "The diagram below illustrates a freely suspended bar magnet hanging from a point in a horizontal ceiling. The thread used for suspending the magnet and the axis of the magnet are as indicated on the diagram. The angle marked θ is called the angle of", "images": ["Physics/imgs/1998/phy_98_four_four.png"], "options": {"A": "depression", "B": "declination", "C": "variation", "D": "dip"}, "answer": "D", "explanation": "Magnetic dip, dip angle, or magnetic inclination is the angle made with the horizontal by the Earth's magnetic field lines. The dip angle is in principle the angle made by the needle of a vertically held compass", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>45", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "Lenz's law of electromagnetic induction states that", "images": [], "options": {"A": "the induced charge is constant for a fixed change of flux.", "B": "a force is exerted on a current-carrying conductor in a magnetic field.", "C": "the magnitude of the induced e.m.f. in a circuit is proportional to the rate of change of the number of lines of force linking the circuit.", "D": "the induced current in a conductor is in such a direction as to oppose the change producing it."}, "answer": "D", "explanation": "Lenz's law, in electromagnetism, states that an induced electric current flows in a direction such that the current opposes the change that induced it. This law was deduced in 1834 by the Russian physicist Heinrich Friedrich Emil Lenz (1804–65).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>46", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE", "question": "A proton of charge 1.6 x 10-19 C is projected into a uniform magnetic field of flux density 5.0 x 10-5 T. If the proton moves parallel to the field with a constant speed of 1.6 x 106 ms-1, calculate the magnitude of the force exerted on it by the field.", "images": [], "options": {"A": "0.0 N", "B": "2.0 x 10-21 N", "C": "1.3 x 10-17 N", "D": "5.1 x 10-14 N"}, "answer": "C", "explanation": "F = Bqv; F = force; B = flux density; q = charge; v = velocity  ==> F = 5.0 x 10-5 x 1.6 x 10-19 x 1.6 x 106 = 1.3 x 10-17 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>47", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "The direction of the magnetic field at a point in the vicinity of a bar magnet is", "images": [], "options": {"A": "along the line joining the point to a neutral point.", "B": "always away from the south pole of the magnet.", "C": "opposite the direction of the resultant field at that point.", "D": "the direction towards which the north pole of a compass needle would point."}, "answer": "D", "explanation": "The direction of the magnetic field at a point in the vicinity of a bar magnet is the direction towards which the north pole of a compass needle would point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>48", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : RESONANCE", "question": "In L-C circuit, the inductance and capacitance are 0.5 H and 20 μf respectively. Calculate the resonant frequency of the circuit.", "images": [], "options": {"A": "24.2 Hz", "B": "36.7 Hz", "C": "50.3 Hz", "D": "60.5 Hz"}, "answer": "C", "explanation": "fo=12π√LC=12π√(0.5 x 20 x 10-6)=16.286√10-5  ==>fo=16.286 x 3.2 x 10-3=10.01988  ∴fo=50.3Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>49", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "The diagram below illustrates an a.c. source of 50 V(r.m.s), 100/π Hz connected in series with an inductor of inductance L and a resistor of resistance R. The current in the circuit is 2 A and the p.d across L and R are 30 V and 40 V respectively.     Use this information to answer Questions below     Calculate the power factor of the circuit.", "images": ["Physics/imgs/1998/phy_98_four_nine.png"], "options": {"A": "1.33", "B": "1.25", "C": "0.80", "D": "0.75"}, "answer": "C", "explanation": "Powerfactor=cosθ=RZ;whereR=VI=402=20Ω  Z=√(R2+X2)=√(202+152)=√(400+225)  ==>Z=√625=25Ω  ∴cosθ=2025=0.8", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>50", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "The diagram below illustrates an a.c. source of 50 V(r.m.s), 100/π Hz connected in series with an inductor of inductance L and a resistor of resistance R. The current in the circuit is 2 A and the p.d across L and R are 30 V and 40 V respectively.     Use this information to answer Questions below   Calculate the average power dissipated in the circuit.", "images": ["Physics/imgs/1998/phy_98_four_nine.png"], "options": {"A": "100 W", "B": "80 W", "C": "60 W", "D": "20 W"}, "answer": "B", "explanation": "I = 2 A, R = 20 &#937;  P = I2R = 22 x 20 = 4 x 20 = 80 W", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>51", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "Use the following data to determine the length L of a wire when a force of 30 N is applied, assuming Hooke's law is obeyed.  Force applied/N 0 5 10 30Length of wire/mm 500.0 500.5 501.0 L", "images": [], "options": {"A": "3.0 mm", "B": "3.5 mm", "C": "503.0 mm", "D": "503.5 mm"}, "answer": "C", "explanation": "Fαe;f=ke;k=fe  WhenF=0;L=500.0mmi.ewhennoforceisapplied,theoriginallengthis500.0mm  WhenF=5N;Newlength=500.5∴e=500.5-500=0.5mm  Fromk=fe=50.5=10Nm-1  NowwhenF=30;e=Fk=3010=3.0mm  ∴L=500.0+3.0=503.0mm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>52", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Which of the following explains the concave meniscus of water in a clean glass tube? The", "images": [], "options": {"A": "adhesion between water and glass molecules is greater than the cohesion between water molecules.", "B": "cohesion between water molecules is greater than the adhesion between glass and water molecules.", "C": "molecules of water near the glass move faster than the molecules at the centre of the tube.", "D": "molecules of water at the water-air boundary are often attracted to the centre of the tube."}, "answer": "A", "explanation": "Water forms concave meniscus in a clean glass tube because the force of attraction between the water and glass molecules is stronger than the force of attraction between the water molecules.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>53", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "An electron is accelerated from rest through a potential difference of 70 kV in a vacuum. Calculate the maximum speed acquired by the electron.  [electronic charge = -1.6 x 10-19 C; mass of an electron = 9.1 x 10-31 kg]", "images": [], "options": {"A": "3.00 x 108 ms-1", "B": "2.46 x 108 ms-1", "C": "1.57 x 108 ms-1", "D": "1.32 x 108 ms-1"}, "answer": "C", "explanation": "eV=12mv2;2eV=mv2;v2=2eVm  ==>v=√2eVm=√2 x 1.6 x 10-19 x 70 x 1039.1 x 10-31=√224 x 10-169.1 x 10-31  =v=√24.620x1015  ∴v=1.57x108ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>54", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "When light from a source is sent through a gas  I. certain wavelengths are absorbed.  II. an emission line spectrum results.  III. a dark line is left.  Which of the following is/are correct?", "images": [], "options": {"A": "I only", "B": "III only", "C": "I and II only", "D": "I and III only"}, "answer": "D", "explanation": "When light from a source is sent through a gas some light of certain wavelengths are absorbed resulting in gaps that appear as dark lines", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>55", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Calculate the value of half-life of a radioactive element whose decay constant is 0.077 s-1.", "images": [], "options": {"A": "0.5 s", "B": "3.0 s", "C": "5.1 s", "D": "9.0 s"}, "answer": "D", "explanation": "t1/2=0.693λ=0.6930.077=9.0s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>56", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "The process of increasing the energy of an atom via inelastic collision with an electron is known as", "images": [], "options": {"A": "ionization", "B": "excitation", "C": "field emission", "D": "photoemission"}, "answer": "B", "explanation": "excitation, is the addition of a discrete amount of energy (called excitation energy) to a system—such as an atomic nucleus, an atom, or a molecule—that results in its alteration, ordinarily from the condition of lowest energy (ground state) to one of higher energy (excited state).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1998>57", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive nuclide of proton number X emits a β particle to form a new nuclide of proton number Y. The correct equation relating X and Y is", "images": [], "options": {"A": "X = Y - 1", "B": "X = Y + 1", "C": "X = 1 - Y", "D": "X = 1/Y"}, "answer": "B", "explanation": "When a radioactive nuclide emits a β particle (which is essentially an electron), a neutron in the nucleus is converted into a proton. This increases the proton number by 1. Therefore, the correct equation relating X and Y is X = Y + 1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>58", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "The frictional effect between the layers of a moving fluid is called", "images": [], "options": {"A": "capillarity", "B": "turbulence", "C": "diffusion", "D": "viscosity"}, "answer": "D", "explanation": "Viscosity is the resistance of a fluid (liquid or gas) to a change in shape or movement of neighbouring portions relative to one another. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1998>59", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Two radioactive elements X and Y have half-lives of 100 and 50 years respectively. Samples of X and Y initially contain equal number of atoms. What is the ratio of the number of the remaining atoms of X to that of Y after 200 years?", "images": [], "options": {"A": "4 : 1", "B": "1 : 2", "C": "1 : 1", "D": "1 : 4"}, "answer": "D", "explanation": "X⇒Initialamountofsamplex  Halflife=50years  After200yearsi.e.,4halflives,amount remaining=124=116  Y⇒Initialamountofsampley  Halflife= 100years  After200yearsi.e.,2halflives,amount remaining=122=14  So,ratioofXremainingtothatofY=116:14=116x41=14=1:4", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1998>60", "subject": "Physics", "year": "1998", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "It is always not possible to determine exactly and simultaneously the position and momentum of a particle. This statement is known as the", "images": [], "options": {"A": "De Broglie law.", "B": "Heisenberg uncertainty principle.", "C": "Compton effect.", "D": "Frank-Hertz experimental law."}, "answer": "B", "explanation": "Formulated by the German physicist and Nobel laureate Werner Heisenberg in 1927, the uncertainty principle states that we cannot know both the position and momentum of a particle, such as a photon or electron, with perfect accuracy; the more we know about the particle's position, the less we know about its momentum and vice versa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>1", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "The force between molecules of the same substance is termed", "images": [], "options": {"A": "elastic force", "B": "repulsive force", "C": "cohesive force", "D": "adhesive force"}, "answer": "C", "explanation": "Cohesive force is the force of attraction between similar molecules. For example, the force that holds water molecules together is cohesive force.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>2", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A net force of magnitude 0.6 N acts on a body of mass 40 g, initially at rest. Calculate the magnitude of resulting acceleration", "images": [], "options": {"A": "90 ms-2", "B": "60 ms-2", "C": "30 ms-2", "D": "15 ms-2"}, "answer": "D", "explanation": "Using the formula F = ma, where F is the force, m is the mass and a is the acceleration. Rearranging the formula, we get a = F/m. Substituting the given values, we get a = 0.6N / 0.04kg = 15 ms-2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>3", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Palm oil from a bottle flows out more easily after it has been heated because the", "images": [], "options": {"A": "molecules are given potential energy during the heating", "B": "friction between oil layers is reduced", "C": "oil molecules force each other out", "D": "adhesion between the oil molecules and those of the bottle is increased"}, "answer": "B", "explanation": "If a liquid is heated the particles are given more energy and move faster and faster expanding the liquid.The result is that liquids show a reduction in viscosity (internal friction) with increasing temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>4", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A body weighing 100 N moves with a speed of 5 ms-1 in a horizontal circular path of radius 5 m. Calculate the magnitude of the centripetal force acting on the body.  [g = 10 ms-2]", "images": [], "options": {"A": "10 N", "B": "50 N", "C": "75 N", "D": "100 N"}, "answer": "B", "explanation": "W=100N;g=10ms-2;v=5ms-1;r=5m;W=mg;m=Wg=10010=10 kg   ∴F=mv2r=10 x 525=10x5=50N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>5", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "MOTION : RELATIVE MOTION", "question": "A motor-cyclist, passing a road junction, moves due west for 8 s at a uniform speed of 5 ms-1. He then moves due north for another 6 s with the same speed. At the end of the 6 s his displacement from the road junction is 50 m in the direction of", "images": [], "options": {"A": "N53oE", "B": "N37oE", "C": "N53oW", "D": "N37oW"}, "answer": "C", "explanation": "due west distance covered = 8 x 5 = 40 m    due north distance covered = 6 x 5 = 30 m  tanθ=4030=43  θ=tan-143  θ = 53o    ∴ direction is N53oW", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>6", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF VELOCITY", "question": "The time rate of change of displacement is known as", "images": [], "options": {"A": "speed", "B": "velocity", "C": "impulse", "D": "acceleration"}, "answer": "B", "explanation": "The time rate of change of displacement is known as velocity. Velocity is a vector quantity that refers to 'the rate at which an object changes its position'. In other words, velocity is speed in a given direction. Speed, on the other hand, is a scalar quantity that refers to 'how fast an object is moving'. Impulse is the change in momentum of an object when the object is acted upon by a force for an interval of time. Acceleration is the rate of change of velocity per unit of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>7", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A stone of mass 0.7 kg is projected vertically upwards with a speed of 5 ms-1. Calculate the maximum height reached.  [Take g as 10 ms-2 and neglect air resistance]", "images": [], "options": {"A": "1.00 m", "B": "1.25 m", "C": "1.50 m", "D": "3.75 m"}, "answer": "B", "explanation": "m = 0.7 kg; u = 5 ms-1; g = 10 ms-2; hmax = ?; At maximum height, v = 0    v2 = u2 - 2gs (g = -ve)    0 = 52 - 2 x 10 x hmax    2 x 10 x hmax = 52    20hmax = 25    ∴hmax=2520=1.25m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>8", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "If the force of attraction between the sun and the planets is removed, the planets will", "images": [], "options": {"A": "fall towards the sun", "B": "scatter and stop moving", "C": "continue to move at tangent to their original orbit", "D": "continue to move perpendicular to their original orbits"}, "answer": "C", "explanation": "Gravitational force acts between the sun and the planets, which causes the planets to orbit around the sun.    If this force between sun and the planets is removed, the path of motion of the planet is disturbed, and the planets start traveling along the straight path tangential to their orbital path out in the free space.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>9", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A 15 kg mass suspended from a ceiling is pulled aside with a horizontal force, F as shown in the diagram beside. Calculate the value of the tension T  [g = 10 ms-1]", "images": ["Physics/imgs/1999/phy_99_nine.png"], "options": {"A": "300.0 N", "B": "173.2 N", "C": "30.0 N", "D": "17.3 N"}, "answer": "B", "explanation": "cosθ=adjhyp  cos30o=mgT=15 x 10T=150T  Tcos30o=150  ∴T=150cos 30o=173.2N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>10", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "A pendulum bob executing simple harmonic motion has 2 cm and 12 Hz as amplitude and frequency respectively. Calculate the period of the motion.", "images": [], "options": {"A": "2.00 s", "B": "0.83 s", "C": "0.08 s", "D": "0.06 s"}, "answer": "C", "explanation": "The period of a pendulum bob executing simple harmonic motion is the reciprocal of the frequency. Given that the frequency is 12 Hz, the period of the motion is 1/12 = 0.08333 s, which is approximately 0.08 s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>11", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : THIRD LAW", "question": "A trolley of mass 4 kg moving on a smooth horizontal platform with a speed of 1.0 ms-1 collides perfectly with a stationary trolley of the same mass on the same platform. Calculate the total momentum of the two trolleys immediately after the collision", "images": [], "options": {"A": "0.5 Ns", "B": "1.0 Ns", "C": "4.0 Ns", "D": "8.0 Ns"}, "answer": "C", "explanation": "The law of conservation of energy states that  pinitial = pfinal  So, the total momentum  p = mv = 4 x 1 = 4.0 Ns", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>12", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The ice point of an ungraduated mercury-in-glass thermometer is X, while its steam point is 90o. This thermometer reads 60o when the true temperature is 40oC. Calculate the value of X", "images": [], "options": {"A": "60o", "B": "48o", "C": "40o", "D": "30o"}, "answer": "C", "explanation": "Sincethetemperatureisthesame  ==>60 - x90 - x=40 - 0100 - 0==>100(60-x)=40(90-x)  =6000-100x=3600-40x  =6000-3600=100x-40x  =2400=60x  ∴x=240060=40o", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>13", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "Iron at 30oC feels cooler to the hand than wood at 28oC because", "images": [], "options": {"A": "their linear expansivities are not equal", "B": "the temperature of the iron higher than that of the wood", "C": "iron is a better radiator of heat than wood", "D": "iron conducts heat more quickly from the hand than wood"}, "answer": "D", "explanation": "Iron at 30oC feels cooler to the hand than wood at 28oC because iron conducts heat more quickly from the hand than wood", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>14", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "An iron rod of length 50 m at a temperature of 60oC is heated to 70oC. Calculate its new length  [Linear expansivity of iron = 1.2 x 10-5 K-1]", "images": [], "options": {"A": "50.006 m", "B": "50.060 m", "C": "51.600 m", "D": "51.200 m"}, "answer": "A", "explanation": "L1=50m;θ1=60oC;θ2=70oC;L2=?;α=1.2x10-5K  α=L2 - L1L1(θ2 - θ1)==>L2=L1(1+α(θ2-θ1))  =L2=50(1+1.2x10-5x(70-60))=50(1+1.2x10-5x10)  =L2=50(1+0.00012)=50(1.00012)  ∴L2=50.006m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>15", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "The heat capacity of a substance is the energy", "images": [], "options": {"A": "required to raise the temperature of a unit mass of the substance by one degree", "B": "required to raise the temperature of the substance by one degree", "C": "absorbed by the substance at constant temperature", "D": "lost by a unit mass of the substance"}, "answer": "B", "explanation": "The heat capacity of a substance is the energy required to raise the temperature of the substance by one degree", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>16", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "The temperature of a piece of metal of mass 9 g is raised from 10oC to 110oC when it absorbs 108 J of heat energy. Determine the specific heat capacity of the metal in Jkg-1K-1", "images": [], "options": {"A": "1.2", "B": "12.0", "C": "120.0", "D": "1200.0"}, "answer": "C", "explanation": "m = 9 g = 0.009 kg; θ1 = 10oC; θ2 = 110oC; H = 108 J; c = ?  H = mcΔθ  = 108 = 0.009 x c x (110 - 10)  = 108 = 0.009 x c x 100  = 108 = 0.9c  ∴c=1080.9=120.0Jkg-1K-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>17", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statements is not correct", "images": [], "options": {"A": "A sea breeze is due to convection in air", "B": "Cotton materials are better than the woollen ones for use in hot weather", "C": "Convectional currents play an important role in the cooling of the engine of a motor car", "D": "the vacuum space in a flask helps to reduce heat loss by radiation"}, "answer": "D", "explanation": "All the statements are correct except for the last one. A vacuum flask reduces heat loss by preventing conduction and convection, not radiation. The vacuum space in a flask prevents heat transfer by conduction and convection because these processes require a medium (solid, liquid, or gas) to occur. However, heat can still be transferred by radiation, which does not require a medium. The flask's reflective inner surface helps to reduce this radiative heat loss by reflecting radiated heat back into the flask.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>18", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "Calculate the heat energy required to change 0.1 kg of ice at 0oC to water boiling at 100oC.  [Specific heat capacity of water = 4200 Jkg-1K-1]  [Specific latent heat of fusion of ice = 336,000 Jkg-1]", "images": [], "options": {"A": "75,600 J", "B": "336,000 J", "C": "340,200 J", "D": "378,000 J"}, "answer": "A", "explanation": "H = mL + mcΔθ = m(L + cΔθ)  H = 0.1(336000 + 4200(100 - 0) = 0.1(336000 + 4200 x 100)  H = 0.1(336000 + 420000) = 0.1 x 756000  ∴ H = 75,600 J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>19", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following statements about evaporation is not correct?", "images": [], "options": {"A": "The rate of evaporation of a liquid varies with temperature", "B": "The molecules of an evaporating liquid have an average speed", "C": "Evaporation occurs when faster molecules escape from the surface of a liquid", "D": "Evaporation takes place inside a liquid"}, "answer": "D", "explanation": "Evaporation takes place only at the surface of a liquid, whereas boiling may occur throughout the liquid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>20", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "Calculate the power rating of an immersion heater used for 10 minutes to increase the temperature of 10 kg of water by 15 K.  [Specific heat capacity of water = 4200 Jkg-1K-1]", "images": [], "options": {"A": "1,050 W", "B": "16,800 W", "C": "18,060 W", "D": "20,160 W"}, "answer": "A", "explanation": "m = 10 kg; Δθ = 15 K; c = 4200 Jkg-1K-1; t = 10 minutes = 10 x 60 = 600 s; H = mcΔθ  H = 10 x 4200 x 15 = 630,000 J  ∴P=Ht=630,000600=1,050W", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>21", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A ray of light is incident on a plane mirror at an angle of 20o. This mirror is rotated through, twice this angle. In this new position, the angle between the incident ray and the reflected ray is", "images": [], "options": {"A": "20o", "B": "40o", "C": "80o", "D": "120o"}, "answer": "D", "explanation": "i = 20o; θ = 2 x 20o = 40o  Angle between incident ray ON and the new reflected ray NR2 = ONR2 = (i + θ) + (i + θ) = 2(i + θ)  ∴ the angle between the incident ray and the reflected ray = 2(20 + 40) = 2 x 60 = 120o", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>22", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES", "question": "The air column in a resonance tube is set into resonance by a vibrating tuning fork. The resultant waves in the air column will be", "images": [], "options": {"A": "mechanical and transverse", "B": "progressive and longitudinal", "C": "stationary and transverse", "D": "stationary and longitudinal"}, "answer": "D", "explanation": "When air that is set  into vibration by a tuning fork  vibrates inside a resonance tube, the waves produced are reflected at the ends producing a longitudinal stationary wave along the length of the resonance tube, thus a loud sound is heard.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>23", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "The image of a object is located 6 cm behind a convex mirror. If its magnification is 0.6, calculate the focal length of the mirror", "images": [], "options": {"A": "3.75 cm", "B": "6.60 cm", "C": "10.00 cm", "D": "15.00 cm"}, "answer": "D", "explanation": "v=-6cm;m=0.6;m=vu==>0.6=6u;u=60.6=10cm  but1f=1u+1v  1f=110-16(v=-ve)  1f=6 - 1060  1f=-460  1f=-115  f=-15(focallengthofadivergingmirrorisnegative)  ∴f=15.00cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>24", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The refractive index of glass for yellow light is greater than that for red light because yellow light", "images": [], "options": {"A": "has a greater amplitude than red light", "B": "is more intense than red light", "C": "travels more slowly than than red light", "D": "deviates less than red light"}, "answer": "C", "explanation": "Refractive index is inversely proportional to wavelength. Yellow has lower wavelength compares to red. And that is why the refractive index is more in yellow light in the glass.    Wavelength is directly proportional to speed. Yellow light having a lower wavelength will have a slower speed than red light", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>25", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The real image of an object formed by a converging lens of focal length 15 cm is three times the size of the object. Calculate the object distance", "images": [], "options": {"A": "60 cm", "B": "30 cm", "C": "20 cm", "D": "15 cm"}, "answer": "C", "explanation": "f=15cm;m=3;u=?;m=vu==>3=vu;v=3u  but1f=1u+1v  115=1u+13u(sincev=3u)  115=3 + 13u  115=43u  15=3u4  15x4=3u  ∴u=5x4=20cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>26", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Which of the following statements is not correct about long sight?", "images": [], "options": {"A": "A long-sighted person can see distant objects clearly", "B": "light from a nearby object is focused behind the retina", "C": "The eyeball is too short", "D": "The defect is corrected by using a diverging lens."}, "answer": "D", "explanation": "Long sightedness, also known as hypermetropia, is a common eye condition where nearby objects appear blurred, while far objects can be seen clearly. This happens when the light that enters the eye is focused behind the retina, rather than directly on it. This is often because the eyeball is too short. However, the defect is corrected by using a converging lens, not a diverging lens. A converging lens is a lens that converges rays of light that are traveling parallel to its axis. It is thicker in the middle than at the edges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>27", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "The amplitude of a wave is the", "images": [], "options": {"A": "distance between two successive troughs of the wave", "B": "separation of two adjacent particles vibrating in phase", "C": "maximum displacement of the wave particle from the equlibrium position", "D": "distance travelled by a wave in complete cycle of its motion."}, "answer": "C", "explanation": "The amplitude of a wave is the maximum displacement of the wave particle from the equlibrium position", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>28", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "In order to obtain a sound note of a high pitch from a wire stretched by a constant tension, the wire must be", "images": [], "options": {"A": "short and thick", "B": "short and thin", "C": "long and thick", "D": "long and thin"}, "answer": "B", "explanation": "The pitch depends on frequency  and frequency is inversely proportional to length and mass density of the wire. So, the shorter the length of the wire, the more the frequency of the wire. Also the thinner the wire, the lesser the mass density and as a result, the more the frequency of the wire.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>29", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "If the position of resonance in a resonance tube is 16.50 cm from the open end of the tube, calculate the distance from the open end to the next position where resonance occurs.  [Neglect end-correction]", "images": [], "options": {"A": "24.70 cm", "B": "33.00 cm", "C": "41.25 cm", "D": "49.50 cm"}, "answer": "D", "explanation": "L=λ4=16.5 cm(forfirstresonance)  λ=4x16.5=66cm  L=3λ4=3 x 664=49.50cm(atnextresonance)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>30", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "Thunder is usually heard some seconds after lightning is observed because", "images": [], "options": {"A": "the human eye is more sensitive to light than the ear to sound", "B": "sound and light travel in different media", "C": "thunder occurs after lightning", "D": "light travels faster than sound"}, "answer": "D", "explanation": "A person on the ground sees lightning flash before hearing the thunder because light at a speed of around 3.0 x 108 ms-1 travels much faster than sound which moves at 330 ms-1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>31", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Using the diagram below, calculate the effective capacitance of the circuit.", "images": ["Physics/imgs/1999/phy_99_three_one.png"], "options": {"A": "1.56 μf", "B": "3.00 μf", "C": "3.71 μf", "D": "9.00 μf"}, "answer": "A", "explanation": "LetCbetheeffectivecapacitanceandC1bethecapacitanceinparallel==>C1=3+4=7μf  ∴1C=12+17=7 + 214  =1C=914  ∴C=149=1.56μf", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>32", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT", "question": "Using the data on the diagram below, calculate the potential difference across the 20 Ω resistor.  [Neglect the internal resistance of the cell]", "images": ["Physics/imgs/1999/phy_99_three_two.png"], "options": {"A": "5 V", "B": "10 V", "C": "20 V", "D": "60 V"}, "answer": "D", "explanation": "The P.d V1 across the 5 Ω wire = IR = 2 x 5 = 10 V  ∴Currentthroughthe10Ωwire=V1R=1010=1A  ∴ Total current across 20 Ω wire = 1 + 2 = 3 A  ∴ P.d V2 across 20 Ω wire = IR = 3 x 20 = 60 V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>33", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "The parts of a bar magnet at which the magnetic effect is strongest are called the", "images": [], "options": {"A": "poles", "B": "neutral points", "C": "magnetic declination", "D": "magnetic meridians"}, "answer": "A", "explanation": "A magnetic pole is the part of a magnet that exerts the strongest force on other magnets or magnetic material, such as iron.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>34", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A resistance wire of length 2 m and of uniform cross sectional area 5.0 x 10-7 m2 has a resistance of 2.2 Ω. Calculate its resistivity", "images": [], "options": {"A": "1.8 x 10-7 Ωm", "B": "5.5 x 10-7 Ωm", "C": "1.8 x 107 Ωm", "D": "5.5 x 107 Ωm"}, "answer": "B", "explanation": "R=ρLA  i.e2.2=ρ x 25.0 x 10-7  2.2x5.0x10-7=2ρ  ∴ρ=2.2 x 5.0 x 10-72=11 x 10-72=5.5x10-7Ωm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>35", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "Magnetic flux density is defined as the", "images": [], "options": {"A": "total number of magnetic lines of force surrounding a magnet", "B": "number of magnetic lines of force per unit area normal to the magnetic field", "C": "strength of the magnetic field sorrounding a current carrying conductor", "D": "magnetic force exerted on a unit magnetic pole"}, "answer": "B", "explanation": "The magnetic flux density or magnetic induction is the number of lines of force passing through a unit area of material, B. The unit of magnetic induction is the tesla (T).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>36", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "The voltage and current in the primary of a transformer are 200 V and 2 A respectively. If the transformer is used to light ten 12 V, 30 W bulbs, calculate its efficiency.", "images": [], "options": {"A": "100%", "B": "90%", "C": "75%", "D": "50%"}, "answer": "C", "explanation": "Power supplied to primary cell = IV = 2 x 200 = 400 W  Power developed in secondary cell = 10 x 30 = 300 W  ε=P.SP.Px100%  ==>ε=300400x100%  ∴ ε = 75%", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>37", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "In a uniform electric field, the magnitude of the force on a charge of 0.2 C is 4 N. Calculate the electric field intensity", "images": [], "options": {"A": "20 NC-1", "B": "8 NC-1", "C": "5 NC-1", "D": "2 NC-1"}, "answer": "A", "explanation": "The electric field intensity is defined as the force experienced by a unit positive charge placed in the field. It can be calculated using the formula E = F/q, where E is the electric field intensity, F is the force, and q is the charge. Substituting the given values, we get E = 4N / 0.2C = 20 NC-1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>38", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY", "question": "A rocket of mass m is fired from the earth's surface such that it just escapes from the earth's gravitational field. If R is the radius of the earth and g the acceleration of free fall due to gravity, the escape velocity of the rocket is expressed as", "images": [], "options": {"A": "√2gR", "B": "√2/Rg", "C": "√2g/R", "D": "√R2/2g"}, "answer": "A", "explanation": "The escape velocity of a rocket is given by the formula v = √(2gR), where g is the acceleration due to gravity and R is the radius of the Earth. This formula is derived from the principle of conservation of energy, which states that the total energy of an isolated system remains constant. In this case, the kinetic energy of the rocket (1/2 mv^2) is equal to the gravitational potential energy (mgh) at the point of escape. Solving for v gives the escape velocity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>39", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "A 10 Ω coil takes 21 s to melt 10 g of ice at 0oC. Assuming no heat losses, determine the current in the coil.  [Specific latent heat of fusion = 336 Jg-1]", "images": [], "options": {"A": "16 A", "B": "5 A", "C": "4 A", "D": "3 A"}, "answer": "C", "explanation": "I2Rt = mL  ==> I2 x 10 x 21 = 10 x 336  = I2 x 210 = 3360  =I2=3360210=16  ∴ I = √16 = 4 A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>40", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "A point charge of magnitude 2 μC is moved through a distance of 0.20 m against a uniform field of intensity 25 Vm-1. Calculate the workdone on the charge.", "images": [], "options": {"A": "5.0 x 10-6 J", "B": "1.0 x 10-5 J", "C": "5.0 x 10-5 J", "D": "1.0 x 10-2 J"}, "answer": "B", "explanation": "W = QV; but V = Ed; E = electric intensity  ==> V = 25 x 0.2 = 5 V  ∴ W = 2 x 10-6 x 5 = 1.0 x 10-5 J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>41", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Bohr's atomic model proves most successful for the explanation of the:  I. structure of the hydrogen atom  II. line spectra of the hydrogen atom  III. multi-electron atoms  Which of the following statements is/are correct?", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "I and III only"}, "answer": "C", "explanation": "The model's key success lay in explaining the Rydberg formula for hydrogen's spectral emission lines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>42", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "Use the diagram above to answer Questions below     The diagram above illustrates the energy transitions of five electrons of an atom. Which of the transitions will produce the emission of longest wave length?", "images": ["Physics/imgs/1999/YKH7NY.png"], "options": {"A": "I", "B": "II", "C": "III", "D": "IV"}, "answer": "A", "explanation": "The one with the least energy produces the longest wavelength  ΔE for I = 0.0 - (-2.6) = 0.0 + 2.6 = 2.6 eV (which is the least energy)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>43", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "Use the diagram above to answer Questions below   Which of the transitions will produce emission of highest frequency?", "images": ["Physics/imgs/1999/YKH7NY.png"], "options": {"A": "V", "B": "IV", "C": "III", "D": "II"}, "answer": "A", "explanation": "The one with the most energy produces the highest frequency  ΔE for V = 0.0 - (-12.0) = 0.0 + 12.0 = 12.0 eV (which is the most energy)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>44", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "The following statements relate to atomic spectrum  I. All elements emit and absorb characteristic spectra  II. Spectral analysis is an important method of identifying environmental pollutants  III. The chemical composition of stars could be determined using spectral analysis", "images": [], "options": {"A": "I, II and III", "B": "II and III only", "C": "I and III only", "D": "I and II only"}, "answer": "A", "explanation": "Atomic spectra is the spectrum of the electromagnetic radiation emitted or absorbed by an electron during transitions between different energy levels within an atom. When an electron gets excited from one energy level to another, it either emits or absorbs light of a specific wavelength.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>45", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "A metal has a work function of 4.375 eV. Calculate its threshold frequency  [h = 6.6 x 10-34 Js, 1 eV = 1.6 x 10-19 J]", "images": [], "options": {"A": "2.01 x 1015 Hz", "B": "1.06 x 1015 Hz", "C": "6.30 x 1014 Hz", "D": "1.60 x 1014 Hz"}, "answer": "B", "explanation": "W = hfo; W = 4.375 eV = 4.375 x 1.6 x 10-19 J    ==> 4.375 x 1.6 x 10-19 = 6.6 x 10-34 x fo    =fo=4.375 x 1.6 x 10-196.6 x 10-34=7 x 10-196.6 x 10-34  ∴  fo = 1.06 x 1015 Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>46", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The half-life of a radioactive substance is", "images": [], "options": {"A": "its average life time", "B": "one-half the value of its decay constant", "C": "the length of time needed by the substance to decay completely", "D": "the length of time during which the activity of the substance reduces by 50%"}, "answer": "D", "explanation": "The time-interval in which the mass of a radioactive substance or the number of its atoms, is reduced to half its initial value is called the half-life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>1999>47", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The half-life of a radioactive element is 5 s. Calculate its decay constant", "images": [], "options": {"A": "0.113 s-1", "B": "0.136 s-1", "C": "0.139 s-1", "D": "0.193 s-1"}, "answer": "C", "explanation": "λ=0.693t1/2=0.6935=0.139s-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>48", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "A sheet of paper is placed in the path of the following radiations  I. Alpha particles II. Beta particles III. Gamma rays  Which of the radiations will pass through the sheet of paper", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "II and III only"}, "answer": "D", "explanation": "Alpha particles can't go through paper, but beta particles and gamma rays can. When the three types of radiation hit the aluminium, only the gamma rays get through. Beta particles can get through paper but the aluminium stops them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>1999>49", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following are the essential parts of an atomic bomb?", "images": [], "options": {"A": "Uranium and neutrons", "B": "Radium and polonium", "C": "Nitrogen and neutrons", "D": "Uranium and α-particles"}, "answer": "A", "explanation": "An atomic bomb relies on nuclear fission, where the nucleus of an atom splits into two smaller nuclei. The process releases a large amount of energy. The most common materials used for this are isotopes of uranium or plutonium. Neutrons are used to initiate the fission process. Therefore, the essential parts of an atomic bomb are uranium and neutrons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>1999>50", "subject": "Physics", "year": "1999", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following is not a safety precaution in a nuclear station?", "images": [], "options": {"A": "Radioactive materials are stored in gas casings", "B": "Radioactive materials are handled with remote controlled tongs", "C": "Technicians in nuclear stations wear radio sensitive badges which are checked regularly", "D": "Radioactive materials are kept in thick-walled lead container"}, "answer": "A", "explanation": "The safety of operating staff is a prime concern in nuclear plants. Radiation exposure is minimised by the use of remote handling equipment for many operations in the core of the reactor. Other controls include physical shielding and limiting the time workers spend in areas with significant radiation levels.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>1", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "When the surface of a piece of chalk is scrapped the tiny particles that flake off are known as", "images": [], "options": {"A": "matter", "B": "molecules", "C": "elements", "D": "atoms"}, "answer": "D", "explanation": "Matter is anything that takes up space and has mass. While the chalk dust is certainly matter, it's not a specific term for the particles themselves.    Atoms are the smallest units of matter that retain the chemical properties of an element. Therefore, the individual particles of chalk dust are indeed atoms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>2", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : MEASUREMENT OF DISTANCE", "question": "Thediagramaboverepresentasectionofapairofverniercallipers.thereadingontheinstrumentis", "images": ["Physics/imgs/2000/JRY4HD.png"], "options": {"A": "5.22 cm", "B": "5.24 cm", "C": "5.25 cm", "D": "5.26 cm"}, "answer": "D", "explanation": "From the main scale, we have 5.2cm  (this is the last reading before & zero on the venier scale)  The reading on the vernier scale is 0.06cm  (where the main and vernier sccale coincides)    Reading = 5.2 + 0.06 = 5.26cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>3", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "An iron rod is moved from the earth to the moon. which of the following remains unchanged?.  I. mass  II. weight  III. relative density", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I and III only"}, "answer": "D", "explanation": "Mass and relative density is always constant.  Weight varies, because gravity on the earth and moon are not the same.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>4", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A uniform cylindrical hydrometer of mass 20g and cross sectional area 0.54cm2 floats upright in a liquid. if 25cm of its length is submerged, calculate the relative density of he liquid.[Density of water = 1g cm3]", "images": [], "options": {"A": "1.54", "B": "1.48", "C": "1.25", "D": "0.80"}, "answer": "B", "explanation": "Mass = 20g  Cross sectional area = 0.54cm2  Length = 25cm  Volume = area x length  V = 0.54 x 25 = 13.5cm3  Density=MV=2013.5=1.48gcm-3  R.D=Density of substanceDensity of water=1.481=1.48", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>5", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "The apparent weight of a body wholly immersed in water is 32N and its weight in air 96N. calculate the volume of the body. density of water = 1000kg m3, g = 10ms2", "images": [], "options": {"A": "8.9 ×10-3 m3", "B": "6.4 ×10-3 m3", "C": "3.2 ×10-3m3", "D": "3.0 × 10-3m3"}, "answer": "B", "explanation": "Apparent weight = 32N  Real weight = 96N  Density of water = 1000kgm-3  acceleration (g) = 10ms-2    Upthrust = Real weight - Apparent weight  ⇒ 96N - 32N = 64N    Upthrust = weight of body displaced  Weight of body = Vpg  gb = density  V=64gb=6410,000=6.4x10-3m3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>6", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "A wooden block of mass 1.6kg rest on a rough horizontal surface. if the limiting frictional force between the block and the surface is 8N, calculate the coefficient of friction [g = 10ms-2]", "images": [], "options": {"A": "0.6", "B": "0.5", "C": "0.3", "D": "0.2"}, "answer": "B", "explanation": "Wooden block weighs 1.6kg  Force = 8N  g = 10m/s2  Coefficientoffriction=FR  Reaction (R) = mg  R = 1.6 x 10 = 16N  μ=8N16N=0.5", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>7", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "A ball bearing is gently released from rest and allowed to fall through a viscous fluid. which of the following statement about the motion is correct?", "images": [], "options": {"A": "its acceleration decreases before terminal velocity is attained", "B": "when terminal velocity is attained the acceleration of the fluid becomes zero", "C": "its velocity increases before terminal velocity is attained", "D": "velocity"}, "answer": "B", "explanation": "After terminal velocity is reached, the net acceleration of the body falling through a fluid is zero because the body after attaining terminal velocity will continue moving with same velocity through the viscous medium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>8", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MOTION : RELATIVE MOTION", "question": "The driver of a car moving with a uniform speed of 40ms-1 observes a truck approaching in the opposite direction with a speed of 20ms-1. calculate the speed of the car relative to that of the truck.", "images": [], "options": {"A": "0.5ms-1", "B": "2.0ms-1", "C": "20.0ms-1", "D": "60.0ms-1"}, "answer": "D", "explanation": "Since they are moving in opposite directions   relative speed of the car to the truck is = 40 + 20 = 60m/s", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>9", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION", "question": "A bus travelling at 15ms-1 accelerates uniformly at 4ms-2 what is the distance covered in 10s?", "images": [], "options": {"A": "150m", "B": "170m", "C": "350m", "D": "600m"}, "answer": "C", "explanation": "Initial speed = 15m/s  acceleration = 4m/s2  time = 10s     Using 2nd Newton's law of motion,  s=ut+12at2  s=15x10+12x102x4  s = 150 + 200  s = 350m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>10", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "Which of the following sketches represents the velocity-time graph of the motion of a stone projected vertically upwards and allowed to return to the point of projection?", "images": ["Physics/imgs/2000/v26.png", "Physics/imgs/2000/v27.png", "Physics/imgs/2000/v28.png", "Physics/imgs/2000/v29.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "This graph shows the stones comes back to rest, to its original status", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>11", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above illustrates three forces T1, T2 and 100N in equilibrium. Determine the magnitude of T", "images": ["Physics/imgs/2000/v30.png"], "options": {"A": "100 tan 30∘", "B": "100cos30∘", "C": "200sin30∘", "D": "200tan30∘"}, "answer": "A", "explanation": "Therefore,  T1 = 100 tan 30∘    the magnitude of T = 100 tan 30∘.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>12", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY", "question": "A uniform meter rule of mass 90g is pivoted at the 40 cm mark. if the rule is in equilibrium with an unknown mass m placed ate the 10cm mark and a 72g mass at the 70cm mark, determine m", "images": [], "options": {"A": "72g", "B": "102g", "C": "198g", "D": "504g"}, "answer": "B", "explanation": "Applying the principle of moment   Anti clockwise = clockwise     m × 30 = (90 x 10) + (72 x 30)  30m = 900 + 2160  30m = 3060  m=306030=102g", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>13", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SCALARS AND VECTORS : ADDITION OF VECTORS", "question": "The resultant of two forces acting on an object is maximum when the angle between them is?", "images": [], "options": {"A": "180∘", "B": "90∘", "C": "45∘", "D": "0∘"}, "answer": "D", "explanation": "The resultant of two forces acting on an object is maximum when the angle between them is 0 degrees. This is because when two forces act in the same direction (i.e., the angle between them is 0 degrees), they add up to give the maximum resultant force. If the angle is anything other than 0 degrees, the resultant force will be less than the sum of the two forces due to the vector nature of forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>14", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The bob of a simple pendulum takes 0.25s to swing from its equilibrium position to one extreme end. calculate its period", "images": [], "options": {"A": "0.25s", "B": "0.50s", "C": "0.75s", "D": "1.00s"}, "answer": "D", "explanation": "Time taken to swing from equilibrium position to one extreme end, which is 1/4 period, is 0.25s  Period for 1 oscillation = 0.25s × 4 = 1.00s", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>15", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M", "question": "The period of oscillation of a particle executing simple harmonic motion is 4⊼ seconds. if the amplitude of oscillation is 3.0m, calculate the maximum speed of the particle.", "images": [], "options": {"A": "1.5ms-1", "B": "3.0ms-1", "C": "4.5ms-1", "D": "6.0ms-1"}, "answer": "A", "explanation": "T = 4π, r = 3.0m, V = ?  since V = wr  andw=2πT  substituting for T = 4π  w=2π4π=12  Therefore,  V = wr  V=12×3.0=1.5ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>16", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "An inelastic collision takes place between balls of known masses. just before the collision one of the balls is moving with a known velocity while other is stationary, which of the following physical quantities can be determined from the information given?", "images": [], "options": {"A": "speed of each of the ball after collision", "B": "kinetic energy of each ball afer collision", "C": "total momentum of the two balls after collision", "D": "mutual forces exerted by the balls"}, "answer": "C", "explanation": "In an inelastic collision, the total momentum before the collision is equal to the total momentum after the collision. This is known as the law of conservation of momentum. Therefore, we can determine the total momentum of the two balls after the collision. However, we cannot determine the speed or kinetic energy of each ball after the collision, or the mutual forces exerted by the balls, from the information given. Therefore, the correct option is 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>17", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "Using the force-displacement diagram shown above, calculate the work done.", "images": ["Physics/imgs/2000/v31.png"], "options": {"A": "2000J", "B": "1000J", "C": "20J", "D": "5J"}, "answer": "A", "explanation": "Work done  = force x displacement    = 100 x 20   = 2000J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>18", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A machine of efficiency 80% is used to raise a body of mass 75kg through a vertical height of 3m in 30s. calculate the power input.[g  = 10ms-1]", "images": [], "options": {"A": "9.4w", "B": "60.0w", "C": "75.0w", "D": "93.8 w"}, "answer": "D", "explanation": "Efficiency=work outputwork input=80100=75 x 10 x 3work input  80 x work input = 75 x 10 x 3   workinput=75 x 10 x 3 x 10080  =75 x 3 x 252  Power=work inputtime  =75 x 3 x 252 x 30=3754=93.75", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>19", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Two bodies, P and Q are in thermal equilibrium. which of the following statement about the bodies is correct?", "images": [], "options": {"A": "the temperature of Q is higher than that of P", "B": "p and Q have the same capacity", "C": "P and Q have the same mass", "D": "P and Q are the same temperature"}, "answer": "D", "explanation": "A condition where two bodies in contact no longer exchange heat, they are of the same temperature", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>20", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The cubic expansivity of mercury is 1.8 ×10-4k1  and the linear expansivity of glass is 8.0 ×10-6k-1. calculate the apparent expansivity of the mercury glass container.", "images": [], "options": {"A": "100 ×10-4k-1", "B": "1.56 ×10-4K-1", "C": "1.72 × 10× 104k-1", "D": "2.4 × 10-4k-1"}, "answer": "B", "explanation": "δr is the real cubic expansivity  δa is the apparent cubic expansivity  δ is the cubic expansivity of the vessel     Cubic expansivity of the vessel = 3 x expansivity of material   ⇒ 3 x 8.0 x 10-6 = 24.0 x 10-6  ⇒ 2.4 x 10-5  δr = δa + δ  δa = δr - δ  substituting,  δa = 1.8 x 10-4 - 2.4 x 10-5  ⇒ 1.8 x 10-4 - 0.24 x 10-4  ⇒ (1.8 - 0.24) x 10-4  ⇒ 1.56 x 10-4", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>21", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "Thediagramaboveshowsthevariationofvolumevofaglasswithtemperature0inacharles'law experiment.thevalueofthetemperatureatthepointsxis", "images": ["Physics/imgs/2000/v32.png"], "options": {"A": "-32∘c", "B": "-100∘c", "C": "-273∘c", "D": "-373∘c"}, "answer": "C", "explanation": "According to charle's law,  at -273°C the volume is assumed to be zero (0).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>22", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The volume and pressure of a given mass at 27∘c are 76cm3 and 80cm of mercury respectively. calculate its volume at s.t.p", "images": [], "options": {"A": "36.2cm", "B": "72.8cm", "C": "100.0cm", "D": "808.9cm"}, "answer": "B", "explanation": "P1V1T1=P2V2T2  T1 = 27°C = 27 + 273 = 300K  P1 = 80cmHg = 800mmHg  V1 = 76cm3    T2 = 273K  P2 = 760mmHg  V2 = ?  Making V2 the subject of formular  V2=P1V1T2P2T1  V2=800 x 76 760=72.8cm2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>23", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "A piece of metal of mass 50g is cooled from 80∘c to 20∘c calculate the amount of heat lost.[specify heat capacity of the material of metal  = 450Jkg-1k-1]", "images": [], "options": {"A": "4.50 × 103 J", "B": "2.25 ×103 J", "C": "1.80 × 103 J", "D": "1.35 × 103 J"}, "answer": "D", "explanation": "H = mcΔθ  substituting values in,   H = 0.05 x 450 x (80 - 20)  H = 0.05 x 450 x 60 = 1350J  H = 1.35 x 103J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>24", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT", "question": "The mass of water vapour in a given volume of air is 0.05 g  at 20∘c, while the mass of water vapour required to saturate it at the same temperature is 0.15g. calculate the relative humidity of air", "images": [], "options": {"A": "3.33%", "B": "5.55%", "C": "33.3%", "D": "55.5%"}, "answer": "C", "explanation": "Relative humidity is the ratio of the actual amount of water vapour present in the air to the maximum amount of water vapour the air could hold at that temperature, expressed as a percentage. Here, the actual amount of water vapour is 0.05g and the maximum amount of water vapour the air could hold at 20°C is 0.15g. Therefore, the relative humidity is (0.05g / 0.15g) * 100% = 33.3%. Therefore, the correct answer is 33.3%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>25", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "The temperature at which the saturated vapour pressure of liquid is equal to the external atmospheric pressure is known as", "images": [], "options": {"A": "dew point", "B": "boiling point", "C": "lower fixed point", "D": "tripple point"}, "answer": "B", "explanation": "When a liquid is exposed to atmospheric pressure, it boils when its saturated vapour pressure equals 1 atmospheric pressure (101325Pa)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>26", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A periodic pulse travels a distance of 20.0m in 1.00s. if its frequency is 2.0 × 103Hz, calculate the wavelength", "images": [], "options": {"A": "1.0×103m", "B": "1.0 × 102m", "C": "2.0 × 102m", "D": "1.0 × 10-2m"}, "answer": "D", "explanation": "V = F⋋  making ⋋ the subject of formular   ⋋=VF=202.0 x 103=10x10-3 = 10-2m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>27", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M", "question": "A wave has an amplitude equal to 4.0m .The displacement y of the 1/3⊼ rad s-1 and phase angle 2/3⊼ rad. The displacement y of the wave particle is given as", "images": [], "options": {"A": "y = 4 sin ⊼/3 (t-2)", "B": "y = 4 sin⊼/3(t+2/⊼)", "C": "y = 4 sin ⊼/3(2t+1)", "D": "y  = 4 sin⊼/3(t+2)"}, "answer": "D", "explanation": "y = Asin(ωt + ∅)  substituting  y=Asin(π3t +2π3)  y=4sinπ3(t+2)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>28", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "In the diagram above, an incident ray AY makes an angle an angle makes an angle of 30∘ with the normal XY, if the mirror is rotated anticlockwise about Y through an angle of 20∘, while AY is fixed, what angle will the reflected ray now make with the incident ray", "images": ["Physics/imgs/2000/v33.png"], "options": {"A": "70∘", "B": "80∘", "C": "100∘", "D": "120∘"}, "answer": "C", "explanation": "The new incident ray becomes = 30° + 20° = 50°  (since the mirror was rotated by 20°)  Therefore, the reflected ray = 50°  angle between incident ray and reflected ray = 50° + 50° = 100°", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>29", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A concave mirror can be used to produce a parallel beam of light if a lighted bulb is placed", "images": [], "options": {"A": "between its focus and the pole", "B": "at its focus", "C": "at its center of curvature", "D": "between its focus and center of curvature"}, "answer": "B", "explanation": "A concave mirror can be used to produce a parallel beam of light if a lighted bulb is placed at its focus. This is because the rays of light from the bulb, which are incident on the mirror, will reflect off the mirror and travel parallel to each other. Hence, option 2 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>30", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A  simple miscroscope forms an image 10cm from an eye close to the lens. if the object is 6cm from the eye , calculate the focal length of the lens", "images": [], "options": {"A": "3.75cm", "B": "4.00cm", "C": "15.00 cm", "D": "16.00cm"}, "answer": "A", "explanation": "Len formular,  1U+1V=1f  1f=110+16  3+530=830  F=308=3.75cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>31", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "When white light passes through a triangular glass prism, there is dispersion because of", "images": [], "options": {"A": "diffraction of light", "B": "polarisation of light", "C": "the difference of light wave in glass", "D": "the interference of light waves in glass"}, "answer": "C", "explanation": "The wavelength hence speed of each of the light components vary, therefore they leave at different angles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>32", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "In which of the following media does sound travel fastest", "images": [], "options": {"A": "water", "B": "brass", "C": "air", "D": "wood"}, "answer": "B", "explanation": "Sound travels fastest in solids compared to liquids and gases. This is because particles in a solid are closely packed together, allowing sound waves to transfer more quickly from one particle to the next. Among the given options, brass, which is a solid, would allow sound to travel the fastest.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>33", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SOUND WAVES : RESONANCE", "question": "A turning fork of frequency 600Hz is sounded over a close resonance tube . if the first and second resonant positions are 0.130m and 0.413m respectively, calculate the speed of sound in air.", "images": [], "options": {"A": "509.4ms-1", "B": "480.0ms-1", "C": "339.6ms-1", "D": "169.8ms-1"}, "answer": "C", "explanation": "Since,   F = 600Hz  V = F⋋ = 2F x (l2 - l1)  and ⋋ = l2 - l1 = (0.413 - 0.130) = 0.283  V = 2 x 600 x (0.413 - 0.130)  V = 2 x 600 x (0.283)  V = 339.6ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>34", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SOUND WAVES : RESONANCE", "question": "Loudness increases as a vibrating turning fork is brought nearer the end of a pipe containing air column due to", "images": [], "options": {"A": "resonance", "B": "echo", "C": "reverberation", "D": "diffraction"}, "answer": "A", "explanation": "The loudness of a sound increases due to resonance when a vibrating tuning fork is brought nearer to the end of a pipe containing air column. Resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration and hence increased loudness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>35", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SOUND WAVES : HARMONIES AND OVERTONES", "question": "The factor which enables the ear to distinguish between a note played on different instrument is the", "images": [], "options": {"A": "pitch", "B": "speed", "C": "harmonic", "D": "loudness"}, "answer": "C", "explanation": "The factor which enables the ear to distinguish between a note played on different instruments is the harmonic. Harmonics are the frequencies that are multiples of the fundamental frequency. Different instruments produce different sets of harmonics, which gives each instrument its unique sound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>36", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "An object is situated within earth's gravitational field. which of the following factors does not affect acceleration of free fall, g?", "images": [], "options": {"A": "The distance of the object from the center of the earth", "B": "latitude of the earth on which the object is situated", "C": "the mass of the object", "D": "rotation of the earth"}, "answer": "C", "explanation": "The acceleration of free fall, g, is not affected by the mass of the object. This is a fundamental principle of gravity that was famously demonstrated by Galileo when he dropped two objects of different masses from the Leaning Tower of Pisa and found that they hit the ground at the same time. The other options, such as the distance of the object from the center of the earth, the latitude of the earth on which the object is situated, and the rotation of the earth, can all affect the value of g.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>37", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The capacitance of the parallel-plate capacitor is increased by making the area of the plates", "images": [], "options": {"A": "small and their separation large", "B": "large and their separation small", "C": "and their seperation small", "D": "and their seperation equal"}, "answer": "B", "explanation": "The larger the area of a capacitor, the increase in capacitance, the smaller the distance of seperation between the plates the higher the capacitance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>38", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Usethediagramtoanswerthequestion      Inthediagramabove,thecurrentpassingthroughthe6Ωresistoris1.5A,calculatethecurrentinthe3Ωresistor", "images": ["Physics/imgs/2000/RJJRWE.png"], "options": {"A": "1.2A", "B": "0.90A", "C": "0.75A", "D": "0.60A"}, "answer": "D", "explanation": "For parallel connection,  effectiveresistance=12+13=56  R=65  Thereforevoltage=1.5×65=1.8    For 3Ω resistor,  I=VR=1.83=0.6A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>39", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Usethediagramtoanswerthequestion    calculate the terminal p.d of the battery in the diagram", "images": ["Physics/imgs/2000/RJJRWE.png"], "options": {"A": "7.5V", "B": "9.00V", "C": "10.80V", "D": "11.25V"}, "answer": "C", "explanation": "Terminal P.d (VT) = V6 + Vp  where,  V6 = voltage across 6Ω resistor  Vp=95V  VT=9+95=10.8V", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>40", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "An immersion heater is rated 120W. how long does it take the heater to raise the temperature of 1.2kg of water by 15∘C. [Assuming heat lost to the surrounding is negligible specific heat capacity of water  = 4200Jkg-1K-1]", "images": [], "options": {"A": "65.0 minutes", "B": "60.0 minutes", "C": "52.5 minutes", "D": "10.5 minutes"}, "answer": "D", "explanation": "Power lost = Power gained (By heater)  P=mcΔθt  therefore,  P x t = mcΔθ  t=mcΔθp=1.2 x 4200 x 15120  ⇒ 450 x 15 = 630 seconds    convert to minutes ⇒ 10.5 minutes", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>41", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "The region around a magnet in which the magnetic influence experienced is called ?", "images": [], "options": {"A": "Magnetic flux", "B": "magnetic field", "C": "magnetic meridian", "D": "magnetic decination"}, "answer": "B", "explanation": "The region around a magnet where magnetic forces can be detected is called the magnetic field. It is the space around a magnet where the magnetic influence can be experienced. Magnetic flux, on the other hand, is a measure of the total magnetic field which passes through a given area. Magnetic meridian and magnetic declination are terms related to Earth's magnetic field, not a magnet's.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>42", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "Ifthebarmagnetisaccidentlybrokenintothreeplaces asshowninthediagrambelow,thepolaritiesofPandQrespectivelyare", "images": ["Physics/imgs/2000/FLRTWC.png"], "options": {"A": "S and S", "B": "N and S", "C": "N and N", "D": "S and N"}, "answer": "B", "explanation": "Both ends cannot have the same polarity, and the north is closer to the original north of the original piece, same with the south.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>43", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A device used to prevent wearing away of the make-and -break contacts of an induction coil is called a/an", "images": [], "options": {"A": "fuse", "B": "electroscope", "C": "resisitor", "D": "capacitor"}, "answer": "D", "explanation": "A capacitor is connected across the make and break contacts, and helps the field to die off much rapidly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>44", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "An inductor of inductance 10H carries a current of 0.2A calculate the energy stored in the inductor.", "images": [], "options": {"A": "0.1J", "B": "0.2J", "C": "1.0J", "D": "2.0J"}, "answer": "B", "explanation": "Energystoredinaninductor=12LI2  =12x10x(0.2)2=0.2J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>45", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "Calculate the inductance of an inductor whose reactance is one ohm at 50Hz", "images": [], "options": {"A": "2.00 ×102H", "B": "6.36 × 103H", "C": "3.18 × 10-3H", "D": "4.55 × 104 H"}, "answer": "C", "explanation": "XL = 2πfL  Making L the subject of formular  L=XL2πF  L=72 x 22 x 50=744 x 50 = 3.18 x 10-3H", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>46", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "Bohr's theory provides evidence for the", "images": [], "options": {"A": "structure of the atom", "B": "positive charge of an electron", "C": "existence of energy level in the atom", "D": "positive charge on the proton"}, "answer": "C", "explanation": "Bohr's theory, also known as Bohr's model of the atom, provides evidence for the existence of energy levels in the atom. According to this theory, electrons orbit the nucleus in specific energy levels, and can absorb or emit energy when they transition between these levels.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2000>47", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A nuclide 20284Y emits in succession a α-particles and a β -particles. the atomic number of the resulting nuclide is", "images": [], "options": {"A": "198", "B": "83", "C": "82", "D": "80"}, "answer": "B", "explanation": "42He = α  β = 0-1e  20284Y → 42He + 0-1e  20284Y → 19882Z + 42He  19882Z → 19883A + 0-1e    Therefore, 82 - (-1) = 83", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>48", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The half life of a radioactive substance is 14days. if 48g of this substance is stored, after how many days will 1.5g of the original substance remain ?", "images": [], "options": {"A": "84 days", "B": "70 days", "C": "56 days", "D": "40 days"}, "answer": "B", "explanation": "4824  12  6  3  1.51 half life  2 half life  3 half life  4 half life  5 half life  5 half life = 5 x 14 = 70 days", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2000>49", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "A material of mass 1.0 × 103 kg undergoes a fission process which decreases its mass by 0.02 percent. calculate the amount of energy released in the process [c = 3.0 × 108ms-1]", "images": [], "options": {"A": "1.8 × 1020 J", "B": "1.8 × 1013 J", "C": "1.8 × 1012 J", "D": "1.8 × 1010 J"}, "answer": "C", "explanation": "E = ΔMc2  0.02 x 1.0 x 10-3 x (3.0 x 108)2  2.0 x 10-5 x 9.0 x 1016  1.8 x 1012J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2000>50", "subject": "Physics", "year": "2000", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "Absorption line spectra exhibited by atoms is a result of", "images": [], "options": {"A": "change in the kinetic energy of a moving atom", "B": "instability of the nucleons", "C": "excation of an electron in the atom", "D": "transition of an electron from a higher to lower energy level"}, "answer": "D", "explanation": "Absorption line spectra are produced when an electron absorbs energy and transitions from a lower energy level to a higher energy level within an atom. When the electron returns to its original energy level, it emits a photon of light. The energy of this photon corresponds to a specific wavelength of light, which appears as a line in the absorption spectrum. Therefore, the correct answer is 'transition of an electron from a higher to lower energy level'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>1", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following physical processes cannot be explained by the molecular theory of matter?", "images": [], "options": {"A": "Evaporation", "B": "thermal conduction", "C": "radiation of heat", "D": "convention currents in fluids"}, "answer": "C", "explanation": "Radiation cannot be explained by the molecular theory of matter. It is the movement of electro-magnetic waves not matter (particles).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>2", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A spring balance, which is suspended from the roof of a lift, carries a mass of 1kg at its free end. if the lift accelerates upwards at 2.5ms-2, determines the reading on the spring balance. [g = 10ms-2]", "images": [], "options": {"A": "25.0N", "B": "12.5N", "C": "7.5N", "D": "4.0N"}, "answer": "B", "explanation": "Since the lift is accelerating upwards,  The total force will be,   F = Ma  ⇒ 1 × 2.5 = 2.5N  Weight = mg = 1 × 10 = 10N  Reading = F + wt = 2.5 + 10 = 12.5N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>3", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "An object of weight 10N immersed in a liquid displaces a quantity of the liquid. if the liquid displaced weighs 6N. determine the upthrust on the object", "images": [], "options": {"A": "20N", "B": "10N", "C": "6N", "D": "4N"}, "answer": "C", "explanation": "The upthrust on an object immersed in a fluid is equal to the weight of the fluid displaced by the object. In this case, the weight of the liquid displaced is 6N, so the upthrust on the object is also 6N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>4", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Which of the following statement about pressure is not correct? pressure", "images": [], "options": {"A": "increases with an increase in surface area", "B": "decreases with an increase in surface area", "C": "increases with a decrease in surface area", "D": "increases with an increase in the applied force"}, "answer": "A", "explanation": "Pressure is defined as the force per unit area. Therefore, if the surface area increases while the force remains constant, the pressure decreases. This is because the force is spread over a larger area, reducing the pressure. Hence, the statement 'pressure increases with an increase in surface area' is not correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>5", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "The apparent weight of a body fully immersed in water is 32N and its weight in air is 96N. calculate the volume of the body.[Density of water = 1000kg m3, g = 10ms-2]", "images": [], "options": {"A": "8.9 ×10-3m3", "B": "6.4 ×10-3m3", "C": "3.2 ×10-3m3", "D": "3.0 ×10-3m3"}, "answer": "B", "explanation": "When fully immersed in water,  apparent weight = 32N   Weight in air = 96N  Therefore, the upthrust = weight in Air - weight in water  ⇒ 96 - 32 = 64N  Also, F = Ma  Therefore, M=Fa=Fg=6410=6.4kg  DensityMassvolume,Volume=Massdensity  =6.41000=6.4×10-3m3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>6", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "A block weighing 15N rest on a flat surface and a horizontal force of 3N is exerted on it. Determine the frictional force on the block.", "images": [], "options": {"A": "0.3N", "B": "0.5N", "C": "3.0N", "D": "5.0N"}, "answer": "C", "explanation": "Weight = Force of gravity = 15N  Applied force = 3N  The block is not accelerating,  Therefore the block is in it's static state,  F = UF  Also, U = Applied Force/Weight  U=315=0.2  Therefore,  where F is the normal force  U is the coefficient of friction  F is the weight  F = 0.2 × 15 = 3N", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>7", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "Which of the following equation represents the distance x, travelled by a body moving on a straight road with a constant speed ? [The other symbols have their usual meaning]", "images": [], "options": {"A": "X = ut + 1/2at2", "B": "X = ut", "C": "x=V2-u22a", "D": "X = - 1/2 at2"}, "answer": "B", "explanation": "The equation for distance travelled by a body moving with a constant speed is given by X = ut, where 'u' is the initial velocity and 't' is the time. The other equations involve acceleration (a), which is not present in a motion with constant speed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>8", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : ENERGY OF S.H.M", "question": "The amplitude of the motion of a body performing simple harmonic decreases with time because", "images": [], "options": {"A": "frictional forces dissipate the energy with time", "B": "The frequency of oscillation varies with time", "C": "the period of oscillation varies over time", "D": "energy is supplied by some external agencies"}, "answer": "A", "explanation": "In a simple harmonic motion, the amplitude decreases with time due to the dissipation of energy by frictional forces. The frequency and period of oscillation do not vary with time in simple harmonic motion, and energy is not supplied by external agencies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>9", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M", "question": "The amplitude of the particle executing simple harmonic motion is 5cm while it angular frequency is 10 rads-1.calculate the magnitude of the maximum acceleration of the particle.", "images": [], "options": {"A": "0.25ms-1", "B": "0.50ms-1", "C": "2.00ms-1", "D": "5.00ms-1"}, "answer": "D", "explanation": "Maximum acceleration (a) = w2r  w = 10, r = 5cm = 0.05m  substituting values for w and r, we have   a = 102 × 0.05 = 5ms-2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>10", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "The time rates of change of momentum is", "images": [], "options": {"A": "impulse", "B": "force", "C": "power", "D": "pressure"}, "answer": "B", "explanation": "The tie rate of change of momentum is force.  This is gotten from Newton's second law.  The rate of change of linear momentum of a body is directly proportional to the external force applied on the body, and takes place always in the direction of the force applied.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>11", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statement about elastic collision is correct ?", "images": [], "options": {"A": "Momentum is lost due to the sound produced", "B": "loss in momentum is equal to loss in kinetic energy", "C": "Both kinetic energy and momentum are conserved", "D": "kinetic energy is lost while momentum is conserved"}, "answer": "C", "explanation": "In an elastic collision, both momentum and kinetic energy are conserved. This means that the total momentum and total kinetic energy before the collision is equal to the total momentum and total kinetic energy after the collision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>12", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Electrical resistance is a property of an electrical conductor that causes electrical energy to be converted into", "images": [], "options": {"A": "mechanical energy", "B": "heat energy", "C": "magnetic energy", "D": "chemical energy"}, "answer": "B", "explanation": "Electrical resistance is a property of an electrical conductor that opposes the flow of an electric current resulting in the conversion of electrical energy into heat energy. This is due to the collisions of the moving particles within the conductor which generates heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>13", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MACHINES :", "question": "A simple machine with an efficiency of 75% lifts a load of 5000 N when a force of 500N is applied to it. calculate the velocity ratio of the machine", "images": [], "options": {"A": "10.0", "B": "13.3", "C": "17.5", "D": "25.0"}, "answer": "B", "explanation": "M.A=LoadEffort  Load = 5000N, Effort = 500N  M.A=5000N500N=10    Efficiency=M.AV.R=0.75  V.R=M.AEfficiency=100.75=13.3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>14", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MACHINES :", "question": "A screw jack with a tommy bar of length 12cm is used to raise a car through a vertical height of 25cm by turning the Tommy bar through 50 revolutions. Calculate the approximate velocity ratio of the jack.[π = 3.14]", "images": [], "options": {"A": "21", "B": "38", "C": "48", "D": "151"}, "answer": "D", "explanation": "V.R=2πap  a=12,p=2550=0.5  substituting values  V.R=2 × 3.14×120.5=151", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>15", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A beam PQ pivoted at P carries a load of 80N as shown above . calculate the effort, E, required to keep it horizontal. [Neglect the weight of the beam]", "images": ["Physics/imgs/2001/v39.png"], "options": {"A": "32.0N", "B": "26.7N", "C": "16.0N", "D": "13.3N"}, "answer": "D", "explanation": "Clock-wise motion = Anti-clockwise motion  substituting values,  3 × E = 80 × 0.5  3E = 40  E=403=13.3N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>16", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A resistance thermometer has a resistance of 20Ω at 100∘C. if the resistance is 52Ω in a medium . calculate the corresponding temperature.", "images": [], "options": {"A": "49.2∘C", "B": "60.6∘C", "C": "80.0∘C", "D": "84.7∘C"}, "answer": "A", "explanation": "Therefore, 100 - 0x - 0=85 - 2052 - 20  X=100 × 3265 = 49.2°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>17", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "A given mass of an ideal gas has a pressure of 500N m-2 at -13∘C. if its volume remains constant, calculate its pressure at 247∘C.", "images": [], "options": {"A": "25N m-2", "B": "50N m-2", "C": "500N m-2", "D": "1000N m-2"}, "answer": "D", "explanation": "Volume is constant  From the question,  P1 = 500Nm-2, T1 = -13°C = 260K, P2 = ?, T2 = 247°C  T2 = 247°C + 273°C = 520K    Using pressure law,  P1T1=P2T2  P2=P1T2T1  substituting  P2=500×520260=1000Nm-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>18", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The volume of an ideal gas has a pressure of 77cm Hg and temperature 60∘C is 240cm3. if the temperature and pressure are increased at 98∘C and 81 Hg respectively. calculate the new volume of the gas .", "images": [], "options": {"A": "411.5 cm3", "B": "267.1cm3", "C": "254.2cm3", "D": "112.7cm3"}, "answer": "C", "explanation": "V1P1T1=V2P2T2  V1 = 240cm3  P1 = 77mmHg  T1 = 60°C = 60 + 273 = 333K  V2 = ?, P2 = 81mmHg, T2 = 98°C = 98 + 273 = 371K  V2=V1P1T2T1P2  =240 x 77 x 371333 x 81 = 254.2cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>19", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "The amount of heat given out or absorbed whe a substance changes its state at a constant temperature is known as", "images": [], "options": {"A": "latent heat", "B": "heat capacity", "C": "specific latent heat", "D": "specific heat capacity"}, "answer": "A", "explanation": "Latent Heat is the heat required to convert a solid into a liquid or vapour, or a liquid to vapour, without change in temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>20", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : VAPOUR AND VAPOUR PRESSURE", "question": "Which of the following physical quantities affects the saturated vapour pressure of the liquid", "images": [], "options": {"A": "Temperature", "B": "volume", "C": "mass", "D": "Density"}, "answer": "A", "explanation": "The saturated vapour pressure of a liquid is the pressure exerted by a vapour in thermodynamic equilibrium with its condensed phases at a given temperature. It is dependent on the temperature of the liquid. As the temperature increases, the kinetic energy of the molecules increases, and more molecules can escape from the surface of the liquid to the vapour phase, increasing the saturated vapour pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>21", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY AND THE WEATHER", "question": "Humidity is used to describe the amount of", "images": [], "options": {"A": "air in water vapour", "B": "cloud available in the atmosphere", "C": "air in equal colume of cloud", "D": "water vapour in the atomsphere"}, "answer": "D", "explanation": "Humidity is a measure of the amount of water vapour in the atmosphere. It is not a measure of the amount of air in water vapour, the amount of cloud available in the atmosphere, or the amount of air in an equal volume of cloud. Therefore, the correct answer is 'water vapour in the atmosphere'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>22", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "PROPERTIES OF WAVES : REFRACTION", "question": "Surface waves travelling in deep water at 15ms-1 are incident at shallow water boundary. if the angles of incidence and refraction are 45∘ and 30∘ respectively, calculate the speed of the waves in shallow waters.", "images": [], "options": {"A": "8.7 cm", "B": "10.6 cm", "C": "15.4 cm", "D": "17 cm"}, "answer": "B", "explanation": "index(n)=sin isin r=speed in deep waterspeed in shallow water  subsituting values,  sin 45sin 30=15x  x=15sin30sin45=10.6ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>23", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "An incident ray is reflected normally by a plane mirror onto a screen where it forms a bright spot. the mirror and screen are parallel and 1m apart.if the mirror is rotated through 5∘ calculate the displacement. of the spot.", "images": [], "options": {"A": "8.7cm", "B": "10.0cm", "C": "15.4cm", "D": "17.6cm"}, "answer": "D", "explanation": "Angle of rotation = 5°  Glancing angle = 2 × angle of rotation  ⇒ 2 × 5° = 10°  tanθ=Displacement from spotOriginal distance  tan10=x100cm  x = 100tan10 = 100 × 0.176 = 17.6cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>24", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Convex spherical mirrors are preferred to plane mirrors as driving mirrors because", "images": [], "options": {"A": "the image produced are upright and clearly visible", "B": "it provides a wider field of view", "C": "the image produced is erect and diminished", "D": "the image produced is not laterally inverted."}, "answer": "B", "explanation": "Convex spherical mirror gives a wider view, which allow the driver see most of the traffic behind him.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>25", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "An object is placed 260 cm from a lens . calculate the magnification of the  image", "images": [], "options": {"A": "28", "B": "26", "C": "24", "D": "13"}, "answer": "D", "explanation": "Magnification=VirtualReal=VU  =26020=13", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>26", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "A piece of cloth appears green in sunlight. when held in red light, it appears", "images": [], "options": {"A": "green", "B": "blue", "C": "red", "D": "black"}, "answer": "D", "explanation": "A piece of green cloth held under a red light will appear black, this is because the green colour is absorbed by the red spectrum, no colour is reflected, hence the black colour.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>27", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Dispersion of white light by a glass prism occurs because", "images": [], "options": {"A": "A white light consists of a mixture of seven different colours", "B": "Refractive index of glass is different for each constituent for each colour", "C": "The speed of each colour of light in for each colour", "D": "speed of each colour of light in the glass is proportional to the angle of refractive index of glass"}, "answer": "B", "explanation": "Dispersion of white light by a glass prism occurs because the refractive index of glass is different for each constituent color. This is due to a phenomenon known as dispersion, where different wavelengths (or colors) of light are refracted by different amounts. This causes the white light to split into its constituent colors, creating a spectrum.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>28", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "Which of the following statement about sound is correct?", "images": [], "options": {"A": "A sound wave travels for the normal at point of incidence", "B": "sound travel faster in air than water", "C": "the wavelength of sound changes when its travels from air to  water", "D": "the frequency of sound changes when it travels from air to water"}, "answer": "C", "explanation": "The correct statement about sound is that the wavelength of sound changes when it travels from air to water. This is because the speed of sound is different in different mediums. When sound travels from air to water, its speed increases, and since the frequency remains the same (as frequency is a property of the source and doesn't change with medium), the wavelength must increase (since speed = frequency x wavelength).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>29", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The diagram above shows the wire of a sonometer box set into resonance by vibrating turning fork of frequency, f, when the wire is stretched by a tension T, the resonating length of the sound produced is ⋋         Which of the following statement is not correct? The wave produced on the wire is", "images": ["Physics/imgs/2001/KXJYAD.png"], "options": {"A": "stationary and longitudinal", "B": "stationary and mechanical", "C": "mechanical and longitudinal", "D": "progressive and transverse"}, "answer": "A", "explanation": "Sound wave are longitudinal and since , it is a standing wave, it is stationary", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>30", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The diagram above shows the wire of a sonometer box set into resonance by vibrating turning fork of frequency, f, when the wire is stretched by a tension T, the resonating length of the sound produced is ⋋       Which of the following statement about the frequency of mass per unit is not correct? it is", "images": ["Physics/imgs/2001/KXJYAD.png"], "options": {"A": "proportional to the mass per unit length of the wire", "B": "Equal to the frequency of the turning fork", "C": "inversely proportional to the lenght of the wire", "D": "proportional to the  square root of the tension"}, "answer": "A", "explanation": "The frequency of vibration of a wire is not proportional to the mass per unit length of the wire.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>31", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The diagram above shows the wire of a sonometer box set into resonance by vibrating turning fork of frequency, f, when the wire is stretched by a tension T, the resonating length of the sound produced is ⋋       if the frequency of the turning fork at resonance is 256Hz, calculate the frequency of vibration of the wire when the tension in the wire is increased to 196N.", "images": ["Physics/imgs/2001/KXJYAD.png"], "options": {"A": "130.6Hz", "B": "182.9Hz", "C": "358.4Hz", "D": "501.8Hz"}, "answer": "C", "explanation": "F = k&radic;T&nbsp;  From this relationship we know,  F1&radic;T1&nbsp;=F2&radic;T2&nbsp;  From question  T1 = 100N, T2 = 196N, F1 = 256Hz, F2 = ?   Making F2 the subject of formular  F2=F1&radic;T2&nbsp;&radic;T1&nbsp;=256&radic;196&nbsp;10  F2 = 358.4Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>32", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "The magnitude of the gravitational force between two particles 0.10m apart is 10N. if the distance between them is increased to 0.20m, calculate the magnitude of the new force", "images": [], "options": {"A": "40.0N", "B": "20.0N", "C": "5.0N", "D": "2.5N"}, "answer": "D", "explanation": "F=kr2  Therefore,  F1r12 = F2r22  F1 = 10N, r1 = 0.10m, F2 = ?, r2 = 0.2  making F2 the subject,  F2=&radic;F1r12&nbsp;r22=10(0.1)2(0.2)2=2.5N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>33", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "As plates of a charged variable capacitors are moved closer together, the potential difference between them", "images": [], "options": {"A": "increases", "B": "decreases", "C": "remains the same", "D": "is doubled"}, "answer": "B", "explanation": "As the distance between the plates decreases, capacitance increases. And as capacitance increases, the potential difference decreases since potential difference is inversely proportional to the capacitance so that the charge remains constant (V = Q/C)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>34", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Use the diagram to answer  question       What is the effective capacitance in the circuit?", "images": ["Physics/imgs/2001/v40.png"], "options": {"A": "2 µF", "B": "6 µF", "C": "18 µF", "D": "216 µF"}, "answer": "A", "explanation": "For capacitors in series  1C1+1C2+1C3+1C4...  Therefore,  1C1+1C2+1C3  16+16+16=36=12  C = 2 µF", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>35", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Use the diagram to answer  question   What is the total energy stored by the capacitors?", "images": ["Physics/imgs/2001/v40.png"], "options": {"A": "2.0 ×10-4 J", "B": "1.0×10-4 J", "C": "9.0×10-4 J", "D": "1.0×10-2 J"}, "answer": "D", "explanation": "TotalEnergy=E=12CV2  E=12CV2  substituting values,  E=12×2×10-6×104J=10-2J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>36", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Three identical lamps each of power 100w, are connected in a parallel across a potential difference of 250v. calculate the current in the circuit", "images": [], "options": {"A": "7.5A", "B": "2.5A", "C": "1.2A", "D": "0.8A"}, "answer": "C", "explanation": "Power = IV  making I the subject of the formula  I = P/V  Eachlamphascurrent,I=100250=25A  Potential difference across equals = I1 + I2 + I3  =25+25+25=1.2Amperes", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>37", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "An electric bulb is rated 60W, 220V. calculate the resistance of its filament when it is operating normally", "images": [], "options": {"A": "296.7Ω", "B": "400.0Ω", "C": "512.2Ω", "D": "806.7Ω"}, "answer": "D", "explanation": "P=V2R  where,  P = Power, V = Potential difference, R = Resistance  Making R the subject of formular   R = V2/P = (220)2/60 = 806.7Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>38", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MAGNETIC FIELD : THE EARTH’S MAGNETIC FIELD", "question": "The earth 's magnetic equator passes through jos in Nigeria at jos, the", "images": [], "options": {"A": "angle of variation is zero", "B": "magnetic declination is 90∘.", "C": "angle of dip is zero", "D": "horizontal component of the earth's magnetic field is zero"}, "answer": "C", "explanation": "Jos, Nigeria is closer to the equator. The angle of dip at the equator is typically close to zero degrees. This means that the magnetic field lines are nearly horizontal to the Earth's surface.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>39", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "Which of the following statement about magnetic lines of force is not correct?", "images": [], "options": {"A": "A magnetic line of force is an imaginary line which the north pole of a magnet would describe if it is free to move", "B": "magnetic lines of force do not cross one another", "C": "The presence of magnetic lines of force ina region indicates the presence of a manetic field", "D": "magnetic lines of force are closely-packed together at neutral point"}, "answer": "D", "explanation": "A neutral point in a magnetic field is a point at which the horizontal component of earth's magnetic field and magnetic field due to the magnet are equal and opposite.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>40", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "The material used for reconstructing the core of an electromagnet is", "images": [], "options": {"A": "iron", "B": "carbon", "C": "copper", "D": "steel"}, "answer": "A", "explanation": "The core of an electromagnet is usually made from a ferromagnetic material like iron. This is because iron has a high magnetic permeability, meaning it can easily be magnetized and demagnetized. This property makes it ideal for use in the core of an electromagnet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>41", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "In a circuit diagram above calculate the energy stored in the inductor at resonance", "images": ["Physics/imgs/2001/v41.png"], "options": {"A": "0.100J", "B": "0.050J", "C": "0.010J", "D": "0.005J"}, "answer": "B", "explanation": "At resonance,  I=VR  100100=1Ampere  Energystoredininductor=12L12  substituting,  L=12(0.1)(1)2 = 0.05J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>42", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "calculate the reactance of the inductor in the circuit diagram shown above.[⊼ = 22/7]", "images": ["Physics/imgs/2001/v42.png"], "options": {"A": "132Ω", "B": "214Ω", "C": "264Ω", "D": "269Ω"}, "answer": "C", "explanation": "Resistance of inductor = XL = 2πfL  2x227x60x0.71=264Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>43", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "In which of the following transitions is the largest quantum of energy liberated by an hydrogen atom when the electron changes energy levels? (n is the quantum number )", "images": [], "options": {"A": "n = 2 to n = 1", "B": "n = 1 to n = 2", "C": "n = 2 to n = 3", "D": "n = 3 to n= 2"}, "answer": "A", "explanation": "The energy difference between energy levels in a hydrogen atom is given by the Rydberg formula. The energy difference is greatest when the transition is from n=2 to n=1. This is because the energy levels in a hydrogen atom are not equally spaced, but get closer together as n increases. Therefore, the energy difference is greatest for transitions to the n=1 level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>44", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "A photon of wavelength ⋋∘ is emitted when an electron in an atom makes a transition from a level of energy 2Ek to that of energy Ek. if the electron transits from 4/3Ek to Ek level determine the wavelength of the proton that would be emitted", "images": [], "options": {"A": "3⋋∘", "B": "2⋋∘", "C": "3/4⋋∘", "D": "1/3⋋∘"}, "answer": "D", "explanation": "2EK - EK = ⋋0  EK = ⋋0  43EK-EK=x  =4EK - 3EK3=x  EK3=0  but EK = ⋋0  substituting,  x=⋋03=13⋋", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>45", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Production of x-ray in an x-ray tubes begins with", "images": [], "options": {"A": "photo electric emission", "B": "collision of electrons", "C": "thermionic emission", "D": "field  emission of electrons"}, "answer": "C", "explanation": "The production of X-rays in an X-ray tube begins with thermionic emission. In this process, electrons are emitted from a heated filament. These electrons are then accelerated towards a metal target, producing X-rays when they collide with the target atoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>46", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The nucleon number and the proton number of a neutral atom of an element are 23 and 11 respectively. how many neutrons are present in the atom?", "images": [], "options": {"A": "11", "B": "12", "C": "23", "D": "34"}, "answer": "B", "explanation": "The nucleon number of an atom is the total number of protons and neutrons in the nucleus. Given that the nucleon number is 23 and the proton number is 11, the number of neutrons can be calculated by subtracting the proton number from the nucleon number. Therefore, the number of neutrons is 23 - 11 = 12.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2001>47", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "A nitrogen nucleus bombarded with alpha particles produces an oxygen nucleus and proton. The nuclear reaction for this process is 42He + 148N →178O + 11 + Q. Which of the following statement about the reaction is not correct?", "images": [], "options": {"A": "A bombardment result into a nucleus with a greater proton number", "B": "it is an induced nuclear reaction greater proton number", "C": "it is a natural radioactive decay", "D": "the sum of the initial nucleon numbers is equal to the sum of final nucleon numbers"}, "answer": "C", "explanation": "The given nuclear reaction is an example of induced nuclear reaction, not a natural radioactive decay. In natural radioactive decay, the nucleus of an atom spontaneously disintegrates into a different nucleus or different particle. However, in this case, the nitrogen nucleus is bombarded with alpha particles to produce an oxygen nucleus and a proton, which is a process of induced nuclear reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>48", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "ENERGY : WORLD ENERGY RESOURCES", "question": "In nuclear reactor, electricity can be generated through the following processes, arrange the process in the correct order  I. The steam is used to drive turbines   II. The heat energy released is removed by passing water through the reactor   III. The turbines in turn generates electricity  IV. The water then passes through some form of heat exchanger to produce steam", "images": [], "options": {"A": "II,IV,I and III", "B": "I,II,III and IV", "C": "III,I,IV and II", "D": "IV,I,III and II"}, "answer": "A", "explanation": "The heat energy is released is removed by passing water through the reactor, which produces steam, the steam drives the turbine which produces electricity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2001>49", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Electrons passing through crystals are diffracted because they", "images": [], "options": {"A": "Are repelled by the atoms in the crystal", "B": "Are attracted by the atoms in the crystal", "C": "posses wave properties", "D": "are particles"}, "answer": "C", "explanation": "Electrons passing through crystals are diffracted because they possess wave properties. This is based on the wave-particle duality principle in quantum mechanics, which states that every particle or quantum entity can be described as both a particle and a wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2001>50", "subject": "Physics", "year": "2001", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "The duality of matter implies that", "images": [], "options": {"A": "exits as a particle of dual composition", "B": "has momentum and energy", "C": "has both wave and particles properties", "D": "is made of dual materials"}, "answer": "C", "explanation": "Matter exhibit both wave and particle properties. It is the concept of quantum mechanics that every particle can be described as a \"wave\" or \"particle\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>1", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "One common characteristics of solid, liquid and gases is that", "images": [], "options": {"A": "all the three have fixed volume", "B": "their molecules have the same size", "C": "their molecular are always in motion", "D": "all the three have the same inter molecular forces"}, "answer": "C", "explanation": "One common characteristic of solids, liquids, and gases is that their molecules are always in motion. This is based on the kinetic theory of matter, which states that all matter is composed of particles (molecules, atoms, or ions) that are in constant motion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>2", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "the forces between the molecules of a liquid in contact with that of a solid is", "images": [], "options": {"A": "adhesive", "B": "cohesive", "C": "magnetic", "D": "repulsive"}, "answer": "A", "explanation": "The forces between the molecules of a liquid in contact with that of a solid are adhesive forces. Adhesive forces refer to the attractive force between two unlike molecules. They are caused by forces of attraction between different substances, such as mechanical and electrostatic forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>3", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The energy needed to separated the nucleons against the forces which hold them together is", "images": [], "options": {"A": "nuclear energy", "B": "mechanical energy", "C": "ionisation energy", "D": "binding energy"}, "answer": "D", "explanation": "The energy needed to separate the nucleons against the forces which hold them together is known as binding energy. Binding energy is the energy required to disassemble a whole system into separate parts. A bound system typically has a lower potential energy than its constituent parts; this is what keeps the system together. The difference in potential energy is known as the binding energy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>4", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A reservoir is filled with a liquid of density 2000kgm-3. calculate the depth at which the pressure in the liquid will be equal to 9100Nm-2.[g ^ 10ms-2].", "images": [], "options": {"A": "0.262m", "B": "0.455m", "C": "0.664m", "D": "0.8119m"}, "answer": "B", "explanation": "P = ρgh  (ρ = density, h = depth, g = 10m/s2)  9100 = 2000 × 10 × h  h=910020,000=0.455m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>5", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "solid weighs 45N and 15N respectively in air and water.Determine the relative density of the solid", "images": [], "options": {"A": "0.33", "B": "0.50", "C": "1.50", "D": "3.00"}, "answer": "C", "explanation": "R.D=weight in airupthrust  Weight in air = 45N  Weight in water = 15N  Upthrust = 45 - 15 = 30N  R.D = 45N/30N = 1.5", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>6", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "POSITION, DISTANCE AND DISPLACEMENT : DISTINCTION BETWEEN DISTANCE AND DISPLACEMENT.", "question": "A boy travels 8km eastward to a point B and ten 6km northward to another point c, determine the difference between the magnitude of displacement of the boy and distance travelled by him.", "images": [], "options": {"A": "2.0km", "B": "4.0km", "C": "10.0km", "D": "14.0km"}, "answer": "B", "explanation": "The difference in the displacement = length OC    OC2 = OB2 + BC2    ⇒ 82 + 62  ⇒ = 64 + 36  OC2 = 100  squaring both sides  OC = 10km  total distance  = 14km  Difference between distance and displacement  = 14 - 10 km = 4km", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>7", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "The magnitude of the force required to make an object of mass, m move with speed, v in a circular path of radius. is given by the expression", "images": [], "options": {"A": "mr/v", "B": "mr2/v", "C": "mv2/r", "D": "mv/r2"}, "answer": "C", "explanation": "The force required to keep an object moving in a circular path is given by the centripetal force formula, which is F = mv^2 / r, where m is the mass of the object, v is the speed of the object and r is the radius of the circular path. Hence, the correct option is 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>8", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "A man was moving round a circular path continuously for 4 minutes and covered the following distance in the times stated below   Distance(in metres) 200 400 600 800Time (in minutes) 1 2 3 4. which of the following statement is correct about the motion of the man?", "images": [], "options": {"A": "The man was moving with uniform speed but non-uniform velocity", "B": "The speed was changing constantly", "C": "The velocity was uniform", "D": "it was an instance of motion is which both speed and velocity are the same"}, "answer": "A", "explanation": "V=2001=4002=6003=8004=200m/min  Uniform speed but direction keeps changing", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>9", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION", "question": "A car take of from rest and cover a distance of 80m on a straight road in 10s. calculate the magnitude of its acceleration", "images": [], "options": {"A": "1.25ms-2", "B": "1.60ms-2", "C": "4.00ms-2", "D": "8.00ms-2"}, "answer": "B", "explanation": "U = 0 (starting from rest)  Using newton's third law of motion  s=ut+12at2  80=0×t+12a102  80=12a102  160 = 100a  a = 1.6m/s2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>10", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : MOTION UNDER GRAVITY", "question": "An object is released from rest at a height of 25m. calculate the time it takes to fall to the ground [g = 10ms-2]", "images": [], "options": {"A": "25.00s", "B": "10.00s", "C": "2.50s", "D": "2.24s"}, "answer": "D", "explanation": "u = o (starting from rest)  s=ut+12at2  s=12at2(sinceu=0)  25=12x10xt2  t2=255  t2 = 5  t = 2.24s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>11", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "An object is acted upon by a system of parallel forces causing the object to be in elastic equilibrium. which of the following statement is not correct ?", "images": [], "options": {"A": "The resultant of the reactant of the parallel forces is zero.", "B": "The algebraic sum of all the moments of the force zero", "C": "All the parallel forces must be equal in magnitude and direction", "D": "sum of the forces in one direction must equal to the sum of the forces in the opposite direction"}, "answer": "C", "explanation": "For a body to be in static equilibrium when being acted by different forces, the forces must be equal in magnitude and direction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>12", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "An object ,A, is held in equilibrium as illustrated in the diagram, determine the magnitude ,W, of the weight of A", "images": ["Physics/imgs/2002/v45.png"], "options": {"A": "23N", "B": "17N", "C": "7N", "D": "5N"}, "answer": "B", "explanation": "If the object is in equilibrium,  W = resultant of T1 and T2  W2 = T12 + T22  ⇒ 82 + 152  W2 = 64 + 255  W2 = 289  squaring both sides  W = 17N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>13", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "A spiral spring of natural length 30.cm and forces constant of 20Nm-1 is compressed to 20.0cm. calculate the energy stored in the spring", "images": [], "options": {"A": "0.1 J", "B": "1.0J", "C": "10.0J", "D": "100.J"}, "answer": "A", "explanation": "Energystored(E)=12KC2  C = 30 - 20 = 10cm = 0.1m  E=12x20x(0.1)2 = 0.1J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>14", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "In the diagram above, AB represents a uniform rod of length 1.50m which is in equilibrium on a pivot at P, If AP = 40cm, calculate the mass of the rod. [g = 10ms-2]", "images": ["Physics/imgs/2002/APMEBT.png"], "options": {"A": "0.280kg", "B": "0.400kg", "C": "0.613kg", "D": "0.800kg"}, "answer": "D", "explanation": "applying law of moments    Therefore,  7N x 40cm = 35cm x W  W=7N x 40cm35cm=0.8kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>15", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "Which of the following statement correctly defines quantitatively, the work done by a force ?The product of the force and the distance moved", "images": [], "options": {"A": "parallel to the line of action of the force and the reference point", "B": "perpendicular to the line of action of the force from the reference point", "C": "on the line through the reference point", "D": "by the object"}, "answer": "A", "explanation": "The work done by a force is defined as the product of the force and the distance moved parallel to the line of action of the force and the reference point .", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>16", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A load of mass120kg is raised vertically through a height of 2m in 30s by a machine whose efficiency is 100%. calculate the power generated by the machine [g = 10ms-2]", "images": [], "options": {"A": "60W", "B": "80W", "C": "100W", "D": "120W"}, "answer": "B", "explanation": "Power=work donetime taken  since efficiency is 100%  Therefore,P=mght  P=120 × 10×230=80w", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>17", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "MACHINES :", "question": "A block and tackle system has 6 pulley . if the efficiency of the machine is 60%. determine the mechanical advantage", "images": [], "options": {"A": "12.0", "B": "10.0", "C": "3.6", "D": "1.8"}, "answer": "C", "explanation": "V.R = 6, Efficiency (E) = 60%  E=M.AV.R  M.A = E x V.R  M.A = 6.6 x 6  M.A = 3.6", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>18", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following actions will improve the efficiency of a pulley system?", "images": [], "options": {"A": "Reducing the mass the pulley", "B": "increasing the frictional force between the string of the pulley", "C": "increasing the mass per unit length of the string of the pulley", "D": "increasing the mass of pulley"}, "answer": "A", "explanation": "The efficiency of a pulley system can be improved by reducing the mass of the pulley. This is because a lighter pulley requires less force to move, which reduces the amount of energy lost to overcoming inertia and friction. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>19", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The ice and steam point of a certain thermometer are -20∘ and 100∘ respectively. calculate the celsius temperature corresponding to 70∘ on the thermometers", "images": [], "options": {"A": "84.0∘C", "B": "75∘C", "C": "64.0∘C", "D": "58.0∘C"}, "answer": "B", "explanation": "Tc100=70 - (-20)120  Tc=90 × 100120=75°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>20", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The silver coating on the inside of a vacuum flask reduces heat loss by", "images": [], "options": {"A": "conduction", "B": "radiation", "C": "condensation", "D": "convection"}, "answer": "B", "explanation": "The silver coating on the inside of a vacuum flask reduces heat loss by radiation. This is because silver is a good reflector of infrared radiation, which is the primary form of heat transfer in a vacuum. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>21", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "Water of mass120g at 50∘C is added to 200g of water at 10∘C and mixture is well stirred. calculate the temperature of the mixture [Neglect heat losses to the surrounding]", "images": [], "options": {"A": "60∘C", "B": "40∘C", "C": "25∘C", "D": "10∘C"}, "answer": "C", "explanation": "Using,  MCθ = M1Cθ1 + M2Cθ2  where M = M1 + M2  θ = common temperature   Therefore,  (120 + 200)C × θ = 120 × C × 50 + 200 × C × 10  320Cθ = 6000C + 2000C  θ=8000C320C=25°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>22", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "Calculate the energy required to vaporise 50g of water initially at 80∘C. [specific heat capacity of water = 4.2Jg-1K-1] at 80]    [Specific latent heat of vaporization of steam, L = 2260 J/g]", "images": [], "options": {"A": "113,000J", "B": "117,200J", "C": "234,400J", "D": "420,000J"}, "answer": "B", "explanation": "E = mCθ + mL  where,  θ = temperature required to get to steam point   θ = θs - θ0 = 100°C - 80°C = 20°C  E = mcθ + ml  E = 50 x 4.2 x 20 + 50 x 2260  E = 4200 + 113000  E = 117,200J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>23", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES", "question": "What type of motion does the skin of a Talking drum perform when it is struck with a drum stick?", "images": [], "options": {"A": "Random", "B": "rational", "C": "translational", "D": "vibratory"}, "answer": "D", "explanation": "When a drum skin is struck with a drum stick, it vibrates. These vibrations create sound waves that we hear as the drum sound. Therefore, the motion of the drum skin is vibratory.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>24", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "A slinky spring fixed at one end is placed horizontally on a table. The free end is displaced parallel to the table and then released. the resulting waveform is", "images": [], "options": {"A": "transverse", "B": "longitudinal", "C": "stationary", "D": "electromagnetic"}, "answer": "B", "explanation": "Longitudinal waves are waves in which the displacement of the medium is in the same direction as, or the opposite direction to, the direction of propagation of the wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>25", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A radio wave has a wavelength is 150m. if the velocity of radio wave in free wave is 3 × 10⁸m/s)", "images": [], "options": {"A": "4.5 ×1010Hz", "B": "50×109Hz", "C": "4.5×109Hz", "D": "2.0×106Hz"}, "answer": "D", "explanation": "V = F⋋  F=V⋋=3 x 108150=2.0x106Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>26", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "In the wave equation y = E0 sin(200t - ⊼x), E0 represent the", "images": [], "options": {"A": "amplitude", "B": "frequency", "C": "period", "D": "wavelenght"}, "answer": "A", "explanation": "In the wave equation y = E0 sin(200t - ⊼x), E0 represents the amplitude of the wave. The amplitude of a wave is the maximum displacement of the wave from its equilibrium position. It is the distance from the crest or the trough of the wave to the equilibrium position. In this equation, E0 is the maximum displacement of the wave, hence it represents the amplitude.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>27", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "The size of the hole of a pin hole camera is increased. The resultant image formed becomes", "images": [], "options": {"A": "sharper", "B": "reduced in size", "C": "enlarged", "D": "blurred"}, "answer": "D", "explanation": "The size of the hole in a pinhole camera is inversely proportional to the sharpness of the image formed. This means that as the size of the hole increases, the sharpness of the image decreases and the image becomes blurred. This is because a larger hole allows more light rays to enter at different angles, which results in a less focused image.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>28", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The refractive index of a medium relative to air is 1.8. calculate, to the nearest degree, the critical angle for the medium", "images": [], "options": {"A": "68∘", "B": "56∘", "C": "34∘", "D": "18∘"}, "answer": "C", "explanation": "n = 1.8  Critical angle i = 90°  sin isin c=1.8  sin90sin c=1sin c  1sin c=1.8  sinc=18  sin-1(0.5556) = 34°", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>29", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens of focal length 15m  form a virtual image at a point 10cm from a lens. calculate the distance of the object from the lens", "images": [], "options": {"A": "10.00cm", "B": "6.00cm", "C": "50cm", "D": "1.50cm"}, "answer": "B", "explanation": "1F=1U-1V(virtualisnegative)  115=1U-110  1U=115+110=530  1U=115+110=530  1U=530  U=305=6cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>30", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "In a compound microscope, the image formed by the objective lens is at distance of 3.0cm from the eye lens. if the final image is at 25.0cm from the eye lens, calculate the focal length of the eyes lens", "images": [], "options": {"A": "0.3cm", "B": "2.7cm", "C": "3.4cm", "D": "8.3cm"}, "answer": "C", "explanation": "1U+1V=1F  13+1-25=1F  1F=25 - 375=2275  F=7522=3.4", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>31", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A pulse of a sound is transmitted from a ship and the reflection from he sea bed is recorded after 0.2s. calculate the depth of the sea.[take speed of sound in sea water  = 1560ms-1]", "images": [], "options": {"A": "312.0m", "B": "156.0m", "C": "78.0m", "D": "31.2m"}, "answer": "B", "explanation": "The formula to calculate the depth of the sea is d = vt/2. Substituting the given values into the formula, we get the depth of the sea as 156.0m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>32", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "SOUND WAVES : RESONANCE", "question": "When two notes of nearly equal frequency are sounded together, a periodic rise and fall in sound intensity can be heard. this phenomenon is called", "images": [], "options": {"A": "beats", "B": "diffraction", "C": "overtones", "D": "resonance"}, "answer": "A", "explanation": "In acoustics, a beat is an interference pattern two sounds of slightly frequencies, perceived as a periodic variation in volume.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>33", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "Which of the following instrument is not a wind instrument", "images": [], "options": {"A": "larinet", "B": "saxophone", "C": "trumpet", "D": "xylophone"}, "answer": "D", "explanation": "The xylophone is not a wind instrument. It is a percussion instrument that is played by striking wooden bars with mallets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>34", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "Which of the following actions will not cause an increase in the vibrating string?", "images": [], "options": {"A": "increasing the tension in the string", "B": "Decreasing the mass per unit length of the string", "C": "Decreasing the lenght of the tring", "D": "increasing the cross sectional area of the string"}, "answer": "D", "explanation": "The thicker the string the lower the frequency and pitch  F=12L&radic;&nbsp;TPA  where, A = area", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>35", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "Which of the following items can be used to compare the relative magnitude of electric charges on two bodies?", "images": [], "options": {"A": "ebonite rod", "B": "gold leaf electroscope", "C": "proff planes", "D": "the electrophorus"}, "answer": "B", "explanation": "A gold leaf electroscope can be used to compare the relative magnitude of electric charges on two bodies. It works by indicating the presence and magnitude of a charge through the application of electrostatic induction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>36", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Three capacitor each of capacitance is 18µF are connected in series, calculate the effective capacitance of the capacitors", "images": [], "options": {"A": "54.00µF", "B": "18.00µF", "C": "6.00µF", "D": "0.17µF"}, "answer": "C", "explanation": "Effective capacitance (series connection)  1C=1C1+1C2+1C3  1C=118+118+118  1C=318  C=183=6.00µF", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>37", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "Two spheres of masses 100kg and 90 kg respectively have their centers separated by a distance of 1.0 m, calculate the magnitude of the forces of attraction between them[G = 6.70 ×10-11Nm2kg2]", "images": [], "options": {"A": "6.70 ×10-11N", "B": "6.70 ×10-10N", "C": "6.03 ×10-10N", "D": "6.03 ×10-7N"}, "answer": "D", "explanation": "F=GM1M2r2  =6.70 x 10-11 x 100 x 90(1.0)2=6.7 x 10-11 x 90001 = 60300 x 10-11 = 6.03 x 106 x 10-11  ⇒ 6.03 x 10-7N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>38", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "The magnitude of the gravitational attraction between the earth and a particles is 40N. if the mass of the particle is 4kg, calculate the magnitude of the gravitational field intensity of the earth on the particles", "images": [], "options": {"A": "10.0Nkg-1", "B": "12.6Nkg-1", "C": "25.0Nkg-1", "D": "160.0Nkg-1"}, "answer": "A", "explanation": "The gravitational field intensity of the earth on the particle is given by  FGm=40N4Kg=10NKg-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>39", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Local action is normally prevented in a simple electric cell by", "images": [], "options": {"A": "introducing an oxidising agent in the acid", "B": "not drawing current continuously for long period", "C": "amalgamating the surface of the zinc plate", "D": "using a porous pot to isolate the zinc from the acid"}, "answer": "C", "explanation": "Local action in a simple electric cell is prevented by amalgamating the surface of the zinc plate. Local action refers to the self-discharge of a cell when small areas of the zinc plate, due to impurities, act as local cells with the rest of the plate. This results in wastage of zinc even when no current is being drawn from the cell. Amalgamation is the process of coating the zinc plate with a layer of mercury. This provides a uniform surface and prevents local action.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>40", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT", "question": "The lead-acid accumulator consist of", "images": [], "options": {"A": "lead as the positive electrode", "B": "lead oxide as the negative electrode", "C": "Hydrochloric acid as the electrolyte", "D": "tetraoxosulphate(VI) acid as the electrolyte"}, "answer": "D", "explanation": "A lead-acid accumulator consists of sulphuric acid or tetraoxosulphate (vi) acid as the electrolyte.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>41", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "Which of the following action will not lead to an increase in their induced e.m.f in a coil of wire rotating between the poles of a magnet ? increasing the", "images": [], "options": {"A": "strength of the magnet", "B": "number of turns in the coil", "C": "speed of rotation of the coil", "D": "Gap between the poles of the magnet"}, "answer": "D", "explanation": "The induced electromotive force (e.m.f) in a coil of wire rotating between the poles of a magnet is determined by the strength of the magnet, the number of turns in the coil, and the speed of rotation of the coil. Increasing the gap between the poles of the magnet will not increase the induced e.m.f. In fact, it will decrease the magnetic field strength and thus reduce the induced e.m.f.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>42", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "A transformer has 400 turns and 200 turns in the primary and secondary winding respectively. if the the current in the primary and secondary winding are 3A and 5A respectively, calculate the efficiency of the transformer", "images": [], "options": {"A": "85.0%", "B": "83.3%", "C": "37.5%", "D": "30.0%"}, "answer": "B", "explanation": "Es α Ns  Es = KNs  Ep α Np  Ep = KNp  IE = power  Power in secondary (Ps) = IsEs = KIsNs  Power in the primary (Pp) = IpEp = KIpNp  Efficiency=PsPp×100%=kIsNsKIpNp×100%  =IsNsIpNp×100%  Efficiency=200400×53×100=83.3%", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>43", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "MAGNETIC FIELD : THE EARTH’S MAGNETIC FIELD", "question": "A freely-suspended magnet swinging in a horizontal plane comes to rest with its axis pointing approximately.", "images": [], "options": {"A": "north-south", "B": "south-west", "C": "north-east", "D": "south-east"}, "answer": "A", "explanation": "Since the magnet is swinging horizontally,", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2002>44", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "Calculate the inductance,L, of the coil in the circuit diagram shown above", "images": ["Physics/imgs/2002/GA9LGJ.png"], "options": {"A": "3.8H", "B": "0.6H", "C": "0.4H", "D": "0.2H"}, "answer": "B", "explanation": "XL (Reactance) = V/I = 240/2 = 120Ω  XL = 2πFL  making L the subject  L=XL2πF=1202π × 100/π  =120200=0.6  L = 0.6H", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>45", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "In a model of the hydrogen atom, the energy level Wn are given by the formula Wn = -R/N2. Where n is an integer and R is a constant, Determine the energy  released in the transition form n = 3 to n =2", "images": [], "options": {"A": "R/5", "B": "-R/4", "C": "5R/36", "D": "-5R/36"}, "answer": "C", "explanation": "Wn=-Rn2  when energy levels are n = 3 and n = 2  Energy released is given by  Wn3-n2=-R(132+122)=-R(19-14)  =-R(4-936)=-R(-536)=5R36", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2002>46", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "If a radioactive atom emits a beta particle, its mass number", "images": [], "options": {"A": "increase by one", "B": "remains the same", "C": "decreases by one", "D": "increase by two"}, "answer": "B", "explanation": "When a radioactive atom emits a beta particle, a neutron in the nucleus is converted into a proton and an electron (the beta particle). This increases the atomic number by one, but the mass number (the total number of protons and neutrons) remains the same, as a neutron has been converted into a proton. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>47", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "When light fall on a metallic surface, the number of electrons that can be emitted would depend solely on the", "images": [], "options": {"A": "area of the metallic surface", "B": "frequency of the light", "C": "intensity of the light", "D": "time of exposure of etallic to light"}, "answer": "B", "explanation": "The number of electrons that can be emitted when light falls on a metallic surface depends on the frequency of the light. This is based on the photoelectric effect, which states that electrons are emitted from the surface of a metal when light of a certain frequency (or higher) shines on it. The frequency of the light determines the energy of the photons, and if this energy is high enough, it can overcome the work function of the metal and cause electrons to be emitted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>48", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following material is used to control the rate of neutron production in a nuclear reactor?", "images": [], "options": {"A": "boron rods", "B": "concrete shield", "C": "graphite rods", "D": "uranium rods"}, "answer": "A", "explanation": "Boron rods are used to control the rate of neutron production in a nuclear reactor. Boron has a high cross-section for absorption of neutrons, which means it is very effective at capturing and thus reducing the number of free neutrons in the reactor. This helps to control the rate of the nuclear chain reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>49", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following is usually used to cause fission in an atomic reactor?", "images": [], "options": {"A": "alpha particles", "B": "beta particles", "C": "electrons neutrons", "D": "neutrons"}, "answer": "D", "explanation": "Neutrons are usually used to cause fission in an atomic reactor. Fission is the process by which the nucleus of an atom splits into two or more smaller nuclei, along with the release of a large amount of energy. This process is initiated by the absorption of a neutron by the nucleus of the atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2002>50", "subject": "Physics", "year": "2002", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "A nuclide X is produced by bombarding a nitrogen (N) nucleus with an alpha (α) particles wit release of heavy hydrogen (D) nucleus as shown by following nuclear equation. α + 147→pqX + 21D. Determine the values of p and q in the equation.", "images": [], "options": {"A": "12 and 6", "B": "14 and 7", "C": "16 and 8", "D": "19 and 8"}, "answer": "C", "explanation": "α + 148N → pqX + 21D  42He + 147N → pqX + 21D  Hence,  4 + 14 = p + 2  p = 18 - 2 = 16  then,  2 + 7 = q + 1  9 = q + 1  q = 9 - 1 = 8    P = 16 and q = 8", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>1", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "A tuber of cassava can be processed into powder. This explains the fact that", "images": [], "options": {"A": "matter can change spontaneously from one state to another", "B": "matter cannot be destroyed", "C": "force is required to change matter from one state to another", "D": "matter is made up of tiny particles"}, "answer": "D", "explanation": "The process of grinding the cassava into powder involves breaking down the larger particles of the cassava into smaller particles, which demonstrates that matter is made up of tiny particles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>2", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A piece of metal of relative density 5.0 weighs 60N in air. Calculate its weight when fully immersed in water.", "images": [], "options": {"A": "4N", "B": "5N", "C": "48N", "D": "60N"}, "answer": "C", "explanation": "R.D = 5  W1 = Weight in air = 60N  W2 = Weight in water = ?  R.D=W1W1 - W2=51  =6060 - W2=51  1 × 60 = 5(60 - W2)  60 = 300 - 5W2  W2=2405=48N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>3", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A net force of 15 N acts upon a body of mass 3kg for 5s. Calculate the change in the speed of the body.", "images": [], "options": {"A": "25.0ms-1", "B": "9.0ms-1", "C": "2.5ms-1", "D": "1.0ms-1"}, "answer": "A", "explanation": "Ft = M(v - u)  Ft = Mdv (where v - u = dv)  dv=FtM  dv=15 × 53  ⇒ 25.0ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>4", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "The tendency of a body to remain at rest when a force is applied to it is called", "images": [], "options": {"A": "impulse", "B": "momentum", "C": "inertia", "D": "friction"}, "answer": "C", "explanation": "The tendency of a body to remain at rest when a force is applied to it is called inertia. Inertia is a property of matter by which it continues in its existing state of rest or uniform motion in a straight line, unless that state is changed by an external force.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>5", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A force acts on a body for 0.5s changing its momentum from 16.0kgms-1 to 21.0kgms-1. Calculate the magnitude of the force.", "images": [], "options": {"A": "42.0N", "B": "37.0N", "C": "32.0N", "D": "10.0N"}, "answer": "D", "explanation": "The force can be calculated using the formula for impulse, which is the change in momentum. The formula is F = Δp/Δt, where F is the force, Δp is the change in momentum and Δt is the change in time. Substituting the given values gives F = (21.0kgms-1 - 16.0kgms-1) / 0.5s = 10N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>6", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : UNIFORM/NON-UNIFORM ACCELERATION", "question": "Which of the graphs below shows the motion of a body with uniform retardation?", "images": ["Physics/imgs/2003/img1a.png", "Physics/imgs/2003/img1b.png", "Physics/imgs/2003/img1c.png", "Physics/imgs/2003/img1d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "The velocity keeps reducing with time in retardation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>7", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A moving object is said to have uniform acceleration if its", "images": [], "options": {"A": "displacement decreases at a constant rate", "B": "speed is directly proportional to time", "C": "velocity increases by equal amount in equal time intervals", "D": "velocity varies inversely with time"}, "answer": "C", "explanation": "Uniform acceleration is defined as the rate at which an object changes its velocity. This means that the velocity of the object increases or decreases by an equal amount in equal intervals of time. Therefore, the correct answer is 'velocity increases by equal amount in equal time intervals'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>8", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The period of an oscillatory motion is defined as the", "images": [], "options": {"A": "average of the times used in completing different numbers of oscillations", "B": "time to complete a number of oscillations", "C": "time to complete one oscillation", "D": "time taken to move from one extreme position to the other"}, "answer": "C", "explanation": "The period of an oscillatory motion is the time taken for one complete cycle of vibration to pass a given point. As such, the period of an oscillation is defined as the time to complete one oscillation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>9", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONSERVATION OF MECHANICAL ENERGY", "question": "The mass on a loaded spiral spring oscillates vertically between two extreme positions P and R equidistant from the equilibrium position Q. Which of the following statements about the system is not correct?", "images": [], "options": {"A": "The momentum of the mass is maximum at Q", "B": "The elastic potential energy of the spring is maximum at Q", "C": "The kinetic energy of the mass is maximum at P", "D": "The total energy of the system is always constant"}, "answer": "B", "explanation": "In a simple harmonic motion like a mass on a spring, the elastic potential energy is maximum at the extreme positions (P and R), not at the equilibrium position (Q). Therefore, the statement 'The elastic potential energy of the spring is maximum at Q' is not correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>10", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A ball of mass 5.0kg hits a smooth vertical wall normally with a speed of 2 ms-1. Determine the magnitude of the resulting impulse.", "images": [], "options": {"A": "20.0 kgms-1", "B": "10.0 kgms-1", "C": "5.0 kgms-1", "D": "2.5 kgms-1"}, "answer": "B", "explanation": "m = 5kg, v = 2ms-1  Ft = M(V2 - V1) = MV  ⇒ 5 × 2 = 10kgms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>11", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following statements correctly defines a simple machine? A device", "images": [], "options": {"A": "that can provide electric current", "B": "which can only carry people from one place to another", "C": "with which work can be done easily", "D": "which changes the state of rest or of uniform motion of an object along a straight line"}, "answer": "C", "explanation": "A simple machine is a mechanical device that changes the direction or magnitude of a force. In general, they can be defined as the simplest mechanisms that use mechanical advantage (also called leverage) to multiply force. A simple machine uses a single applied force to do work against a single load force. It makes work easier, hence option 3 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>12", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A platinum resistance thermometer has a resistance of 4Ω at 0°C and 10Ω at 100°C. Assuming the resistance changes uniformly with temperature, calculate the resistance of the thermometer when the temperature is 45°C.", "images": [], "options": {"A": "14.0Ω", "B": "6.7Ω", "C": "3.2Ω", "D": "2.7Ω"}, "answer": "B", "explanation": "θ°=Rθ - R0R100 - R0×100  =Rθ - 410 - 4×100  45=Rθ - 46×100  270 = 100Rθ - 400  270 + 400 = 100Rθ  Rθ=670100   ⇒ 6.7Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>13", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A metal rod of length 100cm is heated through 100°C, calculate the change in length of the rod. [linear expansivity of the material of the rod is 3 × 10-5K-1]", "images": [], "options": {"A": "4mm", "B": "3mm", "C": "2mm", "D": "1mm"}, "answer": "B", "explanation": "α=ΔLLo(Δθ)  substituting  3×10-5=ΔL100 × 100cm  ΔL = 3 × 10-5 × 100 × 100  ⇒ 0.3cm = 3mm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>14", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "The heat capacity of a calorimeter is the amount of energy required to", "images": [], "options": {"A": "change the temperature of 1kg of the calorimeter by 1k", "B": "change 1kg mass of the calorimeter to liquid at the same temperature", "C": "change the temperature of the calorimeter by 1K", "D": "melt the calorimeter into liquid at a constant temperature"}, "answer": "C", "explanation": "The heat capacity of an object is defined as the amount of heat energy required to raise the temperature of the object by one degree Kelvin (or Celsius, as the size of the degree is the same in both scales). Therefore, the heat capacity of a calorimeter is the amount of energy required to change the temperature of the calorimeter by 1K, which corresponds to option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>15", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "Which of the following statements about latent heat of vaporisation is correct. It", "images": [], "options": {"A": "weakens the adhesive forces between molecules of a liquid and those of its container", "B": "breaks completely the force of attraction between the molecules of a liquid", "C": "adds to the heat content of a liquid", "D": "increases the cohesive forces between liquid molecules"}, "answer": "B", "explanation": "breaks completely the force of attraction between the molecules of a liquid", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>16", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "When the pressure of a fixed mass of gas is doubled at constant temperature, the volume of the gas is", "images": [], "options": {"A": "increased four times", "B": "doubled", "C": "unchanged", "D": "halved"}, "answer": "D", "explanation": "According to Boyle's law, the pressure of a gas is inversely proportional to its volume at constant temperature. This means that if the pressure is doubled, the volume is halved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>17", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The volume of a given mass of an ideal gas at 327K and 9.52 × 104Pa is 40cm3. Calculate the volume of the gas at 273K and 1.034 × 105 Pa.", "images": [], "options": {"A": "68.23 cm3", "B": "47.91 cm3", "C": "44.60 cm3", "D": "30.75 cm3"}, "answer": "D", "explanation": "T1 = 373K; P1 = 9.52 × 104Pa  V1 = 40cm3  T2 = 273K, P2 = 1.034 × 105Pa, V2 = ?  P1V1T1=P2V2T2  V2=P1V1T2T1P2=9.52 × 104 × 40 × 2733.27 × 1.034 × 105  V2 = 30.75cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>18", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The diagram above represents the displacement D versus time, t, graph of a progressive wave. Deduce the frequency of the wave.", "images": ["Physics/imgs/2003/img2.png"], "options": {"A": "20 Hz", "B": "10 Hz", "C": "5 Hz", "D": "4 Hz"}, "answer": "B", "explanation": "t = 0.10second from graph  F=1T=10.10=10Hz", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>19", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A wave of wavelength 0.30m travels 900m in 3.0s, calculate its frequency.", "images": [], "options": {"A": "68.0 Hz", "B": "225.0 Hz", "C": "270.0 Hz", "D": "1000.0 Hz"}, "answer": "D", "explanation": "Velocity=DT=9003=300m/s  Velocity = Fλ   Therefore, 300m/s = 0.3mk  F=3000.3=1000Hz", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>20", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Which of the following conditions is necessary for the occurrence of total internal reflection of light?", "images": [], "options": {"A": "Light must travel from an optically less dense to a denser medium", "B": "The angle of incidence must be equal to the critical angle", "C": "The angle of incidence must be greater than the critical angle", "D": "The angle of refraction must be 90°"}, "answer": "C", "explanation": "Total internal reflection occurs when light travels from a denser medium to a less dense medium and the angle of incidence is greater than the critical angle. The critical angle is the angle of incidence that provides an angle of refraction of 90 degrees. If the angle of incidence is greater than this, no refraction occurs and all the light is reflected back into the denser medium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>21", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The image which cannot be formed on a screen is said to be", "images": [], "options": {"A": "inverted", "B": "erect", "C": "real", "D": "virtual"}, "answer": "D", "explanation": "A real image is formed when light rays converge at a point and can be projected on a screen. A virtual image, on the other hand, is formed when light rays diverge and appear to be coming from a point but cannot be projected on a screen. Therefore, the image which cannot be formed on a screen is said to be virtual.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>22", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "An object is placed in the principal axis and at the centre of curvature of a concave mirror, the image of the object formed by the mirror is", "images": [], "options": {"A": "real and magnified", "B": "real and inverted", "C": "erect and magnified", "D": "erect and virtual"}, "answer": "B", "explanation": "When an object is placed at the centre of curvature of a concave mirror, the image formed is real, inverted and of the same size as the object. This is because the rays of light parallel to the principal axis and those passing through the centre of curvature are reflected back along the same path and intersect at the centre of curvature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>23", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A converging lens produces an image four times as large as an object placed 25cm from the lens. Calculate its focal length.", "images": [], "options": {"A": "100cm", "B": "33cm", "C": "29cm", "D": "20cm"}, "answer": "D", "explanation": "M = 4  M=VU  4=V25  V = 100cm  1F=1U+1V=125+1100  4+1100=5100=120  F = 20cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>24", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The horizontal floor of a water reservoir appears to be 1.0m deep when viewed vertically from above. If the refractive index of water is 1.35, calculate the real depth of the reservoir.", "images": [], "options": {"A": "2.35m", "B": "1.35m", "C": "1.00m", "D": "0.35m"}, "answer": "B", "explanation": "n=real depthapparent depth  Apparent depth = 1.0m, n = 1.35, real depth = ?  1.35=real depth1  real depth = 1 × 1.35 = 1.35m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>25", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens has a focal length of 5cm. Determine its power.", "images": [], "options": {"A": "+20.0D", "B": "+0.2D", "C": "-20.0D", "D": "-0.2D"}, "answer": "A", "explanation": "The power of a lens is the reciprocal of its focal length in meters. In this case, the focal length is 5cm, or 0.05m. Therefore, the power is 1/0.05 = 20D. The power of a converging lens is positive, so the correct answer is +20.0D, which corresponds to option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>26", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Which of the following pairs of light rays shows the widest separation in the spectrum of white light?", "images": [], "options": {"A": "Green and blue", "B": "Orange and indigo", "C": "Blue and violet", "D": "Red and yellow"}, "answer": "B", "explanation": "It is observed that there is a wide distance between orange and indigo", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>27", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following statements about the human eye and the camera is correct?", "images": [], "options": {"A": "Both form virtual images of objects", "B": "The image formed by the eye is upright in the retina while that formed by the camera is inverted on the film", "C": "The inside of both of them is blackened to absorb unwanted light", "D": "The focal length of both the eye lens and the camera lens can be varied"}, "answer": "C", "explanation": "The interior of both the  human and camera is black and light proof so as to prevent the reflction of stray rays of light", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>28", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The speed of sound in air is directly proportional to", "images": [], "options": {"A": "its temperature on the celsius scale", "B": "its temperature on the thermodynamic scale", "C": "the cube root of its temperature on the celsius scale", "D": "the square root of its temperature on the absolute scale"}, "answer": "D", "explanation": "Speed of sound waves directly with square root of temperature in kelvin.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>29", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "Which of the following statements about the characteristics of sound waves is correct?", "images": [], "options": {"A": "Loudness decreases with increase in intensity", "B": "The pitch of a note is determined by its amplitude", "C": "The intensity of a sound wave is proportional to its amplitude", "D": "The quality of a note depends on its overtones"}, "answer": "D", "explanation": "The quality of a note depends on its overtones. Overtones are the frequencies higher than the fundamental frequency that are present in a sound. They give a sound its unique quality, or timbre, which allows us to distinguish between different musical instruments or voices. The other options are incorrect. Loudness is directly proportional to the intensity of a sound, not inversely. The pitch of a note is determined by its frequency, not its amplitude. The intensity of a sound wave is proportional to the square of its amplitude, not directly to its amplitude.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>30", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A sonometer wire of linear density 0.08 kg m-1 subjected to a tension of 800N is plucked. Calculate the speed of a pulse which moves from one end of the wire to the other.", "images": [], "options": {"A": "179.0 ms-1", "B": "100.0 ms-1", "C": "15.8 ms-1", "D": "8.0 ms-1"}, "answer": "B", "explanation": "The speed of a pulse in a sonometer wire can be calculated using the formula v = &radic;T/μ&nbsp;, where T is the tension in the wire and μ is the linear density of the wire. Substituting the given values, we get v = &radic;800/0.08&nbsp; = 100 ms-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>31", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "Which of the following instruments gives a pure note when sounded?", "images": [], "options": {"A": "Talking drum", "B": "Siren", "C": "Tuning fork", "D": "Guitar"}, "answer": "C", "explanation": "A tuning fork produces a pure note when sounded. This is because it vibrates at a single frequency, producing a sound wave with a single frequency. This results in a pure tone.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>32", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC LINES OF FORCE", "question": "Which of the following features of an electrostatic line of force is not correct?", "images": [], "options": {"A": "It is an imaginary line which a positive charge would describe if it is free to move", "B": "The tangent drawn at any point on a curved line of force shows the direction of the electric field intensity at that point", "C": "It is sometimes curved", "D": "It can cross another line of force in a region of intense electric field"}, "answer": "D", "explanation": "Electrostatic lines of force cannot cross each other. This is because the direction of the electric field is given by the tangent to the line of force at that point. If two lines of force cross each other, there would be two tangents at the point of intersection, which would mean that the electric field has two directions at that point. This is not possible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>33", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "DESCRIPTION PROPERTY OF FIELDS : CONCEPT OF FIELDS", "question": "Which of the following statements about a force field is correct?", "images": [], "options": {"A": "Electrostatic, gravitational and magnetic forces are always attractive.", "B": "Electric, gravitational and magnetic fields obey inverse square laws", "C": "Field lines are real but their corresponding fields are imaginary", "D": "Field lines and their corresponding fields are both real"}, "answer": "B", "explanation": "The correct statement is that electric, gravitational and magnetic fields obey inverse square laws. This is because the strength of these fields decreases with the square of the distance from the source. This is known as the inverse square law. The other options are incorrect. Electrostatic, gravitational and magnetic forces are not always attractive. For example, like charges repel each other in an electrostatic field. Field lines are not real, they are a visual representation used to describe the direction and strength of a field. The field itself is a region where a force would be felt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>34", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A positively charged glass rod is placed near the cap of a positively charged electroscope. The divergence of the leaf is observed to", "images": [], "options": {"A": "decrease", "B": "increase", "C": "remain the same", "D": "increase and collapse immediately"}, "answer": "B", "explanation": "The repulsion force from like charges increases divergence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>35", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Two identical cells each of emf 2V and internal resistance 1.0Ω are connected in parallel. The combination is connected to an external load of 1.5Ω. Calculate the current in the circuit.", "images": [], "options": {"A": "0.57A", "B": "1.00A", "C": "1.14A", "D": "2.00A"}, "answer": "B", "explanation": "Connectedinparallel,effectiveresistance=1r+r=11+1=12  effective emf = 2v  external resistance = 1.5  I=VR=20.5+1.5=22=1A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>36", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "Which of the following factors does not affect the electric resistance of a wire?", "images": [], "options": {"A": "Length", "B": "Mass", "C": "Temperature", "D": "Cross sectional area"}, "answer": "B", "explanation": "The electric resistance of a wire is affected by its length, temperature, and cross-sectional area, but not its mass. The resistance of a wire increases with its length and temperature and decreases with its cross-sectional area. This is because resistance is a measure of how much a material opposes the flow of electric current, and these factors affect how easily current can flow. However, the mass of the wire does not directly affect its resistance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>37", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A current of 10A passes through a conductor for 10s, calculate the charge flowing through the conductor", "images": [], "options": {"A": "100.0C", "B": "10.0C", "C": "1.0C", "D": "0.1C"}, "answer": "A", "explanation": "The charge flowing through a conductor can be calculated using the formula Q = It, where Q is the charge, I is the current, and t is the time. In this case, I = 10A and t = 10s, so Q = 10A * 10s = 100C. Therefore, the charge flowing through the conductor is 100C.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>38", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A lamp is rated 240V 60W, calculate the resistance of its filament.", "images": [], "options": {"A": "240Ω", "B": "360Ω", "C": "960Ω", "D": "1440Ω"}, "answer": "C", "explanation": "The resistance of a lamp's filament can be calculated using Ohm's law, which states that the resistance (R) is equal to the voltage (V) divided by the current (I). The current can be calculated by dividing the power (P) by the voltage, so I = P/V = 60W/240V = 0.25A. Therefore, R = V/I = 240V/0.25A = 960Ω.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>39", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "The maximum power dissipated by a 100Ω resistor in a circuit is 4W, calculate the voltage across the resistor.", "images": [], "options": {"A": "10V", "B": "20V", "C": "25V", "D": "400V"}, "answer": "B", "explanation": "The power dissipated by a resistor is given by the formula P = V^2/R, where P is the power, V is the voltage, and R is the resistance. Rearranging the formula to find V gives V = &radic;P*R&nbsp;. Substituting the given values gives V = &radic;4W * 100Ω&nbsp; = 20V. Therefore, the correct answer is 20V.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>40", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "One difference between a reactance and a resistance in an alternating current circuit is", "images": [], "options": {"A": "resistance is larger than reactance", "B": "energy is not dissipated in a reactance", "C": "energy is stored in a resistance but not in a reactance", "D": "the current in a reactance is lower than in the resistance"}, "answer": "B", "explanation": "The main difference between reactance and resistance in an alternating current circuit is that energy is not dissipated in a reactance. In a resistance, the electrical energy is converted into heat and is dissipated, whereas in a reactance, the energy is stored in the electric or magnetic field and is returned to the circuit when the conditions change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>41", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The diagram above shows the resultant electric field pattern due to two electric point charges P and S. Which of the following statements is correct", "images": ["Physics/imgs/2003/JENJJR.png"], "options": {"A": "P is negatively charged while S is positively charged", "B": "P is positively charged while S is negatively charged", "C": "Both P and S are positively charged", "D": "Both P and S are negatively charged"}, "answer": "D", "explanation": "Both P and S are negatively charged since their arrows point inward.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>42", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "The bar magnet illustrated in the diagram above picks up an unmagnetised steel nail X. In turn, X picks up a similar nail Y and so on. The nails are said to be magnetised by", "images": ["Physics/imgs/2003/img4.png"], "options": {"A": "conduction", "B": "single touch", "C": "induction", "D": "divided touch"}, "answer": "C", "explanation": "The process by which the unmagnetized steel nails become magnetized when they come into contact with the bar magnet and each other is known as induction.    In this case, the bar magnet induces magnetism in the nearby unmagnetized steel nails without direct contact through a flow of electric current, which is characteristic of magnetic induction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>43", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "The direction of induced current in a straight wire placed in a magnetic field is determined by using", "images": [], "options": {"A": "Fleming's right hand rule", "B": "Maxwell's screw rule", "C": "Faraday's law", "D": "Lenz's law"}, "answer": "A", "explanation": "Fleming's right hand helps tell direction of induced current.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>44", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "Which of the following statements about an electromagnet is not correct?", "images": [], "options": {"A": "It is a temporary magnet", "B": "Its strength depends on the current", "C": "Its strength depends on the number of units in its coil", "D": "It has permanent poles"}, "answer": "D", "explanation": "An electromagnet is a type of magnet in which the magnetic field is produced by an electric current. The magnetic field disappears when the current is turned off. Therefore, it does not have permanent poles. The strength of the magnetic field produced by such a magnet can be changed by changing the amount of electric current that passes through it, which means its strength depends on the current. The number of turns in the coil also affects the strength of the electromagnet. Hence, the statement 'It has permanent poles' is not correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2003>45", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following statements is true of ultra violet radiations. It", "images": [], "options": {"A": "supports the sensation of hearing", "B": "does not cause the emission of electrons from metals", "C": "is an electromagnetic wave", "D": "is not capable of causing sun burn"}, "answer": "C", "explanation": "Ultraviolet (UV) radiation is a form of electromagnetic radiation that comes from the sun and man-made sources like tanning beds. UV radiation is a component of the electromagnetic spectrum with wavelengths shorter than visible light but longer than X-rays. It does not support the sensation of hearing, it can cause the emission of electrons from metals (photoelectric effect), and it is capable of causing sunburn. Hence, the statement 'It is an electromagnetic wave' is true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>46", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Which of the following statements is not true of the isotopes of an element? They", "images": [], "options": {"A": "are atoms of the same element", "B": "have the same chemical properties", "C": "have the same atomic number", "D": "have the same mass number"}, "answer": "D", "explanation": "Isotopes are variants of a particular chemical element which differ in neutron number, and consequently in nucleon number. All isotopes of a given element have the same number of protons but different numbers of neutrons in each atom. They are atoms of the same element, have the same chemical properties, and have the same atomic number. However, they do not have the same mass number because the mass number is the total number of protons and neutrons in an atom, and this can vary between isotopes. Hence, the statement 'They have the same mass number' is not true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>47", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive element has a decay constant of 0.077s-1, calculate its half life.", "images": [], "options": {"A": "12.5s", "B": "9.0s", "C": "5.1s", "D": "0.5s"}, "answer": "B", "explanation": "λ = 0.077s-1  WhereT=0.692λ  =0.6920.077=9.0s", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>48", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "The minimum energy required to remove an electron from an atom is known as", "images": [], "options": {"A": "excitation energy", "B": "ionization energy", "C": "binding energy", "D": "photon energy"}, "answer": "B", "explanation": "The minimum energy required to remove an electron from an atom is known as the ionization energy. Ionization energy is the energy required to remove an electron from a gaseous atom or ion. The term is often used to describe the first ionization energy, which is the energy required to remove the outermost, or highest energy, electron from a neutral atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2003>49", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Nuclear fission is preferred to nuclear fusion in the generation of energy because", "images": [], "options": {"A": "very high temperatures are required for fusion", "B": "the raw materials for fusion are not easily obtained", "C": "energy obtained from fusion is relatively smaller", "D": "the by product of fusion are very dangerous"}, "answer": "A", "explanation": "Nuclear fission is preferred to nuclear fusion in the generation of energy because very high temperatures are required for fusion. Nuclear fusion requires temperatures of millions of degrees to overcome the electrostatic repulsion between the positively charged nuclei. On the other hand, nuclear fission can occur at much lower temperatures, making it more feasible for energy generation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2003>50", "subject": "Physics", "year": "2003", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following reactions represents nuclear fusion?", "images": [], "options": {"A": "21H + 21H → 31He + 10n", "B": "23592u + 10n → 14556Ba + 9036Kr + 2 10n", "C": "23490Th → 0-1n + 23491Pa", "D": "23892U → 42He + 23490Th"}, "answer": "A", "explanation": "Nuclear fusion is a reaction in which two or more atomic nuclei are combined to form one or more different atomic nuclei and subatomic particles (neutrons or protons). The difference in mass between the reactants and products is manifested as the release of large amounts of energy. The option 1 represents this process, where two hydrogen nuclei (protons) are combined to form a helium nucleus and a neutron.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>1", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "The molecular structure of a liquid is such that", "images": [], "options": {"A": "The molecular have unlimited freedom of movement.", "B": "Molecular movement is restricted to vibration only.", "C": "Intermolecular collisions take place.", "D": "All molecules move with the same speed."}, "answer": "C", "explanation": "In a liquid, the molecules are close together and have a random arrangement. The molecules have more energy than in a solid and this allows them to move around and collide with each other, hence the option 'Intermolecular collisions take place' is correct. The other options are incorrect as molecules in a liquid do not have unlimited freedom of movement, their movement is not restricted to vibration only, and not all molecules move with the same speed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>2", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following concepts is not an evidence of the particle nature of matter?", "images": [], "options": {"A": "Diffusion", "B": "Brownian motion", "C": "Diffraction", "D": "Crystallization"}, "answer": "C", "explanation": "Diffraction is a wave property, not a particle property. It is the bending of waves around the corners of an obstacle or aperture into the region of geometrical shadow of the obstacle. In contrast, diffusion, Brownian motion, and crystallization are all evidence of the particle nature of matter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>3", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "Which of the following statements about the mass and the weight of a body is not correct? Its", "images": [], "options": {"A": "mass is a scalar quantity.", "B": "weight is a function of the gravitational pull on it.", "C": "mass on earth and on the moon is the same.", "D": "weight at the equator and at the poles is the same."}, "answer": "D", "explanation": "The weight of an object varies with location due to changes in gravitational pull. At the poles, the gravitational pull is slightly stronger than at the equator, hence an object will weigh slightly more at the poles than at the equator. Therefore, the statement 'weight at the equator and at the poles is the same' is not correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>4", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A diver is 5.2m below the surface of water of density 1000 kgm-3. If the atmospheric pressure is 1.02 × 105Pa, calculate the pressure on the diver.  [g = 10ms-2]", "images": [], "options": {"A": "6.20 × 104 Pa", "B": "1.02 × 105 Pa", "C": "1.54 × 105 Pa", "D": "5.20 × 105 Pa"}, "answer": "C", "explanation": "Pressure on the driver is P1 + P2  P1 = ρgh, P2 = 1.02 × 105 (atmospheric pressure)  P1 = 1000 × 10 × 5.2  P1 = 5.2 × 104 + 1.02 × 105 = 1.54 × 105 Pa", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>5", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "An object weighs 60.0N in air, 48.2N in a certain liquid X, and 44.9N in water. Calculate the relative density of X.", "images": [], "options": {"A": "3.300", "B": "1.279", "C": "0.932", "D": "0.782"}, "answer": "D", "explanation": "relativedensity=loss of weight in airloss of weight in water  =60.0 - 48.260.0 - 44.9=0.782", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>6", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A steel needle floating on water, sinks when kerosine is added to the water. This is because the kerosine", "images": [], "options": {"A": "increases the surface tension of the water.", "B": "reduces the density of water.", "C": "reduces the surface tension of the water.", "D": "reduces the upthrust on the needle."}, "answer": "C", "explanation": "The steel needle floats on water due to the surface tension of the water. Surface tension is a property of the surface of a liquid that allows it to resist an external force. When kerosine is added to the water, it reduces the surface tension of the water. As a result, the needle sinks because the reduced surface tension can no longer support the weight of the needle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>7", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Calculate the change in volume when 90g of ice is completely melted. [density of water = 1gcm-3, density of ice = 0.9gcm-3]", "images": [], "options": {"A": "0.00 cm3", "B": "9.00 cm3", "C": "10.00 cm3", "D": "90.00 cm3"}, "answer": "C", "explanation": "Volume of 90g of water  90g1gcm-3=90cm3  Volume of 90g of ice  90g0.9gcm-3=100cm3  Difference = 100cm3 - 90cm3 = 10cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>8", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "On which of the following factors does the viscosity of a liquid depend?  I. Nature of the liquid;  II. Temperature of the liquid;  III. Area of the liquid surface.", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "A", "explanation": "The viscosity of a liquid depends on the nature of the liquid and the temperature of the liquid. The nature of the liquid refers to the type of molecules in the liquid and their interactions. The temperature of the liquid affects the kinetic energy of the molecules, which in turn affects the viscosity. The area of the liquid surface does not affect the viscosity of the liquid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>9", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "An elastic string of force constant 200 Nm-1 is stretched through 0.8m within its elastic limit. Calculate the energy stored in the string.", "images": [], "options": {"A": "64.0J", "B": "80.0J", "C": "128.0J", "D": "160.0J"}, "answer": "A", "explanation": "The energy stored in an elastic string is given by the formula E = 1/2 kx^2, where k is the force constant and x is the extension. Substituting the given values, we get E = 1/2 * 200 * 0.8^2 = 64.0J. Therefore, the correct answer is 64.0J.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>10", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MACHINES :", "question": "A machine of velocity ratio 5 is used in lifting a load with an effort of 500N. If the machine is 80% efficient, determine the magnitude of the load.", "images": [], "options": {"A": "2500N", "B": "2000N", "C": "900N", "D": "625N"}, "answer": "B", "explanation": "M.A=Load500=L500  V.R = 5  E=Load500×15×100=80  =L25=80  L = 80 × 25 = 2000N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>11", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "The speed of an object in rectilinear motion can be determined from the", "images": [], "options": {"A": "area under a velocity-time graph", "B": "area under a distance-time graph", "C": "slope of a distance-time graph", "D": "slope of a velocity-time graph"}, "answer": "C", "explanation": "The speed of an object in rectilinear motion can be determined from the slope of a distance-time graph  Slope=distancetime", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>12", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A body is said to be moving with uniform acceleration if it experiences equal", "images": [], "options": {"A": "increases in velocity at equal time intervals", "B": "decreases in velocity at equal time intervals", "C": "increases in speed at equal time intervals", "D": "decreases in speed at equal time intervals"}, "answer": "A", "explanation": "A body is said to be moving with uniform acceleration if it experiences equal increases in velocity at equal time intervals. This is the definition of uniform acceleration. It means that the rate of change of velocity is constant over time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>13", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A body dropped from a certain height above the ground level, falls with uniform", "images": [], "options": {"A": "speed", "B": "velocity", "C": "acceleration", "D": "retardation"}, "answer": "C", "explanation": "A body dropped from a certain height above the ground level, falls with uniform acceleration. This is due to the force of gravity, which causes all objects to accelerate towards the earth at a constant rate (ignoring air resistance). This rate is approximately 9.8 m/s^2 on the surface of the earth.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>14", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 8kg moving with a speed of 30ms-1 is brought to rest in 2.5s by a constant retarding force.   Calculate the magnitude of the force.", "images": [], "options": {"A": "240N", "B": "96N", "C": "20N", "D": "9N"}, "answer": "B", "explanation": "Using the first equation of motion to find deceleration  v = u + at  final velocity (v) = 0  u = 30m/s  t = 2.5s  a=u - vt  =30 - 02.5=302.5  F=ma=8×302.5=96N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>15", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A force acting on a body causes a change in the momentum of the body from 12 kgms-1 to 16 kgms-1 in 0.2s.  Calculate the magnitude of the force.", "images": [], "options": {"A": "140.0N", "B": "20.0N", "C": "4.0N", "D": "0.8N"}, "answer": "B", "explanation": "The force acting on a body is given by the change in momentum divided by the time taken for this change. This is based on Newton's second law of motion which states that the rate of change of momentum of a body is directly proportional to the force applied and occurs in the direction in which the force is applied. In this case, the change in momentum is 16 kgms-1 - 12 kgms-1 = 4 kgms-1. The time taken for this change is 0.2s. Therefore, the force is 4 kgms-1 / 0.2s = 20.0N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>16", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "The bob of a simple pendulum has a mass of 0.02kg. Determine the weight of the bob. [g = 10ms-2]", "images": [], "options": {"A": "0.02N", "B": "0.20N", "C": "20.00N", "D": "200.00N"}, "answer": "B", "explanation": "The weight of an object is given by the product of its mass and the acceleration due to gravity. This is based on the formula W = mg, where W is the weight, m is the mass and g is the acceleration due to gravity. In this case, the mass of the bob is 0.02kg and the acceleration due to gravity is 10ms-2. Therefore, the weight of the bob is 0.02kg * 10ms-2 = 0.20N.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>17", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A ball bearing is projected vertically upwards from the ground with a velocity of 15ms-1. Calculate the time taken by the ball to return to the ground. [g = 10ms-2]", "images": [], "options": {"A": "1.5s", "B": "3.0s", "C": "5.0s", "D": "7.5s"}, "answer": "B", "explanation": "Using the first equation of motion   v = u + at  v = 0, u = 15m-1, a = -10m/s2  t=v - ua=1510=1.5s  time taken to reach ground = 2t = 2 × 1.5s  ⇒ 3.0s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>18", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "A loaded spring performs simple harmonic motion with an amplitude of 5cm. If the maximum acceleration of the load is 20cms-2, calculate the angular frequency of the motion.", "images": [], "options": {"A": "2 rad s-1", "B": "4 rad s-1", "C": "5 rad s-1", "D": "10 rad s-1"}, "answer": "A", "explanation": "ω(angularvelocity)=&radic;ar&nbsp;=&radic;20cms-25cm&nbsp;=&radic;4rad s-2&nbsp;  ⇒ 2rad s-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>19", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "When compared with water, mercury is preferred as a thermometric liquid because it", "images": [], "options": {"A": "has a higher density.", "B": "has a lower specific heat capacity.", "C": "exhibits anomalous thermal expansion.", "D": "contains molecules which have very strong adhesive forces."}, "answer": "B", "explanation": "Mercury is preferred as a thermometric liquid over water because it has a lower specific heat capacity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>20", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Which of the following values on the absolute scale of temperature is the ice point?", "images": [], "options": {"A": "0 K", "B": "32 K", "C": "100 K", "D": "273 K"}, "answer": "D", "explanation": "The ice point, or the temperature at which water freezes, is 0 degrees Celsius. On the absolute scale of temperature, also known as the Kelvin scale, 0 degrees Celsius is equivalent to 273 K.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>21", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "On a cold day, a concrete floor feels colder to the bare foot than a mat on the same floor because the", "images": [], "options": {"A": "mat is a better conductor of heat than the foot.", "B": "mat loses heat to the bare foot at a faster rate.", "C": "mat is a better conductor of heat than the floor.", "D": "concrete floor is a better conductor of heat than the mat."}, "answer": "D", "explanation": "Heat energy from your leg flows faster to the concrete, thereby having the cold feeling, mat has high insulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>22", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "When a metal ball is heated through 30°C, its volume becomes 1.0018 cm3. If the linear expansivity of the material of the ball is 2.0 × 10-5K-1, calculate its original volume.", "images": [], "options": {"A": "1.0000 cm3", "B": "1.0020 cm3", "C": "1.0036 cm3", "D": "1.0180 cm3"}, "answer": "A", "explanation": "ΔV = V1θα  V2 - V1 = αV1θ (ΔV = V2 - V1)  making V1 the subject of formular,  we have   V1[1 + αθ] = V2  V1=V2[1+αθ  =1.0018[1 + 30 × 6 × 10-5  =1.00181.0018  V1 = 1cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>23", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A faulty barometer reads 72.6 cmHg when the atmospheric pressure is 75.0cmHg. Calculate the atmospheric pressure when this barometer reads 72.0 cmHg.", "images": [], "options": {"A": "79.4 cmHg", "B": "74.4 cmHg", "C": "74.2 cmHg", "D": "69.4 cmHg"}, "answer": "B", "explanation": "The barometer reads lower than the actual atmospheric pressure. The difference between the actual and the reading is 2.4cmHg. So, when the barometer reads 72.0 cmHg, the actual atmospheric pressure would be 74.4 cmHg.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>24", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "On the basis of the kinetic theory, an increase in the temperature of a fixed volume of an ideal gas causes", "images": [], "options": {"A": "an increase in the number of the gas molecules.", "B": "a decrease in the density of the gas.", "C": "an increase in the average speed of the gas molecules.", "D": "a decrease in the pressure exerted by the gas."}, "answer": "C", "explanation": "According to the kinetic theory of gases, an increase in temperature of a fixed volume of an ideal gas causes an increase in the average speed of the gas molecules. This is because temperature is directly proportional to the average kinetic energy of the gas molecules, and kinetic energy is related to the speed of the molecules. Therefore, when the temperature increases, the average kinetic energy and hence the average speed of the gas molecules also increase.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>25", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The temperature of 900cm3 of an ideal gas at a pressure of 114cmHg is 27°C. Calculate its volume at 76cmHg and 0°C.", "images": [], "options": {"A": "50.0 cm3", "B": "546.0 cm3", "C": "659.3 cm3", "D": "1228.5 cm3"}, "answer": "D", "explanation": "P1V1T1=P2V2T2  T1 = 27 + 273 = 300K  T2 = 0 + 273 = 273  making V2 subject of the formular  V2=P1V1T2P2T1  =900 × 114 + 27376 × 300 = 1228.5cm3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>26", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "The basic difference between a transverse wave and a longitudinal wave travelling in the same direction in a medium is in the", "images": [], "options": {"A": "amplitude of the waves.", "B": "wavelength of the waves.", "C": "direction of vibration of the particles of the medium.", "D": "period of vibration of the particles of the medium."}, "answer": "C", "explanation": "Transverse waves travels perpendicularly in the direction of the wave while longitudional waves travels in the same direction reavelled by the wave.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>27", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "PROPERTIES OF WAVES : REFRACTION", "question": "A wave travelling from water to glass suffers a change in its speed at the common boundary. Which of the following properties explains this observation?", "images": [], "options": {"A": "Dispersion", "B": "Refraction", "C": "Interference", "D": "Diffraction"}, "answer": "B", "explanation": "The phenomenon that explains the change in speed of a wave as it moves from one medium to another is called Refraction. Refraction is the bending of a wave when it enters a medium where its speed is different. The refraction of light when it passes from a fast medium to a slow medium bends the light ray toward the normal to the boundary between the two media. Hence, the correct answer is Refraction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>28", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The image of an optical pin placed at the principal focus of a concave mirror will be formed", "images": [], "options": {"A": "between the principal focus and the pole.", "B": "at the centre of curvature.", "C": "between the principal focus and the centre of curvature.", "D": "at infinity."}, "answer": "D", "explanation": "When an object is placed at the principal focus of a concave mirror, the image is formed at infinity. This is because the rays of light from the object, after reflection, will become parallel to the principal axis. Hence, the correct answer is 'at infinity.'", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>29", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A man 1.8m tall stands 3m away from a pin hole camera. If the distance between the pin hole and the screen of the camera is 0.3m. Calculate the height of the image of the man produced by the camera.", "images": [], "options": {"A": "0.18m", "B": "0.50m", "C": "1.62m", "D": "18.00m"}, "answer": "A", "explanation": "M=length of cameradistance of object from pinhole=height of imageheight of object  0.33=x1.8  x=1.8 × 0.33 = 0.18m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>30", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "In an experiment using a converging lens to produce real images on a screen, the linear magnification, m, is plotted against the image distance, v, as illustrated in the diagram below. The distance OP represents the", "images": ["Physics/imgs/2004/img1.png"], "options": {"A": "focal length of the lens", "B": "thickness of the lens", "C": "radius of curvature of the lens", "D": "diameter of the lens"}, "answer": "A", "explanation": "The distance OP represents the focal length of the lens", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>31", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A magnified and virtual image of a near object is produced by", "images": [], "options": {"A": "prism binoculars", "B": "astronomical telescope", "C": "periscope", "D": "simple microscope"}, "answer": "D", "explanation": "A simple microscope, or magnifying glass, produces a magnified and virtual image of a near object. This is because it uses a converging lens to bend light rays inward, which makes the object appear larger than it actually is. The image is virtual because the light rays do not actually meet at the point where the image appears to be.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>32", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "During a thunderstorm, lightning and thunder occurred simultaneously in the atmosphere. An observer on the earth's surface sees the lightning flash shortly before hearing the thunder. This is because the", "images": [], "options": {"A": "atmospheric pressure is higher at the surface than at the higher altitudes.", "B": "speed of sound is less than that of light.", "C": "temperature of the atmosphere decreases with altitude.", "D": "atmospheric density decreases with altitude."}, "answer": "B", "explanation": "Light travels faster than sound. This is why we see lightning before we hear thunder. The speed of light is approximately 299,792 kilometers per second, while the speed of sound is around 343 meters per second (in air at sea level). Therefore, the light from the lightning reaches us much faster than the sound of the thunder.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>33", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "A girl stands 80m away from a tall cliff and blows a whistle. If the speed of sound in air is 330ms-1, how long would it take for her to hear the echo of the sound?", "images": [], "options": {"A": "2.062s", "B": "0.970s", "C": "0.485s", "D": "0.242s"}, "answer": "C", "explanation": "Speedofecho=2 x dt  330=2 x 804  t=160330  t = 0.48", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>34", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "Which of the following reasons explains why the walls and ceilings of a standard concert hall are usually covered with perforated pads? To", "images": [], "options": {"A": "increase the intensity of sound waves.", "B": "increase the loudness of the sound waves.", "C": "reduce the effect of reverberation of sound waves.", "D": "decrease the frequency of sound waves."}, "answer": "C", "explanation": "The walls and ceilings of a concert hall are usually covered with perforated pads to reduce the effect of reverberation of sound waves. Reverberation is the persistence of sound in a particular space after the original sound is removed. When sound is produced in an enclosed space, multiple reflections build up and blend together, causing reverberation. This can distort the sound quality, hence the need to reduce its effect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>35", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "The sound from a vibrating tuning fork is louder when the tip of its stem is placed on a wooden table than when in air because", "images": [], "options": {"A": "the friction between the table and the tuning fork generate additional energy", "B": "air molecules absorb sound waves but wood transmits sound waves", "C": "the table increases the frequency of the tuning fork", "D": "a larger mass of air is set into vibration by the table"}, "answer": "D", "explanation": "The sound from a vibrating tuning fork is louder when the tip of its stem is placed on a wooden table than when in air because a larger mass of air is set into vibration by the table. This is because the table, being a solid, can transmit the vibrations more effectively than air. These vibrations cause the air particles around the table to vibrate, producing a louder sound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>36", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : TYPES OF DISTRIBUTION OF CHARGES", "question": "Charges on a conductor are", "images": [], "options": {"A": "evenly distributed over a surface of any shape.", "B": "concentrated on the inner surface of the conductor.", "C": "concentrated at the outer flat surface of the conductor.", "D": "generally concentrated at sharply curved surface."}, "answer": "D", "explanation": "Charges on a conductor are generally concentrated at sharply curved surfaces. This is due to the fact that the electric field is stronger at points where the curvature is greater, causing the charges to accumulate there. This is known as the 'lightning rod effect', as it is the principle behind the working of a lightning rod.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>37", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the following functions is performed by manganese IV oxide in the Leclanche' cell?", "images": [], "options": {"A": "Control of local action", "B": "Depolarisation of the cell", "C": "Regulating current flow in the cell", "D": "Reduction of the internal resistance of the cell"}, "answer": "B", "explanation": "In a Leclanche cell, manganese IV oxide (MnO2) acts as a depolarizer. A depolarizer is a substance that reduces the buildup of positive charge (polarization) at the anode or negative charge at the cathode during the operation of a battery. This helps to maintain a steady flow of electrons and thus a steady current.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>38", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A car fuse marked 3A operates optimally on a 12V battery, calculate the resistance of the fuse.", "images": [], "options": {"A": "36.0Ω", "B": "15.0Ω", "C": "9.0Ω", "D": "4.0Ω"}, "answer": "D", "explanation": "I=VR  R=VI=123=4.0Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>39", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Find the cost of running a 60W lamp for 24 hours, if 1kWhr costs 5 Naira.", "images": [], "options": {"A": "14.4 Naira", "B": "12.5 Naira", "C": "7.2 Naira", "D": "2.0 Naira"}, "answer": "C", "explanation": "60watt bulb for 24hrs  P = 60 × 24 = 1440watts = 1.44kW  Charge = P × charge per hr  ⇒ 1.44 × 5  ⇒ ₦7.20", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>40", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The quantity of electric charge stored in a capacitor is measured in", "images": [], "options": {"A": "Farad", "B": "Ampere", "C": "Coulomb", "D": "Volt"}, "answer": "C", "explanation": "The quantity of electric charge stored in a capacitor is measured in Coulombs. The unit of charge in the International System of Units (SI) is the Coulomb, which is equivalent to the charge transported by a steady current of one ampere in one second.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>41", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : STORAGE OF CHARGES", "question": "Calculate the energy stored in a 20μF capacitor if the p.d between the plates is 40V.", "images": [], "options": {"A": "3.2 × 10-2J", "B": "1.6 × 10-2J", "C": "8.0 × 10-4J", "D": "4.0 × 10-4J"}, "answer": "B", "explanation": "E=12CV2  E=12×20×10-6×40×40  ⇒ 10 × 10-6 × 40 × 40  ⇒ 1.6 × 10-2J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>42", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "Given that the gravitational constant is G, Newton's universal law of gravitation states that the force of attraction between two masses M1 and M2 separated by a distance r is", "images": [], "options": {"A": "Gr2M22", "B": "GrM1M2", "C": "GM1M2r2", "D": "GM1M2r"}, "answer": "C", "explanation": "The force varies directly with the masses and inversely with the square of the distance.  GM1M2r2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>43", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "A charge of 1.6 × 10-10C is placed in a uniform electric field of intensity 2.0 × 105NC-1. Calculate the magnitude of the electric force exerted on the charge.", "images": [], "options": {"A": "3.2 × 105N", "B": "1.8 × 105N", "C": "3.2 × 10-5N", "D": "1.8 × 10-5N"}, "answer": "C", "explanation": "The electric force exerted on a charge in a uniform electric field is calculated by multiplying the charge by the field intensity. So, 1.6 × 10-10C * 2.0 × 105NC-1 = 3.2 × 10-5N. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>44", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "Which of the following statements is not correct?", "images": [], "options": {"A": "A magnetic field is a region in which a magnetic force may be detected.", "B": "A magnetic line of force is a path along which a magnetic north-pole would move if it were free.", "C": "Magnetic fields are scalar quantities.", "D": "Neutral points are obtained where the earth's magnetic field is exactly equal and opposite to that due to a magnet."}, "answer": "C", "explanation": "Magnetic fields are vector quantities, not scalar quantities. They have both magnitude and direction. Therefore, the statement 'Magnetic fields are scalar quantities' is not correct. Hence, the correct answer is option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>45", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "The main function of the mouth piece of a telephone is that it converts sound energy to", "images": [], "options": {"A": "mechanical energy", "B": "electrical energy", "C": "chemical energy", "D": "thermal energy"}, "answer": "B", "explanation": "The main function of the mouthpiece of a telephone is to convert sound energy into electrical energy. This is done by a microphone in the mouthpiece that converts the sound waves into electrical signals. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>46", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "An atom is normally electrically neutral because the", "images": [], "options": {"A": "number of electrons is equal to the number of protons", "B": "number of electrons is equal to the number of neutrons", "C": "number of protons is equal to the number of neutrons", "D": "electrons of the atom are buried deeply in the nucleus"}, "answer": "A", "explanation": "An atom is electrically neutral because the number of electrons (negative charge) is equal to the number of protons (positive charge). This balance of charges results in a net charge of zero, making the atom electrically neutral.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2004>47", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "In which of the following devices is the principle of photoelectric effect not applicable?", "images": [], "options": {"A": "Closed-circuit television camera", "B": "Burglar alarm", "C": "Solar cells", "D": "Periscope"}, "answer": "D", "explanation": "The principle of photoelectric effect is not applicable in a periscope. The photoelectric effect is the phenomenon where electrons are emitted from a material (usually metallic) when light of suitable frequency falls on it. This principle is used in devices like closed-circuit television cameras, burglar alarms, and solar cells, but not in periscopes, which work on the principle of reflection of light.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>48", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Which of the following statements about X-rays is not correct? They", "images": [], "options": {"A": "are electromagnetic waves.", "B": "can be used to study crystal lattice.", "C": "can destroy living cells.", "D": "are produced from the nucleus of an atom."}, "answer": "D", "explanation": "X-rays are not produced from the nucleus of an atom. They are produced when high-energy electrons strike a metal target or when electrons are rearranged in an atom. The other statements are correct: X-rays are electromagnetic waves, they can be used to study crystal lattice, and they can destroy living cells.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2004>49", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radio active substance has a half-life of 3 days. If a mass of 1.55g of this substance is left after decaying for 15 days, determine the original value of the mass.", "images": [], "options": {"A": "49.6g", "B": "37.2g", "C": "24.8g", "D": "12.4g"}, "answer": "A", "explanation": "after3days→12N  after6days→14N  after9days→18N  after12days→116N  after15days→132N  132N→1.55  1N → x  Original mass = 32 × 1.55 = 49.6g", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2004>50", "subject": "Physics", "year": "2004", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Which of the following representations is correct for an atom X with 28 electrons and 30 neutrons?", "images": [], "options": {"A": "3028X", "B": "2830X", "C": "5830X", "D": "5828X"}, "answer": "D", "explanation": "The atomic notation for an atom is usually written as ^A_ZX, where A is the atomic mass number (the number of protons plus neutrons), Z is the atomic number (the number of protons or electrons in a neutral atom), and X is the symbol for the element. In this case, the atom has 28 electrons (and therefore 28 protons in a neutral atom) and 30 neutrons. Therefore, the atomic mass number is 28 + 30 = 58. So the correct representation for the atom is 5828X.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>1", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following phenomena is the practical evidence for the existence of the continual motion of molecules?", "images": [], "options": {"A": "Translational motion", "B": "Rotational motion", "C": "Brownian motion", "D": "Oscillatory motion"}, "answer": "C", "explanation": "Brownian motion is the random motion of particles suspended in a fluid (a liquid or a gas) resulting from their collision with the fast atoms or molecules in the gas or liquid. This phenomenon provides practical evidence for the continual motion of molecules, as it can be directly observed under a microscope.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>2", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF SCALARS~~SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Each of the following physical quantities is classified as a vector or a scalar quantity. Which of the classifications is correct?", "images": [], "options": {"A": "Electric potential (Vector)", "B": "Momentum (Scalar)", "C": "Gravitational field intensity (Scalar)", "D": "Magnetic flux density (Vector)"}, "answer": "D", "explanation": "The correct classification is 'Magnetic flux density (Vector)'. Magnetic flux density is a vector quantity because it has both magnitude and direction. Electric potential is a scalar quantity because it only has magnitude. Momentum is a vector quantity because it has both magnitude and direction. Gravitational field intensity is a vector quantity because it has both magnitude and direction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>3", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "Which of the following statements about a spring balance and/or a chemical balance is not correct?", "images": [], "options": {"A": "The chemical balance operates on the principle of moments.", "B": "The spring balance operates on Hooke's law.", "C": "Either may be used to measure the weight of a substance.", "D": "The reading of a spring changes over the surface of the earth, while that of the chemical balance remains constant."}, "answer": "C", "explanation": "The incorrect statement is 'Either may be used to measure the weight of a substance.' A spring balance measures weight, which is a force, while a chemical balance measures mass. Weight is dependent on gravity, while mass is a constant. Therefore, a chemical balance cannot be used to measure weight.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>4", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "The friction which exists between two layers of liquid in relative motion is called", "images": [], "options": {"A": "capillarity", "B": "surface tension", "C": "viscosity", "D": "cohesion"}, "answer": "C", "explanation": "The friction which exists between two layers of liquid in relative motion is called 'viscosity'. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid. A fluid with large viscosity resists motion because its molecular makeup gives it a lot of internal friction. A fluid with low viscosity flows easily because its molecular makeup results in very little friction when it is in motion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>5", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "A body of mass 25kg, moving at 3ms-1 on a rough horizontal floor is brought to rest after sliding through a distance of 2.50m on the floor. Calculate the coefficient of sliding friction.  [g = 10.0 ms-2]", "images": [], "options": {"A": "0.09", "B": "0.18", "C": "0.36", "D": "0.54"}, "answer": "B", "explanation": "F = μR  where, F is friction  μ is coefficient of friction  R is the normal reaction  From equation,  μ=FR  F = Ma   R = Mg  substituting for F and R, we have,  μ=MaMg  Using the third equation of motion to obtain a  we have  v2 = u2 + 2as  v = 0, since the body is brought to rest   u = 3m/s  s = 2.50m  From the third equation of motion making a  the subject of the formular  we have,  a=v2-u22s  a=02-322(2.5)=-95=-1.8m/s2  The negative sign shows the body is decelerating  Therefore, μ=25kg × 1.8ms-225kg × 10ms_2  μ = 0.18", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>6", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following simple machines is a second class lever?", "images": [], "options": {"A": "Wheel barrow", "B": "Crowbar", "C": "Claw hammer", "D": "Seesaw"}, "answer": "A", "explanation": "A wheelbarrow has it's load in between the fulcrum and force (effort).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>7", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MACHINES :", "question": "A wheel and axle of radii 800mm and 200mm respectively is used to raise a body of weight 800N by application of 250N. Calculate the efficiency of the machine.", "images": [], "options": {"A": "85%", "B": "80%", "C": "60%", "D": "20%"}, "answer": "B", "explanation": "E=M.AV.R  V.Rofwheelandaxle=radius of wheelradius of axle  =800mm200=4  V.R = 4  Therefore,  E=3.24×100=80%", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>8", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Masses, m1 and m2 at the 20-cm and 65-cm marks respectively of a uniform metre rule freely suspended at its centre of gravity. If the metre rule balances horizontally, determine the ratio m2 : m1.", "images": [], "options": {"A": "2 : 1", "B": "3 : 3", "C": "2 : 3", "D": "1 : 2"}, "answer": "A", "explanation": "Clockwise moment = Anticlockwise moment  Clockwise moment = 30 × M1 = 30M1  Anticlockwise moment = 15 × M2 = 15M2  30M1 = 15M2  M2M1=3015  M2M1=21  Ration of M2 : M1 = 2 : 1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>9", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "Which of the following types of motion does a body undergo when acted upon by a couple?", "images": [], "options": {"A": "Vibrational", "B": "Translational", "C": "Rotational", "D": "Random"}, "answer": "C", "explanation": "A body acted upon by a couple undergoes rotational motion, which matches option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>10", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A body starts from rest and accelerates uniformly at 5ms-2 until it attains a velocity of 25ms-1. Calculate the time taken to attain this velocity.", "images": [], "options": {"A": "2.5s", "B": "5.0s", "C": "10.0s", "D": "125.0s"}, "answer": "B", "explanation": "Using the first equation of motion  v = u + at  25 = 0 + at  at = 25   a = 5m/s2  25 = 5t  t=255=5", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>11", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A particle accelerates uniformly from rest at 6.0ms-2 for 8s and then decelerates uniformly to rest in the next 5s. Determine the magnitude of the deceleration.", "images": [], "options": {"A": "9.6 ms-2", "B": "24.0 ms-2", "C": "30.0 ms-2", "D": "48.0 ms-2"}, "answer": "A", "explanation": "Using the first equation of motion   v = u + at  The body first accelerates uniformly from rest,  u = 0  a = 6.0m/s  t = 8s  Therefore, v = 0 + (6 × 8)  v = 48 m/s  The body then decelerates from u = 48m/s to rest (v = 0) in 5 seconds (t = 5)    ∴ Using the first equation, make a the subject of the formula  a=u - vt  a=48-05=485=9.6ms-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>12", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The frequency of a swinging pendulum is the", "images": [], "options": {"A": "number of complete oscillations the pendulum makes in one second.", "B": "number of amplitudes the bob makes in one second.", "C": "angle the bob swings through in one second.", "D": "distance the bob covers in one second."}, "answer": "A", "explanation": "Frequency of a swinging pendulum is the number of complete oscillations the pendulum makes in one second.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>13", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "Which of the following statements about an object performing simple harmonic motion is correct. Its acceleration", "images": [], "options": {"A": "is maximum at the extreme ends.", "B": "is constant and directed towards a fixed point.", "C": "is zero when it is displaced from the equilibrium position.", "D": "varies linearly with the displacement from a fixed point and is directed towards the fixed point."}, "answer": "A", "explanation": "In simple harmonic motion, the acceleration of the object is directly proportional to the displacement from the equilibrium position and is always directed towards it. However, the acceleration is maximum at the extreme ends of the motion, which are the points of maximum displacement from the equilibrium position. Therefore, the correct answer is 'is maximum at the extreme ends.'", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>14", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 5kg moving with a velocity of 10ms-1 collides with a stationary body of mass 6kg. If the two bodies stick together and move in the same direction after the collision, calculate their common velocity.", "images": [], "options": {"A": "4.55ms-1", "B": "12.00ms-1", "C": "30.00ms-1", "D": "50.00ms-1"}, "answer": "A", "explanation": "Using the law of conservation of momentum  M1U1 + M2U2 = M1V1 + M2V2  R. H. S = (M1 + M2)V, since both body stick together .  Therefore, M1U1 + M2U2 = (M1 + M2)V  Substituting  (5 × 10) + (6 × 0) = (5 + 6)V  50 + 0 = 11V  50 = 11V  V=5011=4.55ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>15", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "SATELLITES AND ROCKETS :", "question": "Fuel was consumed at a steady rate of 5.0 × 10-2kg per second in a rocket engine and ejected as a gas with a speed of 4 × 103ms-1. Determine the thrust on the rocket.", "images": [], "options": {"A": "20N", "B": "80N", "C": "200N", "D": "800N"}, "answer": "C", "explanation": "Thrust = mass ejected per second × Velocity  ⇒ 5 x 10-2 x 4 x 103 = 20 x 101 = 200N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>16", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "Which of the following quantities has the same unit as energy?", "images": [], "options": {"A": "Power", "B": "Work", "C": "Force", "D": "Momentum"}, "answer": "B", "explanation": "Energy is the capacity to do work. Therefore, the unit of energy is the same as that of work. Power is the rate of doing work or the amount of energy transferred per unit time, which is different from energy. Force is a push or pull upon an object resulting from the object's interaction with another object, which is also different from energy. Momentum is the product of the mass and velocity of an object, again different from energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>17", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ENERGY : WORLD ENERGY RESOURCES", "question": "Which of these is the source of solar energy?", "images": [], "options": {"A": "Sun", "B": "Water", "C": "Wind", "D": "Air"}, "answer": "A", "explanation": "Solar energy is the energy from the Sun. The Sun is the source of solar energy. Water, wind, and air can be sources of other types of energy, but not solar energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>18", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The lower and upper fixed points of a thermometer are 30mm and 180mm respectively. Calculate the temperature in degrees Celsius when the thermometer reads 45mm.", "images": [], "options": {"A": "10.0°C", "B": "15.0°C", "C": "20.0°C", "D": "30.0°C"}, "answer": "A", "explanation": "45 - 30180 - 30=x - 0100 - 0  15150=x100  x=15×100150=10°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>19", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "A body of mass, m, has a specific heat capacity, s, and a heat capacity, c. If the temperature of the body changes by θ°C, which of the following equations is correct?", "images": [], "options": {"A": "msθ = mc-1", "B": "ms = C", "C": "ms = sθ", "D": "ms = cθ"}, "answer": "B", "explanation": "Heat lost = Heat gained  cθ = msθ  ms = C    Therefore, the correct equation is ms = C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>20", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "An immersion heater rated 400W, 220V, is used to heat a liquid of mass 0.5kg. If the temperature of the liquid increases uniformly at the rate of 2.5°C per second, calculate the specific heat capacity of the liquid. [Assume no heat is lost]", "images": [], "options": {"A": "1100 Jkg-1K-1", "B": "320 Jkg-1K-1", "C": "200 Jkg-1K-1", "D": "176 Jkg-1K-1"}, "answer": "B", "explanation": "Since there is no heat loss  IVt = mcθ  Therefore,  c=IVtmθ=Ptmθ  c=400 × 10.5 × 2.5=320Jkg-1K-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>21", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "Water falls through a height of 50m. Determine the temperature rise of the water at the bottom of the fall.  [Neglect energy losses. Specific heat capacity of water = 4200 Jkg-1K-1, g = 10ms-2]", "images": [], "options": {"A": "0.119°C", "B": "0.840°C", "C": "1.190°C", "D": "8.400°C"}, "answer": "A", "explanation": "Since there is no heat/Energy loss   Energy from fall = mgH  M is mass  g is acceleration due to gravity  H is height    Energy converted to heat = mcθ  mgH = mcθ  dividing through by m  gH = cθ  Therefore,  θ=gHc  =10 × 504200=0.119°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>22", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "The energy required to change a solid to liquid at constant temperature is called", "images": [], "options": {"A": "thermal capacity", "B": "specific heat capacity", "C": "latent heat of fusion", "D": "latent heat of vaporization"}, "answer": "C", "explanation": "The energy required to change a solid to liquid at constant temperature is called the latent heat of fusion. This is the amount of energy needed to change a substance from the solid phase to the liquid phase at a constant temperature and pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>23", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following statements about boiling and evaporation at atmospheric pressure is correct?", "images": [], "options": {"A": "Evaporation and boiling of water take place at 100°C", "B": "Evaporation of water takes place at a temperature greater than 100°C, while boiling takes place at 100°C", "C": "Evaporation of water takes place at 100°C while boiling takes place at a higher temperature", "D": "Boiling takes place at 100°C while evaporation may take place at temperature lower than 100°C"}, "answer": "D", "explanation": "Boiling is a process where a liquid turns into a vapor at a specific temperature, which for water is 100°C at atmospheric pressure. Evaporation, on the other hand, can occur at any temperature below the boiling point. It is a surface phenomenon where molecules at the surface of a liquid with enough kinetic energy can escape into the gaseous phase. Therefore, evaporation can take place at temperatures lower than 100°C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>24", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statements is correct?", "images": [], "options": {"A": "The density of a liquid decreases when it expands", "B": "The densities of liquids increase when the liquids are heated", "C": "The real expansivity of a liquid is less than its apparent expansivity", "D": "A liquid changes to solid when heated to a sufficiently high temperature"}, "answer": "A", "explanation": "When a liquid expands, its volume increases. Since density is mass divided by volume, an increase in volume while the mass remains constant will result in a decrease in density. Therefore, the density of a liquid decreases when it expands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>25", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure exerted by a given mass of gas in a container", "images": [], "options": {"A": "decreases if the container is heated.", "B": "increases if the molecules of the gas move faster.", "C": "increases if the volume of the container is doubled.", "D": "decreases as the kinetic energy of the gas molecules."}, "answer": "B", "explanation": "According to the kinetic theory of gases, the pressure exerted by a gas is directly proportional to the average kinetic energy of its molecules. Therefore, if the molecules of the gas move faster, their kinetic energy increases, which in turn increases the pressure they exert.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>26", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES", "question": "Which of the following statements about a progressive mechanical wave is correct?", "images": [], "options": {"A": "It can be plane polarised", "B": "Its energy is localised at specific points of its profile", "C": "It does not require a material medium for its propagation", "D": "Its frequency remains constant as it travels between different media"}, "answer": "D", "explanation": "Its frequency remains constant as it travels between different media", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>27", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The distance between two points in phase on a progressive wave is 5cm. If the speed of the wave is 0.20ms-1, calculate its period.", "images": [], "options": {"A": "4.00s", "B": "2.50s", "C": "0.25s", "D": "0.04s"}, "answer": "C", "explanation": "v = λF  F=1T  substituting F for 1/T,  we have  v=λT  Therefore, T=λV  T=0.056.20=14=0.25seconds", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>28", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "PROPERTIES OF WAVES : REFRACTION", "question": "Radio waves travel in air at 3.0 × 108 ms-1. If the waves enter water of refractive index 4/3, calculate the speed of radio waves in water.", "images": [], "options": {"A": "4.33 × 108 ms-1", "B": "4.00 × 108 ms-1", "C": "2.25 × 108 ms-1", "D": "1.33 × 108 ms-1"}, "answer": "C", "explanation": "Refractiveindex=speed of wave in airspeed of wave in water  43=3 × 108speed in water  Speedinwater=3×108×34 = 2.25 × 108 ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>29", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The amplitude of a wave is the", "images": [], "options": {"A": "distance travelled by the wave in a complete cycle of its motion.", "B": "maximum displacement of the wave particle from the equilibrium position.", "C": "separation of two adjacent particles vibrating in a phase.", "D": "distance between two successive troughs of the wave"}, "answer": "B", "explanation": "maximum displacement of the wave particle from the equilibrium position.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>30", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following optical instruments does not depend on the use of plane mirrors?", "images": [], "options": {"A": "Kaleidoscope", "B": "Simple microscope", "C": "Sextant", "D": "Simple periscope"}, "answer": "B", "explanation": "A simple microscope does not depend on the use of plane mirrors. It works on the principle of refraction of light. The other options, Kaleidoscope, Sextant, and Simple periscope, all use plane mirrors in their operation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>31", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "A ray of light is incident normally on a plane mirror. If the incident ray is kept fixed while the mirror is rotated through an angle of 30°, determine the initial and final angle of reflection respectively.", "images": [], "options": {"A": "0° and 60°", "B": "90° and 30°", "C": "0° and 30°", "D": "90° and 60°"}, "answer": "C", "explanation": "When a ray of light is incident normally on a plane mirror, the angle of incidence is 0°. If the mirror is rotated through an angle of 30°, the angle of incidence is now 30° and from the law of reflection, the angle of incidence equals the angle of refraction. Thererefore, the angle of reflection before and after rotation of the mirror are 0° and 30° respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>32", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "In which of the following media is the transmission of sound waves fastest?", "images": [], "options": {"A": "Vacuum", "B": "Air", "C": "Wood", "D": "Iron"}, "answer": "D", "explanation": "Sound waves travel fastest in solids compared to liquids and gases. This is because particles in a solid are closely packed together, allowing the sound waves to transfer their energy more efficiently from one particle to the next. Among the given options, Iron is a solid and hence the transmission of sound waves is fastest in it.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>33", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The ability of a material to store an electric charge when its plates are at different potentials is referred to as its", "images": [], "options": {"A": "conductance", "B": "inductance", "C": "capacitance", "D": "resistance"}, "answer": "C", "explanation": "Capacitance is the ability of a material to store electric charge, when it's plates are at different potential.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>34", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Two capacitors of capacitances 0.4μF and 0.5μF are connected in parallel and charged to a p.d. of 50V. Determine the total charge acquired.", "images": [], "options": {"A": "45μC", "B": "25μC", "C": "20μC", "D": "10μC"}, "answer": "A", "explanation": "For capacitor in parallel, equivalent single capacitance is   C = C1 + C2  ⇒ 0.4μF + 0.5μF = 0.9μF  Charge = CV  ⇒ 0.9μF × 50 = 45μC", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>35", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A parallel plate capacitor of capacitance 600μF has a potential difference of 2000V between its plate. Calculate the charge on either plate of the capacitor.", "images": [], "options": {"A": "1.2C", "B": "3.3C", "C": "3330.0C", "D": "120000.0C"}, "answer": "A", "explanation": "The charge (Q) on a capacitor can be calculated using the formula Q = CV, where C is the capacitance and V is the voltage. Substituting the given values, we get Q = 600μF * 2000V = 1.2C. Therefore, the charge on either plate of the capacitor is 1.2C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>36", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A chemical cell of internal resistance 1Ω supplies electric current to an external resistor of resistance 3Ω. Calculate the efficiency of the cell.", "images": [], "options": {"A": "75%", "B": "50%", "C": "33%", "D": "25%"}, "answer": "A", "explanation": "The efficiency of a cell can be calculated using the formula Efficiency = (Load resistance / (Load resistance + Internal resistance)) * 100%. Substituting the given values, we get Efficiency = (3Ω / (3Ω + 1Ω)) * 100% = 75%. Therefore, the efficiency of the cell is 75%.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>37", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "An electric lamp is rated 240V, 40W. What is the cost of running the lamp for 72 hours if the electricity authority charges ₦2.50 per kWh?", "images": [], "options": {"A": "₦7.20", "B": "₦18.00", "C": "₦180.00", "D": "₦720.00"}, "answer": "A", "explanation": "Total cost = Ivt × charge per hour = Pt × charge   40w to kw  40w1000kw=4100=0.04kw  Total cost = 0.04 × 72 × 2.5 = ₦7.20", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>38", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Which of the following statements explains lost volt in an electric circuit? The", "images": [], "options": {"A": "total p.d from a source to maintain a flow of current through the circuit as well as the source", "B": "p.d to drive current through the circuit components except the source", "C": "p.d across all external components connected to the source of electricity", "D": "p.d across the internal resistance of the cell"}, "answer": "D", "explanation": "Lost volt in an electric circuit refers to the potential difference (p.d) across the internal resistance of the cell. This is because when current flows through a circuit, some energy is lost as heat due to the internal resistance of the cell. This energy loss is represented as a 'lost volt'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>39", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A constantan wire has a cross sectional area of 4 × 10-8m2 and a resistivity of 1.1 × 10-6Ωm. If a resistor of resistance 11Ω is to made from this wire, calculate the length of the wire required.", "images": [], "options": {"A": "0.4m", "B": "0.8m", "C": "2.5m", "D": "5.0m"}, "answer": "A", "explanation": "R=ρ1A  making l the subject of formular  l=RAρ  l=11 × 4 × 10-81.1 × 10-6=0.4m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>40", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "The mass weight of a body on earth are 8kg and 80N respectively. Determine the mass and weight on a planet where the pull of gravity is 1/8 that of earth.", "images": [], "options": {"A": "8kg, 8N", "B": "1kg, 10N", "C": "64kg, 10N", "D": "8kg, 10N"}, "answer": "D", "explanation": "The mass of an object remains constant regardless of the location. Therefore, the mass of the body on the other planet will still be 8kg. The weight of an object is given by the product of the mass and the gravitational pull. Since the gravitational pull on the other planet is 1/8 that of earth, the weight will be 1/8 of 80N which is 10N. Therefore, the mass and weight of the body on the other planet will be 8kg and 10N respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>41", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "Lenz's law of electromagnetic induction states that", "images": [], "options": {"A": "a force is exerted on a current carrying conductor in a magnetic field", "B": "electromotive force is induced in a circuit whenever there is a change in the magnetic flux linked with the circuit", "C": "the magnitude of the induced electromotive force in a circuit is proportional to the rate of change of flux linking the circuit", "D": "the induced current in a coil is in such a direction that it sets up a magnetic field which opposes the change producing it"}, "answer": "D", "explanation": "Lenz's law the induced current in a coil is in such a direction that it sets up a magnetic field which opposes the change producing it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>42", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "A bar magnet is placed near and lying along the axis of a solenoid connected to a galvanometer. The pointer of the galvanometer shows no deflection when", "images": [], "options": {"A": "the magnet is moved away from the stationery solenoid", "B": "the solenoid is moved away from the stationary magnet", "C": "the magnet is moved towards the stationary solenoid", "D": "there is not relative motion between the magnet and the solenoid"}, "answer": "D", "explanation": "The principle of electromagnetic induction states that a change in the magnetic field within a closed loop of wire induces a current in the wire. This means that if there is no relative motion between the magnet and the solenoid, there will be no change in the magnetic field within the solenoid, and hence no current will be induced. Therefore, the galvanometer will show no deflection.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>43", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "An electric motor is a machine that converts", "images": [], "options": {"A": "mechanical energy into electrical energy", "B": "electrical energy into mechanical energy", "C": "high voltage to low voltage", "D": "low voltage to high volume"}, "answer": "B", "explanation": "An electric motor is a device that converts electrical energy into mechanical energy. The motor works on the principle of magnetic effects of electric current. When an electric current is passed through a coil in a magnetic field, it experiences a force which makes it rotate. This rotation can be used to do mechanical work.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2005>44", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "Which of the following statements is not a reason for using soft iron in making the core of a transformer? It", "images": [], "options": {"A": "retains its magnetism for a long time", "B": "is easily magnetised", "C": "reduces energy loss due to the hysteresis", "D": "is easily demagnetised"}, "answer": "A", "explanation": "Soft iron is used in the core of a transformer because it is easily magnetised and demagnetised, and it reduces energy loss due to hysteresis. However, it does not retain its magnetism for a long time, which is a desirable property in a transformer core. This is because the core needs to rapidly switch its magnetism as the AC current changes direction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>45", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following statements is an advantage of nuclear fusion over nuclear fusion over nuclear fission?", "images": [], "options": {"A": "The resulting chain reaction which produces large amount of energy.", "B": "No radioactive waste is produced as by-product.", "C": "Very high temperatures required in the process.", "D": "The end products is lead."}, "answer": "B", "explanation": "Nuclear fusion is a process where two light atomic nuclei combine to form a heavier nucleus. This process releases a large amount of energy. One of the advantages of nuclear fusion over nuclear fission is that it does not produce radioactive waste as a by-product. Nuclear fission, on the other hand, involves the splitting of a heavy atomic nucleus into two lighter ones, and this process produces a significant amount of radioactive waste.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>46", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Beta particles are fast-moving", "images": [], "options": {"A": "protons", "B": "electrons", "C": "neutrons", "D": "photons"}, "answer": "B", "explanation": "Beta particles are high-energy, high-speed electrons or positrons emitted by certain types of radioactive nuclei such as potassium-40. The production of beta particles is termed beta decay. They are a type of ionizing radiation and for radiation protection purposes are regarded as being more ionising than gamma rays, but less ionising than alpha particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>47", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "A process by which two light atoms join to form a new atom of higher atomic mass is", "images": [], "options": {"A": "natural radioactivity", "B": "nuclear fission", "C": "nuclear fusion", "D": "chain reaction"}, "answer": "C", "explanation": "The process by which two light atoms join to form a new atom of higher atomic mass is called nuclear fusion. This process is responsible for the energy produced by the sun and other stars. In nuclear fusion, two atomic nuclei combine to form a heavier nucleus, releasing a large amount of energy in the process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2005>48", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "Light of energy 5.0eV falls on a metal of work function 3.0eV and electrons are emitted, determine the stopping potential.  [electronic charge, e = 1.60 × 10-19C]", "images": [], "options": {"A": "1.7V", "B": "2.0V", "C": "8.0V", "D": "15.0V"}, "answer": "B", "explanation": "Energy of radiation = 5.0eV  Working function = 3.0eV  Stopping potential = K.E  Energy of incident radiation = work function + kinetic energy  ⇒ 5.0 - 3.0 = 2.0eV", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>49", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "The mass of a proton is 1.0074μ and that of a neutron is 1.0089μ. Determine the energy evolved in stabilizing the nucleus of nitrogen of a mass number 14 with 7 protons and 7 neutrons.  [speed of light = 3.0 × 108ms-1, 1μ = 1.67 × 10-27kg]", "images": [], "options": {"A": "1.710 × 108 J", "B": "3.131 × 10-8 J", "C": "1.476 × 10-8 J", "D": "2.332 × 10-9 J"}, "answer": "A", "explanation": "Since 1μ = 1.67 × 10-27kg (for protons)  1.0074μ = 1.0074 × 1.67 × 10-27kg  ⇒ 1.682358 × 10-27    For 7 protons,  7 × 1.682358 × 10-27  ⇒ 1.1776506 × 10-26    For neutrons,  since neutrons = 1.0089μ  mass = 1.0089 × 1.67 × 10-27  ⇒ 1.684863 × 10-27  For 7, = 1.684863 × 10-27 × 7 = 1.1794041 × 10-26  Adding the protons and neutrons mass, we have  1.1776506 × 10-26 + 1.1794041 × 10-26 = 2.3570547 × 10-26  E=12mv2=12×2.3570547×10-26×(3×108)2 = 1.061 × 10-9J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2005>50", "subject": "Physics", "year": "2005", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Uranium of atomic number 92 and mass number 238 emits an alpha particle from its nucleus. The new nucleus formed has respectively, atomic number and mass number.", "images": [], "options": {"A": "94 and 238", "B": "90 and 236", "C": "88 and 234", "D": "90 and 234"}, "answer": "D", "explanation": "23892U → 42He + abX  4 + a = 238  a = 238 - 4  a = 234  b + 2 = 92  b = 90 - 2  b = 90  The atomic number and mass number are 90 and 234.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>1", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "DESCRIPTION PROPERTY OF FIELDS : CONCEPT OF FIELDS", "question": "Which of the following phenomena causes capillarity of liquids in tubes of narrow bore?", "images": [], "options": {"A": "Viscosity", "B": "Surface tension", "C": "Osmosis", "D": "Brownian motion"}, "answer": "B", "explanation": "Surface tension causes the capillarity of liquids in tubes of narrow bore. Surface tension is the tension or force acting parallel to the surface of a liquid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>2", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "Which of the following physical quantities are derived?  I. Area II. Thrust III. Pressure IV. Mass", "images": [], "options": {"A": "I, II, III and IV", "B": "I, II and III only", "C": "I, II and IV only", "D": "I and III only"}, "answer": "B", "explanation": "Derived quantities are those quantities which are produced from the combination of base quantities through multiplication or division. Area is derived from length x width, Thrust is derived from mass x acceleration, and Pressure is derived from force/area. However, Mass is a fundamental or base quantity, not a derived quantity. Therefore, the correct answer is I, II and III only.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>3", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A block of volume 3 × 105m3 and density 2.5 × 103kg m-3 is suspended from a spring balance with 2/3 of its volume immersed in a liquid of density 900kg m-3. Determine the reading of the spring balance. [g = 10ms-2]", "images": [], "options": {"A": "0.18 × 1010N", "B": "0.57 × 1010N", "C": "0.75 × 1010N", "D": "0.93 × 1010N"}, "answer": "B", "explanation": "Volume of block = 3 × 105m3  Density of block = 2.5 × 103 kgm-3  Volume immersed in the liquid = 2/3 × 3 × 105 m3  Density of the liquid = 900kgm-3  Weight in the liquid = ?  Upthrust experienced in the liquid = 2/3 × 3 × 105 × 900 × 10 = 1.8 × 109  The weight of the block in air = 3 × 105 × 2.5 × 103 × 10 = 7.5 × 109  The tension, T in the spring balance = Weight of the block in liquid   T = W - U  T = (7.5 - 1.8)109N  T = 5.7 × 109 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>4", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION", "question": "A solid body will float in a liquid if its", "images": [], "options": {"A": "density is less than that of the liquid", "B": "mass is equal to that of the liquid", "C": "density is greater than that of the liquid", "D": "mass is less than that of the liquid"}, "answer": "A", "explanation": "According to Archimedes' principle, a solid body will float in a liquid if its density is less than that of the liquid. This is because the upthrust or buoyant force exerted by the liquid on the solid body is greater than the weight of the solid body, causing it to float.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>5", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "An object is said to undergo oscillatory motion when it moves", "images": [], "options": {"A": "in an erratic manner", "B": "to and fro about a fixed point", "C": "in a circular path", "D": "along a continuous path from the starting point"}, "answer": "B", "explanation": "Oscillatory motion is a type of motion in which an object moves to and fro about a fixed point. This is often seen in pendulums and springs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>6", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A moving car of mass 800kg experiences a frictional force of 200N. If it accelerates at 2ms-2, calculate the magnitude of the force applied to the car.", "images": [], "options": {"A": "600N", "B": "1000N", "C": "1600N", "D": "1800N"}, "answer": "D", "explanation": "Given:  The mass of the car = 800kg  The Frictional Force = 200N  Acceleration = 2ms-2  Force applied = F  ∴ Net Force on the car = mass × acceleration  F - 200 = 800 × 2  F - 200 = 1600  F = 1800N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>7", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A body is rotating in a horizontal circle of radius 2.5m with and angular speed of 5 rads-1. Calculate the magnitude of the radial acceleration of the body.", "images": [], "options": {"A": "62.50 ms-2", "B": "31.25 ms-2", "C": "12.50 ms-2", "D": "10.00 ms-2"}, "answer": "A", "explanation": "Given:  The radius of the circle = 2.5m  Angular speed, ω = 5 rads-1  Radial acceleration, a = a  Recall that: a = ω2r   a = (5)2 × 2.5 = 25 × 2.5 = 62.5ms-2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>8", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "Uniform speed occurs when there is equal change of", "images": [], "options": {"A": "distance in equal times", "B": "displacement in equal times", "C": "velocity in equal times", "D": "acceleration in equal times"}, "answer": "A", "explanation": "Uniform speed refers to the condition where an object covers equal distances in equal intervals of time. This is different from uniform velocity, which would require both equal speed and constant direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>9", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A car accelerates uniformly from rest at 5ms-2. Determine its speed after 10s.", "images": [], "options": {"A": "50.0ms-1", "B": "25.0 ms-1", "C": "2.0ms-1", "D": "0.5ms-1"}, "answer": "A", "explanation": "Acceleration, a = 5ms-2  Initial velocity, U = 0  Final velocity = V ; Time = t = 10s  Recall: V = u + at ; V = 0 + 5(10)  V = 50ms-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>10", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SPEED AND VELOCITY : DISTANCE/DISPLACEMENT-TIME GRAPH", "question": "The diagram above shows the speed-time graph of a car. If the car covered a total distance of 600m in 25s, calculate its maximum speed.", "images": ["Physics/imgs/2006/pix1.png"], "options": {"A": "30 ms-1", "B": "25 ms-1", "C": "20 ms-1", "D": "15 ms-1"}, "answer": "A", "explanation": "Given: The velocity-time graph  600=12×5×Vmax+15×Vmax+12×5×Vmax  600=Vmax(12×5+15+12×5)  600 = Vmax (20)  Vmax = 30ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>11", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Which of the following quantities is a vector?", "images": [], "options": {"A": "Speed", "B": "Distance", "C": "Energy", "D": "Momentum"}, "answer": "D", "explanation": "A vector quantity is one that has both magnitude (size) and direction. Of the options given, only momentum is a vector quantity. Momentum is the product of an object's mass and its velocity, and it has a direction (the same as the direction of the velocity). Speed, distance, and energy are all scalar quantities, meaning they have magnitude but no direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>12", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Determine the magnitude of P in the diagram above.", "images": ["Physics/imgs/2006/PA2EFL.png"], "options": {"A": "16N", "B": "20N", "C": "32N", "D": "40N"}, "answer": "C", "explanation": "Given: The diagram in the question   Pcos60° × 50 = 40 × 20  0.5P × 50 = 800  25P = 800  P = 32N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>13", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : ENERGY OF S.H.M", "question": "Which of the following statements about smile harmonic motion is correct? The", "images": [], "options": {"A": "total mechanical energy is always conserved", "B": "linear acceleration is directed to any variable point", "C": "linear acceleration varies inversely with displacement", "D": "period of oscillation varies linearly as acceleration due to gravity"}, "answer": "A", "explanation": "In simple harmonic motion, the total mechanical energy is always conserved. This is because the sum of kinetic and potential energy remains constant throughout the motion. The other options are incorrect. The linear acceleration is always directed towards the equilibrium position, not any variable point. The linear acceleration does not vary inversely with displacement, but is directly proportional to the displacement. The period of oscillation does not vary linearly with acceleration due to gravity, but is independent of it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>14", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A force on a body causes a change in the momentum of the body from 12 kg ms-1 to 16 kg ms-1 in 0.2 s. Calculate the magnitude of the impulse", "images": [], "options": {"A": "28.0 Ns", "B": "20.0 Ns", "C": "4.0 Ns", "D": "0.8 Ns"}, "answer": "C", "explanation": "Given: The initial momentum, P1 = 12kg ms-1  The final momentum, P2 = 16kgms-1  The time taken for the change to take place = 0.25s.  Recall that Impulse = Ft = Δ P  ∴ Impulse = ΔP = P2 - P1  Impulse = 16 - 12 = 4kgms-1 = 4Ns", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>15", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ENERGY : WORLD ENERGY RESOURCES", "question": "Which of the following sources of energy is renewable?", "images": [], "options": {"A": "Petroleum", "B": "Charcoal", "C": "Hydro", "D": "Nuclear"}, "answer": "C", "explanation": "Hydro energy is a renewable source of energy. It is derived from the movement of water and can be replenished naturally. On the other hand, petroleum, charcoal, and nuclear energy are non-renewable sources of energy. They cannot be replenished on a human timescale and their reserves are finite.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>16", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A stone of mass 2.0 kg is thrown vertically upwards with a velocity of 20 ms-1, calculate the initial kinetic energy of the stone.", "images": [], "options": {"A": "200 J", "B": "400 J", "C": "800 J", "D": "1600 J"}, "answer": "B", "explanation": "Given:  The mass of the stone = 2.0kg  Velocity of throw, u = 20.0ms-1  Totalkineticenergy=12mu2  = 1/2 × 2 × (20)2  = 400Nm or 400J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>17", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "Which of the following statements about the mouth piece of a telephone is correct? It converts sound energy into", "images": [], "options": {"A": "Acoustic Energy", "B": "Mechanical Energy", "C": "Electrical Energy", "D": "Heat Energy"}, "answer": "C", "explanation": "The mouthpiece of a telephone converts sound energy into electrical energy. This is because the sound waves produced by the speaker's voice cause a diaphragm in the mouthpiece to vibrate. These vibrations are then converted into electrical signals by a process known as transduction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>18", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "The potential energy in an elastic string of force constant k which has been extended by x metres is expressed as", "images": [], "options": {"A": "1/2 kx2", "B": "kx2", "C": "1/2 kx", "D": "kx"}, "answer": "A", "explanation": "The potential energy in an elastic string of force constant K, which has been extended by x metres = 1/2 kx2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>19", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "The engine of a train produces a force of 3000N when moving at 30ms-1. Calculate the power of the engine.", "images": [], "options": {"A": "1.00 × 102 W", "B": "3.00 × 104 W", "C": "9.00 × 104 W", "D": "3.00 × 105 W"}, "answer": "C", "explanation": "The power of an engine is calculated by the formula P = Fv, where P is power, F is force, and v is velocity. Substituting the given values, we get P = 3000N * 30ms-1 = 90000W or 9.00 × 104 W.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>20", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "MACHINES :", "question": "The velocity ratio of an inclined plane, inclined at an angle θ to the horizontal can be expressed as", "images": [], "options": {"A": "(sinθ-1)", "B": "sinθ", "C": "(cosθ)-1", "D": "cosθ"}, "answer": "A", "explanation": "The velocity ratio (VR) of an inclined plane is given by the formula VR = 1/sinθ. This is because the velocity ratio is the ratio of the distance moved by the effort to the distance moved by the load. In an inclined plane, the effort moves along the slope (hypotenuse) while the load moves vertically (opposite side). The ratio of these distances is 1/sinθ.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>21", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "MACHINES :", "question": "A block and tackle system has six pulleys. A force of 50N applied to it lifts a load of weight W. If the efficiency of the system is 40%, calculate W.", "images": [], "options": {"A": "300N", "B": "200N", "C": "140N", "D": "120N"}, "answer": "D", "explanation": "Given:  The velocity ratio, V.R = Number of pulleys = 6  The Effort, E = 50N  The Load, L = W  Efficiency = 40%  Recall:Efficiency=(LE)×1V.R  ∴40100=W50×16  410=W300  W = 120N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>22", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The sagging of overhead electrical cables is the consequence of", "images": [], "options": {"A": "linear expansivity", "B": "superficial expansivity", "C": "cubic expansivity", "D": "conductivity"}, "answer": "A", "explanation": "That is a consequence of linear expansivity. An increase in temperature of the wire will cause it to extend in length and this makes it to sag.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>23", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "The silvered surface in a vacuum flask reduces heat loss due to", "images": [], "options": {"A": "conduction", "B": "convection", "C": "radiation", "D": "evaporation"}, "answer": "C", "explanation": "The silvered surface in a vacuum flask reduces heat loss due to radiation. Radiation is the transfer of heat by electromagnetic waves. The silvered surface reflects these waves back into the flask, reducing heat loss.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>24", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "How long will it take to heat 3 kg of water from 28°C to 88°C in an electric kettle taking 6A from a 220V supply?   [Specific Heat Capacity of Water = 4180 J kg-1k-1]", "images": [], "options": {"A": "120s", "B": "570s", "C": "600s", "D": "836s"}, "answer": "B", "explanation": "The mass, m of the water = 3kg.  The heat change, Δθ = 88°c - 28°c = 60°c  The current, I = 6A  The voltage, V = 220V  The SHC of water = 4180Jkg-1k-1; The time, t = unknown  Recall that: Electrical energy = ivt  It should be noted that: Electrical Energy = Thermal Energy   6 × 220 × t = 3 × 4180 × 60  1320t = 180 × 4180  t=180×41801320  t = 180×19×220/220×6 = 30 × 19   = 570s.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>25", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION", "question": "The amount of energy required to change a kilogram of ice block into water without a change in temperature is", "images": [], "options": {"A": "heat capacity of ice", "B": "specific heat capacity", "C": "specific latent heat of vapourization of ice", "D": "specific latent heat of fusion of ice"}, "answer": "D", "explanation": "The energy required to change a kilogram of ice into water without a change in temperature is known as the specific latent heat of fusion. This is the amount of heat energy required to change 1 kg of a substance from a solid to a liquid (or vice versa) without a change in temperature. Therefore, the correct answer is 'specific latent heat of fusion of ice'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>26", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "A quantity of stem at 100°C condenses to water at the same temperature by releasing 6.9 × 104J of energy. Calculate the mass of the condensed steam. [ specific latent heat of vapourization of water = 2.3 × 106 J kg-1]", "images": [], "options": {"A": "3.0 × 10-1 kg", "B": "3.0 × 10-2 kg", "C": "3.0 × 10-3 kg", "D": "3.0 × 10-4 kg"}, "answer": "B", "explanation": "Given:  The change in temperature = 0°C (since it is from 100°C to 100°C)  The heat energy released, E = 6.9 × 104J; SLH of vaporization = 2.3 × 106Jkg-1  The mass of the condensed steam is unknown.  Recall, E = mL  6.9 × 104 = m × 2.3 × 106;  m=6.9×1042.3×106=3×10-2kg=0.03kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>27", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "The temperature of a liquid falls after some of it has evaporated because", "images": [], "options": {"A": "the liquid left is smaller in volume and the breeze easily cools it.", "B": "the more energetic molecules have escaped into the atmosphere", "C": "the liquid left has latent heat", "D": "after evaporation impurities are left behind"}, "answer": "B", "explanation": "When a liquid evaporates, it is the more energetic (hotter) molecules that have enough energy to overcome the intermolecular forces and escape into the atmosphere. This leaves behind the less energetic (cooler) molecules, resulting in a decrease in the average kinetic energy of the liquid and hence a decrease in its temperature. Therefore, the correct answer is 'the more energetic molecules have escaped into the atmosphere'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>28", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The S.I units of frequency, period and amplitude of a wave are respectively", "images": [], "options": {"A": "hertz, second and centimetre", "B": "second, metre and hertz", "C": "metre, hertz and second", "D": "hertz, second and metre"}, "answer": "D", "explanation": "The S.I units of frequency = Hertz   The S.I units of period = second  The S.I units of amplitude = metre", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>29", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A note of frequency 2000Hz has a velocity of 400ms-1, Calculate the wave length of the note.", "images": [], "options": {"A": "5.0m", "B": "2.0m", "C": "0.5m", "D": "0.2m"}, "answer": "D", "explanation": "Frequency, f = 2000Hz  Velocity, v = 400ms-1  Wavelength, λ = ?  Recall that: v = fλ  ∴ 400 = λ × 2000  λ=4002000  λ = 0.2 m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>30", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT", "question": "The eclipse of the moon occurs when the", "images": [], "options": {"A": "moon comes exactly between the earth and the sun", "B": "earth comes exactly between the moon and the sun", "C": "sun comes exactly between the earth and the moon", "D": "moon reflects all the rays from the sun onto the earth"}, "answer": "B", "explanation": "An eclipse of the moon, or a lunar eclipse, occurs when the Earth comes exactly between the moon and the sun. This causes the Earth's shadow to fall on the moon, making it appear dark from our perspective. Therefore, the correct answer is 'earth comes exactly between the moon and the sun'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>31", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT", "question": "Which of the following observations cannot be explained using the rectilinear propagation of light?", "images": [], "options": {"A": "Production of images by a pinhole camera", "B": "Production of real images of objects by lenses", "C": "Formation of an annular eclipse", "D": "Diffraction patterns of light"}, "answer": "D", "explanation": "The rectilinear propagation of light refers to the principle that light travels in straight lines. This principle explains the production of images by a pinhole camera and the production of real images of objects by lenses. However, it does not explain the formation of diffraction patterns of light. Diffraction is a wave property of light that involves the bending of light waves around obstacles or the spreading of light waves after they pass through a small opening. This phenomenon cannot be explained by the rectilinear propagation of light.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>32", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The distance between the successive crests of a wave travelling at 20 ms-1 is 25 cm. Calculate the frequency of the wave.", "images": [], "options": {"A": "0.8 Hz", "B": "5.0 Hz", "C": "50.0 Hz", "D": "80.0 Hz"}, "answer": "D", "explanation": "- The distance between two successive crest = Wavelength = 25cm = 0.25m  - The velocity, V of the wave = 20ms-1  Frequency, f is unknown   Recall, v = fλ  20 = f × 0.25  f = 80Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>33", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "A ray from a fixed object is incident on a plane mirror at an angle of 20°. If the mirror is rotated through 30°, by how many degrees would the reflect ray rotate?", "images": [], "options": {"A": "60o", "B": "50o", "C": "40o", "D": "30o"}, "answer": "B", "explanation": "The reflected ray would rotate through an angle of 20° + 30° = 50°", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>34", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following distances is usually adjustable in the camera? The distance between the", "images": [], "options": {"A": "lens and the film", "B": "diaphragm and the shutter", "C": "shutter and the film", "D": "diaphragm and the film"}, "answer": "A", "explanation": "In a camera, the distance that is usually adjustable is the distance between the lens and the film. This is because adjusting this distance allows for the focusing of the image on the film.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>35", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A travelling microscope is focussed on a mark on a table. If a glass block of thickness 18.0cm is placed on the mark, by how many centimetres will the microscope be moved upwards so as to focus the mark once again?  [refractive index of glass = 1.5]", "images": [], "options": {"A": "27cm", "B": "24cm", "C": "9cm", "D": "6cm"}, "answer": "D", "explanation": "Apparentdepth=thicknessrefractiveindex   =181.5=12cm  Upward adjustment = 18 - 12 = 6cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>36", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "In which of the following media would sound wave travel fastest?", "images": [], "options": {"A": "Wood", "B": "Water", "C": "Iron", "D": "Mercury"}, "answer": "C", "explanation": "The speed of sound in a medium is determined by the medium's elasticity and density. Sound travels faster in solids than in liquids or gases because molecules in a solid medium are closer together and can more easily transfer vibration energy. Among the given options, iron, being a solid, would allow sound waves to travel fastest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>37", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "Which of the following actions is necessary in order to tune a string to produce a note of an octave higher than its fundamental?", "images": [], "options": {"A": "Doubling the length of the string", "B": "Reducing the tension by half", "C": "Reducing the mass per unit length", "D": "Increasing the tension four times"}, "answer": "C", "explanation": "The frequency of a vibrating string is inversely proportional to its length and directly proportional to the square root of its tension. It is also inversely proportional to the square root of its mass per unit length. To produce a note of an octave higher than its fundamental, the frequency must be doubled. This can be achieved by reducing the mass per unit length of the string.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>38", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "The acceleration due to gravity may be defined as the force", "images": [], "options": {"A": "of attraction of the sun on the earth", "B": "with which the earth revolves around the sun", "C": "with which the earth attracts one-kilogram mass", "D": "of the moon on the earth"}, "answer": "C", "explanation": "The acceleration due to gravity is defined as the force with which the earth attracts a one-kilogram mass. This is a fundamental concept in physics, specifically in the study of gravity. The force of gravity is a measure of the gravitational attraction between two objects, in this case, the earth and a one-kilogram mass.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>39", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "An electron of mass m and charge e enters a uniform electric field between two metal plates P and Q separated by a distance d. P is maintained at a potential V while Q is earthed. Determine an expression for the magnitude of the acceleration of the electron through the field.", "images": [], "options": {"A": "eV/md", "B": "d/meV", "C": "md/eV", "D": "e/Vmd"}, "answer": "A", "explanation": "The force on the electron due to the electric field is given by F = eE, where E is the electric field strength. The electric field strength is given by E = V/d. Therefore, the force on the electron is F = eV/d. According to Newton's second law, F = ma, where m is the mass of the electron and a is its acceleration. Therefore, a = F/m = eV/md. Hence, the magnitude of the acceleration of the electron through the field is eV/md.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>40", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Which of the following factors does not affect the capacitance of a parallel plate capacitor?", "images": [], "options": {"A": "Area of the plates", "B": "Nature of the surface of the plates", "C": "Distance of separation between the plates", "D": "Nature of the insulating material between the plates"}, "answer": "B", "explanation": "The capacitance of a parallel plate capacitor is given by the formula C = εA/d, where ε is the permittivity of the insulating material, A is the area of one of the plates, and d is the distance between the plates. Therefore, the capacitance is affected by the area of the plates, the distance of separation between the plates, and the nature of the insulating material between the plates. The nature of the surface of the plates does not affect the capacitance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>41", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The equivalent capacitance of a 3µF capacitor and a 6µF capacitor connected in parallel is", "images": [], "options": {"A": "2.0µF", "B": "3.0µF", "C": "4.5µF", "D": "9.0µF"}, "answer": "D", "explanation": "The capacitance, C1 = 3µF  The capacitance, C2 = 6µF  Equivalent capacitance, CT = ?  CT = C1 + C2  CT = 3 + 6   = 9.0µF", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>42", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A cell of e.m.f 1.5V and internal resistance 1.0 Ω is connected to two resistors of resistances 2.0Ω and 3.0Ω in series. Calculate the current through the resistors.", "images": [], "options": {"A": "0.25A", "B": "0.30A", "C": "0.35A", "D": "0.50A"}, "answer": "A", "explanation": "Given:  The e.m.f of the cell, E = 1.5V  The internal resistance, r = 1.0Ω  The Load, R1 = 2.0Ω  The Load = R2 = 3.0Ω  The Effective Load, = R1 + R2 (Since they are in series) = 2 + 3 = 5.0Ω  Recall: E = I(R + r)  ∴ 1.5 = I(5 + 1)  1.5 = 6I  I = 0.25A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>43", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "An electric lamp rated 120W in used on a 240 Vrms, calculate the resistance of its filament.", "images": [], "options": {"A": "480Ω", "B": "360Ω", "C": "60Ω", "D": "2Ω"}, "answer": "A", "explanation": "The power rating, P = 120W  The root mean square, voltage, Vr.m.s = 240   The resistance, R of the filament is unknown  Recall:P=V2R  120=(240)2R  120R = 576 × 102  R = 480Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>44", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "Which of the following statements about a bar magnet is correct?", "images": [], "options": {"A": "Iron filings cling uniformly along the length of the bar magnet", "B": "The magnetic properties are more pronounced at the middle of a magnet", "C": "It is impossible to have the same poles at the ends of a magnet", "D": "The magnetic properties are more pronounced at points near the ends of the bar."}, "answer": "D", "explanation": "The magnetic properties of a bar magnet are more pronounced at points near the ends of the bar. These ends are called poles of the magnet. The region around the poles has the strongest magnetic effect, hence iron filings will tend to gather more at the poles than along the length of the magnet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2006>45", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "The force experienced by a current-carrying conductor moving in a magnetic field is employed in the working of the   I. moving coil ammeter II. electric bell III. electric motor  Which of the statements above are correct?", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "C", "explanation": "The force experienced by a current-carrying conductor moving in a magnetic field is employed in the working of I and III.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2006>46", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "The breaking up of an atomic nucleus into two fragments of nearly equal sizes is known as", "images": [], "options": {"A": "nuclear fusion", "B": "nuclear fission", "C": "thermonuclear reaction", "D": "natural radioactivity"}, "answer": "B", "explanation": "The breaking up of an atomic nucleus into two fragments of nearly equal sizes is known as nuclear fission. In nuclear fission, the nucleus of an atom splits into two smaller fragments. This process often produces free neutrons and photons (in the form of gamma rays), and releases a large amount of energy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>47", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "A 500kV is applied across an X-ray tube. Calculate the maximum velocity of the electrons produced.  [Me = 9.1 × 10-31kg, e = 1.6 × 10-19C]", "images": [], "options": {"A": "4.2 × 108 ms-1", "B": "1.8 × 108 ms-1", "C": "4.2 × 105 ms-1", "D": "1.8 × 105 ms-1"}, "answer": "A", "explanation": "Given:  - The voltage applied = 500kV  - The maximum velocity of electrons = Vmax  Mass of electrons = 9.1 × 10-31kg. The charge of electron = 1.6 × 10-19C.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>48", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive substance of mass 768g has a half life of 3 years. After how many years does this substance leave only 6g undecayed?", "images": [], "options": {"A": "21", "B": "18", "C": "15", "D": "12"}, "answer": "A", "explanation": "- The initial mass given =768g  - Half-life = 3 years    ∴ The decay process will take place 7 times before it decays to 6g.  ∴ It will take (7 × 3) years = 21 years.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>49", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Fusion is not usually used for generating electric power because", "images": [], "options": {"A": "no energy is released when fusion takes place", "B": "very high temperatures are required to initiate fusion reaction", "C": "the raw materials needed are not easily available", "D": "heavy nuclei are involved"}, "answer": "B", "explanation": "Fusion is not usually used for generating electric power because very high temperature are required to initiate fusion reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2006>50", "subject": "Physics", "year": "2006", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An atom 23491P emits a gamma radiation. The resultant nuclide is", "images": [], "options": {"A": "23490Th", "B": "23489Ac", "C": "23090Th", "D": "23491Pa"}, "answer": "D", "explanation": "Gamma radiation does not change the atomic number or the mass number of an atom. It only involves the emission of high energy photons from the nucleus. Therefore, the resultant nuclide after the emission of gamma radiation from 23491P would still be 23491P. However, the symbol for the element with atomic number 91 is Pa (Protactinium), not P. Therefore, option 4 is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>1", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Which of the following observations is not an effect of surface tension?", "images": [], "options": {"A": "Droplets of water dripping slowly from a tap", "B": "Mercury spilled on a clean glass plate forms small spherical droplets", "C": "An insect walking across the surface of a pond", "D": "Water flowing out more easily than engine oil from container"}, "answer": "D", "explanation": "The observation that is not an effect of surface tension is:    D) Water flowing out more easily than engine oil from a container.    Surface tension is a property of liquids that results from the cohesive forces between molecules at the liquid's surface. It tends to minimize the surface area and causes liquids to form into rounded shapes (like droplets) and resist spreading. This property explains observations A, B, and C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>2", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "Which of the physical quantities is correctly paired with its corresponding S.I. unit?", "images": [], "options": {"A": "Density [kg m3]", "B": "Power [J s-1]", "C": "Specific latent heat [J kg-1 k-1]", "D": "Pressure [N m-1]"}, "answer": "B", "explanation": "Power=EnergyTime  ∴TheS.IunitofPower=TheS.I unit of Energy The S.I unit of Time  The S.I unit of Power = J/S = JS-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>3", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A liquid of volume 2.00 m3 and density 1.00 × 103 kg m-3 is mixed with 3.00 m3 of another liquid of density 8.00 × 103 kg m3. Calculate the density of the mixture.  [Assume there is no chemical reaction]", "images": [], "options": {"A": "5.20 × 102 kg m-3", "B": "8.80 × 102 kg m-3", "C": "1.13 × 102 kg m-3", "D": "5.20 × 103 kg m-3"}, "answer": "D", "explanation": "Given: V1 = 2.00m3; V2 = 3.00m3  m1 = p1v1 = 2.00 × 1.0 × 103 = 2 × 103kg  m2 = p2v2 = 8.00 × 103 × 3.00 = 24 × 103  Thedensityofthemixture=m1 + m2v1 + v2=(24 + 2) × 1035=26 × 1035  = 5.2 × 103kgm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>4", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "Which of the following statements about solid friction are correct? It  I. is a force  II. occurs between the surfaces of two bodies in contact  III. depends on the area of contact", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "A", "explanation": "- Solid friction is a force.  - Solid friction occurs between the two surfaces in contact.  - Solid friction does not depend on the area of contact.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>5", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "A man of mass m, experiences a viscous drag, F and an upthrust, U as he descends towards the ground at a steady velocity, using a parachute. If the acceleration of free fall is g, which of the following expression is correct?", "images": [], "options": {"A": "FU = mg", "B": "U + F - mg = 0", "C": "U - F = mg", "D": "F - U - mg = 0"}, "answer": "B", "explanation": "Upthrust and viscous drag act upwards while the weight of the man acts downwards.  Therefore, total upward force = Total downward Force  ∴ U + F = W (W = mg)  U + F = mg  U + F - mg = 0", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>6", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A body moving at a constant speed accelerates when it is in", "images": [], "options": {"A": "rectilinear motion", "B": "translational motion", "C": "circular motion", "D": "vibrational motion"}, "answer": "C", "explanation": "A body moving at a constant speed can accelerate if it is in circular motion. This is because acceleration is a change in velocity, and velocity is a vector quantity, meaning it has both magnitude (speed) and direction. In circular motion, the direction of the velocity is constantly changing, even if the speed is constant, so there is acceleration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>7", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "MOTION : CONCEPT OF VELOCITY", "question": "An object of mass 2kg moves with a uniform speed of 10 ms-1 for 5s along a straight path. Determine the magnitude of its acceleration.", "images": [], "options": {"A": "0 ms-2", "B": "1 ms-2", "C": "3 ms-2", "D": "4 ms-2"}, "answer": "A", "explanation": "Given:  The mass, m of the object = 2kg  The uniform speed, v = 10ms-1  The time, t = 5s  a = 0 (since the speed is uniform).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>8", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "The term rectilinear acceleration means the rate of increase of", "images": [], "options": {"A": "velocity along a circular path in a unit time", "B": "distance along a rectangular path in a unit time", "C": "displacement along a straight-line path in a unit time", "D": "velocity along a straight path in a unit time"}, "answer": "D", "explanation": "Rectilinear acceleration means the rate of increase of velocity along a straight-line path in a unit time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>9", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A vehicle moving with a uniform speed is gradually brought to rest. Which of the following sketches describe the motion of the vehicle?", "images": ["Physics/imgs/2007/pix1.png", "Physics/imgs/2007/pix2.png", "Physics/imgs/2007/pix3.png", "Physics/imgs/2007/pix4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The sketch that best describe the motion of the vehicle is:", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>10", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION", "question": "A body moving with an initial velocity u accelerates until it attains a velocity of v within a time t. The distance, s covered by the body is given by the expression", "images": [], "options": {"A": "s=(v - 2u2)t", "B": "s=(v + 2u2)t", "C": "s=(v + u2)t", "D": "s=(2v + u2)t"}, "answer": "C", "explanation": "This is one of the equations of motion.  Distance = Average velocity × Time  s=(v + u2)t", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>11", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A body accelerates uniformly from rest at 2ms-2. Calculate the magnitude of its velocity after travelling 9m.", "images": [], "options": {"A": "4.5 ms-1", "B": "6.0 ms-1", "C": "18.0 ms-1", "D": "36.0 ms-1"}, "answer": "B", "explanation": "Initially velocity, u = 0 (since it's from rest)  Final velocity, v = V  Distance travelled, s = 9m  Acceleration, a = 2 ms-2  Recall: v2 = u2 + 2as  v2 = 02 + 2(2)(9)  v2 = 36  v = &radic;36&nbsp;   = 6ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>12", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above illustrates three forces acting on an object at point O. If the object is in equilibrium, determine the magnitude of the force P.", "images": ["Physics/imgs/2007/pix5.png"], "options": {"A": "10.5 N", "B": "11.0 N", "C": "17.3 N", "D": "20.0 N"}, "answer": "D", "explanation": "∴ 10 = P sin 30°  ∴ P = 20.0N    The magnitude of the force P is 20N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>13", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A swinging pendulum between the rest position and its maximum displacement possesses", "images": [], "options": {"A": "kinetic energy only", "B": "potential energy only", "C": "gravitational energy only", "D": "both kinetic and potential energy"}, "answer": "D", "explanation": "The question is about the concept of energy in simple harmonic motion. A swinging pendulum possesses both kinetic and potential energy. At the maximum displacement, the pendulum has maximum potential energy and minimum kinetic energy. At the rest position, the pendulum has maximum kinetic energy and minimum potential energy. Therefore, the correct option is 'both kinetic and potential energy'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>14", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "A block of mass 4.0kg causes a spiral spring to extend by 0.16m from its unstretched position. The block is removed and another body of mass 0.50 kg is hung from the same spiral spring. If the spring is then stretched and released, what is the angular frequency of the subsequent motion?   [g = 10 ms-2]", "images": [], "options": {"A": "10&radic;5&nbsp; rad s-1", "B": "5&radic;2&nbsp; rad s-1", "C": "5 rad s-1", "D": "&radic;5&nbsp; rad s-1"}, "answer": "A", "explanation": "* The mass of the block, m = 4.00kg = 40N  * The extension, e = 0.16m  * Recall that: F = Ke ; K=Fe=400.16=250Nm-1  Also recall: (1)F=1T(Frequencyisthereciprocaloftime)  T=2π&radic;m&nbsp;K  ∴F=K2π&radic;m&nbsp;=2502π&radic;0.5&nbsp; = 10&radic;5&nbsp; rad s-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>15", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "An external force of magnitude 100 N  acts on a particle of mass 0.15kg for 0.03s. Calculate the change in the speed of the particle.", "images": [], "options": {"A": "50 ms-1", "B": "25 ms-1", "C": "20 ms-1", "D": "5 ms-1"}, "answer": "C", "explanation": "Given:  Force, F = 100N, mass, m = 0.15kg, Time, t = 0.03s; change in speed, Δv = ?  Recall:   F=mΔt  Ftm=ΔV;  ΔV=100×0.030.15=30.15=20ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>16", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "A car of mass 800 kg moves from rest on a horizontal track and travels 60 m in 20s with uniform acceleration. Assuming there were no frictional forces, calculate the accelerating force.", "images": [], "options": {"A": "240.00 N", "B": "800.00 N", "C": "1600.00 N", "D": "2400.00 N"}, "answer": "A", "explanation": "Given:  Mass, m = 800kg, Initial velocity, u = 0ms-1 (from rest); Velocity, V = 60m/20s = 3ms-1  Force, F = ?   Recall that; F=m(v - u)t=ma  Also recall, S = ut + 1/2 at2  ∴ 60 = 0(20) + 1/2 × a × (20)2  60=12×a×400  60 = 200a  a = 0.3ms-2  From, F = ma; F = 0.3 × 800   = 240N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>17", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A plane inclined at 30° to the horizontal has an efficiency of 50%. Calculate the force parallel to the plane required to push a load of 120N uniformly up the plane.", "images": [], "options": {"A": "50.0 N", "B": "120.0 N", "C": "200.0 N", "D": "240.0 N"}, "answer": "B", "explanation": "Given: Angle, θ = 30°, Efficiency, E = 50%, Load, L = 120N; Effort, E = ?  Efficiency=Mechanical AdvantageVelocity Ratio×1001  50100=120E×sin30°  12=60E  E = 120N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>18", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "Mechanical energy can be either", "images": [], "options": {"A": "kinetic or electric", "B": "chemical or potential", "C": "potential or kinetic", "D": "electric or heat"}, "answer": "C", "explanation": "Mechanical energy is the sum of kinetic and potential energy in an object that is used to do work. Kinetic energy is the energy of motion and potential energy is the energy stored in an object due to its position or state. Therefore, the correct answer is 'potential or kinetic'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>19", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The ice and steam points on a mercury-in-glass thermometer are 10 cm and 30 cm respectively. Calculate the temperature in degree celsius when the mercury meniscus is at the 14 cm mark.", "images": [], "options": {"A": "20°C", "B": "30°C", "C": "34°C", "D": "70°C"}, "answer": "A", "explanation": "Given:  The ice point = 10cm  The steam point = 30cm  The temperature when the meniscus is at the 14cm mark is unknown  ∴x - 0100 - 0=14 - 1030 - 10  ∴x 100=420  x5=4;  x = 20°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>20", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following surfaces will radiate heat energy best?", "images": [], "options": {"A": "Red surface", "B": "White surface", "C": "Black surface", "D": "Yellow surface"}, "answer": "C", "explanation": "Black surfaces are the best emitters of heat radiation. This is because black surfaces absorb all wavelengths of light and convert them into heat, so they are also the best at emitting heat. Therefore, the correct answer is 'Black surface'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>21", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "Which of the following statements distinguishes thermal conduction from convection?  I. Conduction requires a material medium while convection does not  II. In convection, there is actual motion of hot material while in conduction, molecules vibrate faster about their mean positions.  III. Conduction takes place in solids while convection takes place in fluids.", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "B", "explanation": "In convection, there is actual motion of hot material while in conduction, molecules vibrate faster about their mean positions. Conduction takes place in solids while convection takes place in fluids.  ∴ II and III are correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>22", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A cube made of a metal of linear expansivity α is heated through a temperature θ. If the initial volume of the cube is Vo, the correct expression for the increase in volume of the cube is", "images": [], "options": {"A": "1/3 α Voθ", "B": "1/2 α Voθ", "C": "2 α Voθ", "D": "3 α Voθ"}, "answer": "D", "explanation": "Recall: Cubic expansivity = 3 × Linear expansivity  ∴ Cubic expansivity = 3α  Cubicexpansivity=Change in volumeOriginal volume×Change in temperature  ∴3α=Change in volumeV0 × Δθ  ∴ change in volume = 3α VoΔθ", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>23", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A relative density bottle of volume 50 cm3 is completely filled with a liquid at 30o. It is then heated to 80°C such that 0.75 cm3 of the liquid is expelled. Calculate the apparent cube expansivity of the liquid.", "images": [], "options": {"A": "0.00030 k-1", "B": "0.00032 k-1", "C": "0.01970 k-1", "D": "0.02030 k-1"}, "answer": "A", "explanation": "Given:  Volume of bottle = 50cm3  Initial temperature = 30°C  Final temperature = 80°C  Volume of the liquid expelled = 0.75cm2  γa=Volume expelledVolume left × temperature rise  =0.7549.25 × 50 = 0.00030k-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>24", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "A body of mass 200g and specific heat capacity 0.4 Jg-1 k-1 cools from 37oC to 31oC. Calculate the quantity of heat released by the body.", "images": [], "options": {"A": "4800J", "B": "1200J", "C": "480J", "D": "202J"}, "answer": "C", "explanation": "Given:  Mass of the body, m = 200g  Specific Heat Capacity, SHC = 0.4jg-1k-1  Temperature rise = 37°c - 31°c = 6*degc  Quantity of heat, Q = mcΔθ  Q = 200 × 0.4 × 6   = 480J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>25", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "At standard atmospheric pressure, a solution of common salt is heated gradually until most of it boils away. Which of the following diagrams correctly illustrates the temperature (θ) versus time (t) graph for this process?", "images": ["Physics/imgs/2007/pix6.png", "Physics/imgs/2007/pix7.png", "Physics/imgs/2007/pix8.png", "Physics/imgs/2007/pix9.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "The graph illustrated in the answer above best describes the information given.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>26", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "According to the kinetic theory of gases, which of the following properties of a gas can be can be affected by the collision of the gas molecules with the walls of its container?", "images": [], "options": {"A": "Temperature", "B": "Energy", "C": "Viscosity", "D": "Pressure"}, "answer": "D", "explanation": "Pressure is the effective force of collision with which the molecules of a gas collide with a unit area of the wall of the container.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>27", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure of fixed mass of an ideal gas at 27oC is 3Pa. The gas is heated at a constant volume until its pressure is 5Pa. Determine the new temperature of the gas.", "images": [], "options": {"A": "100°C", "B": "227°C", "C": "273°C", "D": "500°C"}, "answer": "B", "explanation": "Given:  P1 = 3Pa; T1 = 27°c = 300k; P2 = 5Pa; T2 = ?  V1 = V2  P1T1=P2T2  ∴3300=5T2  3T2 = 1500  T2 = 500K = 227°c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>28", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following waves is electromagnetic?", "images": [], "options": {"A": "X-rays", "B": "Sound waves", "C": "Water waves", "D": "Tidal waves"}, "answer": "A", "explanation": "X-rays are a type of electromagnetic wave. Electromagnetic waves are waves that can travel through the vacuum of outer space. Mechanical waves, such as sound waves and water waves, require a medium in order to travel. The electromagnetic spectrum is a continuum of all electromagnetic waves arranged according to frequency and wavelength.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>29", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The distance between two points P and Q, along a wave is 0.05m. If the wavelength of the wave is 0.10m. Determine the angle between P and Q in radians.", "images": [], "options": {"A": "0.1π", "B": "π", "C": "2π", "D": "10π"}, "answer": "B", "explanation": "Given: Distance, x = 0.05m  Wavelength λ = 0.10m  Phase angle, ∅ = ?  Recall:  ∅=2πλx  ∅=2π0.10×0.05   ∅=0.05×2π0.10   ∅=510×2π   ∅ = π", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>30", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT", "question": "Which of the following phenomena is not a direct consequence of rectilinear propagation of light?", "images": [], "options": {"A": "Lunar and solar eclipses", "B": "Images of object in a pinhole camera", "C": "Diffraction of light", "D": "Shadows of opaque objects"}, "answer": "C", "explanation": "Rectilinear propagation of light is the principle that light travels in straight lines. This principle explains phenomena such as shadows and the operation of pinhole cameras. However, diffraction, which is the bending of light around the corners of an obstacle or aperture, is not a direct consequence of rectilinear propagation. Instead, it is a result of the wave nature of light.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>31", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "An objects is placed 10cm in front of a plane mirror. If it is moved 8cm farther away from the mirror, determine the distance of the final image from the mirror.", "images": [], "options": {"A": "2 cm", "B": "9 cm", "C": "16 cm", "D": "18 cm"}, "answer": "D", "explanation": "In a plane mirror, the magnification is unity, i.e = 1. Since the magnification = 1, object distance, u = Image distance, V  ∴ u = v  u1 = v1 and u2 = v2  When: u1 = 10cm; v1 = 10cm  u2 = 10cm + 8cm  Also, V2 = 10cm + 8cm   = 18cm", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>32", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "In which of the following pieces of apparatus is the radius of curvature equal to twice the focal length?", "images": [], "options": {"A": "Dicolt lens", "B": "Diverging lens", "C": "Converging lens", "D": "Parabolic mirror"}, "answer": "C", "explanation": "In a converging lens (also known as a convex lens), the radius of curvature is indeed twice the focal length. This is because the focal length is the distance from the lens to the point where light rays parallel to the axis converge, while the radius of curvature is the distance from the lens to the center of the sphere from which the lens is cut. In a converging lens, these two distances are the same, hence the radius of curvature is twice the focal length.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>33", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "When an object is placed at the centre of curvature of a concave mirror, its image is formed at?", "images": [], "options": {"A": "the focus", "B": "infinity", "C": "the centre of curvature", "D": "a distance twice the radius of curvature"}, "answer": "C", "explanation": "When an object is placed at the centre of curvature of a concave mirror, its image is formed at the centre of curvature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>34", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A rectangular glass prism of thickness d and absolute refractive index n is placed on a point object, which is viewed vertically downward from above the prism. Which of the following expressions correctly defines the apparent upward displacement of the object?", "images": [], "options": {"A": "d/n", "B": "dn", "C": "d/n-2", "D": "d(n - 1)n"}, "answer": "A", "explanation": "Recallthat:Refractiveindex=Real depthApparent depth  Therefore, n=dApparent depth  Apparentdepth=dn", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>35", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "Which of the following factors can affect the speed of sound in air?  I. The temperature of the surrounding  II. The direction of wind  III. The pitch of the sound", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "A", "explanation": "The factors that affect the speed of sound in air include:  - Temperature  - Wind direction  - Relative humidity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>36", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "SOUND WAVES : RESONANCE", "question": "A sounding tuning fork is brought near the open end of a pipe containing air and the loudness of the sound is observed to increase. This observation is due to", "images": [], "options": {"A": "an echo", "B": "resonance", "C": "interference", "D": "reverberation"}, "answer": "B", "explanation": "The increase in the loudness of the sound when a sounding tuning fork is brought near the open end of a pipe is due to resonance. Resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration and hence an increase in loudness. Therefore, the correct answer is 'resonance'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>37", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "Which of the following statements about sound waves is not correct? Sound waves can be", "images": [], "options": {"A": "reflected", "B": "refracted", "C": "diffracted", "D": "polarized"}, "answer": "D", "explanation": "Sound waves are mechanical waves and cannot be polarized. Polarization is a property of transverse waves, such as light waves, not longitudinal waves like sound. Therefore, the statement that sound waves can be polarized is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>38", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : FORCED VIBRATION AND RESONANCE", "question": "Which of the following statements is correct about resonance? Resonance occurs when a body", "images": [], "options": {"A": "vibrates with its natural frequency", "B": "is forced to vibrate at its own natural frequency by another body vibrating at the same frequency", "C": "vibrates at the frequency of the body causing the vibration", "D": "vibrates with an irregular frequency"}, "answer": "B", "explanation": "Resonance occurs when a body is forced to vibrate at its own natural frequency by another body vibrating at the same frequency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>39", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "A dry plastic comb used in combing hair was found to attract pieces of paper and dust. The most probable explanation for this phenomenon is that the comb has been given.", "images": [], "options": {"A": "magnetization by induction", "B": "electric charges by induction", "C": "electric charges by conduction", "D": "electric charges by friction"}, "answer": "D", "explanation": "When a dry plastic comb is used to comb hair, it can become charged due to friction. This is known as triboelectric effect or charging by friction. The comb then attracts pieces of paper and dust due to electrostatic attraction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2007>40", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTRIC FIELD : STORAGE OF CHARGES", "question": "Which of the following components is used for storing electric charges?", "images": [], "options": {"A": "Inductor", "B": "Resistor", "C": "Capacitor", "D": "Electrometer"}, "answer": "C", "explanation": "A capacitor is used for storing electric charges. It is a passive electronic component with two terminals. The effect of a capacitor is known as capacitance. While some capacitance exists between any two electrical conductors in proximity in a circuit, a capacitor is a component designed to add capacitance to a circuit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>41", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "DESCRIPTION PROPERTY OF FIELDS : PROPERTIES OF A FORCE FIELD", "question": "Which of the following operations does not represent an action of a force field?", "images": [], "options": {"A": "Falling of a mango fruit from the tree", "B": "Picking of nails using a bar magnet", "C": "Repulsion of two like charges", "D": "Pushing of a wheel-barrow on a level ground"}, "answer": "D", "explanation": "Falling of a mango fruit from the tree represent the action of gravitational force field.  Picking of nails using a bar magnet & Repulsion of two like charges represent the action of the magnetic force field.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>42", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Calculate the effective resistance between P and Q in the diagram shown above.", "images": ["Physics/imgs/2007/sscephysics2017q42.png"], "options": {"A": "0.75Ω", "B": "4.00Ω", "C": "5.00Ω", "D": "7.00Ω"}, "answer": "B", "explanation": "Given: The diagram  The 2 Ω resistors are parallel to one another. Therefore,theireffectiveresistance=2×22+2=44=1Ω    Then the diagram becomes:    Now, the 3Ω resistors is in series with the 1Ω resistor. Therefore, the effective resistance = 3 + 1 = 4Ω    N.B:  (1) If resistors are in parallel, the effective resistance is equal to the reciprocal of the sum of the reciprocals of the resistance.  (2) If resistors are in serial arrangement, the effective resistance is equal to the sum of the resistance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>43", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A bulb marked 240V, 40W is used for 30 minutes. Calculate the heat generated", "images": [], "options": {"A": "320J", "B": "400J", "C": "10800J", "D": "72000J"}, "answer": "D", "explanation": "Given:  Voltage, V = 240v  Power, P = 40W  Time, T = 30minutes = 1800seconds (60 seconds = 1 minute)  Heat energy generated = ?  Recall that: Electrical energy = Power × Time  It should be noted that in this case, Electrical energy = Heat energy   ∴ Heat energy = Power × Time = 40 × 1800   = 72000J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>44", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Five 80 - W and three 100 - W lamps are run for 8 hours. If the cost of energy is N5.00 per unit, calculate the cost of running the lamps.", "images": [], "options": {"A": "N280.00", "B": "N28.00", "C": "N7.20", "D": "N1.44"}, "answer": "B", "explanation": "For five 80W  = 80 x 5 = 400  Three 100W = 100 x 3  Total power = 700  for 8 hours = 700 x 8  = 5600  ConvertingtoKW=5600100  = 5.6KW  Amount = 5 x 5.6,   = 28.00", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>45", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following electromagnetic wave can be detected by its heating effect?", "images": [], "options": {"A": "Ultraviolet radiation", "B": "X-rays", "C": "Gamma rays", "D": "Infrared radiation"}, "answer": "D", "explanation": "Infrared radiation is known for its heating effect. It is the type of electromagnetic radiation that is most associated with heat, as it is emitted by hot objects and can be absorbed by objects, causing them to heat up. This is why it is used in heat lamps and thermal imaging cameras.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>46", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "If a gas is excited by high voltage to produce a discharge, and the light is examined in a spectrometer", "images": [], "options": {"A": "an explosion is observed", "B": "the rainbow colours are seen", "C": "an emission spectrum is observed", "D": "dark lines are observed"}, "answer": "C", "explanation": "When a gas is excited by high voltage, it emits light at specific wavelengths, which correspond to the energy differences between the energy levels of the atoms in the gas. When this light is examined in a spectrometer, an emission spectrum is observed. This spectrum consists of bright lines at the wavelengths of the emitted light, against a dark background. This is different from an absorption spectrum, where dark lines are seen against a continuous spectrum, which would be observed if white light were passed through a cool gas.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>47", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The number of protons in an element increased by one after a radioactive decay. The element must have decayed by emitting", "images": [], "options": {"A": "a beta particle", "B": "an alpha particle", "C": "a gamma ray", "D": "a neutron"}, "answer": "A", "explanation": "The number of proton increased by one. Since atomic number = number of proton,   We can then say that the atomic number increased by 1.  abX → ab + 1P + o-1e   ∴ The atom has been decayed by Beta particle emitting a beta particle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>48", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "The correct sequence of energy transformations in the operation of an X-ray tube is   I. X-rays   II. Kinetic energy of thermo electrons   III. Potential energy of the target atoms  IV. Heat energy of the emitted electrons", "images": [], "options": {"A": "IV, III, II, I", "B": "IV, II, III, I", "C": "II, IV, III, I", "D": "III, IV, II, I"}, "answer": "B", "explanation": "In the operation of X-ray tube, energy is transmitted in this order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2007>49", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "In a nuclear reactor, chain reactions result from the release of", "images": [], "options": {"A": "electrons", "B": "photons", "C": "neutrons", "D": "protons"}, "answer": "C", "explanation": "In a nuclear reactor, chain reactions result from the release of neutrons. When a neutron strikes the nucleus of a fissile atom, the nucleus splits, releasing energy and additional neutrons. These newly released neutrons can then cause further fissions, leading to a chain reaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2007>50", "subject": "Physics", "year": "2007", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "There is always an uncertainty involved in any attempt to measure the position and momentum of an electron simultaneously. This statement is known as the", "images": [], "options": {"A": "De Broglie's law", "B": "Heisenberg uncertainty principle", "C": "Franck-Hertz experimental law", "D": "Wave-particle paradox"}, "answer": "B", "explanation": "The statement is known as the Heisenberg uncertainty principle. This principle states that it is impossible to simultaneously measure the exact position and momentum of a particle. In other words, the more precisely one property is measured, the less precisely the other can be controlled, determined, or known.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>1", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "If the air inside a rigid box is heated, the   I. average speed of the molecules increases  II. pressure of the air increases  III. average separation of the molecules increases.    Which of the statements above are correct?", "images": [], "options": {"A": "I and II only", "B": "III only", "C": "II and III only", "D": "I, II and III"}, "answer": "A", "explanation": "If the air is heated, the average speed of the molecules increase and the pressure of the air will also increase.  N.B: When a gas is heated, the number of collisions of the molecules of the gas usually increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>2", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "Which of the following sets of quantities is fundamental?", "images": [], "options": {"A": "Length, mass and time", "B": "Speed, length and time", "C": "Speed, mass and distance", "D": "Distance, speed and time"}, "answer": "A", "explanation": "The fundamental quantities in physics are length, mass and time. These are the basic units from which other units are derived. Speed, distance and pressure are derived quantities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>3", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "The diagram above illustrates a Hare's apparatus, e1, e2 represent densities and h1, h2 heights of column of liquids. Which of the following equations is correct?", "images": ["Physics/imgs/2008/XKPRPM.png"], "options": {"A": "h1=h2e1e2", "B": "h1=h2e2e1", "C": "h1=e1e2h2", "D": "h1=e1h2e2"}, "answer": "B", "explanation": "It should be noted that the pressure on both sides are equal;  i.e P1 = P2  Recall:   P = ρgh  ∴ P1 = P2 becomes ρ1gh1 = ρ2gh2  ∴ ρ1h1 = ρ2h2  h1=ρ2h2h1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>4", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION", "question": "Which of the statements about Archimedes' principle is correct? The upthrust on a body is a measure of the", "images": [], "options": {"A": "mass of fluid displaced", "B": "weight of the body", "C": "volume of the body", "D": "weight of the fluid displaced"}, "answer": "D", "explanation": "Archimede's principle holds that when an object is partially or totally immersed in a fluid, it experiences a loss of weight (upthrust) which is equal to the weight of the fluid displaced.  ∴ Upthrust is a measure of the weight of the fluid displaced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>5", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following is/are in random motion?   I. Pollen grains in water  II. The molecules of hydrogen gas  III. Fine chalk particles floating in air", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "Random motion refers to the unpredictable, erratic movement of particles. Pollen grains in water, molecules of hydrogen gas, and fine chalk particles floating in air all exhibit random motion due to the constant, random collisions they undergo with other particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>6", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A car travelling with a uniform velocity of 30ms-1 along a horizontal road overcomes a constant frictional force of 600N. Calculate the power of the engine of the car.", "images": [], "options": {"A": "18kW", "B": "20kW", "C": "180kW", "D": "200kW"}, "answer": "A", "explanation": "Given: The uniform velocity of the car = 30ms-1  The frictional force, FR = 600N  Recall: Power = Force × Velocity  ∴ P = 600 × 30 = 18000W = 18KW.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>7", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A rectangular block of dimensions 2.0m × 1.0m × 0.5m weighs 200N. Calculate the maximum pressure exerted by the block on a horizontal floor.", "images": [], "options": {"A": "100Nm-2", "B": "200Nm-2", "C": "300Nm-2", "D": "400Nm-2"}, "answer": "A", "explanation": "Given: The dimension of the block = 2.0m × 1.0m × 0.5m  The weight, W of the block = 200N  The maximum pressure, Pmax = ?  Recall that: Pressure,P=ForceArea  The maximum pressure will be exerted when the block is occupying its maximum area on the floor.  The maximum area of the block = 2 × 1 = 2m2  ∴Pmax=2002=100Nm-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>8", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "The diagram above represents the displacement-time graph of the motion of an object thrown upwards. The velocity of the object at the point P is", "images": ["Physics/imgs/2008/ssce2008physicsq8.png"], "options": {"A": "maximum", "B": "uniform", "C": "zero", "D": "terminal"}, "answer": "C", "explanation": "At point P, the object has reached its maximum height where the velocity is equal to zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>9", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "A very sensitive spring balance was used to determine the weight of an object at the north pole. When the same spring balance was used to measure the weight of the same object at the equator, it was found to reduce. The explanation for this observation is that", "images": [], "options": {"A": "it is very hot at the equator", "B": "the spring balance has expanded", "C": "the acceleration of free fall due to gravity varies with location", "D": "the mass of the body is reduced"}, "answer": "C", "explanation": "It should be noted that Weight, W = mass, m × acceleration due to gravity, g  ∴ W = mg  'g' varies from place to place. (it is usually greater at the pole than at the equator).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>10", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "SCALARS AND VECTORS : RESULTANT VELOCITY", "question": "A ship moving northward with speed Vs is acted upon by a wind blowing the due west at a speed Vw. Which of the following diagrams correctly indicates the velocity VR of the wind relative to the ship?", "images": ["Physics/imgs/2008/pix3.png", "Physics/imgs/2008/pix4.png", "Physics/imgs/2008/pix5.png", "Physics/imgs/2008/pix6.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "Given: The northward speed, Vc  The speed of the wind, Vw  The resultant speed = VR", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>11", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above shows three forces F1, F2 and F3 which keep the bar AB in horizontal equilibrium. Which of the following equations is correct?", "images": ["Physics/imgs/2008/pix3s.png"], "options": {"A": "F3 = F1 + F2", "B": "F2 = F1 + F3", "C": "F1 = F2 - **F3", "D": "F1 = F2 + F3"}, "answer": "D", "explanation": "Given: The diagram in the question    It should be noted that if a body is in equilibrium under the action of parallel forces, the total upward force = total downward force.  Therefore, F3 + F2 = F1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>12", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A mass attached to a string is moving in a circular path. If the speed is doubled, the tension in the string will be", "images": [], "options": {"A": "doubled", "B": "halved", "C": "four times as great", "D": "one-fourth as much"}, "answer": "C", "explanation": "Given: Initial speed = V1  Final speed = V2 = 2V1  Initial tension = T1  Final tension = T2 = ?  It should be noted that: V α &radic;T&nbsp;  ∴ V = K&radic;T&nbsp;   V&radic;T&nbsp;=K  V1&radic;T1&nbsp;=V2&radic;T2&nbsp;  V1&radic;T1&nbsp;=2V1&radic;T2&nbsp;:1&radic;T1&nbsp;  =2&radic;T2&nbsp;:&radic;T2T1&nbsp;=21  T2T1=(2)2  T2T1=41  T2 = 4T1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>13", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "An object of mass 2kg moving with a velocity of 3ms-1 collides head-on with another object of mass 1kg moving in the opposite direction with a velocity 4ms-1. If the objects stick together after collision, calculate their common speed.", "images": [], "options": {"A": "0.60ms-1", "B": "0.67ms-1", "C": "2.00ms-1", "D": "3.33ms-1"}, "answer": "B", "explanation": "Given: m1 = 2kg ; m2 = 1kg  v1 = 3ms-1 ; v2 = 4ms-1  Common velocity, V is unknown  Recall: m1v1 + m2v2 = (m1 + m2)V  V=m1v1+m2v2m1+m2(Iftheyaremovinginthesamedirectionalbeforecollision)  Also, m1v1 - m2v2 = (m1 + m2)v  v=m1v1 - m2v2m1 + m2  v=6 - 43=23=0.67ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>14", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Which of the following devices converts heat energy to electrical energy?", "images": [], "options": {"A": "Transformer", "B": "Dynamo", "C": "Thermocouple", "D": "Thermostat"}, "answer": "C", "explanation": "A thermocouple is a device that converts heat energy into electrical energy by exploiting the Seebeck effect, where a voltage is produced by a temperature difference between two different metals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>15", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A ball is dropped and it hits the floor at a point A. It rebounds upwards to a point B. While moving from A to B its", "images": [], "options": {"A": "kinetic energy is increasing", "B": "potential energy is increasing", "C": "potential energy is decreasing", "D": "kinetic energy  remains constant"}, "answer": "B", "explanation": "The information can be represented diagrammatically as:    From A to B the height is decreasing such that h4 = 0.  ∴ Potential energy at B (h4 = 0) = mg(0) = 0.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>16", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "An object of mass 0.25kg moves at a height h above the ground with a speed of 4ms-1. If its mechanical energy at this height is 12 J, determine the value of h. [g = 10ms-1]", "images": [], "options": {"A": "0.8m", "B": "4.0m", "C": "4.8m", "D": "5.6m"}, "answer": "B", "explanation": "Given: Mass of object, m = 0.25kg  Height, h above the ground = h  Speed, v = 4ms-1.  The mechanical energy, M.E at h = 12J  → It should be noted that M.E = P.E + K.E  ∴12=mgh+12  mv2  12=m(gh+v22)  12=0.25(10h+162)  12 = 0.25(10h + 8)  12 = 2.5h + 2  10 = 2.5h  h = 4m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>17", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following equations for the efficiency of a machine is correct?", "images": [], "options": {"A": "Efficiency=Velocity RatioMechanical Advantage×100%", "B": "Efficiency=InputOutput×100%", "C": "Efficiency=Load distanceEffort distance×100%", "D": "Efficiency=Mechanical AdvantageVelocity Ratio×100%"}, "answer": "D", "explanation": "The efficiency of a machine is given by the ratio of the Mechanical Advantage to the Velocity Ratio, multiplied by 100%. The Mechanical Advantage is the ratio of the output force (load) to the input force (effort), and the Velocity Ratio is the ratio of the distance moved by the effort to the distance moved by the load. Therefore, the correct equation for the efficiency of a machine is Efficiency = (Mechanical Advantage / Velocity Ratio) * 100%, which matches option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>18", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The design of the thermostat of an electric iron is based on the", "images": [], "options": {"A": "emission of electrons from metals when heated", "B": "increase in size of metals when heated", "C": "increase in the density of metals when heated", "D": "change in the mass of metals when heated"}, "answer": "B", "explanation": "The design of the thermostat is based on the increase in size of metals when heated.    Such that: T2 > T1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>19", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A metal rod of length 50cm is heated from 40°C to 80°C. If the linear expansivity of the material is α, calculate the increase in length of the rod (in metres) in terms of α.", "images": [], "options": {"A": "20 α", "B": "200 α", "C": "2000 α", "D": "20000 α"}, "answer": "A", "explanation": "Given:  The initial length, L1 = 50cm = 0.5m  The initial temperature, θ1 = 40°c  The final temperature, θ2 = 80°c  The linear expansivity = α  The increase in length, ΔL = ?  Recall:α=ΔLL1(Δθ)  Also recall:α=ΔL0.5(40)  α=ΔL2000  ∴ ΔL = 20α", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>20", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The cubic expansivity of a certain gas at a constant pressure is 1/273 K-1.  If a given mass of the gas is held at constant pressure and its volume at 0oC is 273m3, determine the volume of the gas at 273°C.", "images": [], "options": {"A": "273m3", "B": "546m3", "C": "819m3", "D": "1092m3"}, "answer": "B", "explanation": "Given: The cubic expansivity, γ of the gas = 1/273 k-1  The pressure, P is constant; i.e P1 = P2  Volume, V1 = 273m3 at 0°c = 273k  Volume, V2 = ? at 273°c = 546k  The two notable parameters are: volume and temperature  Recall:V1T1=V2T2  273273=V2546  ∴ V2 = 546cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>21", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "Water mass 1.5kg is heated from 30°C to 80°C using an electric kettle which is rated 5A, 230V. Calculate the time taken to reach the final temperature.  [Specific heat capacity of water = 4200 Jkg-1K-1]", "images": [], "options": {"A": "4.57 minutes", "B": "5.02 minutes", "C": "7.30 minutes", "D": "10.04 minutes"}, "answer": "A", "explanation": "Given: The mass, m of water = 1.5kg  The temperature change = 80°c - 30°c = 50°c  Electric current, I = 5A  Voltage, V = 230V  SHC of water = 4200Jkg-1k-1  It should be noted that: The electrical energy released by the heater = The heat energy absorbed by water.  ∴ Ivt = mcΔθ  5 × 230 × t = 1.5 × 4200 × 50  1150t = 315,000  t=3150001150=630023≈274seconds=4.57minutes", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>22", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "The working principle of a pressure cooker is based on the", "images": [], "options": {"A": "increase in the volume of steam inside it", "B": "complete trapping of heat inside it", "C": "increase in the pressure of the pot", "D": "decrease in the pressure of the pot"}, "answer": "C", "explanation": "A pressure cooker works by increasing the pressure inside the pot. This increase in pressure raises the boiling point of the water inside the cooker, allowing the food to cook at a higher temperature and therefore cook faster. This matches option 3.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>23", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "It takes a shorter time for a liquid to boil at the top of a mountain than at the base because at the top, the", "images": [], "options": {"A": "temperature is higher", "B": "pressure is lower", "C": "humidity is higher", "D": "temperature is constant"}, "answer": "B", "explanation": "It should be noted that, the higher the height, the lower the atmosphere pressure and the lower the boiling point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>24", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Light is considered as a transverse wave because it travels", "images": [], "options": {"A": "through materials without causing disturbance of the medium", "B": "through space with constant speed", "C": "in a direction parallel to the plane containing the electric and magnetic fields", "D": "in a direction perpendicular to the plane containing the electric and magnetic fields."}, "answer": "D", "explanation": "Transverse wave possess particles which travel perpendicular to that of the energy propagated by the wave. It should be noted that the energy propagated by the wave is electromagnetic in nature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>25", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "Thediagramaboveillustratesthesun,moonandearthinthesamestraightlineduringaneclipse. An observer at the point P on earth observes.", "images": ["Physics/imgs/2008/ssce2008physicsq25.png"], "options": {"A": "annular eclipse", "B": "partial eclipse", "C": "total eclipse", "D": "no eclipse"}, "answer": "A", "explanation": "Annular eclipse is formed when the distance between the sun and the moon is such that the umbra cone of the moon's shadow ends above the surface of the earth. This occurs when the angular diameter of the sun as observed from the earth is greater than that of the moon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>26", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "The letter F is placed in front of a plane mirror as illustrated in the diagram beside.    Which of the following represents the image observed?", "images": ["Physics/imgs/2008/pix9.png", "Physics/imgs/2008/pix10.png", "Physics/imgs/2008/pix11.png", "Physics/imgs/2008/pix12.png", "Physics/imgs/2008/pix13.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The process (phenomenon) illustrated is  Lateral Inversion .", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>27", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "In the day time, it is possible to see under shady areas such as under a tree, because light has undergone", "images": [], "options": {"A": "internal reflection", "B": "refraction", "C": "diffraction", "D": "diffuse reflection"}, "answer": "D", "explanation": "During the day, we can see under shady areas such as under a tree because light has undergone diffuse reflection. Diffuse reflection is the reflection of light in many directions by a rough surface. The leaves and branches of the tree scatter the light in many directions, allowing us to see under the tree.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>28", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The distance between a concave mirror and a object placed in front of it is 1.0m. If the radius of curvature of the mirror is 4.0m, the image formed will be", "images": [], "options": {"A": "2.00m behind the mirror", "B": "2.00m in front of the mirror", "C": "1.25m in front of the mirror", "D": "1.25m behind the mirror"}, "answer": "A", "explanation": "Recall:   1v=1f-1u  v = image distance, u = object distance; f = focal length  f=(Radius)2  f=r2  Given: v = ? u = 1.0m   f=42=2m  1v=12-11  1v=-12  v = -2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>29", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The image of an object formed by a convex mirror is", "images": [], "options": {"A": "real, erect and enlarged", "B": "real, inverted and enlarged", "C": "virtual, erect and diminished", "D": "virtual, erect and enlarged"}, "answer": "C", "explanation": "The image formed by a convex mirror is usually virtual i.e it is formed at the back of the mirror. The image formed by a convex mirror is erect, i.e it stands upright upon forming. The image formed by a convex mirror is also diminished, i.e it is usually smaller than the object.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>30", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "When viewed straight down, a fish in a pond is", "images": [], "options": {"A": "farther below than it appears to be", "B": "nearer than it appears to be", "C": "found at exactly the same point it is seen", "D": "seen beside its large"}, "answer": "A", "explanation": "Due to refraction, a fish in a pond appears to be closer to the surface than it actually is. This is because light rays from the fish bend away from the normal as they move from a denser medium (water) to a less dense medium (air), causing the fish to appear to be at a shallower depth. So, the fish is actually farther below but it appears to be closer to the surface.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>31", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens and a screen are placed 20cm and 80cm respectively from an object in a straight line so that a sharp image of the object is formed on the screen. If the object is 3cm high, calculate the height of the image formed.", "images": [], "options": {"A": "1cm", "B": "9cm", "C": "12cm", "D": "15cm"}, "answer": "B", "explanation": "Recall:vu=HiHo  u = object distance, v = image distance, Hi = image height, Ho = object height  ∴6020=Hi3  31=Hi3  ∴ Hi = 9cm.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>32", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following defects of vision is as a result of the eye ball being too long?", "images": [], "options": {"A": "Long sight", "B": "Astigmatism", "C": "Short sight", "D": "Loss of accommodation"}, "answer": "C", "explanation": "The short sightedness is as a result of the eye ball being too long such that rays from distant objects are brought to a focus in front of the retina instead of at the retina", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>33", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "A sound wave is produced from a source and an echo is heard t seconds afterwards. If d is the distance of the reflecting surface from the source, v the speed, λ the wavelength and T the period of the wave, then", "images": [], "options": {"A": "d=2tλ", "B": "d=λt2T", "C": "d=2Tλt", "D": "d=λTt"}, "answer": "B", "explanation": "When a sound is produced, the sound heard by the source immediately after the sound is produced is the echo.    ∴V=2dt  Recall; V = fλ  ∴fλ=2dt  fλt = 2d  d=fλt2  Also,F=1T  ∴d=fλt2becomes  d=λt2T", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>34", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "A negatively charged rod is held close to an uncharged metal ball on an insulating stand. The ball will", "images": [], "options": {"A": "be negatively charged", "B": "be positively charged", "C": "have an excess of negative charges on the side nearest the rod", "D": "have an excess of positive charges on the side nearest the rod"}, "answer": "D", "explanation": "When a negatively charged rod is held close to an uncharged metal ball on an insulating stand, the ball will have an excess of positive charges on the side nearest the rod.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>35", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "Two bodies each carrying a charge of 2.00 × 10-10 C are 5cm apart. Calculate the magnitude of the force between the charges.  [1/4πεo  =  9 × 10⁹Nm²/C²]", "images": [], "options": {"A": "1.44 × 10-7 N", "B": "7.20 × 10-9 N", "C": "7.20 × 10-11 N", "D": "1.44 × 10-11 N"}, "answer": "D", "explanation": "Given: - charge, q1 = q2 = 2 × 10-10C  - the distance between the two charges = 5cm =0.05m  - the magnitude of force, F is unknown.    Recall:F=Kq1q2d2(coloumb'slaw)  ∴F=k(2×10-10×2×10-10)(0.05)2=k(4×10-20)0.0025   = k × 0.16 × 10-16    = 9 × 109 × 0.16 × 10-16    = 1.44 × 10-7N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>36", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "If the charge on an object is measured as 4.0 × 10-10 C, how many excess electrons does the object possess, given that the charge of an electron is 1.6 × 10-19C?", "images": [], "options": {"A": "18", "B": "19", "C": "25", "D": "37"}, "answer": "C", "explanation": "Given: (1) The charge on the object = 4.0 × 10-18c  (2) The charge of an electron = 1.6 × 10-19c  Recall:Excesselectron=Charge on the object Charge of electron  ∴Excesselectron=4.0×10-181.6×10-9   = 2.5 × 10 = 25", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>37", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Which of the following is a unit of the time rate of flow of electric charges?", "images": [], "options": {"A": "Coulomb", "B": "Ampere", "C": "Volt", "D": "Watt"}, "answer": "B", "explanation": "- The time rate of flow of electric charges = Current  That is, ChargeTime=Current  ∴CoulombSecond=Ampere  Coulomb is the S.I unit of charge, second is the S.I unit of time and Ampere is the S.I unit of current.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>38", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire, 1.0m long and with cross-sectional area 2.0 × 10-7 m2 has a resistance of 0.1Ω. Calculate the electrical conductivity of the wire.", "images": [], "options": {"A": "2.0 × 107 Ω-1m-1", "B": "5.0 × 107Ω-1m-1", "C": "2.0 × 108Ω-1m-1", "D": "5.0 × 108Ω-1m-1"}, "answer": "B", "explanation": "Given:  (1) The length of the wire, l = 1.0m  (2) Area of cross-section, A = 2 × 10-7m2  (3) Resistance, R = 0.1Ω  (4) Electrical conductivity is unknown.  Recall: R = ρ/A : P is the electrical resistivity.  It should be noted that;   Theelectricalconductivity=1ρ  ∴0.1=ρ×1.02×10-7  Electricalconductivity=12×10-8=12×108Ω-1m-1  = 0.5 × 108 Ω-1m-1   = 5 × 107Ω-1m-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>39", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Three capacitors each of capacitance 1.5µF are connected in series. The total capacitance in the circuit is", "images": [], "options": {"A": "2.0µF", "B": "1.5µF", "C": "0.6µF", "D": "0.5µF"}, "answer": "D", "explanation": "Given: (1) The value of the capacitance of each capacitor = 1.5µF  Recall: if capacitance of capacitors are arranged in series, the total resistance, CT is given as: 1CT=1C1+1C2+1C3......+1Cn  ∴1CT=11.5+11.5+11.5  1CT=31.5  CT=1.53=12=0.5µF", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>40", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT", "question": "A voltmeter is a device that", "images": [], "options": {"A": "draws high current", "B": "has a very low resistance", "C": "has a very high resistance", "D": "is able to measure both voltage and current"}, "answer": "C", "explanation": "A voltmeter is a device that is used to measure the voltage difference between two points in an electrical circuit. It has a very high resistance so that it does not draw current from the circuit and alter the voltage it is measuring. Therefore, the correct answer is 'has a very high resistance'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2008>41", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "Which of the following actions will not increase the sensitivity of a moving coil galvanometer?", "images": [], "options": {"A": "Using a strong temporary magnet", "B": "Increasing the area and number of turns of the coil", "C": "Using a weak hair spring", "D": "Using a light pointer"}, "answer": "A", "explanation": "The sensitivity of a moving coil galvanometer can be increased by increasing the area and number of turns of the coil, using a weak hair spring, and using a light pointer. However, using a strong temporary magnet will not increase the sensitivity. Moving coil galvanometer uses a permanent magnet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>42", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "Fleming's right hand rule is also called the", "images": [], "options": {"A": "motor rule", "B": "dynamo rule", "C": "screw rule", "D": "thumb rule"}, "answer": "B", "explanation": "Fleming's right hand rule is also called the dynamo rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>43", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "A transformer is required to supply 12Vrms to operate a toy train set from a 240Vrms. If the number of turns in the secondary coil is 100, calculate the number of turns required in the primary coil.", "images": [], "options": {"A": "5", "B": "12", "C": "2000", "D": "2400"}, "answer": "A", "explanation": "Given: Primary voltage = 12  Secondary voltage = 240  Number of turns in the secondary coil = 100  Number of turns in the primary coil = ?  Recall:EsEp=NsNp  ∴24012=100x  201=100x  x = 5", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>44", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "The diagram above illustrates a bar magnet near a coil connected to a galvanometer. When the magnet is rapidly moved towards the coil  I. an e.m.f is induced in the coil.  II. the galvanometer needle deflects.  III. the magnet is attracted.    Which of the statements above are correct?", "images": ["Physics/imgs/2008/NGJ2MA.png"], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "A", "explanation": "When the magnet is moved towards the galvanometer, an e.m.f is usually induced in the coil and this causes the pointer to deflect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>45", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "A direct current of 5A flows through a 0.2H inductor, Calculate the energy stored in the inductor.", "images": [], "options": {"A": "0.5J", "B": "1.0J", "C": "2.5J", "D": "5.0J"}, "answer": "D", "explanation": "Given: (1) Inductance, L = 0.2H  (2) Current, I = 5A  (3) Power, P = ?  (4) Energy = ?  Recall: P = I2L  P = 52 × 0.2 = 5W  ∴ Energy = 5J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2008>46", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Both γ rays and X-rays  I. can be produced by thermionic emission  II. have low frequencies  III, have short wavelengths    Which of the statements above is/are correct?", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I and III only"}, "answer": "C", "explanation": "γ rays and X-rays are both forms of electromagnetic radiation. They are not produced by thermionic emission (statement I is incorrect) and they do not have low frequencies (statement II is incorrect). They do, however, have short wavelengths (statement III is correct). Therefore, the correct answer is III only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>47", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "When a radioactive substance undergoes a beta decay, its", "images": [], "options": {"A": "mass number decreases by 1", "B": "atomic number decreases by 1", "C": "mass number increases by 1", "D": "atomic number increases by 1"}, "answer": "D", "explanation": "abX → ab+1P + 0-1e (Beta particle)  The atomic number of the resulting atom will increase by one.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>48", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Nuclear fission is preferred to nuclear fusion in the generation of energy because", "images": [], "options": {"A": "very high temperatures are required for fusion", "B": "the raw materials for fusion are easily obtained", "C": "energy obtained from fusion is relatively smaller", "D": "the by-products of fusion are very dangerous"}, "answer": "A", "explanation": "Nuclear fusion requires very high temperatures (in the order of millions of degrees) to overcome the electrostatic repulsion between the positively charged nuclei that are to be fused together. This makes it technically challenging to achieve and control, which is why nuclear fission is currently preferred for energy generation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>49", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Control in nuclear reactors is effected with boron rods because the rods have the ability to", "images": [], "options": {"A": "absorb electrons", "B": "absorb neutrons", "C": "accelerate electrons", "D": "slow down neutrons"}, "answer": "B", "explanation": "Control rods in nuclear reactors are used to absorb neutrons, which slows down the nuclear chain reaction. Boron is one of the materials commonly used for this purpose because it has a high cross-section for neutron absorption, meaning it is very likely to absorb neutrons when they pass through it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2008>50", "subject": "Physics", "year": "2008", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive element has a decay constant of 0.077s-1. Calculate its half-life.", "images": [], "options": {"A": "13.0s", "B": "9.0s", "C": "5.1s", "D": "0.5s"}, "answer": "B", "explanation": "Given: (1) The decay constant, λ = 0.077s-1  (2) The half-life, t1/2 = ?  Recall;t1/2=0.693λ  t1/2=0.6930.077=9s", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>1", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "In which of the following states of matter do the molecules vibrate about their mean positions?", "images": [], "options": {"A": "Liquids only", "B": "Solids only", "C": "Liquids and gases only", "D": "Solids, Liquids and gases"}, "answer": "B", "explanation": "The molecules of solids are less energetic and they therefore vibrate about their fixed positions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>2", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "DERIVED QUANTITIES AND DIMENSIONAL ANALYSIS :", "question": "Which of the following properties of a steel bar can be measured in terms of the dimension of length only?", "images": [], "options": {"A": "Weight", "B": "Density", "C": "Pressure", "D": "Volume"}, "answer": "D", "explanation": "Volume is measured in (a unit of length)3. Therefore, the properly of steel bar that can be measured only in terms of the dimension of length is volume.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>3", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "In a hydraulic press, a force of 40N is applied to the smaller piston of area 10cm2. If the area of the larger piston is 200cm2, calculate the force obtained.", "images": [], "options": {"A": "800N", "B": "500N", "C": "80N", "D": "50N"}, "answer": "A", "explanation": "Given: Force on smaller piston, F1 = 40N  Area of smaller piston, A1 = 10cm2  Force on larger piston, F2 = ?  Area of larger piston, A2 = 200cm2  Recall: F1A1=F2A2  ∴4010=F2200  F2 = 800N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>4", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A body of volume 0.046m3 is immersed in a liquid of density 980kgm-3 with 3/4 of its volume submerged. Calculate the upthrust on the body.  [g = 10 ms-2]", "images": [], "options": {"A": "11.27N", "B": "33.81N", "C": "112.70N", "D": "338.10N"}, "answer": "D", "explanation": "Given: (1) The volume of the body = 0.046m3  (2) The density of the liquid = 980kgm-3  (3)Volumesubmerged(immersed)=34(0.046)  (4) Upthrust = ?  Recall: Upthrust, u = Volume submerged × Density of liquid × acceleration due to gravity  ∴ u = vdg  u = 0.0345 × 980 × 10  u = 33.81 × 10  u = 338.1 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>5", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Which of the following types of motion will be produced when a pair of equal and opposite non-collinear parallel forces acts on a body", "images": [], "options": {"A": "Vibrational motion", "B": "Random motion", "C": "Translational motion", "D": "Rotational motion"}, "answer": "D", "explanation": "- This system of equal and opposite non-colinear parallel forces is a system of couple.  - It should be noted that couple causes the rotational motion of the system, since there is a net moment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>6", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A body moving in a circle at a constant speed has   I. a velocity tangential of the circle  II. a constant kinetic energy  III. an acceleration directed towards the circumference of the circle    Which of the statements above are correct?", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "A", "explanation": "III. an acceleration directed towards the circumference of the circle is not correct  Therefore, I and II is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>7", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "A car moves with a speed of 30ms-1. Calculate the distance travelled in 30s.", "images": [], "options": {"A": "30m", "B": "60m", "C": "450m", "D": "900m"}, "answer": "D", "explanation": "Given: (1) the constant speed of the car (v = u) = 30ms-1  (2) the distance travelled in 30s is unknown  Recall: S=(v + u2)t  ∴s=(30+302)30  s = 30 × 30 = 900m.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>8", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "A moving body accelerates when it", "images": [], "options": {"A": "changes its direction at constant speed", "B": "maintains a constant linear speed", "C": "covers equal distances in equal times in a straight line", "D": "is acted upon by balanced forces"}, "answer": "A", "explanation": "Acceleration is a change in velocity per unit time. Velocity is a vector quantity, meaning it has both magnitude (speed) and direction. Therefore, a body can accelerate by changing its speed, its direction, or both. In the case of a body moving in a circle at a constant speed, it is constantly changing its direction, hence it is accelerating even though its speed remains constant. Therefore, a moving body accelerates when it changes its direction at constant speed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>9", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "The following properties of a solid are measured on earth:  I. weight  II. specific heat capacity  III. density  Which of the properties will have a different value if measured in space?", "images": [], "options": {"A": "I", "B": "II", "C": "III", "D": "II and III only"}, "answer": "A", "explanation": "Weight is the force exerted by the gravitational pull of the earth on an object. In space, where there is no gravity, the weight of an object would be different. However, specific heat capacity and density are intrinsic properties of a material and do not change with location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>10", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "SCALARS AND VECTORS : VECTOR REPRESENTATION", "question": "Which of the vector diagram below represents the following position vectors?", "images": ["Physics/imgs/2009/ssce2009physicsq10.png", "Physics/imgs/2009/pix1.png", "Physics/imgs/2009/pix2.png", "Physics/imgs/2009/pix3.png", "Physics/imgs/2009/pix4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "the vector diagram that best represent the position vectors is:", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>11", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Two forces 6N and 8N, act eastwards and northwards respectively on a body. Calculate the magnitude of their equilibrant.", "images": [], "options": {"A": "2N", "B": "7N", "C": "10N", "D": "14N"}, "answer": "C", "explanation": "Given: Two forces: (1) 6N acting eastwards.  (2) 8N acting northwards.    It should be noted that the magnitude of their equilibrant is equal to that of the resultant, R  R2 = 82 + 62  R = &radic;64 + 36&nbsp; = &radic;100&nbsp; = 10N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>12", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The period of a simple pendulum of length 80.0cm was found to have doubled when the length of the pendulum was increased by X. Calculate X.", "images": [], "options": {"A": "26.7cm", "B": "40.0cm", "C": "160.0cm", "D": "240.0cm"}, "answer": "D", "explanation": "Given: (1) The length, l, of the pendulum = 80.00cm  (2) Length, l2 = L1 + X  (3) Initial period = T1  (4) Final period = 2T1 (doubled)  Recall: T α &radic;L&nbsp;  ∴T1&radic;L1&nbsp;=T2&radic;L2&nbsp;  ∴T1&radic;80&nbsp;=2T1&radic;L2&nbsp;  1&radic;80&nbsp;=2&radic;L2&nbsp;  &radic;L280&nbsp;=21  ∴x80=41  x = 320cm  Since L2 = L1 + x  ∴ 320 = 80 + x  x = 240cm.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>13", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mas 5kg moving with a velocity of 30ms-1 due east is suddenly hit by another body and changes its velocity to 50ms-1 in the same direction. Calculate the magnitude of the impulse received.", "images": [], "options": {"A": "100Ns", "B": "150Ns", "C": "250Ns", "D": "400Ns"}, "answer": "A", "explanation": "Given: The mass, m of the body = 5kg  The velocity v of the body = 30ms-1  The final velocity, v2 of the body = 50ms-1  Recall: Impulse = (mass)(change in velocity)  I = 5(50 - 30)  I = 5(20) = 100kgms-1 or 100Ns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>14", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Electrical energy is measured in", "images": [], "options": {"A": "ampere", "B": "coulomb", "C": "kilowatt - hour", "D": "kilowatt"}, "answer": "C", "explanation": "Electrical energy is measured in kilowatt-hours. A kilowatt-hour is a unit of energy equivalent to one kilowatt (1 kW) of power expended for one hour of time. The kilowatt-hour is not a standard unit in any formal system, but it is commonly used in electrical applications.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>15", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A stone of mass 0.5kg is dropped from a height of 12m. Calculate its maximum kinetic energy.  [g = 10ms-1]", "images": [], "options": {"A": "3.0J", "B": "6.0J", "C": "30.0J", "D": "60.0J"}, "answer": "D", "explanation": "Given: (1) The mass of the stone = 0.5kg  (2) Height, h of fall = 12m  g = 10ms-2  Recall, P.E = mgh   The maximum kinetic energy = Potential energy at maximum height   ∴ K.Emax = mgh = 0.5 × 12 × 10 = 60J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>16", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MACHINES :", "question": "A machine of efficiency 80% is used to lift a box. If the effort applied by the machine is twice the weight of the box, calculate the velocity ratio of the machine.", "images": [], "options": {"A": "0.50", "B": "0.63", "C": "0.80", "D": "1.60"}, "answer": "B", "explanation": "Given: (1) The efficiency, of the machine = 80%  (2) The effort, E = 2 × the weight of the load(box)  (3) The velocity ratio is unknown  Recall:Efficiency=Mechanical AdvantageVelocity Ratio  ∴Efficiency=(L2L)÷VR  80100=12×1VR  0.8=0.5VR  0.8VR = 0.5  VR=58=0.625≈0.63", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>17", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A faulty thermometer registers 102.5°C at 100oC. If the thermometer has no zero error, what will it register at 55°C?", "images": [], "options": {"A": "54.6°C", "B": "55.0°C", "C": "56.0°C", "D": "56.4°C"}, "answer": "D", "explanation": "x - 0102.5 - 0=55 - 0100 - 0  x102.5=55100  100x = 55 × 102.5   x=102.5 × 1120  x = 56.575°C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>18", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A rod of initial length 2m at a temperature of 25°C is heated to 80 ° C, Calculate the increase in length of the rod if its linear expansivity is 4.0 × 10-3K-1", "images": [], "options": {"A": "0.26m", "B": "0.44m", "C": "0.53m", "D": "0.84m"}, "answer": "B", "explanation": "Given: Initial length, L1 = 2m  Initial temperature, θ1 = 25°c  Final temperature, θ2 = 80°c  Linear expansivity, α = 4 × 10-3k-1  Change in length, ΔL = ?  Recall: α=ΔL1Δθ  ∴4×10-3=Δ2(55)  ΔL = 440 × 10-3 = 4.4 × 10-1m   = 0.44m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>19", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "As a bicycle tyre was being pumped up, it was noticed that contrary to Boyle's law the volume increased as the pressure increased. The best explanation of this is that Boyle's law is only true for.", "images": [], "options": {"A": "ideal gases", "B": "a fixed mass of gases", "C": "a mixture of gases", "D": "a gas at variable temperature"}, "answer": "A", "explanation": "Boyle's law states that the pressure and volume of a gas have an inverse relationship when temperature is held constant. However, this law is only applicable to ideal gases, which are hypothetical gases that perfectly follow gas laws. Real gases do not follow Boyle's law exactly because of interactions between the gas molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>20", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "It takes 4 minutes to boil a quantity of water using an electrical heating coil. How long will it take to boil the same quantity of water using the same heating coil if the current is doubled?  [Neglect any external heat losses]", "images": [], "options": {"A": "8minutes", "B": "4minutes", "C": "2minutes", "D": "1minutes"}, "answer": "C", "explanation": "H1 = H2 * H is the electrical energy supplied   I1Vt1 = I2Vt2 * I is the current, V is the voltage and t is the time  I1t1 = I2t2  I2 = 2I1  Recall: H = IVt  ∴ I1t1 = 2I1t2  t1 = 2t2  ∴ 4 = 2t2  t2 = 2 minutes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>21", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : MELTING POINT", "question": "When table salt is added to ice, the melting point of the ice", "images": [], "options": {"A": "is raised", "B": "is lowered", "C": "remains unchanged", "D": "is first raised, then lowered"}, "answer": "B", "explanation": "When salt is added to ice, the melting point of the ice is usually lowered. It should be noted that impurities lower the melting point of a hither to pure solid substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>22", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following factors affect the rate of evaporation of a liquid?  I. Exposed surface area  II. Temperature of the surroundings  III. Thermal capacity of the liquid  IV. Relative humidity of the surrounding", "images": [], "options": {"A": "II and III only", "B": "II, III and IV only", "C": "I, III and IV only", "D": "I, II and IV only"}, "answer": "D", "explanation": "The rate of evaporation of a liquid is affected by the exposed surface area (the larger the surface area, the faster the evaporation), the temperature of the surroundings (the higher the temperature, the faster the evaporation), and the relative humidity of the surrounding (the lower the humidity, the faster the evaporation). The thermal capacity of the liquid does not directly affect the rate of evaporation, so option III is not correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>23", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT", "question": "Which of the following instruments is used to measure relative humidity?", "images": [], "options": {"A": "Hydrometer", "B": "Barometer", "C": "Hypsometer", "D": "Hygrometer"}, "answer": "D", "explanation": "A hygrometer is used to measure relative humidity. Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. A hygrometer measures this by comparing the temperatures of two thermometers, one of which has a wet bulb and the other a dry bulb.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>24", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : AMPLITUDE, FREQUENCY, PERIOD AND WAVELENGTH", "question": "The maximum displacement of a vibrating tuning fork is its", "images": [], "options": {"A": "amplitude", "B": "frequency", "C": "period", "D": "wavelength"}, "answer": "A", "explanation": "Amplitude is the maximum displacement of a wave from its equilibrium position. The sound wave produced by the turning fork will have its maximum displacement called 'amplitude'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>25", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "A boat is rocked by waves of speed 30ms-1 whose successive crests are 10 m apart. Calculate the rate at which the boat receives the waves.", "images": [], "options": {"A": "30s-1", "B": "10s-1", "C": "3s-1", "D": "1s-1"}, "answer": "C", "explanation": "Given: (1) The speed , v of the boat = 30ms-1  (2) The distance between the successive crest = wavelength = 10m  (3) The frequency, f = ?  Recall: V = fλ  ∴ 30 = f × 10   f = 3Hz or 3s-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>26", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "Which of the following waves is not transverse?", "images": [], "options": {"A": "Light waves", "B": "Sound waves", "C": "Sea waves", "D": "Radio waves"}, "answer": "B", "explanation": "Sound waves are not transverse waves. Transverse waves are waves in which the displacement of the medium is perpendicular to the direction of propagation of the wave. Sound waves are longitudinal waves, where the displacement of the medium is parallel to the direction of propagation of the wave.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>27", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "PROPERTIES OF WAVES : DIFFRACTION", "question": "Light travelling through a small pinhole usually does not make a shadow with a distinct sharp edge because of", "images": [], "options": {"A": "diffraction", "B": "interference", "C": "reflection", "D": "refraction"}, "answer": "A", "explanation": "Light travelling through a small pinhole does not make a shadow with a distinct sharp edge because of diffraction. Diffraction is a phenomenon that occurs when a wave encounters an obstacle or a slit. It is described as the bending of waves around the corners of an obstacle or aperture into the region of geometrical shadow of the obstacle. In this case, the pinhole acts as the obstacle, causing the light to bend and thus not forming a sharp shadow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>28", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT PLANE SURFACES", "question": "The angle of incidence of a ray of light on a plane mirror is 55°. Determine the angle between the reflected ray and the mirror.", "images": [], "options": {"A": "35°", "B": "45°", "C": "55°", "D": "110°"}, "answer": "A", "explanation": "Angle of incidence = angle of reflection.  So, angle between reflected ray and the mirror is 90⁰- 55⁰= 35⁰", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>29", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A concave mirror forms a magnified and erect image only when the object is placed", "images": [], "options": {"A": "at the centre of curvature", "B": "at the focus", "C": "between the focus and the pole of the mirror", "D": "beyond the radius of curvature"}, "answer": "C", "explanation": "A concave mirror forms a magnified and erect image only when the object is placed between the principal focus and the pole of the mirror.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>30", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A thin lens is placed 50cm from an illuminated object. The image produced has linear magnification of 1/4. Calculate the power of the lens in dioptres.", "images": [], "options": {"A": "2.5D", "B": "5.0D", "C": "10.0D", "D": "25.0D"}, "answer": "C", "explanation": "Given: u = 50cm  m=14  Recall:m=vu  ∴14=v50  4v = 50   v = 12.5cm  Also recall:   1v+1u=1f  112.5+150=1f  50 + 12.5625=1f  f=62562.5=10cm  P=100f=10010=10.0D", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>31", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Which of the following characteristics of light determines its colour?", "images": [], "options": {"A": "Velocity", "B": "Wavelength", "C": "Amplitude", "D": "Intensity"}, "answer": "B", "explanation": "The color of light is determined by its wavelength. Different colors of light have different wavelengths. For example, red light has a longer wavelength than blue light. This is why when light passes through a prism, it is split into its component colors in a process called dispersion. The colors are arranged according to their wavelengths, with red having the longest wavelength and violet having the shortest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>32", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following is not a part of electromagnetic spectrum?", "images": [], "options": {"A": "X-rays", "B": "Microwaves", "C": "Infrared radiation", "D": "Alpha rays"}, "answer": "D", "explanation": "Alpha rays is not a part of the electromagnetic spectrum. In the electromagnetic spectrum we have: radio waves, micro waves, infrared radiation, visible light, ultra-violet rays, gamma rays.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>33", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "PROPERTIES OF WAVES : INTERFERENCE", "question": "Sound interference is necessary to produce the phenomenon of", "images": [], "options": {"A": "beats", "B": "doppler effect", "C": "acoustic resonance", "D": "echo"}, "answer": "A", "explanation": "Sound interference is necessary to produce the phenomenon of beats. Beats are the periodic and repeating fluctuations heard in the intensity of a sound when two sound waves of very similar frequencies interfere with each other. The interference of two waves causes the total amplitude observed to be the sum of the amplitudes of the individual waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>34", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "A satellite in circular motion around the earth does not have", "images": [], "options": {"A": "a gravitational forces acting on it", "B": "a uniform velocity", "C": "an acceleration", "D": "a centripetal force acting on it"}, "answer": "B", "explanation": "The satellite is undergoing circular motion; hence, it has an acceleration (centripetal). A body that accelerates will not have a uniform velocity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>35", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "When a conductor mounted on an insulating stand is charged and left for sometime, the conductor eventually loses all its charges. This is because the", "images": [], "options": {"A": "electric charges evaporate from the surface of the conductor", "B": "charges are conducted to earth", "C": "charges on the conductor are neutralized by opposite charges from the surrounding air", "D": "charges ionize the surrounding air"}, "answer": "C", "explanation": "The observation is as a result of the fact that: charges on the conductor are neutralized by opposite charges from the surrounding air.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>36", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "Use the information below to answer this question  An isolated metal sphere of radius R, carrying an electric charge, Q is situated in a medium of relative permittivity, εr. A test chare is placed at a point P, distance r from the surface of the sphere. Let εo represent the permittivity of free space.    The electric potential at P is given by the expression", "images": [], "options": {"A": "Q4πεoεrr", "B": "Q4πεoεr(R + r)", "C": "Q4πεoεr(R - r)", "D": "Q4πεoεrR"}, "answer": "D", "explanation": "Theelectricpotential=Q4πεR  ε = εoεr  ∴=Q4πεoεrR", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>37", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "Use the information below to answer this question  An isolated metal sphere of radius R, carrying an electric charge, Q is situated in a medium of relative permittivity, εr. A test chare is placed at a point P, distance r from the surface of the sphere. Let εo represent the permittivity of free space.  The magnitude of the electric field intensity at P is given by the expression", "images": [], "options": {"A": "Q4πεoεrr2", "B": "Q4πεoεr(R + r)2", "C": "Q4πεoεr(R - r)2", "D": "Q4πεoεrR2"}, "answer": "D", "explanation": "Electricfieldintensity=Electric field forcecharge  Electric field force=KQ2R2  whereK=14πεoεr  ∴F=Q24πεoεrR2  Intensity=Q24πεoεrR2×1Q  =Q4πεoεrR2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>38", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A resistor of resistance R is connected to a battery of negligible internal resistance. If a similar resistor is connected in series with it, the", "images": [], "options": {"A": "effective resistance of the circuit is halved", "B": "total power dissipated is doubled", "C": "total current in the circuit is halved", "D": "terminal voltage halfed"}, "answer": "B", "explanation": "Given: R1 = R1 (Initial resistance)  P1 = P1 (Initial power  I1 = I1 (Current)  R1 = 2R1 (Final resistance)  P2 = ?  Since: P = I2R  P1 = I12R1;  P2 = I22 × 2R1 = 2I2R1  ∴ P2 = 2P1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>39", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A cell of e.m.f 1.5V is connected in series with a resistor of resistance 3.0A voltmeter connected across the cell registers 0.9V. Calculate the internal resistance of the cell.", "images": [], "options": {"A": "2.0Ω", "B": "3.0Ω", "C": "5.0Ω", "D": "6.0Ω"}, "answer": "A", "explanation": "Given: e.m.f, E = 1.5V  Internal resistance, r = ?  Total resistance (load) = 3.0Ω  Voltage, V = 0.9v    Recall: V = IR and E = Ir + V  ∴ 1.5 = Ir + 0.9 ......(i)  Since, V = IR then,  0.9 = I × 3  I = 0.3  (1) becomes: 1.5 = (0.3)r + 0.9  0.6 = 0.3r;    r = 2Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>40", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire of resistivity 4.40 × 10-5Ω cm has a cross sectional area of 7.50 × 10-4cm2. Calculate the length of this wire that will be required to make a 4.0Ω resistor", "images": [], "options": {"A": "82.50cm", "B": "68.18cm", "C": "15.90cm", "D": "11.94cm"}, "answer": "B", "explanation": "Given: (1) Resistivity, ρ = 4.40 × 10-5Ωcm  (2) Area of cross-section, A = 7.50 × 10-4cm2  (3) Length, L = ?  (4) Resistance of the resistor = 4Ω  Recall:R=ρlA  4=4.40 × 10-5 × L7.50 × 10-4  30 × 10-4 = 4.40 × 10-5L  L=3×10-34.4×10-5  L = 0.6816 × 10-3 - -5  L = 68.18 × 10-2 × 10-3 + 5  L = 68.18 × 10-2 × 102  L = 68.18cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>41", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A battery of e.m.f. 12.0V and internal resistance 0.5Ω is connected to 1.5Ω and 4.0Ω series resistor. Calculate the terminal voltage of the battery.", "images": [], "options": {"A": "13.0V", "B": "11.0V", "C": "3.0V", "D": "1.0V"}, "answer": "B", "explanation": "Given: E.m.f, E = 12.0V  Internal resistance, r = 0.5Ω  External resistance (load) = 1.5 + 4.0 = 5.5Ω  Terminal voltage, V = ?  Recall that: E = IR + Ir and V = IR  ∴VR=ER + r  V5.5=125.5 + 0.5  V5.5=126  ∴V5.5=21  V = 11V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>42", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "If the direction of the current in a straight wire is reversed, the magnetic field", "images": [], "options": {"A": "remains the same", "B": "becomes the parallel to the wire", "C": "ceases to exist", "D": "is oppositely directed"}, "answer": "D", "explanation": "If the direction of the current in a straight wire is received, the magnetic field is oppositely directed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>43", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "An ideal step-down transformer steps up", "images": [], "options": {"A": "power", "B": "energy", "C": "current", "D": "voltage"}, "answer": "C", "explanation": "A step-down transformer reduces the voltage from the primary to the secondary coil, but it increases the current. This is because the power (which is the product of voltage and current) must remain constant, as per the law of conservation of energy. Therefore, an ideal step-down transformer steps up the current.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>44", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "An inductor of inductance 1.0H is connected in series with a capacitor of capacitance 2.0μF in an a.c circuit. Calculate the value of frequency that will make the circuit to resonate.", "images": [], "options": {"A": "112.5Hz", "B": "225.0Hz", "C": "353.5Hz", "D": "707.21Hz"}, "answer": "A", "explanation": "Given: Inductance, L = 1.0H  Capacitance, C = 2.0μF  Resonance frequency, fo = ?  Recall:fo=12π&radic;LC&nbsp;  ∴fo=12 × 3.142&radic;1 × 2 × 10-6&nbsp;  ∴Fo=16.282 × &radic;2&nbsp; × 10-3  Fo=18.9×103=10008.9=112.5Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>45", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES", "question": "An ammeter connected to an a.c circuit records 5.5A. The peak current in the circuit is", "images": [], "options": {"A": "7.8A", "B": "7.1A", "C": "3.9A", "D": "3.5A"}, "answer": "A", "explanation": "Given:   (1) Peak current, Io = ?  (2) Root mean square current, Ir.m.s = 5.5A  Recall: Io = Ir.m.s × &radic;2&nbsp;  Io = 5.5 × &radic;2&nbsp; = 7.8A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>46", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "The table below shows the energy distribution for various levels of an atom. Use it to answer this question.  Energy level (n)1234Energy (eV)-13.6-3.39-1.51-0.85  [h = 6.6 × 10-34 Js, e = 1.6 × 10-19C; c = 3.0 × 108 ms-1]    Calculate the first excitation energy of the atom.", "images": [], "options": {"A": "1.60 × 10-19 J", "B": "1.02 × 10-18 J", "C": "1.60 × 10-18 J", "D": "1.02 × 10 J"}, "answer": "C", "explanation": "∆E= E2-E1       = -3.39 - (-13.6)       = -3.39 + 13.6       =10.21eV    1eV = 1.6 x 10^-19  10.eV= 10.21 x 1.6 x 10^-19            =1.6 x 10^-18J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>47", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "The table below shows the energy distribution for various levels of an atom. Use it to answer this question.  Energy level (n)1234Energy (eV)-13.6-3.39-1.51-0.85  [h = 6.6 × 10-34 Js, e = 1.6 × 10-19C; c = 3.0 × 108 ms-1]  If the atom de-excites from n = 2, wavelength of the emitted radiation is", "images": [], "options": {"A": "2.4 × 10-7m", "B": "1.2 × 10-7m", "C": "2.4 × 10-9m", "D": "1.2 × 10-9m"}, "answer": "B", "explanation": "If the atom de-excites from n = 2; the wavelength of the emitted radiation is given by:   λ=hcE=6.6×10-34×3×10812.75×10-19=1.2×10-7m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2009>48", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "Two isotopes of uranium are designated as 238U and 235U. The numbers 238 and 235 represent their", "images": [], "options": {"A": "atomic numbers", "B": "nucleon numbers", "C": "proton numbers", "D": "neutron numbers"}, "answer": "B", "explanation": "In the notation for isotopes, the number following the element symbol (in this case, uranium or U) represents the total number of protons and neutrons in the nucleus of the atom. This total is also known as the nucleon number or mass number. Therefore, in the isotopes 238U and 235U, the numbers 238 and 235 represent the nucleon numbers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2009>49", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "The main difference between x-rays and γ-rays lies in their", "images": [], "options": {"A": "ionizing ability", "B": "absorption rate", "C": "mode of production", "D": "mode of propagation"}, "answer": "C", "explanation": "The main difference between x-rays and γ-rays lies in their mode of production. X-rays are produced when high-energy electrons strike a metal target, while γ-rays are produced by radioactive atoms and in nuclear explosions. Both have similar properties like ionizing ability, absorption rate, and mode of propagation, but their production method is what sets them apart.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2009>50", "subject": "Physics", "year": "2009", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "An electron of mass 9.1 × 10-31 kg moves with a speed of 107ms-1. Calculate the wavelength of the associated wave.  [h = 6.6 × 1034Js]", "images": [], "options": {"A": "9.10 × 10-24m", "B": "4.55 × 10-17m", "C": "7.25 × 10-11m", "D": "6.20 × 10-8m"}, "answer": "C", "explanation": "Given that: mass, m = 91 × 10-31kg  speed, v = 107ms-1  Wavelength, λ= ?  Planck's constant, h = 6.6 × 10-34Js  c = 3.0 × 108ms-1  Recall,  λ=hc1/2 mv2  sinceλ=hcE  where,E=12mv2  λ=6.6 × 10-34 × 3.0 × 10812 × 9.1 × 10-31 × (107)2  λ=6.6 × 3.0 × 10-34 + 8 0.5 × 9.1 × 10-31 × 1014  λ = 7.25 × 10-11m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>1", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following properties of a long steel bar would alter if the bar were melted, recast into a cube and allowed to cool to its original temperature?", "images": [], "options": {"A": "Density", "B": "Volume", "C": "Specific heat capacity", "D": "Electrical resistance"}, "answer": "D", "explanation": "The electrical resistance of a material depends on its shape and size, as well as its resistivity. When the steel bar is melted and recast into a cube, its shape and size change, which would alter its electrical resistance. The other properties like density, volume, and specific heat capacity are intrinsic properties of the material and would not change with the change in shape or size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>2", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "Which of the following instruments is the best for measuring the diameter of a thin constantan wire?", "images": [], "options": {"A": "Callipers", "B": "Metre rule", "C": "Micrometer screw gauge", "D": "Vernier callipers"}, "answer": "C", "explanation": "The micrometer screw gauge can be used to measure the diameter of a thin constantan wire. This is possible because of its accuracy (0.01mm).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>3", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "What is the density of a fuel relative density 0.72?  [Density of water = 1000kgm-3]", "images": [], "options": {"A": "72kg m-3", "B": "720kg m-3", "C": "7200kg m-3", "D": "72000kg m-3"}, "answer": "B", "explanation": "Given: (1) the relative density of the fuel = 0.72  (2) the density of water = 1000kgm-3  Recall:Therelativedensityofasubstance=Density of the substanceDensity of water  ∴0.72=Density of the substance1000  Density of the substance = 72kgm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>4", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "The types of motion which a cylindrical drum rolling down an inclined plane undergoes are", "images": [], "options": {"A": "circular and translational", "B": "rotational and translational", "C": "rotational and circular", "D": "rectilinear and circular"}, "answer": "B", "explanation": "The circumference of the drum is undergoing rotational motion while the centre undergoes translational motion.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>5", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "Which of the following statements about a moving particle is correct?", "images": [], "options": {"A": "If the resultant force acting on the particle is zero, then it is in dynamic equilibrium", "B": "If the resultant force acting on the particle is greater than zero, then it is moving with a uniform velocity", "C": "The rate of change of its momentum with time takes place in a direction opposite to that of its motion", "D": "The particle failing freely covers equal distances in equal time intervals"}, "answer": "A", "explanation": "A particle is in dynamic equilibrium if the resultant force acting on it is zero. This means that the sum of all forces acting on the particle is zero, resulting in no acceleration or change in velocity. Therefore, the particle can either be at rest or moving with a constant velocity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>6", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "Which of the following statements about static friction is correct? It", "images": [], "options": {"A": "is independent of the nature of surfaces in contact", "B": "depends on the area of surfaces in contact", "C": "depends on the relative motion between the surfaces in contact", "D": "depends on the weight of the moving body"}, "answer": "D", "explanation": "Static friction is the friction that needs to be overcome to start moving an object. It depends on the weight of the moving body because the heavier the object, the more force is needed to overcome the static friction and start moving the object. This is due to the fact that friction is a force that opposes motion, and it is proportional to the normal force (which is the weight of the object in this case).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>7", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "MOTION : RELATIVE MOTION", "question": "Two cars X and Y travelling in opposite directions along the same highway at uniform velocities 110kmh-1 and 90kmh-1 respectively pass each other at a certain point. The velocity of X relative to Y at the time they pass each other is", "images": [], "options": {"A": "200kmh-1", "B": "100kmh-1", "C": "40kmh-1", "D": "20kmh-1"}, "answer": "A", "explanation": "The relative velocity of the two cars X and Y as at the time they pass each other = The sum of their velocities  ∴ Relative velocity = 110 + 90 = 200kmh-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>8", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "The average speed of an object is determined by dividing the sum of its initial and final speeds by two only when the acceleration is", "images": [], "options": {"A": "changing", "B": "uniform", "C": "increasing", "D": "decreasing"}, "answer": "B", "explanation": "The average speed of an object is determined by dividing the sum of its initial and final speeds by two only when the acceleration is uniform. This is because when acceleration is uniform, the object's speed changes at a constant rate, so the average speed is simply the average of the initial and final speeds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>9", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A body is projected horizontally from the top of a cliff 45m above the ground. If the body lands at a distance 30m from the foot of the cliff. Calculate the speed of projection.  [g = 10ms-2]", "images": [], "options": {"A": "10ms-1", "B": "15ms-1", "C": "20ms-1", "D": "30ms-1"}, "answer": "A", "explanation": "Given: The height, h of projection 45m  The range, R of projection = 30m. The velocity, U of projection = ?  Recall: R = UT ......(1)  T=&radic;2Hg&nbsp;......(2)  ∴R=u&radic;2×Hg&nbsp;  30=u&radic;9010&nbsp;  30 = u*&radic;9&nbsp;  30 = u × 3  30 = 3u  u = 10ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>10", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Which of the following statements best describes a rigid body? A body which", "images": [], "options": {"A": "is not easily deformed", "B": "when deformed remains its shape", "C": "is brittle", "D": "when deformed remains deformed"}, "answer": "A", "explanation": "A rigid body is a body that is not easily deformed. This means that it can withstand forces applied to it without changing its shape or size. This is different from a brittle body, which can break or crack easily, or a body that remains deformed after a force is applied, which would indicate that it is not rigid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>11", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SPEED AND ACCELERATION OF S.H.M", "question": "A simple harmonic oscillator has a period of 0.02s and amplitude of 0.25m. Calculate the speed in ms-1 at the centre of the oscillation.", "images": [], "options": {"A": "1.25π", "B": "25.00π", "C": "100.00π", "D": "400.00π"}, "answer": "B", "explanation": "Given: (1) the period, T = 0.02s  (2) the amplitude, A = 0.25m   Recall: Frequency,F=1T......(i)  Speed,V=ωA......(ii)  Angular speed, ω = 2πf ......(iii)  ∴F=10.02=50Hz  ω = 2π × 50 = 100π  V = 100π × 0.25  V = 2.5π", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>12", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "A vertical string, suspended from a fixed point and having a small mass attached to the free end is set into oscillations. Which of the following statements about the system are correct?  I. The potential energy of the mass is a minimum at the middle of the swing.  II. Its kinetic energy is a maximum at the middle of the swing.  III. The sum of the potential and kinetic energies is constant throughout the swing.", "images": [], "options": {"A": "I, II and III", "B": "I and II only", "C": "II and III only", "D": "I and III only"}, "answer": "C", "explanation": "It kinetic energy is a maximum at the middle of the swing. The sum of P.E and K.E is constant throughout.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>13", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A moving body of mass 25.0kg undergoes a uniform retardation of 20.0m-2. Calculate the magnitude of the retarding force.", "images": [], "options": {"A": "1.25N", "B": "8.00N", "C": "45.00N", "D": "500.00N"}, "answer": "D", "explanation": "Given: The mass, m of the body = 25.0kg  The retardation = 200ms-2  The magnitude of the retarding force, F = ?  Recall: F = mass × retardation  F = 25 × (20) = 500N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>14", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ENERGY : WORLD ENERGY RESOURCES", "question": "Which of the following sources of energy is/are exhaustible?  I. Solar  II. Fossil fuel  III. Tidal power", "images": [], "options": {"A": "II only", "B": "III only", "C": "I and II only", "D": "II and III only"}, "answer": "A", "explanation": "Exhaustible energy sources are those that are finite and will eventually run out. Fossil fuels, such as coal, oil, and natural gas, are examples of exhaustible energy sources because they take millions of years to form. On the other hand, solar energy and tidal power are renewable energy sources because they are replenished naturally and regularly. Therefore, only statement II is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>15", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "MACHINES :", "question": "A machine is said to be a third class lever when the", "images": [], "options": {"A": "load is between the fulcrum and effort", "B": "fulcrum is between the effort and load", "C": "effort is between the fulcrum and load", "D": "fulcrum is directly below the load"}, "answer": "C", "explanation": "The third class lever is such that the effort is found between the fulcrum and the load. e.g Wheel barrow.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>16", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A thermometer records 680 mmHg at steam point and 440 mm at ice point. The temperature it records at 380 mmHg is", "images": [], "options": {"A": "-25°C", "B": "-20°C", "C": "20°C", "D": "25°C"}, "answer": "A", "explanation": "Given: (1) The reading at steam point = 680mmHg.  (2) The reading at ice point = 440mmHg  (3) The temperature, θ when it reads 380mmHg = ?  ∴x - 0100 - x =380 - 440680 - 380  x100 - x=-60300  x100 - x=-15  5x = x - 100  4x = -100  x = -25°c", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>17", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The advantages of the thermoelectric thermometer include the following characteristics except that it", "images": [], "options": {"A": "can measures rapidly changing temperatures", "B": "can measure high and low temperatures", "C": "can measure temperature almost at a point", "D": "is fairly sensitive"}, "answer": "D", "explanation": "The fact it is fairly sensitive is not an advantage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>18", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "In a thermos flask, heat loss by radiation is minimized by the", "images": [], "options": {"A": "silvered surfaces", "B": "vacuum within the double walls", "C": "plastic stopper", "D": "cork support"}, "answer": "A", "explanation": "In a thermos flask, heat loss by radiation is minimized by the silvered surfaces. The silvered surfaces reflect the heat radiation back into the flask, preventing it from escaping. This is a principle of thermal radiation, where shiny or white surfaces are good reflectors of heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>19", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The pressure P, volume V and absolute temperature T of a given mass of an ideal gas, change simultaneously. Which of the following equations is correct about the gas?", "images": [], "options": {"A": "PV=constantT", "B": "PT=constant", "C": "PV=constantT", "D": "1T=constantPV"}, "answer": "D", "explanation": "The product of pressure and the quotient of volume and temperature is constant for and ideal gas", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>20", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "Specific heat capacity 26.4Jkg-1k-1 of a body means that when 26.4J of heat energy is supplied to a body of", "images": [], "options": {"A": "mass 1000 kg, the temperature rises by 1K", "B": "mass 1kg, the temperature rises by 1000K", "C": "mass 1kg, the temperature rises by 1K", "D": "mass 1000kg, the temperature rises by 1000K"}, "answer": "C", "explanation": "The specific heat capacity = 264Jkg-1k-1. This is the heat energy supplied to a body of mass, 1 kg when the temperature is raised b 1K.  ∴ Specific heat capacity of 264Jkg-1k-1 means when 264J of heat energy is supplied to a body of mass, 1 kg, the temperature is raised by 1K.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>21", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "An electric drill rated 400W is used to drill a hole in copper of mass 400g in 20s. Calculate the rise in temperature if all the heat produced is absorbed by the copper.  [Specific heat capacity of copper = 400Jkg-1k-1]", "images": [], "options": {"A": "100°C", "B": "75°C", "C": "50°C", "D": "45°C"}, "answer": "C", "explanation": "Given: (1) The power rating, P of the drill = 400W  (2) The mass of copper = 400g  (3) The time taken, t = 205  (4) SHC of copper = 400Jkg-1k-1.  N:B: Heat energy lost by the drill = Heat gained by copper   ∴ Electrical power × Time = mass × SHC × Temperature rise.  = 400 × 20 = 0.4 × 400 × Temperature rise  8000 = 160 × Temperature rise  ∴ Temperature rise = 50°C or 50K", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>22", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "A solid of mass 0.5kg initially at 50°C melts at 60°C. Calculate the quantity of heat required to melt it completely.  [Specific heat capacity of the solid = 1.0 kJkg-1k-1]  [Specific latent of heat of fusion of solid = 2.0kJkg-1]", "images": [], "options": {"A": "1500J", "B": "10000J", "C": "10500J", "D": "15000J"}, "answer": "C", "explanation": "Given: (1) mass, m of the solid = 0.5kg  (2) Initial temperature, θ1 = 50°c  (3) Final temperature, θ2 = 60°c  (4) SHC of the solid = 2.0KJKg-1k-1  (5) Specific latent heat of fusion = 1.0 kJkg-1.  Quantity of Heat = mL + mcΔθ  Q = 0.5 × 1 + 0.5 × 2 × 10   = (0.5 + 10)kJ = 10.5kJ = 10,500J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>23", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT", "question": "Dew point is not affected by", "images": [], "options": {"A": "temperature", "B": "wind", "C": "the amount of water vapour in the atmosphere", "D": "atmospheric pressure"}, "answer": "B", "explanation": "Dew point is the temperature at which air becomes saturated with water vapor, after which the water vapor begins to condense into liquid water. It is affected by the temperature, the amount of water vapor in the atmosphere, and the atmospheric pressure. However, it is not affected by wind.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>24", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "A certain wave has a speed of 20ms-1. If the frequency of the wave is 0.25Hz, calculate the distance between successive crests of the wave.", "images": [], "options": {"A": "5.0m", "B": "40.0m", "C": "50.0m", "D": "80.0m"}, "answer": "D", "explanation": "Given: (1) the speed, v = 20ms-1  (2) the frequency, f of the wave = 0.25Hz  (3) the wavelength, λ is unknown  Recall: v = fλ  20 = 0.25λ  λ = 80.0m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>25", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "PROPERTIES OF WAVES : DIFFRACTION", "question": "The ability of a wave to spread around corners is called", "images": [], "options": {"A": "polarisation", "B": "dispersion", "C": "diffraction", "D": "reflection"}, "answer": "C", "explanation": "The ability of a wave to spread around corners is called diffraction. Diffraction is a wave phenomenon that describes the ability of waves to bend around obstacles and spread out after passing through a narrow opening.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>26", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The following devices use plane mirrors in their operations, except", "images": [], "options": {"A": "periscope", "B": "sextant", "C": "kaleidoscope", "D": "binoculars"}, "answer": "D", "explanation": "Binoculars do not use plane mirrors in their operations. Instead, they use a series of lenses to magnify distant objects. On the other hand, periscopes, sextants, and kaleidoscopes all use plane mirrors in their operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>27", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "When an object is placed at the principal focus of a concave mirror, the location of the image formed is", "images": [], "options": {"A": "between principal focus and pole", "B": "between principal focus and centre of curvature", "C": "at infinity", "D": "at centre of curvature"}, "answer": "C", "explanation": "When an object is placed at the principal focus of a concave mirror, the image formed is always at infinity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>28", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "From the diagram above, the correct equation for the refractive index n of the medium is", "images": ["Physics/imgs/2010/X82E9H.png"], "options": {"A": "n = tani", "B": "n=sinisin90°", "C": "n=sinicos(90° - i)", "D": "n = sin90°"}, "answer": "A", "explanation": "refractiveindex(n)=sin isin r  where r = 180 - (90 + i)    → r = 90 - i    since sin(90 - i) = cos i    ∴refractiveindex(n)=sin icos i=tani", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>29", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light travels from air to water. The refractive index of water is given by the expression", "images": [], "options": {"A": "velocity in watervelocity in air", "B": "sine of angle of refractionsine of angle of incidence", "C": "apparent depthreal depth", "D": "wavelength in air  wavelength in water"}, "answer": "D", "explanation": "Given: The two media concerned; air and water.  It should be noted that, refracted index, n can be expressed in many ways.  1.n=Velocity in media 1  Velocity in media 2  2.n=Wavelength in media 1  Wavelength in media 2  3.n=Sine of angle of incidencesine of angle of refraction", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>30", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A lens that is thinner at the middle and thicker at the edges is", "images": [], "options": {"A": "diverging", "B": "converging", "C": "plano-convex", "D": "converging meniscus"}, "answer": "A", "explanation": "A lens that is thinner at the middle and thicker at the edges is a diverging lens. This is because it spreads out light rays that are incident on it, causing them to diverge or spread out.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>31", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following electromagnetic waves has the longest wavelength?", "images": [], "options": {"A": "Radio waves", "B": "Gamma rays", "C": "Infrared waves", "D": "Ultraviolet rays"}, "answer": "A", "explanation": "The electromagnetic spectrum is the range of all types of EM radiation. Radiation is energy that travels and spreads out as it goes – the visible light that comes from a lamp in your house and the radio waves that come from a radio station are two types of electromagnetic radiation. The other types of EM radiation that make up the electromagnetic spectrum are microwaves, infrared light, ultraviolet light, X-rays and gamma-rays. Among these, Radio waves have the longest wavelength.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>32", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "The amplitude of a sound wave determines its", "images": [], "options": {"A": "frequency", "B": "quality", "C": "loudness", "D": "pitch"}, "answer": "C", "explanation": "In a sound wave, the amplitude is related to the level of energy it carries. Sound waves with greater amplitudes move particles of air, or other media through which they are traveling, with greater intensity and thus, we perceive the sound wave as being louder. So, the amplitude of a sound wave determines its loudness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>33", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "As the air column of length L in an air pipe decreases, the frequency of the stationary wave emitted.", "images": [], "options": {"A": "decreases", "B": "increases", "C": "varies as D2", "D": "varies as &radic;L&nbsp;"}, "answer": "B", "explanation": "Frequency,Fα1√Length  As the length, L reduces/decrease, the frequency F will increase.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>34", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTROSTATICS", "question": "A positively charged glass rod is placed near the cap of a positively chaged electroscope. The divergence of the leaf is observed to", "images": [], "options": {"A": "decrease", "B": "increase", "C": "remain the same", "D": "increase and collapse immediately"}, "answer": "B", "explanation": "When the positively charged glass rod is placed near the cap of a positively charged electroscope, the divergence of the leaf is increased.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>35", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Capacitors are used in the following devices, except", "images": [], "options": {"A": "water pumping machines", "B": "ceiling fans", "C": "electric irons", "D": "television sets"}, "answer": "A", "explanation": "Capacitors are used in electrical devices to store electrical energy temporarily. They are commonly found in ceiling fans, electric irons, and television sets where they help in smoothing out the flow of electricity or blocking direct current while allowing alternating current to pass. However, water pumping machines typically do not use capacitors.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>36", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Use the diagram beside to answer this question.        Calculate the current, I.", "images": ["Physics/imgs/2010/8AJD79.png"], "options": {"A": "0.60A", "B": "0.97A", "C": "1.03A", "D": "5.00A"}, "answer": "B", "explanation": "Given: The circuit diagram  Current, I = ?  Electromotive force, e.m.f = 12v  Load=4 × 64 + 6+10=2.4+10=12.4Ω  Recall: V = IR  ∴I=VR=1212.4=0.97A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>37", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Use the diagram beside to answer this question.      Determine the potential difference, V across the parallel resistors.", "images": ["Physics/imgs/2010/8AJD79.png"], "options": {"A": "2.0V", "B": "2.3V", "C": "3.0V", "D": "9.7V"}, "answer": "B", "explanation": "Req of the parallel connection = 6×46+4\\frac{6×4}{6+4}6+46×4​ = 2.4 &#937;  Recall: V = IR  ∴ V = 0.97 × 2.4 = 2.3V", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>38", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "A galvanometer of internal resistance 50Ω and full scale deflection of 20mA is converted into a voltmeter by connecting a resistor of resistance 1950Ω in series to it. Calculate the maximum voltage that can be read by the voltmeter.", "images": [], "options": {"A": "20V", "B": "30V", "C": "38V", "D": "40V"}, "answer": "D", "explanation": "Given: The current, I = 20 × 10-3A = 0.02A  Internal Resistance, r = R1 = 50Ω  Load = 1950Ω  Maximum voltage, V = IR1 + IR2   = 0.02 (50 + 1950)   = 0.02(2000)   = 40V", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>39", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "In the wiring of houses, the fuse is connected to the wire coloured", "images": [], "options": {"A": "blue", "B": "brown", "C": "yellow", "D": "yellow and green"}, "answer": "B", "explanation": "In the wiring of houses, the fuse is connected to the live wire which is usually brown in color. The fuse is a safety device that protects the electrical circuit by breaking the circuit when there is an overload. The live wire is the wire that carries current from the power source to the appliance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>40", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "Which of the following factors does not affect the electric resistance of a wire?", "images": [], "options": {"A": "Length", "B": "Mass", "C": "Temperature", "D": "Cross-sectional area"}, "answer": "B", "explanation": "The electric resistance of a wire is affected by its length, temperature, and cross-sectional area but not its mass. The resistance of a wire increases with its length and temperature and decreases with its cross-sectional area. This is because resistance is a measure of how much a material opposes the flow of electric current, and these factors affect how easily current can flow through the wire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>41", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "Which of the following factors will increase the sensitivity of a moving coil meter?", "images": [], "options": {"A": "Strong spring", "B": "Low number of turns", "C": "Small area of coil", "D": "Soft iron core"}, "answer": "D", "explanation": "The sensitivity of a moving coil meter will be increased if the construction is composed of soft iron core.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>42", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "In other to prevent bar magnets from losing their strength, they are stored with keepers such that the two bars are placed with", "images": [], "options": {"A": "like poles facing each other and the keepers placed at their ends", "B": "like poles facing each other and the keepers placed between them", "C": "unlike poles facing each other and the keepers placed at their ends", "D": "unlike poles facing each other and the keepers placed between them."}, "answer": "C", "explanation": "Keepers are materials in which magnets are stored, so as to preserve their magnetic properties. Unlike poles of the magnet usually face each other with the keepers placed at their ends.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>43", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "The resonant frequency of an a.c circuit is 1000kHz. If each of the capacitance and inductance in the circuit is reduced by 50% and no other changes are made, the resonant frequency will become", "images": [], "options": {"A": "250kHz", "B": "750kHz", "C": "1000kHz", "D": "2000kHz"}, "answer": "D", "explanation": "Given: Fo (Resonant frequency) = 1000kHz.  Recall: Fo=12π&radic;LC&nbsp;  L2=L12  C2=C12  F1&radic;L1C1&nbsp; = F2&radic;L2C2&nbsp;  F1F2=&radic;L2C2L1C1&nbsp;  F1F2=&radic;L1/2 × C1/2 L1C1&nbsp;  F1F2=&radic;L1C14×1L1C1&nbsp;  F1F2=&radic;14&nbsp;  F1F2=12  F1 × 2 = F2  ∴ F2 = 2F1 = 2 × 1000  = 2000KHz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>44", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "The energy, E stored in an inductor of inductance L when current I passes through it is given by the equation.", "images": [], "options": {"A": "E=12LI2", "B": "E = LI2", "C": "E=12LI", "D": "E=12L2I"}, "answer": "A", "explanation": "The energy stored in an inductor is given by the formula E = 1/2 LI2, where L is the inductance and I is the current. This formula comes from the work done in establishing the current in the inductor. The work done against the back emf (electromotive force) in establishing the current is stored as magnetic potential energy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>45", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : EDDY CURRENTS", "question": "Eddy currents can be reduced by", "images": [], "options": {"A": "using coil of high resistance", "B": "winding the coil on a soft iron core", "C": "creating holes in the metal plates", "D": "using coil of low resistance"}, "answer": "C", "explanation": "Eddy currents are circulating currents induced in the metal body when it is subjected to a changing magnetic field. These currents cause energy loss due to heating effect. Eddy currents can be reduced by creating holes in the metal plates, which breaks the path of the eddy currents and thus reduces their magnitude.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>46", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "An electron moves with a speed of 2.0 × 106ms-1 in a straight line. Calculate the wavelength of the electron wave.  [Mass of an electron = 9.1 × 10-31kg]  [Planck's constant = 6.6 × 10-34Js]", "images": [], "options": {"A": "3.63 × 10-10 m", "B": "6.51 × 10-9 m", "C": "4.24 × 10-8 m", "D": "7.25 × 10-8 m"}, "answer": "C", "explanation": "Given: v = 2.0 × 106ms-1  λ = ?  m = 9.1 × 10-31kg  h = 6.6 × 10-34Js  c = 3.0 × 108ms-1  Recall,   λ=hc1/2 mv2  λ=6.6 × 10-34 × 3.0 × 1081/2 × 9.1 × 10-31 × (2.0 × 106)2  λ=6.6×3.00.5×9.1×4×10-34 + 810-31 + 12  λ = 4.243 × 10-8m  λ = 4.24 × 10-8m (2d.p)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2010>47", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "Oxidation of the filament in a light bulb is prevented by the introduction of", "images": [], "options": {"A": "hydrogen", "B": "oxygen", "C": "argon", "D": "mercury vapour"}, "answer": "C", "explanation": "The filament in a light bulb is usually made of tungsten, which oxidizes and breaks down at high temperatures. To prevent this, the bulb is filled with an inert gas like argon, which does not react with the filament even at high temperatures, thus preventing its oxidation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2010>48", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : THERMIONIC EMISSION", "question": "In a cathode ray tube, the function of the X-plates is to", "images": [], "options": {"A": "deflect the electron beam horizontally", "B": "deflect the electron beam vertically", "C": "reflect the electron beam", "D": "generate sinusoidal waves"}, "answer": "A", "explanation": "In a cathode ray tube, the X-plates are used to deflect the electron beam horizontally. The cathode ray tube works by shooting a beam of electrons (originating from the cathode) towards the anode. The X-plates and Y-plates are used to deflect this beam in the horizontal and vertical directions respectively. This deflection allows the beam to hit different parts of the screen, creating the images we see.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>49", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "A nuclide represented as 7032X has a neutron-proton ratio of", "images": [], "options": {"A": "0.5", "B": "0.8", "C": "1.2", "D": "1.5"}, "answer": "C", "explanation": "Given: The nuclide 7032 X. The number of proton = 32 (atomic number) and the number of neutron = (70 - 32) = 38.  ∴ neutron: Proton ration = 38 : 32  = 19 : 16 = 1 . 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2010>50", "subject": "Physics", "year": "2010", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Neutrons are used to induce artificial radioactivity because they", "images": [], "options": {"A": "are energetic", "B": "have no charge", "C": "have no mass", "D": "are ionizing"}, "answer": "B", "explanation": "Neutrons are used to induce artificial radioactivity because they have no charge. This means they can penetrate the nucleus of an atom without being repelled by the positive charge of the protons in the nucleus. Once inside the nucleus, a neutron can cause the atom to become radioactive by upsetting the balance of protons and neutrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>1", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statement is not correct?", "images": [], "options": {"A": "Molecules of ice, water and water vapour have equal intermolecular distances", "B": "Molecules of ice, water and water vapour do not differ in the structure of their molecules", "C": "Molecules of water vapour attract each other with forces far less than the forces of attraction between water molecules", "D": "Water is less compressible than water vapour"}, "answer": "A", "explanation": "* Ice, water and steam exist respectively as solid, liquid and gas.    * From the studies of atom, the molecules of a solid are very closely packed and are held together by a very strong forces of attraction, the molecules of a liquid are closely packed but not like those of solids and are held together by strong forces of attractions not up to that of solid; the molecules of a gas are very far apart from one another and are held together by very weak attractive forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>2", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "The density p of a spherical ball of diameter d and mass m is given by", "images": [], "options": {"A": "p = 3m/4πm3", "B": "p = 4πmd3", "C": "p = 6m/πd3", "D": "p = 3m/2πd3"}, "answer": "C", "explanation": "* Density = mass/volume    *Thevolumeofasphere=43π(d38)     * Density of a spherical ball of diameter d and mass (m) is given by    ρ=m÷4π3d38   ρ=mπd36=6mπd3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>3", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A metal rod of density 7000kgm-3 and cross-sectional area of 0.001257m2 has a mass of 1.76kg. Calculate its length", "images": [], "options": {"A": "0.20m", "B": "0.25m", "C": "0.40m", "D": "0.50m"}, "answer": "A", "explanation": "* Density = 7000 kgm-3    Area(A) = 0.001257m2 = 1.257 x 10-3m2    mass(m) = 1.76kg    length (l) = ?    Recall that,    Density=massvolume=massArea x length(height)    7000=1.761.257 x 10-3 x length   7 x 1.257 x length = 1.76    length=1.768.799=1.768.8    = 0.2m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>4", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure in a liquid", "images": [], "options": {"A": "is the same at all point in the liquid", "B": "decreases with depth", "C": "is the same in all directions at a given point", "D": "is equal to the atmospheric pressure"}, "answer": "C", "explanation": "The pressure in a liquid is the same in all directions at a given point. This is known as Pascal's law, which states that any change in pressure applied at any point in a fluid is transmitted undiminished to all other points in the fluid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2011>5", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "FLUID AT REST : VISCOSITY (FRICTION IN FLUIDS)", "question": "The property of a liquid that is used to determine its suitability as a lubricant is its", "images": [], "options": {"A": "capillarity", "B": "viscosity", "C": "surface tension", "D": "relative density"}, "answer": "B", "explanation": "The property of a liquid that is used to determine its suitability as a lubricant is its viscosity. Viscosity is a measure of a fluid's resistance to flow. It describes the internal friction of a moving fluid. A fluid with large viscosity resists motion because its molecular makeup gives it a lot of internal friction. A fluid with low viscosity flows easily because its molecular makeup results in very little friction when it is in motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>6", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "Which of the following graphs describes a body that accelerates uniformly with an initial velocity greater than zero?", "images": ["Physics/imgs/2011/opt1.png", "Physics/imgs/2011/opt2.png", "Physics/imgs/2011/opt3.png", "Physics/imgs/2011/opt4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "Acceleration is the time rate of increase in velocity of a body.    Mathematically, acceleration=change in velocitytime    This change in velocity is such that the final velocity is greater than the initial velocity.    V2 = V1    ΔV = V2 - V1    ΔV = 0    The change in velocity = 0    Acceleration = 0/time = 0.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>7", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "The area under a velocity-time graph represents", "images": [], "options": {"A": "final velocity attained", "B": "distance covered", "C": "acceleration", "D": "work done"}, "answer": "B", "explanation": "* The weight of a body is the gravitational force of attraction experienced by a body.    That is Weight = Gravitational Force.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>8", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "In the absence of gravitational force, the weight of a body is", "images": [], "options": {"A": "its mass", "B": "zero", "C": "its density", "D": "its volume"}, "answer": "B", "explanation": "* The area of a graph is the product of the y-axis of the graph and its x-axis.    * The area under a velocity-time graph, i = velocity x time = distance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2011>9", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "A stone of mass 300g is released from rest from the top of a building of height 100m. Determine the kinetic energy gained by the stone when it is quarter way down from the point of release (g = 10ms-2).", "images": [], "options": {"A": "750.0J", "B": "225.0J", "C": "75.0J", "D": "22.5J"}, "answer": "C", "explanation": "* As the body is falling the P.E is decreasing and its K.E increasing.    * At Quarter way down, the PE as reduced by Quarter distance (height) and the K.E has increased.    * At the top of the buildiing K.E = 0    P.E = mgh = 0.3(10)(100) = 300J    At Quarter way down, P.E = 3/4 x 100 x 0.3 x 10 = 225J.    At every point M.E = K.E + P.E which is constant   300 = 225 + K.E    K.E = 75J    At a distance quarter way down from the point of release.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>10", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A body of mass 120g placed at the 10cm mark on a uniform metre rule makes the settle horizontally on a fulcrum placed at the 35cm mark. Calculate the mass of the rule", "images": [], "options": {"A": "60g", "B": "80g", "C": "120g", "D": "200g"}, "answer": "D", "explanation": "* On a uniform metre rule, the weight usually acts at the centre.    *Assume that the length = 100cm        Take moment about the fulcrum    120(25) = 15W    3000 = 15W    W = 200g", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>11", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "Two simple pendula A and B of equal lengths and of masses 5g and 20g respectively are located in the same environment. The periods TA and TB of their respective oscillation are related by the equations", "images": [], "options": {"A": "TA = 4TB", "B": "TA = 1/4TB", "C": "TA = TB", "D": "TA = 5TB"}, "answer": "C", "explanation": "* It should be noted that the period of oscillation of a simple pendulum depends on the length of the inextensible string unto which the bob is tied and the acceleration due to gravity.    * This can be deduced from    T = 2π&radic;l/g&nbsp;    where 'l' is the length of the string and 'g' the acceleration due to gravity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>12", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "An object of mass 5.0kg moves with a velocity of 10ms-1. Calculate its momentum.", "images": [], "options": {"A": "50.0kgms-1", "B": "15.0kgms-1", "C": "2.0kgms-1", "D": "0.5kgms-1"}, "answer": "A", "explanation": "Momentum is calculated by multiplying the mass of an object by its velocity. In this case, the mass is 5.0kg and the velocity is 10ms-1. Therefore, the momentum is 5.0kg * 10ms-1 = 50.0kgms-1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>13", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A coin is pushed from the edge of a laboratory bench with a horizontal velocity of 15.0ms-1, if the height of the bench from the floor is 1.5m, calculate the distance from the foot of the bench of the point of impact with the floor. (g = 10ms-2)", "images": [], "options": {"A": "0.75m", "B": "2.25m", "C": "8.22m", "D": "15.00m"}, "answer": "C", "explanation": "Recall that,    x = ut + 1/2gt2    We use 'g' because the body falls under gravity.    * For horizontal direction g = 0    Hence, x = uT, H = 1.5m    T = &radic;2H/g&nbsp;, g = 10ms-2    T = &radic;2(1.5)/10&nbsp;    T = &radic;3/10&nbsp; = &radic;0.3&nbsp;    x = 15&radic;0.3&nbsp; = 8.22m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>14", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following statements correctly defines a simple machine? A device", "images": [], "options": {"A": "that can produce electric current", "B": "which can only carry people from one place to another", "C": "with which work can be done easily", "D": "which changes the state of rest or of uniform motion of an object"}, "answer": "C", "explanation": "A simple machine is a device that makes work easier. It does this by either changing the direction of a force, increasing the magnitude of a force, or increasing the distance or speed of a force. Therefore, the correct definition of a simple machine is a device with which work can be done easily.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>15", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "MACHINES :", "question": "The radius of a wheel is 30.0 cm and that of its axle is 6.0 cm. Calculate the effort required to fit a load of 120.0 N using this machine, assuming 100% efficiency", "images": [], "options": {"A": "600.0 N", "B": "40.0 N", "C": "24.0 N", "D": "20.0 N"}, "answer": "C", "explanation": "Since the efficiency is 100%    M.A = V.R    LOADEFFORT=2πR2πr → In a wheel and axle.   lE=Rr   R = 30cm, r = 6cm, L = 120N   120x=306   30x = 720; x = 24N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>16", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Which of the following properties is not considered in choosing mercury as a thermometric liquid?", "images": [], "options": {"A": "Density", "B": "Expansivity", "C": "Conductivity", "D": "Opacity"}, "answer": "A", "explanation": "Density s not considered in choosing mercury as a thermometric liquid", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>17", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "A hypsometer is used for determining", "images": [], "options": {"A": "steam point", "B": "relative humidity", "C": "ice point", "D": "relative density"}, "answer": "A", "explanation": "A hypsometer measures the boiling point of water, which varies with atmospheric pressure, allowing for the determination of altitude based on the steam point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>18", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "Which of the following statements about anomalous expansion of water are correct?    I. There is contraction between 0oC and 4oC   II. There is expansion between 0oC and 100oC    III. The volume is minimum at 4oC  IV. The volume is maximum at 4 oc", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "II and IV only"}, "answer": "C", "explanation": "* Between 0oc and 4oc water behaves in an anomalous way.    * The volume decreases upon increases in temperature between 0oc and 4oc.    * There is a contraction between 0oc and 4oc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>19", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "Which of the following equation shows the linear expansivity (α) and the cubic expansivity (γ) of a material are related?", "images": [], "options": {"A": "γ = α", "B": "γ = 1 - α", "C": "γ = 2α", "D": "γ = 3α"}, "answer": "D", "explanation": "The linear expansivity (α) of a material is a measure of how much a material expands per degree change in temperature. The cubic expansivity (γ) is a measure of how much a material's volume changes with a change in temperature. The relationship between these two quantities is given by the equation γ = 3α. Therefore, option 4 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>20", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "Which of the following assumption is not valid for an ideal gas?", "images": [], "options": {"A": "Molecules of a particular gas are identical", "B": "Molecules move freely throughout the volume of the container", "C": "Force of attraction between molecules is negligible", "D": "Molecules move at constant speed between collisions"}, "answer": "D", "explanation": "In the kinetic theory of gases, which describes an ideal gas, there are several assumptions made. These include that the molecules of a particular gas are identical, that they move freely throughout the volume of the container, and that the force of attraction between molecules is negligible. However, it is not assumed that molecules move at a constant speed between collisions. In fact, their speeds are expected to vary due to collisions and the distribution of kinetic energy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>21", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A body is pulled over a distance of 500m by a force of 20 N. if the power developed is 0.4 kW, calculate the time interval during which the force is applied", "images": [], "options": {"A": "0.2s", "B": "2.5 s", "C": "25.0 s", "D": "250.0 s"}, "answer": "C", "explanation": "Power=EnergyTime    Parameters given, F = 20N, d = 500m    P = 0.4KW = 400W    Energy = F x d    = 20 x 500 = 104Nm    Power=EnergyTime    400=1044   400x = 104    4x ×102 = 104    4x = 100    x = 25seconds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>22", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "A metal of mass 200 g at a temperature of 100 oC is placed in 100g of water 25oC in a container of negligible heat capacity. If the final steady temperature is 30 oC, calculate the specific heat capacity of the metal. (Specific heat capacity of water is 4200 Jkg-1 K-1)", "images": [], "options": {"A": "150 Jkg-1 K-1)", "B": "300 Jkg-1 K-1)", "C": "320 Jkg-1 K-1)", "D": "1960 Jkg-1 K-1)"}, "answer": "A", "explanation": "* Heat lost by the metal = Heat gained by the water.    H = mcΔθ   Hm = Hw   mwcw(Δθ)w = MmCm(Δθ)m    mw = 100g , (Δθ)w = 5oc    (Δθ)m = 70oc   Cw = 4200JKg-1K-1; cm = ?    * 100g = 0.1kg; 200g = 0.1kg    0.1 x 4200 x 5 = 0.2 x cm x 70    0.1 x 21000 = 14cm    cm=210014=150Jkg-1k-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>23", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Ether produces a cooling effect when it is poured on the hand because it has", "images": [], "options": {"A": "low conductivity", "B": "high conductivity", "C": "high latent heat of vaporization", "D": "low latent heat of vaporization"}, "answer": "D", "explanation": "* It evaporates quickly due to low latent heat of vaporization     * Evaporation results in cooling", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>24", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "Which of the following statements about the image formed by a plane mirror is not correct?", "images": [], "options": {"A": "It is laterally inverted", "B": "It has unit magnification", "C": "It is formed by actual intersection of rays", "D": "Its distance from the mirror is equal to that of the object from the mirror"}, "answer": "C", "explanation": "The image formed by a plane mirror is a virtual image, which means it is formed by the apparent intersection of light rays, not the actual intersection. A virtual image is an image that appears to be in a location where light does not actually reach. Light does not actually pass through the location on the other side of the mirror; it only appears to an observer as though the light is coming from this location.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2011>25", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The image formed by a convex mirror is always", "images": [], "options": {"A": "real, erect and diminished", "B": "real, inverted and diminished", "C": "virtual, inverted and diminished", "D": "virtual, erect and diminished"}, "answer": "D", "explanation": "- The image formed by a convex mirror is usually at the back of the mirror (virtual), upright (erect) and smaller than the object (diminished).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>26", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray undergoes a minimum deviation at 40o when it is incident on an equilateral triangular glass prism. Calculate the refraction index of the prism", "images": [], "options": {"A": "1.48", "B": "1.50", "C": "1.53", "D": "1.67"}, "answer": "C", "explanation": "Dm = 40o    A = 60o    n=sin(Dm+A2)÷sin(A2)   n=sin(50)sin30=0.76600.5=1.53.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>27", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Total internal refraction occurs in an optical prism when light rays", "images": [], "options": {"A": "travel from the prism into an optically denser medium", "B": "are incident in the prism at an angle greater than the critical angle", "C": "are incident normally in the prism", "D": "travel from the prism to air"}, "answer": "B", "explanation": "Total internal reflection occurs when light travels from a denser medium to a less dense medium (like from glass to air) and hits the boundary at an angle greater than the so-called critical angle. The critical angle is the angle of incidence that provides an angle of refraction of 90-degrees. If the angle of incidence is greater than this critical angle, the light doesn't refract, but instead is totally internally reflected. So, the correct answer is 'are incident in the prism at an angle greater than the critical angle'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>28", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The speed of light in a certain medium is V while its speed in a vacuum is C. The absolute refractive index of the medium is", "images": [], "options": {"A": "C + V", "B": "C/V", "C": "V/C", "D": "C - V"}, "answer": "B", "explanation": "* The refractive index of a medium is the ratio of the speed of light in vacuum to the speed of light in that medium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>29", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "An object is placed 20.0 cm in front of a converging lens of focal length 15.0cm. Calculate its image distance.", "images": [], "options": {"A": "1.3 cm", "B": "8.6 cm", "C": "35.0 cm", "D": "60.0 cm"}, "answer": "D", "explanation": "1v=1f-1u  u = 20cm  1v=1f-1u  1v=115-120  1v=20-15300  1v=5300  v = 60cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>30", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Presbyopia is a defect of the eye resulting from", "images": [], "options": {"A": "weak ciliary muscles", "B": "short eyeball", "C": "loss of sphericity of the lens", "D": "long eyeball"}, "answer": "A", "explanation": "Presbyopia is a condition associated with aging in which the eye exhibits a progressively diminished ability to focus on near objects. This happens due to the loss of elasticity of the lens of the eye, which is controlled by the ciliary muscles. As we age, the ciliary muscles become weak and are unable to change the shape of the lens to focus on nearby objects, leading to presbyopia. Therefore, the correct answer is 'weak ciliary muscles'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>31", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The focal length of the eye-piece of an astronomical telescope is fl. W‎hile the focal length of the objective is f2. For normal adjustment, the angular magnification is given by", "images": [], "options": {"A": "f2/fl", "B": "1 - f2/fl", "C": "f2/fl - 1", "D": "fl/f2"}, "answer": "A", "explanation": "Angular magnification = focal length of the objective lens (fo) divided by the focal length of the eyepiece (fe).    M = fo/fe.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>32", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "SOUND WAVES : BEATS", "question": "Two sound waves have frequencies of 12Hz and 10Hz. Calculate their beat period.", "images": [], "options": {"A": "0.5 s", "B": "1.0 s", "C": "1.2 s", "D": "2.0 s"}, "answer": "A", "explanation": "F1 = 12Hz, F2 = 10Hz    Beat = F2 - F1 (Difference in frequencies)    Beat = 12 - 10 = 2Hz    Period = 1/frequency = 1/2 = 0.5s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>33", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "The main difference between echo and reverberation is that", "images": [], "options": {"A": "reverberation is reflected sound while echo is refracted sound", "B": "the time interval between incident sound and refracted sound is shorter for reverberation", "C": "the amplitude of an echo is greater", "D": "reverberation is from acoustic speakers while echo comes from clifts"}, "answer": "B", "explanation": "Echo and reverberation are both phenomena of sound reflection. The main difference between them is the time interval between the original sound and the reflected sound. If this time interval is longer than 0.1 seconds, our brain can distinguish the original sound and the reflected sound as two separate sounds. This is called an echo. If the time interval is less than 0.1 seconds, our brain cannot distinguish them and perceives it as a prolongation of the original sound. This is called reverberation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>34", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following statements about the electromagnetic waves is correct?", "images": [], "options": {"A": "Radiowaves have longer frequencies than X-rays", "B": "X-rays have the longest wavelength", "C": "Some of the waves travel at 3.0 x 108ms-1", "D": "While light occupies a region beyond ultraviolet rays"}, "answer": "C", "explanation": "All electromagnetic waves, including radio waves and X-rays, travel at the speed of light in a vacuum, which is approximately 3.0 x 108 meters per second. This is a fundamental property of electromagnetic waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>35", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "The correct relationship between \"G\" and \"g\" in a gravitational field is given by the equation (Where the symbols have their unusual meaning)", "images": [], "options": {"A": "g = GM/R", "B": "GM/R2", "C": "g = GM2/R", "D": "g = GM2/R2"}, "answer": "B", "explanation": "Fg = GMm/R2   Fg = mg;   mg = GMm/R2   g = GM/ R2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>36", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The capacitance of a parallel-plate capacitor.", "images": [], "options": {"A": "decreases when the separation between the plates decreases", "B": "increases when he potential difference between the plates is increased", "C": "is greater without a dielectric  material between the plates than with a dielectric", "D": "is greater with a dielectric between the plates than without a dielectric"}, "answer": "D", "explanation": "Capacitance (c) = Aεo / d    where A, εo and d are area, permitivity of dielectric and distance between the plates respectively. As the permittivity increases (which is as a result of an increase in the dielectric), the capacitance increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>37", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTROSTATICS", "question": "When the pointed end of an uncharged optical pin is brought near the cap of a positively charged electroscope, it is observed that the gold leaves", "images": [], "options": {"A": "collapse slowly", "B": "vibrate", "C": "are not affected", "D": "diverge rapidly"}, "answer": "A", "explanation": "When the pointed end of an uncharged optical pin is brought near the cap of a positively charged electroscope, the gold leaves collapse slowly. This is because the uncharged pin induces a negative charge on the cap of the electroscope, which neutralizes some of the positive charge, causing the leaves to collapse slowly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>38", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "Calculate the total charge in the circuit", "images": ["Physics/imgs/2011/HEPDND.png"], "options": {"A": "80µC", "B": "35µC", "C": "20µC", "D": "16µC"}, "answer": "D", "explanation": "Q = CV    Qtotal = CeqXY    2μF // 6μF    CT = 2 + 6 = 8μF    8μF in series with 2μF    1cT=18+12=1016   CT=1610=1.6μC   Qtotal = 1.6 x 10 = 16μC.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>39", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT", "question": "Using the circuit diagram above. Calculate the potential difference across the capacitors in parallel", "images": ["Physics/imgs/2011/HEPDND.png"], "options": {"A": "10.0 V", "B": "8.0 V", "C": "6.7 V", "D": "2.0 V"}, "answer": "D", "explanation": "Q = CV    Voltage across the 2μF capacitance    V=QC=162=8v   Total voltage = 8v + voltage across parallel capacitors.    10 = 8 + x    x = 2v", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>40", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "Which of the following substances does not conduct electricity?", "images": [], "options": {"A": "Graphite", "B": "Glass", "C": "Sulphuric acid", "D": "Table salt solution"}, "answer": "B", "explanation": "Glass does not conduct electricity. It is an insulator, a material that does not allow the flow of electric current. Other options like Graphite, Sulphuric acid, and Table salt solution are conductors of electricity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2011>41", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The unit of capacitance is", "images": [], "options": {"A": "Farad", "B": "Coulomb", "C": "Henry", "D": "Ohm"}, "answer": "A", "explanation": "The unit of capacitance is Farad. Capacitance is the ability of a body to store an electrical charge. It is the ratio of the change in an electric charge in a system to the corresponding change in its electric potential. The standard unit of capacitance in the International System of Units (SI) is the farad (F), which is equal to one coulomb per volt (1 C/V).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2011>42", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "An ammeter with a full scale deflection of 10mA has internal resistance of 0.5Ω. Calculate the resistance of the shunt required to adapt it to read up to 3A.", "images": [], "options": {"A": "0.0017Ω", "B": "0.0130Ω", "C": "0.0250Ω", "D": "0.1000Ω"}, "answer": "A", "explanation": "To convert a galvanometer to an ammeter. A shunt is applied in parallel to the galvanometer. A shunt is applied in parallel to the galvanometer. Which means the voltage of the shunt will be equal to the voltage of the galvanometer.   Vs = Vg    IsRs = IgRg    Is + Ig = I    Is = I - Ig    (I - Ig)Rs = IgRg    Rs = IgRg/(I - Ig)   Rs = (0.01)(0.5)/3 - 0.01 = 0.0017Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>43", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "The resistivity, p, of a material of length l, cross-sectional area A, and resistance R, is given by the equation", "images": [], "options": {"A": "p = RA/l", "B": "p = l/RA", "C": "p = Rl/A", "D": "p = R/Al"}, "answer": "A", "explanation": "R α l    RαlA;   RαlA;R=klA    k = ρ    R=ρlA    RAl=ρ", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>44", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "A wire of length 30 cm is moved with a speed of 2 ms-1 at right angle to a magnetic field of flux density 0.4 T. Calculate the emf induced in the wire.", "images": [], "options": {"A": "0.15 V", "B": "0.24 V", "C": "2.70 V", "D": "24.00 V"}, "answer": "B", "explanation": "Emf = BLVsinθ   v = 2ms-1, l = 0.3m θ = 90o (at right angles) B = 0.47    Emf = (0.4)(0.3)(2)(1)    = (0.8)(0.3) = 0.24 V", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>45", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "Which of the following practices will lead to losses in electrical power transmission?", "images": [], "options": {"A": "using transmission cable to large diameter", "B": "Transmitting at high voltage and low current", "C": "Transmitting at relatively low voltage and high current", "D": "using a step-up transformer at the production end"}, "answer": "C", "explanation": "There will be a loss in the electrical power transmission if the transmission is at a low voltage and high current.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>46", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "For photoelectric emission, the threshold frequency is the", "images": [], "options": {"A": "maximum frequency of incident radiation that will eject electrons.", "B": "minimum frequency of incident radiation required to eject electrons", "C": "frequency which results in the emission of the greatest number of electrons.", "D": "frequency which impacts greatest kinetic energy to emitted electrons"}, "answer": "B", "explanation": "In photoelectric emission, the threshold frequency is the minimum frequency of incident radiation required to eject electrons from a material. This is because each material has a certain minimum energy requirement to remove an electron, and this energy is directly proportional to the frequency of the incident radiation according to Planck's equation (E = hf), where h is Planck's constant and f is the frequency of the radiation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>47", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Which of the following is not applicable to X-ray? They", "images": [], "options": {"A": "travel in straight lines", "B": "travel with speed of light", "C": "are deflected by magnetic field", "D": "affect photographic films"}, "answer": "C", "explanation": "X-rays are a type of electromagnetic radiation, just like light rays, but with a much higher energy level. As such, they travel in straight lines and at the speed of light. They can also affect photographic films, which is why they are used in medical imaging. However, unlike charged particles such as electrons or protons, X-rays are not deflected by magnetic fields because they are electrically neutral.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>48", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Uranium - 234 disintegrated to form thorium-230 by emitting", "images": [], "options": {"A": "alpha particles", "B": "gamma rays", "C": "beta negative rays", "D": "beta positive rays"}, "answer": "A", "explanation": "When alpha particle is emitted by an atom it reduces the mass number by '4' and the atomic number by '2'    23492U → 23090T + 42He", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2011>49", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "The changes in mass of fuel during a nuclear reactions 2.0 x 10-27 kg. Calculate the amount of energy released. (Speed of light = 3.0 x 108ms-1)", "images": [], "options": {"A": "1.8 x 10-10 J", "B": "9.0 x 10-11 J", "C": "6.0 x 10-19 J", "D": "1.2 x 10-45 J"}, "answer": "A", "explanation": "Energy released (E) = mass X    (speed of light in vacuum)2    E = mc2    E = 2 x 10-27 x 9 x 1011    E = 18 x 10-11    E = 1.8 x 101 x 10-11    E = 1.8 x 10-10J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2011>50", "subject": "Physics", "year": "2011", "type": "Objective", "topic": "ENERGY : WORLD ENERGY RESOURCES", "question": "Nuclear fusion is not used as a source of energy because", "images": [], "options": {"A": "very high temperature is needed for the reaction", "B": "the fuel for the reaction is not easy to obtain", "C": "less energy is released", "D": "the reaction is too slow"}, "answer": "A", "explanation": "Nuclear fusion is not used as a source of energy because very high temperature is needed for the reaction.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>1", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "The unit of pressure can be expressed as", "images": [], "options": {"A": "kgms-2", "B": "kgm-1s-2", "C": "kgm-2s-2", "D": "kgm-2s-1"}, "answer": "B", "explanation": "Pressure = Force/Area = MLT-2/L2 = ML-1T-2 = Kgm-1s-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>2", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "The diagram below illustrates trapped air in a syringe placed in water that is gradually heated. It is observed that the piston rises as the temperature of the water rises.   Which of the following statements explains this observation?", "images": ["Physics/imgs/2012/pix.png"], "options": {"A": "Frequency of collision of trapped air molecule with walls of the syringe is more", "B": "Molecules of trapped air expand more", "C": "Number of molecules of trapped air increase", "D": "Speed of the trapped air molecules decrease"}, "answer": "B", "explanation": "The molecules of trapped air expand more causing an increase volume which is the cause of the rise of the piston", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>3", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "Which of the following devices is used to determine the relative density of an acid?", "images": [], "options": {"A": "Manometer", "B": "Hydrometer", "C": "Hypsometer", "D": "Hygrometer"}, "answer": "B", "explanation": "* Hydrometer is the appropriate instrument in the options    * Manometer is used to measure gas pressure.    * Hypsometer is used to measure steam point.    * Hygrometer is used to measure relative humidity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>4", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A block of wood of density 0.6gcm-3, weighing 3.06N in air floats freely in a liquid of density 0.9gcm-3. Calculate the volume of the portion immersed. (g = 10ms2)", "images": [], "options": {"A": "510cm3", "B": "340cm3", "C": "254cm3", "D": "170cm3"}, "answer": "D", "explanation": "Density of the wood = 0.6gcm-3    Weight of the wood in air = 3.06N    Density of liquid = 0.9gcm-3    Mass of wood in air = 0.306kg    Volume of wood in air = mass/ density    =0.306 x 1030.6    = 510cm3    *Volumeofthewoodintheliquid=massdensity=0.306 x 1030.9=340cm3    Volume of the wood immersed = (510 - 340)cm3 = 170cm3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>5", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "A metal ball of weight W falls through a column of glycerin of viscosity V. If the ball experiences an upthrust U and terminal velocity is attained, then", "images": [], "options": {"A": "W > U + V", "B": "W = U + V", "C": "W + U - V", "D": "W"}, "answer": "B", "explanation": "When a ball attains terminal velocity, the net force acting on it is zero. This means that the weight of the ball (W) is balanced by the upthrust (U) and the viscous force (V). Therefore, W = U + V. Hence, the correct option is 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>6", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following substances is the most volatile at room temperature?", "images": [], "options": {"A": "Water", "B": "Diesel", "C": "Petrol", "D": "Kerosene"}, "answer": "C", "explanation": "* Water has hydrogen bond and it is the only polar solvent in the options these make it to be non-volatile.    * Petrol, kerosine and diesel are petroleum products    * Inorder of decreasing volatility.    Diesel → kerosene → Petrol.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>7", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The movement of fluid up or down a narrow tube is", "images": [], "options": {"A": "osmosis", "B": "brownian motion", "C": "capillarity", "D": "diffusion"}, "answer": "C", "explanation": "The movement of fluid up or down a narrow tube is known as capillarity. Capillarity is a phenomenon where liquid rises or falls in a narrow tube due to the surface tension of the liquid and the adhesive interaction between the liquid and the tube material. This is not osmosis (which is the movement of solvent from an area of lower solute concentration to an area of higher solute concentration), brownian motion (which is the random motion of particles suspended in a fluid), or diffusion (which is the movement of particles from an area of higher concentration to an area of lower concentration).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>8", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "A bird flies at 10ms-1 for 3s, 15ms-1 for 3s and 20ms-1 for 4s. Calculate the bird average speed.", "images": [], "options": {"A": "4.5ms-1", "B": "15.0ms-1", "C": "15.5ms-1", "D": "51.7ms-1"}, "answer": "C", "explanation": "Average speed = Total distance / total time taken    Total distance covered = (10 x 3) + (15 x 3) + (20 x 4) = 155m    Total time taken  = 3 + 3 + 4    = 10s   Average speed = 155/10 = 15.5ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>9", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "Which of the following velocity-time graph does not represent an accelerated motion?", "images": ["Physics/imgs/2012/opt1.png", "Physics/imgs/2012/opt2.png", "Physics/imgs/2012/opt3.png", "Physics/imgs/2012/opt4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "* In 'A', dv/dt which is equal to the slope, and the slope which is equal to the acceleration of the body is zero.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>10", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "The time of flight for a projectile motion is given by the expression", "images": [], "options": {"A": "U sinθ/g", "B": "Usinθ/2g", "C": "2U sinθ/g", "D": "U sin 2θ/g"}, "answer": "C", "explanation": "* The time of flight is twice the time taken to reach maximum height (for a body undergoing projectile motion).    * Time taken to reach maximum height (t) is resolved vertically since height is a vertical distance.    Xy = usinθ - gt    at maximum height V = 0    - usinθ = - gt    usinθ = gt    t = usinθ/g    Time of flight (T)    T = 2usinθ/g", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>11", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "An object is dropped from the top of a tower. If it takes 4s for it to reach the ground, calculate the height of the tower.  (g = 10ms-2, ignore air resistance)", "images": [], "options": {"A": "20m", "B": "40m", "C": "80m", "D": "160m"}, "answer": "C", "explanation": "T = &radic;2H/g&nbsp;    parameters given,    g = 10ms-2    T = 4s    U = &radic;2H/10&nbsp;    161=2H10;    2H = 160    H = 80m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>12", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY", "question": "When a body is slightly tilted, it is found that its centre of of gravity is slightly raised. What is that state of equilibrium of the body?", "images": [], "options": {"A": "Unstable", "B": "Stable", "C": "Neutral", "D": "Cannot be determined"}, "answer": "A", "explanation": "The state of equilibrium of the body is unstable.    When a body is in unstable equilibrium, tilting it slightly will cause its center of gravity to rise, which will make it more likely to fall over.    In this case, when the body is tilted slightly, its center of gravity is raised. This means that the body is more likely to fall over if it is tilted further.    The other options are not correct:    A. Stable: In stable equilibrium, tilting the body slightly will cause its center of gravity to fall, which will make it less likely to fall over.  B. Neutral: In neutral equilibrium, tilting the body slightly will not cause its center of gravity to rise or fall.  D. Cannot be determined: The state of equilibrium of the body can be determined by observing how it behaves when it is tilted slightly. In this case, the body is in unstable equilibrium because its center of gravity rises when it is tilted slightly.  Therefore, the answer is A. Unstable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>13", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "A simple pendulum makes 50 oscillation in one minute. Determine its period of oscillation.", "images": [], "options": {"A": "0.04s", "B": "0.83s", "C": "1.20s", "D": "50.00s"}, "answer": "C", "explanation": "Number of oscillations = 50    Time taken = 1 min = 60 secs    Period = Time taken / Number of oscillation    Period = 60/50 = 1.20s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>14", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "The tendency for a stationary body to continue to remain at rest when a force is applied to it is known as", "images": [], "options": {"A": "friction", "B": "impulse", "C": "inertia", "D": "momentum"}, "answer": "C", "explanation": "Inertia is the resistance of any physical object to any change in its velocity. This includes changes to the object's speed, or direction of motion. An aspect of this property is the tendency of objects to keep moving in a straight line at a constant speed, when no forces act upon them. In this case, the body is stationary and it wants to remain at rest when a force is applied, this is due to its inertia.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2012>15", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A resultant force of magnitude 15N acts on a body of mass 250g. Calculate the magnitude of the acceleration.", "images": [], "options": {"A": "0.06ms-2", "B": "3.75ms-2", "C": "16.67ms-2", "D": "60.00ms-2"}, "answer": "D", "explanation": "Force (F) = 15N    Mass(m) = 250g = 0.25kg    F = ma; a=fm=150.25=60ms-2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>16", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A girl stands on a scale in a lift. If the reading on the scale is less than her weight, then the lift is moving.", "images": [], "options": {"A": "upward with uniform speed", "B": "upward with uniform acceleration", "C": "downward with uniform speed", "D": "downward with uniform acceleration"}, "answer": "D", "explanation": "W > T  - In view of the question the body will move downward under gravity    - A body moving under gravity does so at a constant value of acceleration.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>17", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "The S.I unit of heat is", "images": [], "options": {"A": "joule", "B": "kelvin", "C": "watt", "D": "ampere"}, "answer": "A", "explanation": "The SI unit of heat is the Joule. Heat is a form of energy and the SI unit for energy is Joule. Kelvin, Watt and Ampere are units for temperature, power and electric current respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2012>18", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A body is pulled through a distance of 500m by a force of 20N. If the power developed is 0.4kW, calculate the time for which the force acts", "images": [], "options": {"A": "250.0s", "B": "25.0s", "C": "2.5s", "D": "0.5s"}, "answer": "B", "explanation": "Power=EnergyTime=Force x distanceTime    Power = 0.4kw = 400W    Distance = 500m    Force = 20N    400=10000x  x = 25 seconds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>19", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A metal sheet of area 100cm2 was heated through 70oC. Calculate its new area if the linear expansivity of the metal is 0.000017K-1", "images": [], "options": {"A": "100.06cm-2", "B": "100.12cm-2", "C": "100.24cm-2", "D": "100.36cm-2"}, "answer": "C", "explanation": "∝=A2 - A1A1×θ  A2 = A1(1 + βθ)    where β = The area expansivity    θ = Change in temperature.    β = 2α    where α = linear expansivity of the body.    ⇒ β = 2 x 0.000017     = 0.000034 K-1    ∴ A2 = 100 (1 + (0.000034 x 70))    = 100(1 + 0.00238)    = 100(1.00238)    = 100.238 cm²    = 100.24 cm²  (to 2 d.p)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>20", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "The thermopile is a device for detecting", "images": [], "options": {"A": "radioactive radiations", "B": "radiant energy", "C": "X-rays", "D": "the presence of electrons"}, "answer": "B", "explanation": "A thermopile is a device that converts thermal energy into electrical energy. It is often used to detect radiant energy, such as the heat energy emitted by an object. Radiant energy is the energy of electromagnetic waves. The term is most commonly used in the fields of radiometry, solar energy, heating and lighting, but is also used less frequently in other fields like telecommunications.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>21", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "In the formation of sea breeze, wind blows from", "images": [], "options": {"A": "sky to land", "B": "sea to sky", "C": "land to sea", "D": "sea to land"}, "answer": "D", "explanation": "Sea breeze is a wind that blows from the sea towards the land. This happens during the day when the land heats up faster than the sea. The warm air over the land rises, and the cooler air from the sea moves in to replace it, creating a breeze from the sea to the land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>22", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "A piece of copper of mass 20g at a temperature of 1100C was dropped into a mixture of ice and water at 00C. If the final steady temperature of the mixture is 00C, calculate the amount of ice that melted. (Specific heat capacity of copper = 0.4 Jg-1K-1), specific latent heat of fusion of ice = 330 Jg-1)", "images": [], "options": {"A": "0.37g", "B": "0.60g", "C": "2.40g", "D": "2.70g"}, "answer": "D", "explanation": "Heat lost by copper = Heat gained by the ice in melting    MCΔθ = Heat lost by copper    mcΔθ = (20)(0.4)(110-0) = 880    mlf = Heat gained by ice    mlf = m(330) = 330m    800 = 330m    m = 800/330 = 2.70g.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>23", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following factors decreases the rate of evaporation of a liquid?", "images": [], "options": {"A": "increase in pressure over the liquid", "B": "lowering the boiling point", "C": "decreases in humility", "D": "wind"}, "answer": "A", "explanation": "The rate of evaporation of a liquid is influenced by several factors. One of these is the pressure over the liquid. An increase in pressure over the liquid decreases the rate of evaporation. This is because the increased pressure forces more molecules into the liquid, reducing the number of molecules that can escape and evaporate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>24", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "When two waves are superimposed on each other, the following occurrences are possible except", "images": [], "options": {"A": "nodal lines", "B": "anti nodal lines", "C": "stationary waves", "D": "dispersion"}, "answer": "D", "explanation": "When two waves super impose on each other, a point of zero displacement (node) and a point of maximum displacement which is normally unstable (antinode) is formed.    * On a stationary wave we have both node and antinode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>25", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "Which of the following properties of waves is exclusive to transverse waves?", "images": [], "options": {"A": "Reflection", "B": "Interface", "C": "Diffraction", "D": "Polarization"}, "answer": "D", "explanation": "Polarization is a property exclusive to transverse waves. Polarization is the phenomenon in which waves of light or other radiation are restricted in direction of vibration. Longitudinal waves, such as sound waves in air, cannot be polarized. The other options, reflection, interface, and diffraction, are properties that can be exhibited by both transverse and longitudinal waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>26", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "An object of height 2.5cm is placed 20cm from a convex mirror of focal length 10cm. Calculate the height of its image", "images": [], "options": {"A": "2.5cm", "B": "3.0cm", "C": "5.0cm", "D": "25.0cm"}, "answer": "A", "explanation": "Applying the mirror equation    1f=1u-1v(convexmirror)   810=120-1v   110=20+v20v=v-2020v   110=v-2020v   20v = 10v - 200     10v = -200   v = -20cm (at the back of the mirror)    Magnification=image heightobject height=vu    HiHo=vu;   Hi2.5=2020;   Hi = 2.5cm.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>27", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light passes from air to water to glass to air. Given that the refraction index for light passing from air to water is 4/3 and air to glass is 3/2, calculate the refractive index of a glass relative to water.", "images": [], "options": {"A": "0.50", "B": "0.67", "C": "0.75", "D": "1.13"}, "answer": "D", "explanation": "aŋw=43,avg=32  gŋw=aŋgaŋw=32÷43=32x34  =98=1.125≈1.13", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>28", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "An object is placed at a point X between the focal point F and the optical centre C of a diverging lens. If F' is the focal point on the other side of the lens, the image of the object is formed between", "images": [], "options": {"A": "F and X", "B": "X and C", "C": "C and F'", "D": "F' and 2F'"}, "answer": "B", "explanation": "* When an object is placed between F and the optical centre 'c' or pole 'p' of a diverging lens, the image is usually between the object placed at a point X and the pole (p) or optical centre (C) of the lens.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>29", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An object is placed 10cm from a converging lens of focal length 15cm, calculate the magnification of the image formed", "images": [], "options": {"A": "3.0", "B": "1.5", "C": "0.6", "D": "0.3"}, "answer": "A", "explanation": "u = 10cm; f = 15cm, v = ?    1f=1v+1u   115=1v+110   115=10 + v10v    10v = 150 + 15v    10v - 15v = 150    -5v = 150    v = -30cm   M=vu=8010=3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>30", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A telescope is said to be in normal adjustment when the", "images": [], "options": {"A": "focal length of object is greater than that of the eye-piece", "B": "focal length of the eyepiece is greater than that of the objective", "C": "focal length of the eyepiece is equal to that of the objective", "D": "objective focal point coincides with that of the eye-piece."}, "answer": "D", "explanation": "A telescope is said to be in normal adjustment when the final image is at infinity and the rays of light are parallel as they enter the eye. This condition is achieved when the objective focal point coincides with that of the eyepiece. This means that the image formed by the objective lens is at the focal point of the eyepiece lens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>31", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "The sound heard by a person after the reflection of the sound generated by him is called", "images": [], "options": {"A": "reverberation", "B": "resonance", "C": "echo", "D": "audibility"}, "answer": "C", "explanation": "The sound heard by a person after the reflection of the sound generated by him is called an echo. An echo is a reflection of sound that arrives at the listener with a delay after the direct sound. The delay is proportional to the distance of the reflecting surface from the source of the sound and the listener.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2012>32", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Which of the following sets of coloured light is/are secondary colours?  I. Red, Blue and Green   II. Blue, Cyan and Magenta   III. Green, Magenta and Yellow   IV. Yellow, Cyan and Magenta", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "IV only", "D": "I, II and IV only"}, "answer": "C", "explanation": "Secondary colours are produced when two primary colours are mixed    * Red + green = Yellow    Red + blue = Magenta    Green + blue = cyan.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>33", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "Which of the following diagrams correctly illustrates the vibration of air column for second harmonics in an open pipe?", "images": ["Physics/imgs/2012/core1.png", "Physics/imgs/2012/core2.png", "Physics/imgs/2012/core3.png", "Physics/imgs/2012/core4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "For second harmonics, λ = l    In A, l=λ4+λ2+λ4=2λ2=λ", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>34", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "When two like charges are brought together, the potential energy of the system formed will", "images": [], "options": {"A": "increase because work is done against the field", "B": "increase because work is done by the field", "C": "decrease because work is done by the field", "D": "decrease because work is done against the field"}, "answer": "A", "explanation": "Like charges repel each other. Therefore, when two like charges are brought together, work has to be done against the electric field created by the charges. This work done is stored as potential energy in the system. Hence, the potential energy of the system increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>35", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Two capacitors, each of the capacitance 2µf are connected in parallel. If the p.d across them is 120V, calculate the charge on each capacitor", "images": [], "options": {"A": "6.0 x 10-5C", "B": "1.2 x 10-4C", "C": "2.4 x 10-4C", "D": "4.8 x 10-4C"}, "answer": "C", "explanation": "Since they are in parallel    V1 = V2 ; Q = CV    Q1C1=Q2C2    Q = (4μF)(120v)    Q = 480μc    480 - Q22=Q22;   Q1 + Q2 = 480μc    2Q2 = 480    Q2 = 240μc = 2.4 x 10-4c", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>36", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the following properties is an advantage of a lead-acid accumulator over an alkaline accumulator?", "images": [], "options": {"A": "Possesses low internal resistance", "B": "Can be recharged", "C": "has shorter life span", "D": "Possesses higher emf"}, "answer": "A", "explanation": "A lead-acid accumulator has a low internal resistance. This is an advantage because it allows the battery to deliver a high current when needed. Internal resistance is the opposition to the flow of electric current within a battery, causing a voltage drop from the battery's internal source voltage to its terminal voltage, which results in heat generation within the battery. The lower the internal resistance, the less heat generated and the more efficient the battery.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2012>37", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "Six dry cell each of emf 2.0V and internal resistance of 1.0Ω are connected in parallel across a load of 3.0Ω. Calculate the effective current in the circuit", "images": [], "options": {"A": "0.63A", "B": "0.50A", "C": "0.31A", "D": "0.22A"}, "answer": "A", "explanation": "E = 2v (They are in parallel)    R=16=0.166≈0.17   E = I(R + r)    r = 3Ω    2 = I(0.17 + 3)    23.17=I;    I = 0.631A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>38", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Two similar cells are used to light two similar lamps as illustrated in the diagram above. In which of the circuit diagram are the lamps brightest?", "images": ["Physics/imgs/2012/tri1.png", "Physics/imgs/2012/tri2.png", "Physics/imgs/2012/tri3.png", "Physics/imgs/2012/tri4.png"], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "A", "explanation": "In A, the total emf is E1 + E2 also the voltage is the highest in P.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>39", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "A 12Ω resistor dissipate 8kJ of heat in 20s. Calculate the current through the resistor", "images": [], "options": {"A": "5.8A", "B": "6.9A", "C": "30.0A", "D": "33.3A"}, "answer": "A", "explanation": "E = I2RT    E = 8KJ = 8000J    R = 12Ω    T = 20s    8000 = I2 x 12 x 20    I2=8000240    I2 = 33.3    I = &radic;33.3&nbsp;    I = 5.8A", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2012>40", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "A bar magnet is broken in two pieces. Which of the following diagrams are correctly illustrate the polarities of the pieces?", "images": ["Physics/imgs/2012/polar1.png", "Physics/imgs/2012/polar2.png", "Physics/imgs/2012/polar3.png", "Physics/imgs/2012/polar4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "In a bar magnet, there are two opposite poles    * At every point on a bar magnet, there is an attraction due to unlikeness of charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>41", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "The magnetic relay is a device used for", "images": [], "options": {"A": "timing in sport", "B": "storing magnetic field", "C": "reading the magnitude of magnetic flux", "D": "controlling another circuit carrying larger current"}, "answer": "D", "explanation": "A magnetic relay is a type of switch that opens or closes a circuit when a small magnetized current is passed through it. This allows it to control another circuit that carries a larger current. The relay is 'magnetic' because it uses magnetism to create the mechanical movement which opens or closes the switch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>42", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : EDDY CURRENTS", "question": "A core of a transformer is usually laminated in order to", "images": [], "options": {"A": "reduce magnetic flux leakage", "B": "reduce eddy current", "C": "prevent vibration of the transformer", "D": "making magnetic reversal in the core much easier"}, "answer": "B", "explanation": "The core of a transform is usually laminated in order to reduce eddy's current also called induced current as they result in heat loss in the core.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>43", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "Which of the following modes is the most economical method of transmitting electrical power over long distance?", "images": [], "options": {"A": "Alternating current at low voltage and high current", "B": "Alternating current at high voltage and high current", "C": "Alternating current at high voltage and low current", "D": "Direct current at low voltage and high current"}, "answer": "C", "explanation": "The most economical method of transmitting electrical power over long distances is by using alternating current at high voltage and low current. High voltage is used because it reduces the amount of power lost as heat in the transmission lines. Low current is used because it reduces the size (and therefore cost) of the transmission lines.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>44", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "An inductor is connected to a 24V, 50Hz main supply, if the current through the inductor is 1.5A, calculate the inductance of the indicator. (π = 22/7)", "images": [], "options": {"A": "8.0 x 102H", "B": "7.5 x 100H", "C": "1.6 x 100H", "D": "5.1 x 10-2H"}, "answer": "D", "explanation": "XL = 2πfl, f = 50Hz, v = 24v, I = 1.5A   L=VI=241.5=16   XL=2x227x50x16=5.1x10-2H.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>45", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : VECTOR DIAGRAMS", "question": "In a R-C circuit", "images": [], "options": {"A": "Irmsleads Vrms by 60o", "B": "Irms lags Vrmsby 60o", "C": "VrmslagsIrms by 90o", "D": "Vrmsleads Irms by 90o"}, "answer": "D", "explanation": "In an RC (Resistor-Capacitor) circuit, the voltage leads the current by 90 degrees. This is because the capacitor in the circuit causes a phase shift between the voltage and the current.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2012>46", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An atom in an excited state is one whose", "images": [], "options": {"A": "potential energy is minimum", "B": "potential energy is maximum", "C": "electrons are in  the conduction band", "D": "electrons have moved to higher energy level"}, "answer": "D", "explanation": "An atom is said to undergo excitation when its electrons move from a lower energy level to a higher energy level.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>47", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "A metal with a work function of 3.0 eV is irradiated with ultraviolet light of energy 4.0 eV. The kinetic energy of the ejection electron is", "images": [], "options": {"A": "1.0 eV", "B": "3.0 eV", "C": "4.0 eV", "D": "7.0 eV"}, "answer": "A", "explanation": "The kinetic energy of the ejected electron is given by the difference between the energy of the incident light and the work function of the metal. This is based on the photoelectric effect, which states that when light shines on a metal surface, it can transfer energy to electrons. This energy can overcome the work function (the minimum energy needed to remove an electron from a metal surface) and any excess energy becomes the kinetic energy of the ejected electron. Therefore, the kinetic energy of the ejected electron is 4.0 eV - 3.0 eV = 1.0 eV.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>48", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Which of the following statements about X-rays is correct? X-rays", "images": [], "options": {"A": "are produced when a metal surface is irradiated with ultraviolet light", "B": "are produced when a metal target is used to block fast moving electrons", "C": "have long wavelengths and are therefore very penetrating", "D": "are not part of the electromagnetic spectrum"}, "answer": "B", "explanation": "X-rays are produced when a metal target is used to block fast moving electrons according to Wilhelm Roentgen.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>49", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following arrangements of radiation is in the order of decreasing penetrating power?", "images": [], "options": {"A": "∝, β, γ", "B": "∝, γ, β", "C": "β, γ, ∝", "D": "γ, β, ∝"}, "answer": "D", "explanation": "* γ- has the highest penetrating power and can only be stopped with a bad block    * β- has a high penetrating power and can only be stopped by an aluminium foil.    * α- has the lowest penetrating power and can only be stopped with a sheet of paper.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2012>50", "subject": "Physics", "year": "2012", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following radiations emitted in radioactive decay has momentum, a fairly high penetrating power and is deflected by a magnet?", "images": [], "options": {"A": "Alpha particle", "B": "Beta particle", "C": "Gamma radiation", "D": "X-radiation"}, "answer": "B", "explanation": "Beta particles are high-energy, high-speed electrons or positrons emitted by certain types of radioactive nuclei such as potassium-40. They have momentum, a fairly high penetrating power and are deflected by a magnet. Alpha particles, on the other hand, have a lower penetrating power and are also deflected by a magnet, but they are not as penetrating as beta particles. Gamma and X-radiations are electromagnetic waves and do not have momentum or get deflected by a magnet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>1", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The rising of a liquid in an open ended glass tube of narrow bore is", "images": [], "options": {"A": "osmosis", "B": "adhesion", "C": "capillarity", "D": "surface tension"}, "answer": "C", "explanation": "The rising of a liquid in an open-ended glass tube of narrow bore is due to capillarity. Capillarity is the ability of a liquid to flow in narrow spaces without the assistance of, or even in opposition to, external forces like gravity. It occurs because of intermolecular forces between the liquid and surrounding solid surfaces. Osmosis is the spontaneous net movement of solvent molecules through a semi-permeable membrane into a region of higher solute concentration, in the direction that tends to equalize the solute concentrations on the two sides. Adhesion is the tendency of dissimilar particles or surfaces to cling to one another, and surface tension is the elastic tendency of a fluid surface which makes it acquire the least surface area possible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>2", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "Which of the following units is equivalent to the Watt?", "images": [], "options": {"A": "kgm-2", "B": "kgm2s-3", "C": "Kgm2s-2", "D": "kgm-2s-1"}, "answer": "B", "explanation": "Power=EnergyTime=Force x DistanceTime    =MLT-2xLT    = ML2T-3 = kgm2s-3.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>3", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Which of the following statements about pressure in a liquid is correct?", "images": [], "options": {"A": "The pressure in a liquid increases with depth", "B": "The higher the density of a liquid, the lower the pressure it exerts", "C": "Pressure in a liquid acts only in a direction perpendicular to the side of the containing vessel.", "D": "Pressure is independent of the acceleration due to gravity"}, "answer": "A", "explanation": "Pressure in a liquid increases with depth. This is because pressure is defined as the force exerted per unit area. In a liquid, this force is due to the weight of the liquid above the point where the pressure is being measured. Therefore, the deeper you go into the liquid, the more liquid there is above you, and the greater the pressure. The other options are incorrect. The pressure in a liquid is not dependent on the density of the liquid, it does not act only in a direction perpendicular to the side of the containing vessel, and it is not independent of the acceleration due to gravity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>4", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A block of wood of mass 5 kg is pulled on a platform by a force of 40N as illustrated in the diagram above. If the friction force, F experienced by the block is 12N, Calculate the magnitude of the acceleration of the block.", "images": ["Physics/imgs/2013/W6BA7H.png"], "options": {"A": "2.4 ms-2", "B": "5.6 ms-2", "C": "8.0 ms-2", "D": "10.4 ms-2"}, "answer": "B", "explanation": "Netforce = mass x acceleration    (40 - 12) = 5a    28 = 5a    a = 5.6ms-2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>5", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "Solid friction, like viscosity, is", "images": [], "options": {"A": "independent of the surface areas in contact", "B": "independence of the relative motion between layers", "C": "dependent on normal reaction", "D": "in opposition to motion"}, "answer": "D", "explanation": "Viscosity is friction in fluid which acts in opposition to motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>6", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "SPEED AND VELOCITY : CONCEPT OF SPEED", "question": "The slope of linear distance-time graph represents", "images": [], "options": {"A": "acceleration", "B": "displacement", "C": "speed", "D": "velocity"}, "answer": "C", "explanation": "* The slope of any graph (m) = dy/dx or m = Δy/Δx    * The slope of distance - time graph: m = Δx / Δy = Speed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>7", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A body of mass 2 kg is released from rest on a smooth plane inclined at an angle of 60o to the horizontal.   Calculate the acceleration of the body down the plane.  [g = 10 ms-2]", "images": [], "options": {"A": "3.1ms-2", "B": "5.2ms-2", "C": "6.0 ms-2", "D": "8.7 ms-2"}, "answer": "D", "explanation": "* a = gsinθ (if no friction)    * a = 10sin60o = 8.4ms-2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>8", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "The total area under a force-velocity graph represents", "images": [], "options": {"A": "energy", "B": "momentum", "C": "power", "D": "pressure"}, "answer": "C", "explanation": "* The area of any graph is the product of the quantity on the y-axis  and that on the x-axis    * The area of force-velocity graph is the product of force and velocity which is equal to POWER.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>9", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A body of mass 20 g projected vertically upwards in vacuum returns to the point of projection after 1.2s. [g = 10ms-2]     Calculate the speed of projection", "images": [], "options": {"A": "0.6 ms-1", "B": "1.2ms-1", "C": "6.0 ms-1", "D": "12.0 ms-1"}, "answer": "C", "explanation": "Mb(mass of the body) = 20g = 0.02kg    T (time of flight) = 1.2s    t (time taken to reach maximum height) = 0.6s; g = 10ms-2    * t = &radic;2H/g&nbsp;; gt2/2 = H    10x(0.6)2 / 2 = 1.80m    * There is an energy-conversion process: From K.E to P.E    K.E = P.E    1/2mv2 = mgh    v2 = 2gh    v2 = (20)(1.8)    v2 = 36    v = &radic;36&nbsp;    v = 6ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>10", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "A body of mass 20 g projected vertically upwards in vacuum returns to the point of projection after 1.2s. [g = 10ms-2]    Determine the potential energy of the body at the maximum height of its motion", "images": [], "options": {"A": "0.36J", "B": "0.72J", "C": "360.00J", "D": "720.00J"}, "answer": "A", "explanation": "m=20g=0.02kg,T=1.2s  T=2ug  1.2=2u10  2u=12  u=6ms-1  Atmaximumheight,v=0  t=T2=1.22=0.6s  v=u-gt  H=ut-12gt2  =6(0.6)-12×10×0.62  =3.6-1.8  =1.8m  PE=mgh=0.02×10×1.8  =0.36J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>11", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Four co-planar forces of magnitudes 10N, 17N, 6N and 20N act at point O as shown in the diagram above.   Determine the magnitude of the resultant force.", "images": ["Physics/imgs/2013/corel2.png"], "options": {"A": "53.0 N", "B": "21.0 N", "C": "7.0 N", "D": "5.0 N"}, "answer": "D", "explanation": "Net horizontal force (∑fx) = 20 - 17    Net vertical force (∑fg) = 10 - 6    Resultant (R) = &radic;(∑fx)2 + (∑fy)2&nbsp;    R = &radic;32 + 42 &nbsp;    R = &radic;25&nbsp;    R = 5N.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>12", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The maximum displacement on either side of the equilibrium position of an object in simple harmonic motion represents", "images": [], "options": {"A": "period", "B": "amplitude", "C": "wavelength", "D": "frequency"}, "answer": "B", "explanation": "In simple harmonic motion, the maximum displacement from the equilibrium position is known as the amplitude. It is the greatest distance that the object moves from its equilibrium position. Therefore, the correct option is amplitude.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>13", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "From Newton's first law of motion,", "images": [], "options": {"A": "a body can only undergo transitional motion", "B": "once a body remains at rest, no force acts on it", "C": "the net force acting on a body in uniform linear motion is zero", "D": "a body's inertia is its weight"}, "answer": "C", "explanation": "According to the Newtons First Law of Motion, 'a body at rest will continue to be at rest and a body moving with uniform motion will continue to be in this state of motion unless an external impressed force is applied'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>14", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "A body of mass 11kg is suspended from a ceiling by an aluminium wire of length 2m and diameter 2mm. Calculate the elastic energy stored in the wire.  [Young modulus of aluminium is 7.0 x 1010 Nm-2, g = 10ms-2, x = 3.14 ]", "images": [], "options": {"A": "1.1 x 10-1 J", "B": "5.5 x 10-2 J", "C": "1.1 x 10-4 J", "D": "5.5 x 10-5 J"}, "answer": "B", "explanation": "E = FL/Ae ; A = πr2    K.E = 1/2Fe   FlEA=e   e=110x227x1010x3.14x10-6    e = 10 x 10-1m    K.E=12x110x10-3   K.E = 5.5 x 10-2J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>15", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "MACHINES :", "question": "The velocity ratio of an incline plane", "images": [], "options": {"A": "increase with increase in angle of inclination", "B": "increase with decrease in the angle of inclination", "C": "decrease with decrease in the angle of inclination", "D": "is independent of the angle of inclination"}, "answer": "B", "explanation": "The velocity ratio of an inclined plane is the ratio of the effort applied to the load lifted. It is given by the formula 1/sinθ, where θ is the angle of inclination. Therefore, as the angle of inclination increases, the velocity ratio decreases, and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>16", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Which of the following types of thermometers is used for the calibration of other thermometers?", "images": [], "options": {"A": "Liquid-in-glass thermometer", "B": "Constant volume gas thermometer", "C": "optical pyrometer", "D": "Thermocouple"}, "answer": "B", "explanation": "The constant volume gas thermometer is used for the calibration of other thermometers because it is based on the absolute temperature scale, which is independent of the properties of any particular substance. This makes it the most accurate type of thermometer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>17", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The magnitude of the expansion or contraction of a substance depends on the    I. temperature change    II. nature of the substance  III. size of the substance", "images": [], "options": {"A": "I and II only", "B": "II and III only", "C": "I and III only", "D": "I, II and III"}, "answer": "D", "explanation": "This can be deduced from    α=l2 - l1l1Δθ   α (linear expansivity) which varies from one material to the other.    Length(l) which also varies with temperature change (Δθ)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>18", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "High polished silvery surfaces are", "images": [], "options": {"A": "poor absorbers and poor emitter of radiation", "B": "good absorbers and good emitter of radiation", "C": "good absorbers but poor emitters of radiation", "D": "poor absorbers but good emitters of radiation"}, "answer": "A", "explanation": "High polished silvery surfaces are poor absorbers and poor emitters of radiation. This is because they reflect most of the radiation that falls on them, rather than absorbing it. Similarly, they are poor emitters because they do not have many free electrons to emit radiation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>19", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The volume of a given mass of gas at 270C and 800 mmHg is 76 cm3. Calculate its volume at s.t.p", "images": [], "options": {"A": "10.0 cm3", "B": "72.8 cm3", "C": "60.0 cm3", "D": "36.4 cm3"}, "answer": "B", "explanation": "From the general gas equation   P1V1T1=P2V2T2    P1 = 800mmHg, P2 = 760mmHg, V1 = 76cm3, V2 = ? T1 = 27 + 273 = 300k, T2 = 273k    800 x 76300=760 x V2273   8 x 763=760V2273    81=10V291   V2=72810=72.8cm3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>20", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "The outlet of a bicycle pump is used to inflate a football. Why does the pressure of the air inside the pump increase as the pump handle is slowly pushed downward at constant temperature?", "images": ["Physics/imgs/2013/corel20.png"], "options": {"A": "Momentum of the air molecules are increased", "B": "volume occupied by the molecules are increased", "C": "frequency of collision of the air molecules with the walls of the pump is increased", "D": "molecules are colliding with one another in the system."}, "answer": "C", "explanation": "frequency of collision of the air molecules with the walls of the pump is increased", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>21", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Ice of mass 10g at -5oC was completely converted to water at 0oC. Calculate the quantity of heat used.  [Specific heat capacity of ice = 2.1 Jg-1K-1; specific latent heat of fusion of ice = 336Jg-1]", "images": [], "options": {"A": "105J", "B": "3255J", "C": "3465J", "D": "16821J"}, "answer": "C", "explanation": "Total heat used = Specific heat capacity of ice + latent heat of fusion of ice    SHC of ice = mcΔθ    = (10)(2.1)(5) = 105    LHF of ice = mlf    = (10)(336) = 3360    Total heat = 105 + 3360 = 3465J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>22", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "An electric heater has a resistance of 50Ω. When it is immersed in water and connected  to main source, it draws a current of 4A. Calculate the heat gained by the water if the heater is switched on for 2 minutes, assuming no heat losses to the surroundings", "images": [], "options": {"A": "400 J", "B": "1600 J", "C": "24000 J", "D": "96000 J"}, "answer": "D", "explanation": "Heat gained by the water = I2Rt    I = 4.0A, t = 2 minutes = 120seconds, R = 50Ω    H = I2RT = 42 x 50 x 120 = 96000J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>23", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "When salt is dissolved in water, the freezing point of the water", "images": [], "options": {"A": "increases", "B": "decreases", "C": "remains the same", "D": "increase and later decreases"}, "answer": "B", "explanation": "When salt is dissolved in water, it disrupts the structure of the water molecules and makes it harder for them to form the ordered structure necessary for freezing. This means that the freezing point of the water decreases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>24", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "The diagram above illustrates a waveform. Which of the points on the waveform are in phase?", "images": ["Physics/imgs/2013/core3.png"], "options": {"A": "P and R", "B": "R and T", "C": "P and T", "D": "Q and S"}, "answer": "C", "explanation": "P and T are in phase as the angular displacement from P to T is 2 π", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>25", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The equation of a certain progressive transverse wave is y = 2 sin 2π (1/0.01 - x/30). Where x and y are in cm, and t in seconds, calculate the period of the wave.", "images": [], "options": {"A": "0.001s", "B": "0.010s", "C": "10.000s", "D": "100.000s"}, "answer": "B", "explanation": "Given,    y=2sin2π(t0.01-x30)    Fromy=Asin2π(tF-xλ)    tT=t0.01    T = 0.01secs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>26", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "At which equation position should an object be placed in front of a concave mirror in order to obtain an image which is of the same size as the object?", "images": [], "options": {"A": "At the centre of curvature", "B": "At the principal focus", "C": "Between the pole and the principal focus", "D": "Between the centre of curvature and the principal focus"}, "answer": "A", "explanation": "An object placed on the centre of curvature of a concave mirror will produce an image of unit magnification; i.e the image size is the same as the object size.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>27", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "Images formed by a convex mirror are always", "images": [], "options": {"A": "magnified", "B": "behind the mirror", "C": "real", "D": "inverted"}, "answer": "B", "explanation": "A convex mirror, also known as a diverging mirror, always forms images that are virtual, upright, and reduced in size. This is because the light rays never actually meet, but rather they diverge upon reflection. Therefore, the image appears to be located behind the mirror.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>28", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The refractive index of a material is 1.5. Calculate the critical angle at the glass-air interface.", "images": [], "options": {"A": "190", "B": "210", "C": "390", "D": "420"}, "answer": "D", "explanation": "n=sinCsin90o   1.5=11.5=sinC1     c = sin-1(0.667)    c = 42o.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>29", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "A diverging lens of focal length 30cm produces an image 20cm from the lens. Determine the object distance", "images": [], "options": {"A": "10cm", "B": "12cm", "C": "50cm", "D": "60cm"}, "answer": "B", "explanation": "Since it's a diverging lens (concave) the image will be virtual. Hence the mirror equation becomes    1f=1u-1v      f = 30cm, v = 20cm    130=1u-120   130=20 - u20u   20u = 600 - 30 u    50U = 600    U = 12cm.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>30", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following statements about the Galilean telescope is not correct?", "images": [], "options": {"A": "The final image is inverted", "B": "It is shorter than terrestrial telescope", "C": "The final image is erect", "D": "It has a small field of view"}, "answer": "A", "explanation": "The Galilean telescope, which uses a convex objective lens and a concave eyepiece, produces an erect (upright) image, not an inverted one. Therefore, the statement 'The final image is inverted' (option 1) is not correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>31", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following radiation has its frequency lower than that of infra-red radiation?", "images": [], "options": {"A": "Ultra-violet rays", "B": "Gamma rays", "C": "X-rays", "D": "Radio waves"}, "answer": "D", "explanation": "The electromagnetic spectrum is the range of all types of EM radiation. Radiation is energy that travels and spreads out as it goes – visible light or light that we can see is one type of EM radiation. Other types of EM radiation that make up the electromagnetic spectrum are microwaves, infrared light, ultraviolet light, X-rays and gamma-rays. The order of the spectrum based on increasing frequency is: Radio waves, Microwaves, Infrared, Visible light, Ultraviolet, X-rays, Gamma rays. Therefore, the radiation with frequency lower than that of infra-red radiation is Radio waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>32", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "A string under tension produces a note of frequency 14 Hz. Determine the frequency when the tension is quadrupled.", "images": [], "options": {"A": "14Hz", "B": "18Hz", "C": "28Hz", "D": "56Hz"}, "answer": "C", "explanation": "F = 1/2l&radic;T/U&nbsp;    Keep all other factors constant    F = K&radic;T&nbsp;, F1 = 14; F2 = ?    T1 = T1   T2 = 4T1   K = F/&radic;T&nbsp;;    K1 = K2 ,   F1/&radic;T1&nbsp; = F2/&radic;T2&nbsp;   14/F2 = &radic;T1/4T1&nbsp;    14/F2 = &radic;1/4&nbsp;    14/F2 = 1/2    F2 = 28Hz.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>33", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "Which of the following statements about waves in pipes is correct?", "images": [], "options": {"A": "For open pipes, there is only one end correction to be accounted for", "B": "For close closed pipes, there are two end corrections to be accounted for", "C": "Only odd harmonics are possible in closed pipes", "D": "All harmonics are possible in closed pipes"}, "answer": "C", "explanation": "In a closed pipe, only odd harmonics are possible. This is because the pipe is closed at one end, which forces the wave to have a node (point of no displacement) at that end. At the open end, the wave must have an antinode (point of maximum displacement). This pattern of nodes and antinodes means that only odd harmonics, which have a node at one end and an antinode at the other, can exist in the pipe.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>34", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "When a person holds a negative charged metal rod and stands bare-footed on the ground, how will the charges leak?", "images": [], "options": {"A": "Negative charges flows to the ground through the person's body", "B": "positive charges flows from the ground through his body to neutralize the genitive charges", "C": "Positive charges in the air neutralizes the negative charges the person is holding", "D": "Negative charges will leak through the air"}, "answer": "A", "explanation": "When a person holds a negatively charged metal rod and stands bare-footed on the ground, the negative charges will flow to the ground through the person's body. This is because the ground is a good conductor and provides a path for the charges to move. This is a basic principle of electrostatics, where like charges repel and unlike charges attract. The negative charges on the rod will be attracted to the positive charges in the ground, causing a flow of charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>35", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "A charge of 2.0 x 10-5C experience a force of 80 N in a uniform electric field. calculate the magnitude of the electric field intensity.", "images": [], "options": {"A": "8.0 x 106 NC-1", "B": "4.0 x 106 NC-1", "C": "4.0 x 104 NC-1", "D": "2.0 x 104 NC-1"}, "answer": "B", "explanation": "ElectricIntensity=ForceCharge    Force (F) = 80N    Charge(Q) = 2 x 10-5C    E=802x10-5=40x105=4x106N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>36", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "An electric circuit is connected as illustrated below. Determine the equivalent emf and current flowing through the circuit respectively, neglecting the internal resistance of the cells.", "images": ["Physics/imgs/2013/corel3.png"], "options": {"A": "2 V, 1.0 A", "B": "2 V, 4.0 A", "C": "6 V, 0.3 A", "D": "6 V, 3.0 A"}, "answer": "A", "explanation": "For parallel connection, the equivalent voltage is = 2v    r = 0; R = 2Ω    E = IR    2 = I(2)    I = 1.0A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>37", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "A potential difference of 12 V is applied across the ends of a 6Ω resistor for 10 minutes. Determine the quantity of heat generated.", "images": [], "options": {"A": "720 J", "B": "1200 J", "C": "14400 J", "D": "43200 J"}, "answer": "C", "explanation": "The quantity of heat generated in a resistor can be calculated using the formula Q = I^2Rt, where Q is the heat, I is the current, R is the resistance, and t is the time. However, we don't have the current, but we have the potential difference (V) and the resistance (R). Ohm's law states that I = V/R. Substituting this into the heat formula gives Q = V^2/R * t. Substituting the given values, we get Q = (12V)^2 / 6Ω * 10*60s = 14400 J. Therefore, the quantity of heat generated is 14400 J.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>38", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "A galvanometer of internal resistance of 10Ω has a full scale deflection with a current of 10 mA. Calculate the magnitude of the resistance required to convert it to a voltmeter capable of measuring up to 3V.", "images": [], "options": {"A": "290Ω", "B": "300Ω", "C": "333Ω", "D": "1000Ω"}, "answer": "A", "explanation": "VmRm=VgRg;   ImRmRm=IgRgRg  3Rm=0.01;Rm=300Ω   Resistance required = 300 - 10 = 290Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>39", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the following instruments is used to determine the accurate value of the electromotive force of a cell?", "images": [], "options": {"A": "Voltmeter", "B": "Meter bridge", "C": "voltameter", "D": "potentiometer"}, "answer": "D", "explanation": "The emf of a cell can be measured with a potentiometer which compares the unknown emf with the emf of a standard cell.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>40", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "The direction of motion of a current-carrying conductor placed within the opposite poles of a magnet is determined using", "images": [], "options": {"A": "Fleming's left-hand rule", "B": "Fleming's right-hand rule.", "C": "Maxwell's corkscrew rule", "D": "Ampere's rule"}, "answer": "A", "explanation": "Fleming's left-hand rule is used to find the direction of force experienced by a current-carrying conductor in a magnetic field. The thumb, forefinger and middle finger are held at right angles to each other. The forefinger points in the direction of the magnetic field (North to South), the middle finger points in the direction of the current (positive to negative), and the thumb shows the direction of the force or motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>41", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "Two straight current carrying conductors are placed near each other, which of the following diagrams correctly illustrate the magnetic field pattern formed by the conductors?", "images": ["Physics/imgs/2013/opt1.png", "Physics/imgs/2013/opt2.png", "Physics/imgs/2013/opt3.png", "Physics/imgs/2013/opt4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The diagram that correctly illustrate the magnetic field pattern formed by the conductors is:", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>42", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The capacitance of parallel plates capacitors varies", "images": [], "options": {"A": "inversely as the square of the distance between the plates", "B": "directly as the square of the distance between the plates", "C": "inversely as the distance between the plates", "D": "directly as the distance between the plates"}, "answer": "C", "explanation": "- Capacitance (C) α Area (A)    - Capacitance (C) α εo - Permittivity     -Capacitance(C)α1distance(d)    C=Aεod.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>43", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "Which of the following devices works on the principle of electromagnetic induction?", "images": [], "options": {"A": "Carbon microphone", "B": "Electric heater", "C": "Moving iron ammeter", "D": "Simple d.c. motor"}, "answer": "D", "explanation": "A simple d.c. motor works on the principle of electromagnetic induction. Electromagnetic induction is the production of an electromotive force across an electrical conductor in a changing magnetic field.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>44", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : EDDY CURRENTS", "question": "Which of the following devices doesn't make use of eddy current for its action? A/An", "images": [], "options": {"A": "galvanometer", "B": "speedometer", "C": "induction furnace", "D": "induction coil"}, "answer": "A", "explanation": "A galvanometer does not make use of eddy currents for its action. Eddy currents are loops of electrical current induced within conductors by a changing magnetic field in the conductor due to Faraday's law of induction. Galvanometers measure electric current, they do not rely on eddy currents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>45", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "A coil of inductance 0.12 H and resistance 4 Ω, is connected across a 240v, 50Hz supply. Calculate the current through it [π = 3.14]", "images": [], "options": {"A": "6.3 A", "B": "33.3 A", "C": "37.2 A", "D": "40.0 A"}, "answer": "A", "explanation": "Recall that: XL = 2πfL    XL = 2 x 3.14 x 50 x 0.12 = 37.68   I=VLXL=24037.68=6.3A.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>46", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "The work function of a metal is 2.56 × 10-19J. Calculate the frequency of a photon whose energy is required to eject from the metal an electron with a kinetic energy of 3.0eV.  [1eV = 1.6 x 10-19J; h = 6.6 x 10-34Js]", "images": [], "options": {"A": "5.56 x 1019Hz", "B": "1.66 x 1019Hz", "C": "1.12 x 1015Hz", "D": "8.42 x 1014Hz"}, "answer": "C", "explanation": "E = 3eV    1eV = 1.6v x 10-19J    E = 4.8 x 10-19J    Work function = 2.56 x 10-19J    Frequency(f) = ?    f = E+W / h    f = 4.8 x 10-19 + 2.56 x 10-19 / 6.6 x 10-34    f=7.36 x 10-196.6 x 10-34    f = 1.12 x 1015Hz.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2013>47", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "The minimum energy required to cause photoelectric emission when the surface of a metal is irradiated with electromagnetic radiation of suitable frequency is called", "images": [], "options": {"A": "critical energy", "B": "ionization energy", "C": "work function", "D": "planck's constant"}, "answer": "C", "explanation": "The minimum energy required to cause photoelectric emission when the surface of a metal is irradiated with electromagnetic radiation of suitable frequency is called the work function. The work function is a property of the material of the metal and is the minimum energy required to remove an electron from the metal surface.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>48", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "Which of the following particles are termed nucleons in a neutral atom?", "images": [], "options": {"A": "Protons and neutrons", "B": "Neutrons and electrons", "C": "protons and electrons", "D": "protons, electrons and neutrons"}, "answer": "A", "explanation": "* Nucleus is usually concentrated with protons and neutrons.    * Protons and Neutrons are generally termed 'nucleons' - meaning \"Nucleus particles\"", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2013>49", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following statements about the use of radioisotopes is not correct? They are used to", "images": [], "options": {"A": "induce mutations in plants and animals to obtain new and improved varieties", "B": "trace the paths of metabolic processes in plants and animals", "C": "estimate the age of rocks", "D": "locate broken bones"}, "answer": "D", "explanation": "Radioisotopes are used in a variety of applications in medical, industrial, and scientific fields. They are used to induce mutations in plants and animals to obtain new and improved varieties, trace the paths of metabolic processes in plants and animals, and estimate the age of rocks. However, they are not used to locate broken bones. Instead, X-rays, which are a form of electromagnetic radiation, are commonly used to image bones and identify fractures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2013>50", "subject": "Physics", "year": "2013", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Which of the following phenomena supports the theory that waves have a particles nature?", "images": [], "options": {"A": "Electron diffraction", "B": "Photoelectric effect", "C": "Diffraction of light", "D": "X-ray interference"}, "answer": "B", "explanation": "The photoelectric effect is a phenomenon that supports the theory that waves have a particle nature. This effect refers to the emission of electrons when light is shone onto a material. It can only be explained if light is considered to be composed of particles, because it is as if these 'light particles' are knocking the electrons out of the material. This cannot be explained if light is considered purely as a wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>1", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "A ball falling through a viscous liquid is acted upon by", "images": [], "options": {"A": "Upthrust only", "B": "Upthrust and the ball's weight", "C": "The ball's weight and viscous force", "D": "Upthrust, the ball's weight and viscous force"}, "answer": "D", "explanation": "The body is acted upon by three forces.    Its weight which acts downward    The upthrust and viscous force acts upward.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>2", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "An object of mass m moves with a uniform speed v round a circular path of radius r. If its angular speed is w, the magnitude of the centripetal force acting on it is", "images": [], "options": {"A": "mw2r", "B": "mv2/r", "C": "mwr", "D": "mv2/r2"}, "answer": "B", "explanation": "Centripetal force (F) = mass x centripetal acceleration    Centripetal acceleration (ac) = V2/r    F=mv2r", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>3", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY", "question": "When an elastic material is stretched by a force, the energy stored in it is", "images": [], "options": {"A": "kinetic", "B": "potential", "C": "thermal", "D": "electrical"}, "answer": "B", "explanation": "When an elastic material is stretched by a force, the energy stored in it is potential energy. This is because the work done in stretching the material is stored as potential energy within the material. If the material is released, this stored energy can be converted into kinetic energy as the material returns to its original shape.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>4", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "If no net force acts on an objects, the object maintains a state of rest or constant speed in a straight line. The above is a statement of Newton's", "images": [], "options": {"A": "first law of motion", "B": "second law of motion", "C": "third law of motion", "D": "law of universal gravitation"}, "answer": "A", "explanation": "Newton's first law of motion an object at rest will remain at rest and a body moving with uniform motion in a straight line will continue to be in this position (state) unless an external force is applied.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>5", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "Which of the velocity-time graphs below correctly describes the motion of a body by a force that is equal to the frictional force acting on it?", "images": ["Physics/imgs/2014/opt1.png", "Physics/imgs/2014/opt2.png", "Physics/imgs/2014/opt3.png", "Physics/imgs/2014/opt4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "The net force on the body is zero. Hence, the acceleration is 0.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>6", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "When the linear momentum of a body is constant, the net force acting on it", "images": [], "options": {"A": "is zero", "B": "increases", "C": "decreases", "D": "remain constant"}, "answer": "A", "explanation": "According to the  law of conservation of momentum when the momentum is constant, the net force is zero.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>7", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Which of the following pairs of physical quantities is made up of vectors?", "images": [], "options": {"A": "Speed and displacement", "B": "Mass and force", "C": "Displacement and acceleration", "D": "Momentum and length"}, "answer": "C", "explanation": "Vectors are quantities that have both magnitude and direction. Displacement and acceleration are both vector quantities because they both have magnitude (size) and direction. Speed and mass are scalar quantities (only have magnitude), while length is also a scalar quantity and momentum is a vector quantity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>8", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The knowledge of surface tension is applied in the following areas except in", "images": [], "options": {"A": "manufacturing of rain coasts", "B": "production of palm oil", "C": "floating of a needle in water", "D": "washing of plate with soapy water"}, "answer": "B", "explanation": "The knowledge of surface tension is not usually applied in production of palm oil.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>9", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A body is projected vertically upwards with a speed of 10ms-1 from a point 2m above the ground. Calculate the total time taken for the body to reach the ground.  [g = 10ms-2]", "images": [], "options": {"A": "1.00s", "B": "2.00s", "C": "2.18s", "D": "3.00s"}, "answer": "C", "explanation": "/AB/=U22g=H   10020=5m   TimetoreachA=T=&radic;2Hg&nbsp;=&radic;1010&nbsp;=1sec    From A to C = /AB/ + /BC/    = 5 + 2 = 7m    TimetofallfromAtoC=T=&radic;2(7)10&nbsp;=&radic;1410&nbsp;=&radic;1.4&nbsp;=1.18    Total time = 1 + 1.18 = 2.18 seconds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>10", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A car starts from rest and covers a distance of 40m in 10s. Calculate the magnitude of its acceleration.", "images": [], "options": {"A": "0.25ms-2", "B": "0.80ms-2", "C": "3.20ms-2", "D": "4.00ms-2"}, "answer": "B", "explanation": "s=ut+12at2    40=0(t)+12xax(10)2    40=12xax100    80 = 100a    a = 0.80ms-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>11", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above illustrates a uniform metre rule which is balanced on a pivot by some masses. Calculate the value of M.", "images": ["Physics/imgs/2014/core1.png"], "options": {"A": "500.0g", "B": "400.0g", "C": "44.4g", "D": "25.0g"}, "answer": "D", "explanation": "Taking moment about the pivot    M x 40 = 100 x 10    40m = 1000    m = 25g.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>12", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The period of a simple pendulum X is 5s. What is the period of a simple pendulum Y which makes 50 vibrations?", "images": [], "options": {"A": "12.5s", "B": "2.5s", "C": "2.0s", "D": "1.2s"}, "answer": "A", "explanation": "T=nt    t=nT    tx = ty    nxTx=nyTy   205=50Ty   20Ty = 250    Ty = 12.5s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>13", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "Alcohol of mass 21g and density 0.7gcm-3 is mixed with 10g of water. Determine the density of the mixture.  [Density of water = 1.0gcm-3]", "images": [], "options": {"A": "0.775gcm-3", "B": "0.780gcm-3", "C": "0.875gcm-3", "D": "0.880gcm-3"}, "answer": "A", "explanation": "Densityofamixture=mass of the mixtureVolume of the mixture   Mass of the alcohol = 21g    Density of the alcohol = 0.7gcm-3    Density=massvolume;volume=massdensity=210.7=30cm3    Volumeofwater=mass of waterDensity of water=101=10cm3   Densityofthemixture=21+1040=3040=0.775gcm-3", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>14", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "A device that convert mechanical energy into electrical energy is", "images": [], "options": {"A": "a dynamo", "B": "an electric motor", "C": "an induction coil", "D": "a transformer"}, "answer": "A", "explanation": "A dynamo is a device that converts mechanical energy into electrical energy. This is done by rotating a coil in a magnetic field, which induces a current in the coil. An electric motor, on the other hand, converts electrical energy into mechanical energy. An induction coil and a transformer both work on the principle of electromagnetic induction, but they do not convert mechanical energy into electrical energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>15", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "The SI unit of power is", "images": [], "options": {"A": "N", "B": "Pa", "C": "W", "D": "J"}, "answer": "C", "explanation": "The SI unit of power is the Watt (W). Power is the rate at which work is done or energy is transferred. It is equal to the work done per unit time. In the International System of Units (SI), the unit of power is the watt (W), which is equal to one joule per second.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>16", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MACHINES :", "question": "A screw-jack has the distance between its successive threads as P and the length of its tommy bar as r. Its velocity ratio is given by the expression", "images": [], "options": {"A": "2πr2/P", "B": "2πr/P", "C": "2π/rP", "D": "P/2πr"}, "answer": "B", "explanation": "The velocity ratio of a screw jack is given by the expression 2πr/P. The velocity ratio of a machine is the ratio of the distance moved by the effort to the distance moved by the load. For a screw jack, the distance moved by the effort is the circumference of the circle described by the tommy bar (2πr), and the distance moved by the load is the pitch of the screw (P).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>17", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "Heat transfer by conduction is similar to wave motion because", "images": [], "options": {"A": "there is increase in temperature", "B": "transfer of materials is involved", "C": "charged particles vibrate at right angles", "D": "no transfer of materials is involved"}, "answer": "D", "explanation": "Heat transfer by conduction is similar to wave motion because no transfer of materials is involved. In conduction, heat is transferred from molecule to molecule within a substance without any movement of the substance as a whole. This is similar to wave motion where energy is transferred from particle to particle within the medium without any net movement of the medium itself.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>18", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY AND THE WEATHER", "question": "The temperature at which the water vapour in the air saturates the air and begins to condense is known as", "images": [], "options": {"A": "dew point", "B": "critical point", "C": "boiling point", "D": "triple point"}, "answer": "A", "explanation": "Dewpoint is the temperature at which the water vapour in the air saturates the air and begins condense.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>19", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : MELTING POINT", "question": "The change of state from solid to liquid occurs", "images": [], "options": {"A": "at constant temperature", "B": "when temperature is lower than the boiling point", "C": "when temperature is just near freezing point", "D": "when temperature is equal to the boiling point"}, "answer": "A", "explanation": "The change of state from solid to liquid, also known as melting, occurs at a constant temperature. This is because the energy supplied is used to overcome the forces of attraction between the particles of the solid, rather than to increase the kinetic energy of the particles. Therefore, the temperature remains constant until all the solid has melted.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>20", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Which of the following types of thermometers can be used to measure a range of temperatures from -50oC to 50oC?   I. Clinical   II. Mercury-in-glass  III. Alcohol-in-glass", "images": [], "options": {"A": "I only", "B": "II only", "C": "III only", "D": "I and II only"}, "answer": "C", "explanation": "Alcohol-in-glass thermometers can be used to measure a range of temperatures from -50 degrees Celsius to 50 degrees Celsius. This is because alcohol has a lower freezing point and a higher boiling point than mercury, making it suitable for measuring a wider range of temperatures. Clinical thermometers and mercury-in-glass thermometers have a more limited range and are not suitable for measuring such low temperatures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>21", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A body of mass Mkg rest on a plan inclined at an angle θ to the horizontal. The component of the weight of the body parallel to the plane is", "images": [], "options": {"A": "Mg sin θ", "B": "Mg cos θ", "C": "Mg tan θ", "D": "Mg sec θ"}, "answer": "A", "explanation": "The component of the weight of a body parallel to an inclined plane is given by the formula Mg sin θ, where M is the mass of the body, g is the acceleration due to gravity, and θ is the angle of inclination. This is because the weight of the body acts vertically downwards, and the component parallel to the plane is the projection of this weight along the direction of the plane.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>22", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "A quantity of water 20oC is mixed with another quantity  of water at 70oC. The final steady temperature of the mixture is 40oC. Determine the ratio of the cold water to that of the hot water.", "images": [], "options": {"A": "7:2", "B": "3:2", "C": "2:5", "D": "1:2"}, "answer": "B", "explanation": "Heat lost by the hot water = Heat gained by the cold water.    MHCHΔθH = MCΔθC    Let CH = CC    mHΔθH = mCΔθC    (Δθ)H = 70 - 40 = 30oC    (Δθ)C = 40 - 20 = 20oC    mH30 = mC20   mCmH=32", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>23", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The mass of an empty density bottle is 30g. When filled with a liquid, the mass of the bottle and the liquid is 40g. On heating the filled through 400C, the mass reduces to 38g. Calculate the apparent cubic expansibility of the liquid.", "images": [], "options": {"A": "6.25 x 10 K-1", "B": "6.25 x 10-3 K-1", "C": "2.25 x 10-3 K-1", "D": "2.50 x 10-4 K-1"}, "answer": "B", "explanation": "Mass of the liquid = 40g - 30g = 10g    Mass of the liquid expelled = 10g - 8g = 2g    Mass of the liquid remaining = 8g, Temperature rise = 40oC    Apparentcubicexpansivity=Mass expelledMass remainingxtemp.rise    =28x40=6.25x10-3kgoC-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>24", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A car travelling at 30ms-1 overcomes a frictional resistance of 100N while moving. Calculate the power developed by the engine. [1 hp = 0.75kW]", "images": [], "options": {"A": "0.23hp", "B": "0.40 hp", "C": "4.00 hp", "D": "4.40 hp"}, "answer": "C", "explanation": "Power = Force x velocity    Power = 100 x 30 = 3000W = 3KW    1hp = 0.75KW    xhp = 3KW    0.75x = 3   x = 4hp", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>25", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "The quality of a note depends on its", "images": [], "options": {"A": "frequency", "B": "pitch", "C": "overtones", "D": "amplitude"}, "answer": "C", "explanation": "The quality of a note depends on its overtones.    Overtones are additional frequencies present in a sound wave along with the fundamental frequency. The combination of these overtones determines the unique timbre or quality of a sound. Different instruments and voices produce different combinations of overtones, which is why a note played on a violin sounds different from the same note played on a flute.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>26", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "A transverse wave can be distinguished from a longitudinal wave by", "images": [], "options": {"A": "diffraction", "B": "reflection", "C": "refraction", "D": "polarization"}, "answer": "D", "explanation": "A transverse wave can be distinguished from a longitudinal wave by polarization. Polarization is a property of waves that can oscillate with more than one orientation. Transverse waves can be polarized while longitudinal waves cannot be polarized. Therefore, the correct answer is polarization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>27", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "PROPERTIES OF WAVES : INTERFERENCE", "question": "The superposition of waves to produce maximum or zero effect at a point is known as", "images": [], "options": {"A": "reflection", "B": "refraction", "C": "interference", "D": "diffraction"}, "answer": "C", "explanation": "Interference is the mixing up of two or more waves to produce another wave. This point of zero displacement is the node and the point of maximum displacement is the antinode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>28", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Refraction of light differs from reflection in that, in refraction   I. at least two media are involved   II. there is a change in the direction of the ray  III. the speed of the ray changes", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "II and III only", "D": "I and III only"}, "answer": "D", "explanation": "The key difference between refraction and reflection is that, in refraction:    I. At least two media are involved, as light passes from one medium to another.  III. The speed of the light ray changes as it moves between media with different optical densities.    While a change in direction (II) occurs in both refraction and reflection, the speed change is unique to refraction, making it the more distinct point of difference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>29", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following relation about the focal length fo of the object and focal length fe of the eye piece of a compound microscope is correct?", "images": [], "options": {"A": "fo = fe", "B": "fo > fe", "C": "fo e", "D": "fe = 2fo"}, "answer": "B", "explanation": "In a compound microscope, the objective focal length (fo) is less than the focal length of the eye-piece (fe).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>30", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The functional difference between a lens and a mirror is that a lens", "images": [], "options": {"A": "reflects a beam of light while a mirror refracts it", "B": "refract a beam of light while a mirror reflects it", "C": "absorbs incident rays while a mirror transmit them", "D": "transmit incident rays while a mirror absorbs them"}, "answer": "B", "explanation": "Lens are refracting materials, i.e they usually refract rays of light (beam) while mirrors are reflecting materials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>31", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "The diagram above illustrates an electromagnetic wave travelling with speed 3.0 x 108 ms-1. Calculate the wave length of the wave.", "images": ["Physics/imgs/2014/arrow.png"], "options": {"A": "0.05m", "B": "0.15m", "C": "0.16m", "D": "0.40m"}, "answer": "C", "explanation": "From the diagram    5λ2=0.4    λ=0.85=0.16   Hence, wavelength λ = 0.16m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>32", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "An observer hears an echo 1.26 seconds after blowing a whistle near a cliff. Calculate the distance of the observer from the cliff. [Speed of sound in air = 330 ms-1]", "images": [], "options": {"A": "104.0m", "B": "207.9m", "C": "415.8m", "D": "523.8m"}, "answer": "B", "explanation": "v=2xt    330=2x1.26   2x = 330 x 1.26    x = 165 x 1.26 = 207.9m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>33", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A fish inside a pond appears to be at a depth of 1.5m when viewed vertically from  above. The refractive index of the water in the pond is 1.3. Calculate the apparent displacement of the fish.", "images": [], "options": {"A": "2.50m", "B": "1.95m", "C": "1.50m", "D": "0.45m"}, "answer": "D", "explanation": "Refractiveindex=Real depthApparent depth=Apparent depth + Apparent displacementApparent depth   1.3=1.5+Apparent displacement1.5    1.95 = 1.5 + Apparent displacement    Apparent displacement = 1.95 - 1.5 = 0.45m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>34", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An object is placed in front of the two plane mirrors inclined at 60o to each other. Determined the number of images formed", "images": [], "options": {"A": "2", "B": "3", "C": "5", "D": "7"}, "answer": "C", "explanation": "numberofImages=360θ-1   θ = 60o    n=36060-1    n = 6 - 1 = 5 images.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>35", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "An ammeter can be adapted to measure potential difference by using a", "images": [], "options": {"A": "shunt", "B": "multiplier", "C": "rheostat", "D": "resistance box"}, "answer": "B", "explanation": "An ammeter can be adapted to measure potential difference by using a multiplier. A multiplier is a high resistance connected in series with the ammeter. It allows the ammeter to measure higher currents by diverting most of the current away from the ammeter. When connected in parallel with the circuit element whose potential difference is to be measured, the combination of the ammeter and multiplier acts like a voltmeter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>36", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "The region around a magnet in which magnetic force can be experienced is known as", "images": [], "options": {"A": "declination", "B": "flux density", "C": "field", "D": "flux"}, "answer": "C", "explanation": "The region around a magnet in which magnetic force can be experienced is known as the magnetic field. This is the space around a magnet where the force of the magnet can be detected. Magnetic fields are produced by moving electric charges and the intrinsic magnetic moments of elementary particles associated with a fundamental quantum property, their spin.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>37", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "In an a.c circuit, when the supply voltage frequency is equal to the resonant frequency, the current", "images": [], "options": {"A": "lead, the supply voltage by 90o", "B": "lags behind the supply voltage by 90o", "C": "leads the supply voltage by 45o", "D": "is in phase with the supply voltage"}, "answer": "D", "explanation": "At resonance, cosθ = 0 i.e Vf = Rf and Vc = VL. Hence, the current is in phase with the supply voltage.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>38", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ENERGY : FORMS OF ENERGY", "question": "The energy stored in a simple cell is", "images": [], "options": {"A": "electrical", "B": "nuclear", "C": "thermal", "D": "chemical"}, "answer": "D", "explanation": "The energy stored in a simple cell is chemical energy. This is because a cell converts chemical energy into electrical energy during the process of electrochemical reactions. The chemical energy is stored in the form of potential energy in the chemicals that make up the cell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>39", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "Which of the following conditions occur at resonance in a series RLC circuit?   I. Impedance equals resistance   II. Current is maximum    III. Reactance are maximum    IV. Current and voltage are 90o out of phase", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I, II and III only", "D": "I, II, III and IV"}, "answer": "A", "explanation": "At resonance in a series RLC circuit, the impedance equals the resistance and the current is maximum. This is because at resonance, the inductive reactance equals the capacitive reactance, causing the total reactance to be zero. Hence, the impedance (which is the vector sum of resistance and reactance) equals the resistance. Also, since the impedance is minimum at resonance, the current (which is inversely proportional to the impedance) is maximum. However, the reactance are not maximum and the current and voltage are not 90 degrees out of phase at resonance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>40", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "An electric motor converts", "images": [], "options": {"A": "electrical energy to mechanical energy", "B": "mechanical energy to electrical energy", "C": "mechanical energy to sound energy", "D": "electrical energy to thermal energy"}, "answer": "A", "explanation": "An electric motor works on the principle of electromagnetic induction, which states that when a current-carrying conductor is placed in a magnetic field, it experiences a mechanical force. Therefore, an electric motor converts electrical energy into mechanical energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2014>41", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A 15µ capacity is connected to a 240V, 50Hz a.c. source. Calculate the reactance of the capacitor [π = 3.142]", "images": [], "options": {"A": "16Ω", "B": "68Ω", "C": "106Ω", "D": "212Ω"}, "answer": "D", "explanation": "c = 15μF    V = 240v    Frequency, F = 50Hz; π = 3.14 , XC = ?   Xc=12πFc   XC=12 x 3.14 x 50 x 15 x 10-6  XC=13.14 x 15 x 10-6   XC = 212.3Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>42", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "Two identical charges situated 20cm apart in vacuum repel each other with a force of 1.0N. Calculate the value of each charges. [(4πεo)-1 = 9 x 109 N m2C-2]", "images": [], "options": {"A": "2.1µC", "B": "3.6µC", "C": "4.0µC", "D": "4.4µC"}, "answer": "A", "explanation": "F=Kq1q2r2(coulumb'slaw)   Fr2k=q1q2    Since the charges are identical q1 = q2 = q   Fr2k=q2;k=14πεo=9x109Nm2c2     1x4x10-29x109=q2     q2=49x10-11;    q=&radic;49x10-11&nbsp;=2.1x106c    = 2.1µC", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>43", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "In the circuit above, E is a battery of negligible internal resistance. If its emf is 9.0v, calculate the current in the circuit", "images": ["Physics/imgs/2014/box.png"], "options": {"A": "1.8A", "B": "1.0A", "C": "0.8A", "D": "0.3A"}, "answer": "B", "explanation": "Effectiveresistance=5Ω+(20 x 520 + 5)Ω    5Ω + 4Ω = 9Ω    V = 9V; V = IR   9 = I(9) , I = 1.0A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>44", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire of length 100cm has a resistance of 10Ω. If its cross-sectional area is 0.005cm2, determine its resistivity.", "images": [], "options": {"A": "0.0005Ωcm", "B": "0.0015Ωcm", "C": "0.0016Ωcm", "D": "0.0700Ωcm"}, "answer": "A", "explanation": "R=ρA    RAl=ρ(Resistivity)   ρ=10 x 5 x 10-3100=5x10-4Ωcm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>45", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "A transformer has 400 turns of wire in the primary coil and 40 turns in the secondary coil. If the input voltage is 150 volts, calculate the magnitude of the output voltage", "images": [], "options": {"A": "150V", "B": "55V", "C": "36V", "D": "15V"}, "answer": "D", "explanation": "NPNS=EPES    40040=150ES    ES x 10 = 150    ES = 15V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>46", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "The circuit above illustrates a standard resistor R, voltage source E and lamp L connected in series. If the temperature of R is increased, the brightness of the lamp will", "images": ["Physics/imgs/2014/box2.png"], "options": {"A": "increase sharply", "B": "decrease slightly", "C": "remain the same", "D": "increase gradually"}, "answer": "B", "explanation": "As the temperature increases, the resistance which is the opposition to the flow of current increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2014>47", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The energy required to separate the nucleus in an atom completely is known as", "images": [], "options": {"A": "mass defect of the atom", "B": "electron binding energy", "C": "excitation energy", "D": "nuclear binding energy"}, "answer": "D", "explanation": "The energy required to separate the nucleus in an atom completely is known as the nuclear binding energy. This energy is a measure of the force that holds the nucleus together, and it is equivalent to the amount of energy that would be required to disassemble the nucleus into its individual protons and neutrons. Therefore, the correct option is 4.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>48", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "Which of the following statements is the major advantage of nuclear fusion over fission?", "images": [], "options": {"A": "Nuclear fusion releases more energy", "B": "More neutrons are released in fusion than in fission", "C": "Fusion does not release as much dangerous radiation as fission", "D": "Fusion reactions occurs more readily than fission"}, "answer": "C", "explanation": "Fusion does not release as much dangerous radiation as fission", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>49", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : THERMIONIC EMISSION", "question": "An aluminium foil nucleon is placed across a beam of radiation from a radioactive source. Which of the following types of radiation will be stopped by it?", "images": [], "options": {"A": "Beta", "B": "Alpha", "C": "Gamma", "D": "X-rays"}, "answer": "A", "explanation": "Beta particles can only be stopped by aluminum foil", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2014>50", "subject": "Physics", "year": "2014", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "An element of nucleon number P and atom number Q emits an alpha particles from its nucleus. The resultant numbers of the new element formed are respectively", "images": [], "options": {"A": "P -4 and Q + 2", "B": "P -4 and Q - 2", "C": "P + 2 and Q + 2", "D": "P + 2 and Q - 2"}, "answer": "B", "explanation": "An element of nucleon number P and atom number Q emits an alpha particles from its nucleus. The resultant numbers of the new element formed are P -4 and Q - 2 respectively", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>1", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "MASS AND WEIGHT : DISTINCTION BETWEEN MASS AND WEIGHT", "question": "Which of the following statements about mass and weight are correct   I. Weight is the force of gravity on a body   II. The mass of a body is the quantity of matter in the body   III. The weight of a body is greatest at the equator.  IV. The mass of a body is greatest at the poles", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "II and IV only", "D": "III and Iv only"}, "answer": "A", "explanation": "I - Weight is the force of gravity on a body    II - The mass of a body is the quantity of matter in a body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>2", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "Materials that can be stretched and still return to their original forms when the stresses are removed are said to be", "images": [], "options": {"A": "elastic", "B": "elastomer", "C": "plastic", "D": "thermoplastic"}, "answer": "A", "explanation": "A material is said to be elastic if after small application of force, it returns to its original position.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>3", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "Which of the following units is derived?", "images": [], "options": {"A": "kg", "B": "m", "C": "K", "D": "N"}, "answer": "D", "explanation": "In physics, a derived unit is a unit that is not a base unit but is derived from base units. The kilogram (kg), meter (m), and Kelvin (K) are all base units in the International System of Units (SI). The Newton (N), however, is a derived unit because it is defined as the force needed to accelerate one kilogram of mass at the rate of one meter per second squared (kg*m/s^2).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>4", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The barometric reading at a place is 73.5cmHg. Calculate the pressure at a point 30m below the surface of water contained in a reservoir at the place.   [g = 10ms-2, density of mercury = 1.3 x 104kgm-3, density of water = 1.0 x 103kgm-3]", "images": [], "options": {"A": "4.0 x 105 Nm-2", "B": "3.0 x 105 Nm-2", "C": "2.0 x 105 Nm-2", "D": "1.0 x 105 Nm-2"}, "answer": "B", "explanation": "Total pressure = pressure due to the atmosphere + Pressure due to water    the barometric reading Is 73.5Hg  P = hpg  p = 1.0 x 103, h = 30, g = 10  p =  1.0 x 103 x 30 x 10    = 3 x 105Nm-2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>5", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "An object floats in a fluid when it displaces its", "images": [], "options": {"A": "volume of liquid in which it floats", "B": "mass of liquid in which it floats", "C": "weight of fluid in which it floats", "D": "density of fluid in which it floats"}, "answer": "C", "explanation": "According to Archimedes' principle, an object floats in a fluid when it displaces a volume of the fluid equal to its own weight. Therefore, the object floats when it displaces its weight of the fluid in which it floats, which matches option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>6", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The resultant force in a couple is", "images": [], "options": {"A": "zero", "B": "infinite", "C": "the sum of the forces", "D": "the product of the forces"}, "answer": "A", "explanation": "A couple is a system of two equal and opposite parallel forces.    F1 = -F2    F1 + F2 = 0", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>7", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "The slopes of a straight-line velocity-time graph represents", "images": [], "options": {"A": "uniform acceleration", "B": "uniform speed", "C": "total distance travelled", "D": "work done"}, "answer": "A", "explanation": "The slope of a velocity-time graph represents acceleration. If the graph is a straight line, it indicates that the acceleration is constant or uniform. Therefore, the correct answer is 'uniform acceleration'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>8", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A body is projected with an initial velocity U at an angle θ to the horizontal. The time taken by it to reach its maximum height is given by the expression", "images": [], "options": {"A": "2USinθ/g", "B": "U2Sin2θ/2g", "C": "USinθ/g", "D": "USinθ/2g"}, "answer": "C", "explanation": "Vy = usinθ - gt    at maximum height, Vy = 0    -usinθ = -gt    t = usinθ/g", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>9", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY", "question": "Which of the following statements describes a body in a stable equilibrium correctly? A", "images": [], "options": {"A": "person walking on a tight-rope", "B": "ball on a smooth horizontal table", "C": "ball resting on an inverted hemispherical bowl", "D": "ball in the middle of a hemispherical bowl"}, "answer": "D", "explanation": "A body is said to be in stable equilibrium if, when displaced slightly, it returns to its original position. A ball in the middle of a hemispherical bowl, when displaced, will roll back to the middle, indicating that it is in a state of stable equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>10", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "POSITION, DISTANCE AND DISPLACEMENT : DISTINCTION BETWEEN DISTANCE AND DISPLACEMENT.", "question": "In a school compound, a girl walks 40m due east from the laboratory to the staff room to submit her report. Then she turns and walks 30m due north to her classroom. Determine the magnitude of her displacement from the laboratory", "images": [], "options": {"A": "10m", "B": "35m", "C": "50m", "D": "70m"}, "answer": "C", "explanation": "The displacement = (402 + 302)1/2    The displacement = (1600 + 900)1/2    The displacement = (2500)1/2     The displacement = 50m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>11", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Two strings each inclined at an angle 30o to the horizontal are used to hold a bucket of water weighing 20N. Calculate the tension in each string.", "images": [], "options": {"A": "20 √ 3N", "B": "20N", "C": "10 √ 3N", "D": "10N"}, "answer": "B", "explanation": "2Tsin30o = 20    T1=201=20N  ∴ the tension in each string is 20N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>12", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A bullet fired vertically upwards reaches a height of 50m, Neglecting air resistance, calculate the magnitude of the initial velocity of the bullet. [g = 10ms-2]", "images": [], "options": {"A": "500.0ms-1", "B": "100.00ms-1", "C": "70.0ms-1", "D": "50.0ms-1"}, "answer": "B", "explanation": "The K.E of the ball is converted to P.E    K.E = P.E    12mv2=mgh    V2 = 2gh, v2 = 2 x 10 x 500    v = &radic;10,000&nbsp; = 100.00ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>13", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS", "question": "A uniform bar AB is balanced on a knife-edge which is 60cm from B by a mass of 22g which hangs at C 10cm from A as illustrated in the diagram above. Calculate the mass of the bar.", "images": ["Physics/imgs/2015/pix1.png"], "options": {"A": "133.3g", "B": "66.0g", "C": "60.0g", "D": "22.0g"}, "answer": "B", "explanation": "Since it's a uniform bar the weight acts at the centre which is 50cm    * Take moment about the pivot    22 x 30 = 10W    W = 66g.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>14", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A body of mass 1000kg is released from a height of 10m above the ground. Determine its kinetic energy just before it strikes the ground. [g = 10ms-2]", "images": [], "options": {"A": "10J", "B": "103J", "C": "104J", "D": "105J"}, "answer": "D", "explanation": "P.E at the point of release = K.E at the ground    mgh = K.E at the ground    K.E at the ground = 1000kg x 10gms-2 x 10m    K.E at the ground = 105kgm2s-2 = 105J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>15", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "The diagram below illustrates four test-tubes containing the same volume of a liquid at different pressures. In which of the test-tubes does the liquid boil last if they are supplied with the same, quantity of heat?", "images": ["Physics/imgs/2015/opt1.png", "Physics/imgs/2015/opt2.png", "Physics/imgs/2015/opt3.png", "Physics/imgs/2015/opt4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "A", "explanation": "The boiling point increases as the pressure increases.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>16", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The crackling noise produced by aluminium roofing sheets on a house during a hot sunny day is as a result of", "images": [], "options": {"A": "thermal equilibrium of the sheet", "B": "conduction of heat by the sheets", "C": "contraction of heat by the sheet", "D": "expansion of the sheets"}, "answer": "D", "explanation": "The cracking noise produced by this aluminum is due to an increase in the dimension of the aluminum.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>17", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Water is unsuitable for use as a thermometric liquid because it", "images": [], "options": {"A": "expands uneven between 0oC and 4oC", "B": "has a narrow temperature range", "C": "has a concave meniscus", "D": "maintain a fixed density"}, "answer": "A", "explanation": "The anomalous behaviour of water between 0oC and 4oC makes it unsuitable for use as a thermometric fluid.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>18", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "MACHINES :", "question": "The diagram illustrates a block and tackle pulley system in which an effort (N) supports a load of 100.0N. If the efficiency of the machine is 75%, calculate the value of N.", "images": ["Physics/imgs/2015/pulley.png"], "options": {"A": "22.2 N", "B": "38.0 N", "C": "67.0 N", "D": "75.0 N"}, "answer": "A", "explanation": "V.R = Number of pulleys = 6    M.A = ?, Efficiency(E)=M.AV.Rx100    E = 75% = 0.75   0.75=M.A6   M.A = 4.5    M.A=LoadEffort   Effort(N)=1004.5=2009=22.2N.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>19", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "A quantity of hot water at 100oC is added to 400g of water of 10oC  until the temperature of the mixture is 60oC. Calculate the mass of the hot water added.  [Specific heat capacity of water = 4200JKg-1K-1]", "images": [], "options": {"A": "200g", "B": "320g", "C": "400g", "D": "500g"}, "answer": "D", "explanation": "CHot water = CCold water    Specific heat capacity of hot water = specific heat capacity    Heat lost by hot water = Heat gained by the cold water    mHCH(Δθ)H = mcCc(Δθ)c    (Δθ)H = 100oC - 60oC = 40oC    (Δθ)C = 60oC - 10oC = 50oC    mH x 40oC = 400 x 50    mH = 500g.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>20", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : MELTING POINT", "question": "In the experiment in which a molten substance is allowed to cool, the cooling curve shown above was obtained. The temperature 60oC is known as the", "images": ["Physics/imgs/2015/graph.png"], "options": {"A": "vaporization point", "B": "boiling point", "C": "cooling point", "D": "melting point"}, "answer": "D", "explanation": "At 60oC, the solid phase and the liquid phase are at equilibrium.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>21", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "Which of the following concepts is a method of heat transfer that doesn't require a material medium?", "images": [], "options": {"A": "Conduction", "B": "Radiation", "C": "Diffusion", "D": "Convection"}, "answer": "B", "explanation": "Radiation is the method of heat transfer that doesn't require a material medium. It is the process by which energy is transmitted through a vacuum or through material media in the form of electromagnetic waves. Unlike conduction and convection, radiation can occur in a vacuum, such as space.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>22", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "HEAT ENERGY : HEAT CAPACITY", "question": "Which of the following units is the S.I unit of heat capacity?", "images": [], "options": {"A": "JKg-1", "B": "JKg-1K-1", "C": "JK-1", "D": "Jg-1K-1"}, "answer": "C", "explanation": "Heat capacity is the amount of heat energy required to change the temperature of a substance by 1oC   c=HΔθ=JK-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>23", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The pressure applied to an enclosed fluid at one end is transmitted equally throughout the fluid and to the container walls. This statement is", "images": [], "options": {"A": "Archimede's principle", "B": "Bernoulli's principle", "C": "pascal's principle", "D": "Heisenberg's uncertainty principle"}, "answer": "C", "explanation": "The statement describes Pascal's Principle. Pascal's Principle states that when a change in pressure is applied to an enclosed fluid, it is transmitted undiminished to all portions of the fluid and to the walls of its container. This principle is used in hydraulic systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>24", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "The diagram above illustrates a wave form. Determine the speed of the wave.     NB: T=0.65", "images": ["Physics/imgs/2015/curve.png"], "options": {"A": "5.4ms-1", "B": "8.4ms-1", "C": "9.6ms-1", "D": "10.0ms-1"}, "answer": "D", "explanation": "Velocity = Frequency x Wavelength    V = f x λ    F = n/t; n = 2    t = 0.6    f = 2/0.6 = 20/6 = 3.3Hz    Wavelength(λ) = ?    λ = π    3π = 9m    π = 3 = λ    v = 3.3 x 3 = 9.9ms-1    ≈ 10ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>25", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "What type of wave is emitted by a loud speaker?", "images": [], "options": {"A": "Transverse", "B": "Longitudinal", "C": "Gamma", "D": "Radio"}, "answer": "B", "explanation": "A loudspeaker emits sound waves, which are longitudinal waves. Longitudinal waves are waves in which the displacement of the medium is in the same direction as, or the opposite direction to, the direction of propagation of the wave. In the case of sound waves, the air particles vibrate back and forth in the same direction of the wave.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>26", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "An object is placed 15cm from a diverging lens of focal length 12cm. The image of the object formed by the lens is", "images": [], "options": {"A": "real and 6.67cm from the lens", "B": "virtual and 6.67cm from the lens", "C": "real and 60.00cm from the lens", "D": "virtual and 60.00cm from the lens"}, "answer": "B", "explanation": "Since it's a diverging lens, f = -ve    -1f=1u+1v    -112=115+1v   -15-12180=-27180=1v   v=-18027=-609=-6.67cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>27", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which of the following types of lenses is suitable for correcting the eye defect illustrated by the ray diagram?", "images": ["Physics/imgs/2015/eye.png"], "options": {"A": "Bi-converging", "B": "Bi-diverging", "C": "Plano diverging", "D": "Diverging meniscus"}, "answer": "A", "explanation": "The diagram shows a condition of longsightedness which is usually correcting using a converging lens (convex lens)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>28", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A swimming pool is 2.1m deep. If it contains water of refractive index 1.3, calculate the apparent depth of the pool", "images": [], "options": {"A": "3.4m", "B": "2.7m", "C": "1.6m", "D": "0.8m"}, "answer": "C", "explanation": "Refractiveindex=Real depthApparent depth  Apparentdepth=real depth Refractive index=2.11.3=1.6m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>29", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "When an air column is set into vibrations, the distance between two consecutive nodes of the resultant wave is", "images": [], "options": {"A": "One-quarter of the wavelength", "B": "One-halve of the wavelength", "C": "the wavelength", "D": "twice of the wavelength"}, "answer": "B", "explanation": "In a standing wave, the distance between two consecutive nodes is half the wavelength. A node is a point along a standing wave where the wave has minimum amplitude. In the case of a standing wave, these points are located at the ends of each oscillation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>30", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A girl standing some distance from the foot of a tall cliff claps her hands and hears the echo 0.8s later. Calculate her distance from the cliff. [speed of sound in air = 320ms-1]", "images": [], "options": {"A": "82m", "B": "102m", "C": "128m", "D": "140m"}, "answer": "C", "explanation": "The distance to the cliff can be calculated using the formula: distance = speed * time / 2. The time is divided by 2 because the sound wave has to travel to the cliff and back. Substituting the given values, we get distance = 320ms-1 * 0.8s / 2 = 128m.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>31", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Red light travels faster than blue light when both of them pass through a glass prism because the", "images": [], "options": {"A": "refractive index of red light is greater than that of blue light", "B": "refractive index of blue light is greater than that of a red light", "C": "red light is more intense than the blue light", "D": "blue light is more intense than the red light"}, "answer": "B", "explanation": "Red light travels faster because the refractive index of blue light is greater than that of red light.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>32", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An object is placed 20cm from a concave mirror of focal length 15cm. Calculate the linear magnification of the image formed.", "images": [], "options": {"A": "0.5", "B": "1.5", "C": "2.0", "D": "3.0"}, "answer": "D", "explanation": "M=vu   1f=1v+1u  115=1v+120   115-120=1v   5300=1v   v = 60cm    M=6020=3.0", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>33", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "All electromagnetic waves in a vacuum have the same", "images": [], "options": {"A": "wavelength", "B": "frequency", "C": "speed", "D": "amplitude"}, "answer": "C", "explanation": "All electromagnetic waves, regardless of their frequency or wavelength, travel at the same speed in a vacuum. This speed is approximately 3.00 x 10^8 meters per second, and is often referred to as the speed of light.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>34", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "The diagram illustrates two charges particles W and X. The charges on W and X are respectively", "images": ["Physics/imgs/2015/charge.png"], "options": {"A": "negative; negative", "B": "negative; positive", "C": "positive; positive", "D": "positive; negative"}, "answer": "A", "explanation": "The charges are repelling one another, so they are like charges (i.e the may be positive-positive or negative-negative)    But, because the charges flow inward they are negative-negative charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>35", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES", "question": "An alternating current supply is connected to an electric lamp which lights with the same brightness as it does with a direct current source of emf 6V. The peak potential difference of the a.c supply is", "images": [], "options": {"A": "4.6V", "B": "6.0V", "C": "8.5V", "D": "12.0V"}, "answer": "C", "explanation": "Vrms=Vm&radic;2&nbsp;    Vm = Vrms x &radic;2&nbsp;    Vm = 6 x &radic;2&nbsp;    Vm = 8.5V.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>36", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "An electric generator rated 12kW, 2kV distributes power through a cable of resistance 20Ω. Calculate the power loss in the cable", "images": [], "options": {"A": "120W", "B": "360W", "C": "720W", "D": "2400W"}, "answer": "C", "explanation": "Power loss = I2R; R = 20Ω    P = IV    12 x 1032 x 103=I   I = 6    Power loss = 36 x 20 = 720W", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>37", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Which of the following statements is correct? When capacitors of different values are connected in series", "images": [], "options": {"A": "the same charge flows through them", "B": "the same voltage appears across each capacitor", "C": "different quantities of charges flow through them with voltage across them", "D": "different quantities of charges flow through them with the same voltage across them"}, "answer": "A", "explanation": "When capacitors are connected in series, the same charge flows through them.    Q = CV    QC=V   Q = K", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>38", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the following statement(s) about a three-pin plug is/are correct?   I. The brown wire is the live wire   II. The fuse is connected to the live wire  III. The earth wire is coloured blue", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "I, II and III only"}, "answer": "C", "explanation": "The brown wire in a three-pin plug is indeed the live wire, and the fuse is connected to the live wire to prevent excessive current from damaging the device. Therefore, statements I and II are correct. However, the earth wire is not blue; it is typically green and yellow. Therefore, statement III is incorrect. The correct answer is 'I and II only'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>39", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "The symbol illustrated above is that of a resistor", "images": ["Physics/imgs/2015/arror.png"], "options": {"A": "Which absorbs light", "B": "Which emits light", "C": "Which absorb heat to function properly", "D": "Whose resistance is light dependence"}, "answer": "C", "explanation": "A resistor which absorbs heat to function properly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>40", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire of cross-sectional area 0.60mm2 has a resistivity of 7.2 x 10-7 Ωm. Calculate the length of wire that will have a resistance of 3Ω", "images": [], "options": {"A": "0.25m", "B": "2.50m", "C": "3.60m", "D": "36.00m"}, "answer": "B", "explanation": "R=ρlA   RAρ=l  l=3 x 0.60 x 10-67.2 x 10-7=2.50m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>41", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "A battery of emf 24V is connected to three resistors P, Q and R as illustrated in the diagram above. Determine the voltage across the resistor Q.", "images": ["Physics/imgs/2015/ssce2015q41phy.png"], "options": {"A": "5V", "B": "10V", "C": "14V", "D": "24V"}, "answer": "B", "explanation": "When R is in parallel, V is the same   Total V = VPQ + VR ;   24 = VPQ + 14   VPQ = 24 - 14 = 10V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>42", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "The mass of the earth is 6.0 × 1024kg and that of the moon is 7.0 × 1022Kg. If the distance between them is 4.0 × 108m, calculate the force of attraction between them.  [G = 6.7 x 10-11Nm2Kg-2]", "images": [], "options": {"A": "1.8 x 105N", "B": "1.8 x 1010N", "C": "1.8 x 1015N", "D": "1.8 x 1020N"}, "answer": "D", "explanation": "Fg=GMeMmr2;    Me - mass of the earth , Mm - mass of the moon, G - Universal gravitational constant,    r - distance apart.    Fg=6.7x10-11x6x1024x7x102216 x 1016    Fg=281.4 x 103516 x 1016=18x1019   = 1.8 x 1020N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>43", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "MAGNETIC FIELD : THE EARTH’S MAGNETIC FIELD", "question": "The angle which the direction of the earth magnetic field makes with the horizontal at a place is known as", "images": [], "options": {"A": "angle of contact", "B": "angle of dip", "C": "angle of declination", "D": "magnetic meridian"}, "answer": "B", "explanation": "The angle which the direction of the earth magnetic field makes with the horizontal at a place is known as the angle of dip. This is a term used in geophysics to describe the angle made by the Earth's magnetic field lines with the horizontal plane.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>44", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "What must be connected between the point P and Q to establish a steady current through the incomplete circuit diagram illustrated above?", "images": ["Physics/imgs/2015/pix3.png"], "options": {"A": "Fuse", "B": "Ammeter", "C": "Cell", "D": "Voltmeter"}, "answer": "C", "explanation": "To establish a steady current through the incomplete circuit diagram illustrated a cell is needed to be connected in the circuit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>45", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "When current flows through a moving-coil galvanometer, the force exerted on the pointer depends on the    I. strength of the current    II. magnetic field strength    III. length of the soil.  Which of the statement(s) is/are correct?", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and III only", "D": "I, II and III"}, "answer": "D", "explanation": "The force exerted on the pointer of a moving-coil galvanometer depends on the strength of the current (I), the magnetic field strength (II), and the length of the coil (III). This is because the force experienced by a current-carrying wire in a magnetic field is given by F = BIL, where F is the force, B is the magnetic field strength, I is the current, and L is the length of the wire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>46", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "In a nuclear fission process, the mass defect was 1.2 × 10-5kg. Calculate the energy released.   [speed of light in vacuum = c = 3.0 x 108ms-1]", "images": [], "options": {"A": "1.8 x 1011J", "B": "5.20 x 1011J", "C": "1.08 x 1012J", "D": "2.50 x x 1013J"}, "answer": "C", "explanation": "Recall that,    E = mc2    E = 1.2 x 10-5 x 9 x 1016    E = 10.8 x 1011    E = 1.08 x 1012J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2015>47", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "ELECTRICAL CONDUCTION THROUGH MATERIALS [ELECTRONIC] :", "question": "Which of the following statements about a diode is correct?", "images": [], "options": {"A": "Reverse bias diodes have low resistance", "B": "Forward bias diodes have high resistance", "C": "Forward bias diodes produce high current", "D": "Forward bias diodes function as a result of heat"}, "answer": "C", "explanation": "A diode is a semiconductor device that allows current to flow in one direction only. When a diode is forward biased, it allows current to flow freely through it, hence producing high current. The other options are incorrect because a reverse bias diode has high resistance, not low, and a forward bias diode does not have high resistance. Also, the functioning of a diode is not a result of heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>48", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Which of the following phenomena best support the wave nature of matter?", "images": [], "options": {"A": "Electron diffraction", "B": "Photoelectric effect", "C": "Electron momentum", "D": "Black body radiation"}, "answer": "A", "explanation": "The wave nature of matter is best supported by the phenomenon of electron diffraction. This is a quantum mechanical phenomenon where particles such as electrons exhibit wave-like properties, such as interference and diffraction. The other options do not directly support the wave nature of matter. The photoelectric effect supports the particle nature of light, electron momentum is a property of particles, and black body radiation is related to the energy distribution of photons in a black body, not matter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2015>49", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "Which of the following radiation constitutes a stream of electron?", "images": [], "options": {"A": "Gamma rays", "B": "X-rays", "C": "Cathode rays", "D": "Radio waves"}, "answer": "C", "explanation": "Cathode rays constitute a stream of electrons. They are produced in vacuum tubes when a high voltage is applied across electrodes, causing electrons to be emitted from the cathode (negative electrode) and travel to the anode (positive electrode). Gamma rays and X-rays are types of electromagnetic radiation, not streams of electrons, and radio waves are a type of electromagnetic wave.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2015>50", "subject": "Physics", "year": "2015", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "22688Ra emits two alpha particles to produce Polonium (Po) nuclide. The correct formula for the nuclide is", "images": [], "options": {"A": "22486Po", "B": "22286Po", "C": "22284Po", "D": "21884Po"}, "answer": "D", "explanation": "The correct formula for the nuclide is:  22688Ra → 2 42He + 21884Po", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>1", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "DERIVED QUANTITIES AND DIMENSIONAL ANALYSIS :", "question": "The dimensions of momentum are", "images": [], "options": {"A": "MLT", "B": "ML-1T-1", "C": "MLT-1", "D": "ML-1T"}, "answer": "C", "explanation": "The dimension of momentum is given by the product of mass and velocity. The dimension of mass is M (mass), the dimension of velocity is LT-1 (length per time). Therefore, the dimension of momentum is MLT-1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2016>2", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A student measures the volume of a liquid using a measuring cylinder. What else needs to be measured by the student in order to determine the density of the liquid?", "images": [], "options": {"A": "Depth of the liquid in the cylinder", "B": "Mass of the cylinder", "C": "Mass of the liquid", "D": "Temperature of the liquid"}, "answer": "C", "explanation": "The mass of the liquid is also required to determine the density of the liquid since,  Density=massvolume", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2016>3", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "The diagram above represents the graph of stress against strain for an elastic wire. The point Q on the graph is the", "images": ["Physics/imgs/2016/2016ssceq3phy.png"], "options": {"A": "elastic limit", "B": "breaking point", "C": "yield point", "D": "proportional limit"}, "answer": "B", "explanation": "The point Q on the graph is the is the breaking point.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>4", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MOTION : MOTION UNDER GRAVITY", "question": "A ball is dropped from the top of a tower. Due to air resistance, it reaches terminal velocity. Which of the following statement(s) about its motion is/are correct?  I. The acceleration of the ball is zero  II. The net force on the ball is zero  III. The velocity of the ball increases", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "II and III only", "D": "I, II and III"}, "answer": "B", "explanation": "The acceleration of the ball is zero due to the fact that it is due to air resistance and gravity. The net force on the ball is also zero because it is the same amount of force that it applied on both sides of the ball.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>5", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Which of the following substances lowers the surface tension of water?", "images": [], "options": {"A": "Metal", "B": "Sand", "C": "Detergent", "D": "Paper"}, "answer": "C", "explanation": "Surface tension is the property of a liquid that allows it to resist an external force. It is caused by the cohesive forces between liquid molecules. Detergents lower the surface tension of water by disrupting the cohesive forces between water molecules. This is why detergent is often added to water when washing dishes or clothes, as it allows the water to more effectively penetrate and clean the items.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>6", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS", "question": "An object of volume 400cm3 and density 2.5gcm-3 is suspended  from a spring balance with half its volume immersed in water. Determine the reading on the spring balance.  (Density of water = 1 gcm-3)", "images": [], "options": {"A": "1200g", "B": "1000g", "C": "800g", "D": "400g"}, "answer": "C", "explanation": "Recall, Density = m/v  2.5 = m ÷ 400  m = 2.5/400  m = 1000g  Also, mass of object in water = Density of water × Half Volume of water  m = 1gcm-3 × 200cm3  m = 200g  ∴ Spring Balance Reading = (1000 - 200)g    = 800g", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>7", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "The diagram above illustrates a force-distance graph for the motion of a wooden block. Determine the work done on the block when moved through a distance of 5m.", "images": ["Physics/imgs/2016/pix9.png"], "options": {"A": "4J", "B": "15J", "C": "25J", "D": "100J"}, "answer": "D", "explanation": "Recall, Workdone = Force × distance   where, F = 20N, d = 5m  Workdone = 20 × 5 = 100Nm  ∴ Workdone = 100J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>8", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "The two positions of a body undergoing a uniformly accelerated motion are (10s, 10ms-1) and (30s, 50ms-1) on the velocity-time graph. Calculate the magnitude of the acceleration of the body.", "images": [], "options": {"A": "0.5ms-2", "B": "2.0ms-2", "C": "10.0ms-2", "D": "40.0ms2"}, "answer": "B", "explanation": "(10s, 10ms-1) and (30s, 50ms1)  Acceleration=Δvt  Acceleration=50 - 1030 - 10=4020=2ms-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>9", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "At a birthday party, the celebrant pops a corked fruit wine. If the cork shoots out of the bottle at an angle of 40° to the horizontal and travels a horizontal distance of 4.5 m in 1.25s, calculate the initial speed of the cork", "images": [], "options": {"A": "4.2 ms-1", "B": "4.7 ms-1", "C": "5.6 ms-1", "D": "7.1 ms-1"}, "answer": "B", "explanation": "Given; θ = 40°, R = 4.50m, t = 1.25s, u = ?  Recall, R = ucosθt  4.50 = u cos40° × 1.25  u=4.50.766 × 1.25=4.50.96  u = 4.7ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>10", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A uniform metre rule is balanced on a fulcrum placed at the 35cm mark by suspending a mass of 120g at the 10cm mark. Calculate the mass of the metre rule", "images": [], "options": {"A": "60g", "B": "80g", "C": "120g", "D": "200g"}, "answer": "D", "explanation": "Clockwise moment = anticlockwise moment half of a meter rule  = 50cm which Is the mid-point   (35-10) x 120 = 50 – 35 x W  25 x 120 = 15W  W = 200g", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>11", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MOTION : TYPES OF FORCE", "question": "A plank is placed along the path on which a wheel barrow containing sand is pushed at a construction site to prevent it from sticking as illustrated in the diagram above. The large area of the plank prevents the wheel barrow from getting stuck by", "images": ["Physics/imgs/2016/pix10.png"], "options": {"A": "increasing the reaction on the ground", "B": "increasing the pressure on the ground", "C": "decreasing the pressure on the ground", "D": "decreasing the weight on the ground"}, "answer": "B", "explanation": "The plank prevents the barrow from getting stuck because it increases the pressure on the ground.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>12", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "When a body is thrown vertically upwards, its velocity at the maximum height is", "images": [], "options": {"A": "maximum", "B": "zero", "C": "double its initial value", "D": "half its initial value"}, "answer": "B", "explanation": "The velocity of a body at its maximum height is zero (0) because the body rests briefly before falling.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>13", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "SOUND WAVES : RESONANCE", "question": "Resonance occurs when one vibrating object causes a second object to vibrate at its own natural", "images": [], "options": {"A": "amplitude", "B": "speed", "C": "frequency", "D": "intensity"}, "answer": "C", "explanation": "Resonance occurs when one vibrating object causes a second object to vibrate at its own natural frequency. This is because resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>14", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The mouth piece of a telephone handset converts", "images": [], "options": {"A": "electrical energy to sound energy", "B": "sound energy to electrical energy", "C": "sound energy to radiowave", "D": "radiowave to sound energy"}, "answer": "B", "explanation": "The mouthpiece of a telephone handset converts sound energy to electrical energy. This is because when you speak into the mouthpiece of a telephone, your voice causes the air molecules inside it to vibrate. These vibrations are then converted into electrical signals by a microphone in the mouthpiece. These electrical signals can then be transmitted over telephone lines to another telephone, where they are converted back into sound.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>15", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "Four identical trolleys are loaded with different masses and move along a straight road at the same speed. Which of the trolleys has the greatest inertia?", "images": ["Physics/imgs/2016/pix5.png", "Physics/imgs/2016/pix6.png", "Physics/imgs/2016/pix7.png", "Physics/imgs/2016/pix8.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "The trolley carrying the highest mass/load will have the greatest Inertia because Inertia is the reluctance of a body.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>16", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "In the clinical thermometer, the function of the kink is to   I. prevent the back flow of mercury after use  II. ensure the back flow of mercury after use  III. maintain the thermometric property of mercury  IV. allow the temperature attained to be read", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "I and IV only", "D": "III and IV only"}, "answer": "C", "explanation": "The kink in a clinical thermometer helps to prevent backflow of the mercury after use which also simultaneously allows any temperature attained to be read.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>17", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "Which of the following statements correctly defines the boiling point of a liquid. The temperature at which the", "images": [], "options": {"A": "saturated vapour pressure equals the atmospheric pressure", "B": "molecules leave the liquid at a rate equal to the rate at which they return", "C": "molecules leave the liquid at a rate higher than that at which they return", "D": "molecules leave the liquid at a rate lower than the rate at which they return"}, "answer": "A", "explanation": "The boiling point of a liquid is the point at which the saturated vapour pressure is equal to the atmospheric/earth pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>18", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY AND THE WEATHER", "question": "The diagram above is used to determine the", "images": ["Physics/imgs/2016/pix12.png"], "options": {"A": "boiling point of water", "B": "atmospheric pressure", "C": "upper fixed point of a thermometer", "D": "amount of water in the atmosphere"}, "answer": "C", "explanation": "The diagram above which is a Hypsometer is used to determine the upper fixed point of a thermometer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>19", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "An aluminium rod of length 1.8 m at 10°C is heated to produce a difference in length of 0.007m. Calculate the temperature to which it is heated.  (Linear expansivity of aluminium = 2.3 × 10-5K-1)", "images": [], "options": {"A": "155°C", "B": "160°C", "C": "169°C", "D": "179°C"}, "answer": "D", "explanation": "Recall,LinearExpansivity,α=l2 - l1l1Δθ  =l2 - l1l1(θ2 - θ1)  2.3×10-5=0.0071.8 × (θ1-10)  0.007 = 2.3 × 10-5 × 1.8 × (θ1 - 10)  θ1-10=0.0072.3 × 10-5 × 1.8  θ1 = 179°C", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>20", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A mercury-in-glass thermometer reads 4cm at ice point and 29cm at steam point. Calculate the temperature when the mercury level is at 9cm.", "images": [], "options": {"A": "13°C", "B": "20°C", "C": "33°C", "D": "38°C"}, "answer": "B", "explanation": "9 - 429 - 4=α100  500 = 25α  α=50025  α = 20°C", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>21", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "The continuous stirring in the method of mixtures to determine the specific thermal capacity of a substance ensures", "images": [], "options": {"A": "continuous dissipation of heat of the room", "B": "uniform distribution of thermal energy to all parts of the mixture", "C": "that thermal energy is confined to the mixture", "D": "that there is rapid heat exchange"}, "answer": "B", "explanation": "Continuous stirring in the method of mixtures ensures uniform distribution of thermal energy to all parts of the mixture. This is because stirring helps to distribute the heat evenly throughout the mixture, ensuring that all parts of the mixture reach the same temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>22", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statements is correct about the effect of dissolved salt on the freezing point of water?", "images": [], "options": {"A": "The freezing point is lowered", "B": "The freezing point is increased", "C": "There is no change in the freezing point", "D": "The change in the freezing point depends on the temperature of the surrounding"}, "answer": "A", "explanation": "When salt is dissolved in water, it lowers the freezing point of the water. This is a process known as freezing point depression. The salt interferes with the intermolecular attractions between the water molecules, reducing their ability to form the crystalline structure necessary for ice to form and thus lowering the freezing point.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2016>23", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "A pressurized perfume bottle is left on the window pane of a room. What happens to the gas molecules of the perfume on a sunny day? They", "images": [], "options": {"A": "expand", "B": "collide less often", "C": "move more rapidly", "D": "contract"}, "answer": "C", "explanation": "When the perfume bottle is left on the window pane on a sunny day, the heat from the sun increases the kinetic energy of the gas molecules in the perfume. This causes the molecules to move more rapidly. This is based on the kinetic theory of gases which states that the temperature of a gas is directly proportional to the average kinetic energy of its molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>24", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "Given that v, f and λ are the velocity, frequency and wavelength of a wave respectively. Which of the following equation is correct?", "images": [], "options": {"A": "v = f2λ", "B": "f = v/λ", "C": "f = v/λ2", "D": "λ = f/v2"}, "answer": "B", "explanation": "The relationship between the velocity (v), frequency (f), and wavelength (λ) of a wave is given by the equation v = fλ. Therefore, the frequency of the wave can be calculated by rearranging this equation to f = v/λ.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2016>25", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "Three letters are placed in front of a plane mirror as illustrated in the diagram below. The image formed is illustrated by", "images": ["Physics/imgs/2016/pix13.png", "Physics/imgs/2016/pix1.png", "Physics/imgs/2016/pix2.png", "Physics/imgs/2016/pix3.png", "Physics/imgs/2016/pix4.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "The   image    formed   is illustrated by:", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2016>26", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "The distance between two successive troughs of a wave is 0.4m. If the frequency of the source is 825Hz. Calculate the speed of the wave.", "images": [], "options": {"A": "165.0 ms-1", "B": "330.0 ms-1", "C": "412.5 ms-1", "D": "825.0 ms-1"}, "answer": "B", "explanation": "The distance between two successive troughs of a wave is the wavelength. The speed of a wave is given by the formula speed = frequency * wavelength. Substituting the given values, speed = 825Hz * 0.4m = 330 ms-1. Therefore, the correct option is 2.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>27", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "X-rays and infra-red rays are both electromagnetic. Which common property do the waves have? Both waves", "images": [], "options": {"A": "are longitudinal", "B": "have the same frequency", "C": "have the same wavelength", "D": "travel at the same speed in a vacuum"}, "answer": "D", "explanation": "X-rays and infra-red rays are both types of electromagnetic waves. All electromagnetic waves, regardless of their frequency or wavelength, travel at the same speed in a vacuum, which is the speed of light (approximately 3.00 x 10^8 m/s). Therefore, the correct option is 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>28", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The image formed by a concave mirror is real, inverted and magnified, when the object is place", "images": [], "options": {"A": "at the focus", "B": "at the centre of curvature", "C": "beyond the centre of curvature", "D": "between the centre of curvature and the focus"}, "answer": "D", "explanation": "When an object is placed between the center of curvature and the focus the image will be real, inverted and magnified", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>29", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Total internal reflection  I. is a phenomenon of refraction of light  II. occurs when light rays travel into a denser medium   III. occurs when the critical angle is just exceeded   IV. is a phenomenon of reflection of light    Which of the statements above are correct?", "images": [], "options": {"A": "I and II only", "B": "I and III only", "C": "I, II and III only", "D": "I, III and IV only"}, "answer": "B", "explanation": "Total internal reflection is a phenomenon that occurs when light travels from a denser medium to a less dense medium at an angle greater than the critical angle.  hus, the option that includes these correct statements is:  I and III only", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>30", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Complementary colours are those which", "images": [], "options": {"A": "have the same refractive index", "B": "have the same wavelength", "C": "add-up to produce black light", "D": "add-up to produce white light"}, "answer": "D", "explanation": "Complementary colors are pairs of colors which, when combined or mixed, cancel each other out (lose hue) by producing a grayscale color like white or black. When placed next to each other, they create the strongest contrast for those two colors. Complementary colors may also be called 'opposite colors'. So, the correct answer is 'add-up to produce white light'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>31", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The diagram above illustrates the waveform of a note produced by vibrations in an air column of length, L. If the speed of sound in air is V, derive an expression for the frequency of the note", "images": ["Physics/imgs/2016/pix14.png"], "options": {"A": "V/L", "B": "5VL/2", "C": "5L/4V", "D": "5V/4L"}, "answer": "D", "explanation": "l = 5/4 λ  λ=4l5  Recall, V = fλ  f=Vλ  f=V4l/5   = 5V/4L", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>32", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "The pair of musical instruments that works on the vibration of air in pipes is", "images": [], "options": {"A": "piano and the organ", "B": "guitar and the flute", "C": "trumpet and the violin", "D": "flute and the trumpet"}, "answer": "D", "explanation": "The flute and the trumpet are both wind instruments that produce sound from the flow of air across an opening; in the flute, the air is directed against the edge of a hole, causing it to vibrate and produce sound, while in the trumpet, the player's lips vibrate to create sound as they blow into a large, flared bell. So, the correct answer is 'flute and the trumpet'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>33", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An astronomical telescope has objective and eye-piece lenses of focal lengths 3.5m and 5 cm respectively. Determine the magnifying power of the telescope when in normal adjustment.", "images": [], "options": {"A": "70.0", "B": "17.5", "C": "7.0", "D": "0.7"}, "answer": "A", "explanation": "The magnifying power of a telescope in normal adjustment is given by the ratio of the focal length of the objective lens to the focal length of the eyepiece. In this case, the focal length of the objective lens is 3.5m (or 350cm) and the focal length of the eyepiece is 5cm. Therefore, the magnifying power is 350cm/5cm = 70.0. Hence, option 1 is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>34", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "An aluminium cable of diameter 4 × 10-3m and resistivity 3.0 × 10-4Ωm has a resistance of 21Ω. Calculate the length of the cable   (π = 3.14)", "images": [], "options": {"A": "8.0 × 102m", "B": "8.8 × 103m", "C": "8.0 × 104m", "D": "8.8 × 104m"}, "answer": "B", "explanation": "Given; d = 4 × 10-3m  Resistivity = 3.0 × 10-8Ωm  R = 21Ω  π = 3.14, l = ?  Recall,R=ϠLA  L=ARϠ  L=227×16 × 10-64×213.0 × 10-8  L= 8.8 × 103m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>35", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "The ammeter A2 shown in the circuit diagram above reads 3.0 A. Determine the reading of the ammeter A1", "images": ["Physics/imgs/2016/pix15.png"], "options": {"A": "12A", "B": "9A", "C": "7A", "D": "2A"}, "answer": "D", "explanation": "V1 = V2  ∴ I1R1 = I2R2  A1 × 6Ω = 3.0 × 4Ω  A1=3.0 × 4Ω 6Ω=6.03  A1 = 2.0A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>36", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "The electricity meters in houses measure energy units consumed in", "images": [], "options": {"A": "kilowatt - hour", "B": "volt", "C": "ampere", "D": "coulomb"}, "answer": "A", "explanation": "Electricity meters in houses measure the amount of electrical energy consumed. The standard unit of electrical energy is the kilowatt-hour (kWh), which is the amount of energy used by a load of one kilowatt over a period of one hour. Hence, option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>37", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "A man and his friend have masses 70kg and 60kg respectively. If they are seated 1.0m apart, calculate the gravitational force of attraction between them.  (G = 6.67 × 10-11 Nm2kg-2)", "images": [], "options": {"A": "1.59 × 10-14N", "B": "2.80 × 10-7N", "C": "1.30 × 102N", "D": "6.30 × 1013N"}, "answer": "B", "explanation": "Recall,  From Newton's Gravitational Law;  F=Gm1m2r2  F=6.67 × 1011 × 70 × 60 (1.0)2  F = 2.80 × 10-7N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>38", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The p.d. across a parallel plate capacitor is 103V. If the distance between the two plates is 10cm, calculate the magnitude of the electric field strength between the plates.", "images": [], "options": {"A": "1.0 × 104 Vm-1", "B": "1.0 × 105 Vm-1", "C": "1.5 × 105 Vm-1", "D": "2.0 × 105 Vm-1"}, "answer": "A", "explanation": "Recall,ElectricField=P.ddistance  E = 103/0.1    = 1.0 × 104Vm-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>39", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "Two different materials, rubbed against each other, acquire opposite charges when separated. This is an example of charging by", "images": [], "options": {"A": "induction", "B": "friction", "C": "conduction", "D": "convection"}, "answer": "B", "explanation": "When two different materials are rubbed against each other and acquire opposite charges when separated, this is an example of charging by friction. Charging by friction occurs when electrons are transferred from one material to another through the process of rubbing. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>40", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Which of the following factors does not affect the e.m.f of a primary cell? Its", "images": [], "options": {"A": "size", "B": "internal resistance", "C": "operating temperature", "D": "duration of usage"}, "answer": "A", "explanation": "The electromotive force (e.m.f) of a primary cell is determined by the chemical reaction within the cell, not its physical size. The other factors listed (internal resistance, operating temperature, and duration of usage) can affect the e.m.f because they can influence the efficiency of the chemical reaction or the flow of electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>41", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "Two magnets are used to magnetize a soft iron bar PQ as illustrated in the diagram above. The correct polarity at P and Q respectively are", "images": ["Physics/imgs/2016/pix16.png"], "options": {"A": "S and N", "B": "N and S", "C": "S and S", "D": "N and N"}, "answer": "B", "explanation": "The correct polarity at P and Q respectively are N and S respectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>42", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "In strong magnets, keepers are used to", "images": [], "options": {"A": "reduce self-demagnetization", "B": "cancel the effect of the earth's magnetic field", "C": "protect the magnet from stray electric fields", "D": "increase the strength of the magnets"}, "answer": "A", "explanation": "Keepers are used in strong magnets to reduce self-demagnetization. Self-demagnetization is a process where a magnet gradually loses its magnetism over time. This can be caused by the magnet's own magnetic field, which can induce opposing magnetic fields within the magnet itself. By using a keeper, the magnetic field lines are 'short-circuited' and this reduces the effect of self-demagnetization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>43", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE", "question": "A 10μC charge moves with a velocity of 1.0 × 105 ms-1 at right angle of a uniform magnetic field of flux density 5.0 × 10-4T. Calculate the force on the charge", "images": [], "options": {"A": "5.0 × 10-5N", "B": "5.0 × 10-4N", "C": "5.0 × 105N", "D": "`5.0 × 106N"}, "answer": "B", "explanation": "Recall, F = qvBsinθ  where, B = 5.0 × 10-4T  Q = 10μC  F = ?  F = 5.0 × 10-4 × 1.0 × 105 × 101 × 10-6 × sin 90    F = 5.0 × 10-4N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>44", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "Which of the following statements is not correct about steel and soft iron?", "images": [], "options": {"A": "Steel is more readily magnetized than soft iron", "B": "Permanent magnets are usually made of steel", "C": "Soft iron is more readily magnetized than steel", "D": "Soft iron more readily loses its magnetism than steel"}, "answer": "A", "explanation": "Steel is harder to magnetize than soft iron. This is because steel is a permanent magnet, which means it retains its magnetism once it's magnetized. Soft iron, on the other hand, is a temporary magnet, which means it's easy to magnetize and demagnetize. Therefore, the statement 'Steel is more readily magnetized than soft iron' is incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>45", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "MAGNETIC FIELD : USE OF ELECTROMAGNETS", "question": "What determines the polarity at the ends of an electromagnet? The", "images": [], "options": {"A": "magnitude of the current passing through the wire", "B": "material of the core of the magnet", "C": "material of the coil", "D": "direction of current in the wire"}, "answer": "D", "explanation": "The polarity of an electromagnet is determined by the direction of the current flowing through the wire. This is based on the right-hand rule, which states that if you point your thumb in the direction of the current, your fingers will curl in the direction of the magnetic field. Therefore, if you reverse the direction of the current, you also reverse the polarity of the electromagnet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>46", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "How many beta particle(s) are emitted in the radioactive decay of   19879 Au → 19880Hg?", "images": [], "options": {"A": "1", "B": "2", "C": "3", "D": "5"}, "answer": "A", "explanation": "In the radioactive decay of 19879 Au → 19880Hg, one beta particle is emitted. This is because a beta decay involves the transformation of a neutron into a proton and an electron (the beta particle). The atomic number (the bottom number) increases by one, indicating that one proton has been added to the nucleus. Therefore, only one beta particle is emitted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>47", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "The phenomenon by which two light atomic nuclei combine to form a heavy nuclide with the release of energy is known as", "images": [], "options": {"A": "radioactivity", "B": "nuclear fusion", "C": "nuclear fission", "D": "chain reaction"}, "answer": "B", "explanation": "Nuclear fusion is the phenomenon whereby two light atomic nuclei combine to form a heavy nuclide with the release of energy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2016>48", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following graphs is correct for the decay of a radioactive substance with a half-life of 2 years?", "images": ["Physics/imgs/2016/pix17.png", "Physics/imgs/2016/pix20.png", "Physics/imgs/2016/pix18.png", "Physics/imgs/2016/pix19.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "The graph that is correct for the decay of a radioactive substance with a half-life of 2 years is:", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>49", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "In a p-type semiconductor, the", "images": [], "options": {"A": "number of holes are equal to the number of electrons", "B": "electrical resistivity increases", "C": "electrons are the majority charge carriers", "D": "holes are the majority charge carriers"}, "answer": "D", "explanation": "In a p-type semiconductor, holes are the majority charge carriers. A p-type semiconductor is created by doping an intrinsic semiconductor with an electron acceptor element during manufacture. The majority charge carriers are holes, while the minority charge carriers are electrons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2016>50", "subject": "Physics", "year": "2016", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Let Δ x be the uncertainty in the measurement of position and Δp the uncertainty in measurement of momentum. Then, the uncertainty principle relation is given as", "images": [], "options": {"A": "Δ x. Δp = h", "B": "Δx. Δp ≤ h", "C": "Δx. Δp ≥ h", "D": "Δx. Δp > h"}, "answer": "C", "explanation": "The uncertainty principle relation is given as:    Δx · Δp ≥ h    This relation states that the product of the uncertainties in position (Δx) and momentum (Δp) is greater than or equal to Planck's constant (h).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>1", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "The diagram above illustrates a micrometer screw gauge. Determine its reading", "images": ["Physics/imgs/2017/pix1.png"], "options": {"A": "2.44mm", "B": "2.46mm", "C": "2.86mm", "D": "2.96mm"}, "answer": "B", "explanation": "The diagram in the question is that of a micrometer screw gauge.  Recall: To take the readings of a micrometer screw gauge, we take the sum of the main scale reading and the micro scale reading.  Micrometer Reading = Mainscale reading + Microscale reading  MR = MSR + msr ----------- (1)  MR = 2.00m + 0.46mm  = 2.46mm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>2", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "DERIVED QUANTITIES AND DIMENSIONAL ANALYSIS :", "question": "Which of the following dimensions represents impulse?", "images": [], "options": {"A": "MLT-2", "B": "MLT-1", "C": "MLT", "D": "ML"}, "answer": "B", "explanation": "Impulse = Ft  Force = ma  a = v/t ; v = d/l = l/t  a = LT-2  so force = MLT-2  Therefore, Impulse = Ft  = MLT-2 × T = MLT-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>3", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION", "question": "A body accelerates uniformly from rest at 2ms-2. Calculate its velocity when it has travelled a distance of 9m.", "images": [], "options": {"A": "3.0 ms-1", "B": "4.5ms-1", "C": "6.0ms-1", "D": "18.0ms-1"}, "answer": "C", "explanation": "a = 2m/s2  u = 0  s = 9m   v = ?  using v2 = u2 + 2as  v2 = 02 + 2 x 2 x 9  v2 = 36  v =  &radic;36&nbsp; = 6m/s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>4", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statements about matter is not correct?", "images": [], "options": {"A": "Molecules of solids move more freely than molecules of liquids and gases", "B": "Molecules of solids are more closely packed than those of the liquids", "C": "Energy is required to break the intermolecular forces of attraction between molecules", "D": "Molecules of liquids move about within the liquid and they are in constant random motion"}, "answer": "A", "explanation": "The molecules of gases move with the highest speed, followed by the molecules of liquid and then solids.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>5", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A ball is projected horizontally from the top of a tower. Neglecting air resistance, which of the following statements about its motion is/are correct?  I. Vertical acceleration on the ball decreases as it falls   II. The vertical force on the ball remains constant  III. The vertical speed of the ball increases as it falls", "images": [], "options": {"A": "I only", "B": "II only", "C": "I and II only", "D": "II and III only"}, "answer": "D", "explanation": "The vertical acceleration on the ball does not decrease as it falls, it remains constant due to gravity. Therefore, statement I is incorrect. The vertical force on the ball also remains constant, as it is the gravitational force acting on the ball. Therefore, statement II is correct. The vertical speed of the ball increases as it falls due to the constant acceleration from gravity. Therefore, statement III is correct. Hence, the correct option is 'II and III only'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>6", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "Two forces 100N and 60N act on an object of mass 10Kg as illustrated in the diagram above. Neglecting friction, calculate the acceleration of the object.", "images": ["Physics/imgs/2017/pix6s.png"], "options": {"A": "4.0ms-2", "B": "13.1ms-2", "C": "16.0ms-1", "D": "22.6ms-2"}, "answer": "B", "explanation": "Resolving 100N into horizontal and vertical  100sin45 = 70.71; 100cos45 = 70.71  vertical forces =100 -70.71 =29.29  Horizontal force = 70.71 + 60 = 130.71    Resultant of vertical and horizontal forces using pythagoras theorem  R = 133.9N from F = m2  a=Fm=133.910=13.4 m/s2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>7", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A body weighing 14N in air is partially immersed in water. If the mass of water displaced in the process is 200g, calculate the upthrust on the body. [g = 10ms-2]", "images": [], "options": {"A": "2.0N", "B": "3.0N", "C": "3.5N", "D": "7.0N"}, "answer": "A", "explanation": "W = 14N  mass of water displaced = 200g = 0.2kg  Upthrust = weight of the fluid displaced   = mass of the fluid displaced × gravity  = 0.2kg × 10m/s2   = 2N", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>8", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following processes is not a surface phenomenon?", "images": [], "options": {"A": "Condensation", "B": "Evaporation", "C": "Photoemission", "D": "Thermionic emission"}, "answer": "A", "explanation": "The process that is not considered a surface phenomenon among the given options is:    Condensation.    While condensation involves the transition from a gas to a liquid at surfaces (like dew forming on grass), it occurs throughout the volume of the gas and liquid, making it more of a bulk phenomenon. The other processes listed (evaporation, photoemission, and thermionic emission) are closely related to the interactions occurring at surfaces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>9", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "A chemical balance is used for measuring", "images": [], "options": {"A": "volume", "B": "mass", "C": "thickness", "D": "density"}, "answer": "B", "explanation": "A chemical balance is used for measuring mass. It is a device used in chemical laboratories for the precise measurement of small quantities of matter. It is not used for measuring volume, thickness or density.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>10", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A body is whirled round a circular path at constant speed. Which of the following diagrams correctly indicates the direction of the body's velocity (v) and acceleration (a)?", "images": ["Physics/imgs/2017/pix10a.png", "Physics/imgs/2017/pix10b.png", "Physics/imgs/2017/pix10c.png", "Physics/imgs/2017/pix10d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "For a body undergoing circular motion, the acceleration is directed towards the centre, and the velocity is directed round the circumference of the circle as we have in", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>11", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MOTION : CONCEPT OF SPEED", "question": "A motorist travelling at 72kmh-1 had his eyes shut for 0.4s during a hard sneeze. Calculate the distance covered by him during this time interval", "images": [], "options": {"A": "50.0m", "B": "28.8m", "C": "18.0m", "D": "8.0m"}, "answer": "D", "explanation": "Velocity=72kmh=72*times100360=20ms-1  Time = 0.4s, Distance, S = ?  FromS=ut+12at2  Since the motorist is travelling at 72km/h, it suggests that the velocity is constant, therefore, acceleration = 0  therefore, S = ut = 20 × 0.4 = 8m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>12", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "The angle at which a projectile must be fired to cover maximum range is", "images": [], "options": {"A": "30°", "B": "45°", "C": "60°", "D": "90°"}, "answer": "B", "explanation": "The angle, θ at which aa projectile must be fired to cover maximum horizontal distance/range  = 45°  N.B:Rmax=u2g", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>13", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "A body can undergo the following types of motion except", "images": [], "options": {"A": "random", "B": "translational", "C": "rotational", "D": "relative"}, "answer": "D", "explanation": "A body cannot undergo \"relative motion\". Relative motion usually involves two bodies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>14", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "Which of the following graphs correctly represents the relationship between the kinetic energy (K.E) and the displacement (d) from point of release of a swinging pendulum bob?", "images": ["Physics/imgs/2017/pix14a.png", "Physics/imgs/2017/pix14b.png", "Physics/imgs/2017/pix14c.png", "Physics/imgs/2017/pix14d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "For a swinging pendulum, at the point of rest, i.e at equilibruim, the K.E is maximum, when displaced so that it moves through a certain height h, the K.E decreases to minimum and then back to maximum as it comes back to the equilibrium position    From the illustration above, we obtain the following graph.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>15", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "The energy stored in a spring of stiffness constant k = 2000Nm−1 when extended 4cm is", "images": [], "options": {"A": "0.16J", "B": "1.60J", "C": "16.00J", "D": "160.00J"}, "answer": "B", "explanation": "The spring constant = the measure of stiffness = 2000Nm−1    Energy stored in a spring = Work done to stretch it through a distance = change in potential energy     = kx2/12     = 2000×(0.04)2/2= 3.22=1.60J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>16", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Ice of mass 50g at 0°C was completely melted by 70% of the total heat energy supplied. Calculate the total heat energy supplied. (Specific latent heat of fusion of ice = 336Jg-1]", "images": [], "options": {"A": "2400J", "B": "6800J", "C": "7251J", "D": "24000J"}, "answer": "D", "explanation": "Mass of ice = 50g  Temperature of ice at 0° to water at 0°C   I = 336 Fom, Q = ml  70% of Q = ml   70100×Q=ml  0.7Q = ml  0.7Q = 50 *times 336  Q=50×3360.7=24000J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>17", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MACHINES :", "question": "A plane is inclined at an angle θ to the horizontal. Its velocity ratio is", "images": [], "options": {"A": "sinθ", "B": "tanθ", "C": "1sinθ", "D": "1tanθ"}, "answer": "C", "explanation": "The velocity ratio of the inclined plane is:  V.R =1sinθ", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>18", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "The diagram above illustrates a beaker of water being heated. It is observed that as the bubbles rise they get bigger in size. The reason for this observation is", "images": ["Physics/imgs/2017/pix18.png"], "options": {"A": "water pressure on the bubbles decreases", "B": "density of water increases with rise in temperature", "C": "volume of water increases with rise in temperature", "D": "atmospheric pressure on the bubbles decreases"}, "answer": "D", "explanation": "A decrease in the atmosphere pressure causes the bubble to get bigger", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>19", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT", "question": "Which of the following devices transforms light energy to electrical energy?", "images": [], "options": {"A": "Bulb", "B": "Television", "C": "Solar cell", "D": "Light emitting diode (LED)"}, "answer": "C", "explanation": "A solar cell is a device that transforms light energy into electrical energy. This is done through the photovoltaic effect, where photons from the light source are absorbed by the solar cell, causing electrons to be knocked loose from their atoms. These free electrons then move through the cell, creating an electric current.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>20", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "A motor of a corn mill machine operates on electrical energy of 1.44 × 105J. If one-quarter of the energy is wasted in the form of sound and heat, determine the efficiency of the machine.", "images": [], "options": {"A": "25%", "B": "36%", "C": "64%", "D": "75%"}, "answer": "D", "explanation": "Efficiency=Work outputWork input×100  Workoutput=34×1.44×105(since14iswasted)  Work input = 1.44 × 105  Efficiency=34 × 1.44 × 1051.44 × 105×1001  Efficiency=34×100=75%", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>21", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Thermal energy added or removed from a substance that changes the state of the substance is called", "images": [], "options": {"A": "latent heat", "B": "heat of reaction", "C": "calorimetry", "D": "specific heat"}, "answer": "A", "explanation": "The thermal energy that is added or removed from a substance, causing it to change state, is called latent heat. This is the heat energy required to change the state of a substance without changing its temperature. For example, the heat energy required to change water from a solid (ice) to a liquid, or from a liquid to a gas (steam), is latent heat.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>22", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "The maximum density of water occurs at a temperature of", "images": [], "options": {"A": "0°C", "B": "4°C", "C": "37°C", "D": "273°C"}, "answer": "B", "explanation": "The maximum density of water occurs at 4°C. This is an explanation to the anomalous expansion of water", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>23", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "HEAT ENERGY : VAPOUR AND VAPOUR PRESSURE", "question": "A vapour whose molecules are in dynamic equilibrium with those of its own liquid is said to be", "images": [], "options": {"A": "unsaturated", "B": "gaseous", "C": "saturated", "D": "diffused"}, "answer": "C", "explanation": "Such vapour is said to be saturated. That is, the rate of evaporation is equal to the rate of condensation", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>24", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "The diagram above illustrates two waves of equal amplitudes A and frequencies approaching each other.   When the two waves meet at a point 1 mid way between them, the vertical displacement of the resulting wave will be", "images": ["Physics/imgs/2017/pix24.png"], "options": {"A": "0", "B": "A/2", "C": "A/4", "D": "2A"}, "answer": "D", "explanation": "The waves will interfere constructively, so that a bigger wave will be formed   A + A = 2A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>25", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "A rainbow is formed when sunlight is incident on water droplets suspended in the air due to", "images": [], "options": {"A": "diffraction", "B": "refraction", "C": "dispersion", "D": "interference"}, "answer": "C", "explanation": "A rainbow is formed due to the dispersion of light. When sunlight passes through raindrops, it is refracted, or bent, and then reflected by the inside surface of the droplet. When the light exits the droplet, it is refracted again. The bending of light, or refraction, causes the different colors in the light spectrum to spread out and form a circle of colors. This is known as dispersion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>26", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "Which of the following statements about the 3rd overtone of a vibrating air column of an open pipe is correct? It has", "images": [], "options": {"A": "4 nodes", "B": "5 nodes", "C": "3 antinodes", "D": "4 antinodes"}, "answer": "A", "explanation": "The diagram above represents an open pipe at the 3rd overtone. There are 5 antinodes and 4 nodes", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>27", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "Consider the wave equation:  y = 10sin7(x - 50t). What does the number 10 in the equation represent?", "images": [], "options": {"A": "Acceleration", "B": "Speed", "C": "Amplitude", "D": "Wavelength"}, "answer": "C", "explanation": "In the wave equation y = Asin(kx - wt), A represents the amplitude of the wave. The amplitude of a wave is the maximum displacement of the wave from its equilibrium position. In this case, the number 10 in the equation represents the amplitude of the wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>28", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PROPERTIES OF WAVES : DIFFRACTION", "question": "Plane waves passing through a narrow gap emerge as circular waves. This phenomenon is known as", "images": [], "options": {"A": "interference", "B": "dispersion", "C": "refraction", "D": "diffraction"}, "answer": "D", "explanation": "The phenomenom is diffraction. This occurs when waves propagating in group pass through a tiny orifice to form a circular wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>29", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light incident at an angle θ in a rectangular prism grazes the surface of the prism on emerging from the prism. Determine the value of θ. [Absolute refractive index of the material of the prism is 1.5].", "images": [], "options": {"A": "41.8°", "B": "48.2°", "C": "60.8°", "D": "90.0°"}, "answer": "A", "explanation": "Angle of incidence, i = θ  Refractive index, n = 1.5  N.B: i = e (angle of emergence)  n=1sinθ  1.5=1sinθ  1.5sinθ = 1  sinθ = 0.66  θ = sin-10.66  θ = 41.8°", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>30", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "The diagram above illustrates a wave set-up between two fixed ends 4.0m apart. If the speed of the wave is 1.0ms-1, its wavelength and frequency respectively are", "images": ["Physics/imgs/2017/pix30.png"], "options": {"A": "1m, 0.25Hz", "B": "2m, 0.25Hz", "C": "2m, 0.50Hz", "D": "4m, 0.50Hz"}, "answer": "C", "explanation": "Velocity, v = 1.0m/s    4m = λ/2 + λ/2 + λ/2 + λ/2  4m=4λ2  8m = 4λ  λ=8m4=2m  V = fλ ---------- (1)  1.0 = f × 2  f=12=0.5Hz  (λ, f) = (2m, 0.5Hz)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>31", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "Two plane mirrors are inclined at an angle 20° to each other. Determine the number of images formed when an object is placed between them.", "images": [], "options": {"A": "17", "B": "18", "C": "19", "D": "20"}, "answer": "A", "explanation": "Angle of inclination, θ = 20°, n = ?  Recall: For two mirrors inclined at θ to each other, the number of images formed will be   Fromn=360θ-1  n=36020-1  n = 18 - 1 = 17 images", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>32", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A converging lens of focal length 10cm forms an erect image three times the size of a real object. Calculate the distance between the object and the image.", "images": [], "options": {"A": "26.6cm", "B": "11.1cm", "C": "13.3cm", "D": "20.0cm"}, "answer": "A", "explanation": "Focal length = 10cm  * The image is erect and magnified   Magnification, m = 3 = v/u  Image size (V) = 3U --------- (1)    N.B: When the converging lens forms a magnified, and erect image, the image is always virtual.  The distance between the object and the image is given as d.  d = v - u -------------- (2)  recall:1f=1v+1u  110=13u+1u  110=1+33u  3u = 40  u = 13.3cm  v = 3u = 39.9cm  d = v - u = 39.9cm - 13.3cm  d = 26.6cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>33", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The inverse of the time required for a wave to complete one full cycle is called", "images": [], "options": {"A": "wavelength", "B": "period", "C": "frequency", "D": "amplitude"}, "answer": "C", "explanation": "The time taken for a wave to complete a cycle is known as period.  The inverse is called \"frequency\"", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>34", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "Two bar magnets are placed near each other. Which of the following diagrams correctly illustrates the magnetic field pattern formed by the pair?", "images": ["Physics/imgs/2017/pix34a.png", "Physics/imgs/2017/pix34b.png", "Physics/imgs/2017/pix34c.png", "Physics/imgs/2017/pix34d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The magnetic flux (lines of force) move from the N-pole to the S-pole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>35", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The force per unit charge experienced at a point in a field is the", "images": [], "options": {"A": "gravitational field strength", "B": "electric potential", "C": "electric field intensity", "D": "magnetic field strength"}, "answer": "C", "explanation": "The force per unit charge experienced at a point in a field is the electric field intensity. It is a vector quantity and is defined as the force experienced by a unit positive charge placed at that point. Gravitational field strength is the force per unit mass experienced by a small test mass placed in the field. Electric potential is the work done per unit charge in bringing a positive point charge from infinity to a particular point in the field. Magnetic field strength is a measure of the intensity of the magnetic field at a particular location.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>36", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "Which of the following objects is not a conductor of electricity?", "images": [], "options": {"A": "The Earth", "B": "Human body", "C": "Iron rod", "D": "Dry wood"}, "answer": "D", "explanation": "A conductor is a material that allows electric charge to move freely. Metals like iron rod are good conductors of electricity. The Earth and the human body are also conductors due to the presence of water and other substances that allow the flow of electric charge. However, dry wood is a poor conductor or insulator of electricity because it lacks free electrons that can move and carry electric charge.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2017>37", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "A circuit is set up as shown in the diagram above. When the key is closed, the reading on the ammeter will be", "images": ["Physics/imgs/2017/pix37.png"], "options": {"A": "6A", "B": "4A", "C": "2A", "D": "1A"}, "answer": "C", "explanation": "Resistor in parallel  RP=1x11+1=12  RS=1+12=32Ω  From ohm's law,  I=VR=33/2=3x23=63=2A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>38", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY", "question": "Which of the following statements is/are correct?  I. Gravitational potential due to a mass at a point a distance r away is proportional to r2  II. Gravitational field strength is a scalar quantity  III. Gravitational intensity is proportional to the weight of a unit mass", "images": [], "options": {"A": "I, II and III", "B": "III only", "C": "II only", "D": "I only"}, "answer": "B", "explanation": "Gravitationalpotential,V=-GMer  (1)iswrong,Vα1randnotα1r2  All strengths/intensities are vector quantities. So (II) is wrong only (III) is correct.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>39", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The diagrams below illustrate electrical connections to the element of an electric pressing iron. In which of the connections is the fuse correctly fixed?", "images": ["Physics/imgs/2017/pix39a.png", "Physics/imgs/2017/pix39b.png", "Physics/imgs/2017/pix39c.png", "Physics/imgs/2017/pix39d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The fuse is correctly fixed in the diagram:", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>40", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "A transformer connected to a 240Vrms has 3000 turns in its primary coil and 500 turns in its secondary coil. Calculate the output voltage", "images": [], "options": {"A": "4000V", "B": "400V", "C": "40V", "D": "4V"}, "answer": "C", "explanation": "Np = 3000turns   Ns = 500turns  Ep = 240Vrms  Es = ?  Es/Ep = Ns/Np  Es=Ep×NsNp  =240×5003000=1203= 40V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>41", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A lamp rated 100W, 240V is lit for 5 hours. Calculate the cost of lighting the lamp if 1kWh of electrical energy cost ₦5.", "images": [], "options": {"A": "₦2.50", "B": "₦3.20", "C": "₦6.50", "D": "₦9.60"}, "answer": "A", "explanation": "Power = 100w  Voltage = 240v  Time = 5 hrs  Energy consumed (w) = Pt= 100 *ties* 5 = 500whr  converting 10 kilowatt hour   500/1000 = 0.5Kwh  cost of lighting = 0.5× 5= ₦2.5", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>42", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A battery of emf 3.0V is connected across a potentiometer wire AB of 10Ωm-1 as illustrated in the diagram above. If the jocket J makes contact at the 30cm mark, determine the resistance of length AJ and voltage across AJ.", "images": ["Physics/imgs/2017/pix42.png"], "options": {"A": "3.0Ω ; 0.9V", "B": "3.0Ω ; 3.0V", "C": "3.3Ω ; 0.3V", "D": "3.3Ω ; 9.0V"}, "answer": "A", "explanation": "E = 3V, R/l = 10Ωm-1  l = 30cm, R = ?  Rl=10  R0.3=10  R = 3Ω  EV=l1l2  V=3×0.31  V = 0.9V", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>43", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "The main reason why a.c is transmitted at very high voltage and low current is that it", "images": [], "options": {"A": "flows faster through the conductor", "B": "can be stepped down", "C": "is cheaper to generate", "D": "reduces heat loss"}, "answer": "D", "explanation": "This transmission mode reduces heat loss.  N.B = H = I2Rt  H α I2  The higher the current, the higher the amount of heat generated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>44", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The diagram above illustrate two charged bodies, X and Y separated by a distance r. Each body has charge q and mass m. Which of the following statements about the electrostatic force Fe and the gravitational force Fg acting between the bodies is correct?", "images": ["Physics/imgs/2017/pix44.png"], "options": {"A": "Fe is attraction while Fg is repulsion", "B": "Both Fe and Fg are that of repulsion", "C": "Both Fe and Fg are that of attraction", "D": "Fe is repulsion while Fg is attraction"}, "answer": "D", "explanation": "There is always a gravitational force of ATTRACTION, but the electrostatic force of ATTRACTION OR REPULSION. For the charges, illustrated in the question, there will be a repulsion, since they are like charges", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>45", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : IMPEDANCE", "question": "The opposition offered to an alternating current in a C - R series circuit is known as", "images": [], "options": {"A": "impedance", "B": "resistance", "C": "reactance", "D": "friction"}, "answer": "A", "explanation": "In an alternating current (AC) circuit containing both resistance (R) and capacitance (C), the total opposition to current flow is called impedance. Impedance takes into account both the resistance of the circuit and the reactance (opposition to current flow caused by capacitors and inductors). Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>46", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Which of the following pairs of concepts constitutes complementary variables as expressed by the Heisenberg uncertainty principle?", "images": [], "options": {"A": "Momentum and time", "B": "Energy and acceleration", "C": "Position and momentum", "D": "Velocity and momentum"}, "answer": "C", "explanation": "The Heisenberg uncertainty principle states that the more precisely the position of a particle is determined, the less precisely its momentum can be known, and vice versa. Therefore, position and momentum are complementary variables.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>47", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The nucleon number of an atom is the total number of", "images": [], "options": {"A": "electrons and protons", "B": "electrons and neutrons", "C": "neutrons minus electrons", "D": "protons and neutrons"}, "answer": "D", "explanation": "The nucleon number/mass number of an atom is the number of protons and neutrons in the nucleus of the atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>48", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "n = α ----------------- 0.0eV  E = 3 ----------------- - 1.6eV  E = 2 ----------------- -3.7eV  E = 1 ----------------- -5.5eV  E = 0 ----------------- -10.4 eV  The energy levels in the mercury atom is illustrated in the diagram above. Calculate the ionisation energy of the atom.", "images": [], "options": {"A": "+21.2eV", "B": "+10.4eV", "C": "-10.4eV", "D": "-21.2eV"}, "answer": "B", "explanation": "The ionisation energy of an atom is the energy required to remove an electron from the ground state (lowest energy level) of the atom to infinity. In the given diagram, the ground state energy level is -10.4 eV. Therefore, the ionisation energy is the absolute value of this energy level, which is +10.4 eV.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2017>49", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following statements about gamma radiation is correct? Gamma radiation can", "images": [], "options": {"A": "be seen by the naked eye", "B": "not pass through an aluminium foil", "C": "be present naturally in our surroundings", "D": "be used as a tracer"}, "answer": "D", "explanation": "Gamma radiation can be used as a tracer in medical imaging and industrial processes to track the movement of substances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2017>50", "subject": "Physics", "year": "2017", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Radio waveMicro waveInfrared wavePQRGamma ray  The table above shows the components of electromagnetic spectrum in order of increasing frequency. Which of the following sets correctly identifies P, Q and R respectively?", "images": [], "options": {"A": "Visible, ultraviolet, X-ray", "B": "X-ray, visible, ultraviolet", "C": "Ultraviolet, visible, X-ray", "D": "X-ray, ultraviolet, visible"}, "answer": "A", "explanation": "In order of increasing frequencies, the electromagnetic spectrum is arranged as thus  Radiowave  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  Microwave  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  Infrared wave  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  Visible light  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  Ultraviolet rays  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  X-rays  &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp ↓  Gamma rays", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>1", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The S.I unit of sound energy is", "images": [], "options": {"A": "Hz.", "B": "cd.", "C": "dB.", "D": "J."}, "answer": "D", "explanation": "The SI unit of energy, including sound energy, is the joule (J). Sound energy is a form of mechanical energy that is created when a force causes an object or substance to vibrate — the energy is transferred through the substance in a wave. Therefore, the correct answer is J.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>2", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "The general definition of elastic modulus is", "images": [], "options": {"A": "stressstrain", "B": "strainstress", "C": "stress x strain", "D": "√stress/strain"}, "answer": "A", "explanation": "ElasticModulus=Young'sModulus=Tensile StressTensile strain", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>3", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The diagram above illustrated a simple barometer. Which distance measures the atmospheric pressure?", "images": ["Physics/imgs/2018/pix1.png"], "options": {"A": "PQ", "B": "QR", "C": "RS", "D": "QS"}, "answer": "B", "explanation": "The part which measures the atmospheric pressure is QR.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>4", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "The property of a body to remain at rest or to continue in a uniform motion, in a straight line is called", "images": [], "options": {"A": "momentum", "B": "inertia", "C": "impulse", "D": "energy"}, "answer": "B", "explanation": "Inertia is the tendency of a body at rest to remain at rest or a body undergoing uniform motion along a straight line to continue in that state of motion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>5", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "During a training session, two footballers pass a ball repeatedly between each other. The 'to and fro' motion of the ball is not simple harmonic because the   I. acceleration of the ball is not directed towards a fixed point   II. restoring force is not directed towards the centre.  III. acceleration of the ball is not directly proportional to the displacement from a fixed point     Which of the statements above are correct?", "images": [], "options": {"A": "I and III only", "B": "I and II only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "The 'to and fro' motion of the ball is not simple harmonic because all the three statements are correct. In a simple harmonic motion, the acceleration of the object is always directed towards a fixed point (the equilibrium position), the restoring force is always directed towards the centre and the acceleration of the object is directly proportional to its displacement from its equilibrium position.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>6", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES’ PRINCIPLE", "question": "A dam is able to hold  large quantity of water because its wall is", "images": [], "options": {"A": "thickest at the top", "B": "thickest at the middle", "C": "thickest at the bottom", "D": "of the same thickness throughout"}, "answer": "C", "explanation": "A dam is able to hold large quantity of water because of the fact that it is thickest at the bottom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>7", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A body of mass m moving round a circle of radius r with a uniform speed v experiences a centripetal force F. The work done by the centripetal force on it is", "images": [], "options": {"A": "Fv.", "B": "zero", "C": "Fmr", "D": "Fr/m"}, "answer": "B", "explanation": "a = ac {centripetal acceleration)  Fc = mac  The motion starts from A; and ends at A.  The work done = 0", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>8", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A block is acted upon by two horizontal forces as illustrated in the diagram above. The block accelerate at 1.5ms-2. Calculate the mass of the block.", "images": ["Physics/imgs/2018/pix2.png"], "options": {"A": "6 kg", "B": "9 kg", "C": "10 kg", "D": "15 kg"}, "answer": "A", "explanation": "Net force on the body = 10N - 1N = 9N  Recall: FN = ma ------------- *  9 = 1.5(m)  m = 6.0kg", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>9", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "Which of the following quantities are dimensionally independent?   I. dielectric constant   II. momentum   III. efficiency   IV. refractive index", "images": [], "options": {"A": "I and II", "B": "II, III and IV", "C": "I, II, III and IV", "D": "I, III and IV"}, "answer": "D", "explanation": "Momentum is the only quantity in the option that has a dimension, the remaining quantities in the options are dimensionless.  Momentum = mass × velocity  = kgms-1  The dimension of momentum = MLT-1.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>10", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A body is projected with an initial velocity u at angle θ to the horizontal. If Rmax is the maximum range of the projectile, what does the relation  represent u2/Rmax respectively.", "images": [], "options": {"A": "The vertical distance covered", "B": "Acceleration due to gravity", "C": "The horizontal distance covered", "D": "The acceleration of the body due to gravity"}, "answer": "D", "explanation": "The range R of the motion is given as  R=u2sin2θg  at Rmax, i.e when θ = 45°  Rmax=u2sin90°g  Rmax=u2g  g=u2Rmax------------***  ∴u2Rmax=accelerationduetogravity", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>11", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "An object at rest is said to posses", "images": [], "options": {"A": "potential energy", "B": "kinetic energy", "C": "chemical energy", "D": "electrical energy"}, "answer": "A", "explanation": "An object at rest is said to possess potential energy.    at point A, the body possesses P.E = Wh = mgh", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>12", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "According to Newton's law of cooling, the heat energy lost her unit area of a body depends the   I. Surface area   II. Nature of the surface   III. Temperature of the surface", "images": [], "options": {"A": "I and II only", "B": "II and IV only", "C": "I, II and III", "D": "I, II and IV"}, "answer": "C", "explanation": "According to the Newton's law of cooling.  Heatlostpersecond=dQdt=KS(θ-θR)-------(1)  S → Area of the body surface  θR → temperature of the surrounding  K → a constant that depends on the nature of the surface.  Only the temperature of the surface does not fall into the equation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>13", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "The graph of density against temperature for water is correctly illustrated by", "images": ["Physics/imgs/2018/pix3.png", "Physics/imgs/2018/pix4.png", "Physics/imgs/2018/pix5.png", "Physics/imgs/2018/pix6.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "Normally, the higher the temperature, the lower the density and vice versa.  But it should be noted between 0°C and 4°C water behaves anomalously, i.e it density increases with temperature; from 4°c and above, it tends to decrease with temperature.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>14", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A football is kicked at an angle of 45o to the horizontal over a defence line up with a velocity of 15 ms-5. Calculate the magnitude of horizontal velocity of the ball at its highest point. (Neglect friction, g = 10 ms-2)", "images": [], "options": {"A": "0.0 ms-1", "B": "5.6  ms-1", "C": "10.6  ms-1", "D": "15.0  ms-1"}, "answer": "C", "explanation": "Uy = Usinθ  Ux = Ucosθ  From = v = u + at  since the ball is moving upward from A to B i.e a = -g  v = u - gt  vy = uy - gt  vy = usinθ - gt ----------- *  vx = ucosθ --------- **  As the ball goes up, Vy decreases and when it gets to the highest point, Vy = 0.  N.B: Vx (horizontal velocity) is constant through out the motion.  Vx=15cos45°=15(1&radic;2&nbsp;)=15&radic;2&nbsp;=7.5&radic;2&nbsp;=10.6ms-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>15", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The ice point on the absolute scale of temperature is", "images": [], "options": {"A": "0 K.", "B": "32 K.", "C": "100 K", "D": "237 K."}, "answer": "A", "explanation": "The ice point on the absolute scale of temperature, also known as the Kelvin scale, is 0 K. This is the lowest possible temperature, where all thermal motion ceases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>16", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following factors does not increase the rate of evaporation of water in a lake?", "images": [], "options": {"A": "Increase in the pressure of the atmosphere", "B": "Rise in temperature", "C": "Increase in the surface area of the lake", "D": "Increase in the speed of wind"}, "answer": "A", "explanation": "The rate of evaporation increases with   - an increased surface area  - an increased wind speed  - an increased temperature.  N.B: Atmospheric pressure decreases with evaporation rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>17", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The bob of a simple pendulum takes 8.0 s to complete 10 oscillations. Determine the frequency of oscillation of the bob.", "images": [], "options": {"A": "0.80 Hz", "B": "1.25 Hz", "C": "7.50 Hz", "D": "8.00 Hz"}, "answer": "B", "explanation": "The frequency of oscillation of the bob is the reciprocal of the time taken for one oscillation. Given that the bob takes 8.0 s to complete 10 oscillations, the time for one oscillation is 8.0 s / 10 = 0.8 s. Therefore, the frequency is 1 / 0.8 s = 1.25 Hz.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>18", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The diagram above illustrates the mercury-in-glass the thermometer used for determining the temperature of a room. Use the date on it to determine the room temperature.", "images": ["Physics/imgs/2018/pix7.png"], "options": {"A": "3.3oC", "B": "7.0oC", "C": "13.0oC", "D": "30.0oC"}, "answer": "D", "explanation": "Recall:  TcT100=XT-XoX100-X0  X ≡ Thermometric property like volume, pressure, length (in this case)  Tc100=3cm10cm (We are comparing with the centigrade scale)  Tc = 30°C", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>19", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "Frequency is measured in", "images": [], "options": {"A": "metre per second", "B": "second", "C": "hertz", "D": "farad"}, "answer": "C", "explanation": "The S.I unit of frequency is Hertz.  This was named after Friedrich Hertz, who gave the most acceptable definition of frequency.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>20", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following electromagnetic wave is most energetic?", "images": [], "options": {"A": "Radio waves", "B": "X-ray", "C": "Gamma rays", "D": "Ultra-violet rays"}, "answer": "C", "explanation": "From, E = hf ----------- * {According to Max Planck}  The higher the energy, the higher the frequency and vice versa. So the one with the highest frequency will have the highest energy.    According to the arrange Gamma rays are the most energetic since they have the highest frequency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>21", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "Rainbow formation is a natural phenomenon illustrating that white light", "images": [], "options": {"A": "splits into three components after rainfall", "B": "is dispersed by glass prisms.", "C": "splits into its constituent colours before rainfall", "D": "is dispersed into its constituent colour by raindrops"}, "answer": "D", "explanation": "A rainbow is a meterological phenomenon that is caused by reflection, refraction and dispersion of light in water droplets resulting in a spectrum of light appearing in the sky.  &nbsp &nbsp The rainbow formation is basically due to 3 phenomena refractive total internal reflection and dispersion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>22", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The lens illustrated above can best be described as a", "images": ["Physics/imgs/2018/pix8.png"], "options": {"A": "converging meniscus", "B": "plano-convex", "C": "diverging meniscus", "D": "bi-convex"}, "answer": "B", "explanation": "Plano-convex lenses are positive spherical lenses having convex surface on one side and flat surface on the other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>23", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "Two plane minors are inclined to each other such that an object between them has 11 images. Determine the angles of inclination", "images": [], "options": {"A": "300", "B": "450", "C": "600C", "D": "900C"}, "answer": "A", "explanation": "Recall: When two plane mirrors are inclined at an angle θ, the number (n) of images formed is given by:  n=360θ-1  11=360θ-1  12=360θ  12θ = 360  θ = 30°", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>24", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "The pitch of a note is not affected by", "images": [], "options": {"A": "frequency", "B": "tension in a vibrating string", "C": "mass of a vibrating string", "D": "amplitude of sound wave"}, "answer": "D", "explanation": "Pitch depends on frequency, f  Recall:F=vλ-----------*  For a string,    L=λ2  λ = 2L  ∴f=V2L;f=12L&radic;Tϥ&nbsp;  ϥ=mL→masslength(Tistension)  So automatically, pitch depends of frequency, mass and tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>25", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "When two flat plate conductors are arranged in such a way that they passes equal and opposite changes separated by a dielectric, they from a/an", "images": [], "options": {"A": "electroscope", "B": "electrophorus", "C": "capacitor", "D": "cell"}, "answer": "C", "explanation": "Diagrammatically, we have:     This description gives a capacitor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>26", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "Which electricity device does the diagram above illustrate?", "images": ["Physics/imgs/2018/pix9.png"], "options": {"A": "a.c. generator", "B": "a.c. motor", "C": "d.c. generator", "D": "d.c. motor"}, "answer": "A", "explanation": "This is a diagrammatic representation of an A.C generator or alternator.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>27", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A simple barometer is constructed using a liquid Q1 of density 16.2g/cm3. Calculate the least length of the tube to be used to measure pressure of 1.5 atmospheres.   (Density of mercury = 13.6/cm3)  [atmosphere = 76.0 cm of mercury]", "images": [], "options": {"A": "1358 mm", "B": "957 mm", "C": "760 mm", "D": "638 mm"}, "answer": "D", "explanation": "pressure of mercury = pressure of liquid   P = hpg  hmpmgm = hQpQgQ  7 x 13.6 x 10 = hQ x 16.2 x 10  76x13.6x1016.2x10=hQ    hQ = 63.8cm= 638mm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>28", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "A bar AB is balanced horizontally on two knife edges as illustrated in the diagram above. Determine the weight of the bar", "images": ["Physics/imgs/2018/T4D7F3.png"], "options": {"A": "10.0N", "B": "20.0N", "C": "40.0N", "D": "50.0N"}, "answer": "C", "explanation": "Since the question says it is \"balanced horizontally\", it means it is at equilibrium.  One of the conditions for equilibrium, particularly for a body that is acted upon by a system of parallel forces is that:  Total upward force = Total downward force  20N + 20N = W  40N = W  W = 40N  The weight of the ruler is 40N.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>29", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "To obtain a virtual, erect and magnified image from a thin converging lens, an object must be placed", "images": [], "options": {"A": "between the focus and the lens", "B": "at the focus", "C": "between the focus and twice the focal length", "D": "beyond twice the focal length"}, "answer": "A", "explanation": "A converging lens is a convex lens.  To obtain a virtual, erect and magnified image the object must be placed between the focal point (F) and the lens     the object must between the focus and the lens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>30", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "The diagram above represents a transverse travelling wave. Which two points are 1800 out of phase?", "images": ["Physics/imgs/2018/pix11.png"], "options": {"A": "A and E", "B": "B and D", "C": "C and F", "D": "D and H"}, "answer": "B", "explanation": "Points    B    and   D   are   out of  phase by 180°", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>31", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "Two objects P and Q of masses 100kg and 20kg respectively are 1.2m apart on a horizontal surface. Calculate the net gravitational force", "images": [], "options": {"A": "1.11 x 10-7N towards P", "B": "1.11 x 10-7 towards Q", "C": "9.26 x 10-8 towards P", "D": "9.26 x 10-8 towards Q"}, "answer": "D", "explanation": "mp = 100kg  mq = 20kg  r = 1.2m  Fg = unknown     FPQ = Force on P due to Q  F=GM1M2r2  =66.67x10-11x100x20(1.2)2   = 9.26 x 10-8   It is towards Q because Q is a lighter object and will move  a bit faster hence the force will act in the direction of Q.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>32", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : POWER TRANSMISSION AND DISTRIBUTION", "question": "The primary of a transformer has 100 turns and its secondary has 200 turns. If the voltage at the primary is 100 V, determine the voltage at the secondary", "images": [], "options": {"A": "50 V", "B": "100 V", "C": "200 V", "D": "400 V"}, "answer": "C", "explanation": "Np = 100  Ns = 200  Vp = 100v  Vs = unknown  N.B: N means number of turns     N α V  NpNs=VpVs--------*  Note that we are dealing with a step up transformer here since Np s.  100200=100Vs  Vs = 200V", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>33", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "In the diagram illustrated above, a block of mass M is at rest on a plane inclined at an angle θ to the horizontal. As θ increase, the velocity ratio of the plane", "images": ["Physics/imgs/2018/pix12.png"], "options": {"A": "increases", "B": "decreases", "C": "remain the same", "D": "decreases and later increases"}, "answer": "B", "explanation": "Recall: For such inclined plane;  V.R=1sinθ  V.Rα1θ(becausesinθincreasesθ)  So as increases, V.R decreases.  Check for θ = 30°, 45°, 60° and 90° you will see that V.R decreases as θ increases.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>34", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "When the speed of a car is halved, its kinetic energy is", "images": [], "options": {"A": "doubled", "B": "quartered", "C": "halved", "D": "quadrupled"}, "answer": "B", "explanation": "Recall:  K.E=12mV2  Let the mass be constant.  k.E1k.E2=V12V22  whenthespeedishalved,i.eV2=V12  E1E2=V12V124  E1E2=41  E2=E14  When the speed is halved, the energy is quartered.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>35", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "A wire of length 400 cm is stretched between two fixed points. When plucked, its fundamental frequency is 150 Hz. Calculate the speed of the wave produced.", "images": [], "options": {"A": "250 ms-1", "B": "625 ms-1", "C": "1200 ms-1", "D": "1500 ms-1"}, "answer": "C", "explanation": "L = λ/2 = 400cm  λ = 800cm  λ = 8m  Recall, V = fλ  V = 150 × 8  V = 1200ms-1.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>36", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "The diagram above illustrated a waveform. Determine the number of wavelength in it.", "images": ["Physics/imgs/2018/pix13.png"], "options": {"A": "4", "B": "312", "C": "212", "D": "2"}, "answer": "C", "explanation": "Count the number of oscillation  n=212  wavelengthnumber=212  N.B: Number of oscillations = Number of wavelengths", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>37", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A resistor with fixed resistance value is called a", "images": [], "options": {"A": "resistance box", "B": "standard resistor", "C": "shunt", "D": "multiplier"}, "answer": "B", "explanation": "Standard resistor is a resistor with fixed resistance value.  Note that a resistor with variable resistance value is called a rheostat.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>38", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : STORAGE OF CHARGES", "question": "Which of the following statements is not an advantage of an alkaline accumulator?", "images": [], "options": {"A": "The electrolyte does not need attention", "B": "It can be recharged", "C": "It has low internal resistance", "D": "It has a much longer life than lead-acid"}, "answer": "D", "explanation": "Advantages of Alkaline Accumulators  - Large current can be drawn from them, meaning they have low internal resistance  - They require little attention to be maintained  - They are lighter than the lead-acid accumulators  - It is rechargeable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>39", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "The diagrams above illustrates the wire connections to a three-pin plug. The wires P, Q and R respectively are", "images": ["Physics/imgs/2018/4GBLND.png"], "options": {"A": "live, neutral and earth", "B": "neutral, earth and live", "C": "earth, live and neutral", "D": "earth, neutral and live"}, "answer": "B", "explanation": "From the diagram above, it can be seen that,  P = Neutral  Q = Earth  R = Live", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>40", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Which of the following statements about parallel plate capacitors is/are correct?   I. Capacitance of the capacitor is inversely proportional to the distance between the plates   II. Capacitors can filter a.c. signals from d.c.   III. Capacitors can store changes", "images": [], "options": {"A": "I only", "B": "I and II only", "C": "II and III only", "D": "I, II and III"}, "answer": "D", "explanation": "All I, II and III are correct.  - Capacities store charges (III is correct)  -FromC=Aε0d,Iiscorrect  - Capacitors can filter a.c signals from d.c (II is correct)", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>41", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "A circuit contains three ammeters A1, A2 and A3 with reading of A2 and A3 shown as indicated in the diagram above. Determine the reading of A1", "images": ["Physics/imgs/2018/pix15.png"], "options": {"A": "2 A", "B": "3 A", "C": "5 A", "D": "8 A"}, "answer": "B", "explanation": "The current that flows from the source is I which is equal to 5A, this same current enters R1, but when it gets to point C, the currents into A1 (which enters R2) and A2 (which enters R3)  A3 = A1 + A2  5A = A1 + 2A  A1 = 3A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>42", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "Which of the following statements about magnetic lines of force is not correct? They", "images": [], "options": {"A": "pass through even non-magnetic materials", "B": "run from the north pole to the south pole", "C": "are in a state of tension and tend to be shorted", "D": "intersect one another"}, "answer": "D", "explanation": "Magnetic lines of force do not intersect each other. Each line of force provides a distinct path for the magnetic field, and no two field lines can intersect each other. If they did, it would mean that at the point of intersection, the magnetic field would have two different directions, which is not possible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>43", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : EDDY CURRENTS", "question": "In which of the following activities is an induction coil not useful?", "images": [], "options": {"A": "Investigation of high voltages", "B": "Study of electric discharge", "C": "Operation of X-ray tubes", "D": "A.C. power transmission"}, "answer": "D", "explanation": "An induction coil is a type of electrical transformer used to produce high-voltage pulses from a low-voltage direct current (DC) supply. It is not useful in AC power transmission.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>44", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : IMPEDANCE", "question": "In a series R-L-C circuit, R = 10 ohm, Xc = 4F and XL = 9 ohm. The impedance of the circuit is", "images": [], "options": {"A": "4.1 ohm", "B": "5.0 ohm", "C": "10.8 ohm", "D": "11.2 ohm"}, "answer": "D", "explanation": "Diagrammatically, we have     R → Resistance {opposition to the flow of current in a resistor}  XL → Inductive reactance {opposition to the flow of current in an inductor}  XC → Capacitive reactance {opposition to the flow of current in a capacitor}  Z → Impedance {resultant or effective opposition to the flow of current}  If you are interested in the phasor diagram, here is it,     We are going to use (c) to compute Z     ∴ z2 = 102 + 52  z2 = 100 + 25  z2 = 125  z = &radic;125&nbsp; = 5&radic;5&nbsp; = 11.2 ohm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2018>45", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "A student uses two compass needles to investigate the magnetic field around a bar magnet. Which of the following diagrams show the correct directions of the needles?", "images": ["Physics/imgs/2018/pix16.png", "Physics/imgs/2018/pix17.png", "Physics/imgs/2018/pix18.png", "Physics/imgs/2018/pix19.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "the diagram that shows the correct direction of the needles is:", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>46", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Which of the following particles may be emitted in a process of natural radioactivity?", "images": [], "options": {"A": "α - particles and β - particles", "B": "α - particles and X-rays", "C": "β - particles and X rays", "D": "y  - rays and X-rays"}, "answer": "A", "explanation": "Natural radioactivity is the emission of any of α - particle, β-particles and γ-rays from the nucleus of an unstable atom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>47", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "In which of the following situations is photoelectric effect employed?   I. Automatic devices for switching on light at dusk   II. Automatic doors in departmental stores   III. Automatic devices for switching on air conditioners  IV. Automatic voltage stabilization", "images": [], "options": {"A": "I, II and IV only", "B": "I, III and IV only", "C": "III and IV only", "D": "I and II only"}, "answer": "D", "explanation": "The photoelectric effect is the phenomenon where electrons are ejected from a material when light of sufficient frequency shines on it. This principle is employed in automatic devices for switching on light at dusk (I), and automatic doors in departmental stores (II).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2018>48", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following radiations has the longest wavelength?", "images": [], "options": {"A": "Gamma ray", "B": "Radio wave", "C": "Infrared ray", "D": "X-ray"}, "answer": "B", "explanation": "Radio wave has the highest wavelength", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>49", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "In which of the following fields is radioisotopes not used?", "images": [], "options": {"A": "Medicine", "B": "Oil industry", "C": "Agriculture", "D": "Weather forecast"}, "answer": "D", "explanation": "Radioisotopes are used in various fields such as medicine, oil industry, and agriculture for different purposes like diagnosis and treatment of diseases, tracing oil and gas flow, and improving crop varieties respectively. However, they are not used in weather forecasting. Weather forecasting relies on meteorological data and does not involve the use of radioisotopes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2018>50", "subject": "Physics", "year": "2018", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "A muscle is represented by 7032B   Determine its neutron-proton ratio.", "images": [], "options": {"A": "0.5", "B": "0.8", "C": "1.2", "D": "1.5"}, "answer": "C", "explanation": "Given the atom:  7032B  Note that: 70 = Atomic mass = Number of proton + Number of neutron   and  32 = Atomic number = Number of proton  Recall: Atomic mass = Number of proton + Number of neutron  70 = 32 + Nn  Nn = 38  Neutron-protonratio=3832=1.2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>1", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "The time rate of increase in velocity is called", "images": [], "options": {"A": "force", "B": "momentum", "C": "acceleration", "D": "speed"}, "answer": "C", "explanation": "The time rate of increase in velocity is called acceleration. It is a measure of how quickly an object changes its velocity. Force is the interaction that, when unopposed, will change the motion of an object. Momentum is the product of the mass and velocity of an object. Speed is the magnitude of velocity.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>2", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Which of the following quantities is a vector?", "images": [], "options": {"A": "Volume", "B": "Momentum", "C": "Energy", "D": "Speed"}, "answer": "B", "explanation": "A vector quantity is a quantity that has both magnitude and direction. Momentum is a vector quantity because it has both magnitude (the amount of momentum) and direction (the direction in which the object is moving). Volume, Energy, and Speed are scalar quantities because they only have magnitude and no direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>3", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "CONSERVATION OF ENERGY", "question": "In an elastic collision, momentum is conversed as well as", "images": [], "options": {"A": "velocity", "B": "kinetic energy", "C": "potential energy", "D": "speed"}, "answer": "B", "explanation": "In an elastic collision, there is no net lo in kinetic energy of the system and the momentum is conserved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>4", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "The induced current in a coil always flows in a direction so as to oppose the change that causes it. This statement is known as", "images": [], "options": {"A": "Coulomb's law", "B": "Lenz's law", "C": "Faraday's law", "D": "Ampere's law"}, "answer": "B", "explanation": "Lens  law states that an induced current in a coil always flows in a direction such that the current opposes the change that induced it .", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>5", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "Which of the following instruments can be used to compare the magnitudes of charges on two given bodies.", "images": [], "options": {"A": "Electrophorus", "B": "Ebonite rod", "C": "Gold-leaf electroscope", "D": "Proof planes"}, "answer": "C", "explanation": "A Gold-leaf electroscope is an instrument that can be used to compare the magnitudes of charges on two given bodies. It works on the principle that like charges repel each other. When a charged object is brought near the cap of the electroscope, the leaves repel each other and diverge. The degree of divergence gives a measure of the amount of charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>6", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A body of mass 2 kg is released from a point 100m above the ground. Calculate its kinetic energy 80m from the point of release.", "images": [], "options": {"A": "1600J", "B": "900J", "C": "600J", "D": "200J"}, "answer": "A", "explanation": "Kinetic energy 80m from point of release = potential energy from 80m high to ground = Mgh = 2 × 10 × 80 = 1600J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>7", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "TYPES OF WAVES : WAVE MOTION", "question": "Which of the following waves is not mechanical?", "images": [], "options": {"A": "Waves in pipes", "B": "Water waves", "C": "Radio waves", "D": "Sound waves"}, "answer": "C", "explanation": "Mechanical waves require a medium through which to travel. Examples of mechanical waves include sound waves, water waves, and waves in pipes. Radio waves, on the other hand, are electromagnetic waves. They can travel through the vacuum of space, and do not require a medium. Therefore, radio waves are not mechanical waves.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>8", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "A loaded spring is set in simple harmonic motion. The force that tends to restore the load to its equilibrium position is", "images": [], "options": {"A": "adhesive", "B": "elastic", "C": "frictional", "D": "gravitational"}, "answer": "B", "explanation": "This force is commonly referred to as the \"restoring force,\" and it's provided by the elasticity of the spring. As the spring is stretched or compressed away from its equilibrium position, it exerts a force in the opposite direction, trying to bring the load (mass) back to its equilibrium position. This force is directly proportional to the displacement from the equilibrium position according to Hooke's Law, which is characteristic of simple harmonic motion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>9", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Which of the following cases cannot produce total internal reflection? A light ray travelling from", "images": [], "options": {"A": "glass of water.", "B": "kerosene to air.", "C": "air to water.", "D": "water to ice."}, "answer": "C", "explanation": "Total internal reflection occurs when a light wave is moving from a denser to less dense medium at an incidence angle > critical angle. Air to water, is moving from less dense to denser medium, total internal reflection cannot occur.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>10", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The vacuum in a thermoflask reduces heat loss resulting from", "images": [], "options": {"A": "radiation only", "B": "conduction and convection only", "C": "radiation and convection only", "D": "conduction only"}, "answer": "B", "explanation": "A thermoflask is designed to reduce heat loss through conduction and convection. The vacuum in a thermoflask prevents heat transfer by conduction and convection because these processes require a medium (solid, liquid, or gas) to occur. Radiation can still occur in a vacuum, but the flask's reflective lining helps to minimize this.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>11", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The diagram above represents an experimental set-up for verifying", "images": ["Physics/imgs/2019/img1.png"], "options": {"A": "lens formula", "B": "refraction laws", "C": "reflection laws", "D": "mirror formula"}, "answer": "D", "explanation": "The generated image depicts a reflective surface, suggesting the presence of a mirror.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>12", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "Which of the following statements about a moving object is correct?", "images": [], "options": {"A": "When accelerating, the resultant force acting on it must be equal to zero.", "B": "There must always be a non-zero resultant force acting on it.", "C": "At a steady velocity, the resultant force acting on it must be equal to zero.", "D": "At a steady velocity, the air resistance must be equal to zero."}, "answer": "C", "explanation": "At a steady velocity, there is no acceleration, therefore, the resultant force is zero. for a moving object  at steady velocity , the result force acting on it must be equal to zero", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>13", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "If the efficiency of a transformer is 100%, which of the following equations would be correct?", "images": [], "options": {"A": "NpEp = NsEs", "B": "NsIp = NpIs", "C": "NsIs = NpIp", "D": "IpEs = IsEp"}, "answer": "C", "explanation": "voltage current relationship for an ideal transformer   EpEs=NpNs=IsIp", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>14", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "A freshly demagnetized bar magnet is placed in the East-West direction to ensure that", "images": [], "options": {"A": "the molecular magnets remain randomly arranged", "B": "the molecular magnets are properly aligned", "C": "it is affected by the earth's magnetic field", "D": "the magnetic domains are within the earth's field"}, "answer": "A", "explanation": "By placing a freshly demagnetized bar magnet in the East-West direction, we are ensuring that the magnetic domains remain randomly arranged and that the magnet remains demagnetized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>15", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Which of the following graphs of a charge Q against potential difference V across capacitor is correct?", "images": ["Physics/imgs/2019/img2a.png", "Physics/imgs/2019/img2b.png", "Physics/imgs/2019/img2c.png", "Physics/imgs/2019/img2d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "Charge varies directly with potential difference.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>16", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "A small amount of air is introduced into the vacuum above the mercury in a mercury barometer tube. The mercury level goes down because the air molecules", "images": [], "options": {"A": "heat the mercury and make it to expand.", "B": "increase the pressure above the mercury.", "C": "cool the mercury and make it to contract.", "D": "decrease the pressure above the mercury."}, "answer": "B", "explanation": "When air is introduced into the vacuum above the mercury in a barometer tube, it increases the pressure above the mercury. This increased pressure pushes down on the mercury, causing the mercury level to go down. This is based on the principle that pressure is force per unit area, and in this case, the force is exerted by the air molecules on the mercury.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>17", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Calculate the quantity of heat needed to change the temperature of 60g of ice at 0°C to 80°C.  [Specific latent heat of fusion of ice = 3.36 × 105 Jkg-1, Specific heat capacity of water = 4.2 × 103 Jkg-1K-1]", "images": [], "options": {"A": "4.80 kJ", "B": "20.16 kJ", "C": "40.32 kJ", "D": "22.17 kJ"}, "answer": "C", "explanation": "Total Heat = Heat required to heat ice from solid at 0°C to liquid at 0°C + Heat required to heat liquid water from 0°C to 80°C  ⇒ m. ΔHfus + M . C . ΔT  Convertingmasstokilogram=60g×1kg1000g = 0.06kg,  substituting, we have   0.06 × 3.36 × 105 + 4.2 × 103 × 0.06 × (90 - 0)  20,160 + 20,160  ⇒ 40,320J  ⇒ 40.32KJ", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>18", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The wire of a platinum resistance thermometer has a resistance of 3.5Ω at 0°C and 10.5 Ω at 100°C. Calculate the temperature of the wire when its resistance is 7.5Ω.", "images": [], "options": {"A": "78°C", "B": "25°C", "C": "36°C", "D": "57°C"}, "answer": "D", "explanation": "7.5 - 3.510.5 - 3.5=x - 0°C100 - 0  =47=x100  x=4×1007 = 57°C", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>19", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "A transverse pulse of frequency 9 Hz travels 4.5m in 0.6s. Calculate the wavelength of the pulse.", "images": [], "options": {"A": "3.33 m", "B": "0.30 m", "C": "0.83 m", "D": "1.20 m"}, "answer": "C", "explanation": "Velocity=speedtime=4.50.6=7.5ms  Velocity = λF  substituting, we have   7.5 = 9λ  λ=7.59=0.83m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>20", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "In which of the following media is speed of sound the least?", "images": [], "options": {"A": "Air", "B": "Brass", "C": "Water", "D": "Wood"}, "answer": "A", "explanation": "The speed of sound is least in air compared to brass, water, and wood. This is because sound travels faster in solids and liquids than in gases. The particles in solids and liquids are closer together than in gases, which allows the sound waves to be transmitted more quickly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>21", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "PROPERTIES OF WAVES : REFLECTION~~PROPERTIES OF WAVES : REFRACTION~~PROPERTIES OF WAVES : DIFFRACTION", "question": "Which of the following characteristics of waves can a ripple tank be used to demonstrate?  I. Reflection  II. Refraction  III. Diffraction", "images": [], "options": {"A": "I, II and III", "B": "II and III only", "C": "I and III only", "D": "I and II only"}, "answer": "A", "explanation": "A ripple tank can be used to show the basic properties of a wave including diffraction, reflection, refraction and interference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>22", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "Which of the following graphs gives the correct relationship between energy and mass when mass is converted to energy.", "images": ["Physics/imgs/2019/img3a.png", "Physics/imgs/2019/img3b.png", "Physics/imgs/2019/img3c.png", "Physics/imgs/2019/img3d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "When mass is converted to energy, for example potential energy it increases proportionally.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>23", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "An 800kg car moving at 80 kmhr-1 collides with a 1200kg car moving at 40kmhr-1 in the same direction. If the cars stick together, calculate their common velocity.", "images": [], "options": {"A": "60 kmhr-1", "B": "8 kmhr-1", "C": "40 km hr-1", "D": "56 km hr-1"}, "answer": "D", "explanation": "M1U1 + M2U2 = (M1 + M2)V  substituting  800 × 80 + 1200 × 40 = (1200, + 800)V  64,000 + 48,000 = 2000V  112,000 = 2,000V  V=112,0002000 = 56 km hr-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>24", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "The mass of a load is doubled while the force acting on it is halved. The resulting acceleration of the load is", "images": [], "options": {"A": "quadrupled.", "B": "quartered.", "C": "halved.", "D": "doubled."}, "answer": "B", "explanation": "F = Ma  Therefore, a (acceleration) = F/M  when M becomes 2M  and F becomes 1/2 F  taking F and M as unity, we have  a=1/22=12×12=14", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>25", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The maximum and minimum thermometer reads the", "images": [], "options": {"A": "maximum temperature during the day and the minimum temperature at night at all times.", "B": "maximum temperature at night and minimum temperature during the day from the last reset.", "C": "maximum temperature at night and minimum temperature during the day at all times.", "D": "maximum temperature during the day and minimum temperature at night from the last reset."}, "answer": "D", "explanation": "A maximum and minimum thermometer reads the maximum and minimum temperature since last reset, with the current temperature reading.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>26", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT", "question": "An a.c. generator can be converted to a d.c. generator by replacing the", "images": [], "options": {"A": "commutator with an armature.", "B": "armature with a commutator.", "C": "commutator with slip rings.", "D": "slip rings with a commutator."}, "answer": "D", "explanation": "An AC generator can be converted into a DC generator by replacing the slip rings with a commutator. A commutator is a rotary electrical switch in certain types of electric motors and electrical generators that periodically reverses the current direction between the rotor and the external circuit. In a DC generator, it allows the current to flow in one direction, converting the alternating current (AC) into direct current (DC).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>27", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "Which of the following statements is the correct reason for using soft iron in making the armature of an electric bell?", "images": [], "options": {"A": "It is a diamagnetic material.", "B": "It loses its magnetism readily.", "C": "It is not easily magnetized.", "D": "It retains its magnetism for a long time."}, "answer": "B", "explanation": "Soft iron is used in the armature of an electric bell because it loses its magnetism readily. This property is known as low retentivity. When the electric current is switched off, the soft iron does not remain magnetized, which allows the bell to stop ringing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>28", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The diagram above illustrates a meter bridge circuit under balanced condition. Determine the value of x.", "images": ["Physics/imgs/2019/img4.png"], "options": {"A": "50 cm", "B": "10.0 cm", "C": "28.6 cm", "D": "57.2 cm"}, "answer": "A", "explanation": "R1R2=x(100-x)  22=x100-x  100 = 2x  x = 50cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>29", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : STORAGE OF CHARGES", "question": "Which of the following devices is used for storing electric charges?", "images": [], "options": {"A": "Transformer", "B": "Ammeter", "C": "Potentiometer", "D": "Capacitor"}, "answer": "D", "explanation": "A capacitor is a device used to store an electric charge, consisting of one or more pairs of conductors separated by an insulator.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>30", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An electron of mass 9.1 × 10-31 kg moves with a speed of 2.0 × 106 ms-1 round the nucleus of an atom in a circular path of radius 6.1 × 10-11m.  Use the information to answer this question.    Determine the angular speed of the electron.", "images": [], "options": {"A": "3.28 × 1016 rad s-1", "B": "8.55 × 103 rad s-1", "C": "9.11 × 1013 rad s-1", "D": "5.22 × 1015 rad s-1"}, "answer": "A", "explanation": "V = rω  ω=Vr  substituting for V and r, we have,  =2.0 × 1066.1 × 10-11=3.28×1016rads-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>31", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "An electron of mass 9.1 × 10-31 kg moves with a speed of 2.0 × 106 ms-1 round the nucleus of an atom in a circular path of radius 6.1 × 10-11m.  Use the information to answer this question.  Calculate the centripetal force acting on the electron.", "images": [], "options": {"A": "7.7 × 10-47 N", "B": "6.0 × 10-8 N", "C": "3.0 × 10-14 N", "D": "1.3 × 10-26 N"}, "answer": "B", "explanation": "F=mv2r  substituting,  F=9.1 × 10-31 × (2.0 × 106)26.1 × 10-11 = 6.0 × 10-8 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>32", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "A device consumes 100W of power when connected to a 120V source. Calculate its resistance.", "images": [], "options": {"A": "1.2Ω", "B": "12,000.0Ω", "C": "20.0Ω", "D": "144.0Ω"}, "answer": "D", "explanation": "P=V2R  Therefore,   R=V2P  substituting for V and P, we have  =120×120100=144.0Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>33", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "PROPERTIES OF WAVES : REFRACTION", "question": "Which property of a wave remains constant when the wave travels from one medium into another?", "images": [], "options": {"A": "Amplitude", "B": "Wavelength", "C": "Velocity", "D": "Frequency"}, "answer": "D", "explanation": "When a wave travels from one medium to another, its frequency remains constant. This is because the frequency of a wave is determined by the source of the wave, not the medium in which it travels. Therefore, the correct answer is option 4.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>34", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The anomalous expansion of water occurs in the range", "images": [], "options": {"A": "0°C to 100°C", "B": "0°C to 4°C", "C": "4°C to 100°C", "D": "-4°C to 0°C"}, "answer": "B", "explanation": "The anomalous expansion of water occurs in the range of 0°C to 4°C. This is because water expands when it is cooled from 4°C to 0°C, which is unusual as most substances contract when cooled. This is known as the anomalous expansion of water.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>35", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light travelling from a rectangular glass block of refractive index 1.5 into air strikes the block at an angle of incidence of 30°. Calculate its angle of refraction.", "images": [], "options": {"A": "48.6°", "B": "19.5°", "C": "20.0°", "D": "45.0°"}, "answer": "B", "explanation": "SinθASinθB=nBnA=sin301.5  =0.51.5  SinθASinθB=1.5 = sin-1 ( 1/3 )  Sin30SinθB=1.5 = 19.5°", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>36", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A rectangular piece of iron measuring 4cm by 3cm at 20°C is heated until its temperature increases by 100°C. Calculate the new area of the metal.  [Linear expansivity of iron is 1.2 × 10-5K-1]", "images": [], "options": {"A": "12.0144 cm2", "B": "12.0346 cm2", "C": "12.0288 cm2", "D": "12.0173 cm2"}, "answer": "C", "explanation": "A2 = A1(1 + βθ)  Substituting,  A1 = 4cm × 3cm = 12cm2  θ = 100 - 20 = 80°C  β = 2 × linear expansivity (2 × α) = 2 × 1.2 × 10-5k-1  ⇒ 2.4 × 10-5k-1  substituting,  A2 = 12 (1 + 2.4 × 10-5 × 80) = 12.0288 cm2", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>37", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "Two bodies of masses 3.0kg and 2.0kg are separated by a distance of 50cm. Calculate the force of attraction between them.  [G = 6.67 × 10-11 Nm2kg-2]", "images": [], "options": {"A": "1.6 × 10-9N", "B": "1.3 × 103N", "C": "2.3 × 103N", "D": "5.0 × 10 N"}, "answer": "A", "explanation": "F=GmMr2  50cm⇒50×1100m=0.5m (converting cm to m)  F=6.67 × 10-11 × 3 ×2(0.5)2  F=6.67 × 10-11 × 60.25  F = 1.6 × 10-9N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>38", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "The diagram above illustrates an object moving in a circular path at constant speed. Which of the arrows indicates the direction of linear velocity?", "images": ["Physics/imgs/2019/img5.png"], "options": {"A": "Z", "B": "X", "C": "Y", "D": "W"}, "answer": "A", "explanation": "The direction of linear velocity is always tangential to the circular path, when performing circular motion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>39", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Which of the following thermometers is used to measure the temperature of the human body?", "images": [], "options": {"A": "Thermocouple", "B": "Alcohol-in-glass thermometer", "C": "Gas thermometer", "D": "Platinum resistance thermometer"}, "answer": "B", "explanation": "The Alcohol-in-glass thermometer is used to measure the temperature of the human body because it is safe, easy to use, and gives accurate readings at the temperature range of the human body.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>40", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "In the diagram above, the time taken to trace a wave between P and Q is", "images": ["Physics/imgs/2019/img6.png"], "options": {"A": "2 periods", "B": "1 period", "C": "1 1/2 periods", "D": "1 1/4 periods"}, "answer": "C", "explanation": "From P to Q, we count 1 1/2 circle which takes 1 1/2 period to cover.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>41", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "Which of the following materials does not serve as a safety device in electrical circuits?", "images": [], "options": {"A": "Connecting wires", "B": "Earth wire", "C": "Fuse", "D": "Switch"}, "answer": "A", "explanation": "The Connecting wires do not serve as a safety device in electrical circuits. The other options, Earth wire, Fuse, and Switch, all serve as safety devices.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2019>42", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following liquids has the highest surface tension?", "images": [], "options": {"A": "Soapy water", "B": "Cold water", "C": "Hot water", "D": "Oily water"}, "answer": "B", "explanation": "Surface tension is the property of a liquid that allows it to resist an external force. It is seen in the phenomena that cause a liquid in small amounts to form spheres, which minimize surface area. Cold water has the highest surface tension among the given options. This is because surface tension decreases with temperature. So, cold water has higher surface tension than hot water. Soapy water and oily water have lower surface tension due to the presence of surfactants that disrupt the cohesive forces between the water molecules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>43", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The nucleon and proton numbers of a neutral atom of an element are 238 and 92 respectively. Determine the number of neutrons in the atom.", "images": [], "options": {"A": "119", "B": "330", "C": "165", "D": "146"}, "answer": "D", "explanation": "nucleon number = Number of protons + Number of Neutrons   Number of neutrons = 238 - 92  ⇒ 146 neutrons.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>44", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT", "question": "An instrument used to measure relative humidity is the", "images": [], "options": {"A": "hygrometer", "B": "hydrometer", "C": "pyrometer", "D": "manometer"}, "answer": "A", "explanation": "Relative humidity is a measure of the amount of water vapor present in air expressed as a percentage of the amount needed for saturation at the same temperature. It is measured using a hygrometer. A hydrometer is used to measure the specific gravity (relative density) of liquids; a pyrometer is used to measure high temperatures; and a manometer is used to measure pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>45", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "MOTION : DISTANCE/DISPLACEMENT-TIME GRAPH", "question": "The area under a velocity-time graph represents", "images": [], "options": {"A": "speed", "B": "acceleration", "C": "moment", "D": "distance"}, "answer": "D", "explanation": "The area under a velocity-time graph represents the displacement or distance covered. This is because the area under the graph is calculated by multiplying velocity (y-axis) by time (x-axis), which gives the distance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>46", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Which of the following statements about a neutral atom is correct? The", "images": [], "options": {"A": "core is composed of electrons and protons.", "B": "number of electrons is equal to that of neutrons.", "C": "number of neutrons is equal to that of protons.", "D": "number of protons is equal to that of electrons."}, "answer": "D", "explanation": "In a neutral atom, the number of protons is equal to the number of electrons. This is because protons carry a positive charge and electrons carry a negative charge. In a neutral atom, the total positive charge from the protons is balanced by the total negative charge from the electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2019>47", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "PROPERTIES OF WAVES : POLARIZATION", "question": "Which of the following properties is not exhibited by sound waves?", "images": [], "options": {"A": "Diffraction.", "B": "Polarization.", "C": "Interference.", "D": "Reflection."}, "answer": "B", "explanation": "Sounds are longitudinal waves, meaning they oscillate parallel to the direction of their motion. Hence, cannot be polarized.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>48", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "When ultraviolet light is incident on certain metallic surfaces, particles are emitted. These particles are called", "images": [], "options": {"A": "positrons.", "B": "protons.", "C": "photoelectrons.", "D": "photons."}, "answer": "C", "explanation": "When light of a particle wavelength (ultraviolet light) falls on some metallic surface photoelectrons are emitted.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>49", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "Niels Bohr drew certain conclusions about the structure of the atom. Which of the following statements is one of those conclusions?", "images": [], "options": {"A": "The allowed orbits contain the same number of electrons.", "B": "Within an atom, there are certain allowed orbits.", "C": "All of the orbits represent the same amount of energy.", "D": "The orbit with the least energy is farthest from the nucleus."}, "answer": "B", "explanation": "Niels Bohr's model of the atom, also known as the Bohr model, proposed that electrons move in specific, discrete orbits around the nucleus. These orbits are 'allowed' in the sense that they are stable and an electron in such an orbit will not radiate energy. Hence, the correct answer is 'Within an atom, there are certain allowed orbits.'", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2019>50", "subject": "Physics", "year": "2019", "type": "Objective", "topic": "HEAT ENERGY : MELTING POINT", "question": "The graph above illustrates the variation of temperature θ with time t for a solid that is being heated. Which processes take place at segments P and Q respectively?", "images": ["Physics/imgs/2019/img7.png"], "options": {"A": "Freezing and vaporization", "B": "Evaporation and solidification", "C": "Melting and boiling", "D": "Condensation and evaporation"}, "answer": "C", "explanation": "During melting and boiling the temperature remains constant, what is taken in is known as latent heat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>1", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "In a collision between two object, Kinetic energy is conserve only if .", "images": [], "options": {"A": "One of the objects was initially at rest", "B": "Potential energy is converted to work", "C": "The collision is inelastic", "D": "The collision is elastic"}, "answer": "D", "explanation": "There are two types of collision   -Elastic colision   -inelasic collision  In elastic colision both the linear momentum and kenetic energy are conserved  In inelastic collision, linear momentum is conserved but kinetic energy is not conserve . this implies that there is loss of kinetic energy when the collision is inelastic.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>2", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "The quantity of motion of a body is its", "images": [], "options": {"A": "Acceleration", "B": "Displacement", "C": "momentum", "D": "Velocity"}, "answer": "C", "explanation": "The quantity of motion of a body is a measure of mass and velocity of the body . This is the product of the ass of a body and its velocity , which is the momentum of the body. Mathematically, linear momentum , p = mass(m) x veocity   p = mv", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>3", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "The volume of a fixed mass of a gas varies inversely as the pressure on it provided the temperature is constant. This statement is", "images": [], "options": {"A": "Pressure law", "B": "Charles law", "C": "Boyle's law", "D": "General gas law"}, "answer": "C", "explanation": "Boyle's law states that the volume of a fixed mass of gas is inversely proportional to pressure provided temperature is constant.  Mathematically,  V ∝ 1/p   v = k/p  where k is a constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>4", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "An image formed on a screen is always.", "images": [], "options": {"A": "Inverted", "B": "magnified", "C": "upright", "D": "virtual"}, "answer": "A", "explanation": "There are two types of images : real and virtual . A real image is the image which can be cast on a screen . it is formed when the light rays coming from an object actually meet after reflection. It is always inverted , an example is the image formed on the cinema screen. on the other hand a virtual image is an image which cannot be cast on a screen , the rays of light forming a virtual image do not actually meet where the image is formed . Virtual image is always upright or erect", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2020>5", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "How would the capacitance of a parallel plate capacitor be affected if the distance of separation of its plates is decreased? it will", "images": [], "options": {"A": "increase in value", "B": "decrease slightly", "C": "Remain unchanged", "D": "drop to Zero"}, "answer": "A", "explanation": "The factors affecting the capacitance of a capacitor are :  - Nature of the di-electric  - Area of the plates of the capacitor  - Distance between he plates of the capacitor . they are related by the formular,  C=EAd  Where C = Capacitance ,E = Absolute permitivity, A = Area of the plates , d = Distance between he plates . it can be seen that capacitance is inversely proportional to the distance between the plates . Decrease in the distance between the plates results in to increase in capacitance and vice versa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>6", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "MACHINES :", "question": "Which of the following machines does not apply the lever principle ?", "images": [], "options": {"A": "Claw hammer", "B": "wheelbarrow", "C": "single pulley", "D": "sugar tong"}, "answer": "C", "explanation": "A lever is a simple achine that is comprised of a rigid beam which is fixed on a pivot. It consists of three parts which are load , fulcrum and effort. It fulcrum is at the middle , it is a first class lever e.g Claw hammer , if the load is at the midddleit is a second class lever e.g wheel barrow . if the effort is at the middle , it is a third class lever e.g sugar tong. A pulley is another type of machine which is not  lever . A pulley is a whell which has a rope around it , hence it does not apply the lever principle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>7", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "The average distance moved by a molecules between collision is called", "images": [], "options": {"A": "Molecular distance", "B": "intermolecular distance", "C": "Mean distance", "D": "Mean free path"}, "answer": "D", "explanation": "Mean free path is the average distance travelled by a moving molecules between collision . It is the actual distance a particle such as a molecule in a gas moves before a collision", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>8", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES", "question": "Which of the following waves requires a material medium for its propagation?", "images": [], "options": {"A": "Radio waves", "B": "Light waves", "C": "sound wave", "D": "X-rays"}, "answer": "C", "explanation": "There are two types of waves :  - mecanical waves - these are waves which require material medium for their propagation e.g sound waves, water waves.  - Electromagnetic wave : Theses are waves which do not require material medium for their propagation e.g Radiowaves , light , X-rays e.t.c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>9", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "The depolarizing agent in a leclanche cell is", "images": [], "options": {"A": "Carbon rod", "B": "ammonia Chloride", "C": "manganse(IV) oxide", "D": "Zinc plate"}, "answer": "C", "explanation": "A lechlanche cell is a primary cell, this means that it cannot be recharged after it has been used up. it has a positive electrode (cathode) is carbon, it negative electrode (anode) is zinc, it has an electrolyte which is ammonium chloride (NH4Cl) and depolarizer which maganese(iv) oxide (MnO2).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>10", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "The material used to slow down the neutron in a nuclear reactor is", "images": [], "options": {"A": "Boron", "B": "Copper", "C": "Graphite", "D": "Uranium"}, "answer": "C", "explanation": "Newton moderation are material used in a nuclear reactor to slow neutron down , such moderator are graphite , beryllum e.t.c they help reduce speed of neutron  which could cause further fission", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>11", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statement explains why soapy water is more effective in cleaning oil-stained dishes", "images": [], "options": {"A": "The oil on the dishes repels the soap", "B": "Soap and heat decrease the surface tension of the water", "C": "Hot water increases the surface tension", "D": "Soap increases the surface tension of oil and water"}, "answer": "B", "explanation": "Some of the ways of reducing surfae tension are boiling , adding saop or detergent , by adding camphor , by adding grease. Ordinary water is not so effective in cleabibg oil stained dishes due to the presence of surface tension but whe hot soapy water is used , washing is more effective since surface tension has been greately reduced.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>12", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The diagram above illustrates a beam of parallel rays from a distance object O, incident on one side of the total refecting prism.  Which diagram does not represent the correct path of the beam when it emerges from the prism?", "images": ["Physics/imgs/2020/4EFELH.png"], "options": {"A": "W", "B": "X", "C": "Y", "D": "Z"}, "answer": "A", "explanation": "When drawing ray diagram for instance drawing two ray from head of the object , the point pf intersection of the two rays represents the position of the head of the image , but in a case of parallel rays of light drawn from the object such that the image is likewise formed at infinity , the ray from t head of the object forms the head of the image , similarly, the ray from the leg of the image . from the diagrams drawn , it is only in  W that the ray from the head forms the leg of the image , others are correctly drawn.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>13", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "An electric device has 50 turns in its primary coil and 20 turns in the secondary coil.The device can be a/an", "images": [], "options": {"A": "Step-up transformer", "B": "Step-down transformer", "C": "Dc generator", "D": "a.c generator"}, "answer": "B", "explanation": "When the number of turns of coil in the secondary coil is greater than that of the primary coil , it is a step-up transformer but when the turns in the secondary coil is less than tthat of the primary coil it is a step-down transformer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>14", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "The earpiece of a telephone handset converts energy from", "images": [], "options": {"A": "Electrical to sound", "B": "sound to electrical", "C": "Radio wave to sound", "D": "Sound to radio wave"}, "answer": "A", "explanation": "There wire of the earpiece takes the electrical energy from the headset which is then converted to sound energy by the earpiece.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>15", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The identical cups containing the same volume of water at 45∘C and 5∘C are left in a room a 25∘C. which of the following graphs correctly illustrates the variation of temperatures with time?", "images": ["Physics/imgs/2020/l85.png", "Physics/imgs/2020/l86.png", "Physics/imgs/2020/l87.png", "Physics/imgs/2020/l88.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "C", "explanation": "The cup containing water at 45∘C loses heat to the room since temperature of the room is lower than its temperature , hence it temperature reduces gradually , the cup containing water at 5∘C gains heat from the room since its temperature is lower than that of the room. hence, its temperature increases gradually , the lines are curved because as the temperature of the water changes the temperature difference between th water and surrounding also changes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>16", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light travelling from glass into ethyl alcohol is incident at the boundary at an angle of incidence 30∘. calculate the angle of refraction.[Refractive index of glass =1.5; refractive index of ethyl alcohol = 1.36]", "images": [], "options": {"A": "27.0∘", "B": "33.5∘", "C": "51.7∘", "D": "2.8∘"}, "answer": "B", "explanation": "Angle of incidence l = 30∘  Angle of refraction , r = ?  Refractive index of glas ng = 1.5  Refractive index of ehyl alcohol, ne = 1.36  from snel' law :  neng=sinisinr  1.361.5=sin30sinr  1.3sinr = 1.5sin30  sinr=1.5sin301.36  Sinr=1.5x0.51.36  Sin r = 0.5515   r = sin-10.5515  r = 33.5∘", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>17", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "A 60kg man stands on the weighing balance in an elevator accelerates upwards at 5mg-2. determine the reading of the scale [g = 10ms-2]", "images": [], "options": {"A": "300N", "B": "600N", "C": "800N", "D": "900N"}, "answer": "D", "explanation": "mass, m = 60kg  g = 10ms-1  acceleration , a = 5ms-2  From an elevated accelerating upward, the reading of the scale , R = m (g+a)   = 60 (10+5)   = 60 x 15  R = 900N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>18", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The length of an iron bar is 100 cm at 20∘C. At what temperature will its length increase by 0.01% ?[Linear expansivity of iron = 1.2 x 10-5 = C-1]", "images": [], "options": {"A": "48.0∘C", "B": "38.0∘C", "C": "28.3∘C", "D": "23.0∘C"}, "answer": "C", "explanation": "Lenght l1 = 100cm  initial temp.θ  =  20∘C  Finall temperature,θ2 = ?  Change in lenght , ∆l = 0.01%   =0.01100x100   = 0.01cm  Final lenght , l2 = 100+0.01  = 100.01cm  Linear expansitivity   ∝ = 1.2 x 10-5 C-1  Recall,∝=∆ll∆θ  1.2x10-5=0.01100∆θ  1.2 x 10-5 x 100∆θ = 0.01  ∆θ=0.011.2 x 10-5 x 100  ∆θ = 8.3∘C  Final temperature ,θ2 = 20+8.3 = 28.3∘C", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>19", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "A moving-coil galvanometer which gives a full-scale deflection with 0.005 it is converted to a voltmeter , reading up to 5F∘ using an estimated resistance of 975Ω", "images": [], "options": {"A": "0.25Ω", "B": "2.50Ω", "C": "25.00Ω", "D": "250.00Ω"}, "answer": "C", "explanation": "For a galvanometer to be converted to a voltmeter, a resistor of high rsistance (multiplier ) must be connected in series with it.    IG = 0.005A is te current that passes through the resistor and the galvanometer   V2 = Voltage across the external resistor  VG = Voltage across the galvanometer   V = VR + VG  V = IGR + IGR  5 = 0.005 x 975 + 0.005RG  5 = 4.875 + 0.005RG  5 = 4.874 = 0.005RG  0.125 = 0.005RG  0.1250.005=RG  RG = 25.00Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>20", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "A beam consisting of α particles, β-particles and y-rays pass through a magnetic field at right angles to the direction of the field. Which of the following observation would be made about the α-particles, β-particles and y-rays respectively?", "images": [], "options": {"A": "Deflected, deflected,deflected", "B": "deflected,deflected, not deflected", "C": "deflected, not deflected, deflected", "D": "Not deflected,deflected,deflected"}, "answer": "B", "explanation": "α - Particles are reresented by helium nuceus and they are positviely charged   β - articls are streams of eectrons which are negatively charged   y  - rays are not particles and they do not posses any charge. they are neutral in nature  Therefore , α-particles and β-particles are deflected while y-rays are not deflected when passed through a magnetic field.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>21", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A parallel plate capacitor is charged and the charging battery subsequently disconnected. If the plates of the capacitor are moved farther apart by means of insulating handle, the", "images": [], "options": {"A": "Capacitance would increase", "B": "capacitance would decrease", "C": "charge on the capacitor would increase", "D": "charge on the capacitor would decrease"}, "answer": "B", "explanation": "When the capcitor is charged and disconnected , the charge stored on the plates remain the same, even when the plates are seperated . But the capacitor is inversely proportional to the distance between the plates. Hence when the distance between the plates increase, capacitance decrease.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>22", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The velocity of sound in air is 15∘C is 340 ms-1 at 47∘C", "images": [], "options": {"A": "790ms-1", "B": "602ms-1", "C": "358ms-1", "D": "322ms-1"}, "answer": "C", "explanation": "The velocity of sound in air is directly proportional to the square root of absolute temperature (in kelvin)  V ∝ √T  V=K√T;K=VT  for two cases  V1√T=V2√T2  T1 = 15∘C = 15 + 273 = 288k  V1 = 340m/s  V2 = ?  T2 = 47∘C = 47 + 273 = 320k  340√288=V2√320  V2=320√320√288  V2 = 358m/s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>23", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the current-voltage characteristics shown below is the exhibited by an ohmic conductor", "images": ["Physics/imgs/2020/l89.png", "Physics/imgs/2020/l90.png", "Physics/imgs/2020/l91.png", "Physics/imgs/2020/l92.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "An ohmic conductor is a conductor which obeys ohm's law. The V-I graph for an ohmic conductor is a striaght ine passing through origin. Examples of ohmic conductors are metals . The V-I graphs for a non-ohmic conductors is a curve . examples are junction diode, electrolyte e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>24", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A 500N box rests on a horizontal floor. A constant horizontal force is exerted on the box so that it moves through its 8m. If the coefficient of kinetic friction between the floor and the box is 0.22, calculate the work done on the box.", "images": [], "options": {"A": "150J", "B": "440J", "C": "400J", "D": "110J"}, "answer": "A", "explanation": "Distance moved, x = 8m  snce a constant force is applied then the force is equal t the frictional force , FR  FR = UR  Coefficient of friction, U =0.22  Nomal reaction , r = 200N  FR = 0.22 x 500   = 110N  Workdone , w = Force x distance, x  W = 880J", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>25", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above illustrates a ball of mass m sliding down a plank inclined at an angle of θ to the horizontal.    The normal force on the ball is", "images": ["Physics/imgs/2020/l84.png"], "options": {"A": "mgsin∅", "B": "mgtan∅", "C": "mgcos∅", "D": "mgcot∅"}, "answer": "C", "explanation": "The normal reaction/force on a body on a horizontal surface is R = mg ; but that on a body on an inclined surface is R = mgCosθ", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>26", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "The diagram above illustrates a ball of mass m sliding down a plank inclined at an angle of θ to the horizontal. The net force on the ball along the plank is", "images": ["Physics/imgs/2020/l84.png"], "options": {"A": "mgsin∅+F", "B": "F-mgcos∅", "C": "mgsin∅-F", "D": "F+mgcos∅"}, "answer": "C", "explanation": "The force which tends to bring down a body on an inclined surface is mgsin∅. for the mass m on the plank , this is in opposite direction to the frictional force . Since the mass the mass slides down the inclined plank, the mgsin∅ is greater than the frictional force , F . Therefore the net force on the plank is mgsin∅ - F", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>27", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "What factors determines the frequency of a note emitted by a vibrating string?", "images": [], "options": {"A": "Amplitude of vibration, force constant of string and length of string", "B": "Amplitude of vibration, force constant of string and tension in string", "C": "Mass per unit length of string, tension in string and length of string", "D": "Force constant of string, tension in string and length of string"}, "answer": "C", "explanation": "The frequency of a note emitted by a vibrating string is given byF0=12l√TU  Where F0 = Fundamental frequency , T = tension in the string, U = mass per unit lenght. therefore , the frequency depends on lenght , mass per unit lenght and tension.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>28", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "The magnitude of the force experienced by a charge of 1.6 x 10-8c in a uniform electric field o intensity 5 x 10 5N/C is", "images": [], "options": {"A": "3.2 x 10 -14N", "B": "8.0 x 10 -3N", "C": "8.0 x 10 3N", "D": "3.1 x 10 13N"}, "answer": "B", "explanation": "Electricfieldintensity,E=force,Fcharge,q  q = 1.6 x10-8, E =5 x 105  5x105=F1.6 x 10-8  F = 0.008 = 8.0 x 10-3 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>29", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "which of the following statement about viscosity is true? it", "images": [], "options": {"A": "depends on areas of the surfaces in contact", "B": "occurs in fluids", "C": "is independent of the relative velocity of the layer", "D": "depends on the tangential force between the layers"}, "answer": "B", "explanation": "Viscosity is a property of fluids (both liquids and gases) that measures their resistance to flow. It is caused by the internal friction within the fluid, which is the result of the cohesive forces between its molecules. Therefore, the statement that viscosity occurs in fluids is true, making option 2 the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>30", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A motorcycle starting from rest, is uniformly accelerated such that its velocity in 10s is 72km/h-1, What is the acceleration?", "images": [], "options": {"A": "108ms -2", "B": "86ms -2", "C": "4ms -2", "D": "2ms -2"}, "answer": "D", "explanation": "Initial velocity , U = 0m/s  Finalvelocity,v=72khs-1=72km1hr=20ms  Time,t = 10s  Acceleration, a = ?  Recall, v = u + at  20 = 0 + a(10)  20 = 10a  20/10 = a  a = 2m/s2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>31", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The temperature of an object is raised by 120 ∘C. The resulting increase in its absolute temperature is", "images": [], "options": {"A": "50 K", "B": "120 K", "C": "200 K", "D": "393 K"}, "answer": "B", "explanation": "A change in temperature in degree celsius has the same value as a change intemperature in kelvin , hence , 120∘C is the same as 120k.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>32", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "Which of the following statement about the motion of a simple pendulum is true?", "images": [], "options": {"A": "it is a simple harmonic motion when the angle of displacement is large", "B": "it passes the equilibrium position with minimum speed", "C": "it possesses maximum kinetic energy at the extreme position", "D": "it swings faster at the poles than at the equator"}, "answer": "D", "explanation": "Option A is wrong in te sense that a large angle of displacement result to conical oscillation .   option B is wrong because the speed of a simple pendulum is maximum at equilibrum position,option c is also wrong because velocity is zero at the extreme position which makes the kinetic energy to be zero.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>33", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE", "question": "An electron of mass m and charge e curves in a circular path in a magnetic field of flux density B. How long does it take to complete one orbit?", "images": [], "options": {"A": "2⊼eBx", "B": "2Bme⊼", "C": "2⊼mBe", "D": "Be2xm"}, "answer": "C", "explanation": "The force, F on a charge q moving perpendicularly in a magnetic field of strenght B wth veocity V is given as F = qvB. Since the particles is an electron , then e is used instead of q.  F = eVB.  the centripetall force needed for the electron to move in its orbit is given asF=mv2vr  Where r is the radius of the orbit  since F = F  eVB = mV2/r  eB=mvr  For a complete orbit circumference of a circle (2⊼r) must hae been covered.  v=Distancetime   =2⊼rt  eBr=Nx2⊼rt  eB=2⊼Bt  eBt = 2⊼m,  t=2⊼mBe", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>34", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "Which of the following about photoelectrons is correct?", "images": [], "options": {"A": "A faint green light produces photoelectrons with less kinetic energy than a bright red light", "B": "A red light releases a smaller number of electrons than a green light", "C": "A faint green light produces photoelectrons with greater kinetic energy than a bright red light", "D": "A red light produces more photoelectrons than a green light"}, "answer": "C", "explanation": "The kinetic energy of photoelectrons is determined by the frequency (or color) of light, not its intensity (or brightness). Green light has a higher frequency than red light, so photoelectrons ejected by green light will have more kinetic energy than those ejected by red light, regardless of the brightness of the light. Therefore, a faint green light can produce photoelectrons with greater kinetic energy than a bright red light.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>35", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "The sketched graph above illustrates  the heating curve of a 0.02 kg of water. Determine the approximate value of the specific latent heat of vaporization of water.", "images": ["Physics/imgs/2020/l83.png"], "options": {"A": "2.25 x 10 6 j kg -1", "B": "4.17 x 10 3  jkg -3", "C": "2.00 x 10 3 j kg  -1", "D": "1.00 x 10 3 j kg -1"}, "answer": "A", "explanation": "specific latent heat of vapourization is amount of heat energy needed to change 1kg of liquid to vapour without a change in temperature . The heat absorbed by the liquid at the beginning of vapourization is 8 x 103J and heat absorbed after the change of stage is 53 x 103J. therefore , the total heat energy needed to change the liquid completely to vapour is  Q = 53 x 103 - 8 x 103 J = 45 x 103J  Recall, Q = mlv  Where , lv =  specific latent heat of vapourization   l=Qm=45x1030.02=2.25x106Jkg-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>36", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "In the hydraulic press, the force F applied to the diameter d of the cylinder by", "images": [], "options": {"A": "F α d2", "B": "F α d", "C": "F α d-1", "D": "F α d-2"}, "answer": "A", "explanation": "Pressure,p=Force,fArea,A Since he area is circular, the A = ⊼r2  P = F/⊼r2  Radius,r=Diameter,d2  r=d2  p=f⊼(d/2)2  p=F⊼d24  px⊼d24=F  F = (p⊼/4)d2  p⊼/4 is constant   F = kd2  F ∝d2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>37", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "In an electric circuit, an inductor of inductance 0.5 H and resistance 50 Ώ is connected to an alternating current source of frequency 60 Hz. Calculate the impedance of the circuit", "images": [], "options": {"A": "50.0 Ώ", "B": "150.0 Ώ", "C": "195.0 Ώ", "D": "1950.1 Ώ"}, "answer": "C", "explanation": "Inductance, l = 0.5H  Resistance , R = 50Ώ  Frequency, f = 60Hz  impedance , z = ?  Z = √R2 + Xl  Where XL =inductive reactance  XL = 188.66Ώ  Z = √502 + 188.62  Z = √2500+3559.96  Z = √3809.96  A = 195.1Ώ  Z = 195.0Ώ", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>38", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statement correctly explains why a total solar eclipse would be seen by people on only  small portion of the earth surface? The", "images": [], "options": {"A": "moon is larger in diameter than the earth", "B": "earth is larger in diameter than the sun", "C": "earth revolves around the sun", "D": "earth is a larger in diameter than the moon"}, "answer": "D", "explanation": "Solar eclipse occurs when the sun, moon and earth are collinear i.e in a straight line, with the moon at the middle , such that the moon cast it shadow on earth surface. The moon's shadow is narrow when it reaches the earth, so the region from which the eclipse is visible is small the earth is larger in diameter than the moon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>39", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "Water waves have a wavelength of 3.6cm and speed of 18cm s -1 in deep water. If the waves enters a shallow water with wave length of 2.0cm, calculate the speed of the waves in the shallow water.", "images": [], "options": {"A": "0.4cm s -1", "B": "2.5cm s -1", "C": "10.0cm s -1", "D": "10.8 m s -1"}, "answer": "C", "explanation": "Wavelenght in deep water, = 3.6cm  Speed in deep water, Vd = 18cm-1  Wavelenght in shallow water ⋋s = 2.0cm  Speed in shallow water. Vs = ?  VdVs=⋋d⋋s  18Vs=3.2.0  18 x 2 = 3.6Vs  36 = 3.6Vs  363.6=Vs  Vs = 10.0cms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>40", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT", "question": "An a.c generator can be converted to a d.c electric motor by replacing the", "images": [], "options": {"A": "slip ring with a split ring, and connecting a battery", "B": "split ring with slip rings and connecting a battery", "C": "a.c with d.c source and connecting a battery", "D": "a.c and d.c source and connecting split rings."}, "answer": "A", "explanation": "Slip rings are used in an ac generator while split rings are used in a dc generator. To convert an ac generator to a d.c generator , the slip are removed and replaced with split rings. Also, a.c generator uses concave magnets , these can be changed , then the coil is replaced with armature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>41", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light travels obliquely from a dense medium to a denser medium. Which of the following statement is true about the light?", "images": [], "options": {"A": "The wavelength of the light increases in the second medium", "B": "The speed of the light increases in the second medium", "C": "The light refracts towards the normal", "D": "There is a change in the  frequency of the light."}, "answer": "C", "explanation": "When a ray of light travels from a less then medium to a denser medim  - The refracted ray moves closer to th normal i.e the angle of refraction becomes smaller than the angle of incidence  - The speed of light decreases   -the wave lenght of the light decreases  - the frequency of the light is unaffected", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>42", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "The electron of mass 9.1 x 10 -31 kg is travelling at a speed of 2.0 x 10 6 ms -1. Calculate the associated  wavelength of the electron.(h=6.6 x 10 -34 js)", "images": [], "options": {"A": "3.63 x 10 -10 m", "B": "3.63 x 10 -8m", "C": "3.63 x 10 -7m", "D": "6.89 x 10 -4m"}, "answer": "A", "explanation": "ass , m =  9.1 x 10-31g  Speed, v = 2.0 x 106ms-1  Wave lenght , λ = ?  Planck's constant, h = .6 x 10-34Js  From DeBroglie equation   λ=hphere p = linear momentum   but , p = mv  λ=hmv  λ.x10-349.1 x 10-31 x 2 x 106  λ = 3.3 x 10-10m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>43", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : MELTING POINT", "question": "Which of the following statements about the process of melting of a solid are true? The temperature of the solid will  i. Remain steady until melting starts  ii. Keep rising until melting  starts  iii. Remains steady as melting proceeds  iv. Keep rising as melting proceeds", "images": [], "options": {"A": "I and III only", "B": "III and IV only", "C": "I,II and III only", "D": "II, III, IV only"}, "answer": "A", "explanation": "During change of state , there is no change in temperature, for solid to change to liquid, heat must be supplied and as it starts rising again after melting has taken place. therefore, the temperature rises before melting takes place remains steady duirng melting and keeps rising after melting .", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>44", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A diver steps off a diving platform that is 10m above the water. If there is no air resistance during the fall, there will be a decrease in the diver's", "images": [], "options": {"A": "gravitational potential energy", "B": "total mechanical energy", "C": "kinectic energy", "D": "momentum"}, "answer": "A", "explanation": "As he diver steps off the diving platform, since there is no air resistance, the divers falll with constant velociy , therefore it linear momentum and knetic energyremains constant, also , the divers total mechanical energy (sum of potential and kinetic) remains the same but the gravitational potential energy decreases due to decrease in height.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>45", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "Which of the following action would increase the electric force between two positively charged particles?", "images": [], "options": {"A": "Decreases the mass of the particles", "B": "Decreases the distance between the particles", "C": "increasing the distance between the particles", "D": "increases the mass of the particles"}, "answer": "B", "explanation": "The force of attraction or repulsion between two charges is inversely proportional to the square of the distance between them.  F∝1d2;F=Kd2 where k is a constant . This implies that as the distance between he charged particles decreases, electric force increases and vice versa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2020>46", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "A luminous objects is one that", "images": [], "options": {"A": "gives off dim blue-green light only in the dark", "B": "gives out light of its own", "C": "shines by reflected light only", "D": "glows only in the presence of light"}, "answer": "B", "explanation": "A luminous objects is an object which emit light on their own whole non luminous objects reflects light falling on them", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2020>47", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS", "question": "Which of the following units is not fundamental?", "images": [], "options": {"A": "Metre", "B": "Kilogram", "C": "joule", "D": "Candela"}, "answer": "C", "explanation": "Fundamental units are units of fundamental quanlities and they are seven , kelvin, mole , candela, amperes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2020>48", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The vacuum between the double walls of a thermos flask reduces heat loss through", "images": [], "options": {"A": "conduction and radiation", "B": "convection and conduction", "C": "radiation only", "D": "conduction only"}, "answer": "B", "explanation": "The vaccum between the walls of a vacuum flask prevent heat being transferred from the inside to the outside by conduction since both conduction and convection require material medium for their transference.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2020>49", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "In photoelectric effect, the number of electrons emitted per seconds from a metallic surface is proportional to the", "images": [], "options": {"A": "intensity of the incident radiation", "B": "frequency of the incident radiation", "C": "energy of the incident radiation", "D": "work function of the metal"}, "answer": "A", "explanation": "The number of electrons emitted is proportional to the intensity or the brightness of the incident radioaction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2020>50", "subject": "Physics", "year": "2020", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "When two cells of negligible internal resistances and equal e.m.f denoted by E 1 and E 2 are connected in parallel, the combined e.m.f. E is given by", "images": [], "options": {"A": "E= E 1 + E 2", "B": "1E=1E1+1E2", "C": "E = E 1 = E 2", "D": "E=E1E2"}, "answer": "C", "explanation": "When cells are connected in series, the combined e.m.f is the sum of the e.m.f of each cell but when cells of eqaul e.m.f are connected in parallel the combined e.m.f is the same as the e.m.f of one of the cells. i.e E = E1 = E2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>1", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "MOTION : TYPES OF FORCE", "question": "Which of the following quantities is not an example of force?", "images": [], "options": {"A": "mass", "B": "tension", "C": "weight", "D": "friction"}, "answer": "A", "explanation": "force is a measurement in newton(N) , tension, weight and friction are all measured in Newton (N) .  but mass is measured in kilogram(kg). on the other hand , tension is the pulling force in string or rope. weight is the gravitational force acting on a body and friction is the opposing force between two bodies in contact. But mass is the quantity of matter in a body", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>2", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : EDDY CURRENTS", "question": "The reason for laminating the soft iron ore of a transformer is to", "images": [], "options": {"A": "reduce eddy current", "B": "reduce the magnetic flux", "C": "increase the magnetic flux", "D": "reduce it efficiency"}, "answer": "A", "explanation": "Eddy current is one of the factors contributing to power loss in a transformer . This is the energy loss in form of heat. It is reduced by laminating the core of the transformer by breaking up the path of current flow.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>3", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTROSTATICS", "question": "Formation of hydrogen bubbles at the copper plate of a primary cell is called?", "images": [], "options": {"A": "polarization", "B": "back e.m.f", "C": "electrolysis", "D": "local action"}, "answer": "A", "explanation": "polarization is a feat of primary cell such that hydrogen bubbles are being produced at the cathode which eventually insulates the cathode since gases are insulators , gases only conducts under low pressure and high potential difference", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>4", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "Which of the following factors does not affect the rate of evaporation of a liquid ?", "images": [], "options": {"A": "Temperature", "B": "Volume", "C": "Wind", "D": "surface area"}, "answer": "B", "explanation": "the factors affecting the rate of evaporation are   - temperature   - wind and dryness of air  - surface area  -nature of liquid   - pressure   The volume of the liquid does not affect the rate of evaporation", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>5", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "The opening in the eye through which light passes to the retina is called the ?", "images": [], "options": {"A": "Pupil", "B": "cornea", "C": "iris", "D": "optic nerve"}, "answer": "A", "explanation": "The eye sees with the pupil and it serves as the opening light passes to the retina. The retina is where the image is formed . The cornea is the outer layer of the eye while iris controls the amount of light entering the pupil, The optic nerve transmits information from the eye to the brain.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>6", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A heat sensitive resistor made of semi conductor is called a", "images": [], "options": {"A": "Thermometer", "B": "Thermostat", "C": "thermistor", "D": "Thermopile"}, "answer": "C", "explanation": "A thermistor is a type of resistor whose resistance is dependent on temperature, more so than in standard resistors. The word is a portmanteau of thermal and resistor. Thermistors are widely used as inrush current limiters, temperature sensors, self-resetting overcurrent protectors, and self-regulating heating elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>7", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Electric motor primarily converts", "images": [], "options": {"A": "Electrical energy into chemical energy", "B": "kinetic energy into potential energy", "C": "electrical energy in to mechanical energy", "D": "electrical energy to heat energy"}, "answer": "C", "explanation": "an electric motor uses the correct flowing in a current carrying conductors placed in a magnetic field to cause rotation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>8", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statement about the molecules of solids and liquid is correct? They both", "images": [], "options": {"A": "have weak attraction", "B": "have wide separation", "C": "exhibit random motion", "D": "exhibit vibratory motion"}, "answer": "D", "explanation": "The molecules have strong attraction while those of liquid have weak attraction . The molecules of solids are closely packed while those of liquid perform random motion. Hence , they both vibrate", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>9", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "The distance between a node and adjacent antinode of a transverse wave is equal to", "images": [], "options": {"A": "half of the wavelength", "B": "The wave length", "C": "Thrice the wave length", "D": "quarter of the wave length"}, "answer": "D", "explanation": "Distance PQ represent are wavelength   N = Node, A = Antinode  distance between N and adjacent A = 1/4|PQ|", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>10", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT", "question": "In photoelectric effect, the number of electrons emitted per seconds from a metallic surface is proportional to the", "images": [], "options": {"A": "intensity of the incident radiation", "B": "frequency of the incident radiation", "C": "energy of the incident radiation", "D": "work function of the metal"}, "answer": "A", "explanation": "In the photoelectric effect, the number of electrons emitted per second from a metallic surface is proportional to the intensity of the incident radiation. The intensity of the radiation determines the number of photons hitting the surface per unit time, and each photon has the potential to eject an electron. Therefore, the higher the intensity, the more electrons are ejected per second. The frequency of the radiation determines the energy of the ejected electrons, not their number. The energy of the incident radiation is related to the frequency, not the intensity. The work function of the metal is the minimum energy required to eject an electron, and does not directly affect the number of electrons ejected per second.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>11", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "Which of the following actions will increase the capacitance of a parallel plate capacitor of a parallel plate capacitor?  I. Decreasing the distance between the plates  II. Increasing the distance between the plates   III. increasing the area of the plates overlap  IV. Avoiding the use of dielectric between the plates", "images": [], "options": {"A": "I and III only", "B": "II and III only", "C": "I and IV only", "D": "III and IV only"}, "answer": "A", "explanation": "factors affecting the capacitance of the capacitor are   - DIstance between the two plates : decrease in distance  increases capacitance of the capacitor and vise ise versa   - Area plates : capacitance is proportional to the area of plates . Increase in area increases capacitance and vice versa  -nature of dielectric : the more the insulating property if dielectric the more capacitance   therefore , the correct answers are I and III", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>12", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "A metallic sphere is heated from 27oC to 200oC without any change of state . Which f the following changes would result from the heating ?", "images": [], "options": {"A": "No change occur in its volume and density", "B": "Its volume increases and its density increases", "C": "Its volume increases and its density decreases", "D": "It volume increases without a change in density"}, "answer": "C", "explanation": "one of the effect of heat on a substance is expansion , hence , increase in temperature on a substance brings about an increase in its volume due to expansion . But since density and volume are inversely related , as volume increase density decreases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>13", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "The acceleration of a moving object can be determined from the", "images": [], "options": {"A": "slope of its distance-time graph", "B": "area under its distance -time graph", "C": "slope of its velocity-time graph", "D": "Area under its velocity-time graph"}, "answer": "C", "explanation": "the slope of a distance time graph is speed, the slope of a displacement time graph is velocity while the slope of a velocity time graph is acceleration , the area under a velocity time graph is the distance covered.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>14", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "A student wishes to measure the potential difference across a resistor, R. she has a galvanometer, G and some connecting wires, what else does she need?", "images": [], "options": {"A": "High value resistor connected in parallel with G", "B": "low value resistor connected in parallel with G", "C": "Low value resistor connected in series with G", "D": "high value resistor connected in series with G"}, "answer": "D", "explanation": "To convert a galvanometer to voltmeter , a multiplier (a resistor of high resistance) must be connected in series with the galvanometer", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>15", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "MACHINES :", "question": "The handle of a screw jack is 35cm long and pitch of the screw is 0.5cm, What force ust be applied at the end of the handle to lift a load of 2000N if the efficiency of the jack is 30%? [take ⊼ = 22/7]", "images": [], "options": {"A": "152.0N", "B": "132.0N", "C": "15.2N", "D": "440.0N"}, "answer": "C", "explanation": "handle, r = 35cm, pitch p = 0.5cm  Force = ?  load , L = 2000N  Efficiency , E = 30%  recall  velocity ratio, VR = 2⊼r/p  =2x22/7x350.5  VR = 440  recall  Efficiency  = MA/VR  30=MA440x100  30=10MA44  30x4410=MA  MA = 132  ButMA=loadeffort  132=2000E  132E = 2000  E = 2000/132  E = 15.2N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>16", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "The inductive reactance in a circuit of frequency 100Hz is 1Ω. Calculate the inductance of the inductor [⊼ = 3.14]", "images": [], "options": {"A": "2.00 x 10-3H", "B": "1.59 x 10-3H", "C": "1.09 x 10-3H", "D": "6.28 x 10-3H"}, "answer": "B", "explanation": "frequency , F = 100Hz  inductive resistance , XL = L  inductance , L = ?  L=XL2⊼f=12x3.14x100  1.59 x 10-3H", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>17", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "The diagram above illustrates the velocity-time graph of a body. Calculate the distance covered by the body during the motion", "images": ["Physics/imgs/2021/m14.png"], "options": {"A": "15m", "B": "84m", "C": "72m", "D": "48m"}, "answer": "C", "explanation": "Distance covered  = Area under the graph  D = area of square  + area of trapezium  D = L x L  + 1/2(a+b)h  D = 4 x 4 + 1/2( 4+ 10)8  D = 16 + 1/2 x 14 x 8  D = 16 + 56  D = 72m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>18", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "An  atom that emits an α- particles ?", "images": [], "options": {"A": "may become a daughter of a different element", "B": "becomes a different isotope of the element", "C": "becomes a daughter with increased mass", "D": "becomes a daughter of  a different element always"}, "answer": "D", "explanation": "When an atom emits an α-particle, it undergoes a type of radioactive decay known as alpha decay. During alpha decay, the atom emits an α-particle, which consists of two protons and two neutrons. As a result, the original atom loses two protons, leading to a change in its atomic number.    This change in atomic number means that the atom transforms into a daughter atom of a different element. The daughter atom will have a different atomic number and belong to a different element on the periodic table.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>19", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Which of the following units is equivalent to the electric current ?", "images": [], "options": {"A": "Cs-1", "B": "W", "C": "Js-1", "D": "C"}, "answer": "A", "explanation": "Electric current ,  I=Quantity of charge, Qtime  The unit of charge is coulomb (C)  The unit of time is second(s)  hence the unit of current is Cs-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>20", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A  ball is swung in a horizontal circle of a centre O with a constant speed. What is the direction of its acceleration?", "images": [], "options": {"A": "Away from O", "B": "along the circumference of the circle", "C": "Towards O", "D": "along a tangent to the circle"}, "answer": "C", "explanation": "A body undergoing circular motion has a constant speed with a tangential velocity, such that its acceleration is directed towards the enter of the circle", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>21", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER", "question": "Which of the following statements is an effect of compressing gas molecules at constant temperature?", "images": [], "options": {"A": "The pressure on the molecules decrease", "B": "The molecules gain more kinetic energy", "C": "The molecules make more impact per second on the walls of the container", "D": "the molecules increase in size"}, "answer": "C", "explanation": "According to boyle's law , the volume of a given mass of gas inversely proportional to pressure at constant temperature , It implies that decrease in volume lead to an increase in pressure . Hence , the gas molecules collides more frequently with the walls of the container", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>22", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "The diagram above is an illustration of an ac circuit . Calculate te reactance of the capacitor", "images": ["Physics/imgs/2021/m92.png"], "options": {"A": "2016Ω", "B": "2000Ω", "C": "200Ω", "D": "4000Ω"}, "answer": "C", "explanation": "Capacitance resistance Xc = 1/2⊼fc  capacitance , C = 5μF  = 5 x 10-6F  frequency,F=500⊼Hz  Xc=12⊼500/⊼x5x10-6   = 1/5x10-6 = 200Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>23", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A current of 2A passes through a wire of resistance 4Ω for 3 minutes . Calculate the energy lost", "images": [], "options": {"A": "960 J", "B": "1440 J", "C": "2880 J", "D": "48 J"}, "answer": "C", "explanation": "current , I = 2A ; resistance , R = 4Ω  time , t = 3minutes  = 3 x 60 = 180s  energy lost, E = I2Rt   = 22 x 4 x 180  E = 2880", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>24", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "GRAVITATIONAL FIELD : NEWTON’S LAW OF GRAVITATION", "question": "which of the following statements  about the universal gravitational constant G, is true?", "images": [], "options": {"A": "it is a fundamental quantity", "B": "it has dimension of M-1L3T-2.", "C": "it S.I is Nm2kg-2", "D": "it is a vector quantity"}, "answer": "C", "explanation": "from newton law of universal gravitation  F=Gm1m2r2  G = Fr2/m1m2, unit  = NM2/kg2 = Nm2Kg-2  where F = Force , m1 and m2 are masses, r = distance   - G has dimension of M-1L3T-2  -G has a unit of Nm2Kg-2  - G is a scaler quantity   - G is a constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>25", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : WAVEFORM", "question": "Determine the values of the amplitude and wavelength , respectively of the wave", "images": ["Physics/imgs/2021/m15.png"], "options": {"A": "8cm : 27cm", "B": "8cm : 9cm", "C": "4cm : 9cm", "D": "16cm : 27cm"}, "answer": "B", "explanation": "Amplitude is the maximum   displacement of a wave from its mean or equilibrium position , therefore , amplitude   A = 16/2 = 8cm  The wave consists of three oscillations. the distance is complete on oscillation is called wavelength  3λ = 27cm  λ = 27/3 = 9cm", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>26", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH", "question": "Determine the speed of the wave     [T = 0.125s]", "images": ["Physics/imgs/2021/m15.png"], "options": {"A": "64cms-1", "B": "32cms-1", "C": "24cms-1", "D": "72cms-1"}, "answer": "D", "explanation": "T = 0.125s; wavelength , λ = 9cm  Speed , V = ?    Bal, V = λ/T = 9/0.125 = 72cm-1", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>27", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "which of the following curve surface will produce a real image   i. concave   ii. convex mirror  iii. diverging lens  iv. converging lens", "images": [], "options": {"A": "i and iii only", "B": "i,ii and iii only", "C": "ii,iii and iv only", "D": "i and iv only"}, "answer": "D", "explanation": "a mirror and converging lens produced both real and virtual images . A convex mirror and a diverging lens produced only virtual image.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>28", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SCALARS AND VECTORS : ADDITION OF VECTORS", "question": "The component of the vectors Q and R are (-3.0,5.5) and (9.2, 4.4), respectively . Determine the component of Q+R", "images": [], "options": {"A": "(3.7,7.4)", "B": "(6.2, 9.9)", "C": "(2.5, -4.8)", "D": "(14.7, 1.4)"}, "answer": "B", "explanation": "Q = 3i + 5.5j  R = 9.2i + 4.4j  Q+R = (-3i + 5.5j) + (9.2i + 4.4j)   = -3i + 9.2i + 5.5j + 4.4j  = 6.2 i  + .9j  Hence the component of Q + R is (6.2, 9.9)", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>29", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the arrangements of radiation below shows decreasing order of wavelengths?", "images": [], "options": {"A": "x-rays > radio waves > infrared radiations", "B": "Radio waves > infrared radiation > x-rays", "C": "infrared radiation > radio waves > x-rays", "D": "x-rays > infrared radiation > radio waves"}, "answer": "B", "explanation": "The electromagnetic spectrum in decreasing order of wave length :  radio wave , microwave , infrared , visible light, ultraviolet rays, x-ras, Gamma rays .", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>30", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "An electric pressing iron is connected to the mains using an insulated wire. After some minutes , the wire becomes very hot . The heat generated in the wire can be minimized by replacing the wire with one of", "images": [], "options": {"A": "thinner insulation", "B": "greater diameter", "C": "Smaller diameter", "D": "Thicke insulation"}, "answer": "B", "explanation": "A thine wire has higher resistance compared to thick wire. hence , more heat is generated in a thin wire than in a thick wire. Therefore , to minimize the heat generated , a wire with greater diameter should be used.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>31", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "In the diagram above , a bulb is lit by drawing 2.0A from 440V a.c source . calculate the cost of keeping the bulb on the two days at $0.40 per kilowatt-hour", "images": ["Physics/imgs/2021/m93.png"], "options": {"A": "$ 16.90", "B": "$ 48.48", "C": "$ 1690.00", "D": "$ 8.48"}, "answer": "A", "explanation": "Current, I = 3A, voltage , V = 440V  Energy , E = pt  power ,  p =  = IV = 2 x 440 = 880W = 0.88kw  time , t = 2 days  = 2 x 24 = 48hrs  E = 0.88 x 48 = 42.2kwh  1kwh = $0.40  4 = 24kwh = x  x = 0.40 x 42.4   = $16.90", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>32", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "A wire of cross-sectional area 2⊼ x 10-8 and resistivity 1.1 x 10-8Ω m, has a resistance of 21Ω. calculate the length of the wire [⊼ = 22/7]", "images": [], "options": {"A": "180m", "B": "140m", "C": "120m", "D": "240m"}, "answer": "C", "explanation": "Area,A  = 2⊼ x 10-8m2; resistivity , p = 1.1 x 10-8Ωm  resistance , R = 21Ω, length ,L = ?  Recall p = RA/L  L=21x2⊼10-81.1x10-8   =42⊼1.1=42x221.1x7  l = 120m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>33", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Which of the following statement best describes the particles in a solid at room temperature? they are", "images": [], "options": {"A": "far apart and moving randomly", "B": "close together and vibrating", "C": "close together and stationary", "D": "close together  and moving randomly"}, "answer": "B", "explanation": "he particles of solid have a very strong molecular attraction between its molecules . Hence , these particles are closely packed . this gives the solids a fixed shape , the particles vibrates about their  main position", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>34", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "A man weighing 200N runs a staircase in 5s. If the height of the staircase is 9m, calculate the power of the man.", "images": [], "options": {"A": "1000W", "B": "360W", "C": "40W", "D": "1800W"}, "answer": "B", "explanation": "Weigh, w = mg = 200N  tme t = 5s  height , h = 9m  power, p = ?  power,p=mght=200x95=360w", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>35", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "A rotating disc contains sets of holes in a circle, An air jet is directed onto the holes and a note of frequency 480Hz is produced. If the number of holes is 20, calculate the speed of rotation of th disc", "images": [], "options": {"A": "10 rev/s", "B": "20 rev/s", "C": "24 rev/s", "D": "8 rev/s"}, "answer": "C", "explanation": "f=nrxnht  f=(nrt) xnh   f=480Hz;nrtx20  480=nrtx20  480=nrtx20  nrt=48020  = 24 rev/s", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>36", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A force of 10N, acting continuously increase the kinetic energy of an object from 20J to 60J. Find the distance moved by the object.", "images": [], "options": {"A": "200m", "B": "40m", "C": "4m", "D": "400m"}, "answer": "C", "explanation": "force , F = 10N,  energy change , ∆KE = 60 - 20 = 40J  distance , d = ?  workdone  = ∆KE  = force  x distance    40 = 10 x d  d = 40/10   = 4m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>37", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "An electric circuit consists of a resistor, a battery and a key. If the voltage of the battery is increase, there would be an increased in the", "images": [], "options": {"A": "current and resistance only", "B": "current , resistance and temperature", "C": "current and temperature only", "D": "resistance and temperature only."}, "answer": "C", "explanation": "According to ohm's a , V α I when the resistance is constant is force (V = IR), hence , increase in voltage increase the currently. As current temperature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>38", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive material has a half-life of 1.0 hour. id 200.g of it was present at 6 a.m on a certain day, how many grams will have decayed by 9 a.m the same day?", "images": [], "options": {"A": "175.0g", "B": "150.0g", "C": "100.0g", "D": "187.5g"}, "answer": "A", "explanation": "half life , t1 = 1hr  original mass , m1 = 200g  time ,t  = 3hrs (6am - 9am)  mas left after 3hrss, m2 = ?  recall, m1/m2 = 2t/t2  200m2=23  200m2=8  200 = 8m2  m=2008=25.g  mass decayed  = 200 - 25 = 175.0g", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2021>39", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SOUND WAVES : SOURCES OF SOUND", "question": "The following statements about a loudspeaker are correct except", "images": [], "options": {"A": "it contains a permanent magnet", "B": "sound signal converted to varying current signal enters the speech coil", "C": "The current in the speech coil creates a magnetic force on the coil", "D": "the magnetic force on the speech coil is uni-directional"}, "answer": "D", "explanation": "The following statements about a loudspeaker are correct except D. the magnetic force on the speech coil is uni-directional.    The magnetic force on the speech coil is bidirectional. This is because the current in the speech coil changes direction as the sound signal changes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>40", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "An ice cube has mass 20g at 5oC. calculate the energy required to raise it temperature to 0oC [specific heat capacity of ice = 2.1jg-1oC-1]", "images": [], "options": {"A": "105J", "B": "100J", "C": "42J", "D": "210J"}, "answer": "D", "explanation": "mas of ice ,m = 20g  change in temperature , ∆θ = 5oC - 0oC  = 5oC   S.H.C of ice  = 2.1Jg-1oC   heat Q = mc∆θ   = 20 x 3.1 x 5  Q = 210J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>41", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A stone is thrown horizontally with initial velocity 15ms-1 from a tower 20m high . How long does it take to reach the ground ?", "images": [], "options": {"A": "2s", "B": "4s", "C": "5s", "D": "1s"}, "answer": "A", "explanation": "initial velocity , u = 15ms-1  height , h = 20m  time , t = ?  recall  h = 1/2gt2  20 = 1/2 x 10t2  20 = st2  t2 = 20/5  t2 = 4  t = √4  t = 2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>42", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "Which of th following statement is not a characteristic of  a plane progressive wave?", "images": [], "options": {"A": "Energy travels out through the medium", "B": "neighbouring points along the profile possess different amplitudes", "C": "Neighbouring points along the profile posses the same amplitude", "D": "Neighbouring particles vibrates with different phase"}, "answer": "B", "explanation": "In a plane progressive wave, energy travels through the medium, neighbouring points along the profile possess the same amplitude, and neighbouring particles vibrate with different phases, making the statement that neighbouring points possess different amplitudes incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>43", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : THERMIONIC EMISSION", "question": "The electrons in a cathode-ray tube are produced by", "images": [], "options": {"A": "heating filament", "B": "ionization of the air", "C": "applying a magnetic field to the y- plates", "D": "applying an electric field to the x-plates."}, "answer": "A", "explanation": "electron in a cathode ray tube are produced by thermionic emission , which is the emission of electron from the surface of a metal after being heated .", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>44", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "POSITION, DISTANCE AND DISPLACEMENT : DISTINCTION BETWEEN DISTANCE AND DISPLACEMENT.", "question": "Which of following statement about distance and displacement is not correct?", "images": [], "options": {"A": "Displacement is a vector quantity", "B": "Distance has dimension L.", "C": "Displacement is measured in meters", "D": "Distance is a vector quantity"}, "answer": "D", "explanation": "SIMILARITIES BETWEEN DISTANCE AND DISPLACEMENT   - They are both measured in meters  - they both have the same dimension, L  - they both have fundamental qualities    Differences between distance and displacement  - Distance   *it is a scalar quantity   - Displacement   - it is a vector Quantity", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2021>45", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SOUND WAVES : HARMONIES AND OVERTONES", "question": "A note produced by an instrument distinguished from from a similar note produced by another instrument by the", "images": [], "options": {"A": "intensity", "B": "pitch", "C": "overtone", "D": "loudness"}, "answer": "C", "explanation": "The quality that distinguishes a note produced by one instrument from a similar note produced by another instrument is the overtone. Overtones are the other frequencies besides the fundamental that exist in musical instruments. Instruments of different types, but the same note, may sound different due to the different overtone pattern or 'timbre' of the instrument.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>46", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "According to pascal's principle , the pressure in a fluid is always", "images": [], "options": {"A": "dependent on density of the fluid", "B": "distributed partially in all directions.", "C": "transmitted equally in all direction", "D": "increasing with height"}, "answer": "C", "explanation": "pascal's  principle states that the pressure  applied to an enclosed fluid is transmitted indiscriminately to every position of the fluid and walls of the containing vessel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>47", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "SCALARS AND VECTORS : CONCEPT OF VECTORS", "question": "Which of the following set of quantities have members which all vectors?", "images": [], "options": {"A": "pressure, energy and force", "B": "force, displacement and momentum", "C": "distance , acceleration and work", "D": "Density, volume and weight."}, "answer": "B", "explanation": "the vectors among the options are force, displacement,momentum , acceleration and weight others are scalar quantities", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>48", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "If the relative humidity of the atmosphere increase the rate of evaporation of sweat from the human body", "images": [], "options": {"A": "decrease", "B": "remains the same", "C": "increase and then decreases.", "D": "increase"}, "answer": "A", "explanation": "humidity is the amount of water vapour present in the atmosphere . hence, increase in relative humidity brings about an increase to the content of water vapour in the atmosphere which reduces the rate of evaporation since is not dry", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>49", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY", "question": "Which of the following factors is not among those that determine the resistance of a wire ? its", "images": [], "options": {"A": "mass", "B": "cross-sectional area", "C": "length", "D": "material"}, "answer": "A", "explanation": "factors affecting resistance of a wire are :  - length of the wire   -temperature   -nature of the conductor .", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2021>50", "subject": "Physics", "year": "2021", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "Which of the following scientist suggested that moving particles  exhibits wave properties ?", "images": [], "options": {"A": "Isaac Newton", "B": "Ernest Rutherford", "C": "Louis de-Broglie", "D": "J.J  Thompson"}, "answer": "C", "explanation": "According to Louis de-Broglie , moving particles also have properties according to th equation  λ=hmv   where λ = wave lenght   h = planck's constant  m = mass   v = velocity   Both wave property (wave lenght) an particles property  (mass) represented in the equation", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>1", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "The area under a force-time graph represents", "images": [], "options": {"A": "change in kinetic energy", "B": "change in momentum", "C": "workdone", "D": "change in initial energy"}, "answer": "B", "explanation": "The area under a force-time graph represents the change in momentum. This is because the area under a force-time graph is equal to the integral of force with respect to time, which is the impulse. Impulse is equal to the change in momentum, according to the impulse-momentum theorem.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>2", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION", "question": "From the principle of flotation, a body sinks in a fluid until it displaces a quantity of fluid equal to its own.", "images": [], "options": {"A": "density", "B": "mass", "C": "weight", "D": "volume"}, "answer": "C", "explanation": "Principle of flotation states that a floating object displaces a weight of fluid equal to its own weight.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>3", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES", "question": "Suppose three identical steel balls Q, R and S are placed on an undulating ground as illustrated in the diagram above. Which of the balls is/are in neutral equilibrium?", "images": ["Physics/imgs/2022/GRNRGK.png"], "options": {"A": "S only", "B": "Q only", "C": "R only", "D": "Q and S only"}, "answer": "B", "explanation": "A body is said to be in a neutral equilibrium if when slightly displaced, it tends to come to rest in its new position.  If Q is slightly displced it comes to rest at the lowest point of the surface, S is in a stable equilibrium, it will return to its position if it is displaced, while R is in an unstable equilibrium.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>4", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "The length of a simple pendulum is increased by a factor of four. By what factor is its period increased?", "images": [], "options": {"A": "0.5π", "B": "2", "C": "2π", "D": "4"}, "answer": "B", "explanation": "T = 2π √L/g  if L2 = 4L  T2 = 2π √4L/g  T2 = 2π √4(√L/g)  T2 = 2(2π √L/g)  T2 = 2T", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>5", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The linear expansivity, α, and the cubic expansivity, γ, of a material are related by the equation.", "images": [], "options": {"A": "γ = α", "B": "γ = 3α", "C": "γ = 2α", "D": "γ = 1/3α"}, "answer": "B", "explanation": "The cubic expansivity (γ) of a material is three times its linear expansivity (α). This is because cubic expansivity is the change in volume of a material per unit original volume per degree Celsius rise in temperature, while linear expansivity is the change in length per unit original length per degree Celsius rise in temperature. Since volume is a three-dimensional quantity (length, width, and height), the cubic expansivity is three times the linear expansivity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>6", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "Which of  the illustrated graphs below represents a body moving with uniform retardation?", "images": ["Physics/imgs/2022/phyobjq6a.jpg", "Physics/imgs/2022/phyobjq6b.jpg", "Physics/imgs/2022/phyobjq6c.jpg", "Physics/imgs/2022/phyobjq6d.jpg"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "The inital velocity(velocity at t=0) is higher than the final velocity.   Decrease in velocity = retardation", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>7", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MOTION : TYPES OF MOTION", "question": "The correct relationship between the displacement, s, of a particle initially at rest in a linear motion and the time, t, is", "images": [], "options": {"A": "s ∝ t-2", "B": "s ∝ t-1", "C": "s ∝ t", "D": "s ∝ t2"}, "answer": "D", "explanation": "Second equation of motion   s = ut + 1/2at2  u= 0, a=constant  s= 1/2at2  s ∝t2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>8", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "The Joule is equivalent to", "images": [], "options": {"A": "kgm2s-1", "B": "kg2ms-2", "C": "kgm2s-2", "D": "kgms-1"}, "answer": "C", "explanation": "joule is the unit for workdone  workdone = force x distance  force = mass x acceleration = kg x ms-2  distance = m  joule = kgms-2 x m  kgm2s-2", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>9", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "HEAT ENERGY : GAS LAWS", "question": "Which of the following statement(s) is/are correct about  a fixed mass of gas compressed in an inexpansible container?  i. The average speed of the molecules increases  ii. The temperature of the gas increases  iii.The molecules hit the walls of the container more often than before the compression.", "images": [], "options": {"A": "i only", "B": "i and ii only", "C": "i and iii only", "D": "i,ii and iii"}, "answer": "D", "explanation": "If a gas is compressed, it means pressure is increased. Since pressure is directly proportional to temperature, the temperature increases, then there is also an increase in speed which means they hit the wall of the container faster.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>10", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES", "question": "An example of a mechanical wave is", "images": [], "options": {"A": "water waves", "B": "radio waves", "C": "x-rays", "D": "light rays"}, "answer": "A", "explanation": "Mechanical waves are waves that transfer energy through a medium e.g water waves, sound waves, spring waves, etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>11", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "Which of the following descriptions of the image formed  by a plane mirror is not correct?  The image is", "images": [], "options": {"A": "erect and of the same size as the object", "B": "laterally inverted and of the same size as the object", "C": "erect and bigger than the object", "D": "virtual and of the same size as the object"}, "answer": "C", "explanation": "Image formed by a plane mirror is  i. virtual and erect  ii. laterally inverted  iii.of same size as the object  iv. formed at the same distance behind the mirror as the distance of the object in front of the mirror", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>12", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MACHINES :", "question": "The efficiency of a wheel and axle is 100% and the ratio of their radii is 5:1. Calculate the effort required to lift a load of mass 20kg using this machine. [g = 10ms-2]", "images": [], "options": {"A": "20N", "B": "25N", "C": "40N", "D": "100N"}, "answer": "C", "explanation": "M.A of wheel and axle = R/r  R/r = 5:1  M.A = 5  M.A = load/effort  load = mg = 20kg x 10 ms-2= 200N  effort = Load/M.A  effort = 200N/5   effort = 40N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>13", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MAGNETIC FIELD : THE EARTH’S MAGNETIC FIELD", "question": "A freely suspended compass needle on the earth's surface settles in a plane called", "images": [], "options": {"A": "geographic meridian", "B": "magnetic meridian", "C": "magnetic declination", "D": "isoganals"}, "answer": "B", "explanation": "Magnetic meridian is a line on the earth's surface approximating a great circle passing through the north and south magnetic poles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>14", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "An object is placed at different distances,u, from a converging lens of focal length, 15.0cm. For what value of u does the lens act as a simple microscope?", "images": [], "options": {"A": "u = 15cm only", "B": "u = 30cm only", "C": "u", "D": "u > 30cm only"}, "answer": "C", "explanation": "For a converging lens to act as a simple microscope, the object must be placed at a distance less than one focal length.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>15", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "SOUND WAVES : BEATS", "question": "The periodic rise and fall in the intensity of sound produced when two notes of nearly equal frequencies are sounded together is called", "images": [], "options": {"A": "doppler effect", "B": "beat", "C": "interference", "D": "resonance"}, "answer": "B", "explanation": "Beats are the periodic and repeating fluctuations heard in the intensity of a sound when two sound waves of very similar frequencies interfere with one another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>16", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The power of a lens is +2.5 D. What is its radius of curvature ?", "images": [], "options": {"A": "2.5 cm", "B": "25.0 cm", "C": "40.0 cm", "D": "80.0 cm"}, "answer": "D", "explanation": "Power of lens(P) = 1/f  f = 1/P  f = 1/2.5  f = 0.4m = 40cm  f = radius of curvature(r)/2  r = 2f  r = 2 x 40cm  r = 80cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>17", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The reason for having a large number of turns in the coil of a moving coil galvanometer is to", "images": [], "options": {"A": "make the deflection of the needle proportional to the current", "B": "increase the sensitivity of the galvanometer", "C": "decrease the magnetic flux produced by the magnet", "D": "make the permanent magnet stronger"}, "answer": "B", "explanation": "The sensitivity of a galvanometer is directly proportional to the number of turns in the coil. More turns mean a greater magnetic effect for a given current, which allows the galvanometer to detect smaller currents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>18", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "Current is passed through two parallel conductors in the same direction. If the conductors are placed near each other, they will", "images": [], "options": {"A": "move in a circle", "B": "repel each other", "C": "remain stationary", "D": "attract each other"}, "answer": "D", "explanation": "If current is passed through two parallel conductors in the same direction, they will attract each other due to magnetic force between them", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>19", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(𝛌), PERIOD (T) AND VELOCITY (V)", "question": "The period of a 10kHZ radio wave travelling at 3.0 x 108 ms-1 is", "images": [], "options": {"A": "3.0 x 10-5 s.", "B": "1.0 x 10-4 s.", "C": "1.0 x 104 s.", "D": "3.0 x 104 s."}, "answer": "B", "explanation": "period (T) = 1/f, 10kHz = 104Hz  T = 1/104s  T = 10-4s  T = 1.0 x 10-4s", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>20", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MAGNETIC MATERIALS :", "question": "The magnetic material produced from the chemical combination of metal oxides and has a very high resistance to electric current is called a", "images": [], "options": {"A": "ferrite substance", "B": "paramagnetic substance", "C": "ferromagnetic substance", "D": "diamagnetic substance"}, "answer": "A", "explanation": "Ferrite substances are magnetic materials produced from the chemical combination of metal oxides. They have a very high resistance to electric current. Ferrites are used in many technological applications, including the cores of electrical transformers, magnetic cores of electrical inductors, and in the production of magnets.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>21", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "A body of mass, M, moving with velocity, V, has a wavelength, λ, associated with it. This phenomenon is called", "images": [], "options": {"A": "photoelectric effect.", "B": "Heisenberg's uncertainty principle", "C": "compton effect", "D": "wave-particle paradox"}, "answer": "D", "explanation": "De Broglie equation, λ = h/mv, is used to descibe the wave properties of matter, which suggests that matter can behave as a wave or particles, thereby leading to the wave-particle paradox.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>22", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "Which of the following statements about a straight current-carrying wire placed in a uniform magnetic field is correct? The wire experiences", "images": [], "options": {"A": "maximum motor force if the current reverses its direction", "B": "no motor force if it is parallel to the field", "C": "no motor force if it is perpendicular to the field", "D": "a motor force with constant direction if either the current or the magnetic field is reversed."}, "answer": "B", "explanation": "If the wire is placed such that the magnetic field is parallel to the length of the wire, the current-carrying wire remains stationary, there would be no force on it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>23", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Three cells each of emf, 1.1 V, and internal resistance, 2Ω, are connected in parallel across a 3Ω resistor. Determine the current in the resistor.", "images": [], "options": {"A": "0.90 A", "B": "0.39 A", "C": "0.30 A", "D": "0.01 A"}, "answer": "C", "explanation": "When cells are connected in parallel, they have same emf = 1.1V   the internal resistances are in parallel, the effective resistance, 1/re = 1/2 + 1/2 + 1/2  1/re = 1+1+12  1/re = 3/2 , re = 2/3 , R = 3Ω.  E = I (R+re)  I = E/(R+re) = 1.1/(3 + 2/3)  I = 1.1  × 3/11  I =3/10 = 0.3A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>24", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "Which of the following statements about electric potential energy is not correct?", "images": [], "options": {"A": "The electric potential energy of a positively charged particle increases when it moves to a point of higher potential.", "B": "The electric potential energy of a negatively charged particle increases when it moves to a point of lower potential.", "C": "The electric potential energy of a positively charged particle decreases when it moves to a point of higher potential.", "D": "The work done in taking a charged particle around a closed path in an electric field is zero."}, "answer": "C", "explanation": "The electric potential energy of a positively charged particle does not decrease when it moves to a point of higher potential", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>25", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "A galvanometer with a full scale deflection of 20 mA is converted to read 8V by connecting a 395Ω resistor in series with it. Determine the internal resistance of the galvanometer.", "images": [], "options": {"A": "2.5Ω", "B": "5.0Ω", "C": "8.0Ω", "D": "10.0Ω"}, "answer": "B", "explanation": "The total voltage measured V = 8V, the voltage across the Resistor = v1 =i ×R  the voltage across the galvanometer v2 = i×r, where r is the internal resistance and i is the current flowing through the circuit(same current flows through the resistor and galvanometer since they are in series) = 20×10-3A= 0.02A  V = v1 + v2  v1 = i×R = 0.02×395 = 7.9V  v2 = i×r = 0.02r  V = 7.9 + 0.02r  8 = 7.9 + 0.02r  0.02r = 8 - 7.9  0.02r = 0.1  r = 0.1/0.02  r = 5Ω", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>26", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE", "question": "An inductor of inductance 10H is connected across an a.c circuit source of 50V, 100Hz.  What is the current in the circuit? [π = 3.14]", "images": [], "options": {"A": "0.200A", "B": "0.070A", "C": "0.050A", "D": "0.008A"}, "answer": "D", "explanation": "VL = ILXL  XL = 2πfL  VL = 50V, f = 100Hz, L= 10H  XL = 2×3.14×100×10 = 6280Ω  VL = IL × 6280  50 = IL × 6280  IL  = 50/6280  IL = 0.008A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>27", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "The speed of fast moving neutrons in a nuclear reactor can be reduced by using", "images": [], "options": {"A": "graphite rods.", "B": "concrete shield.", "C": "iron rods.", "D": "boron rods."}, "answer": "A", "explanation": "In a nuclear reactor, the speed of fast-moving neutrons can be reduced by using graphite rods. This process is known as moderation. The graphite rods act as a moderator that slows down the speed of the neutrons to sustain the chain reaction at a steady rate.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>28", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "In a series R-L-C circuit at resonance, impedance is", "images": [], "options": {"A": "maximum", "B": "minimum", "C": "capacitive", "D": "inductive"}, "answer": "B", "explanation": "At resonance, maximum current is obtained, current is inversely proportional to impedance, therefore the impedance is minimum at resonance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>29", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A lamp is rated 240V, 60W, Determine the resistance of the lamp when lit.", "images": [], "options": {"A": "120Ω", "B": "240Ω", "C": "540Ω", "D": "960Ω"}, "answer": "D", "explanation": "The resistance of the lamp can be calculated using Ohm's law, which states that the resistance (R) is equal to the voltage (V) squared divided by the power (P). Therefore, R = V^2 / P = (240V)^2 / 60W = 960Ω.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>30", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "One major reason why electrical appliances in homes are normally earthed is that the", "images": [], "options": {"A": "person touching the appliance is safe from electric shock", "B": "appliances are maintained at a higher p.d than the earth", "C": "appliances are maintained at a lower p.d than the earth", "D": "appliances are maintained at the same p.d with that of the earth"}, "answer": "A", "explanation": "Electrical appliances are earthed to protect users against electric shock,by providing a path for a fault current to flow to earth, it also causes a circuit breaker or fuse to switch off the electric current to the circuit that has fault.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>31", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "In doping an intrinsic semiconductor to produce a p-type semiconductor,", "images": [], "options": {"A": "the semiconductor is heated up.", "B": "a donor element is added.", "C": "an acceptor element is added.", "D": "the semiconductor is connected to a battery."}, "answer": "C", "explanation": "When a semiconductor is doped with elements from group III of the periodic table like boron(B) and Aluminium(Al), they have 3 valence electron, after forming a covalent bond with the semiconductor which has 4 valence electron, they are left with one electron to attain octet rule, which makes them look for an extra electron to accept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>32", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Arrange the following radiations in order of increasing ionization of air.  I. Alpha  II. Gamma  III. Beta", "images": [], "options": {"A": "I", "B": "II", "C": "II", "D": "I"}, "answer": "C", "explanation": "Gamma has the least ionizing power while Alpha has the highest.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>33", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "WAVE-PARTICLE PARADOX : DUALITY OF MATTER", "question": "If the kinetic energy of an electron is 100eV, what is the wavelength of the de-Broglie wave associated with it ?  [h = 6.6 × 10-34Js, e = 1.6 × 10-19C, me = 9.1 × 10-31kg]", "images": [], "options": {"A": "1.22 × 10-10m", "B": "4.10 × 10-10m", "C": "3.90 × 10-10m", "D": "5.50 × 10-14m"}, "answer": "A", "explanation": "according to de-Broglie's equation, wavelength λ = h/mv  h and m are given while velocity, v, is not given   kinetic energy,K.E = 1/2mv2  K.E = 100eV = 100 × 1.6 × 10-19 = 1.6 × 10-17  v = √2K.E/me    v  = √2 ×1.6×10-17/9.1×10-31  v = √3.2 × 10-17/9.1 × 10-31  v = √0.352×1014  v = 0.5933×107 = 5.933×106  mv = 9.1 × 10-31 × 5.933 × 106= 5.399×10-24kgms-1  λ = h/mv  λ = 6.6 × 10-34/5.399×10-24  λ = 1.22 × 10-10m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>34", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "Gamma rays are produced when", "images": [], "options": {"A": "high velocity electrons are abruptly stopped in metals.", "B": "energy changes occur within the nuclei of atoms.", "C": "energy changes occur within the electronic structure of atoms.", "D": "electrons are deflected in very strong magnetic fields."}, "answer": "B", "explanation": "Gamma rays are produced in the disintegration of radioactive atomic nuclei and in the decay of certain subatomic particles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>35", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The half-life of a radioactive substance is 15 hours. If at some instance, the sample has a mass of 512g, calculate the time it will take 7/8 of the sample to decay.", "images": [], "options": {"A": "15 hours", "B": "30 hours", "C": "45 hours", "D": "60 hours"}, "answer": "C", "explanation": "How long will it take 7/8 to decay and remain 1/8  it remains 1/2 after 15 hours  it will remain 1/4 after 30 hours  and 1/8 after 45 hours", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>36", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL", "question": "When the direction of vibration of the particles of a medium is perpendicular to the direction of propagation of a wave, the wave is said to be", "images": [], "options": {"A": "longitudinal.", "B": "transverse.", "C": "mechanical.", "D": "a sound wave."}, "answer": "B", "explanation": "Transverse waves are waves which travel perpendicularly to the direction of the vibrations producing the waves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>37", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A hunter fires a gun at a point 408 m away from a cliff. If he hears an echo 2.4s later, determine the speed of the sound wave.", "images": [], "options": {"A": "340 ms-1", "B": "380 ms-1", "C": "400 ms-1", "D": "680 ms-1"}, "answer": "A", "explanation": "speed of sound after the echo is heard, v = 2 × distance/total time distance = 408 m, t = 2.4s  v = 2 × 408/2.4 = 340 ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>38", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The distance between the fixed points of a mercury-in-glass thermometer is 30 cm. Determine the temperature when the mercury level is 10.5 cm above the lower fixed point.", "images": [], "options": {"A": "28.6 ∘c", "B": "30.0 ∘c", "C": "35.0 ∘c", "D": "40.5 ∘c"}, "answer": "C", "explanation": "d1-d2/d-d2= 100-0/t-0    d1 - d2 = 30 cm, d - d2 = 10.5cm    30/10.5 = 100/t    30t = 10.5 × 100 (multiplying both sides by 10.5t)    t = 1050/30    t = 35 ∘c", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>39", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "Which of the following statements about electromagnetic waves is not correct ?", "images": [], "options": {"A": "They carry energy as they travel through space.", "B": "They travel with the speed of light.", "C": "They are longitudinal.", "D": "The electric and magnetic fields are at right angles to each other."}, "answer": "C", "explanation": "Electromagnetic waves are transverse waves, not longitudinal waves. In transverse waves, the direction of the oscillation is perpendicular to the direction of motion of the wave. In longitudinal waves, the direction of the oscillation is the same as the direction of motion of the wave.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>40", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The diameter of a brass ring 30 ∘c is 50.0 cm. To what temperature must this ring be heated to increase its diameter to 50.29 cm ?  [ linear expansivity of brass = 1.9 × 10-5 K-1]", "images": [], "options": {"A": "152.6 ∘c", "B": "182.6 ∘c", "C": "306.1 ∘c", "D": "335.3 ∘c"}, "answer": "D", "explanation": "α = l2 - l1/l1(θ2 - θ1)  l2 = 50.29cm, l1 = 50cm, θ1 = 30 ∘c, α = 1.9 × 10-5  l2 - l1 = 50.29 - 50 = 0.29cm    1.9 × 10-5 = 0.29/50(θ2 - 30)    1.9 × 10-5 × 50 × (θ2 - 30) = 0.29 (multiply both sides by 50(θ2 - 30)  (θ2 - 30) = 0.29/1.9 × 10-5 × 50    (θ2 - 30) = 305.2632 ∘c  θ2 = 30 + 305.2632 = 335.3 ∘c", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>41", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "Which of the following concepts is a method of heat transfer that does not require a material medium ?", "images": [], "options": {"A": "conduction", "B": "Diffusion", "C": "Convection", "D": "Radiation"}, "answer": "D", "explanation": "Radiation is the process by which heat is transferred from a hotter place to a cooler place without heating of the intervening medium. Thus no material medium is required.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>42", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "Which of the following statements about light travelling from one material medium to another is not correct?", "images": [], "options": {"A": "The refracted angle is less than the incident angle if the the speed is higher in the first material.", "B": "It bends away from the normal if the speed is lower in the first material.", "C": "Its wavelength does not change.", "D": "Its frequency changes."}, "answer": "D", "explanation": "When light travels from one medium to another, its speed and direction may change, which is a phenomenon known as refraction. However, the frequency of light remains constant. It is the wavelength of light that changes when it enters a different medium, not the frequency. Therefore, the statement \"Its frequency changes.\" is not correct and \"Its wavelength does not change,\" is also incorrect.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>43", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MOTION : CAUSE OF MOTION", "question": "The engine of a car provides a forward force of 1240N and the total resistive force on the car is 800N. If the mass of the car is 1220kg, determine the distance the car has to travel from the rest before acquiring a speed of 4ms-1.", "images": [], "options": {"A": "44.0m", "B": "22.2m", "C": "11.1m", "D": "5.5m"}, "answer": "B", "explanation": "F - FR = ma, F = the force pushing the car =1240N, FR = frictional force = 800N, m = mass of the car = 1220kg, a = acceleration.  1240 - 800 = 1220a  440 = 1220a  a = 440/1220    a = 0.3607ms-2  from third equation of motion, v2 = u2 + 2as  u = 0, v = 4ms-1, a = 0.3607ms-2  42 = 2 × 0.3607 × s  s = 16/0.7214    s = 22.1791m = 22.2m", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2022>44", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY", "question": "A quantity of water at 0∘C is heated to 30∘C. for each degree rise in temperature, its density will", "images": [], "options": {"A": "rise steadily.", "B": "fall steadily", "C": "fall and then rises", "D": "rise and then falls"}, "answer": "D", "explanation": "The density of water increases as the temperature increases until it gets to 4∘C and then falls as the temperature increases from 4∘C to 30∘C (anomalous behaviour of water). water has its highest density at 4∘C.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>45", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A small object of mass 50g is released from a point A. Determine the velocity of the object when it reaches a point B, a vertical distance of 30m below A. [ g= 10ms-2]", "images": [], "options": {"A": "1.5ms-1", "B": "6.0ms-1", "C": "17.3ms-1", "D": "24.5ms-1"}, "answer": "D", "explanation": "from 3rd equation of motion, v2 = u2 + 2gs  u = 0, s = 30m.  v2 = 0 + 2 × 10 × 30  v2 = 600  v = √600  v = 24.5 ms-1", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>46", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "CONCEPTS OF MATTER : CONCEPTS OF MATTER", "question": "Molecules move in random move within a liquid. The total internal energy of the liquid depends on all of the following except its", "images": [], "options": {"A": "temperature", "B": "mass", "C": "specific heat capacity", "D": "melting point"}, "answer": "D", "explanation": "The total internal energy of a liquid depends on its temperature, mass, and specific heat capacity. However, it does not depend on its melting point. The melting point is a property that describes the temperature at which a substance changes from a solid to a liquid state, but it does not directly affect the internal energy of the substance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>47", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MOTION : VISCOSITY (FRICTION IN FLUIDS)", "question": "The viscosity of a fluid depends on the following factors except the", "images": [], "options": {"A": "relative motion between the layers of the fluid", "B": "nature of the material of the fluid", "C": "surface area of the fluid in contact", "D": "normal reaction in the fluid"}, "answer": "D", "explanation": "The viscosity of a fluid depends on the relative motion between the layers of the fluid and the nature of the material of the fluid. However, it does not depend on the normal reaction in the fluid. The normal reaction is a force that acts perpendicular to the surface of contact and does not affect the viscosity of the fluid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2022>48", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS", "question": "Using venier calipers, which of the following readings gives the correct measurement for the length of a rod ?", "images": [], "options": {"A": "4.1cm", "B": "4.13cm", "C": "4.125cm", "D": "4.1254cm"}, "answer": "B", "explanation": "The vernier calipers typically provide readings to a precision of two decimal places in centimeters.    Therefore, the correct measurement for the length of a rod using vernier calipers is: 4.13 cm.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>49", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS", "question": "The basic principle of operation of a beam balance is", "images": [], "options": {"A": "Archimedes principle", "B": "law of flotation", "C": "Hooke's law", "D": "principle of moments"}, "answer": "D", "explanation": "The basic principle of operation of a beam balance is the principle of moments. The principle of moments states that for a body to be in equilibrium, the sum of the clockwise moments about any point must be equal to the sum of the anticlockwise moments about the same point. In a beam balance, the weight of the object being measured is balanced by the weight of a known mass, so that the clockwise and anticlockwise moments are equal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2022>50", "subject": "Physics", "year": "2022", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "In which of the following situations is friction not useful ?", "images": [], "options": {"A": "Operation of a grinding machine", "B": "Walking", "C": "Application of brakes", "D": "Moving piston in a sleeve"}, "answer": "D", "explanation": "Friction is useful in grinding machine , Being able to stop while walking is due to friction, friction is also used in the application of brakes to stop a moving vehicle. While friction reduces the effeciency of a moving piston in a sleeve", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>1", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : HUMIDITY AND THE WEATHER", "question": "The instrument used to measure relative humidity is a", "images": [], "options": {"A": "barometer.", "B": "hydrometer.", "C": "hygrometer.", "D": "manometer."}, "answer": "C", "explanation": "The instrument used to measure relative humidity is a hygrometer. Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. A hygrometer is a device used for measuring the moisture content in the atmosphere, soil, or confined spaces.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>2", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "Which part of the human eye performs the same function as the diaphragm in a lens camera?", "images": [], "options": {"A": "Choroid", "B": "Iris", "C": "Cornea", "D": "Retina"}, "answer": "B", "explanation": "The part of the human eye that performs a function similar to the diaphragm in a camera lens is the Iris.    Just like the diaphragm in a camera lens controls the amount of light entering the camera, the iris in the eye controls the amount of light that enters the eye by adjusting the size of the pupil. It can contract or expand to regulate the size of the pupil in response to varying light conditions, thus controlling the amount of light that reaches the retina at the back of the eye.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>3", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An electron moves from an energy level of -8.6 eV to another level of -3.5 eV. Determine the frequency of the absorbed radiation. [1 eV = 1.6 × 10-19 J, h = 6.6 × 10-34 Js]", "images": [], "options": {"A": "1.24 × 1015 Hz", "B": "2.93 × 1015 Hz", "C": "3.59 × 1016 Hz", "D": "5.39 × 1016 Hz"}, "answer": "A", "explanation": "h=6.6×10-34Js,1eV=1.6×10-19J,E1=-8.6eV,E2=-3.5eV,f=?  ∆E=hf  f=∆Eh  ∆E=E2-E1=-3.5eV-(-8.6eV)=-3.5eV+8.6eV  ∆E=5.1eV=5.1×1.6×10-19=8.16×10-19J  So,  f=8.16 × 10-196.6 × 10-34  ∴f=1.24×1015Hz", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>4", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD", "question": "A ball of mass 0.8 kg is dropped from a height, H. Just before hitting the ground, its velocity is 5.0 ms-1. Determine H.  [g = 10 ms-2]", "images": [], "options": {"A": "1.25 m", "B": "1.60 m", "C": "4.00 m", "D": "6.25 m"}, "answer": "A", "explanation": "u = 0, g = 10 ms-2, v = 5 ms-1, h = ?  From v2 = u2 + 2gh  ⇒  52 = 02 + 2 × 10 × h  25 = 0 + 20h  25 = 20h  ∴h=2520=1.25m", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>5", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : LATENT HEAT", "question": "Which of the following statements about latent heat are correct?  I. When ice melts, latent heat is absorbed  II. When water freezes, latent heat is given off   III. When water evaporates, latent heat is absorbed  IV. When water vapour condenses, latent heat is absorbed", "images": [], "options": {"A": "I and IV only", "B": "II and III only", "C": "I, II and III only", "D": "II, III and IV only."}, "answer": "C", "explanation": "Latent heat is the heat absorbed or released by a substance during a phase change. This is typically when the heat changes the state of a substance but not its temperature. So, when ice melts (solid to liquid), latent heat is absorbed. When water freezes (liquid to solid), latent heat is given off. When water evaporates (liquid to gas), latent heat is absorbed. However, when water vapour condenses (gas to liquid), latent heat is given off, not absorbed. Therefore, the correct statements are I, II and III only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>6", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "Increasing the frequency of a sound wave produces a sound with", "images": [], "options": {"A": "longer wavelength.", "B": "reduced loudness.", "C": "higher pitch.", "D": "more overtones."}, "answer": "C", "explanation": "The pitch of a sound is determined by its frequency. Higher frequencies correspond to higher pitches. For example, a high-pitched sound like a whistle has a higher frequency than a low-pitched sound like a drum.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>7", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "Which of the following diagrams correctly illustrates the mode of oscillation of air in a tube for the first overtone?", "images": ["Physics/imgs/2023/2023_phy_7a.png", "Physics/imgs/2023/2023_phy_7b.png", "Physics/imgs/2023/2023_phy_7c.png", "Physics/imgs/2023/2023_phy_7d.png"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "B", "explanation": "The diagram above, is a full wavelength and the length of an open pipe during first overtone equals one wavelength i.e.  l  = λ", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>8", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD", "question": "In a mass spectrometer, an ion of charge, q, and mass, m, moving in a path of radius, r, in a field of flux density, B, has a speed of", "images": [], "options": {"A": "mrqB.", "B": "mqqr.", "C": "Bqrm.", "D": "mqBr."}, "answer": "C", "explanation": "F=qvB(forceonamovingchargeinamagneticfield)andF=mv2r(centripetalforce)  equatingF,  qvB=mv2r  qB=mvr  qBr=mv  ∴v=Bqrm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>9", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "A sound of frequency 512 Hz reaches a listener 100 m away. If the sound travels in air at s.t.p., what is its wavelength?  [speed of sound in air = 331 ms-1]", "images": [], "options": {"A": "0.195 m", "B": "0.646 m", "C": "1.550 m", "D": "5.120 m"}, "answer": "B", "explanation": "f=512Hz,v=331ms-1,λ=?  v=fλ  λ=vf=331512  λ=0.646m", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>10", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : MODELS OF THE ATOM", "question": "In the Rutherford scattering experiment, a beam of alpha particles was fired at a thin gold film and few of the particles were deflected considerably. This shows that the nucleus of an atom", "images": [], "options": {"A": "contains protons and electrons distributed in a tiny volume.", "B": "is positively charged and is concentrated in a tiny volume.", "C": "is distributed in a tiny volume and emits alpha particles.", "D": "is concentrated in a tiny volume and contains alpha particles."}, "answer": "B", "explanation": "The Rutherford scattering experiment showed that the nucleus of an atom:    is concentrated in a tiny volume and is positively charged.    In the experiment, when alpha particles were fired at a thin gold foil, most of the alpha particles passed straight through, but a few were deflected considerably. This result led Rutherford to conclude that the positive charge of the atom is concentrated in a small, dense nucleus at the center of the atom. The fact that some alpha particles were deflected strongly indicated that there was a positively charged nucleus within the atom. This experiment was crucial in developing our understanding of atomic structure and led to the model of the atom with a central nucleus containing protons and neutrons, surrounded by electrons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>11", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC ENERGY AND POWER", "question": "A charge of 10 C is transferred across a potential difference of 220 V. Determine the work done.", "images": [], "options": {"A": "22 J", "B": "210 J", "C": "230 J", "D": "2200 J"}, "answer": "D", "explanation": "The work done in moving a charge across a potential difference is given by the formula W = QV, where W is the work done, Q is the charge and V is the potential difference. Substituting the given values, we get W = 10 C * 220 V = 2200 J. Hence, the work done is 2200 J.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>12", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "A solenoid is constructed by winding an insulated copper on a long test tube. A constant direct current is passed through the solenoid. Which of the following actions will not increase the strength of the magnetic field of the solenoid? Inserting a", "images": [], "options": {"A": "nickel rod in the test tube.", "B": "brass rod in the test tube.", "C": "soft iron rod in the test tube.", "D": "steel rod in the test tube."}, "answer": "B", "explanation": "Inserting a brass rod in the test tube will not increase the strength of the magnetic field of the solenoid.    The strength of the magnetic field inside a solenoid depends on factors such as the number of turns of wire, the current passing through it, and the core material within the solenoid. Materials with high permeability, like soft iron and steel, can enhance the strength of the magnetic field when inserted into the solenoid. Nickel, which also has some ferromagnetic properties, would have a similar effect.    However, brass is not a ferromagnetic material; it does not enhance the magnetic field strength when inserted into the solenoid. In fact, it might even slightly reduce the magnetic field strength due to its non-magnetic properties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>13", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The following statements are advantages of a solid dielectric material between the plates of a capacitor except that", "images": [], "options": {"A": "it keeps the plates at a fixed separation.", "B": "the maximum potential difference the capacitor can withstand is increased.", "C": "the capacitance of the capacitor of given dimensions is much greater than that of the plates in a vacuum.", "D": "it increases the electrical conduction of the capacitor."}, "answer": "D", "explanation": "The statement that is not an advantage of a solid dielectric material between the plates of a capacitor is:    it increases the electrical conduction of the capacitor.    In fact, one of the primary advantages of using a solid dielectric material between the plates of a capacitor is that it reduces electrical conduction between the plates. Dielectric materials are insulators, and they prevent the flow of electric current between the plates, thus increasing the capacitor's ability to store charge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>14", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "MAGNETIC FIELD : PROPERTIES OF MAGNETS AND MAGNETIC MATERIALS", "question": "Which of the following statements about a ferromagnetic material is correct? It", "images": [], "options": {"A": "attracts non-magnetic materials.", "B": "has low relative permeability.", "C": "repels other magnetic materials.", "D": "has a high susceptibility."}, "answer": "D", "explanation": "The correct statement about a ferromagnetic material is:    It has a high susceptibility.    Ferromagnetic materials are characterized by having a high susceptibility, which means they are strongly attracted to magnetic fields. When placed in a magnetic field, ferromagnetic materials become magnetized and can themselves exhibit strong magnetic properties, attracting other magnetic materials. Ferromagnetic materials, such as iron, nickel, and cobalt, are commonly used in the construction of permanent magnets and electromagnets due to their strong response to magnetic fields.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>15", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "A ball, P, is released from the roof of a building at the same time as another ball, Q, is thrown vertically upward from the base of the building. Which of the following statements is correct?", "images": [], "options": {"A": "The acceleration of P is greater than that of Q and both are in the same direction.", "B": "The acceleration of P is equal to that of Q and both are in the same direction.", "C": "The acceleration of P is equal to that of Q and are in opposite directions.", "D": "The acceleration of P is less than that of Q and both are in the same direction."}, "answer": "B", "explanation": "The correct statement is:    The acceleration of P is equal to that of Q and both are in the same direction.    When ball P is released from the roof of the building, it falls freely under the influence of gravity. Similarly, when ball Q is thrown vertically upward, it initially moves upward but is also under the influence of gravity, which acts to slow it down and eventually make it fall back down.    Both balls, P and Q, are subjected to the same acceleration due to gravity (assuming no other forces are acting on them), which is approximately 9.8 m/s² near the surface of the Earth, and this acceleration acts in the downward direction. Therefore, the acceleration of P is equal to the acceleration of Q, and both are in the same direction, which is downward.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>16", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY", "question": "A planet has mass, M, and radius R, If the universal gravitational constant is G, what is the expression for the escape velocity of an object on the planet?", "images": [], "options": {"A": "(2GR)1/2", "B": "(GR2)1/2", "C": "(GMR)1/2", "D": "(2GMR)1/2"}, "answer": "D", "explanation": "The expression for the escape velocity (ve) of an object from a planet of mass M and radius R using the universal gravitational constant G is:    ve=&radic;2GMR&nbsp;  So,thecorrectoptionis:  (2GMR)1/2", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>17", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "The specific latent heat of vapourization of lead is 8.7 × 105 Jkg-1. This means that 8.7 × 105 J of thermal energy is required to change", "images": [], "options": {"A": "1 kg of molten lead to vapour at constant temperature and pressure.", "B": "1 kg of solid lead to vapour at constant temperature and pressure.", "C": "a given mass of molten lead to vapour at constant temperature and pressure.", "D": "1 kg of molten lead to vapour for every degree rise in temperature."}, "answer": "A", "explanation": "The specific latent heat of vaporization of lead is the amount of thermal energy required to change 1 kg of molten lead to vapor at constant temperature and pressure.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>18", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "A 100 kg device is pulled up a plane inclined at 30° to the horizontal with a force of 1000 N. If the coefficient of friction between the device and the surface is 0.25, determine the total force opposing the motion.  [ g = 10 ms-2]", "images": [], "options": {"A": "216.5 N", "B": "283.5 N", "C": "716.5 N", "D": "975.0 N"}, "answer": "C", "explanation": "The forces opposing the motion of the device are \"mgsin θ\" and \"μN\" where N is the normal reaction  From the diagram, on resolving to components, N = mgcos θ  Total opposing force = mgsin θ + μmgcos θ = mg(sin θ + μcos θ)  = 100 × 10 × (sin 30o + 0.25 × cos 30o)  = 1000 × (0.5 + 0.2165)  = 1000 × 0.7165  = 716.5 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2023>19", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION", "question": "Two objects, A and B, accelerate from rest at uniform rates. B accelerates twice as much as Compared to A, B travels", "images": [], "options": {"A": "two times as far.", "B": "three times as far.", "C": "six times as far.", "D": "at the same distance as A."}, "answer": "A", "explanation": "aB=2aA(Given)  Froms=ut+12at2,  sA=12aAt2andsB=12aBt2(sinceu=0)  sB=12×(2aA)×t2(from aB = 2aA)  sB=aAt2---(i)  SincesA=12aAt2  2sA=aAt2---(ii)  equatingequation(i)and(ii)  sB=2sA  ThereforeBtravelstwotimesasfar.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>20", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The diagram above illustrates a hot metal suspended at the centre of a closed uniform box. Thermometers E, F, G and H are placed in contact with four sides of the box. Which of the thermometers would register the highest temperature?", "images": ["Physics/imgs/2023/2023_phy_20.png"], "options": {"A": "E", "B": "F", "C": "G", "D": "H"}, "answer": "A", "explanation": "Thermometer E would register the highest temperature since the hot metal is suspended from its side.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>21", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : EVAPORATION AND BOILING", "question": "A liquid is left in an open dish. After several days, there is less liquid in the dish. Which of the following statements explains this observation? The", "images": [], "options": {"A": "most energetic molecules leave the surface and return.", "B": "most energetic molecules leave the surface and escape into the air.", "C": "least energetic molecules leave the surface and return.", "D": "least energetic molecules leave the surface and escape into air."}, "answer": "B", "explanation": "The statement that explains the observation is:    The most energetic molecules leave the surface and escape into the air.    This phenomenon is known as evaporation. In a liquid, molecules have varying energies, and the molecules with higher kinetic energies (the most energetic ones) are more likely to overcome the attractive forces within the liquid and transition into the gaseous phase. These molecules escape from the surface of the liquid into the air, gradually reducing the amount of liquid in the open dish. Evaporation is a process that occurs continuously as long as there is a liquid exposed to the air.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>22", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "The colours of the visible light region of the electromagnetic spectrum that have the shortest and longest wavelengths respectively are", "images": [], "options": {"A": "red and blue.", "B": "yellow and blue.", "C": "indigo and violet.", "D": "violet and red."}, "answer": "D", "explanation": "The colors of the visible light spectrum with the shortest and longest wavelengths respectively are:    Violet and red.    Violet light has the shortest wavelength among visible colors, while red light has the longest wavelength. The visible light spectrum, in order of increasing wavelength, goes from violet to blue, green, yellow, orange, and finally red.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>23", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "Which of the following equations is not a correct mirror formula? [The symbols have their usual meanings]", "images": [], "options": {"A": "1f=1u+1v", "B": "N=360θ-1", "C": "f=1D", "D": "m=vu"}, "answer": "C", "explanation": "Theequationf=1Disnotacorrectmirrorformula.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>24", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "An atom in an excited state is one whose", "images": [], "options": {"A": "potential energy is minimum.", "B": "potential energy is maximum.", "C": "electrons are in the conduction band.", "D": "electrons have moved to a higher energy level."}, "answer": "D", "explanation": "An atom in an excited state is one whose electrons have moved to a higher energy level.    In an atom, electrons are typically found in specific energy levels or orbitals. When an electron absorbs energy, it can move from a lower energy level to a higher energy level, which is referred to as an excited state. In this higher energy state, the electron is farther from the nucleus and has more potential energy. When the electron returns to its lower energy level, it emits the excess energy as electromagnetic radiation, often in the form of visible light. This is what gives rise to the characteristic spectral lines observed in spectroscopy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>25", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD", "question": "The conclusive test for magnetism in a steel bar suspended horizontally at its midpoint is when the bar", "images": [], "options": {"A": "always settles in the magnetic N-S direction.", "B": "always settles in the magnetic E-W direction.", "C": "is repelled by a magnet.", "D": "is attracted by a magnet."}, "answer": "A", "explanation": "The conclusive test for magnetism in a steel bar suspended horizontally at its midpoint is when the bar always settles in the magnetic N-S (North-South) direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>26", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES", "question": "Which of the following devices is used to compare the relative magnitudes of charges on two given bodies?", "images": [], "options": {"A": "Electrophorus", "B": "Ebonite rod", "C": "Proof plane", "D": "Gold leaf electroscope"}, "answer": "D", "explanation": "The device used to compare the relative magnitudes of charges on two given bodies is a gold leaf electroscope.    A gold leaf electroscope consists of two thin gold leaves that are attached to a metal rod inside a glass or plastic enclosure. When a charged object is brought near the metal rod, it induces a charge on the leaves. The leaves, being like charges, repel each other and spread apart. By observing the degree to which the leaves separate, you can compare the relative magnitudes of charges on different bodies. This makes a gold leaf electroscope a valuable tool for demonstrating the presence and relative strength of electric charges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>27", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A direct current cannot pass through a parallel plate capacitor because", "images": [], "options": {"A": "the plates are non-conducting.", "B": "the plates have equal but opposite charges.", "C": "there is a leakage of charge from the plates.", "D": "the dielectric between the plates is non-conducting."}, "answer": "D", "explanation": "A direct current (DC) cannot pass through a parallel plate capacitor because the dielectric between the plates is non-conducting.    In a parallel plate capacitor, two conductive plates are separated by a dielectric material (usually an insulator). When a voltage (potential difference) is applied across the plates, it creates an electric field between them, which stores electrical energy in the form of electric potential. The dielectric material between the plates is a non-conducting material, which means it does not allow the flow of electric current. Therefore, in a DC circuit, where current is the flow of charge over time, current cannot flow through the dielectric. Instead, the dielectric serves to store energy in the electric field between the plates without allowing the passage of charge.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>28", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "The process of producing electric current by a changing magnetic field is referred to as", "images": [], "options": {"A": "flux linkage.", "B": "magnet induction.", "C": "electromagnetic induction.", "D": "electrostatic induction."}, "answer": "C", "explanation": "The process of producing electric current by a changing magnetic field is referred to as electromagnetic induction.    Electromagnetic induction is a phenomenon in which a voltage is generated in a conductor when it is exposed to a changing magnetic field. This voltage can then be used to drive an electric current.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>29", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The sagging of overhead electrical wires is caused by", "images": [], "options": {"A": "rough handling.", "B": "radiation of heat.", "C": "linear expansion.", "D": "gravitational attraction."}, "answer": "C", "explanation": "The sagging of overhead electrical wires is caused by linear expansion.    Linear expansion is the tendency of materials to expand in length when they are heated. When overhead electrical wires are heated by the sun, they expand and sag.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>30", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "A cell of emf 2 V has an internal resistance of 0.5 Ω. A current of 0.4 A passes through an external resistor, P. Determine the resistance of P.", "images": [], "options": {"A": "5 Ω", "B": "4.5 Ω", "C": "4 Ω", "D": "1 Ω"}, "answer": "B", "explanation": "E=2V,r=0.5Ω,I=0.4A,P=?  E=I(R+r)  2=0.4(R+0.5)  20.4=R+0.5  5=R+0.5  R=5-0.5=4.5Ω  ∴Theexternalresistor,Pis4.5Ω.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>31", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The property of a body that determines the direction of heat flow when the body is in contact with another body is the", "images": [], "options": {"A": "power.", "B": "heat capacity.", "C": "temperature.", "D": "mass."}, "answer": "C", "explanation": "The property of a body that determines the direction of heat flow when the body is in contact with another body is the temperature.    Heat naturally flows from a body at a higher temperature to a body at a lower temperature. Temperature is a measure of the average kinetic energy of the particles in a substance. When two objects at different temperatures come into contact, heat energy tends to transfer from the warmer object to the cooler one until they reach thermal equilibrium (they are at the same temperature). This is known as the second law of thermodynamics, which describes the direction of heat flow.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>32", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : RESONANCE", "question": "In an RLC series circuit at resonance, the voltages across the resistor and the inductor are 30 V and 40 V respectively. Determine the voltage across the capacitor.", "images": [], "options": {"A": "30 V", "B": "40 V", "C": "50 V", "D": "70 V"}, "answer": "B", "explanation": "At resonance, the inductive reactance is equal to the capacitive reactance. This means that the voltage across the inductor is also equal to the voltage across the capacitor.    Therefore, the voltage across the capacitor is 40 V.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>33", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT", "question": "The purpose of commutators in a direct current motor is to", "images": [], "options": {"A": "increase the efficiency of the motor.", "B": "reverse the direction of the current after every half rotation.", "C": "enable a uniform couple to act on the coil.", "D": "increase the number of rotations per second."}, "answer": "B", "explanation": "The purpose of commutators in a direct current (DC) motor is to reverse the direction of the current after every half rotation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>34", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF ENERGY", "question": "A lead bullet of mass 0.05 kg is fired with a speed of 200 ms-1 into a lead block of mass 0.95 kg at rest. Given that the lead block moves after the impact, determine its kinetic energy.", "images": [], "options": {"A": "50 J", "B": "100 J", "C": "150 J", "D": "200 J"}, "answer": "A", "explanation": "mbullet=0.05kg,vbullet=200ms-1,mblock=0.95kg,ublock=0  Foraninelasticcollision:  mbullet×vbullet+mblock×vblock=(mbullet+mblock)v  0.05×200+0.95×0=(0.05+0.95)v  10+0=v  v=10ms-1  Kineticenergyoftheblock=12mv2  K.E=12×(0.05+0.95)×102(thebulletnowpartoftheblock)  =12×1×102  =12x1x100  =50J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>35", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "What is the name given to the force of attraction between the nucleons in the nucleus of an atom?", "images": [], "options": {"A": "Gravitational force", "B": "Nuclear force", "C": "Electrostatic force", "D": "Magnetic force"}, "answer": "B", "explanation": "The force of attraction between the nucleons (protons and neutrons) in the nucleus of an atom is called the nuclear force or strong nuclear force. This force is responsible for holding the protons and neutrons together in the nucleus despite the electrostatic repulsion between positively charged protons. It is one of the fundamental forces in nature and plays a crucial role in the stability of atomic nuclei.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>36", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "In a controlled thermal fission reactor, the use of control rods will not affect the", "images": [], "options": {"A": "speed of the neutrons released on fission.", "B": "rate of production of the neutrons.", "C": "energy generated in the nuclear reactor.", "D": "amount of radiations produced in the nuclear reactor."}, "answer": "A", "explanation": "In a controlled thermal fission reactor, control rods are used to absorb excess neutrons and thus control the rate of the nuclear reaction. They do not affect the speed of the neutrons released on fission. The speed of the neutrons is determined by the nature of the fission process itself, not by the control rods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>37", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "The most appropriate value of fuse for a kettle rated 220 V, 1.06 kW is", "images": [], "options": {"A": "3 A.", "B": "4 A.", "C": "5 A.", "D": "6 A."}, "answer": "C", "explanation": "V=220V,P=1.06kW=1060W,I=?  P=IV  I=PV=1060220  I≈5A", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>38", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "The type of mirror used by dentists to inspect the teeth of patients is a", "images": [], "options": {"A": "convex mirror.", "B": "concave mirror.", "C": "plane mirror.", "D": "cylindrical mirror."}, "answer": "B", "explanation": "The type of mirror used by dentists to inspect the teeth of patients is a concave mirror.    Concave mirrors are curved inwards and produce a magnified image of the object placed within its focus and pole. This is why dentists use concave mirrors to examine teeth, as it allows them to see the teeth in more detail.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>39", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The diagram below illustrates a mode of vibration of a wire of length 125 cm. The speed of the waves along the wire is 120 ms-1. Use the diagram to answer questions 39 and 40.        Determine the wavelength of the waves.", "images": ["Physics/imgs/2023/2023_phy_39.png"], "options": {"A": "0.25 m", "B": "0.50 m", "C": "0.75 m", "D": "1.00 m"}, "answer": "B", "explanation": "Numberofcycles,n=212=52  Length=nλ  λ=Lengthn=1255/2  ∴λ=50cm=0.50m", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>40", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SOUND WAVES : VIBRATION IN STRINGS", "question": "The diagram below illustrates a mode of vibration of a wire of length 125 cm. The speed of the waves along the wire is 120 ms-1. Use the diagram to answer questions 39 and 40.      Determine the frequency of the waves", "images": ["Physics/imgs/2023/2023_phy_39.png"], "options": {"A": "24 Hz", "B": "192 Hz", "C": "240 Hz", "D": "286 Hz"}, "answer": "C", "explanation": "v=120ms-1,λ=0.50m,f=?  v=fλ  f=vλ=1200.5  ∴f=240Hz", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>41", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.", "question": "Which of the following statements about the properties of the electric field produced by charged parallel plates is not correct?", "images": [], "options": {"A": "The electric field in the region outside the parallel plate is zero, except for the edge effects.", "B": "The electric field is uniform everywhere in the space between the parallel plates.", "C": "The magnitude of the electric field strength at any point between the plates, except near the edges, depends on the magnitude of the charge on each plate.", "D": "The magnitude of the electric field strength at any point between the plates is directly proportional to the magnitude of the charge on each plate."}, "answer": "D", "explanation": "The magnitude of the electric field strength at any point between the plates is not directly proportional to the magnitude of the charge on each plate. Instead, it is directly proportional to the charge density (charge per unit area) on the plates. Therefore, if the charge on the plates is increased while keeping the area of the plates constant, the electric field strength will increase. However, if the area of the plates is also increased such that the charge density remains constant, the electric field strength will not change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>42", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "MOTION : RELATIVE MOTION", "question": "A car, P, with a velocity of 30 ms-1 is travelling in the same direction as a car, Q, with a velocity of 20 ms-1. The velocity of P relative to Q is", "images": [], "options": {"A": "50 ms-1.", "B": "45 ms-1.", "C": "20 ms-1.", "D": "10 ms-1."}, "answer": "D", "explanation": "vP = 30 ms-1, vQ = 20 ms-1    vP = vQ + vP/Q    vP/Q = vP - vQ = 30 - 20    ∴ vP/Q = 10 ms-1", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>43", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM", "question": "The range of wavelengths of the infrared waves in an electromagnetic spectrum is 10-3 m to 10-6 m. The wavelength of the radiation is", "images": [], "options": {"A": "equal to 103 m", "B": "longer than 103 m", "C": "shorter than 10-6 m", "D": "longer than 10-6 m"}, "answer": "D", "explanation": "The range of wavelengths for infrared waves is given as 10-3 m to 10-6 m. This means that the wavelength of the radiation is longer than 10-6 m but shorter than 10-3 m. Therefore, the only correct option is that the wavelength is longer than 10-6 m.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>44", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "When an electron jumps directly from an orbit of n = 4 to n = 2,", "images": [], "options": {"A": "a photon is emitted.", "B": "a photon is absorbed.", "C": "two photons are emitted.", "D": "two photons are absorbed."}, "answer": "A", "explanation": "When an electron jumps directly from an orbit of n = 4 to n = 2, a photon is emitted.    This is a typical scenario in atomic physics where an electron transitions from a higher energy level (orbit) to a lower energy level. During this transition, the electron loses energy, and this energy is emitted in the form of a photon. The energy of the emitted photon corresponds to the energy difference between the two energy levels, as described by the quantization of energy levels in the Bohr model of the atom.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>45", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "When a light-weight body and a massive body are acted upon by the same force for the same period of time, the", "images": [], "options": {"A": "momenta of both bodies remain the same.", "B": "lighter body has a higher momentum.", "C": "massive body has a higher momentum.", "D": "massive body builds up a higher velocity."}, "answer": "A", "explanation": "When a light-weight body and a massive body are acted upon by the same force for the same period of time, the momenta of both bodies remain the same.    Given that the momenta of both the heavy and light bodies are same, it follows that the light body possesses a higher velocity compared to the heavy body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>46", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "Which of the following devices is associated with alternating currents only?", "images": [], "options": {"A": "Induction coil", "B": "Lead-acid accumulator", "C": "Step-up transformer", "D": "Moving-coil galvanometer"}, "answer": "C", "explanation": "The device associated with alternating currents (AC) only from the provided options is the step-up transformer. Step-up transformers are specifically designed to work with alternating currents and are used to increase voltage levels in AC systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>47", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION", "question": "A body starts with an initial velocity of 20 ms-1 and moves with a uniform acceleration, a, for 15 seconds. Which of the following equations represents the distance, S, travelled?", "images": [], "options": {"A": "S = 300 + 225/2a", "B": "S = 300 + 2a/225", "C": "S = 300 + 225a/2", "D": "S = 300a + 225/2"}, "answer": "C", "explanation": "u = 20 ms-1, t = 15 s    S = ut + 1/2 at2    S = 20(15) + 1/2 × a × 152    ∴ S = 300 + 225a/2", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2023>48", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "The ratio of maximum range to maximum height of a projectile is 4. Determine the angle of projection.", "images": [], "options": {"A": "0°", "B": "30°", "C": "45°", "D": "60°"}, "answer": "C", "explanation": "Maximumrange,R=u2sin2θg  Maximumheight,H=u2sin2θ2g  SinceR:H=4  ⇒u2sin2θg:u2sin2θ2g=4  ⇒u2sin2θg÷u2sin2θ2g=4  ⇒u2sin2θg×2gu2sin2θ=4  ⇒2sin2θsin2θ=4  Sincesin2θ=2sinθcosθ  ⇒2 × 2sinθcosθsin2θ=4  ⇒4sinθcosθsin2θ=4  ⇒sinθcosθsin2θ=1  ⇒cosθsinθ=1  ⇒sinθcosθ=1  ⇒tanθ=1  ⇒θ=tan-1(1)  ∴θ=45o", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>49", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : THIRD LAW", "question": "The following statements are observations made about a towing vehicle and a bus that is being towed  I. The force exerted on the bus by the towing vehicle is of the same magnitude as the force that the bus exerts on the road.   II. The force exerted on the bus by the towing vehicle is of the same magnitude as the force exerted on the towing vehicle by the bus.   III. The towing vehicle exerts a force on the bus greater than the force exerted by the bus on the towing vehicle.  IV. The towing vehicle exerts a force on the bus that is the same as the force the road exerts on the towing vehicle.  Which of the following statements is/are correct?", "images": [], "options": {"A": "I only", "B": "II only", "C": "I, II and III only", "D": "II, III and IV only"}, "answer": "B", "explanation": "According to Newton's third law of motion, the force exerted on the bus by the towing vehicle is of the same magnitude as the force exerted on the towing vehicle by the bus (Statement II). The other statements are not necessarily true.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2023>50", "subject": "Physics", "year": "2023", "type": "Objective", "topic": "SPEED AND VELOCITY : VELOCITY-TIME GRAPH", "question": "The diagram above illustrates a velocity-time graph. Determine the distance between X and Y.", "images": ["Physics/imgs/2023/2023_phy_50.png"], "options": {"A": "10.0 m", "B": "40.0 m", "C": "80.0 m", "D": "160.0 m"}, "answer": "D", "explanation": "Distance between X and Y is the area of rectangular portion of the velocity-time graph.     XY  = 40 × (8 - 4) = 40 × 4    ∴  XY  = 160 m", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>1", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The vacuum and silvered surfaces of a vacuum flask walls are to respectively", "images": [], "options": {"A": "Minimize conduction and convection and prevent radiation", "B": "prevent conduction and convection and minimize radiation", "C": "prevent conduction and minimize convection and radiation", "D": "minimize conduction and prevent conduction and radiation"}, "answer": "B", "explanation": "A vacuum flask, also known as a Thermos, has three main components that work together to reduce heat transfer:    1. Vacuum: The space between the inner and outer walls is evacuated, which minimizes conduction and convection. Since there are no molecules to conduct heat, this significantly reduces heat transfer.  2. Silvered surfaces: The inner and outer walls are coated with a thin layer of silver, which is a poor emitter of radiation. This minimizes radiation heat transfer.    By combining these features, a vacuum flask can effectively reduce heat transfer via conduction, convection, and radiation, keeping liquids at a consistent temperature for an extended period.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>2", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "the magnitude of the acceleration of a moving object is equal to the", "images": [], "options": {"A": "gradient of a displacement-time graph", "B": "gradient of a velocity-time graph", "C": "area below  force-time graph", "D": "area below a velocity-time graph"}, "answer": "B", "explanation": "The magnitude of the acceleration of a moving object is equal to the gradient (slope) of the velocity-time graph. This is because acceleration is the rate of change of velocity, and the gradient of the velocity-time graph represents this rate of change.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>3", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "In which of the following states is maximum pressure exerted on a person", "images": [], "options": {"A": "Standing on two feet", "B": "Standing on one foot", "C": "Lying on the floor", "D": "Kneeling on the floor"}, "answer": "B", "explanation": "When you stand on one foot, your body weight is concentrated on a smaller area, resulting in maximum pressure exerted on the foot. This is because pressure is force per unit area (P = F/A), and by reducing the area (standing on one foot instead of two), the pressure increases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>4", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : THERMIONIC EMISSION~~STRUCTURE OF THE ATOM : X-RAYS", "question": "What are cathode rays?", "images": [], "options": {"A": "Stream of electrons", "B": "Beam of neutrons", "C": "Beam of protons", "D": "Stream of alpha particles"}, "answer": "A", "explanation": "Cathode rays are streams of electrons that are emitted from a cathode (a negatively charged electrode) in a vacuum tube, such as a cathode ray tube (CRT) or an electron gun. They are produced when a high voltage is applied between the cathode and an anode (a positively charged electrode), causing electrons to be accelerated and emitted from the cathode.    Cathode rays are used in various applications, including:    - Cathode ray tubes (CRTs) in older televisions and computer monitors  - Electron microscopes  - Electron beam lithography  - Vacuum tubes", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>5", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "The capacitance of a parallel plate capacitor", "images": [], "options": {"A": "decreases when the separation between the plates decreases", "B": "increases when the potential difference between the plates is increased", "C": "is greater without a dielectric between the plates than with a dielectric", "D": "is greater with a dielectric between the plates than without a dielectric"}, "answer": "D", "explanation": "The capacitance of a parallel plate capacitor is greater with a dielectric between the plates than without a dielectric. This is because the dielectric material increases the capacitance by reducing the effective electric field between the plates and increasing the amount of charge that can be stored.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>6", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH", "question": "The diagram above illustrates the movement of a cyclist from P to R. The distance travelled is determined by the", "images": ["Physics/imgs/2024/A4EL2N.jpg"], "options": {"A": "area under QR", "B": "area under PQR", "C": "gradient of PQR", "D": "gradient of QR"}, "answer": "B", "explanation": "By finding the area under the velocity-time graph, you can calculate the distance traveled by an object over a given period of time.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>7", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES~~LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "A ray of light travels from a less dense medium to a denser medium. How are the speed and frequency of the light affected? The speed", "images": [], "options": {"A": "increases and the frequency increases", "B": "decreases and the frequency decreases", "C": "increases and the frequency remains the same", "D": "decreases and the frequency remains the same"}, "answer": "D", "explanation": "When a ray of light travels from a less dense medium to a denser medium, the following changes occur:    - Speed: Decreases (due to the increased density of the medium)  - Frequency: Remains the same (frequency is a property of the light wave itself and is not affected by the change in medium)    As light passes from a less dense medium (e.g., air) to a denser medium (e.g., glass or water), it is refracted, or bent. This bending occurs because light travels at different speeds in different media. The speed of light decreases as it enters the denser medium, but its frequency remains constant.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>8", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "The function of a fuse in an electric circuit is to", "images": [], "options": {"A": "break the circuit when the current exceeds a certain value", "B": "save energy by reducing the voltage", "C": "ensure that the current in the circuit exceeds a certain value", "D": "save energy by reducing the current"}, "answer": "A", "explanation": "A fuse is a safety device designed to protect an electric circuit from excessive current, which can cause damage or fire. It is a weak link in the circuit that breaks (melts) when the current exceeds a predetermined value, interrupting the power supply and isolating the circuit. This prevents damage to the circuit, appliance, or device, and reduces the risk of electrical shock or fire.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>9", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : FIRST LAW", "question": "A body moves with a uniform velocity when the resultant force on it is", "images": [], "options": {"A": "greater than the frictional force acting on it", "B": "less than the frictional force acting on it", "C": "equal to zero", "D": "equal to unity"}, "answer": "C", "explanation": "When the resultant force on a body is zero, it means that the forces acting on the body are balanced, and there is no net force causing acceleration or deceleration. In this case, the body will maintain its uniform velocity, meaning it will continue moving at a constant speed in a straight line.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>10", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW~~NEWTON’S LAWS OF MOTION : THIRD LAW", "question": "The law of conservation of momentum is stated for closed and isolated system. What are the two conditions for a system to be closed and isolated?", "images": [], "options": {"A": "No external force acts on the system and there is no change in mass of the system", "B": "No external force acts on the system and there is a gain in mass", "C": "No external force acts on the system and there is a loss in mass", "D": "An external force acts on the system and there is no change in mass"}, "answer": "A", "explanation": "No external force acts on the system and there is no change in mass of the system.    A closed and isolated system has two conditions:    1. No external force acts on the system: This means that there are no external forces, such as friction, gravity, or thrust, acting on the system. The system is not interacting with the environment through forces.  2. No change in mass: This means that there is no mass entering or leaving the system. The total mass of the system remains constant.    When these two conditions are met, the system is considered closed and isolated, and the law of conservation of momentum applies. This means that the total momentum of the system remains constant over time, and momentum is conserved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>11", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A stone of mass 200 g attached to a string is made to revolve in a horizontal circle of radius 1.5 m at a steady speed of 5 ms-1. Calculate the tension in the string at the bottom of the circle    (g = 10ms-2)", "images": [], "options": {"A": "5.3 N", "B": "3.3 N", "C": "2.0 N", "D": "1.3 N"}, "answer": "B", "explanation": "m = 200 g = 0.2 kg; r = 1.5 m; v = 5 ms-1    F = mv2r = 0.2 &#215; 521.5  ∴ F = 3.3 N", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>12", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY~~ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "To convert milli-ammeter to an ammeter, it is necessary to connect a resistance of", "images": [], "options": {"A": "low value in series with it", "B": "high value in series with it", "C": "low value in parallel with it", "D": "high value in parallel with it"}, "answer": "C", "explanation": "A milli-ammeter is designed to measure small currents (in milliamperes). To convert it into an ammeter (which measures larger currents), you need to connect a shunt resistor (a resistor with low resistance) in parallel with the milli-ammeter.    The low-value resistor allows most of the current to bypass the milli-ammeter, enabling it to measure higher currents without being damaged.    Thus, a low-value resistor in parallel effectively converts a milli-ammeter to an ammeter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>13", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : PLANE MIRROR", "question": "An object is placed 1.5m from a plane mirror. How far is the image from the object?", "images": [], "options": {"A": "3.0m", "B": "1.3m", "C": "1.0m", "D": "0.3m"}, "answer": "A", "explanation": "Distance between image formed and mirror = Distance between object and mirror    Therefore, distance between image and object = 2 &#215; distance between object and mirror    Distance between image and object = 2 &#215; 1.5 = 3. 0 m", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>14", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "Chromatic aberration in lenses can be corrected by using a combination of", "images": [], "options": {"A": "diverging and converging lenses", "B": "an opaque material to cover the ruins of the lenses", "C": "wide parallel beams on the lens' surface", "D": "a thin convex lens"}, "answer": "A", "explanation": "The correct answer is: diverging and converging lenses.    Chromatic aberration is a common issue in lenses where different colors of light are focused at different points, resulting in a distorted image. This can be corrected by using a combination of diverging and converging lenses, known as an achromatic doublet or achromat.    An achromatic doublet consists of:    1. A converging lens (positive lens) made of a material with a high refractive index (e.g., glass)  2. A diverging lens (negative lens) made of a material with a low refractive index (e.g., flint glass)    The converging lens focuses the shorter wavelengths (violet and blue) while the diverging lens spreads out the longer wavelengths (red and orange), effectively canceling out the chromatic aberration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>15", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION", "question": "A cube of wood size 10.0 cm floats vertically in water with 4.5 cm of its length submerged. Calculate the density of the wood.    (Density of water = 1 gcm-3)", "images": [], "options": {"A": "0.450 gcm-3", "B": "0.203 gcm-3", "C": "0.090 gcm-3", "D": "0.045 gcm-3"}, "answer": "A", "explanation": "Volume of cube = 10 cm × 10 cm × 10 cm = 1000 cm3    Volume of cube submerged = volume of water displaced = 10 cm × 10 cm × 45 cm = 450 cm3    Density of water = 1 gcm-3    Using Principle of floatation:    Weight of wood = weight of water displaced    ⇒ Density of wood × Volume of wood × g = density of water × volume of water displaced × g (W = &#961;  × V × g)    ⇒ Densitywood &#215; 1000 = 1 &#215; 450    ⇒Densitywood = 4501000  ∴ Densitywood = 0.450 gcm-3", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>16", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "A temperature of 60 °C is equivalent to", "images": [], "options": {"A": "25 °F", "B": "50 °F", "C": "108 °F", "D": "140 °F"}, "answer": "D", "explanation": "100&#176;C &#8801; 212&#176;F    0&#176;C &#8801; 32&#176;F    60&#176;C &#8801; F    ⇒60 - 0100 - 0 = F - 32212 - 32  ⇒35 = F - 32180  ⇒F - 32 = 3 &#215; 180 5 = 108  ∴ F = 108 + 32 = 140&#176;F", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>17", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "All the following uses are practical applications of x-ray except", "images": [], "options": {"A": "the treatment of tumours", "B": "determining the depth of a mine", "C": "dental operation", "D": "detecting fracture in bones"}, "answer": "B", "explanation": "X-rays are not used to determine the depth of a mine. While X-rays can penetrate solid objects, they are not suitable for measuring the depth of large structures like mines.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>18", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "Two isolated charged spheres each of magnitude + 1 &#215; 10-6 C are separated by a distance of 2.0 &#215; 10-1 m. Calculate the magnitude of the electrostatic force between them.    K =  1 4&#960;&#949;0  = 9 &#215; 109 Nm2C2", "images": [], "options": {"A": "2.25 &#215; 10-1 N", "B": "4.50 &#215; 10-1 N", "C": "2.25 &#215; 101 N", "D": "4.50 &#215; 101 N"}, "answer": "A", "explanation": "Using the formula:  F = Kq1q2r2 = Kq2r2  Where:  F = electrostatic force between the particles  q1 = q2 = q = magnitude of charge of each  r = distance of separation of the particles    F = 9 &#215; 109 &#215; (1 &#215; 10-6)2(2.0 &#215; 10-1)2  F = 2.25 &#215; 10-1 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>19", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CIRCUIT", "question": "In the circuit above, which lamp causes the others to go off?", "images": ["Physics/imgs/2024/8XANTD.jpg"], "options": {"A": "P", "B": "Q", "C": "R", "D": "S"}, "answer": "D", "explanation": "When the lamp S is not connected, the circuit is open, causing other lamps go off.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>20", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "MOTION : SIMPLE IDEAS OF CIRCULAR MOTION", "question": "A particle of mass 3.6 &#215; 10-6 kg revolving around the earth has a radial acceleration of 4.3 &#215; 107 ms-2. Calculate the centripetal force of the particle", "images": [], "options": {"A": "6.25 &#215; 10-14 N", "B": "1.55 &#215; 102 N", "C": "1.00 &#215; 102 N", "D": "2.00 &#215; 10-2 N"}, "answer": "B", "explanation": "Using F = ma:    F = 3.6 &#215; 10-6 &#215; 4.3 &#215; 107    ∴ F = 1.55 &#215; 102 N", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>21", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "For a convex lens to form a real image, the distance between the object and the screen will be", "images": [], "options": {"A": "equal to the focal length of the lens", "B": "less than the focal length of the lens", "C": "twice the focal length of the lens", "D": "four times the focal length of the lens"}, "answer": "C", "explanation": "For a real image to be formed on a screen using a convex lens, the distance between the object and the lens must be at least equal to the focal length. Consequently, the distance between the object and the screen must be at least twice the focal length.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>22", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES~~SIMPLE A.C. CIRCUITS : SERIES CIRCUIT CONTAINING RESISTOR, INDUCTOR AND CAPACITOR", "question": "The constant voltage source supplies a sinusoidal alternating emf. The voltage marked against the components are their peak values.  Determine the peak value of the applied emf", "images": ["Physics/imgs/2024/KW3GTX.jpg"], "options": {"A": "1 V", "B": "4 V", "C": "5 V", "D": "11 V"}, "answer": "C", "explanation": "In an RLC circuit, the peak value of the applied emf is given by:    V = &radic;VR2 + (VL - VC)2&nbsp;    V = &radic;32 + (6 - 2)2&nbsp;    V = &radic;25&nbsp; = 5 V", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>23", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES", "question": "A 2 μF capacitor is connected directly across a 150 Vrms, 60HZ A.C source. Calculate the rms value of the current", "images": [], "options": {"A": "0.113 A", "B": "0.160 A", "C": "150 A", "D": "1324 A"}, "answer": "A", "explanation": "Irms = VrmsXC  XC = 12&#960;fC = 12 &#215; &#960; &#215; 60 &#215; 2 &#215; 10-6  XC = 7.5398 &#215; 10-4Ω  Irms = VrmsXC = 1507.5398 &#215; 10-4  ∴Irms = 0.113 A", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>24", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "A body of mass m is projected vertically upward with a velocity y. At what position will the potential energy be maximum?", "images": [], "options": {"A": "y2  g", "B": "2y2  g", "C": "y2  2g", "D": "y2  4g"}, "answer": "C", "explanation": "The potential energy (PE) of an object is given by:    PE = mgh    where m is the mass, g is the acceleration due to gravity, and h is the height above the ground.    As the body is projected upward, its potential energy increases as it gains height. The potential energy will be maximum when the body reaches its maximum height, which is when its velocity becomes zero (at the peak of its trajectory).    Using the equation for uniform motion:    v² = vo² + 2as    where v = 0 (at the maximum height), vo = y (initial velocity), a = -g (acceleration due to gravity), and s = h (height), we get:    0 = y² - 2gh    Simplifying, we get:    h=y²2g    So, the potential energy will be maximum at a height of y²2g", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>25", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : ENERGY QUANTIZATION", "question": "Light of energy 1.12 &#215; 10-18 J is incident on a metal of ejected electrons with maximum energy of 8.0 &#215; 10-19 J. Calculate the threshold frequency of the metal    [h = 6.626 &#215; 10-34 Js]", "images": [], "options": {"A": "4.8 &#215; 1014 Hz", "B": "1.2 &#215; 1015 Hz", "C": "1. &#215; 1015 Hz", "D": "2.8 &#215; 1015 Hz"}, "answer": "A", "explanation": "E = 1.12 &#215; 10-18 J; K.E = 8.0 &#215; 10-19 J; h = 6.626 &#215; 10-34 Js; fo = ?    E = W + K.E (where W = hfo)    ⇒ E = hfo + K.E    ⇒ hfo = E - K.E    ⇒fo = E - K.Eh  ⇒fo = 1.12 &#215; 10-18 - 8.0 &#215; 10-196.626 &#215; 10-34  ∴ fo = 4.83 &#215; 1014 Hz", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>26", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "An object 2.0 cm high is placed at the radius of curvature of a concave mirror such that it is perpendicular to the principal axis of the mirror. Determine the height of the image.", "images": [], "options": {"A": "0.5 cm", "B": "1.0 cm", "C": "1.5 cm", "D": "2.0 cm"}, "answer": "D", "explanation": "An upright object placed at the centre of curvature, C, of a concave mirror has its image the same height as the object.    From the diagram above, the image, A'B', is of the same height as the object, AB.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>27", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : SECOND LAW", "question": "The diagram above illustrates two boxes P and Q of masses 27.3 kg and 6.2 kg respectively on a smooth horizontal surface. If a force of F of 150 N is applied to the combined forces, calculate the acceleration.", "images": ["Physics/imgs/2024/HK9CG6.jpg"], "options": {"A": "4.5 ms_2", "B": "33.7 ms-2", "C": "70 ms-2", "D": "150 ms-2"}, "answer": "A", "explanation": "Total mass = 27.3 + 6.2 = 33.5 kg    acceleration = Forcemass = 15033.5  ∴ acceleration = 4.5 ms-2", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>28", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : THIRD LAW", "question": "A boy of mass 40 kg jumps off a stationary skateboard and moves horizontally with a speed of 1.5 ms-1 while the skateboard moves in the opposite direction with a speed of 20 ms-1. Calculate the mass of the skateboard.", "images": [], "options": {"A": "60 kg", "B": "40 kg", "C": "3 kg", "D": "2 kg"}, "answer": "C", "explanation": "m1 = 40 kg; m2 = ?; u1 = 0; u2 = 0;     v1 = 1.5 ms-1; v2 = -20 ms-1 (-ve since it moved in the opposite direction)    Using the principle of action = reaction (i.e. the law of conservation of momentum):    m1u1 + m2u2 = m1v1 + m2v2    ⇒ 40(0) + m2(0) = 40(1.5) + m2(-20)    ⇒ 0 = 60 - 20m2    ⇒ 20m2 = 60    ∴m2=6020=3kg", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>29", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : COULOMB’S LAW", "question": "The depolarizing agent of the Leclanche cell is", "images": [], "options": {"A": "powdered carbon", "B": "manganese (IV) oxide", "C": "carbon rod", "D": "ammonium"}, "answer": "B", "explanation": "The Leclanché cell is a battery that was invented and patented by the French scientist Georges Leclanché in 1866. The battery contains a conducting solution (electrolyte) of ammonium chloride, a cathode (positive terminal) of carbon, a depolarizer (oxidizer) of manganese dioxide, and an anode (negative terminal) of zinc (reductant) . Manganese dioxide (MnO2) is the oxidizing agent (depolarizer) in the Leclanché cell .", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>30", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "DERIVED QUANTITIES AND DIMENSIONAL ANALYSIS :", "question": "Which of the following terms has different dimension from the other", "images": [], "options": {"A": "Stress &#215; strain", "B": "Stress/strain", "C": "Pressure", "D": "Torque"}, "answer": "D", "explanation": "Stress, pressure, and stress × strain all have dimensions related to force and area, whereas torque has dimensions related to force and length (Newton-meters). This makes torque distinct from the other options in terms of dimensions.    Here's a brief summary:    - Stress: [ML-1T-2]  - Pressure: [ML-1T-2]  - Stress × strain: [ML-1T-2] (since strain is dimensionless)  - Torque: [ML2T-2]", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>31", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION", "question": "A capacitor described as a mica capacitor has", "images": [], "options": {"A": "both plates made of mica", "B": "one of its plates made of mica", "C": "a dielectric made of mica", "D": "the same capacitance as that of mica"}, "answer": "C", "explanation": "Mica capacitors are a type of capacitor that uses mica, a group of natural minerals, as the dielectric material. Mica is used because of its high dielectric strength, which means it can withstand high voltages without breaking down. Mica capacitors are known for their high precision, stability, and low losses, making them suitable for high-frequency applications", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>32", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : EFFECTS OF HEAT ON MATTER~~HEAT ENERGY : THERMAL EXPANSION", "question": "In which of the following devices is the thermal expansion considered a disadvantage", "images": [], "options": {"A": "Fire alarm", "B": "Thermostat", "C": "Bimetallic thermometer", "D": "Balance wheel of a watch"}, "answer": "D", "explanation": "In a balance wheel, thermal expansion would cause the wheel to expand and contract, affecting its precision and timekeeping accuracy. This is a disadvantage in a watch, where precise timekeeping is crucial.    In a watch's balance wheel, however, thermal expansion would be a disadvantage, as it would affect the precision of the timekeeping mechanism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2024>33", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "The inside portion of a hollow metal sphere of diameter 20 cm is polished. The portion will therefore form a", "images": [], "options": {"A": "concave mirror of focal length 5cm", "B": "concave mirror of focal length 10cm", "C": "convex mirror of focal length 5cm", "D": "convex mirror of focal length 10cm"}, "answer": "A", "explanation": "When the inside of a hollow metal sphere is polished, the polished surface acts as the reflecting surface. Since this surface curves inward, it forms a concave mirror. The focal length of a concave mirror is equal to half of the radius of curvature (or half of the radius of the sphere).    Since the diameter of the sphere is 20 cm, the radius is 10 cm (half of the diameter).     Therefore, the focal length of the concave mirror is:    f=R2=102=5cm", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>34", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "PROJECTILE MOTION :", "question": "Which of the following statements about a projectile is not correct?", "images": [], "options": {"A": "A projectile is  two-dimensional motion", "B": "A projectile is an object launched into air and allowed to move freely due to gravity", "C": "The range of the projectile is independent of the acceleration due to gravity", "D": "The time of flight is dependent on the acceleration due to gravity"}, "answer": "C", "explanation": "The range of a projectile is actually dependent on the acceleration due to gravity. The range is maximized when the angle of launch is 45 degrees, and it is affected by the acceleration due to gravity (g). The correct equation for the range (R) is:    R=u2sin2θg    where u is the initial velocity, θ is the angle of launch, and g is the acceleration due to gravity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>35", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "FLUID AT REST : PRESSURE IN FLUIDS", "question": "Atmospheric pressure decreases with an increase in altitude because", "images": [], "options": {"A": "acceleration due to gravity increases with altitude", "B": "temperature increases with altitude", "C": "internal energy increases with altitude", "D": "interaction among air molecules decreases due to less quantity of air"}, "answer": "D", "explanation": "Atmospheric pressure decreases with an increase in altitude because there are fewer air molecules above you, resulting in less weight pressing down on you. The atmosphere is made up of a vast number of air molecules, and the pressure we experience at the surface is due to the collective weight of these molecules.    As you go higher in altitude, the air density decreases, meaning there are fewer molecules per unit volume. This reduction in density leads to a decrease in atmospheric pressure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>36", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE ATOM : X-RAYS", "question": "The main difference between x-rays and gamma rays is their", "images": [], "options": {"A": "ionizing ability", "B": "absorbing rate", "C": "mode of propagation", "D": "mode of production"}, "answer": "D", "explanation": "X-rays and gamma rays are both forms of ionizing radiation, but they differ in their origin:    - X-rays are produced by accelerating electrons outside the nucleus (e.g., in an X-ray tube).  - Gamma rays are produced by nuclear reactions or radioactive decay within the nucleus (e.g., from radioactive isotopes).", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>37", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES~~LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The phenomenon used for explaining the formation of a rainbow in the sky is", "images": [], "options": {"A": "interference", "B": "refraction", "C": "reflection", "D": "dispersion"}, "answer": "D", "explanation": "The formation of a rainbow involves the dispersion of sunlight as it passes through water droplets in the atmosphere. Dispersion occurs because different colors (wavelengths) of light refract (bend) by different amounts when passing from one medium (air) into another (water).    As a result, white sunlight is split into its constituent colors, creating the spectrum seen in a rainbow. This process also involves refraction and total internal reflection within the droplets, but dispersion is the primary phenomenon responsible for the separation of colors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>38", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : POWER", "question": "Which of the following modes is the most economical method of transmitting electrical power over a long distance?", "images": [], "options": {"A": "Alternating current at high voltage and low current", "B": "Alternating current at low voltage and high current", "C": "Direct current at high voltage and high current", "D": "Direct current at low voltage and low current"}, "answer": "A", "explanation": "Transmitting electrical power over long distances is most economical when using alternating current (AC) at high voltage and low current. This is because power loss in transmission lines is primarily due to resistive losses, which are proportional to the square of the current (P = I2R).    By transmitting power at high voltage and low current, the current in the transmission lines is reduced, significantly minimizing power losses. High voltage transmission also allows for the use of thinner and less expensive cables.  This method is widely used in power grids to efficiently transmit electricity over long distances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>39", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "The correct sequence of ionization power of alpha particle, gamma ray and beta particle respectively is:", "images": [], "options": {"A": "low, medium, high", "B": "high, medium, low", "C": "medium, low, high", "D": "high, low, medium"}, "answer": "D", "explanation": "The ionization power of radiation is related to their ability to interact with matter and ionize atoms and molecules. The sequence from highest to lowest ionization power is:    1. Alpha particles (high): Alpha particles are heavy and strongly interacting, causing significant ionization and damage to materials.  2. Beta particles (medium): Beta particles are lighter and less interacting than alpha particles, but still cause significant ionization.  3. Gamma rays (low): Gamma rays are high-energy electromagnetic radiation, but they are weakly interacting and cause relatively little ionization.    So, the correct sequence is: Alpha (high) > Beta (medium) > Gamma (low).", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>40", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS", "question": "Four pieces of constantan wire, marked E, F, G and H, each of length 1.0m, are at the same temperature. Their respective diameters are 1 mm, 2 mm, 6 mm and 10 mm. Which wire has the highest resistance?", "images": [], "options": {"A": "E", "B": "F", "C": "G", "D": "H"}, "answer": "A", "explanation": "Using the formula for resistivity:  R = &#961; lA  Where R = resistance, &#961;  = resistivity, A = Cross-sectional area, l = length of wire  Resistance is inversely proportional to area, and the larger the diameter, the larger the area.  The wire with the highest resistance will be that with the smallest area, and diameter by extension", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>41", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "TYPES OF WAVES : WAVE MOTION", "question": "The maximum displacement of particles from equilibrium position in a wave motion is known as", "images": [], "options": {"A": "wavelength", "B": "amplitude", "C": "frequency", "D": "polarization"}, "answer": "B", "explanation": "Amplitude is the maximum displacement of particles from their equilibrium position in a wave motion. It is the maximum distance that the particles oscillate from their rest position.    Wavelength is the distance between two consecutive points on a wave that are in phase.    Frequency is the number of oscillations or cycles per second.    Polarization refers to the orientation of the wave's electric field vector.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>42", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "A non-conducting vessel contains a liquid of mass 70.0 g at 25 °C. Another 70.0 g of the same liquid at 35 °C is quickly poured into the vessel. Determine the final temperature of the mixture", "images": [], "options": {"A": "15 °C", "B": "20 °C", "C": "30 °C", "D": "40 °C"}, "answer": "C", "explanation": "Let final temperature be &#952;    Heat lost by hot liquid = Heat gained by cooler liquid.    The masses of both liquids = 70g, their specific heat capacities are the same.    Using H = mc&#952;    70 &#215; c &#215; (35 - &#952;) = 70 &#215; c &#215; (&#952; - 25)    35 - &#952; = &#952; - 25    2&#952; = 35 + 25 = 60    ∴&#952; = 602 = 30 °C", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>43", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "ELECTRIC FIELD : SHUNT AND MULTIPLIER", "question": "A galvanometer of full-scale deflection 10mA has a resistance of 5 Ω. Calculate the shunt needed to convert it to measure a current of 2 A.", "images": [], "options": {"A": "0.025 Ω", "B": "0.050 Ω", "C": "0.250 Ω", "D": "0.500 Ω"}, "answer": "A", "explanation": "Given: Ig = 10mA = 0.010 A, Rg = 5 Ω, I = 2 A    (I - Ig)Rs = IgRg    Rs = IgRgI - Ig = 0.010 &#215; 52 - 0.010  Rs=0.051.99  ∴ Rs = 0.025 Ω", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>44", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION", "question": "In storing magnets, the keepers are used to", "images": [], "options": {"A": "cancel the effect of the earth's magnetism", "B": "reduce self-demagnetization", "C": "protect the magnet from stray electric field", "D": "increase the strength of the magnet"}, "answer": "B", "explanation": "Keepers are soft iron pieces placed across the poles of a magnet to:    - Reduce self-demagnetization: By providing a path for the magnetic field lines to flow, keepers prevent the magnet from losing its strength over time due to internal demagnetization.  - Preserve the magnetic field: Keepers help maintain the magnetic field by providing a low-reluctance path for the field lines.", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2024>45", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "Which of the following factors does not affect the speed of sound?", "images": [], "options": {"A": "Loudness", "B": "Wind direction", "C": "Temperature", "D": "Material medium"}, "answer": "A", "explanation": "Loudness is a measure of the intensity of sound, not its speed. The speed of sound is unaffected by the loudness or intensity of the sound wave.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>46", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "A convex mirror is used as a driving mirror; however, a disadvantage in this regard is that the image", "images": [], "options": {"A": "it produces is virtual", "B": "it produces is real", "C": "it is not as bright as we would like", "D": "appears farther away from the driver"}, "answer": "D", "explanation": "Convex mirrors are used as rearview mirrors in vehicles because they provide a wider field of view and a more comprehensive view of the surroundings. However, a disadvantage is that the image appears smaller and farther away than it actually is, which can be a drawback for the driver.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>47", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY~~HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION", "question": "The amount of heat energy that will be extracted when 0.02 kg of water vapor condenses to water at 970C is    [Specific heat of vaporization of water = 2.26 &#215; 106 J kg-1, Specific heat capacity of water = 4200 J kg-1 k-1", "images": [], "options": {"A": "45,452 J", "B": "45,200 J", "C": "25,200 J", "D": "252 J"}, "answer": "A", "explanation": "Total energy extracted = Energy extracted for change of state + Energy extracted for reduction in temperature    Energy extracted for change of state:    H1 = mL = 0.02 &#215; 2.26 &#215; 106    H1 = 45,200 J    Energy extracted for reduction of temperature:    H2 = mc∆&#952; = 0.02 &#215; 4200 &#215; (100 - 97)    H2 = 0.02 &#215; 4200 &#215; 3    H2 = 252 J    Total energy extracted = H1 + H2 = 45200 + 252 = 45,452 J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>48", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "Water is readily available, but it is not a thermometric liquid mainly because it", "images": [], "options": {"A": "clings to glass", "B": "does not expand uniformly", "C": "boils at low temperature", "D": "is colourless"}, "answer": "B", "explanation": "For a liquid to be used in a thermometer, it must have a uniform and predictable expansion with temperature changes. This ensures accurate and consistent temperature measurements.    Water does not expand uniformly with temperature, particularly around 4°C where it reaches maximum density and begins to expand upon further cooling or heating. This non-uniform expansion makes water unsuitable as a thermometric liquid.    While water clings to glass and is colorless, these factors are less critical compared to its non-uniform expansion. The boiling point is also not the primary reason why water is not used in thermometers.    Therefore, the main reason water is not a thermometric liquid is its lack of uniform expansion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>49", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : BOILING POINT", "question": "The constant temperature at which a liquid changes into gaseous state is known as", "images": [], "options": {"A": "evaporation point", "B": "melting point", "C": "dew point", "D": "boiling point"}, "answer": "D", "explanation": "The boiling point is the temperature at which a liquid changes state from a liquid to a gas (vapor) at standard atmospheric pressure. It is a constant temperature for a specific liquid.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2024>50", "subject": "Physics", "year": "2024", "type": "Objective", "topic": "HEAT ENERGY : THERMAL EXPANSION", "question": "The diagram above illustrates the graph for", "images": ["Physics/imgs/2024/DHXRFP.jpg"], "options": {"A": "the variation of a volume of a gas with increasing temperature", "B": "expansion curve of mercury", "C": "expansion curve of liquid oxygen", "D": "anomalous expansion of water"}, "answer": "D", "explanation": "Anomalous expansion of water refers to the unusual behavior of water when it cools. Unlike most substances, which contract and become denser when cooled, water expands and becomes less dense as it cools below 4°C. This means that water reaches its maximum density at 4°C, and then expands as it freezes into ice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>1", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "MACHINES :", "question": "The diagram below illustrates a pulley system used to raise a 10 kg load. If the effort F needed to raise the load is 70 N, calculate the efficiency of the machine. [g = 10 ms−2]", "images": ["Physics/imgs/2025/FDP4AM.jpg"], "options": {"A": "20.0%", "B": "35.7%", "C": "50.0%", "D": "75.0%"}, "answer": "B", "explanation": "Load (L) = 10 kg; Effort (E) = 70 N; g = 10 ms−2; ε = ?    Load, L, in Newtons = 10 × 10 = 100 N    Since the number of pulleys is 4    ∴ V.R = 4    ε=M.AV.R×100%=L/EV.R×100%  ε=100/704×100%=10070 × 4×100%  ε=100280×100%  ε = 0.357 × 100%    ∴ ε = 35.7%", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>2", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF WORK", "question": "The diagram below illustrates the force-displacement graph of a body. Calculate the work done during the first 20 m of motion.", "images": ["Physics/imgs/2025/6H4JHP.jpg"], "options": {"A": "1000 J", "B": "825 J", "C": "750 J", "D": "500 J"}, "answer": "B", "explanation": "The work done during the first 20 m of motion is the area of the shape ABCDE.    Adding up the areas of each shape in ABCDE would give the working done during the first 20 m of motion.    Work done = I + II + III + IV     Work done = (15 × 10) + (15 × 10) + (1/2 × 10 × (50 − 15)) + (50 − 15) × 10    Work done = 150 + 150 + 1/2 × 10 × 35 + 35 × 10    ∴ Work done = 150 + 150 + 175 + 350 = 825 J", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>3", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "The dispersion of light would result in which of the following phenomena?", "images": [], "options": {"A": "Eclipse", "B": "Shadow", "C": "Rainbow", "D": "Mirage"}, "answer": "C", "explanation": "The dispersion of light is the phenomenon where light is separated into its different colors (wavelengths) as it passes through a medium, such as a prism or water droplets. This happens because different colors of light bend (refract) by different amounts when passing through a medium.    A rainbow is formed when sunlight is dispersed by water droplets in the atmosphere, splitting the light into its constituent colors (red, orange, yellow, green, blue, indigo, and violet).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>4", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "The best color of shirt to be worn on a bright noon day is", "images": [], "options": {"A": "red.", "B": "black.", "C": "green.", "D": "white."}, "answer": "D", "explanation": "On a hot, sunny day, the best clothing color is one that reflects sunlight rather than absorbing it.    White reflects most of the sunlight, keeping you cooler.    Black absorbs all wavelengths of light, converting them into heat, making you feel hotter.    Red, Green, and other dark colors also absorb more light than white, though not as much as black.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>5", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES", "question": "The image formed when an object is placed between the focus and centre of a converging lens is", "images": [], "options": {"A": "real, inverted and magnified.", "B": "real, inverted and diminished.", "C": "erect, virtual and magnified.", "D": "erect, virtual and diminished."}, "answer": "A", "explanation": "For a converging lens (convex lens), when an object is placed between the focus (F) and the center of curvature (2F), the image formed is:    Real (can be projected on a screen),    Inverted,    Magnified (larger than the object),    And formed beyond 2F on the opposite side of the lens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>6", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.~~MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE", "question": "For a charged body moving in an electric and magnetic crossed field, the ratio of the electric field intensity, E to the magnetic flux density, B is known as", "images": [], "options": {"A": "Lorentz ratio.", "B": "Charge ratio.", "C": "Velocity selector.", "D": "Electrochemical equivalence."}, "answer": "C", "explanation": "When a charged particle moves through crossed electric (E) and magnetic (B) fields, it experiences forces due to both fields. In a velocity selector, the fields are adjusted such that only particles with a specific velocity v = E/B pass through undeflected. This setup is used in devices like mass spectrometers.    F = qvB = qE    vB = E    ∴v=EB", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>7", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : CHARACTERISTICS OF SOUND", "question": "A note, K from a keyboard has an amplitude of 0.5 cm and frequency 2000 Hz. Another note, M from a guitar has an amplitude of 1.5 cm and frequency 2000 Hz. Which of the following statements is true if the two notes are compared?", "images": [], "options": {"A": "K is louder than M", "B": "M is louder than K", "C": "M has a higher pitch than K", "D": "K and M have the same timbre."}, "answer": "B", "explanation": "Loudness of a sound is related to its amplitude — the greater the amplitude, the louder the sound.    Note K has amplitude 0.5 cm    Note M has amplitude 1.5 cm (which is greater)  Both have the same frequency (2000 Hz), so they have the same pitch, not loudness.  Therefore, M is louder than K.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>8", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M", "question": "A simple pendulum of length 0.8 m is set oscillating on a planet. If the pendulum completes 20 oscillations in 60 s, calculate the acceleration due to gravity on this planet. [π = 3.14]", "images": [], "options": {"A": "2.5 ms−2", "B": "3.0 ms−2", "C": "3.5 ms−2", "D": "3.8 ms−2"}, "answer": "C", "explanation": "L = 0.8 m; n = 20; t = 60 s; π = 3.14; g = ?    T=tn=6020=3  To calculate the acceleration due to gravity (g) on the planet, we'll use the formula for the period of a simple pendulum:    T=2π&radic;Lg&nbsp;  3=2(3.14)×&radic;0.8g&nbsp;  3=6.28×&radic;0.8g&nbsp;  36.28=&radic;0.8g&nbsp;  (36.28)2=0.8g  g=0.8÷(36.28)2  g = 3.506 ms−2    ∴ g ≃ 3.5 ms−2", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>9", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "HEAT ENERGY : SPECIFIC HEAT CAPACITY", "question": "A liquid of mass 2 kg at 61°C is kept in a lagged vessel. If another 2 kg of the same liquid at 21°C is added to the liquid in the vessel, calculate the final temperature of the mixture.", "images": [], "options": {"A": "50°C", "B": "41°C", "C": "30°C", "D": "15°C"}, "answer": "B", "explanation": "Mass of hot liquid (m₁) = 2 kg    Mass of cold liquid (m₂) = 2 kg    Temperature of hot liquid (θ₁) = 61°C    Temperature of cold liquid (θ₂) = 21°C    Specific heat capacity (c) is same for both liquids (since they are the same substance)    Heat Lost by Hot Liquid = Heat Gained by Cold Liquid    The hot liquid cools down, and the cold liquid warms up until they reach the same final temperature (θf).    m₁c(θ₁ − θf) = m₂c(θf − θ₂)    ⇒ m₁(θ₁ − θf) = m₂(θf − θ₂)    Since m₁ and m₂ are equal    ⇒ θ₁ − θf = θf − θ₂    ⇒ 61°C − θf = θf − 21°C    ⇒ 61°C + 21°C = θf + θf    ⇒ 82°C = 2θf    ∴θf=82°C2=41°C", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>10", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : LENZ’S LAW", "question": "The diagrams below indicate the current induced in a coil as a result of relative motion between it and a bar magnet. Which of the diagrams illustrates the direction of the induced current?", "images": ["Physics/imgs/2025/N2DNPF.jpg", "Physics/imgs/2025/84YYH7.jpg", "Physics/imgs/2025/GD9C42.jpg", "Physics/imgs/2025/99JB8G.jpg"], "options": {"A": "", "B": "", "C": "", "D": ""}, "answer": "D", "explanation": "Case 1: North pole moved towards the loop  The approaching north pole increases the magnetic flux into the loop.    The loop opposes this increase by creating its own north pole (to repel the approaching magnet).    To create a north pole facing the magnet, the current must flow in the counterclockwise direction (when viewed from the magnet's side).      Case 2: North pole moved away from the loop  The magnetic flux decreases as the north pole recedes.    The loop tries to maintain the flux by attracting the magnet — i.e., creating a south pole facing the receding north pole.    To create a south pole, current must flow in the clockwise direction (again, viewed from the magnet's side).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>11", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "HEAT ENERGY : HEAT TRANSFER", "question": "If two bodies, A and B are each in thermal equilibrium with another body C, then the three bodies are in thermal equilibrium with each other. This is the statement of", "images": [], "options": {"A": "Zeroth law of thermodynamics.", "B": "First law of thermodynamics.", "C": "Second law of thermodynamics.", "D": "Third law of thermodynamics."}, "answer": "A", "explanation": "The Zeroth law of thermodynamics states that:    If two bodies (A and B) are each in thermal equilibrium with a third body (C), then A and B are in thermal equilibrium with each other.    This law forms the basis for the concept of temperature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>12", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SIMPLE A.C. CIRCUITS : PEAK AND R..M.S. VALUES", "question": "A constant voltage source in the circuit below supplies a sinusoidal alternating e.m.f., the voltages marked against the components are the peak values.    Determine the peak value of the applied e.m.f.", "images": ["Physics/imgs/2025/RW3BEY.png"], "options": {"A": "11.0 V", "B": "9.0 V", "C": "8.0 V", "D": "5.0 V"}, "answer": "D", "explanation": "VR = 3 V; VL = 6 V; VC = 2 V    Vo = &radic;VR2 + (VL − VC)2&nbsp;    Vo = &radic;32 + (6 − 2)2&nbsp;    Vo = &radic;32 + 42&nbsp;    Vo = &radic;9 + 16&nbsp;    Vo = &radic;25&nbsp;    ∴ Vo = 5.0 V", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>13", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : TRANSMISSION OF SOUND WAVES", "question": "A vibrator is used to generate ripples in a ripple tank. If the distance between two successive troughs is 3.5 cm and the wave travels a distance of 31.5 cm in 1.5 s, calculate the frequency of the vibrator.", "images": [], "options": {"A": "3.0 Hz", "B": "6.0 Hz", "C": "9.0 Hz", "D": "12.0 Hz"}, "answer": "B", "explanation": "λ = 3.5 cm; x = 31.5 cm; t = 1.5 s    v=xt=31.51.5=21cms-1  v=fλ⇒f=vλ  ∴f=213.5=6.0Hz", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>14", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES", "question": "The speed of light in medium A of refractive index 1.5 is 2.0 × 108 ms−1. Determine the speed of light in medium B of refractive index 1.2.", "images": [], "options": {"A": "1.8 × 108 ms−1", "B": "2.5 × 108 ms−1", "C": "2.7 × 108 ms−1", "D": "3.0 × 108 ms−1"}, "answer": "B", "explanation": "nA = 1.5; vA = 2.0 × 108; nB = 1.2, vB = ?    nAnB=vBvA⇒vB=nAnB×vA  vB=1.51.2×2.0×108  vB = 1.25 × 2.0 × 108    ∴ vB = 2.5 × 108", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>15", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : SPEED OF SOUND", "question": "The wavelength of a sound note travelling with a speed of 360 ms−1 is 600 m. Determine the period of the note.", "images": [], "options": {"A": "60.000 s", "B": "6.000 s", "C": "1.667 s", "D": "0.167 s"}, "answer": "C", "explanation": "v = 360 ms−1; λ = 600 m; T = ?    v=fλ⇒f=vλ  f=360600=0.6Hz  ButT=1f  ∴T=10.6=1.667s", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>16", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "MACHINES :", "question": "In which of the following levers is the effort applied between the load and the fulcrum?", "images": [], "options": {"A": "Pliers", "B": "Wheelbarrow", "C": "Sugar tongs", "D": "Table knife"}, "answer": "C", "explanation": "In Class 3 Levers (a.k.a Third Order Levers), the effort is applied between the load and the fulcrum. This arrangement is seen in:    Sugar tongs: The effort (squeezing force) is applied between the fulcrum (pivot point) and the load (sugar being gripped).    Other examples: Tweezers, human arm, fishing rod.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>17", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Use the circuit diagram below to answer question 17 and 18.      The current passing through the 6 Ω resistor is 1.5 A. Calculate the current in the 3 Ω resistor.", "images": ["Physics/imgs/2025/3H6BHG.png"], "options": {"A": "1.20 A", "B": "0.90 A", "C": "0.75 A", "D": "0.60 A"}, "answer": "D", "explanation": "Using the current divider rule,    I3Ω=R2ΩR3Ω + R2Ω×I  I3Ω=23 + 2×1.5  I3Ω=25×1.5  ∴ I3Ω = 0.60 A", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>18", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE", "question": "Use the circuit diagram below to answer question 17 and 18.    Calculate the terminal p.d of the battery in the diagram.", "images": ["Physics/imgs/2025/3H6BHG.png"], "options": {"A": "7.20 V", "B": "7.30 V", "C": "10.80 V", "D": "11.25 V"}, "answer": "C", "explanation": "Terminal p.d, V = IRT    RT=3 × 23 + 2+6=65+6  RT = 1.2 + 6 = 7.2 Ω    ∴ V = 1.5 × 7.2 = 10.80 V", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>19", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "Which of the statements is correct about the nucleus of an atom? It  I. is centrally located in the atom.  II. contains the nucleons and electrons.  III. is positively charged due to the protons.  IV. decays when there is instability inside.", "images": [], "options": {"A": "I, II and IV only", "B": "I, III, and IV only", "C": "I, II, and III only", "D": "I and II only"}, "answer": "B", "explanation": "I. \"The nucleus is centrally located in the atom.\"    True. The nucleus sits at the center of the atom, surrounded by electrons in orbitals.    II. \"The nucleus contains the nucleons and electrons.\"    False. The nucleus contains protons and neutrons (nucleons) but not electrons, which reside outside the nucleus in electron shells.    III. \"The nucleus is positively charged due to the protons.\"    True. Protons carry a positive charge, while neutrons are neutral. The net charge of the nucleus is positive.    IV. \"The nucleus decays when there is instability inside.\"    True. Nuclear decay (e.g., alpha/beta decay) occurs when the nucleus is unstable (e.g., due to an excess of protons/neutrons).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>20", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive element of mass 16 g was isolated and stored. It was discovered that after 40 days only 1 g of the element remained undecayed. Calculate the half-life of the element.", "images": [], "options": {"A": "2.5 days", "B": "5.0 days", "C": "10.0 days", "D": "15.0 days"}, "answer": "C", "explanation": "No = 16 g; N = 1 g; t = 40 days, T1/2 = ?    The fraction of the substance remaining is given by:    NNo=(12)n  ⇒116=(12)n  ⇒124=(12)n  ⇒(12)4=(12)n  ⇒n=4(numberofhalf-lives)  T1/2=tn=404  ∴T1/2=10.0days", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>21", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : ECHOES AND REVERBERATION", "question": "Which of the following reasons explains why the walls and ceilings of a standard concert hall are usually covered with perforated pads? To", "images": [], "options": {"A": "increase the intensity of sound waves.", "B": "increase the loudness of sound waves.", "C": "reduce the effect of reverberation of sound waves.", "D": "decrease the frequency of sound waves."}, "answer": "C", "explanation": "In a concert hall, perforated pads or acoustic panels are used to absorb sound waves and prevent excessive reflections from the walls and ceilings. This helps to:    - Minimize reverberation (prolonged echoing of sound),    - Improve clarity and quality of the sound,    - Ensure that sound does not become muddled or distorted.    - They do not increase intensity, loudness, or alter the frequency of sound.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>22", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)", "question": "A bucket of water of mass 10 kg is swung in a vertical circle of radius 1.2 m. While at the lowest position of the swing, its speed is 5 ms−1. Determine the tension in the string. (g = 10 ms−2)", "images": [], "options": {"A": "41.7 N", "B": "141.7 N", "C": "208.3 N", "D": "308.3 N"}, "answer": "D", "explanation": "m = 10kg; r = 1.2m; v = 5 ms−1; g = 10 ms−2; T = ?    At the lowest position, the net force towards the center is T − mg.    T−mg=mv2r  T=mv2r+mg  T=10 × 521.2+10×10  T=10 × 251.2+10×10  T=2501.2+100  T = 208.3 + 100    ∴ T = 308.3 N", "marks": "1", "difficulty": "3"}, {"id": "objective>Physics>2025>23", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS", "question": "A man's near point is 30 cm. Which of the following eye defects is the man likely to suffer from?", "images": [], "options": {"A": "Hypermetropia", "B": "Myopia", "C": "Presbyopia", "D": "Astigmatism"}, "answer": "A", "explanation": "The near point is the closest distance at which the eye can focus on an object clearly.  For a normal eye, the near point is about 25 cm.    If a man's near point is 30 cm, it means he cannot see nearby objects clearly — his eye cannot focus properly on objects that are close.    This condition is known as:    Hypermetropia (farsightedness) — the eye can see distant objects clearly but struggles with nearby ones.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>24", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : DISPERSION OF WHITE LIGHT", "question": "White light can be produced by a combination of  I. magenta, yellow and cyan.  II. red, blue and green.  III. magenta and green.  IV. yellow, red and green.", "images": [], "options": {"A": "II only", "B": "I, II and III only", "C": "I and IV only", "D": "II and III only"}, "answer": "B", "explanation": "I. Magenta, Yellow, and Cyan  These are the secondary colors of light.    When combined additively, they reproduce all primary colors (Red, Green, Blue), which combine to give white light.    II. Red, Blue, and Green  These are the primary colors of light.    Their additive combination = white light.    III. Magenta and Green  Magenta = Red + Blue    Magenta + Green = Red + Blue + Green = White    IV. Yellow, Red and Green  Yellow = Red + Green    So Yellow + Red + Green = Mostly Red and Green components → not full-spectrum → not white    Therefore, white light can be produced by a combination of I, II and III.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>25", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES", "question": "The diagram below shows a beam of light incident on a mirror. Such a mirror can be used as", "images": ["Physics/imgs/2025/7J2LCD.png"], "options": {"A": "surveillance mirror.", "B": "make-up mirror.", "C": "reflector in microscope.", "D": "depressing mirror."}, "answer": "A", "explanation": "The diagram shows a beam of light incident on a mirror (diverging mirror). A diverging mirror is also known as a convex mirror.    Convex mirrors have the following properties:    - They always form virtual, erect, and diminished (smaller) images.  - They have a wide field of view because they cause parallel rays to diverge and reflections spread out.    Let's analyze the options based on these properties:    Surveillance mirror: Convex mirrors are commonly used as surveillance mirrors (e.g., in shops, on roads at blind corners) because their wide field of view allows them to cover a large area, even though the objects appear smaller. This fits the properties of a diverging mirror.    Make-up mirror: Make-up mirrors are typically concave mirrors (converging mirrors). They are used to produce a magnified, erect (virtual) image when the face is placed within the focal length, which helps in applying make-up. A diverging mirror would make the face look smaller.    Reflector in a microscope: Microscopes primarily use lenses (refracting light) to magnify objects. While some illumination systems might use mirrors, the primary magnification in a microscope comes from converging lenses. A diverging mirror would not be suitable for producing magnified images for observation.    Depressing mirror: This is not a standard term for a type of mirror or its function in optics.    Therefore, a diverging mirror (convex mirror) is best used as a surveillance mirror.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>26", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "PROPERTIES OF WAVES : SUPERPOSITION", "question": "Which of the following statements about stationary wave is not true?", "images": [], "options": {"A": "Particles between adjacent nodes vibrate out of phase with each other.", "B": "Successive nodes or antinodes occur at intervals of half a wavelength.", "C": "Particles between adjacent nodes vibrate in phase with each other.", "D": "Particles between adjacent nodes have different amplitudes."}, "answer": "A", "explanation": "A. Particles between adjacent nodes vibrate out of phase with each other.  This statement is NOT TRUE. In a stationary wave, all particles between any two successive nodes vibrate in phase with each other. Their displacements reach maximums and minimums at the same time, though their amplitudes vary. Particles on opposite sides of a node vibrate out of phase with each other.     B. Successive nodes or antinodes occur at intervals of half a wavelength.  This statement is TRUE.    The distance between two consecutive nodes is λ/2.  The distance between two consecutive antinodes is λ/2.  The distance between a node and an adjacent antinode is λ/4.     C. Particles between adjacent nodes vibrate in phase with each other.  This statement is TRUE. As explained in A, all particles in a single segment (between two nodes) oscillate synchronously.    D. Particles between adjacent nodes have different amplitudes.  This statement is TRUE. At the nodes, the amplitude of vibration is zero. At the antinodes (midway between nodes), the amplitude is maximum. For all other points between a node and an antinode, the amplitude varies, increasing from zero at the node to a maximum at the antinode, and then decreasing back to zero at the next node.    Therefore, the statement that is not true is:  A. Particles between adjacent nodes vibrate out of phase with each other.", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>27", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : VIBRATION OF AIR IN PIPE – OPEN AND CLOSED PIPES", "question": "In a pipe closed at one end and open at the other end, the overtones that accompany the fundamental frequency are", "images": [], "options": {"A": "odd integer multiples of the fundamental frequency.", "B": "even integer multiples of the fundamental frequency.", "C": "all integer multiples of the fundamental frequency.", "D": "prime integer multiples of the fundamental frequency."}, "answer": "A", "explanation": "For a pipe closed at one end and open at the other (a closed pipe system):    The fundamental mode (first harmonic) has a node at the closed end and an antinode at the open end.    Only odd harmonics are produced because the pipe can only accommodate odd-numbered quarter wavelengths.    The overtones produced are the 3rd, 5th, 7th, and so on, harmonics. These are odd integer multiples of the fundamental frequency. Even harmonics are not present in a pipe closed at one end and open at the other.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>28", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A radioactive substance of mass 512.0 g decays to 64.0 g. Determine the number of half-lives involved in the decay.", "images": [], "options": {"A": "8", "B": "6", "C": "4", "D": "3"}, "answer": "D", "explanation": "No = 512.0 g, N = 64.0 g, n = ?    After each half-life, the mass halves:    1. After 1st half-life: 512 ÷ 2 = 256 g    2. After 2nd half-life: 256 ÷ 2 = 128 g    3. After 3rd half-life: 128 ÷ 2 = 64 g    ∴ The number of half-lives involved in the decay is 3.    ALTERNATIVELY    The remaining mass after n half-lives is given by:    NNo=(12)n  64512=(12)n  18=(12)n  123=(12)n  (12)3=(12)n  ∴ n = 3    This confirms that 3 half-lives have passed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>29", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "PROPERTIES OF WAVES : INTERFERENCE", "question": "Two waves will interfere destructively if the path difference between the waves is", "images": [], "options": {"A": "one wavelength.", "B": "one-half wavelength.", "C": "one-quarter wavelength.", "D": "one-eighth wavelength."}, "answer": "B", "explanation": "Destructive interference occurs when two waves meet out of phase - meaning the crest of one aligns with the trough of the other, causing cancellation.  This happens when the path difference between the two waves is an odd multiple of half a wavelength:  Path difference = (n + 1/2)λ, where n = 0, 1, 2, ...     The simplest case is when path difference = 1/2λ (i.e., half a wavelength).", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>30", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "Which of the following statements about a step-up transformer is correct? It has", "images": [], "options": {"A": "less number of turns in the primary coil than in the secondary coil.", "B": "more number of turns in the primary coil than in the secondary coil.", "C": "equal number of turns in the primary coil and the secondary coil.", "D": "its primary coil far away from the secondary coil."}, "answer": "A", "explanation": "A step-up transformer is designed to increase voltage from the primary coil to the secondary coil. This is achieved by having:    - Fewer turns in the primary coil (Np)  - More turns in the secondary coil (Ns)", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>31", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : FARADAY’S LAW", "question": "The unit of magnetic flux density is", "images": [], "options": {"A": "Tesla.", "B": "Watt.", "C": "Newton per metre.", "D": "Coulomb."}, "answer": "A", "explanation": "The Tesla is the SI unit of magnetic flux density (also known as magnetic field strength or B-field). One Tesla is defined as one Weber per square meter (1 T = 1 Wb/m2). It's named after Nikola Tesla", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>32", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTRIC FIELD : CURRENT ELECTRICITY", "question": "Meters are installed in houses to monitor and evaluate the cost of the electricity consumed. What physical quantity does this meter measure?", "images": [], "options": {"A": "Power", "B": "Energy", "C": "Voltage", "D": "Current"}, "answer": "B", "explanation": "Meters installed in houses (often called electricity meters or kilowatt-hour meters) monitor and evaluate the cost of electricity consumed by measuring Energy.    Electricity bills are based on the amount of electrical energy consumed, which is usually measured in kilowatt-hours (kWh).    Power (measured in Watts or kilowatts) is the rate at which energy is used.  Energy (measured in Joules or kilowatt-hours) is the total amount of work done or heat produced over a period of time.  The meter continuously measures the instantaneous power (voltage multiplied by current) and integrates it over time to give the total energy consumed.    Therefore, the physical quantity measured by these meters is Energy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>33", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT", "question": "The type of energy stored by a dry Leclanché cell is", "images": [], "options": {"A": "chemical.", "B": "electrical.", "C": "nuclear.", "D": "thermal."}, "answer": "A", "explanation": "A dry Leclanché cell (a common type of dry cell battery) stores chemical energy, which is converted into electrical energy when the cell is in use.    The cell contains chemical substances (like zinc and manganese dioxide) that undergo redox reactions.    This reaction produces a flow of electrons, i.e., electric current.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>34", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "CONSERVATION OF ENERGY", "question": "The microphone transforms energy from", "images": [], "options": {"A": "electrical to sound.", "B": "sound to electrical.", "C": "electrical to mechanical.", "D": "sound to mechanical."}, "answer": "B", "explanation": "A microphone is a device that converts sound energy into electrical energy.    When you speak into a microphone, sound waves (mechanical vibrations in air) strike a diaphragm inside the mic.    These vibrations are converted into electrical signals that can be amplified, recorded, or transmitted.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>35", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : RADIOACTIVITY", "question": "A hospital received 16 g of a radioactive substance at 1300 hour GMT. At 1700 hour GMT, the fraction of the substance left unchanged was 1/16​. Determine the half-life of the substance.", "images": [], "options": {"A": "4 hours", "B": "2 hours", "C": "1 hour", "D": "0.5 hour"}, "answer": "C", "explanation": "No=16g;NNo=116  Timeelapsed=1700-1300=4hours  T1/2=?  Usingthedecayformula:  NNo=(12)n  116=(12)n  124=(12)n  (12)4=(12)n  n=4(numberofhalf-lives)  T1/2=Time elapsedn=44  ∴T1/2=1hour", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>36", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "NEWTON’S LAWS OF MOTION : THIRD LAW", "question": "Which of the following situations pertains to Newton's third law of motion?", "images": [], "options": {"A": "A ball rolling on the ground", "B": "An accelerating car", "C": "A rocket propelled into space", "D": "Pedalling of bicycle"}, "answer": "C", "explanation": "Newton's Third Law of Motion states:    For every action, there is an equal and opposite reaction.    In a rocket launch, hot gases are expelled downward (action), and the rocket is pushed upward (reaction).    This is a classic example of Newton's third law in action.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>37", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "WORK, ENERGY AND POWER : CONCEPT OF POWER", "question": "The force and velocity of a system are each reduced simultaneously by one-half. The power of the system is", "images": [], "options": {"A": "doubled.", "B": "reduced by a quarter.", "C": "reduced by half.", "D": "constant."}, "answer": "B", "explanation": "Given:    Initial Force (F₁): F    Initial Velocity (v₁): v    Initial Power (P₁): P = F × v    After reduction:    NewForce(F₂):F2​  NewVelocity(v₂):v2​  NewPower(P₂):F₂×v₂=F2×v2=F × v4=P4​  Therefore, the power is reduced to one-quarter of its original value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>38", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "MACHINES :", "question": "A plane is inclined at 45° to the horizontal. Calculate the velocity ratio of the plane.", "images": [], "options": {"A": "0.71", "B": "1.00", "C": "1.41", "D": "1.71"}, "answer": "C", "explanation": "θ = 45°; V.R = ?    V.R=1sinθ=1sin45°  ∴ V.R = 1.41", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>39", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY", "question": "A body in a lift is moving down with acceleration due to gravity. Which of the following statements is correct? The body", "images": [], "options": {"A": "weighs less than its actual weight.", "B": "weighs more than its actual weight.", "C": "weighs exactly its own weight.", "D": "is weightless."}, "answer": "D", "explanation": "When a lift (elevator) is moving downward with acceleration equal to gravity (a = g), it is in free fall.  In this condition, the apparent weight of the body becomes:  Wapparent = m(g − a)   Since a = g, then:  Wapparent = m(g − g) = 0   This means the person or object experiences weightlessness - there is no contact force acting on them from the floor.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>40", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "FLUID AT REST : VISCOSITY (FRICTION IN FLUIDS)", "question": "When the pressure in oil is increased, the viscosity of the oil would be", "images": [], "options": {"A": "increased.", "B": "decreased.", "C": "constant.", "D": "increased, then decreased."}, "answer": "A", "explanation": "Viscosity is the resistance of a fluid to flow.    For liquids like oil:    When pressure increases, the molecules are pushed closer together, reducing their ability to move past one another.    This causes an increase in internal friction, and hence, an increase in viscosity.    NB: This behavior is opposite to gases, where increasing pressure can reduce viscosity under certain conditions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>41", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "What is the number of neutrons in 146C?", "images": [], "options": {"A": "6", "B": "8", "C": "14", "D": "20"}, "answer": "B", "explanation": "Mass number (A) = 14  Atomic number (Z) = 6 (which is the number of protons)  Number of neutrons = A - Z = 14 - 6 = 8", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>42", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT", "question": "The ice and steam points of a resistance thermometer are 12.0 Ω and 20.0 Ω respectively. Calculate the resistance of the thermometer at 10°C.", "images": [], "options": {"A": "12.4 Ω", "B": "12.8 Ω", "C": "13.2 Ω", "D": "13.4 Ω"}, "answer": "B", "explanation": "We are given:    Ice point (0°C) resistance: R0 = 12.0 Ω    Steam point (100°C) resistance: R100 = 20.0 Ω    Temperature: θ = 10°C    Find: Resistance at 10°C (Rθ)    θ − 0100 − 0=Rθ − R0R100 − R0  10 − 0100 − 0=Rθ − 1220 − 12  10100=Rθ − 128  100(Rθ − 12) = 80    100Rθ − 1200 = 80    100Rθ = 80 + 1200    100Rθ = 1280    ∴Rθ=1280100=12.8Ω", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>43", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : FUSION AND FISSION", "question": "A radium nuclide decays by emitting an alpha particle as shown below.  22688Ra → X + 42He. Determine the daughter nuclide.", "images": [], "options": {"A": "22286X", "B": "22288X", "C": "23086X", "D": "23088X"}, "answer": "A", "explanation": "Applying Conservation Laws:    1. Conservation of Mass Number (A):     226 = AX + 4    AX ​= 226 - 4 = 222    2. Conservation of Atomic Number (Z):     88 = ZX + 2    ZX ​= 88 - 2 = 86    The nuclide with Z = 86 is Radon (Rn). Thus:    ∴ X = 22286Rn", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>44", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS", "question": "A bullet of mass 0.025 kg moves at 250 ms−1. Calculate its deBroglie wavelength.  [h = 6.67 × 10−34 Js, e = 1.6 × 10−19 C]", "images": [], "options": {"A": "6.67 × 10−38 m", "B": "5.34 × 10−35 m", "C": "1.07 × 10−34 m", "D": "2.13 × 10−34 m"}, "answer": "C", "explanation": "m = 0.025 kg; v = 250 ms−1; h = 6.67 × 10−34 Js, e = 1.6 × 10−19 C; λ = ?    λ=hp=hmv  λ=6.67 × 10−340.025 × 250  ∴λ=6.67 × 10−346.25=1.07×10−34", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>45", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE", "question": "An electron moving with 5.0 × 105 ms−1 enters a magnetic field at 90°. Calculate the magnitude of the magnetic force on the electron if the magnetic field strength is 0.25 T. [e = 1.6 × 10−19 C]", "images": [], "options": {"A": "1.5 × 10−14 N", "B": "2.0 × 10−14 N", "C": "2.5 × 10−14 N", "D": "3.5 × 10−14 N"}, "answer": "B", "explanation": "v = 5.0 × 105 ms−1; θ = 90°; B = 0.25 T; q = 1.6 × 10−19 C; F = ?    To calculate the magnetic force acting on the electron, we'll use the formula for the force on a moving charge in a magnetic field:    F = qvBsinθ    F = 1.6 × 10−19 × 5.0 × 105 × 0.25 × sin 90°    ∴ F = 2 × 10−14 N", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>46", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "LIGHT WAVES : SOURCES OF LIGHT", "question": "A beam of light which appears to come from a point in space is said to be", "images": [], "options": {"A": "convergent.", "B": "divergent.", "C": "parallel.", "D": "circular."}, "answer": "B", "explanation": "A beam of light that appears to come from a point in space is called divergent because:    The light rays spread out (diverge) as if originating from a single point.    Examples:    - Light emitted from a point source (like a small bulb).    - Light reflecting off a convex mirror.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>47", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "SOUND WAVES : NOISE AND MUSIC", "question": "A sound wave made up of a large number of unrelated frequencies superimposed on each other is called", "images": [], "options": {"A": "harmonics.", "B": "note.", "C": "noise.", "D": "pitch."}, "answer": "C", "explanation": "A sound wave composed of many unrelated (random) frequencies superimposed on each other is known as noise.    Noise lacks a regular pattern or structure, making it non-musical and often unpleasant.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>48", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "MOTION : SOLID FRICTION", "question": "A boy pushes a box of mass 80 kg along a horizontal floor with a force of 200 N. If the box is pushed with a uniform velocity, what is the coefficient of friction between the box and the floor?  [g = 10 ms−2]", "images": [], "options": {"A": "0.25", "B": "0.40", "C": "0.50", "D": "0.65"}, "answer": "A", "explanation": "m = 80 kg; F = 200 N; g = 10 ms−2; μ = ?    Since the box moves at a constant velocity, the net force is zero:    F − Ffriction = 0    F = Ffriction    F = μR     F = μmg (∵ R = mg)    μ=Fmg=20080 × 10  ∴μ=200800=0.25", "marks": "1", "difficulty": "2"}, {"id": "objective>Physics>2025>49", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "HOOKE’S LAW, YOUNG’S MODULES AND WORK DONE IN SPRINGS AND STRING :", "question": "Extremely thin wires can be drawn from platinum simply because platinum is", "images": [], "options": {"A": "crystalline.", "B": "ductile.", "C": "hard.", "D": "malleable."}, "answer": "B", "explanation": "Platinum can be drawn into extremely thin wires because it is highly ductile. Here's why:    Ductility is the ability of a material to undergo plastic deformation under tensile stress (i.e., it can be stretched into wires without breaking).    Platinum's Properties:    Its metallic bonds allow layers of atoms to slide past each other when stretched.    It is one of the most ductile metals, alongside gold and silver.", "marks": "1", "difficulty": "1"}, {"id": "objective>Physics>2025>50", "subject": "Physics", "year": "2025", "type": "Objective", "topic": "ELECTROMAGNETIC FIELD : INDUCTANCE", "question": "The S.I unit of inductance is", "images": [], "options": {"A": "Weber.", "B": "Farad.", "C": "Henry.", "D": "Coulomb."}, "answer": "C", "explanation": "The SI unit of inductance. Inductance measures a coil's opposition to a change in current, producing an electromotive force (EMF). It's named after Joseph Henry.", "marks": "1", "difficulty": "1"}];